// ════════════════════════════════════════════════════════════════════════════
// BRIEF N-bis · ELIMINACIÓN SUGGESTIONS TIPO A · UX COHERENCIA
//
// Alineación arquitectónica con visión declarada del producto:
// "ADI debe sentirse como UN CHATGPT EJECUTIVO CONECTADO A EVIDENCIA
//  OPERACIONAL VIVA · NO como dashboard con chat."
//
// Las suggestions textuales hardcoded (Tipo A · preguntas pre-escritas)
// son herencia del producto anterior (dashboard-first). Contradicen la
// visión conversación-first.
//
// Tipología:
//  · Tipo A · string suggestion ("¿Cuánto suman entre todos?") → ELIMINAR
//  · Tipo B · object con action.type ({text, action:{type, payload}}) → PRESERVAR
//  · Tipo C · campo sentrixAction → PRESERVAR (intocado · contrato propio)
//
// filterTextualSuggestions aplica filtro determinístico:
//  · null/undefined/non-array → retorna intacto (defensivo)
//  · flag OFF → retorna array original sin tocar (rollback bitwise)
//  · flag ON → retorna solo elementos Tipo B (objetos con action.type)
//
// Estrategia: helper único · single source of truth · cero duplicación.
// Composers Tipo A puro envuelven su array con el helper en el return.
// Composers Tipo B puro NO se tocan (helper sería no-op · cero efecto).
//
// Rollback granular: VOICE_REMOVE_TEXTUAL_SUGGESTIONS_ENABLED = false
// preserva comportamiento bitwise idéntico a post-BRIEF N.
//
// UBICACIÓN: declarado ANTES de GENERIC_RESPONSES para evitar TDZ
// (Temporal Dead Zone) · GENERIC_RESPONSES llama al helper en eval del
// objeto literal durante init del módulo.
// ════════════════════════════════════════════════════════════════════════════
const VOICE_REMOVE_TEXTUAL_SUGGESTIONS_ENABLED = true;

function filterTextualSuggestions(suggestions) {
  // Guard defensivo · si la entrada no es array, retornar intacto.
  if (!Array.isArray(suggestions)) return suggestions;
  // Flag rollback · si OFF, preservar array original bitwise.
  if (!VOICE_REMOVE_TEXTUAL_SUGGESTIONS_ENABLED) return suggestions;
  // Filtro: preservar SOLO objects con action.type (cognitive actions Tipo B).
  return suggestions.filter(s =>
    typeof s === "object"
    && s !== null
    && typeof s.action === "object"
    && s.action !== null
    && typeof s.action.type === "string"
  );
}

