// (capital_atrapado_K/capital_total_K = i.capitalAtrapado/capitalTotal · USD crudo), el threshold de
// relevancia (capital_atrapado_K: {high:5000} · USD) y el delta demo (DEMO_DELTA_PROFILE.capital_atrapado_K
// = -5800 · USD) están todos en USD etiquetados _K; _formatAmount (genérico · lo comparte contribucion_K en
// K real) los trata como K → "$5.8M". El fix escala los TRES (snapshot + threshold + profile del capital)
// de USD a K real (÷1000) COORDINADAMENTE, dejando _formatAmount y las otras dims intactos. La regla de oro:
// como snapshot y umbral bajan 1000× juntos, la relevancia NO cambia (|5.8| vs 5 = high, igual que |5800| vs
// 5000) — solo la escala de presentación. off = "$5.8M" (el bug · byte-idéntico). El 1000× queda 100% muerto.
const ADI_DELTA_PRELUDE_CAPITAL_ESCALA_ENABLED = true;

// FIX #D-PANORAMA-CAPITAL-ESCALA-KPI-BIS · helper de escala: capital en USD crudo → K (en miles). Si el fix
// está OFF, devuelve el valor crudo (el bug · byte-idéntico). Centraliza la corrección de los renders del v2.
function _capEscalaK(capitalUSD) {
  if (typeof ADI_PANORAMA_CAPITAL_KPI_FIX_ENABLED !== "undefined" && ADI_PANORAMA_CAPITAL_KPI_FIX_ENABLED) {
    return (typeof capitalUSD === "number") ? capitalUSD / 1000 : capitalUSD;
  }
  return capitalUSD;
}

// Frases de venta total GLOBAL (sin lista). Match exacto-ish · NO "esos/ellos" (esos van a aggregation).
const _VENTAS_TOTAL_GLOBAL_PHRASES = [
  "cuanto vendi en total", "cuanto vendi", "cuanto vendimos en total", "cuanto vendimos",
  "cuanto facture en total", "cuanto facture", "cuanto facturamos en total", "cuanto facturamos",
  "cuanto vende la empresa", "cuanto vendio la empresa", "cuanto factura la empresa",
  "total de ventas", "el total de ventas", "la venta total", "venta total del negocio",
  "cuanto fue la venta total", "cual es la venta total", "cuanto facturo la empresa",
];
// FIX #D-VENTAS-TOTAL-LEXICO · detecta venta total global SIN lista de contexto.
function detectVentasTotalGlobal(text, context) {
  if (typeof ADI_VENTAS_TOTAL_LEXICO_ENABLED === "undefined" || !ADI_VENTAS_TOTAL_LEXICO_ENABLED) return null;
  if (!text || typeof text !== "string") return null;
  // Guard de frontera: si hay lista de contexto activa → NO capturar (deja aggregation_sum_on_context).
  if ((context && context.lastClientList && context.lastClientList.length > 0) ||
      (context && context.lastSkuList && context.lastSkuList.length > 0)) return null;
  const t = text.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[¿¡?!.,;:]+/g, "").trim();
  // Guard léxico: si menciona "esos"/"ellos"/"estos" (referencia a lista) → NO capturar.
  if (/\b(esos|ellos|estos|estas|esas|ellas)\b/.test(t)) return null;
  if (_VENTAS_TOTAL_GLOBAL_PHRASES.includes(t)) {
    return { type: "module", modulo: "ventas", _ventasTotalGlobal: true };
  }
  return null;
}

// ─── _capitalInmovilizado · SINGLE SOURCE OF TRUTH (Def 2 canónica + submétrica estricta) ───
// FIX #D-CAPITAL-DEF-CANONICA · TODO lo que diga "capital inmovilizado" usa esto.
//   total       · Def 2 · plata en SKUs con alerta crit/warn O rotacion < 2  → ~$56K (la canónica)
//   estricto60d · submétrica · plata en SKUs con diasSinVenta > 60           → $33.2K (la sub-lectura)
// NO toca sobrestock (DOH>120) ni premium_slow · esas son OTRAS métricas (cláusula I-SOBRESTOCK-INTACTO).
function _capitalInmovilizado(inventario) {
  const inv = Array.isArray(inventario) ? inventario : (typeof skuInventario !== "undefined" ? skuInventario : []);
  const skusCriticos = inv.filter(s => s.alerta === "crit" || s.alerta === "warn" || s.rotacion < 2);
  const skusSinVenta = inv.filter(s => s.diasSinVenta > 60);
  const total = skusCriticos.reduce((sum, s) => sum + s.stockUSD, 0);
  const estricto60d = skusSinVenta.reduce((sum, s) => sum + s.stockUSD, 0);
  return { total, estricto60d, skusCriticos, skusSinVenta };
}

