// ═══ BRIEF D1.F · SANEO DEL CONTRATO DE ENTIDADES (D-D1-4 firmada) ═══
// Regla de contrato: activeResult.entities contiene SIEMPRE nombres canónicos
// user-facing · nunca IDs internos. Causa raíz (hallazgo C2 · D1.0): AN+.FIX2
// expone clientList como IDs (_buildEntityId · "client_falabella") y el extractor
// R1 los consumía como nombres → R3 no resolvía → re-anchor filtraba IDs verbatim
// al usuario (violación ECL). El fix vive en el EXTRACTOR (cuello único donde nace
// el contrato) · cero touch a composers FIX2 / R3 / R4 / cadena / ring AN.B
// (lastClientList se puebla AGUAS ARRIBA del bloque R1 · conserva los IDs que AN.B espera).
// off = comportamiento base byte-idéntico (el bug C2 vuelve · rollback inmediato).
const VOICE_D1F_ENTITY_SANITIZE_ENABLED = true;
// _d1fResolveEntityName · detección por RESOLUCIÓN, no por prefijo: si el string
// resuelve como ID en el Registry S.A (getEntityById · API pública READ-ONLY ·
// L42071) → canonical_name user-facing. Si no resuelve (nombre real, basura,
// registry apagado) → pasa INTACTO. Defensivo total: cero mutación del Registry,
// cero throw al flujo, lista mixta soportada vía .map().
function _d1fResolveEntityName(s) {
  if (typeof s !== "string" || !s) return s;
  try {
    const e = (typeof getEntityById === "function") ? getEntityById(s) : null;
    if (e && typeof e.canonical_name === "string" && e.canonical_name) return e.canonical_name;
  } catch (err) { /* defensivo · read-only · nunca rompe el flujo */ }
  return s;
}

// ═══ BRIEF D1.a/b/c · CONTINUIDAD DE CAUSA (D-D1-1..7 firmadas · diseño D1.1) ═══
// Tras un hallazgo, "¿por qué?" (y variantes del catálogo cause_query) sirve la CAUSA
// que el motor computó EN EL TURNO DEL HALLAZGO · cifras persistidas en finding.cause ·
// CERO recompute (I1). off = byte-idéntico D1.F (detector null → flujo intacto · I2/I4).
const VOICE_D1_CAUSE_ENABLED = true;

// ── _D1_PATTERN_TO_DRIVER · catálogo estático régimen 2 (mapeo evidence→cause) ──
// UNA entrada con materia prima real (pre-flight D1 aprobado): quality_growth y
// customer_dependency NO exponen evidence/reasoningPattern al write (objeto plano
// pre-contrato-v1 · H-D1-1 · deuda #D-D1-QUALITY-DEPENDENCY-SIN-CONTRATO-V1) →
// cause null → salida 2 honesta anclada (D-D1-1). Cada *_field referencia un key
// de lcr.evidence YA presente al write · cero recompute.
const _D1_PATTERN_TO_DRIVER = {
  high_sales_low_contribution_via_load: {
    driver_key: "commercial_erosion",          // alineado DRIVER_CANONICAL_KEYS
    factor: "carga_comercial",
    value_field: "carga_actual",               // % · ej. 4.5
    unit: "%",
    vs: { type: "best_practice", ref_field: "best_practice_carga", gap_field: "gap_carga_pp" },
    target_field: "cliente_principal",
    narrable_fields: ["carga_actual", "gap_carga_pp", "best_practice_carga",
                      "recuperable_principal_USD", "recuperable_agregado_K",
                      "margen_pct", "benchmark_margen", "top3_clientes"],
  },
};

// ── _d1ExtractCause(lcr) · D1.a · snapshot del driver YA computado este turno ──
// Régimen 1 (copy): lcr.narrative_signals.why.driver (ranking_extremes · cross_metric).
// Régimen 2 (map): lcr.evidence + reasoningPattern vía _D1_PATTERN_TO_DRIVER.
// Resto → null explícito (retrieval/overviews/sku_operational/client-dive D-MB3-1/
// quality/dependency H-D1-1). Defensivo total · null en duda · cero throw.
function _d1ExtractCause(lcr) {
  try {
    if (!lcr || typeof lcr !== "object") return null;
    const _why = lcr.narrative_signals && lcr.narrative_signals.why;
    const _drv = _why && _why.driver;
    if (_drv && _drv.factor) {
      return {
        source: "why_signal",
        driver_key: _drv.mechanism || null,
        factor: _drv.factor,
        value: (typeof _drv.value === "number") ? _drv.value : null,
        unit: _drv.unit || null,
        vs: {
          type: "promedio_interno",
          vs_promedio: (typeof _drv.vs_promedio === "number") ? _drv.vs_promedio : null,
          vs_benchmark: (typeof _drv.vs_benchmark === "number") ? _drv.vs_benchmark : null,
        },
        target_entity: _why.target_entity || _drv.target_entity || null,
        fields: {
          chain: Array.isArray(_drv.chain) ? _drv.chain.slice() : null,
          borderline: !!_drv.borderline,
        },
      };
    }
    const _map = lcr.reasoningPattern && _D1_PATTERN_TO_DRIVER[lcr.reasoningPattern];
    const _ev = lcr.evidence;
    if (_map && _ev && typeof _ev === "object") {
      const _val = _ev[_map.value_field];
      if (typeof _val !== "number") return null; // sin cifra central no hay causa narrable · honest null
      const _fields = {};
      for (const k of _map.narrable_fields) { if (_ev[k] != null) _fields[k] = _ev[k]; }
      return {
        source: "evidence_mapping",
        driver_key: _map.driver_key,
        factor: _map.factor,
        value: _val,
        unit: _map.unit,
        vs: {
          type: _map.vs.type,
          ref: (_ev[_map.vs.ref_field] != null) ? _ev[_map.vs.ref_field] : null,
          gap: (_ev[_map.vs.gap_field] != null) ? _ev[_map.vs.gap_field] : null,
        },
        target_entity: _ev[_map.target_field] || null,
        fields: _fields,
      };
    }
    return null;
  } catch (e) { return null; }
}

// ── detectCausalFollowUp(trimmed, conversationContext) · D1.b · PRE-DISPATCH ──
// null | { matched_marker }. Única fuente léxica: SEMANTIC_INTENTS.cause_query
// .vocabulary_markers (D-D1-3 · mismo régimen de match que _extractIntents: texto
// normalizado + word-boundary · cero matcher paralelo). Frescura = condición exacta
// R3/R4 (D-D1-2 · cero staleness nuevo). Guard de entidad nueva (D-D1-6) con los
// detectores canónicos existentes. Exclusión cross-dim (G8): el PROPIO detector AN
// decide vía su force_enabled (flag-independiente · single source).
function detectCausalFollowUp(trimmed, conversationContext) {
  try {
    if (typeof VOICE_D1_CAUSE_ENABLED === "undefined" || !VOICE_D1_CAUSE_ENABLED) return null;
    if (typeof trimmed !== "string" || !trimmed) return null;
    const ctx = conversationContext || {};
    const ar = ctx.activeResult;
    // hallazgo servible · EXACTO R3/R4
    if (!ar || !Array.isArray(ar.entities) || ar.entities.length === 0) return null;
    // marker causal
    const normalized = _normalizeSemanticText(trimmed);
    if (!normalized) return null;
    let matched = null;
    const markers = (typeof SEMANTIC_INTENTS !== "undefined" && SEMANTIC_INTENTS.cause_query
      && SEMANTIC_INTENTS.cause_query.vocabulary_markers) || [];
    for (const term of markers) {
      const re = new RegExp("\\b" + term.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "\\b", "i");
      if (re.test(normalized)) { matched = term; break; }
    }
    if (!matched) return null;
    // guard de entidad nueva (D-D1-6)
    const _normName = (s) => _normalizeSemanticText(String(s || ""));
    const _arSet = ar.entities.map(_normName);
    const _txtClient = (typeof detectClientInText === "function") ? detectClientInText(trimmed) : null;
    if (_txtClient && _arSet.indexOf(_normName(_txtClient)) < 0) return null;
    const _txtSku = (typeof detectSkuInText === "function") ? detectSkuInText(trimmed) : null;
    if (_txtSku && _arSet.indexOf(_normName(_txtSku)) < 0) return null;
    // exclusión cross-dim (G8 · AN gana)
    try {
      if (typeof detectAnCrossIntent === "function") {
        const _an = detectAnCrossIntent(trimmed, ctx, { type: "generic" }, { force_enabled: true });
        if (_an && _an.is_cross_intent) return null;
      }
    } catch (anErr) { /* defensivo · si AN falla, D1 no se frena ni captura por error */ }
    return { matched_marker: matched };
  } catch (e) { return null; }
}

// ── composeCauseDevelopment(activeResult, scenario) · D1.c · sirve la causa ──
// I1 por construcción: TODA cifra interpolada sale de finding.cause (persistido en el
// turno del hallazgo) · cero re-derivación del dataset · cero resta/aritmética nueva.
// Salida 1 · cause presente → narrativa causal (régimen 1: composeCausalMovement
//   REUSO PURO con shape why adaptado · régimen 2: línea-driver desde cause.fields con
//   referencia EXACTA "mejor práctica" — G-D1-9 opción A, evita mentir "promedio interno").
// Salida 2 · cause null → honesto ANCLADO D-D1-1 (nombra hallazgo · declara sin mecanismo ·
//   vías reales por entityType · cero ejecución · cero texto fallback K).
// Salida 3 · activeResult malformado → re-anchor honesto patrón R3 (defensivo).
function composeCauseDevelopment(activeResult, scenario) {
  // formato monetario · misma semántica que el composer de erosión (USD raw → $K/$M)
  const _fmtUSD = (val) => {
    if (typeof val !== "number" || isNaN(val)) return null;
    if (val >= 1000000) return `$${(val / 1000000).toFixed(2)}M`;
    if (val >= 1000) { const k = val / 1000; return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`; }
    return `$${Math.round(val)}`;
  };
  try {
    // ── Salida 3 · defensivo
    if (!activeResult || !Array.isArray(activeResult.entities) || activeResult.entities.length === 0) {
      return {
        opener: "No tengo un hallazgo activo que explicar en este escenario. ¿Rehacemos el análisis?",
        suggestions: [], sentrixAction: null,
        reasoningPattern: "causal_followup_reanchor", _d1: "reanchor",
      };
    }
    const cause = activeResult.finding && activeResult.finding.cause;
    const entities = activeResult.entities;
    // ── Salida 2 · cause null · honesto ANCLADO (D-D1-1 A+)
    if (!cause) {
      const _noun = activeResult.entityType === "sku" ? "productos"
        : activeResult.entityType === "familia" ? "familias"
        : activeResult.entityType === "marca" ? "marcas" : "cuentas";
      const _list = entities.join(", ");
      const _vias = activeResult.entityType === "sku"
        ? "DOH y capital inmovilizado por producto · rotación contra el promedio · perfil operacional (mantener o liquidar)"
        : (activeResult.entityType === "familia" || activeResult.entityType === "marca")
        ? "participación sobre el total · crecimiento contra el año anterior · margen por línea"
        : "margen y carga comercial por cuenta · contribución contra ventas · concentración de la cartera";
      const opener = `El análisis activo es un ranking descriptivo de ${_noun}: ${_list}. Ese resultado ordena, pero no computó un mecanismo causal que explique por qué quedaron ahí.\n\nPara llegar a la causa puedo mirar: ${_vias}. Decime por dónde y lo corro sobre estas mismas ${_noun}.`;
      return {
        opener,
        suggestions: (typeof filterTextualSuggestions === "function") ? filterTextualSuggestions([]) : [],
        sentrixAction: null,
        reasoningPattern: "causal_followup_anchored_honest", _d1: "anchored_honest",
      };
    }
    // ── Salida 1 · cause presente · narrativa causal (cifras == cause · I1)
    const target = cause.target_entity || entities[0];
    const movements = [];
    if (cause.source === "why_signal") {
      // régimen 1 · composeCausalMovement REUSO PURO · solo si el campo que su template
      // interpola existe con semántica exacta (carga→vs_promedio · margen→vs_benchmark · doh→value)
      const _d = cause.factor === "carga_comercial" ? (typeof cause.vs.vs_promedio === "number")
        : cause.factor === "margen_unitario" ? (typeof cause.vs.vs_benchmark === "number")
        : cause.factor === "doh_alto" ? (typeof cause.value === "number") : false;
      if (_d) {
        const whyShape = {
          target_entity: target,
          driver: {
            factor: cause.factor, value: cause.value,
            vs_promedio: cause.vs.vs_promedio, vs_benchmark: cause.vs.vs_benchmark,
            target_entity: target,
          },
        };
        const line = composeCausalMovement(whyShape, "validate");
        if (line) movements.push(line);
      }
      if (cause.factor === "carga_comercial") {
        movements.push(`Esa carga es el mecanismo: la cuenta paga por vender, lo que diluye la contribución que el volumen genera.`);
        if (cause.fields && cause.fields.borderline) {
          movements.push(`El gap es leve · antes de priorizar esta cuenta vale el juicio de oportunidad sobre el monto.`);
        }
        movements.push(`Siguiente paso: comparar ${target} contra las cuentas virtuosas de la cartera, o simular el impacto de bajar la carga 1pp.`);
      } else if (cause.factor === "margen_unitario") {
        movements.push(`El precio neto por unidad no captura el benchmark de industria · el mecanismo es de margen unitario, no de volumen.`);
        movements.push(`Siguiente paso: revisar estructura de precio y costo de ${target}.`);
      } else if (cause.factor === "doh_alto") {
        movements.push(`El capital queda atrapado porque la velocidad de conversión no acompaña al stock.`);
        movements.push(`Siguiente paso: revisar el perfil operacional de ${target} (mantener o liquidar).`);
      }
    } else {
      // régimen 2 · evidence_mapping · G-D1-9 opción A: referencia EXACTA a mejor práctica
      const f = cause.fields || {};
      const _ref = cause.vs && cause.vs.ref;
      const _gap = cause.vs && cause.vs.gap;
      movements.push(`La carga comercial sobre ${target} es ${cause.value}%${(typeof _gap === "number" && typeof _ref === "number") ? ` · ${Number(_gap).toFixed(1)} puntos sobre la mejor práctica (${_ref}%)` : ""}.`);
      const _recPrincipal = _fmtUSD(f.recuperable_principal_USD);
      if (_recPrincipal) {
        movements.push(`Ese es el mecanismo del margen bajo: la cuenta paga por vender. Negociar esa carga hacia la mejor práctica recupera aproximadamente ${_recPrincipal} anuales sobre ${target}, sin tocar el volumen.`);
      } else {
        movements.push(`Ese es el mecanismo del margen bajo: la cuenta paga por vender.`);
      }
      if (typeof f.margen_pct === "number" && typeof f.benchmark_margen === "number") {
        movements.push(`El margen resultante (${f.margen_pct}%) corre bajo el benchmark de cartera (${f.benchmark_margen}%) mientras esa carga se sostenga.`);
      }
      const _otros = Array.isArray(f.top3_clientes) ? f.top3_clientes.filter(n => n !== target) : [];
      const _recAgg = (typeof f.recuperable_agregado_K === "number") ? _fmtUSD(f.recuperable_agregado_K * 1000) : null;
      if (_otros.length && _recAgg) {
        movements.push(`La misma palanca sobre ${_otros.join(" y ")} suma aproximadamente ${_recAgg} agregados.`);
      }
      movements.push(`Siguiente paso: arrancar la renegociación por ${target}, que concentra el peso económico de la palanca.`);
    }
    return {
      opener: movements.filter(Boolean).join("\n\n"),
      suggestions: (typeof filterTextualSuggestions === "function") ? filterTextualSuggestions([]) : [],
      sentrixAction: null,
      reasoningPattern: "causal_followup_development", _d1: cause.source,
    };
  } catch (e) {
    return {
      opener: "No tengo un hallazgo activo que explicar en este escenario. ¿Rehacemos el análisis?",
      suggestions: [], sentrixAction: null,
      reasoningPattern: "causal_followup_reanchor", _d1: "reanchor_error",
    };
  }
}
// ═══ FIN BRIEF D1 · símbolos top-level ═══

// ═══ ENCARGO D2.a · EL CRUCE QUE NARRA (cuenta→SKU) · 4 firmas founder ═══
// Tras un hallazgo de cuentas, "los SKU de esas cuentas" narra el cruce real
// cuenta→SKU bajo la FRONTERA DE DOS CAPAS (I-D2-DOS-CAPAS): las ventas pertenecen
// a la cuenta; el margen y la rotación pertenecen al producto; la narrativa RELACIONA,
// nunca FUSIONA. off = byte-idéntico D1 (detector null → flujo intacto).
const VOICE_D2_CROSS_ENABLED = true;

// ── _d2JoinCuentaSku(cuenta) · join dos-capas AISLADO (firma aprobada en pre-flight) ──
// FRONTERA HECHA CÓDIGO. capaCuenta = todo de skusPorCliente (pertenece a la cuenta).
// capaProducto = todo GLOBAL del SKU (margen/contribución de skusMargen · doh/rotación/
// estado/acción de skuInventario · accion vía classifySkuOperationalProfile R4-LOCKED,
// reuso read-only). Dos objetos literalmente separados · PROHIBIDO campo cruzado
// (margenEnCuenta, etc.) · único cómputo: participacion (ventas SKU / Σ ventas de ESA
// cuenta · GD2-7 · cuenta-contra-cuenta, no cruza capas). Defensivo total · _joinStatus
// marca faltantes · _supuesto viaja EN el dato. Helper PURO · sin estado.
function _d2JoinCuentaSku(cuenta) {
  const out = { cuenta: cuenta, skus: [], _supuesto: "capaProducto es global del SKU · NO medido dentro de la cuenta" };
  try {
    const rows = (typeof skusPorCliente !== "undefined" && skusPorCliente[cuenta]) || [];
    const totalCuenta = rows.reduce((s, r) => s + (r.actual || 0), 0) || 1; // Σ ventas de la cuenta (GD2-7)
    for (const r of rows) {
      const mk = (typeof skusMargen !== "undefined") ? skusMargen.find(m => m.nombre === r.nombre) : null;
      const inv = (typeof skuInventario !== "undefined") ? skuInventario.find(i => i.sku === r.nombre) : null;
      const status = (mk && inv) ? "full" : (!mk ? "missing_margin" : "missing_inv");
      out.skus.push({
        nombre: r.nombre,
        // ── capaCuenta · TODO de skusPorCliente (pertenece a la cuenta) ──
        capaCuenta: {
          ventas: r.actual != null ? r.actual : null,
          ventasAnt: r.anterior != null ? r.anterior : null,
          ticket: (r.actual != null && r.unidades) ? Math.round((r.actual / r.unidades) * 100) / 100 : null,
          unidades: r.unidades != null ? r.unidades : null,
          unidadesAnt: r.unidadesAnt != null ? r.unidadesAnt : null,
          participacion: r.actual != null ? Math.round((r.actual / totalCuenta) * 1000) / 10 : null, // % sobre la cuenta
        },
        // ── capaProducto · TODO global del SKU (pertenece al producto) ──
        capaProducto: {
          margen: mk && mk.margen != null ? mk.margen : null,
          contribucionSKU: mk && mk.contribucion != null ? mk.contribucion : null,
          doh: inv && inv.doh != null ? inv.doh : null,
          rotacion: inv && inv.rotacion != null ? inv.rotacion : null,
          estado: inv && inv.estado != null ? inv.estado : null,
          stockUSD: inv && inv.stockUSD != null ? inv.stockUSD : null, // para desempate de orden §3.1.3
          accion: inv ? classifySkuOperationalProfile(inv) : null,     // reuso R4-LOCKED read-only
          // ═══ D2.b · campos del discriminador premium-lento (capaProducto · todos globales) ═══
          // diasSinVenta = el separador (se sigue vendiendo) · precioLista = la firma premium ·
          // ventaDiaria refuerza. Misma fuente ya leída · I-D2-DOS-CAPAS intacto (nada cruza la cuenta).
          diasSinVenta: inv && inv.diasSinVenta != null ? inv.diasSinVenta : null,
          precioLista: mk && mk.precioLista != null ? mk.precioLista : null,
          ventaDiaria: inv && inv.ventaDiaria != null ? inv.ventaDiaria : null,
        },
        _joinStatus: status,
      });
    }
    // ═══ D2.b · marca premium_slow (aditivo · NO altera capaProducto.accion) ═══
    if (typeof VOICE_D2B_PREMIUM_SLOW_ENABLED !== "undefined" && VOICE_D2B_PREMIUM_SLOW_ENABLED) {
      for (const s of out.skus) {
        s._premiumSlow = _d2ClassifyPremiumSlow(s.capaProducto) === "premium_slow";
      }
    }
  } catch (e) { /* defensivo · cero throw · out queda con lo computado */ }
  return out;
}

// ═══ ENCARGO D2.b · EL DIFERENCIADOR · premium-lento ≠ fuga (5 firmas founder) ═══
// En el cruce, un SKU que rota lento PERO se sigue vendiendo y es premium (ticket alto)
// NO se lee como fuga. Discriminador GENERAL por atributos (cero nombre de SKU · GD2b-5):
// rota lento ∧ diasSinVenta ≤ 30 (SE VENDE · GD2b-1) ∧ ticket alto (justifica · GD2b-2).
// Corre DESPUÉS de classifySkuOperationalProfile, que queda R4-LOCKED intacta (GD2b-3).
// off = byte-idéntico D2.a (SAM-TV55 vuelve a "rota a ritmo intermedio").
const VOICE_D2B_PREMIUM_SLOW_ENABLED = true;

// Piso de ticket = mediana de precioLista de la cartera ($206.67 · derivado del dato, no mágico).
// Justificación: SAM-TV55 ($665) la supera ampliamente; el AND con diasSinVenta≤30 hace el
// trabajo separador real — LG-DRYER8KG ($329) y MAK-COMP-AIR ($425) superan el piso pero
// caen por diasSinVenta (94/112) → NO premium_slow. El ticket solo justifica narrativamente
// por qué un premium rota lento; nunca salva una fuga (GD2b-2). Validado: SAM-TV55 único.
const _D2B_TICKET_FLOOR = 206.67;
const _D2B_DIAS_SIN_VENTA_MAX = 30;   // GD2b-1 · corte que R4 ya conoce (detectSkuPattern)

// ── _d2ClassifyPremiumSlow(cp) · NUEVO · aislado · NO toca R4 ──
// cp = capaProducto del join (global). Devuelve "premium_slow" | null.
// AND de tres: (1) lentitud real (rotacion baja O doh elevado) · (2) SE VENDE (diasSinVenta≤30)
// · (3) ticket alto (> piso). El (2) es el separador; (3) la justificación. PURO · cero throw.
function _d2ClassifyPremiumSlow(cp) {
  try {
    if (!cp || typeof cp !== "object") return null;
    const lento = (typeof cp.rotacion === "number" && cp.rotacion <= 4)
      || (typeof cp.doh === "number" && cp.doh >= 45);
    const seVende = (typeof cp.diasSinVenta === "number") && cp.diasSinVenta <= _D2B_DIAS_SIN_VENTA_MAX;
    const ticketAlto = (typeof cp.precioLista === "number") && cp.precioLista > _D2B_TICKET_FLOOR;
    return (lento && seVende && ticketAlto) ? "premium_slow" : null;
  } catch (e) { return null; }
}

// ── _d2CompareByProductPain(a, b) · comparador de orden §3.1 (GD2-8 · dolor de producto) ──
// Criterio compuesto, prioridad estricta: (1) peor margen asc · (2) peor rotación asc /
// doh desc · (3) mayor capital comprometido (stockUSD) desc · (4) severidad operacional.
// SOLO capaProducto · nunca capaCuenta · no cruza la frontera. Nulls al final (sin dato
// no se ordena como "lo peor"). Helper PURO testeable.
function _d2CompareByProductPain(a, b) {
  const pa = a.capaProducto || {}, pb = b.capaProducto || {};
  const SEV = { operational_inefficient: 0, borderline: 1, high_volume_healthy: 2 };
  const num = (x, dir) => (typeof x === "number") ? x : (dir === "asc" ? Infinity : -Infinity); // null al final
  // ═══ D2.b · GD2b-4 · premium_slow DESPUÉS de las fugas reales (no desaparece) ═══
  // "Un premium que todavía vende no duele igual que un SKU detenido" (founder). Un premium_slow
  // se ordena después de cualquier no-premium_slow del conjunto, aunque su margen sea peor.
  // Entre dos premium_slow, o entre dos no-premium_slow, sigue el orden §3.1 de D2.a intacto.
  const psA = !!a._premiumSlow, psB = !!b._premiumSlow;
  if (psA !== psB) return psA ? 1 : -1; // el premium_slow va detrás
  // 1 · peor margen primero (asc)
  if (num(pa.margen, "asc") !== num(pb.margen, "asc")) return num(pa.margen, "asc") - num(pb.margen, "asc");
  // 2 · peor rotación primero (asc)
  if (num(pa.rotacion, "asc") !== num(pb.rotacion, "asc")) return num(pa.rotacion, "asc") - num(pb.rotacion, "asc");
  // 3 · mayor capital comprometido (desc)
  if (num(pa.stockUSD, "desc") !== num(pb.stockUSD, "desc")) return num(pb.stockUSD, "desc") - num(pa.stockUSD, "desc");
  // 4 · mayor severidad operacional
  const sa = SEV[pa.accion] != null ? SEV[pa.accion] : 99, sb = SEV[pb.accion] != null ? SEV[pb.accion] : 99;
  return sa - sb;
}

// ── detectCrossSkuFollowUp(trimmed, conversationContext) · D2.a · PRE-DISPATCH ──
// null | { matched_marker }. Hermano de D1.b (léxico propio · disjunto · verificado).
// Disparo: token-producto + anclaje al hallazgo de cuentas + activeResult de cuentas
// (entityType "cliente" · entities>0 · frescura R3/R4 heredada) + exclusión AN. El verbo
// "perder" se captura en entrada · se prohíbe en salida (composer · GD2-2).
function detectCrossSkuFollowUp(trimmed, conversationContext) {
  try {
    if (typeof VOICE_D2_CROSS_ENABLED === "undefined" || !VOICE_D2_CROSS_ENABLED) return null;
    if (typeof trimmed !== "string" || !trimmed) return null;
    const ctx = conversationContext || {};
    const ar = ctx.activeResult;
    // hallazgo de CUENTAS servible (entityType cliente · EXACTO R3/R4)
    if (!ar || ar.entityType !== "cliente" || !Array.isArray(ar.entities) || ar.entities.length === 0) return null;
    const normalized = _normalizeSemanticText(trimmed);
    if (!normalized) return null;
    // token-producto
    const hasProductToken = /\b(sku|skus|producto|productos)\b/i.test(normalized);
    if (!hasProductToken) return null;
    // anclaje al hallazgo
    const anchors = ["de esas cuentas", "de esos clientes", "en esos clientes", "en esas cuentas",
                     "que venden esas cuentas", "esas cuentas", "esos clientes"];
    let matched = null;
    for (const a of anchors) { if (normalized.indexOf(a) >= 0) { matched = a; break; } }
    if (!matched) return null;
    // exclusión cross-dim AN (G8 · AN gana · single source)
    try {
      if (typeof detectAnCrossIntent === "function") {
        const _an = detectAnCrossIntent(trimmed, ctx, { type: "generic" }, { force_enabled: true });
        if (_an && _an.is_cross_intent) return null;
      }
    } catch (anErr) { /* defensivo */ }
    return { matched_marker: matched };
  } catch (e) { return null; }
}

// ── composeCrossSkuNarrative(activeResult, scenario) · D2.a · narra el cruce ──
// Por cuenta: SKUs ordenados por dolor de producto (§3.1), cada uno relacionando
// capaCuenta (ventas/ticket/participación) con capaProducto (margen/rotación) SIN
// fusionarlas. Voz bajo el oráculo (GD2-2): nunca "pierde en la cuenta". Escaneable.
function composeCrossSkuNarrative(activeResult, scenario) {
  const _fmtUSD = (v) => {
    if (typeof v !== "number" || isNaN(v)) return null;
    if (v >= 1000000) return `$${(v / 1000000).toFixed(2)}M`;
    if (v >= 1000) { const k = v / 1000; return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`; }
    return `$${Math.round(v)}`;
  };
  try {
    if (!activeResult || !Array.isArray(activeResult.entities) || activeResult.entities.length === 0) {
      return { opener: "No tengo un hallazgo de cuentas activo para cruzar con sus productos. ¿Rehacemos el análisis?",
               suggestions: [], sentrixAction: null, reasoningPattern: "cross_sku_reanchor", _d2: "reanchor" };
    }
    const cuentas = activeResult.entities;
    const porCuenta = {};
    const skusOrdenados = [];
    const bloques = [];
    for (const cuenta of cuentas) {
      const join = _d2JoinCuentaSku(cuenta);
      const ordenados = join.skus.slice().sort(_d2CompareByProductPain);
      porCuenta[cuenta] = { skus: ordenados, _supuesto: join._supuesto };
      for (const s of ordenados) skusOrdenados.push({ cuenta, nombre: s.nombre, capaProducto: s.capaProducto, _premiumSlow: !!s._premiumSlow });
      const lineas = [];
      for (const s of ordenados) {
        const cc = s.capaCuenta, cp = s.capaProducto;
        // capaCuenta: lo que le vendés (pertenece a la cuenta)
        const ventaStr = _fmtUSD(cc.ventas);
        const part = (typeof cc.participacion === "number") ? `${cc.participacion}% de lo que le vendés a ${cuenta}` : null;
        let linea = `${s.nombre} se vende en ${cuenta}${ventaStr ? ` por ${ventaStr}` : ""}${part ? ` (${part})` : ""}`;
        // capaProducto: margen + rotación (pertenecen al producto · GLOBAL) · oráculo de voz
        if (cp.margen != null) {
          linea += ` y a nivel producto tiene margen ${cp.margen}%`;
          if (cp.rotacion != null && cp.doh != null) {
            // ═══ D2.b · premium_slow: rota lento PERO se sigue vendiendo · no es fuga (GD2b-2/4) ═══
            if (s._premiumSlow) {
              const diasStr = (typeof cp.diasSinVenta === "number") ? `${cp.diasSinVenta} días sin venta` : "se sigue vendiendo";
              linea += `, rota lento (DOH ${cp.doh}), pero es premium de ticket alto y se sigue vendiendo (${diasStr}) — rotación esperable, no capital atrapado`;
            } else {
              const rotaLento = (cp.accion === "operational_inefficient");
              linea += rotaLento ? ` con rotación lenta (DOH ${cp.doh})` : ` y rota ${cp.rotacion >= 7 ? "sano" : "a ritmo intermedio"} (DOH ${cp.doh})`;
            }
          } else {
            linea += ` · sin dato de rotación para ${s.nombre}`;
          }
          linea += ".";
        } else if (cp.rotacion != null && cp.doh != null) {
          linea += ` · sin dato de margen para ${s.nombre}, rota ${cp.rotacion >= 7 ? "sano" : "lento"} (DOH ${cp.doh}).`;
        } else {
          linea += ` · sin dato de producto para ${s.nombre}.`;
        }
        lineas.push(linea);
      }
      bloques.push(`En ${cuenta}:\n${lineas.map(l => "· " + l).join("\n")}`);
    }
    const intro = `De lo que vendés en ${cuentas.length === 1 ? cuentas[0] : cuentas.slice(0, -1).join(", ") + " y " + cuentas[cuentas.length - 1]}, ordenado por el margen y la rotación del producto:`;
    const cierre = `El margen y la rotación son del producto a nivel portafolio · las ventas son de cada cuenta. Para profundizar puedo separar por familia, o mirar qué conviene hacer con los de peor rotación.`;
    return {
      opener: [intro, ...bloques, cierre].join("\n\n"),
      suggestions: (typeof filterTextualSuggestions === "function") ? filterTextualSuggestions([]) : [],
      sentrixAction: null,
      reasoningPattern: "cross_sku_development", _d2: "narrated",
      _crossSku: { porCuenta, skusOrdenados }, // consumido por el case del dispatch (firma C · anidado)
    };
  } catch (e) {
    return { opener: "No tengo un hallazgo de cuentas activo para cruzar con sus productos. ¿Rehacemos el análisis?",
             suggestions: [], sentrixAction: null, reasoningPattern: "cross_sku_reanchor", _d2: "reanchor_error" };
  }
}
// ═══ FIN ENCARGO D2.a · símbolos top-level ═══

// ════════════════════════════════════════════════════════════════════════════
// BRIEF L · RANKING EXTREMES + CROSS-METRIC RANKING
//
// Cierra FOUNDATION-REASONER. Cubre 3 familias de queries:
//   Familia A · ranking extremes (worst/best) por una métrica
//     ej: "¿quién es el peor cliente por margen?"
//   Familia B · cross-metric (ranking dim A, ordenado por dim B)
//     ej: "¿cuál del top 3 contribución tiene peor margen?"
//   Familia C · coreferencia implícita worst/best sobre lista heredada
//     ej: T1 "top 3 clientes" → T2 "y el peor de esos"
//
// Rollback granular: VOICE_RANKING_EXTREMES_ENABLED = false →
// comportamiento bitwise idéntico a post-FIX_K2 (queries "peor" caen a
// fallback honesto BRIEF K).
//
// Precedencia (decisión arquitecto D5): detector ranking-extremes corre
// DESPUÉS de detectIntent · solo si retorna "module" o "generic" · evita
// secuestro de rotation_dive / coverage_dive / mechanism_ranking.
// ════════════════════════════════════════════════════════════════════════════
const VOICE_RANKING_EXTREMES_ENABLED = true;

// RANKING_EXTREMES_METRICS · catálogo declarativo · canonical metric key →
// dataset source + field name + dominio + unidad. Documenta qué métricas el
// ════════════════════════════════════════════════════════════════════════════
// BRIEF P · ALPHA · SEMANTIC INTENT LAYER · P.A · CATÁLOGOS
//
// 4 catálogos top-level + 4 extractores + 1 normalizador.
//
// Decisiones del founder (FASE 2 autorizada):
//   D-P-1 · inserción dentro de detectIntent ANTES return final
//   D-P-2 · reutilizar dispatch existente · cero touch pipeline B
//   D-P-3 · crecimiento_yoy NO incluido (deuda BETA)
//   D-P-4 · marca/familia retornan null (NO mapeo forzado)
//   D-P-5 · vocabulario inicial 40 términos PyME-Chile
//
// Catálogos ajustados al runtime (V4 pre-flight):
//   · canonical_entityType usa "client"/"sku" (NO "cliente")
//   · ranking_key distingue de field (lección #L-RANKING-KEY-VS-FIELD-DISTINTOS)
//
// Cero touch arquitectónico · solo declaraciones top-level.
// Esta sub-fase NO se invoca runtime · solo infraestructura.
// P.B agrega composeSemanticIntent · P.C integra a detectIntent.
// ════════════════════════════════════════════════════════════════════════════

