// ── _normalizeSemanticText · lowercase + sin acentos + trim ──────────────
// Compatible con normalización del resto del codebase (M.B.4 patterns · etc).
function _normalizeSemanticText(text) {
  if (!text || typeof text !== "string") return "";
  return text
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}

// ═══ ENCARGO #D-SCOPE-SHIFT · CAMBIO DE FOCO CONVERSACIONAL · cero LLM ═══
// Cuando el usuario escribe "ahora productos" / "pasemos a inventario" / "volvamos a clientes"
// DENTRO del chat, ADI cambia el dominio al nuevo — en vez de quedar pegado al hilo viejo
// ("Las cuentas de ese análisis son Lider") o caer al fallback. EL FIX NO CONSTRUYE CONTINUIDAD
// NUEVA: produce la señal de dominio nuevo (derivedModule/derivedSku/derivedClient) que la regla
// eclContIsPureContinuation YA respeta ("intent nuevo gana"). El marcador de cambio es OBLIGATORIO
// (cláusula 2): "productos" solo NO dispara · "ahora productos" sí. off = byte-idéntico.
const ADI_SCOPE_SHIFT_ENABLED = true;

// marcadores de cambio (REQUERIDOS · sin uno de estos NO dispara · invariante I-SCOPE-MARCADOR)
const _SCOPE_SHIFT_MARKERS = [
  "ahora", "pasemos a", "pasa a", "cambiemos a", "cambia a",
  "volvamos a", "volve a", "de vuelta a", "y en", "veamos",
];

// dominios reconocidos → { entityDim, domain, painMetric } (painMetric = default sin métrica)
const _SCOPE_SHIFT_DOMAINS = [
  { re: /\b(productos?|skus?)\b/,          entityDim: "sku",     domain: "producto",   painMetric: "rotacion" },
  { re: /\b(inventario|stock|capital)\b/,  entityDim: "sku",     domain: "inventario", painMetric: "rotacion" },
  { re: /\b(clientes?|cuentas?|cartera)\b/, entityDim: "cliente", domain: "cliente",    painMetric: "margen" },
  { re: /\b(margenes?|margen|contribuci[oó]n)\b/, entityDim: "cliente", domain: "margenes", painMetric: "margen" },
  { re: /\b(ventas?|facturaci[oó]n)\b/,    entityDim: "cliente", domain: "ventas",     painMetric: "ventas" },
];

// ── detectScopeShift(trimmed, ctx) · ¿hay "[marcador] [dominio]"? ──
// Devuelve { domain, entityDim, painMetric, markerHit, domainHit } o null. EXIGE marcador + dominio
// (cláusula 2). El marcador debe APARECER ANTES del dominio en la frase (es un switch, no un drill).
function detectScopeShift(trimmed, ctx) {
  try {
    if (typeof ADI_SCOPE_SHIFT_ENABLED === "undefined" || !ADI_SCOPE_SHIFT_ENABLED) return null;
    const n = _normalizeSemanticText(trimmed);
    if (!n) return null;
    // 1. marcador de cambio presente (obligatorio)
    let markerHit = null, markerIdx = -1;
    for (const m of _SCOPE_SHIFT_MARKERS) {
      const idx = n.indexOf(m);
      if (idx >= 0 && (markerIdx < 0 || idx < markerIdx)) { markerHit = m; markerIdx = idx; }
    }
    if (!markerHit) return null; // sin marcador → NO dispara (drill/continuidad)
    // 2. dominio reconocido, mencionado DESPUÉS del marcador (el switch apunta al dominio)
    for (const d of _SCOPE_SHIFT_DOMAINS) {
      const mm = d.re.exec(n);
      if (mm && mm.index >= markerIdx) {
        return { domain: d.domain, entityDim: d.entityDim, painMetric: d.painMetric, markerHit, domainHit: mm[0] };
      }
    }
    return null; // marcador sin dominio reconocido → NO dispara
  } catch (e) { return null; }
}
// ═══ FIN ENCARGO #D-SCOPE-SHIFT · símbolos top-level ═══

// ── _extractEntities(normalizedText) → array de entidades reconocidas ────
// Retorna [{ key, canonical_entityType, matched_term }] · ordenado por orden
// de aparición en texto. Determinístico · primer match gana.
function _extractEntities(normalizedText) {
  if (!normalizedText) return [];
  const results = [];
  for (const [key, entity] of Object.entries(SEMANTIC_ENTITIES)) {
    for (const term of entity.vocabulary) {
      // word boundary para evitar matches parciales
      const re = new RegExp(`\\b${term.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i");
      if (re.test(normalizedText)) {
        results.push({
          key,
          canonical_entityType: entity.canonical_entityType,
          matched_term: term,
        });
        break; // primer match por entity · no duplicar
      }
    }
  }
  return results;
}

// ── _extractMetrics(normalizedText) → array de métricas reconocidas ──────
function _extractMetrics(normalizedText) {
  if (!normalizedText) return [];
  const results = [];
  for (const [key, metric] of Object.entries(SEMANTIC_METRICS)) {
    for (const term of metric.vocabulary) {
      const re = new RegExp(`\\b${term.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i");
      if (re.test(normalizedText)) {
        results.push({
          key,
          field: metric.field,
          ranking_key: metric.ranking_key,
          domain: metric.domain,
          matched_term: term,
        });
        break; // primer match por metric · no duplicar
      }
    }
  }
  return results;
}

// ── _extractQualifiers(normalizedText) → array de cualificadores ─────────
function _extractQualifiers(normalizedText) {
  if (!normalizedText) return [];
  const results = [];
  for (const [key, qual] of Object.entries(SEMANTIC_QUALIFIERS)) {
    for (const term of qual.vocabulary) {
      const re = new RegExp(`\\b${term.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i");
      if (re.test(normalizedText)) {
        results.push({
          key,
          direction: qual.direction || null,
          threshold: qual.threshold || null,
          state: qual.state || null,
          metric_inferred: qual.metric_inferred || null,
          driver_inferred: qual.driver_inferred || null,
          matched_term: term,
        });
        break;
      }
    }
  }
  return results;
}

// ── _extractIntents(normalizedText) → array de intent types ──────────────
// diagnosis_query usa vocabulary_starters (matchea inicio del texto).
// otros usan vocabulary_markers (matchea en cualquier parte).
function _extractIntents(normalizedText) {
  if (!normalizedText) return [];
  const results = [];
  for (const [key, intent] of Object.entries(SEMANTIC_INTENTS)) {
    let matched = false;
    if (intent.vocabulary_starters) {
      for (const term of intent.vocabulary_starters) {
        // startsWith de inicio del texto · maneja "¿que" tras strip
        const stripped = normalizedText.replace(/^[¿¡?!.,;:\s]+/, "");
        if (stripped.startsWith(term + " ") || stripped === term) {
          matched = true;
          break;
        }
      }
    }
    if (!matched && intent.vocabulary_markers) {
      for (const term of intent.vocabulary_markers) {
        const re = new RegExp(`\\b${term.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i");
        if (re.test(normalizedText)) {
          matched = true;
          break;
        }
      }
    }
    if (matched) {
      results.push({
        key,
        composer_hint: intent.composer_hint,
      });
    }
  }
  return results;
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF P · ALPHA · P.A · catálogos + helpers
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF P · ALPHA · SEMANTIC INTENT LAYER · P.B · COMPOSITOR
//
// composeSemanticIntent · 6 fases · ensambla intent sintético desde catálogos
// P.A · mapea a composer existente via _mapToComposer.
//
// Decisiones FASE 2 P.B:
//   D-P.B-1 · trapped_state sin entity infiere entity=sku
//   D-P.B-2 · bleeding_state sin entity infiere entity=cliente
//   D-P.B-3 · Caso 7 RECHAZADO (CLIENT_KEYWORDS PRIORIDAD 1 ya cubre)
//   D-P.B-4 · Caso 6 cross-metric con 2 metrics + 2 qualifiers asociados
//   D-P.B-5 · sin direccionalidad → null → fallback honesto
//   D-P.B-6 · precedencia _mapToComposer: 6 → 4 → 3 → 1 → 2 → 5
//
// Esta sub-fase NO se invoca runtime · solo símbolos top-level.
// P.C integra a detectIntent.
// ════════════════════════════════════════════════════════════════════════════

// ── _resolveMetric · lookup en SEMANTIC_METRICS por key ──────────────────
function _resolveMetric(metricKey) {
  if (!metricKey) return null;
  const metric = SEMANTIC_METRICS[metricKey];
  if (!metric) return null;
  return {
    key: metricKey,
    field: metric.field,
    ranking_key: metric.ranking_key,
    domain: metric.domain,
  };
}

// ── _resolveDirection · worst/best/null desde qualifiers ─────────────────
// Worst gana sobre best si ambos presentes (caso raro).
// low_magnitude implica direction=worst · high_magnitude implica direction=best.
function _resolveDirection(qualifiers) {
  if (!qualifiers || !qualifiers.length) return null;
  // Direction explícita
  const hasWorst = qualifiers.some(q => q.direction === "worst");
  const hasBest = qualifiers.some(q => q.direction === "best");
  if (hasWorst) return "worst";
  if (hasBest) return "best";
  // Threshold implícito
  const hasLow = qualifiers.some(q => q.threshold === "below_benchmark");
  const hasHigh = qualifiers.some(q => q.threshold === "above_benchmark");
  if (hasLow) return "worst";
  if (hasHigh) return "best";
  return null;
}

// ── _associateQualifiersToMetrics · heurística determinística Caso 6 ─────
// Para queries con 2 métricas + 2 qualifiers (uno worst/low · uno best/high):
// asocia cada qualifier al metric más CERCANO en el texto por proximidad
// de índice de matched_term.
//
// Returns: { low_metric, high_metric } o null si no se puede asociar.
// Determinístico · misma query → misma asociación bitwise.
function _associateQualifiersToMetrics(normalizedText, metrics, qualifiers) {
  if (!normalizedText || !metrics || metrics.length < 2 || !qualifiers || qualifiers.length < 2) {
    return null;
  }
  // Filtrar qualifiers que indican direccionalidad
  const directionals = qualifiers.filter(q =>
    q.direction === "worst" || q.direction === "best" ||
    q.threshold === "below_benchmark" || q.threshold === "above_benchmark"
  );
  if (directionals.length < 2) return null;

  // Clasificar low vs high entre los directionals
  const lowQuals = directionals.filter(q => q.direction === "worst" || q.threshold === "below_benchmark");
  const highQuals = directionals.filter(q => q.direction === "best" || q.threshold === "above_benchmark");
  if (lowQuals.length === 0 || highQuals.length === 0) return null; // necesitamos uno de cada

  // Tomar el primer match de cada · localizar indices en el texto normalizado
  const lowQ = lowQuals[0];
  const highQ = highQuals[0];
  const lowIdx = normalizedText.indexOf(lowQ.matched_term);
  const highIdx = normalizedText.indexOf(highQ.matched_term);
  if (lowIdx < 0 || highIdx < 0) return null;

  // Para cada metric · encontrar idx en texto y calcular distancia a cada qualifier
  const metricsWithIdx = metrics.slice(0, 2).map(m => ({
    metric: m,
    idx: normalizedText.indexOf(m.matched_term),
  }));
  // Asegurar todos tienen idx válido
  if (metricsWithIdx.some(m => m.idx < 0)) return null;

  // Asociar: cada qualifier al metric más cercano
  // Estrategia: distancia mínima · si empate · qualifier que aparece primero gana primero
  const distLowToM0 = Math.abs(metricsWithIdx[0].idx - lowIdx);
  const distLowToM1 = Math.abs(metricsWithIdx[1].idx - lowIdx);
  const distHighToM0 = Math.abs(metricsWithIdx[0].idx - highIdx);
  const distHighToM1 = Math.abs(metricsWithIdx[1].idx - highIdx);

  // Decisión por suma mínima · evita doble asignación a misma metric
  // Asignación A: low→M0 · high→M1 · costo = distLowToM0 + distHighToM1
  // Asignación B: low→M1 · high→M0 · costo = distLowToM1 + distHighToM0
  const costA = distLowToM0 + distHighToM1;
  const costB = distLowToM1 + distHighToM0;

  if (costA <= costB) {
    return {
      low_metric: metricsWithIdx[0].metric,
      high_metric: metricsWithIdx[1].metric,
    };
  } else {
    return {
      low_metric: metricsWithIdx[1].metric,
      high_metric: metricsWithIdx[0].metric,
    };
  }
}

// ── _mapToComposer · 6 casos · precedencia 6 → 4 → 3 → 1 → 2 → 5 ─────────
// Retorna intent shape compatible con dispatch pipeline B (V3 P.B audit).
// Si ningún caso matchea · retorna null (fallback honesto).
function _mapToComposer({ entity, metric, direction, qualifiers, metrics, association }) {
  // ── CASO 6 · cross-metric (cliente + 2 metrics + 2 qualifiers asociados) ──
  // Precedencia primero porque es más específico.
  if (
    entity && entity.canonical_entityType === "client" &&
    metrics && metrics.length >= 2 &&
    association && association.low_metric && association.high_metric
  ) {
    // Validar que ambas metrics tienen ranking_key (existen en RANKING_EXTREMES_METRICS)
    if (association.low_metric.ranking_key && association.high_metric.ranking_key) {
      return {
        type: "cross_metric_ranking",
        rankMetric: association.high_metric.ranking_key,
        rankDirection: "best",
        rankN: 3,
        sortMetric: association.low_metric.ranking_key,
        sortDirection: "worst",
        entityType: "client",
        _semantic_origin: true,
      };
    }
  }

  // ── CASO 4 · sku + trapped_state OR capital_inmovilizado ──
  if (
    entity && entity.canonical_entityType === "sku" &&
    (
      (metric && metric.field === "stockUSD") ||
      qualifiers.some(q => q.state === "trapped")
    )
  ) {
    return {
      type: "sku_operational",
      _semantic_origin: true,
    };
  }

  // ── CASO 3 · cliente + bleeding_state (driver_inferred=internal_commercial_load) ──
  // FIX_P_C_RUNTIME_RELOCATION · D-FIX-P.C-2 Opción 2c · mapea a MARGEN WORST
  // (NO carga best). Razón: INTERNAL_DRIVER_RULES["client.carga"] es stub ·
  // narrativa magistral M.B.1 vive en client.margen con driver internal_commercial_load
  // detectado por la rule client.margen · que ES la respuesta ejecutiva correcta
  // a "regalando puntos / comiendo margen" porque la causa raíz (carga comercial alta)
  // está dentro del driver de la narrativa Lider 21.5% firmada V_VISUAL.
  // Lección #L-CONSULTA-SEMANTICA-PUEDE-MAPEAR-A-METRICA-DISTINTA-VIA-DRIVER.
  if (
    entity && entity.canonical_entityType === "client" &&
    qualifiers.some(q => q.driver_inferred === "internal_commercial_load")
  ) {
    return {
      type: "ranking_extremes",
      direction: "worst",
      metric: "margen",
      entityType: "client",
      topN: 1,
      _semantic_origin: true,
    };
  }

  // ── CASO 1 · cliente + worst OR low_magnitude + metric con ranking_key ──
  if (
    entity && entity.canonical_entityType === "client" &&
    metric && metric.ranking_key &&
    (direction === "worst" || qualifiers.some(q => q.threshold === "below_benchmark"))
  ) {
    return {
      type: "ranking_extremes",
      direction: "worst",
      metric: metric.ranking_key,
      entityType: "client",
      topN: 1,
      _semantic_origin: true,
    };
  }

  // ── CASO 2 · cliente + best OR high_magnitude + metric con ranking_key ──
  if (
    entity && entity.canonical_entityType === "client" &&
    metric && metric.ranking_key &&
    (direction === "best" || qualifiers.some(q => q.threshold === "above_benchmark"))
  ) {
    return {
      type: "ranking_extremes",
      direction: "best",
      metric: metric.ranking_key,
      entityType: "client",
      topN: 1,
      _semantic_origin: true,
    };
  }

  // ── CASO 5 · sku + worst/low_magnitude + metric con ranking_key (rotacion · doh) ──
  if (
    entity && entity.canonical_entityType === "sku" &&
    metric && metric.ranking_key &&
    (direction === "worst" || qualifiers.some(q => q.threshold === "below_benchmark"))
  ) {
    return {
      type: "ranking_extremes",
      direction: "worst",
      metric: metric.ranking_key,
      entityType: "sku",
      topN: 1,
      _semantic_origin: true,
    };
  }

  // Sin match · ALPHA NO mapea · fallback honesto
  return null;
}

// ── composeSemanticIntent · función principal · 6 fases ──────────────────
// Retorna intent shape compatible con dispatch · o null si no se puede mapear.
//
// Disciplina: cero estado · función pura · determinístico bitwise.
function composeSemanticIntent(text, context) {
  // Guard básico
  if (!text || typeof text !== "string") return null;
  if (typeof VOICE_SEMANTIC_INTENT_LAYER_ENABLED !== "undefined" && !VOICE_SEMANTIC_INTENT_LAYER_ENABLED) {
    return null; // flag rollback · P.C declara la constante
  }

  // FASE 1 · normalizar + extraer componentes (helpers P.A)
  const normalized = _normalizeSemanticText(text);
  if (!normalized) return null;
  let entities = _extractEntities(normalized);
  let metrics = _extractMetrics(normalized);
  const qualifiers = _extractQualifiers(normalized);
  const intents = _extractIntents(normalized);

  // FASE 2 · inferencias semánticas (D-P.B-1 y D-P.B-2 firmadas)
  // Excepción documentada · NO regla general · qualifier infiere entity
  // SOLO cuando NO hay entity explícita en el texto.
  if (!entities.length) {
    if (qualifiers.some(q => q.state === "trapped")) {
      // D-P.B-1 · trapped_state sin entity → sku
      entities.push({
        key: "sku",
        canonical_entityType: "sku",
        matched_term: "(inferred)",
      });
    } else if (qualifiers.some(q => q.driver_inferred === "internal_commercial_load")) {
      // D-P.B-2 · bleeding_state sin entity → cliente
      entities.push({
        key: "cliente",
        canonical_entityType: "client",
        matched_term: "(inferred)",
      });
    } else if (
      // D-P.B-7 · Caso 6 cross-metric sin entity → cliente (runtime fix)
      // Trigger: ≥2 metrics + ≥2 qualifiers directionals (low + high)
      // Razón: cross_metric_ranking dispatch solo acepta entityType=client.
      // Queries naturales tipo "bajo margen pero alto volumen" sin "clientes".
      metrics.length >= 2 &&
      qualifiers.filter(q => q.direction === "worst" || q.threshold === "below_benchmark").length >= 1 &&
      qualifiers.filter(q => q.direction === "best" || q.threshold === "above_benchmark").length >= 1
    ) {
      entities.push({
        key: "cliente",
        canonical_entityType: "client",
        matched_term: "(inferred)",
      });
    }
  }
  // Inferencia de métrica desde qualifier si no hay explícita
  if (!metrics.length) {
    if (qualifiers.some(q => q.metric_inferred === "capital_inmovilizado")) {
      const inferredKey = "capital_inmovilizado";
      const inferredMetric = SEMANTIC_METRICS[inferredKey];
      if (inferredMetric) {
        metrics.push({
          key: inferredKey,
          field: inferredMetric.field,
          ranking_key: inferredMetric.ranking_key,
          domain: inferredMetric.domain,
          matched_term: "(inferred)",
        });
      }
    } else if (qualifiers.some(q => q.driver_inferred === "internal_commercial_load")) {
      const inferredKey = "carga_comercial";
      const inferredMetric = SEMANTIC_METRICS[inferredKey];
      if (inferredMetric) {
        metrics.push({
          key: inferredKey,
          field: inferredMetric.field,
          ranking_key: inferredMetric.ranking_key,
          domain: inferredMetric.domain,
          matched_term: "(inferred)",
        });
      }
    }
  }

  // FASE 3 · validar composición mínima
  if (!entities.length || !metrics.length) return null;

  // FASE 4 · resolver primarios + asociación cross-metric si aplica
  const primaryEntity = entities[0];
  const primaryMetric = metrics[0];
  const direction = _resolveDirection(qualifiers);
  // Asociación qualifier↔metric para Caso 6 · solo si hay 2 metrics y 2 qualifiers directionals
  const association = _associateQualifiersToMetrics(normalized, metrics, qualifiers);

  // FASE 5 · validar direccionalidad mínima (D-P.B-5)
  // Si NO hay direction explícita NI threshold NI state NI bleeding · null
  const hasDirectionality = direction !== null
    || qualifiers.some(q => q.state === "trapped")
    || qualifiers.some(q => q.driver_inferred === "internal_commercial_load")
    || _metricIsCapitalOnly(primaryMetric); // capital_inmovilizado implica trapped por dominio
  if (!hasDirectionality) return null;

  // FASE 6 · mapear a composer existente
  const intentShape = _mapToComposer({
    entity: primaryEntity,
    metric: primaryMetric,
    direction,
    qualifiers,
    metrics, // para Caso 6
    association, // para Caso 6
    intent: intents[0] || null,
  });

  return intentShape; // null si no mapeable · fallback honesto
}

// ── Helper interno · check de métrica que implica direccionalidad ────────
// capital_inmovilizado siempre implica "trapped" por naturaleza · si query
// es "qué SKUs tienen capital" sin qualifier · igual mapeable a Caso 4.
function _metricIsCapitalOnly(metric) {
  if (!metric || !metric.key) return false;
  return metric.key === "capital_inmovilizado";
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF P · ALPHA · P.B · composeSemanticIntent + helpers
// ════════════════════════════════════════════════════════════════════════════

// BRIEF P · ALPHA · P.C · flag de activación del compositor semántico.
// true por default (D-P.C-1 firmado founder · aliado con otros VOICE_*).
// Rollback granular: cambiar a false desactiva ALPHA · pipeline cae a
// fallback honesto idéntico pre-ALPHA.
const VOICE_SEMANTIC_INTENT_LAYER_ENABLED = true;


// composer SABE rankear. Si una métrica solicitada no aparece acá ·
// _detectMetricInText retorna null · cae a composeHonestUnavailable.
//
// Decisión arquitecto D2: clientes usan applyScenarioToClientesMargen (13
// clientes raw · NO truncado a top-10 con PROTECTED_CLIENTS).
// Decisión arquitecto D3: "SKU por margen" usa skusMargen.margen (dominio
// margenes · NO skuInventario.margenPct).
const RANKING_EXTREMES_METRICS = {
  // ── client metrics (dataset: applyScenarioToClientesMargen) ──
  contribucion: { entityType: "client", source: "clientesMargen", field: "contribucion", domain: "margenes", unit: "$" },
  margen:       { entityType: "client", source: "clientesMargen", field: "margen",       domain: "margenes", unit: "%" },
  ventas:       { entityType: "client", source: "clientesMargen", field: "venta",        domain: "ventas",   unit: "$" },
  carga:        { entityType: "client", source: "clientesMargen", field: "pctRebate",    domain: "margenes", unit: "%" },
  // ── sku metrics ──
  // rotacion / stockUSD / cobertura · dataset skuInventario
  rotacion:     { entityType: "sku",    source: "skuInventario",  field: "rotacion",     domain: "inventario", unit: "x" },
  stockUSD:     { entityType: "sku",    source: "skuInventario",  field: "stockUSD",     domain: "inventario", unit: "$" },
  cobertura:    { entityType: "sku",    source: "skuInventario",  field: "cobertura",    domain: "inventario", unit: "d" },
  doh:          { entityType: "sku",    source: "skuInventario",  field: "doh",          domain: "inventario", unit: "d" },
  // sku_margen / sku_contribucion · dataset skusMargen (decisión D3)
  sku_margen:       { entityType: "sku", source: "skusMargen", field: "margen",       domain: "margenes", unit: "%" },
  sku_contribucion: { entityType: "sku", source: "skusMargen", field: "contribucion", domain: "margenes", unit: "$" },
};

// REASONER_CAPABILITIES_CATALOG · declaración explícita de qué patrones de
// query el razonador determinístico SABE responder. Documentación + referencia.
// NO se invoca runtime · sirve para auditoría continua y para informar
// `_generateContextualAlternatives` sobre qué patterns proponer al founder.
//
// Cada entrada mapea un patrón conceptual a un handler del pipeline B.
const REASONER_CAPABILITIES_CATALOG = {
  // ── SKU ────────────────────────────────────────────────────────────────
  sku_ranking_by_capital:      { handler: "sku_operational",  example: "qué SKUs atrapan más capital" },
  sku_ranking_by_rotation:     { handler: "rotation_dive",    example: "SKUs con menor rotación" },
  sku_ranking_by_coverage:     { handler: "coverage_dive",    example: "SKUs con mayor cobertura" },
  sku_deep_dive:               { handler: "sku_deep_dive",    example: "detalle de LG-DRYER8KG" },
  sku_to_client:               { handler: "cognitive_action", example: "qué clientes lo compran" },
  exit_plan:                   { handler: "cognitive_action", example: "plan de salida de SAM-REF500L" },

  // ── Cliente ────────────────────────────────────────────────────────────
  client_ranking_by_contribution: { handler: "client_contribution_ranking", example: "top 3 clientes por contribución" },
  client_deep_dive:               { handler: "client",                       example: "perfil de Falabella" },
  client_to_sku:                  { handler: "cognitive_action",             example: "qué le vendemos a Falabella" },
  client_dependency_risk:         { handler: "cross_domain_query",           example: "clientes con mayor riesgo de dependencia" },
  growth_opportunity:             { handler: "growth_opportunity",           example: "oportunidades de crecimiento por cliente" },

  // ── Ad-hoc sobre lista (BRIEF G/H/I/J) ────────────────────────────────
  ad_hoc_sum:     { handler: "ad_hoc_reasoning", op: "sum",     example: "y esos cuánto suman" },
  ad_hoc_pct:     { handler: "ad_hoc_reasoning", op: "pct",     example: "a qué % corresponden del total" },
  ad_hoc_average: { handler: "ad_hoc_reasoning", op: "average", example: "y el promedio" },

  // ── Módulo / Cross-domain ─────────────────────────────────────────────
  module_overview:        { handler: "module",             example: "cómo está el negocio en ventas" },
  cross_domain_query:     { handler: "cross_domain_query", example: "panorama general del negocio" },
  mechanism_ranking:      { handler: "cross_domain_query", example: "cuál es el mecanismo más caro" },

  // ── Simulación ────────────────────────────────────────────────────────
  loss_simulation:        { handler: "simulation",            example: "qué pasa si pierdo a Falabella" },
  simulation_benchmark:   { handler: "cognitive_action",      example: "qué pasa si igualo benchmark" },

  // ── Análisis avanzados ────────────────────────────────────────────────
  product_contribution:   { handler: "product_contribution",   example: "contribución por producto" },
  product_dual_comparison:{ handler: "product_dual_comparison",example: "comparar ventas y margen del top SKU" },
  contextual_drilldown:   { handler: "contextual_drilldown",   example: "y por marca" },
};

// BRIEF N-bis · VOICE_REMOVE_TEXTUAL_SUGGESTIONS_ENABLED + filterTextualSuggestions
// movidos a línea ~447 (ANTES de GENERIC_RESPONSES) para evitar TDZ ·
// GENERIC_RESPONSES línea ~470 llama al helper en eval del objeto literal
// durante init del módulo. Ver comentario en sitio de declaración.

// Whitelist de intents previos CLIENTE que califican para herencia implícita.
// SOLO composers que pueblan lastClientList con lista plural (≥2 elementos).
// Nombres reales verificados runtime (H2 pre-flight).
const _IMPLICIT_RANKING_PRODUCERS_CLIENT = new Set([
  "client_contribution_ranking",
  "cross_domain_query",       // erosion/quality/dependency/fuga_distribuida
  "growth_opportunity",       // ranking oportunidades crecimiento
  "query_interpreter",        // FIX FOUNDATION-REASONER · QI con entityDim cliente
  "ad_hoc_reasoning",         // permite encadenar ad-hocs consecutivos
]);

// canInheritImplicitContext · función pura · evalúa si la herencia aplica.
// Retorna true SOLO si todos los guards pasan. Cualquier guard que falle
// retorna false silencioso (no error · cae al flow tradicional).
function canInheritImplicitContext(text, ctx, currentModule) {
  if (!VOICE_AD_HOC_IMPLICIT_INHERITANCE_ENABLED) return false;
  if (!ctx) return false;
  // Guard global · negative guard (común SKU + cliente)
  if (_IMPLICIT_GLOBAL_NEGATIVE_GUARD.test(text)) return false;

  // ── Rama SKU (BRIEF I) ────────────────────────────────────────────────
  const skuListOk    = ctx.lastSkuList && ctx.lastSkuList.length >= 2;
  const skuIntentOk  = _IMPLICIT_RANKING_PRODUCERS_SKU.has(ctx.lastIntent);
  // Cross-module guard SOLO para SKU (SKUs viven en inventario únicamente)
  const skuModuleOk  = !ctx.lastModuleAsked || ctx.lastModuleAsked === currentModule;
  const isSkuRanking = skuListOk && skuIntentOk && skuModuleOk;

  // ── Rama Cliente (BRIEF J · H3 fix: SIN cross-module guard) ───────────
  // Clientes cruzan módulos por naturaleza · derivedModule de composers
  // no refleja navegación física del founder (composers hardcodean a
  // "margenes" típicamente · pero founder puede estar en ventas).
  const clientListOk   = ctx.lastClientList && ctx.lastClientList.length >= 2;
  const clientIntentOk = _IMPLICIT_RANKING_PRODUCERS_CLIENT.has(ctx.lastIntent);
  const isClientRanking = VOICE_AD_HOC_REASONER_CLIENT_ENABLED
                          && clientListOk
                          && clientIntentOk;

  return isSkuRanking || isClientRanking;
}

// _getClientDataset · selecciona dataset scenario-aware según módulo.
// ventas → applyScenarioToClientesVentas · margenes → applyScenarioToClientesMargen.
function _getClientDataset(moduleContext, scenario) {
  if (moduleContext === "margenes") {
    return applyScenarioToClientesMargen(scenario);
  }
  return applyScenarioToClientesVentas(scenario);
}

// _getClientField · campo principal de agregación según módulo (H1 fix).
//   ventas → "actual" (facturación)
//   margenes → "contribucion"
function _getClientField(moduleContext) {
  return moduleContext === "margenes" ? "contribucion" : "actual";
}

// _getClientLabel · etiqueta narrativa según módulo.
function _getClientLabel(moduleContext) {
  return moduleContext === "margenes" ? "contribución" : "facturación";
}

// _resolveImplicitEntityType · desambiguación cuando ambas listas pobladas (H6).
// Tiebreaker default plural_sku cuando lastIntent es ad_hoc_reasoning (encadenamiento).
function _resolveImplicitEntityType(ctx) {
  if (!ctx) return "plural_sku";
  const skuListOk    = ctx.lastSkuList && ctx.lastSkuList.length >= 2;
  const clientListOk = ctx.lastClientList && ctx.lastClientList.length >= 2;

  if (skuListOk && clientListOk) {
    // Ambas pobladas · preferir según lastIntent en whitelist específico.
    // Si lastIntent === "ad_hoc_reasoning" (encadenamiento) · tiebreaker plural_sku.
    if (ctx.lastIntent !== "ad_hoc_reasoning") {
      if (_IMPLICIT_RANKING_PRODUCERS_CLIENT.has(ctx.lastIntent)) return "plural_client";
      if (_IMPLICIT_RANKING_PRODUCERS_SKU.has(ctx.lastIntent)) return "plural_sku";
    }
    return "plural_sku"; // tiebreaker default
  }
  if (clientListOk && _IMPLICIT_RANKING_PRODUCERS_CLIENT.has(ctx.lastIntent)) {
    return "plural_client";
  }
  return "plural_sku";
}

// ── composeAggregationSumClient ───────────────────────────────────────────
// Suma facturación/contribución según módulo · dataset runtime scenario-aware.
function composeAggregationSumClient(clientNames, moduleContext, scenario) {
  const dataset = _getClientDataset(moduleContext, scenario);
  if (!dataset || dataset.length === 0) {
    return composeHonestUnavailable("no tengo el dataset de clientes accesible en este momento.", moduleContext);
  }
  const selected = dataset.filter(c => clientNames.includes(c.nombre));
  if (selected.length === 0) {
    return composeHonestUnavailable(
      `no encuentro ninguno de los clientes (${clientNames.join(", ")}) en el dataset.`,
      moduleContext,
    );
  }
  const field = _getClientField(moduleContext);
  const label = _getClientLabel(moduleContext);
  const total = selected.reduce((sum, c) => sum + (c[field] || 0), 0);
  const opener =
    `Los ${selected.length} clientes (${selected.map(c => c.nombre).join(" · ")}) `
    + `suman ${_fmtAdHocK(total)} en ${label}.\n\n`
    + `*Confianza alta · cálculo determinístico sobre dataset runtime.*`;
  return {
    opener,
    // BRIEF N · D1 Opción A · suggestion truth contract
    // Slot 3 reemplaza "¿Quién es el peor de esos?" (huérfana · ranking-by-worst
    // no existe en pipeline) por interpolación dinámica del primer cliente del
    // set seleccionado. selected[0].nombre garantizado por guard línea 5477
    // (selected.length === 0 → composeHonestUnavailable early return).
    // Razona vía FASE 4 detectIntent → intent.type="client" → composeClientDeepDive.
    // Excepción autorizada (interpolación = misma categoría que opener dinámico).
    // BRIEF N-bis · Tipo A puro · suggestions filtradas (resultado: [])
    // Tipo B preservadas si existieran · UI guard length>0 oculta bloque vacío.
    suggestions: filterTextualSuggestions([
      "¿A qué % corresponden del total?",
      "¿Cuál es el promedio de esos?",
      `Profundizar en ${selected[0].nombre}`,
    ]),
    sentrixAction: {
      label: `Ver ${selected.length} clientes en ${moduleContext === "margenes" ? "Márgenes" : "Ventas"}`,
      moduleChip: moduleContext === "margenes" ? "Márgenes" : "Ventas",
      payload: {
        modulo: moduleContext,
        clientes: selected.map(c => c.nombre),
        skus: [],
        mechanismBanner: `Selección de ${selected.length} clientes`,
      },
    },
  };
}

// ── composeAggregationPctClient ───────────────────────────────────────────
// % que representan los clientes sobre el total del dataset scenario-aware.
function composeAggregationPctClient(clientNames, moduleContext, scenario) {
  const dataset = _getClientDataset(moduleContext, scenario);
  if (!dataset || dataset.length === 0) {
    return composeHonestUnavailable("no tengo el dataset de clientes accesible en este momento.", moduleContext);
  }
  const selected = dataset.filter(c => clientNames.includes(c.nombre));
  if (selected.length === 0) {
    return composeHonestUnavailable(
      `no encuentro ninguno de los clientes (${clientNames.join(", ")}) en el dataset.`,
      moduleContext,
    );
  }
  const field = _getClientField(moduleContext);
  const label = _getClientLabel(moduleContext);
  const selectedTotal = selected.reduce((sum, c) => sum + (c[field] || 0), 0);
  const allTotal = dataset.reduce((sum, c) => sum + (c[field] || 0), 0);
  const pct = allTotal > 0 ? (selectedTotal / allTotal * 100) : 0;
  const opener =
    `Los ${selected.length} clientes (${selected.map(c => c.nombre).join(" · ")}) `
    + `suman ${_fmtAdHocK(selectedTotal)} en ${label} · `
    + `equivalente al ${pct.toFixed(1)}% del total (${_fmtAdHocK(allTotal)}).\n\n`
    + `*Confianza alta · cálculo determinístico sobre dataset runtime.*`;
  return {
    opener,
    // BRIEF N · D1 Opción A · suggestion truth contract
    // Slot 3 reemplaza "¿Quién tiene el peor margen?" (huérfana · ranking-by-worst
    // no existe). Interpolación dinámica del primer cliente del set seleccionado.
    // selected[0].nombre garantizado por guard línea 5525.
    // BRIEF N-bis · Tipo A puro · suggestions filtradas
    suggestions: filterTextualSuggestions([
      "¿Cuánto suman entre todos?",
      "¿Cuál es el promedio de esos?",
      `Profundizar en ${selected[0].nombre}`,
    ]),
    sentrixAction: {
      label: `Ver ${selected.length} clientes en ${moduleContext === "margenes" ? "Márgenes" : "Ventas"}`,
      moduleChip: moduleContext === "margenes" ? "Márgenes" : "Ventas",
      payload: {
        modulo: moduleContext,
        clientes: selected.map(c => c.nombre),
        skus: [],
        mechanismBanner: `Selección de ${selected.length} clientes`,
      },
    },
  };
}

// ── composeAggregationAverageClient ───────────────────────────────────────
// Promedio bimétrica · campo principal + secundario según módulo.
//   ventas: facturación promedio + rebate% promedio
//   margenes: contribución promedio + margen% promedio
function composeAggregationAverageClient(clientNames, moduleContext, scenario) {
  const dataset = _getClientDataset(moduleContext, scenario);
  if (!dataset || dataset.length === 0) {
    return composeHonestUnavailable("no tengo el dataset de clientes accesible en este momento.", moduleContext);
  }
  const selected = dataset.filter(c => clientNames.includes(c.nombre));
  if (selected.length === 0) {
    return composeHonestUnavailable(
      `no encuentro ninguno de los clientes (${clientNames.join(", ")}) en el dataset.`,
      moduleContext,
    );
  }
  const field = _getClientField(moduleContext);
  const label = _getClientLabel(moduleContext);
  const avgPrimary = selected.reduce((sum, c) => sum + (c[field] || 0), 0) / selected.length;

  // Métrica secundaria · ventas → pctRebate · margenes → margen
  const secField = moduleContext === "margenes" ? "margen" : "pctRebate";
  const secLabel = moduleContext === "margenes" ? "margen" : "rebate";
  const avgSecondary = selected.reduce((sum, c) => sum + (c[secField] || 0), 0) / selected.length;

  const opener =
    `Los ${selected.length} clientes (${selected.map(c => c.nombre).join(" · ")}) `
    + `promedian ${_fmtAdHocK(avgPrimary)} en ${label} · ${secLabel} promedio ${avgSecondary.toFixed(1)}%.\n\n`
    + `*Confianza alta · cálculo determinístico sobre dataset runtime.*`;
  return {
    opener,
    // BRIEF N · D1 Opción A · suggestion truth contract
    // Slot 3 reemplaza "¿Quién es el peor de esos?" (huérfana).
    // selected[0].nombre garantizado por guard línea 5575.
    // BRIEF N-bis · Tipo A puro · suggestions filtradas
    suggestions: filterTextualSuggestions([
      "¿Cuánto suman entre todos?",
      "¿A qué % corresponden del total?",
      `Profundizar en ${selected[0].nombre}`,
    ]),
    sentrixAction: {
      label: `Ver ${selected.length} clientes en ${moduleContext === "margenes" ? "Márgenes" : "Ventas"}`,
      moduleChip: moduleContext === "margenes" ? "Márgenes" : "Ventas",
      payload: {
        modulo: moduleContext,
        clientes: selected.map(c => c.nombre),
        skus: [],
        mechanismBanner: `Selección de ${selected.length} clientes`,
      },
    },
  };
}

// ── detectAdHocOperation ──────────────────────────────────────────────────
// Detecta qué operación aritmética hacer sobre las entidades resueltas.
// Retorna { kind, entities } o null si no matchea ningún patrón core.
//
// Patrones cubiertos (BRIEF H · core 3):
//   · aggregation_pct_on_context · "qué % son" · "a qué % corresponden"
//   · aggregation_sum_on_context · "cuánto suman" · "total de esos"
//   · aggregation_average_on_context · "promedio de esos"
//
// H6 fix: paréntesis explícitos en alternancia · regex Pct más robusta.
function detectAdHocOperation(text, deicticResult) {
  if (!deicticResult || !deicticResult.resolved) return null;
  if (!deicticResult.entities || deicticResult.entities.length === 0) return null;

  // Patrón 1 · aggregation_pct_on_context
  // Match condicional: ("qué %" / "qué porcentaje" / "a qué %") OR (("representan"/"corresponden") AND ("%" / "porcentaje"))
  const pctDirect = /\b(qu[eé]\s+%|qu[eé]\s+porcentaje|a\s+qu[eé]\s+%)/i.test(text);
  const verbalPct = /\b(representan|corresponden|equivalen)\b/i.test(text)
                    && /(%|porcentaje)/i.test(text);
  if (pctDirect || verbalPct) {
    return { kind: "aggregation_pct_on_context", entities: deicticResult.entities };
  }

  // Patrón 2 · aggregation_sum_on_context
  // BRIEF J extensión aditiva · verbos cliente-específicos:
  //   · "cuánto suman" / "cuánto son" / "total" / "en total" (genérico · BRIEF H)
  //   · "cuánto facturaron" / "cuánto facturan" (ventas)
  //   · "cuánto contribuyen" / "cuánto aportan" (margenes)
  //   · "cuánto venden" / "cuánto vendieron"
  if (/\b(cu[aá]nto\s+(suman|son|facturan|facturaron|contribuyen|aportan|venden|vendieron|aportaron|contribuyeron)|total\s+de\s+esos|entre\s+todos|en\s+total)\b/i.test(text)) {
    return { kind: "aggregation_sum_on_context", entities: deicticResult.entities };
  }

  // Patrón 3 · aggregation_average_on_context
  // BRIEF I extensión aditiva · soporta queries implícitas sin deíctico:
  //   · "promedio de esos" / "media entre ellos" (explícito · BRIEF H)
  //   · "y el promedio" / "el promedio" / "promedio" (implícito · BRIEF I)
  //     solo cuando el contexto entrega entidades (deicticResult ya resuelto).
  const avgExplicit = /\b(promedio|media)\s+(de\s+esos|entre|de\s+ellos)\b/i.test(text);
  const avgImplicit = /\b(promedio|media)\b/i.test(text)
                      && !/\b(promedio|media)\s+(del?\s+(portafolio|m[oó]dulo|empresa|total|mes|a[nñ]o))/i.test(text);
  if (avgExplicit || avgImplicit) {
    return { kind: "aggregation_average_on_context", entities: deicticResult.entities };
  }

  return null;
}

// ── _fmtAdHocK ────────────────────────────────────────────────────────────
// Formateador K con decimal · patrón composers Ferrari · "$47.4K".
// Top-level porque los composers ad-hoc también son top-level.
function _fmtAdHocK(val) {
  if (val >= 1000) return `$${(val/1000).toFixed(1)}K`;
  return `$${Math.round(val)}`;
}

// ── composeHonestUnavailable ──────────────────────────────────────────────
// Honestidad epistémica · cuando la operación no se puede ejecutar.
// Parametrizado por moduleContext (H4) · suggestions específicas del módulo.
function composeHonestUnavailable(reason, moduleContext) {
  const moduleSuggestions = {
    inventario: [
      "¿Qué SKUs están atrapando más capital?",
      "¿Cuál es la rotación promedio del portafolio?",
      "¿Cuáles SKUs tienen mayor desalineación?",
    ],
    margenes: [
      "¿Qué clientes erosionan el margen?",
      "¿Cuál es el benchmark actual?",
      "¿Quién aporta más contribución?",
    ],
    ventas: [
      "¿Qué clientes crecen vs año anterior?",
      "¿Quiénes están bajo presupuesto?",
      "¿Cómo viene el GAP del módulo?",
    ],
  };
  const suggestions = moduleSuggestions[moduleContext] || moduleSuggestions.inventario;
  return {
    opener: `Para esa pregunta específica no puedo darte un cálculo directo · ${reason}\n\n¿Querés que profundice en alguno en particular?`,
    // BRIEF N-bis · Tipo A puro · suggestions filtradas
    suggestions: filterTextualSuggestions(suggestions),
    sentrixAction: null,
  };
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF K · GLOBAL HONEST FALLBACK · helpers + composer
//
// Intercepta queries no entendidas ANTES de que caigan a fallbacks engañosos
// (composeModuleOverview disfrazado · GENERIC_RESPONSES · routeSuggestion).
// Genera respuesta con honestidad epistémica + 3 alternativas contextuales
// + sentrixAction relacionado si el contexto permite (lastClientList /
// lastSkuList poblados).
//
// Cero LLM · cero inferencia probabilística · función pura determinística.
// Misma query + mismo context + mismo scenario → mismo fallback honesto.
// ════════════════════════════════════════════════════════════════════════════

// _isExplicitModuleOverviewQuery · función pura · regex helper.
// Retorna true si la query es explícitamente un pedido de overview de módulo
// ("cómo está · qué pasa en · resumen · panorama · vista general"). En la
// práctica · estas queries son interceptadas ANTES por la capa semántica V2
// (mechanism_scan_query · línea ~2573) → cross_domain_query. Este regex es
// red de seguridad para queries borderline que escapan la capa semántica.
//
// IMPORTANTE · normaliza acentos antes del test porque JavaScript \b trata
// caracteres acentuados (ó · á · é) como límites de palabra · lo que rompe
// matches como "cómo está". Mismo approach que detectIntent (línea ~4396).
function _isExplicitModuleOverviewQuery(text) {
  if (!text || typeof text !== "string") return false;
  const normalized = text
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
  const overviewPatterns = /\b(como\s+esta|que\s+pasa\s+en|resumen|panorama|vista\s+general)\b/i;
  return overviewPatterns.test(normalized);
}

// FIX #D-BARE-MODULE-WORD · detector ESTRICTO de palabra de módulo suelta.
// Match EXACTO del texto COMPLETO normalizado (no substring): el texto entero ES una palabra/sinónimo
// de módulo. "inventario" → true · "el inventario de Lider" → false (el texto completo no ES "inventario")
// · "inventario y ventas" → false (no es una palabra sola). Espejo de los patrones de module_entity
// (L2328-2330), SOLOS. Las frases con entidad ni llegan acá (detectores de cliente/SKU corren antes);
// este match exacto es defensa en profundidad adicional.
function _isBareModuleWord(text) {
  if (!text || typeof text !== "string") return false;
  const norm = text
    .toLowerCase()
    .trim()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")        // sin tildes
    .replace(/[¿?¡!.,;:]/g, "")             // sin puntuación
    .trim();
  const bareModulePatterns = [
    "inventario", "stock general", "stock",
    "ventas", "facturacion",
    "margenes", "margen general", "rentabilidad general", "mis margenes",
  ];
  return bareModulePatterns.includes(norm);  // match EXACTO del texto completo · NO .includes() de substring
}

// _moduleLabel · helper interno para chips Sentrix.
function _moduleLabel(modulo) {
  if (modulo === "ventas")     return "Ventas";
  if (modulo === "margenes")   return "Márgenes";
  if (modulo === "inventario") return "Inventario";
  return "Módulo";
}

// _generateContextualAlternatives · función pura determinística.
// Genera 3 alternativas válidas que el sistema SÍ sabe responder · priorizando
// alternativas ad-hoc cuando hay context con lista plural en memoria · luego
// alternativas por módulo · luego universales. Determinístico: misma entrada
// produce mismo array (no random).
function _generateContextualAlternatives(ctx, modulo, scenario) {
  const alternatives = [];
  const safeCtx = ctx || {};

  // Alternativa 1-2 · si hay context con lista plural · sugerir ad-hoc
  const hasClientList = Array.isArray(safeCtx.lastClientList) && safeCtx.lastClientList.length >= 2;
  const hasSkuList    = Array.isArray(safeCtx.lastSkuList)    && safeCtx.lastSkuList.length >= 2;

  if (hasClientList) {
    alternatives.push(`Cuánto suman entre todos los clientes del top`);
    alternatives.push(`Promedio del top de clientes`);
  } else if (hasSkuList) {
    alternatives.push(`Cuánto suman entre todos los SKUs del top`);
    alternatives.push(`Rotación promedio del top de SKUs`);
  }

  // Alternativa por módulo activo (capability conocida del razonador)
  if (modulo === "ventas") {
    alternatives.push(`Top clientes por contribución del escenario actual`);
  } else if (modulo === "margenes") {
    alternatives.push(`Clientes con erosión de margen`);
  } else if (modulo === "inventario") {
    alternatives.push(`SKUs que atrapan más capital`);
  }

  // Llenar hasta 3 con alternativas universales determinísticas
  const universal = [
    `Cómo está el negocio en ${_moduleLabel(modulo).toLowerCase()}`,
    `Top entidades del módulo activo`,
    `Panorama general del escenario ${scenario}`,
  ];
  let uIdx = 0;
  while (alternatives.length < 3 && uIdx < universal.length) {
    const next = universal[uIdx++];
    if (next && !alternatives.includes(next)) alternatives.push(next);
  }

  return alternatives.slice(0, 3);
}

// _maybeEmitSentrixAction · función pura · emite chip Sentrix si el contexto
// poblado permite filtrar entidades en el dashboard. Retorna null si no aplica.
function _maybeEmitSentrixAction(ctx, modulo) {
  const safeCtx = ctx || {};
  if (Array.isArray(safeCtx.lastClientList) && safeCtx.lastClientList.length >= 2) {
    return {
      type: "filter_clients",
      label: `Ver ${safeCtx.lastClientList.length} clientes en ${_moduleLabel(modulo)}`,
      moduleChip: _moduleLabel(modulo),
      payload: { clientes: safeCtx.lastClientList },
    };
  }
  if (Array.isArray(safeCtx.lastSkuList) && safeCtx.lastSkuList.length >= 2) {
    return {
      type: "filter_skus",
      label: `Ver ${safeCtx.lastSkuList.length} SKUs en Inventario`,
      moduleChip: "Inventario",
      payload: { skus: safeCtx.lastSkuList },
    };
  }
  return null;
}

// composeGlobalHonestFallback · composer determinístico de honestidad
// epistémica. Cero LLM · cero inferencia. Opener fijo + 3 alternativas
// contextuales + sentrixAction opcional. Suggestions = [] (post N-bis · Tipo A
// eliminado).
//
// Estructura del opener (3 bloques separados por \n\n para AdiBlocks):
//   Bloque 0 · header declarativo
//   Bloque 1 · lista de 3 alternativas con bullets ·
//   Bloque 2 · cierre itálico (honestidad epistémica · NO contiene "confianza"
//             para evitar matchear isConfianzaBlock en AdiBlocks)
//
// reasoningPattern · "global_honest_fallback" · permite telemetría posterior
// vía conversationContext.lastIntent.
// ════════════════════════════════════════════════════════════════════════════
// BRIEF M.B.4 · GLOBAL HONEST FALLBACK · VOICE REFACTOR
//
// Cambios respecto a versión anterior:
//   1. Detector out-of-domain acotado (D-MB4-2 · Opción C founder)
//      · 5 patterns regex obvios: clima · política · deportes · hora/fecha · comida
//      · Si matchea → narrativa especial sin alternativas de negocio
//      · Si NO matchea → flujo normal con 3 alternativas contextuales
//   2. Voz refactor (D-MB4-3 · Forma A founder)
//      · Apertura honesta sin "en este momento" hedge temporal
//      · 3 alternativas como lista bulleted (· separador sutil)
//      · Cierre conversacional · sin asterisco "Honestidad epistémica..."
//   3. Skip narrative_layer · F4 founder · NO emite narrative_signals/posture_hint
//      · FASE 5 detecta ausencia → skip automático
//
// Helpers _generateContextualAlternatives + _maybeEmitSentrixAction · LOCKED
// por BRIEF K · NO se tocan (D-MB4-1).
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// FIX_GREETING_LAYER · saludos cálidos + OOD escalado anti-robot
// Detecta saludos · responde con narrativa cálida que presenta ADI + caminos.
// Detecta OOD persistente (counter consecutiveOODCount en ctx) · responde con
// 4 variantes founder-firmadas + modo persistente al 5to+ · sin acusar patrón.
// RULE-VOICE-002 · dignidad sostenida · cero humor seco · cada negativa es
// marketing implícito desde ángulo distinto.
// ════════════════════════════════════════════════════════════════════════════

const VOICE_GREETING_LAYER_ENABLED = true;

// ── GREETING_PATTERNS · 7 patterns es/en ─────────────────────────────────
const GREETING_PATTERNS = [
  /^\s*(hola|holaaa|holi)\b/i,
  /^\s*(buenos?\s*días?|buenas\s*tardes?|buenas\s*noches?)\b/i,
  /^\s*(qué\s+tal|que\s+tal)\b/i,
  /^\s*(hey|ey)\b/i,
  /^\s*(buen\s*día)\b/i,
  /^\s*saludos?\s*$/i,
  /^\s*(hi|hello)\b/i,
];

// ── detectGreeting · determinístico · normaliza prefix whitespace ────────
function detectGreeting(text) {
  if (!text || typeof text !== "string") return false;
  return GREETING_PATTERNS.some(re => re.test(text.trim()));
}

// ── GREETING_RESPONSE · texto founder-firmado · cálido + caminos ─────────
const GREETING_RESPONSE = `Hola. Soy ADI · tu asesor para mirar el negocio con cifras y postura.

Algunos caminos para empezar:
· Panorama del negocio
· Quién es tu peor cliente por margen
· Qué harías este mes como gerente comercial

O preguntame lo que quieras · vemos.`;

// ── OOD_RESPONSE_VARIANTS · 4 textos founder-firmados literalmente ──────
// T1 · estándar · presenta dominio + invita
// T2 · variación dimensional · enumera capacidades
// T3 · variación valor · declara propósito
// T4 · transición a modo persistente con dignidad
// RULE-VOICE-002: cero mención de número de intentos · cada variante redirige
// al valor del producto desde ángulo distinto.
const OOD_RESPONSE_VARIANTS = [
  `Eso está fuera de lo que razono. Trabajo sobre datos del negocio y decisiones asociadas a ellos.

Si querés probar el motor · partamos por algo como: panorama del negocio o quién está generando mayor presión sobre el margen.`,

  `No trabajo sobre información externa como clima. Lo que sí puedo interpretar está adelante: cartera · márgenes · inventario y comportamiento del negocio.

Elegí un ángulo y lo razonamos.`,

  `Eso queda fuera de mi contexto actual. Donde agrego valor es entendiendo qué está pasando dentro del negocio y qué merece atención.

Por ejemplo: "¿qué harías este mes como gerente comercial?"`,

  `Todavía no entramos en una conversación de negocio. Cuando quieras · puedo partir desde cualquiera de estos caminos:

· Panorama del negocio
· Dónde se está perdiendo contribución
· Qué acciones priorizar este mes`,
];

// ── OOD_PERSISTENT_MODE · texto fijo T5+ · sin acusación · invita ────────
const OOD_PERSISTENT_MODE = `Todavía no veo una conversación relacionada con el negocio. Mi foco es transformar datos en lectura y decisiones.

Podemos partir por:
· Panorama del negocio
· Clientes con mayor presión de margen
· Qué haría este mes como gerente comercial`;

// ── selectOODResponse · selecciona variante según counter ────────────────
// count=1 → variant[0] · count=2 → [1] · count=3 → [2] · count=4 → [3] · 5+ → persistent
function selectOODResponse(consecutiveOODCount) {
  const c = (typeof consecutiveOODCount === "number" && consecutiveOODCount > 0) ? consecutiveOODCount : 1;
  if (c <= 1) return OOD_RESPONSE_VARIANTS[0];
  if (c === 2) return OOD_RESPONSE_VARIANTS[1];
  if (c === 3) return OOD_RESPONSE_VARIANTS[2];
  if (c === 4) return OOD_RESPONSE_VARIANTS[3];
  return OOD_PERSISTENT_MODE;
}

// ── OUT_OF_DOMAIN_PATTERNS · 5 patterns obvios (D-MB4-2 · Opción C) ──────
const OUT_OF_DOMAIN_PATTERNS = [
  /\b(clima|tiempo|lluvia|temperatura)\b/i,
  /\b(politica|elecciones|gobierno|presidente)\b/i,
  /\b(deporte|futbol|partido)\b/i,
  /\b(hora|fecha|dia\s+de\s+hoy)\b/i,
  /\b(comida|receta|cocinar)\b/i,
];

// ── isObviouslyOutOfDomain · detector determinístico ─────────────────────
// Normaliza NFD para matchear con o sin tildes ("política" → "politica").
// Acotado a casos obvios · gap registrado como #D-OUT-OF-DOMAIN-PATTERNS-LIMITADO.
function isObviouslyOutOfDomain(text) {
  if (!text || typeof text !== "string") return false;
  const normalized = text.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  return OUT_OF_DOMAIN_PATTERNS.some(p => p.test(normalized));
}

// ═══ ENCARGO D0.a · ANOMALÍA IMPLÍCITA DETERMINÍSTICA · cero LLM ═══
// Intercepta frases de anomalía/tensión que HOY caen a composeGlobalHonestFallback y las
// rutea a un composer EXISTENTE: con entidad → dive de la cuenta (ángulo anomaly) · sin
// entidad → el mecanismo MÁS MATERIAL del escenario (scanMechanisms · NO lista fija).
// SOLO captura si la anomalía es la intención DOMINANTE (gate de 6 pasos · léxico cerrado).
// off = byte-idéntico (el else-if no existe). NO crea composers, NO toca cifras, NO LLM.
const ADI_D0A_ANOMALY_ROUTER_ENABLED = true;

// ── léxico cerrado de anomalía (determinístico · auditable) ──
const _D0A_ANOMALY_MARKERS = [
  "raro", "extrano", "extraño", "no me cierra", "no cuadra", "no calza",
  "me preocupa", "no me gusta", "algo esta mal", "algo está mal",
  "algo no anda", "se ve mal", "no me suena", "no me cuadra",
];
// ── marcadores de LISTADO/RANKING (intención de enumerar · suprime D0.a) ──
const _D0A_LISTING_MARKERS = ["cuales son", "cuáles son", "muestrame los", "muéstrame los", "muestrame las", "lista de", "listame", "top ", "ranking", "cuales clientes", "qué clientes", "que clientes", "qué productos", "que productos"];
// ── marcadores de MEDIDA/CUANTIFICACIÓN (suprime D0.a) ──
const _D0A_MEASURE_MARKERS = ["cuanto", "cuánto", "que fraccion", "qué fracción", "representa", "cuantos", "cuántos", "cuanta", "cuánta"];
// ── exclusiones GD0-1 (fuera de D0.a por decisión firmada) ──
const _D0A_GD01_EXCLUSIONS = ["no me convence", "no entendi", "no entendí", "explicame", "explícame", "explica mejor"];

// ── _d0aDetectAnomalyMarker(n) · ¿hay patrón de anomalía? (sobre texto normalizado) ──
function _d0aDetectAnomalyMarker(n) {
  try {
    for (const m of _D0A_ANOMALY_MARKERS) if (n.indexOf(m) >= 0) return m;
    return null;
  } catch (e) { return null; }
}

// ── _d0aDominantGate(trimmed) · el gate de intención dominante (6 pasos · §4 aprobado) ──
// Devuelve { pass:true, marker } si la anomalía es dominante; { pass:false, suppressedBy } si no.
// ── _d0SuppressionGate(n) · pasos 1-4 COMPARTIDOS (causal/listing/measure/exclusión) ──
// El motor de supresión común a D0.a y D0.b (GD0b-1 cláusula 5 · reuso literal). Sobre texto
// ya normalizado. Devuelve { suppressed:true, by } si alguna ruta más fuerte aplica, o
// { suppressed:false } si pasa. NO chequea el patrón positivo (eso lo hace cada detector).
function _d0SuppressionGate(n) {
  try {
    if (!n) return { suppressed: true, by: "empty" };
    // paso 1 · marcador CAUSAL dominante (léxico del motor · cause_query)
    const causalMarkers = (typeof SEMANTIC_INTENTS !== "undefined" && SEMANTIC_INTENTS.cause_query
      && SEMANTIC_INTENTS.cause_query.vocabulary_markers) || [];
    for (const c of causalMarkers) if (n.indexOf(c) >= 0) return { suppressed: true, by: "causal:" + c };
    // paso 2 · marcador de LISTADO/RANKING dominante
    for (const l of _D0A_LISTING_MARKERS) if (n.indexOf(l) >= 0) return { suppressed: true, by: "listing:" + l };
    // paso 3 · marcador de MEDIDA/CUANTIFICACIÓN dominante (+ decision_query del motor)
    const decisionMarkers = (typeof SEMANTIC_INTENTS !== "undefined" && SEMANTIC_INTENTS.decision_query
      && SEMANTIC_INTENTS.decision_query.vocabulary_markers) || [];
    for (const d of _D0A_MEASURE_MARKERS.concat(decisionMarkers)) if (n.indexOf(d) >= 0) return { suppressed: true, by: "measure:" + d };
    // paso 4 · exclusiones GD0-1
    for (const x of _D0A_GD01_EXCLUSIONS) if (n.indexOf(x) >= 0) return { suppressed: true, by: "gd01:" + x };
    return { suppressed: false };
  } catch (e) { return { suppressed: true, by: "error" }; }
}

function _d0aDominantGate(trimmed) {
  try {
    const n = _normalizeSemanticText(trimmed);
    if (!n) return { pass: false, suppressedBy: "empty" };
    // pasos 1-4 · supresión compartida
    const sup = _d0SuppressionGate(n);
    if (sup.suppressed) return { pass: false, suppressedBy: sup.by };
    // paso 5 · ¿hay patrón de anomalía? (red de seguridad · si no, no es D0.a)
    const marker = _d0aDetectAnomalyMarker(n);
    if (!marker) return { pass: false, suppressedBy: "no_anomaly_marker" };
    // paso 6 · pasó todo → la anomalía es dominante
    return { pass: true, marker };
  } catch (e) { return { pass: false, suppressedBy: "error" }; }
}

// ── _d0aResolveMaterialMechanism(scenario) · el mecanismo MÁS MATERIAL (§5 · NO lista fija) ──
// Reusa scanMechanisms (Evidencia Única). Ranking: impacto $ absoluto → severidad → ID estable.
function _d0aResolveMaterialMechanism(scenario) {
  try {
    const scan = (typeof scanMechanisms === "function") ? scanMechanisms(scenario) : null;
    if (!scan) return null;
    // normalizar impacto económico a $K anuales desde el campo de agregado de cada mecanismo
    const _impactK = (id, m) => {
      const agg = (m && m.aggregate) || {};
      if (id === "commercial_erosion") {
        if (typeof agg.recuperable_total_K === "number") return agg.recuperable_total_K;
        if (typeof agg.recuperable_total_M_at_3_5 === "number") return agg.recuperable_total_M_at_3_5 * 1000;
      }
      if (id === "quality_of_growth_deterioration" && typeof agg.contribucion_perdida_M === "number") return agg.contribucion_perdida_M * 1000;
      if (id === "customer_dependency_risk" && typeof agg.top3_contribucion_M === "number") return agg.top3_contribucion_M * 1000;
      if (typeof agg.capital_inmovilizado_K === "number") return agg.capital_inmovilizado_K;
      if (typeof agg.total_stockUSD === "number") return agg.total_stockUSD / 1000;
      return 0;
    };
    const _maxSeverity = (m) => {
      const order = { critico: 3, crítico: 3, alto: 2, atencion: 1, atención: 1, bajo: 0 };
      let mx = -1;
      for (const inst of (m.instances || [])) { const s = order[inst.severity] != null ? order[inst.severity] : 0; if (s > mx) mx = s; }
      return mx;
    };
    // elegibles: triggered Y con composer existente (los 3 con composer dedicado + los de scan)
    const COMPOSER_EXISTS = ["commercial_erosion", "quality_of_growth_deterioration", "customer_dependency_risk", "trapped_capital", "liquidity_compression"];
    const elegibles = Object.entries(scan)
      .filter(([id, m]) => m && m.triggered && COMPOSER_EXISTS.indexOf(id) >= 0)
      .map(([id, m]) => ({ id, m, impactK: _impactK(id, m), severity: _maxSeverity(m) }));
    if (elegibles.length === 0) return null;
    // ranking determinístico: impacto $ desc → severidad desc → ID alfabético asc (tie-break estable)
    elegibles.sort((a, b) => {
      if (b.impactK !== a.impactK) return b.impactK - a.impactK;        // paso 1 · impacto absoluto
      if (b.severity !== a.severity) return b.severity - a.severity;     // paso 2 · severidad
      return a.id < b.id ? -1 : (a.id > b.id ? 1 : 0);                   // paso 4 · ID estable
    });
    const top = elegibles[0];
    const reason = top.impactK > 0 ? ("impacto_$" + Math.round(top.impactK) + "K")
      : (top.severity >= 0 ? "severidad" : "tie_break_id");
    return { mechanismId: top.id, materialityReason: reason, impactK: top.impactK };
  } catch (e) { return null; }
}

// ── detectAnomalyIntent(trimmed, ctx, scenario, modulo) · el router D0.a ──
// Devuelve null (no_match) | { route, response, debug }. route: "dive" | "mechanism" | "overview".
function detectAnomalyIntent(trimmed, ctx, scenario, modulo) {
  const debug = { matchedPattern: null, dominantIntentPassed: false, suppressedByStrongerRoute: false, strongerRouteDetected: null, hasEntity: false, entityResolved: null, materialitySelectedMechanism: null, materialityReason: null, routeDestination: null, fallbackPrevented: false, flagEnabled: true };
  try {
    if (typeof ADI_D0A_ANOMALY_ROUTER_ENABLED === "undefined" || !ADI_D0A_ANOMALY_ROUTER_ENABLED) { debug.flagEnabled = false; return null; }
    const gate = _d0aDominantGate(trimmed);
    debug.matchedPattern = gate.marker || null;
    if (!gate.pass) {
      debug.suppressedByStrongerRoute = !!(gate.suppressedBy && gate.suppressedBy !== "no_anomaly_marker" && gate.suppressedBy !== "empty");
      debug.strongerRouteDetected = gate.suppressedBy || null;
      return null; // no_match · el flujo normal continúa
    }
    debug.dominantIntentPassed = true;
    // (a) anomalía CON entidad → dive existente + ángulo anomaly
    const entity = (typeof detectClientInText === "function") ? detectClientInText(trimmed) : null;
    if (entity) {
      debug.hasEntity = true; debug.entityResolved = entity;
      const resp = getClientDeepDive(entity, scenario, { ...(ctx || {}), d0aAngle: "anomaly" });
      debug.routeDestination = "dive:" + entity; debug.fallbackPrevented = true;
      return { route: "dive", response: resp, debug };
    }
    // (b) anomalía SIN entidad → mecanismo MÁS MATERIAL (§5)
    const mat = _d0aResolveMaterialMechanism(scenario);
    if (mat && mat.mechanismId) {
      debug.materialitySelectedMechanism = mat.mechanismId; debug.materialityReason = mat.materialityReason;
      const resp = composeMechanismResponse(mat.mechanismId, scenario);
      debug.routeDestination = "mechanism:" + mat.mechanismId; debug.fallbackPrevented = true;
      return { route: "mechanism", response: resp, debug };
    }
    // (c) sin mecanismo elegible → overview material existente
    if (typeof composeModuleOverview === "function") {
      const resp = composeModuleOverview(scenario, modulo || "ventas");
      debug.routeDestination = "overview"; debug.fallbackPrevented = true;
      return { route: "overview", response: resp, debug };
    }
    // (d) nada seguro → dejar pasar al fallback honesto
    return null;
  } catch (e) { return null; }
}
// ═══ FIN ENCARGO D0.a · símbolos top-level ═══

// ═══ ENCARGO D0.b · OPORTUNIDAD DIFUSA DETERMINÍSTICA · cero LLM (GD0b-1) ═══
// Cuando el gerente insinúa OPORTUNIDAD/upside ("dónde gano más", "plata sobre la mesa",
// "margen que no capturo") y la frase cae al fallback, ADI rutea al UPSIDE recuperable
// (commercial_erosion · destino fijo · el único con recuperable). Reusa el gate de D0.a.
// Las 4 condiciones de honestidad: si no hay recuperable válido → fallback, NO inventa upside.
// Léxico DISJUNTO de D0.a (anomalía≠oportunidad). off = byte-idéntico (el else-if no existe).
const ADI_D0B_OPPORTUNITY_ROUTER_ENABLED = true;

// ── léxico de oportunidad (cerrado · DISJUNTO de _D0A_ANOMALY_MARKERS · §2) ──
const _D0B_OPPORTUNITY_MARKERS = [
  "dejando plata", "plata sobre la mesa", "no capturando", "margen que no",
  "ganar mas", "ganar más", "sacar mas", "sacar más", "aprovechar",
  "no estoy aprovechando", "plata que no estoy viendo", "plata que no veo",
  "oportunidad que me pierdo", "podriamos aprovechar", "podríamos aprovechar",
  "puedo ganar", "puedo sacar", "margen para mejorar",
];

// ── _d0bDetectOpportunityMarker(n) · ¿hay patrón de oportunidad? (texto normalizado) ──
function _d0bDetectOpportunityMarker(n) {
  try {
    for (const m of _D0B_OPPORTUNITY_MARKERS) if (n.indexOf(m) >= 0) return m;
    return null;
  } catch (e) { return null; }
}

// ── _d0bDominantGate(trimmed) · reusa el motor de supresión de D0.a (GD0b-1 cláusula 5) ──
// Mismos pasos 1-4 (causal/listing/measure/exclusión) vía _d0SuppressionGate; paso 5 con el
// léxico de OPORTUNIDAD en vez de anomalía.
function _d0bDominantGate(trimmed) {
  try {
    const n = _normalizeSemanticText(trimmed);
    if (!n) return { pass: false, suppressedBy: "empty" };
    const sup = _d0SuppressionGate(n); // pasos 1-4 COMPARTIDOS con D0.a
    if (sup.suppressed) return { pass: false, suppressedBy: sup.by };
    const marker = _d0bDetectOpportunityMarker(n);
    if (!marker) return { pass: false, suppressedBy: "no_opportunity_marker" };
    return { pass: true, marker };
  } catch (e) { return { pass: false, suppressedBy: "error" }; }
}

// ── _d0bResolveRecoverable(scenario) · las 4 condiciones de GD0b-1 (cláusula 3) ──
// Antes de rutear a commercial_erosion, chequear: (a) activo, (b) composer seguro,
// (c) evidencia, (d) recuperable válido. Si CUALQUIERA falla → null → fallback honesto.
function _d0bResolveRecoverable(scenario) {
  try {
    const scan = (typeof scanMechanisms === "function") ? scanMechanisms(scenario) : null;
    if (!scan) return null;
    const ce = scan["commercial_erosion"];
    if (!ce || !ce.triggered) return null;                              // (a) no activo
    if (typeof composeMechanismResponse !== "function") return null;    // (b) sin composer seguro
    if (!ce.instances || ce.instances.length === 0) return null;        // (c) sin evidencia
    const recuperable = ce.aggregate && ce.aggregate.recuperable_total_K;
    if (!recuperable || recuperable <= 0) return null;                  // (d) sin recuperable válido
    return { mechanism: "commercial_erosion", recuperable };            // upside válido
  } catch (e) { return null; }
}

// ── detectOpportunityIntent(trimmed, ctx, scenario, modulo) · el router D0.b ──
// Devuelve null (no_match) | { route, response, debug }.
function detectOpportunityIntent(trimmed, ctx, scenario, modulo) {
  const debug = { matchedPattern: null, dominantIntentPassed: false, suppressedBy: null, commercialErosionActive: false, recoverableAmount: null, fallbackHonestUsed: false, routeDestination: null, flagEnabled: true };
  try {
    if (typeof ADI_D0B_OPPORTUNITY_ROUTER_ENABLED === "undefined" || !ADI_D0B_OPPORTUNITY_ROUTER_ENABLED) { debug.flagEnabled = false; return null; }
    const gate = _d0bDominantGate(trimmed);
    debug.matchedPattern = gate.marker || null;
    if (!gate.pass) { debug.suppressedBy = gate.suppressedBy || null; return null; } // no_match
    debug.dominantIntentPassed = true;
    // las 4 condiciones de recuperable (GD0b-1 cláusula 3)
    const rec = _d0bResolveRecoverable(scenario);
    if (!rec) {
      // I-D0b-HONESTO · NO inventa upside · deja pasar al fallback honesto (GD0b-1 cláusula 4)
      debug.fallbackHonestUsed = true; debug.routeDestination = "fallback_honest";
      return null;
    }
    debug.commercialErosionActive = true; debug.recoverableAmount = rec.recuperable;
    const resp = composeMechanismResponse("commercial_erosion", scenario);
    debug.routeDestination = "mechanism:commercial_erosion";
    return { route: "mechanism", response: resp, debug };
  } catch (e) { return null; }
}
// ═══ FIN ENCARGO D0.b · símbolos top-level ═══

// ═══ ENCARGO D0.c · EXPLORACIÓN VAGA DETERMINÍSTICA · cero LLM (GD0c-1) ═══
// Cuando el gerente explora SIN dirección ("sorprendeme", "mostrame algo interesante",
// "qué debería mirar", "ayudame a entender el negocio") y la frase cae al fallback, ADI la
// rutea al PANORAMA transversal (composeMechanismScan · el mismo que "dame un panorama").
// Destino FIJO: todas las vagas convergen al mismo panorama (no se personaliza por frase).
// Léxico DISJUNTO de D0.a Y D0.b (frontera triple). Reusa el gate compartido SIN cambios.
// off = byte-idéntico (el else-if no existe). El ÚLTIMO corte de D0.
const ADI_D0C_EXPLORATION_ROUTER_ENABLED = true;

// ═══ FIX #D-FILTROS-PEGADOS · "Nueva sesión" limpia el contexto conversacional ═══
// El botón "Nueva sesión" (handleNewChat) limpiaba el chat y lo visual pero NUNCA
// llamaba setConversationContext → lastClientMentioned/activeThread/investigationDomain/
// lastClientList sobrevivían y contaminaban los turnos siguientes (el filtro pegado).
// Fix: una función canónica del contexto limpio, usada en handleNewChat Y en el
// reset-on-scenario (cierra de paso el gap de 3 campos). off = byte-idéntico (el bug sigue).
const ADI_SESSION_RESET_CLEARS_CONTEXT_ENABLED = true;

// _freshConversationContext() · ÚNICA fuente de verdad del contexto limpio.
// DEBE ser idéntico campo por campo al shape inicial del useState (es lo que la
// recarga dura restaura). 18 campos. Si el useState inicial cambia, esto cambia con él.
function _freshConversationContext() {
  return {
    lastClientMentioned: null,
    lastModuleAsked:     null,
    lastPanoramaDomain:  null,
    lastEvidencia:       null,
    turnCount:           0,
    lastClientMentionedTurn: 0,
    lastSkuMentionedTurn: 0,
    lastSkuMentioned:    null,
    lastSkuList:         [],
    lastClientList:      [],
    lastIntent:          null,
    investigationDomain:     null,
    investigationMetric:     null,
    investigationHypothesis: null,
    investigationLastIntent: null,
    investigationGoal:       null,
    activeThread:            null,
    consecutiveOODCount:     0,
  };
}

// ── léxico de exploración (cerrado · DISJUNTO de _D0A_ANOMALY_MARKERS y _D0B_OPPORTUNITY_MARKERS) ──
// NO incluye "qué me estoy perdiendo" (GD0c-1 cláusula 5 · ya rutea vía cross_domain).
const _D0C_EXPLORATION_MARKERS = [
  "mostrame algo", "mostrame algo interesante", "mostrame lo importante",
  "sorprendeme", "sorpréndeme", "que deberia mirar", "qué debería mirar",
  "que tengo que saber", "qué tengo que saber", "por donde miro", "por dónde miro",
  "por donde parto", "por dónde parto", "que hay de interesante", "qué hay de interesante",
  "ayudame a entender", "ayúdame a entender", "que es lo importante", "qué es lo importante",
];

// ── _d0cDetectExplorationMarker(n) · ¿hay patrón de exploración? (texto normalizado) ──
function _d0cDetectExplorationMarker(n) {
  try {
    for (const m of _D0C_EXPLORATION_MARKERS) if (n.indexOf(m) >= 0) return m;
    return null;
  } catch (e) { return null; }
}

// ── _d0cDominantGate(trimmed) · reusa el motor de supresión compartido (GD0c-1 cláusula 6) ──
// Mismos pasos 1-4 (causal/listing/measure/exclusión) vía _d0SuppressionGate; paso 5 con el
// léxico de EXPLORACIÓN. El marcador de listing es "muéstrame los" (con artículo) → "mostrame
// algo"/"mostrame lo importante" NO se suprimen falsamente.
function _d0cDominantGate(trimmed) {
  try {
    const n = _normalizeSemanticText(trimmed);
    if (!n) return { pass: false, suppressedBy: "empty" };
    const sup = _d0SuppressionGate(n); // pasos 1-4 COMPARTIDOS con D0.a y D0.b
    if (sup.suppressed) return { pass: false, suppressedBy: sup.by };
    const marker = _d0cDetectExplorationMarker(n);
    if (!marker) return { pass: false, suppressedBy: "no_exploration_marker" };
    return { pass: true, marker };
  } catch (e) { return { pass: false, suppressedBy: "error" }; }
}

// ── detectExplorationIntent(trimmed, ctx, scenario, modulo) · el router D0.c ──
// Devuelve null (no_match) | { route, response, debug }. Destino FIJO: composeMechanismScan.
function detectExplorationIntent(trimmed, ctx, scenario, modulo) {
  const debug = { matchedPattern: null, dominantIntentPassed: false, suppressedBy: null, routeDestination: null, flagEnabled: true };
  try {
    if (typeof ADI_D0C_EXPLORATION_ROUTER_ENABLED === "undefined" || !ADI_D0C_EXPLORATION_ROUTER_ENABLED) { debug.flagEnabled = false; return null; }
    const gate = _d0cDominantGate(trimmed);
    debug.matchedPattern = gate.marker || null;
    if (!gate.pass) { debug.suppressedBy = gate.suppressedBy || null; return null; } // no_match
    debug.dominantIntentPassed = true;
    // destino FIJO · el panorama transversal (GD0c-1 cláusula 1) · NO personaliza por frase
    if (typeof composeMechanismScan !== "function") return null; // seguridad · sin composer → fallback
    const resp = composeMechanismScan(scenario);
    debug.routeDestination = "panorama:composeMechanismScan";
    return { route: "panorama", response: resp, debug };
  } catch (e) { return null; }
}
// ═══ FIN ENCARGO D0.c · símbolos top-level ═══

// ════════════════════════════════════════════════════════════════════════════
// INTENT LAYER · átomos (§4) · lemas normalizados, NO frases. Lista corta y
// semántica por átomo. Se detectan por token/lema (reusa normalizeText).
// ════════════════════════════════════════════════════════════════════════════
const INTENT_MODULE_ATOMS = {
  ventas:       ["venta", "ventas", "vender", "facturacion", "facturo", "comercial"],
  margenes:     ["margen", "margenes", "rentabilidad", "rentable"],
  contribucion: ["contribucion", "contribuciones", "aporte", "aportes"],
  inventario:   ["inventario", "stock", "bodega", "bodegas", "almacen", "almacenes"],
  precio:       ["precio", "precios"],
  negocio:      ["negocio", "empresa", "compania", "panorama"],
};
const INTENT_METRIC_ATOMS = {
  venta:        ["venta", "ventas", "facturacion"],
  margen:       ["margen", "rentabilidad"],
  contribucion: ["contribucion", "aporte"],
  stock:        ["stock"],
  doh:          ["doh", "cobertura"],
  rotacion:     ["rotacion"],
  precio:       ["precio", "precios"],
};
// acciones VAGAS → overview (§6 regla de oro). Frases cortas · match por inclusión.
const INTENT_OVERVIEW_ATOMS = ["panorama", "resumen", "como esta", "como estan", "como va", "como van", "como viene", "como vienen", "que pasa con", "que tal", "como vamos", "como anda", "vista general", "dame"];
// acciones ESPECÍFICAS → tienen ruta sellada · la capa DEFIERE si las ve (§3/§12).
const INTENT_SPECIFIC_ACTION_ATOMS = ["compara", "comparar", "versus", " vs ", "contra", "ranking", "top ", "mejores", "peores", "peor", "mejor", "proyecta", "proyeccion", "cuanto vender", "cuanto debe vender", "para aportar", "para llegar", "por que", "porque", "explica", "detalle", "desglose", "cual es el", "cual es la"];

// token con borde de palabra (lema de una palabra) o inclusión (lema multi-palabra)
function _intentHasToken(norm, lema) {
  if (!lema) return false;
  if (lema.indexOf(" ") >= 0) return norm.indexOf(lema) >= 0;
  return new RegExp("(^|[^a-z0-9])" + lema + "([^a-z0-9]|$)").test(norm);
}

// ════════════════════════════════════════════════════════════════════════════
// resolveIntentLayer (§2-§10) · texto → intención → composer SELLADO, o null.
// NUNCA calcula. DEFIERE (null) ante entidad nombrada o acción específica (esas
// ya resolvieron arriba; defensivo). Solo dispara para módulo + acción vaga.
// ════════════════════════════════════════════════════════════════════════════
function resolveIntentLayer(text, scenario, context) {
  if (!FEATURE_INTENT_LAYER || !text || typeof text !== "string") return null;
  const norm = normalizeText(text);

  // 1 · Entidad específica nombrada → DEFIERE (rutas selladas la dueñan · §3/§12).
  if ((typeof detectClientInText === "function" && detectClientInText(text)) ||
      (typeof detectBrandInText === "function" && detectBrandInText(text)) ||
      (typeof detectSkuInText === "function" && detectSkuInText(text))) return null;
  for (const fam of SUPERFAMILIAS.slice(1)) { if (norm.indexOf(normalizeText(fam)) >= 0) return null; }
  for (const suc of SUCURSALES) { if (norm.indexOf(normalizeText(suc)) >= 0) return null; }

  // 2 · Acción específica (ranking/comparación/proyección/inversa/explicación/detalle) → DEFIERE.
  if (INTENT_SPECIFIC_ACTION_ATOMS.some(a => norm.indexOf(a.trim()) >= 0)) return null;

  // 3 · Detectar módulo y métrica por átomos (token/lema · no frase).
  let module = null, route_reason = [];
  for (const mod in INTENT_MODULE_ATOMS) {
    const hit = INTENT_MODULE_ATOMS[mod].find(l => _intentHasToken(norm, l));
    if (hit) { module = mod; route_reason.push("modulo:" + hit); break; }
  }
  let metric = null;
  for (const met in INTENT_METRIC_ATOMS) {
    const hit = INTENT_METRIC_ATOMS[met].find(l => _intentHasToken(norm, l));
    if (hit) { metric = met; route_reason.push("metrica:" + hit); break; }
  }
  const overviewHit = INTENT_OVERVIEW_ATOMS.find(a => norm.indexOf(a) >= 0);
  if (overviewHit) route_reason.push("accion:" + overviewHit);

  // 4 · Sin módulo NI métrica NI acción reconocida → fallback real (§10). La capa no reconoció nada.
  if (!module && !metric && !overviewHit) return null;

  // 5 · Ambigüedad de módulo (§8): sin módulo nombrado → métrica→su módulo, o módulo activo, o negocio.
  if (!module) {
    if (metric) {
      module = (metric === "margen" || metric === "contribucion") ? "margenes"
             : (metric === "stock" || metric === "doh" || metric === "rotacion") ? "inventario"
             : (metric === "precio") ? "precio" : "ventas";
      route_reason.push("modulo<-metrica");
    } else {
      const activo = (context && context.lastPanoramaDomain) ? context.lastPanoramaDomain : null;
      module = activo || "negocio";
      route_reason.push(activo ? "modulo<-activo" : "modulo<-negocio");
    }
  }

  // 6 · Regla de oro (§6): módulo claro + acción vaga = overview · entity null → cartera.
  const intent = { module, action: "overview", entity_type: "cartera", entity_name: null,
    metric: metric || null, confidence: overviewHit ? 0.92 : 0.8, route_reason };

  // 7 · Rutear a composer SELLADO (§7). NUNCA calcula.
  return _routeIntentToComposer(intent, scenario);
}

// rutea la intención resuelta a un composer existente · añade línea de confianza al pie (§9)
function _routeIntentToComposer(intent, scenario) {
  const _confLine = "\n\nConfianza determinística: alta.";
  const _wrap = (res) => {
    if (!res) return null;
    if (typeof res === "string") return { opener: res + _confLine, suggestions: [], sentrixAction: null };
    return { opener: (res.opener || "") + _confLine,
      suggestions: res.suggestions || [], sentrixAction: res.sentrixAction || null };
  };
  const mod = intent.module;
  // overview ventas/margen/inventario → composeModuleOverview (sellado)
  if (mod === "ventas" || mod === "margenes" || mod === "inventario") {
    return _wrap(composeModuleOverview(scenario, mod));
  }
  // contribución vive en el módulo margenes (clientesMargen carga venta+contribución+margen)
  if (mod === "contribucion") {
    return _wrap(composeModuleOverview(scenario, "margenes"));
  }
  // negocio general → tesis de negocio (sellado); si no hay tesis → declaración honesta, NO inventa
  if (mod === "negocio") {
    const thesis = (typeof composeBusinessThesisOpener === "function") ? composeBusinessThesisOpener(scenario) : null;
    if (thesis) return _wrap(thesis);
    return { opener: "El panorama del negocio se arma sobre tres módulos: ventas, margen e inventario. Decime cuál querés y te doy la vista completa." + _confLine,
      suggestions: (typeof filterTextualSuggestions === "function" ? filterTextualSuggestions(["Las ventas", "El margen", "El inventario"]) : ["Las ventas", "El margen", "El inventario"]),
      sentrixAction: null };
  }
  // precio: NO hay panorama de precio (es palanca sobre una entidad · §7 declara, no fabrica)
  if (mod === "precio") {
    return { opener: "El precio en ADI se analiza como palanca sobre una entidad puntual, no como panorama general. Puedo darte el panorama de ventas, margen o inventario, o el efecto de un cambio de precio sobre un cliente, familia o SKU." + _confLine,
      suggestions: (typeof filterTextualSuggestions === "function" ? filterTextualSuggestions(["El margen", "Las ventas"]) : ["El margen", "Las ventas"]),
      sentrixAction: null };
  }
  return null;   // módulo no ruteable → fallback real
}

// ════════════════════════════════════════════════════════════════════════════
// EARLY GATE v2 · resolveIntentLayerEarly (§3 · las 4 condiciones · TODAS deben
// cumplirse para ganar). Self-contained (NO toca resolveIntentLayer v1). Reusa los
// mismos átomos + detectores de entidad + _routeIntentToComposer. Si las 4 se
// cumplen → overview (vía composeModuleOverview/Thesis, igual que v1). Si no → null
// (la cascada sigue exacta, incluida la capa tardía v1).
// ════════════════════════════════════════════════════════════════════════════
function resolveIntentLayerEarly(text, scenario, context) {
  if (!FEATURE_INTENT_LAYER_EARLY || !text || typeof text !== "string") return null;
  const norm = normalizeText(text);

  // ── CONDICIÓN 4 · SIN OPERACIÓN ──
  // (a) endurecimiento crítico: toda operación avanzada lleva un número → DEFIERE
  //     (growth "si crece 10%", price "subo 5%", inversa "$2M" la dueñan). Los overviews no llevan dígitos.
  if (/\d/.test(norm)) return null;
  // (b) átomos de acción (vs/comparar/aportar/ranking/cuanto vender/proyecta/...) → DEFIERE.
  if (INTENT_SPECIFIC_ACTION_ATOMS.some(a => norm.indexOf(a.trim()) >= 0)) return null;

  // ── CONDICIÓN 3 · SIN ENTIDAD nombrada → DEFIERE (dive/comparación/inversa la dueñan) ──
  if ((typeof detectClientInText === "function" && detectClientInText(text)) ||
      (typeof detectBrandInText === "function" && detectBrandInText(text)) ||
      (typeof detectSkuInText === "function" && detectSkuInText(text))) return null;
  for (const fam of SUPERFAMILIAS.slice(1)) { if (norm.indexOf(normalizeText(fam)) >= 0) return null; }
  for (const suc of SUCURSALES) { if (norm.indexOf(normalizeText(suc)) >= 0) return null; }

  // ── CONDICIÓN 2 · VERBO/PREGUNTA VAGA (overview atom) REQUERIDO ──
  const overviewHit = INTENT_OVERVIEW_ATOMS.find(a => norm.indexOf(a) >= 0);
  if (!overviewHit) return null;

  // ── CONDICIÓN 1 · MÓDULO CLARO (átomo de módulo o métrica explícito) ──
  let module = null, route_reason = ["early"];
  for (const mod in INTENT_MODULE_ATOMS) {
    const hit = INTENT_MODULE_ATOMS[mod].find(l => _intentHasToken(norm, l));
    if (hit) { module = mod; route_reason.push("modulo:" + hit); break; }
  }
  let metric = null;
  for (const met in INTENT_METRIC_ATOMS) {
    const hit = INTENT_METRIC_ATOMS[met].find(l => _intentHasToken(norm, l));
    if (hit) { metric = met; route_reason.push("metrica:" + hit); break; }
  }
  if (!module) {
    if (metric) {
      module = (metric === "margen" || metric === "contribucion") ? "margenes"
             : (metric === "stock" || metric === "doh" || metric === "rotacion") ? "inventario"
             : (metric === "precio") ? "precio" : "ventas";
      route_reason.push("modulo<-metrica");
    } else {
      // módulo NO explícito · el early gate es quirúrgico → DEFIERE (la capa tardía v1 / ambigüedad lo maneja).
      return null;
    }
  }
  route_reason.push("accion:" + overviewHit);

  // Las 4 condiciones se cumplen → overview (regla de oro · entity=cartera). NUNCA calcula.
  const intent = { module, action: "overview", entity_type: "cartera", entity_name: null,
    metric: metric || null, confidence: 0.95, route_reason };
  return _routeIntentToComposer(intent, scenario);
}

function composeGlobalHonestFallback(query, conversationContext, modulo, scenario) {
  // ── FIX_GREETING_LAYER · Branch 1 · SALUDO ──────────────────────────────
  // Detección PRIMERA · prevalece sobre todo (incluso OOD patterns).
  // Counter no se modifica · saludo entre OOD preserva conteo.
  if (VOICE_GREETING_LAYER_ENABLED && detectGreeting(query)) {
    return {
      opener: GREETING_RESPONSE,
      suggestions: [],
      sentrixAction: null,
      reasoningPattern: "greeting",
      // SIN narrative_signals · SIN posture_hint · skip FASE 5
    };
  }

  // ── FIX_GREETING_LAYER · Branch 2 · OOD ESCALADO (sustituye legacy) ─────
  // Lee consecutiveOODCount del ctx (counter update vive en pipeline B).
  // Counter+1 = "este turno" · variant[0] cuando count actual es 0 (primer OOD).
  if (VOICE_GREETING_LAYER_ENABLED && isObviouslyOutOfDomain(query)) {
    const currentCount = (conversationContext?.consecutiveOODCount || 0) + 1;
    return {
      opener: selectOODResponse(currentCount),
      suggestions: [],
      sentrixAction: null,
      reasoningPattern: "out_of_domain_escalated",
      // SIN narrative_signals · SIN posture_hint · skip FASE 5
    };
  }

  // ── BRIEF M.B.4 · branch out-of-domain LEGACY (D-MB4-2 Opción C) ────────
  // Activo solo cuando VOICE_GREETING_LAYER_ENABLED=false (flag OFF rollback).
  // Narrativa especial · NO ofrece alternativas de negocio · invitación
  // genérica a reformular hacia el dominio comercial.
  if (isObviouslyOutOfDomain(query)) {
    const opener_ood = [
      `Eso no es algo que pueda razonar con los datos del negocio.`,
      ``,
      `Si querés algo del lado comercial · operacional o de inventario · cualquier pregunta sobre el escenario actual la tomo.`,
    ].join("\n");
    return {
      opener: applyVoiceCalibration(opener_ood, "explore"),
      // BRIEF N-bis · Tipo A puro · suggestions vacías
      suggestions: [],
      sentrixAction: null,  // sin acción · query no relacionada
      reasoningPattern: "global_honest_fallback_ood",
      // F4 founder · SIN narrative_signals · SIN posture_hint · skip FASE 5
    };
  }

  // ── Branch estándar · 3 alternativas contextuales (D-MB4-3 Forma A) ──
  const alternatives = _generateContextualAlternatives(conversationContext, modulo, scenario);
  const sentrixAction = _maybeEmitSentrixAction(conversationContext, modulo);

  const opener_std = [
    `No tengo evidencia determinística para responder eso · pero puedo ayudarte con caminos cercanos.`,
    ``,
    `Tres ángulos que sí puedo cubrir:`,
    `· ${alternatives[0]}`,
    `· ${alternatives[1]}`,
    `· ${alternatives[2]}`,
    ``,
    `Decime cuál te interesa · o reformulalo y vemos.`,
  ].join("\n");

  return {
    opener: applyVoiceCalibration(opener_std, "explore"),
    // BRIEF N-bis · Tipo A puro · suggestions vacías
    suggestions: [],
    sentrixAction,
    reasoningPattern: "global_honest_fallback",
    // F4 founder · SIN narrative_signals · SIN posture_hint · skip FASE 5
  };
}

// ── composeAggregationSum ─────────────────────────────────────────────────
// Suma stockUSD de los SKUs resueltos · cero LLM · dataset runtime.
function composeAggregationSum(skuNames, moduleContext, scenario) {
  const allSkus = applyScenarioToSkuInventario(scenario);
  if (!allSkus || allSkus.length === 0) {
    return composeHonestUnavailable("no tengo el dataset accesible en este momento.", moduleContext);
  }
  const selected = allSkus.filter(s => skuNames.includes(s.sku));
  if (selected.length === 0) {
    return composeHonestUnavailable(
      `no encuentro ninguno de los SKUs (${skuNames.join(", ")}) en el dataset.`,
      moduleContext,
    );
  }
  const total = selected.reduce((sum, s) => sum + (s.stockUSD || 0), 0);
  const opener =
    `Los ${selected.length} SKUs (${selected.map(s => s.sku).join(" · ")}) `
    + `suman ${_fmtAdHocK(total)} en capital comprometido.\n\n`
    + `*Confianza alta · cálculo determinístico sobre dataset runtime.*`;
  return {
    opener,
    // BRIEF N · D1 Opción A · suggestion truth contract
    // Slot 3 reemplaza "¿Cuál es el peor de esos?" (huérfana).
    // selected[0].sku garantizado por guard línea 5710.
    // Razona vía FASE 1 SKU interceptor (SKU canónico) → composeSkuDeepDive.
    // BRIEF N-bis · Tipo A puro · suggestions filtradas
    suggestions: filterTextualSuggestions([
      "¿A qué % corresponden del total?",
      "¿Cuál es la rotación promedio de esos?",
      `Profundizar en ${selected[0].sku}`,
    ]),
    sentrixAction: {
      label: `Ver ${selected.length} SKUs en Inventario`,
      moduleChip: "Inventario",
      payload: {
        modulo: "inventario",
        clientes: [],
        skus: selected.map(s => s.sku),
        mechanismBanner: `Selección de ${selected.length} SKUs`,
      },
    },
  };
}

// ── composeAggregationPct ─────────────────────────────────────────────────
// % que representan los SKUs sobre el total del inventario · scenario-aware.
function composeAggregationPct(skuNames, moduleContext, scenario) {
  const allSkus = applyScenarioToSkuInventario(scenario);
  if (!allSkus || allSkus.length === 0) {
    return composeHonestUnavailable("no tengo el dataset accesible en este momento.", moduleContext);
  }
  const selected = allSkus.filter(s => skuNames.includes(s.sku));
  if (selected.length === 0) {
    return composeHonestUnavailable(
      `no encuentro ninguno de los SKUs (${skuNames.join(", ")}) en el dataset.`,
      moduleContext,
    );
  }
  const selectedTotal = selected.reduce((sum, s) => sum + (s.stockUSD || 0), 0);
  const allTotal = allSkus.reduce((sum, s) => sum + (s.stockUSD || 0), 0);
  const pct = allTotal > 0 ? (selectedTotal / allTotal * 100) : 0;
  const opener =
    `Los ${selected.length} SKUs (${selected.map(s => s.sku).join(" · ")}) `
    + `suman ${_fmtAdHocK(selectedTotal)} en capital comprometido · `
    + `equivalente al ${pct.toFixed(1)}% del inventario total (${_fmtAdHocK(allTotal)}).\n\n`
    + `*Confianza alta · cálculo determinístico sobre dataset runtime.*`;
  return {
    opener,
    // BRIEF N · D1 Opción A · suggestion truth contract
    // Slot 3 reemplaza "¿Cuál tiene rotación más baja?" (huérfana).
    // selected[0].sku garantizado por guard línea 5753.
    // BRIEF N-bis · Tipo A puro · suggestions filtradas
    suggestions: filterTextualSuggestions([
      "¿Cuánto suman entre todos?",
      "¿Cuál es la rotación promedio de esos?",
      `Profundizar en ${selected[0].sku}`,
    ]),
    sentrixAction: {
      label: `Ver ${selected.length} SKUs en Inventario`,
      moduleChip: "Inventario",
      payload: {
        modulo: "inventario",
        clientes: [],
        skus: selected.map(s => s.sku),
        mechanismBanner: `Selección de ${selected.length} SKUs`,
      },
    },
  };
}

// ── composeAggregationAverage ─────────────────────────────────────────────
// Promedio de rotación + stock de los SKUs resueltos.
function composeAggregationAverage(skuNames, moduleContext, scenario) {
  const allSkus = applyScenarioToSkuInventario(scenario);
  if (!allSkus || allSkus.length === 0) {
    return composeHonestUnavailable("no tengo el dataset accesible en este momento.", moduleContext);
  }
  const selected = allSkus.filter(s => skuNames.includes(s.sku));
  if (selected.length === 0) {
    return composeHonestUnavailable(
      `no encuentro ninguno de los SKUs (${skuNames.join(", ")}) en el dataset.`,
      moduleContext,
    );
  }
  const avgRotacion = selected.reduce((sum, s) => sum + (s.rotacion || 0), 0) / selected.length;
  const avgStock = selected.reduce((sum, s) => sum + (s.stockUSD || 0), 0) / selected.length;
  const opener =
    `Los ${selected.length} SKUs (${selected.map(s => s.sku).join(" · ")}) `
    + `promedian rotación ${avgRotacion.toFixed(1)}x · stock promedio ${_fmtAdHocK(avgStock)}.\n\n`
    + `*Confianza alta · cálculo determinístico sobre dataset runtime.*`;
  return {
    opener,
    // BRIEF N · D1 Opción A · suggestion truth contract
    // Slot 2 reemplaza "¿Cuál tiene rotación más baja?" (huérfana) por la antigua
    // slot 3 "¿A qué % corresponden del total?" · slot 3 toma interpolación dinámica.
    // selected[0].sku garantizado por guard línea 5798.
    // BRIEF N-bis · Tipo A puro · suggestions filtradas
    suggestions: filterTextualSuggestions([
      "¿Cuánto suman entre todos?",
      "¿A qué % corresponden del total?",
      `Profundizar en ${selected[0].sku}`,
    ]),
    sentrixAction: {
      label: `Ver ${selected.length} SKUs en Inventario`,
      moduleChip: "Inventario",
      payload: {
        modulo: "inventario",
        clientes: [],
        skus: selected.map(s => s.sku),
        mechanismBanner: `Selección de ${selected.length} SKUs`,
      },
    },
  };
}

// ── composeAdHocReasoning ─────────────────────────────────────────────────
// Dispatcher principal · recibe operation + context + scenario · ejecuta.
// H5: plural_client retorna honest_unavailable (diferido a BRIEF I).
function composeAdHocReasoning(operation, context, scenario, entityType) {
  if (!operation || !operation.kind || !operation.entities || operation.entities.length === 0) {
    return composeHonestUnavailable("la operación está incompleta.", "inventario");
  }
  // BRIEF J · plural_client habilitado · enrutamiento por entityType.
  if (entityType === "plural_client") {
    if (!VOICE_AD_HOC_REASONER_CLIENT_ENABLED) {
      return composeHonestUnavailable(
        "el razonador ad-hoc sobre clientes no está habilitado.",
        "margenes",
      );
    }
    // Determinar moduleContext para clientes desde lastModuleAsked si disponible.
    // Default: margenes (composers de ranking cliente típicamente setean margenes).
    // Si lastModuleAsked es "ventas" · usar ventas. Si es otro · default margenes.
    const clientModule = (context && context.lastModuleAsked === "ventas")
                         ? "ventas"
                         : "margenes";
    switch (operation.kind) {
      case "aggregation_sum_on_context":
        return composeAggregationSumClient(operation.entities, clientModule, scenario);
      case "aggregation_pct_on_context":
        return composeAggregationPctClient(operation.entities, clientModule, scenario);
      case "aggregation_average_on_context":
        return composeAggregationAverageClient(operation.entities, clientModule, scenario);
      default:
        return null;
    }
  }
  // plural_sku · BRIEF H existente · cero cambio.
  const moduleContext = "inventario";
  switch (operation.kind) {
    case "aggregation_sum_on_context":
      return composeAggregationSum(operation.entities, moduleContext, scenario);
    case "aggregation_pct_on_context":
      return composeAggregationPct(operation.entities, moduleContext, scenario);
    case "aggregation_average_on_context":
      return composeAggregationAverage(operation.entities, moduleContext, scenario);
    default:
      return null;
  }
}

// ════════════════════════════════════════════════════════════════════════════
// FASE 1.5.B-HOTFIX-3 · COMPOSER client_metric_followup
//
// Compone respuesta enfocada en UNA métrica de UN cliente · NO deep dive.
// Voz V3 firmada · precisión analítica sobre frases formulaicas.
//
// Métricas cubiertas (HOTFIX-3 alcance inicial):
//   - carga    · rebate/pctRebate sobre ventas
//   - margen   · % margen vs benchmark + vs avg cartera
//   - contribucion · $ contribución absoluta + % cartera
//   - ventas   · $ facturación + % cartera + ratio contribución
//
// Métricas diferidas (BRIEF futuro · pedirá el founder):
//   - rotacion, cobertura (módulo inventario · requieren skusInventario)
//
// Helpers internos del composer · cifras runtime sobre dataset.
// ════════════════════════════════════════════════════════════════════════════
function composeClientMetricFollowUp(clientName, metricKey, scenario, modulo) {
  // FASE 1.5.B-HOTFIX-3-PATCH-3 · cross-dataset
  // ADI como asesor opera a nivel negocio (no limitado por módulo visible) ·
  // coherente con #DIRECCION-FUTURA-RESUMEN-EJECUTIVO-DUAL firmada.
  // Los followups métricos (carga, margen, contribución, ventas) son 
  // preguntas cross-dominio · siempre leen clientesMargen que tiene shape 
  // completo (todos los 13 clientes con todos los fields).
  //
  // Sentrix action sigue apuntando al módulo correcto según métrica:
  //   carga, margen, contribucion → Márgenes (donde viven los datos)
  //   ventas → Ventas (cifra runtime canónica)
  const dataset = applyScenarioToClientesMargen(scenario);

  const c = dataset.find(x => x.nombre === clientName);
  if (!c) {
    return {
      opener: `No tengo a ${clientName} en el detalle de la cartera de este escenario.`,
      suggestions: filterTextualSuggestions([
        "Cuéntame de Falabella",
        "Cuéntame de Lider",
        "Cuéntame de Jumbo",
      ]),
      sentrixAction: null,
    };
  }

  // Promedios de cartera · benchmarks internos
  const avgCarga = dataset.reduce((s, x) => s + (x.pctRebate || 0), 0) / dataset.length;
  const avgMargen = dataset
    .filter(x => x.margen !== null && x.margen !== undefined)
    .reduce((s, x, _, arr) => s + x.margen / arr.length, 0);
  const benchmark = c.benchmark || 30.1;

  let opener = "";
  let suggestions = [];
  let sentrixAction = null;

  // ── Rama CARGA / REBATE ─────────────────────────────────────────────────
  if (metricKey === "carga") {
    const gapVsAvg = c.pctRebate - avgCarga;
    const totalCarga = c.rebates;

    opener = `La carga comercial de ${c.nombre} es **${c.pctRebate}%** · ${Math.abs(gapVsAvg).toFixed(1)} puntos ${gapVsAvg >= 0 ? "sobre" : "bajo"} el promedio de la cartera (${avgCarga.toFixed(1)}%).\n\n`;
    opener += `En valor absoluto representa **$${(totalCarga/1000).toFixed(2)}M anuales** de rebate sobre ventas de $${(c.venta/1000).toFixed(1)}M. `;

    // Thresholds calibrados · D-1.5.B-HOTFIX-3-VOZ-CARGA-MODERADA firmada
    if (gapVsAvg >= 2) {
      opener += `Es de las cuentas más caras de la cartera · cada punto de rebate aquí cuesta más porque el cliente concentra volumen.\n\n`;
      opener += `**Mecanismo disponible**: la lectura natural es si ese ${c.pctRebate}% retorna volumen incremental al benchmark o solo compensa presión comercial sin upside.`;
    } else if (gapVsAvg > 0.3) {
      // FRASE FOUNDER FIRMADA
      opener += `Se ubica moderadamente sobre el promedio de cartera · no explica por sí sola todo el deterioro, pero sí refuerza la necesidad de revisar la carga comercial.`;
    } else if (gapVsAvg < -1) {
      opener += `Es una de las cuentas con carga más liviana · margen libre para crecer comercialmente sin deterioro.`;
    } else {
      opener += `Está en línea con el promedio · sin presión particular de renegociación pero tampoco margen estructural.`;
    }
    opener += `\n\n*Confianza alta · cifras runtime sobre escenario ${scenario}.*`;

    suggestions = filterTextualSuggestions([
      `Compara la carga de ${c.nombre} con el resto`,
      `¿Cuánto recupero si bajo 1 punto?`,
      "Ver Top clientes por carga",
    ]);
    sentrixAction = {
      label: `↗ Ver ${c.nombre}`,
      payload: { module: "margenes", focus: "carga", client: c.nombre },
      moduleChip: "Márgenes",
    };
  }

  // ── Rama MARGEN ─────────────────────────────────────────────────────────
  else if (metricKey === "margen") {
    if (c.margen === null || c.margen === undefined) {
      opener = `No tengo margen consolidado de ${c.nombre} en el módulo actual · si querés revisarlo, cambiá a Márgenes.`;
      suggestions = filterTextualSuggestions([
        `Cuéntame de ${c.nombre} en márgenes`,
        "Top clientes por margen",
      ]);
      return { opener, suggestions, sentrixAction: null };
    }

    const gapVsBench = c.margen - benchmark;
    const gapVsAvgInternal = c.margen - avgMargen;

    opener = `${c.nombre} opera con margen **${c.margen}%** · ${Math.abs(gapVsBench).toFixed(1)} puntos ${gapVsBench >= 0 ? "sobre" : "bajo"} el benchmark de industria (${benchmark}%).\n\n`;
    opener += `Frente al promedio interno de la cartera (${avgMargen.toFixed(1)}%), está ${Math.abs(gapVsAvgInternal).toFixed(1)}pp ${gapVsAvgInternal >= 0 ? "arriba" : "debajo"}. `;

    if (gapVsBench < -3) {
      const destruccion = Math.round(c.venta * (benchmark - c.margen) / 100);
      opener += `La cuenta está sub-rentabilizando: aproximadamente **$${destruccion}K anuales** de contribución no capturada por estar bajo benchmark.\n\n`;
      opener += `**Mecanismo disponible**: el cruce margen vs carga comercial es la lectura natural · si ${c.nombre} tiene carga sobre promedio (${avgCarga.toFixed(1)}%), la palanca de rebate opera antes que la de precio.`;
    } else if (gapVsBench >= 0) {
      opener += `La cuenta es estructuralmente rentable · sostiene el promedio de la cartera.`;
    } else {
      opener += `Margen razonable pero hay espacio · existen 2 palancas disponibles: composición del mix y carga comercial.`;
    }
    opener += `\n\n*Confianza alta · cifras runtime sobre escenario ${scenario}.*`;

    suggestions = filterTextualSuggestions([
      `¿Por qué ${c.nombre} está bajo benchmark?`,
      `Compara con Jumbo`,
      "Ver erosión de margen",
    ]);
    sentrixAction = {
      label: `↗ Ver ${c.nombre}`,
      payload: { module: "margenes", focus: "margen", client: c.nombre },
      moduleChip: "Márgenes",
    };
  }

  // ── Rama CONTRIBUCIÓN ───────────────────────────────────────────────────
  else if (metricKey === "contribucion") {
    // FASE 1.5.B-HOTFIX-3 · Honest fail si dataset no tiene contribución
    // (módulo ventas trae clientesVentas que NO expone contribucion · solo
    // clientesMargen sí). Evita reportar "$0.00M" engañoso.
    if (!c.contribucion || c.contribucion === 0) {
      opener = `No tengo contribución consolidada de ${c.nombre} en el módulo actual · ese dato vive en Márgenes. Si querés revisarlo, cambiá a Márgenes y vuelvo a calcular.`;
      suggestions = filterTextualSuggestions([
        `Cuéntame de ${c.nombre} en márgenes`,
        "Top contribuciones",
      ]);
      return { opener, suggestions, sentrixAction: null };
    }
    const totalCartera = dataset.reduce((s, x) => s + (x.contribucion || 0), 0);
    const pctCartera = totalCartera > 0 ? (c.contribucion / totalCartera * 100) : 0;

    opener = `${c.nombre} aporta **$${(c.contribucion/1000).toFixed(2)}M** de contribución · `;
    opener += `**${pctCartera.toFixed(1)}%** de la cartera total ($${(totalCartera/1000).toFixed(1)}M).\n\n`;

    if (pctCartera > 15) {
      opener += `Es una cuenta estructural · una salida total significaría perder $${(c.contribucion/1000).toFixed(1)}M de contribución que el resto de la cartera difícilmente absorbe.`;
    } else {
      opener += `Aporte relevante pero no dependiente · la cartera tiene resiliencia ante variaciones de esta cuenta.`;
    }
    opener += `\n\n*Confianza alta · cifras runtime sobre escenario ${scenario}.*`;

    suggestions = filterTextualSuggestions([
      `¿Qué pasaría si pierdo a ${c.nombre}?`,
      `Top contribuciones`,
      `Compara con Lider`,
    ]);
    sentrixAction = {
      label: `↗ Ver ${c.nombre}`,
      payload: { module: "margenes", focus: "contribucion", client: c.nombre },
      moduleChip: "Márgenes",
    };
  }

  // ── Rama VENTAS ─────────────────────────────────────────────────────────
  else if (metricKey === "ventas") {
    const totalCartera = dataset.reduce((s, x) => s + x.venta, 0);
    const pctCartera = (c.venta / totalCartera * 100);
    const ratioContrib = c.venta > 0 ? (c.contribucion / c.venta) : 0;

    opener = `${c.nombre} factura **$${(c.venta/1000).toFixed(1)}M** anuales · `;
    opener += `**${pctCartera.toFixed(1)}%** del volumen total de la cartera.\n\n`;
    if (c.sfamilia && c.marca) {
      opener += `El cliente opera en ${c.sfamilia} con marca principal ${c.marca}. `;
    }
    opener += `Cada $1 vendido aporta $${ratioContrib.toFixed(2)} de contribución después de carga.`;
    opener += `\n\n*Confianza alta · cifras runtime sobre escenario ${scenario}.*`;

    suggestions = filterTextualSuggestions([
      `¿Cuánto creció ${c.nombre} YoY?`,
      `Compara con Jumbo`,
      "Top clientes por venta",
    ]);
    sentrixAction = {
      label: `↗ Ver ${c.nombre}`,
      payload: { module: "ventas", focus: "ventas", client: c.nombre },
      moduleChip: "Ventas",
    };
  }

  // ── Fallback métrica no cubierta (rotacion, cobertura, etc) ─────────────
  else {
    opener = `No tengo cobertura determinística para la métrica "${metricKey}" sobre ${c.nombre} en este escenario. Puedo revisar carga, margen, contribución o ventas · decime cuál te interesa.`;
    suggestions = filterTextualSuggestions([
      `Cuéntame de ${c.nombre}`,
      `Y la carga de ${c.nombre}`,
      `Y el margen de ${c.nombre}`,
    ]);
    sentrixAction = null;
  }

  return { opener, suggestions, sentrixAction };
}

// ════════════════════════════════════════════════════════════════════════════
// FASE 1.5.B-HOTFIX-3 · COMPOSER client_comparison
//
// Compone contraste estructurado entre dos clientes · voz V3 firmada.
// Identifica dimensión dominante de diferencia (escala vs eficiencia)
// y produce "lectura" ejecutiva que prioriza acción sobre la cuenta
// más crítica · o detecta cuando la brecha es inmaterial.
//
// D-1.5.B-HOTFIX-3-VOZ-V3-COMPARISON firmada:
//   - Thresholds calibrados (ventasSimilar < 0.20, margenSimilar < 1pp)
//   - Cuando ambas son Tier 1 estructural · insight "palanca en bloque"
//   - "Brecha despreciable" cuando aplica · no fuerza diferenciación
//
// Observación arquitectónica futura (founder · #BACKLOG-INMATERIALIDAD):
//   El composer debería identificar EXPLÍCITAMENTE cuando una diferencia
//   no es material para la decisión. Esta primera versión cubre el caso
//   parcialmente · backlog refinará semántica de "inmaterial".
// ════════════════════════════════════════════════════════════════════════════
function composeClientComparison(clientA_name, clientB_name, scenario, modulo) {
  // FASE 1.5.B-HOTFIX-3-PATCH-3 · cross-dataset
  // La comparación entre 2 clientes es cross-dominio por naturaleza ·
  // ADI como asesor reúne TODA la información disponible para apoyar 
  // decisión (no devuelve al usuario a cambiar de módulo · eso es 
  // navegación, no asesoría).
  //
  // Lectura COMPLETA · escala (venta) + eficiencia (margen) + carga + 
  // contribución absoluta · todo viene de clientesMargen.
  //
  // Sentrix action apunta SIEMPRE a Márgenes (donde viven todos los 
  // fields del análisis comparativo). El módulo de origen ya no 
  // determina la respuesta.
  const dataset = applyScenarioToClientesMargen(scenario);

  const A = dataset.find(x => x.nombre === clientA_name);
  const B = dataset.find(x => x.nombre === clientB_name);

  if (!A || !B) {
    const missing = !A ? clientA_name : clientB_name;
    return {
      opener: `No tengo a ${missing} en el detalle de la cartera de este escenario.`,
      suggestions: filterTextualSuggestions([
        "Cuéntame de Falabella",
        "Cuéntame de Lider",
        "Cuéntame de Jumbo",
      ]),
      sentrixAction: null,
    };
  }

  const benchmark = A.benchmark || 30.1;

  // Cálculos comparativos
  const diffVentas = A.venta - B.venta;
  const diffContrib = A.contribucion - B.contribucion;
  const diffCarga = A.pctRebate - B.pctRebate;
  const diffMargen = (A.margen !== null && B.margen !== null) ? (A.margen - B.margen) : null;

  const totalCartera = dataset.reduce((s, x) => s + x.venta, 0);
  const totalContrib = dataset.reduce((s, x) => s + (x.contribucion || 0), 0);
  const pctA_v = (A.venta / totalCartera * 100);
  const pctB_v = (B.venta / totalCartera * 100);
  const pctA_c = totalContrib > 0 ? (A.contribucion / totalContrib * 100) : 0;
  const pctB_c = totalContrib > 0 ? (B.contribucion / totalContrib * 100) : 0;

  // Detección de dimensión dominante · D-VOZ-V3 thresholds calibrados
  const ventasSimilar = Math.abs(diffVentas / A.venta) < 0.20;
  const margenSimilar = diffMargen === null ? true : Math.abs(diffMargen) < 1;

  // Lead insight calibrado · NO fuerza diferenciación
  let leadInsight = "";
  if (ventasSimilar && margenSimilar) {
    leadInsight = `Dos cuentas estructuralmente parecidas · escala y eficiencia operan en el mismo orden de magnitud.`;
  } else if (ventasSimilar && !margenSimilar) {
    leadInsight = `Las dos cuentas operan en escala similar · la diferencia real está en eficiencia, no en tamaño.`;
  } else if (!ventasSimilar && margenSimilar) {
    leadInsight = `Margen parecido entre ambas · la diferencia es de escala y peso en la cartera.`;
  } else {
    leadInsight = `Ambas dimensiones (escala y eficiencia) divergen entre estas dos cuentas.`;
  }

  // Opener estructurado
  let opener = `**${A.nombre} vs ${B.nombre}** · ${leadInsight}\n\n`;

  // Bloque Volumen
  opener += `**Volumen:** ${A.nombre} factura $${(A.venta/1000).toFixed(1)}M (${pctA_v.toFixed(1)}% cartera) · ${B.nombre} $${(B.venta/1000).toFixed(1)}M (${pctB_v.toFixed(1)}%). `;
  if (ventasSimilar) {
    opener += `Escala equivalente.\n\n`;
  } else {
    opener += `Brecha de $${(Math.abs(diffVentas)/1000).toFixed(1)}M.\n\n`;
  }

  // Bloque Margen (solo si ambos tienen margen)
  if (diffMargen !== null) {
    opener += `**Margen:** ${A.nombre} ${A.margen}% · ${B.nombre} ${B.margen}% · `;
    opener += `ambos ${Math.min(A.margen, B.margen) < benchmark ? "bajo" : "sobre"} benchmark (${benchmark}%). `;
    if (margenSimilar) {
      opener += `Brecha de ${Math.abs(diffMargen).toFixed(1)}pp · despreciable.\n\n`;
    } else {
      const ganador = diffMargen > 0 ? A.nombre : B.nombre;
      opener += `${ganador} aventaja por ${Math.abs(diffMargen).toFixed(1)}pp.\n\n`;
    }
  }

  // Bloque Carga
  opener += `**Carga comercial:** ${A.nombre} ${A.pctRebate}% · ${B.nombre} ${B.pctRebate}%. `;
  if (Math.abs(diffCarga) >= 0.3) {
    const masCargada = diffCarga > 0 ? A.nombre : B.nombre;
    opener += `${masCargada} carga ${Math.abs(diffCarga).toFixed(1)}pp más rebate, lo que explica parte del gap de margen.\n\n`;
  } else {
    opener += `Carga prácticamente idéntica · la diferencia de margen NO viene de rebates.\n\n`;
  }

  // Bloque Contribución
  opener += `**Contribución absoluta:** ${A.nombre} aporta $${(A.contribucion/1000).toFixed(2)}M (${pctA_c.toFixed(1)}% cartera) · ${B.nombre} $${(B.contribucion/1000).toFixed(2)}M (${pctB_c.toFixed(1)}%).\n\n`;

  // Lectura ejecutiva · D-VOZ-V3 · interpretación con inmaterialidad
  const sumPctCartera = pctA_v + pctB_v;
  const ambosTier1 = (pctA_v + pctB_v) > 50;  // si juntos son >50%, son Tier 1 estructural

  if (diffMargen !== null && A.margen < benchmark && B.margen < benchmark) {
    if (ventasSimilar && margenSimilar && ambosTier1) {
      // Inserción del insight Tier 1 cuando aplica
      opener += `**Lectura**: ambas operan bajo benchmark con perfiles muy similares · representan el bloque estructural del Tier 1 que concentra el ${sumPctCartera.toFixed(1)}% del volumen y ${(pctA_c + pctB_c).toFixed(1)}% de la contribución. La palanca opera sobre el bloque como conjunto · la diferencia entre las dos cuentas es inmaterial para esa decisión.`;
    } else if (margenSimilar) {
      opener += `**Lectura**: ambas operan bajo benchmark con margen muy similar · la palanca opera sobre ambas por igual · la brecha entre las cuentas es marginal frente al gap vs benchmark.`;
    } else {
      const peorMargen = A.margen < B.margen ? A : B;
      const avgC = dataset.reduce((s, x) => s + (x.pctRebate || 0), 0) / dataset.length;
      const palancaDisponible = peorMargen.pctRebate > avgC ? "carga comercial" : "mix de productos";
      opener += `**Lectura**: ambas operan bajo benchmark · ${peorMargen.nombre} es el caso más crítico con ${Math.abs(peorMargen.margen - benchmark).toFixed(1)}pp bajo benchmark. La palanca disponible opera sobre ${palancaDisponible}.`;
    }
  } else if (diffMargen !== null && A.margen >= benchmark && B.margen >= benchmark) {
    opener += `**Lectura**: ambas cuentas son estructuralmente rentables · sostienen el promedio de la cartera.`;
  } else if (diffMargen !== null) {
    const enriesgo = A.margen < benchmark ? A : B;
    opener += `**Lectura**: ${enriesgo.nombre} es la que sub-rentabiliza · la palanca opera sobre esa cuenta · la otra es estructuralmente sana en margen.`;
  } else {
    // Caso ventas sin margen
    if (ventasSimilar) {
      opener += `**Lectura**: ambas operan en escala equivalente · la diferencia real (si existe) habría que buscarla en margen, no en volumen.`;
    } else {
      const masGrande = diffVentas > 0 ? A.nombre : B.nombre;
      opener += `**Lectura**: ${masGrande} concentra más peso de cartera · su evolución impacta más en el agregado.`;
    }
  }

  opener += `\n\n*Confianza alta · cifras runtime sobre escenario ${scenario}.*`;

  const suggestions = filterTextualSuggestions([
    `¿Por qué ${A.nombre} pierde margen?`,
    `¿Qué pasaría si pierdo a ${A.nombre}?`,
    `Compara ${B.nombre} con Jumbo`,
  ]);

  // FASE 1.5.B-HOTFIX-3-PATCH-3 · Sentrix action apunta a Márgenes
  // (donde viven los datos del análisis comparativo · cross-dataset).
  const sentrixAction = {
    label: `↗ Ver ${A.nombre} vs ${B.nombre}`,
    payload: { module: "margenes", focus: "comparison", clients: [A.nombre, B.nombre] },
    moduleChip: "Márgenes",
  };

  return { opener, suggestions, sentrixAction };
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF L · RANKING EXTREMES + CROSS-METRIC RANKING · HELPERS + COMPOSERS
//
// Cluster cognitivo · ubicado junto a composers ad-hoc BRIEF H/I/J para
// proximidad lógica. NO toca el detector ad-hoc (decisión arquitecto D1:
// detector implícito separado · sibling).
//
// Orden TDZ-safe: helpers puros primero · luego detectores · luego composers.
// Todos top-level porque el dispatch pipeline B FASE 4 los invoca directamente.
// ════════════════════════════════════════════════════════════════════════════

// ── _detectMetricInText ──────────────────────────────────────────────────
// Mapea sinónimos de métricas en texto a las canonical keys del catálogo
// RANKING_EXTREMES_METRICS. Retorna canonical key o null.
//
// El contexto entityType (cuando ya está resuelto) permite desambiguar
// "margen" entre client.margen y sku_margen · "contribucion" entre
// client.contribucion y sku_contribucion.
function _detectMetricInText(normalizedText, entityTypeHint) {
  const n = normalizedText;
  // Sinónimos canónicos → key del catálogo
  // Orden importa: revisar términos compuestos antes que simples.
  if (/\b(rotacion|rota|gira|veces\s+al\s+a[nñ]o)\b/.test(n)) return "rotacion";
  if (/\b(cobertura|dias\s+de\s+stock)\b/.test(n))             return "cobertura";
  if (/\b(doh|dias\s+de\s+oferta)\b/.test(n))                  return "doh";
  if (/\b(stock\s*usd|stock|capital\s+inmovilizado|capital\s+atrapado)\b/.test(n)) return "stockUSD";
  if (/\b(carga|rebate|carga\s+comercial)\b/.test(n))          return "carga";
  // Ambigüedad margen/contribucion · resolver por entityTypeHint
  if (/\b(margen|rentabilidad|margen\s+unitario)\b/.test(n)) {
    return entityTypeHint === "sku" ? "sku_margen" : "margen";
  }
  if (/\b(contribuci[oó]n|aporte|aportan|aporta)\b/.test(n)) {
    return entityTypeHint === "sku" ? "sku_contribucion" : "contribucion";
  }
  if (/\b(ventas|venta|facturaci[oó]n|facturan|factura)\b/.test(n)) return "ventas";
  return null;
}

// ═══ FIX #D-RANKING-WITH-METRICS · ranking enriquecido (Opción B · solo ranking_extremes) ═══
// Cuando el usuario pide "ranking por A y mostrar B" (ej. "clientes con peor margen y carga"),
// ranking_extremes ordena por A (la PRINCIPAL) e incluye B (la ANEXA) como columna. Corrige
// además el bug de orden actual: _detectMetricInText revisa en orden fijo (carga antes que
// margen), así "peor margen y carga" hoy ordena por CARGA (mal). El detector de anexa identifica
// la principal por posición/"por X", no por el orden interno de detección. off = byte-idéntico.
const ADI_RANKING_WITH_METRICS_ENABLED = true;

// métricas anexables (cláusula 4 · unidades EXCLUIDA · deuda #D-RANKING-WITH-UNITS-BIS)
const _RWM_ANEXA_METRICS = ["ventas", "contribucion", "margen", "carga"];

// ── _rwmResolveMetricToken(tok, entityType) · token de métrica → key del catálogo ──
function _rwmResolveMetricToken(tok, entityType) {
  try {
    const m = _detectMetricInText(tok, entityType);
    if (!m) return null;
    // normalizar sku_* a la métrica base para el set anexable
    const base = m.replace(/^sku_/, "");
    return _RWM_ANEXA_METRICS.indexOf(base) >= 0 ? m : null;
  } catch (e) { return null; }
}

// ── _rwmDetectPrincipalAnexa(trimmed, entityType) · separa PRINCIPAL (ordena) de ANEXA (muestra) ──
// Regla (cláusula 2): principal = la PRIMERA métrica mencionada (la del "por X"/"con menor|peor X")
// · anexa = la SEGUNDA, introducida por una conjunción "y"/"y su"/"y cuanto". El sort SIEMPRE
// atado a la principal. Escanea las métricas en ORDEN DE APARICIÓN (no por el orden interno de
// _detectMetricInText · ese es el bug que corrige). Devuelve { principal, anexa } o null.
function _rwmDetectPrincipalAnexa(trimmed, entityType) {
  try {
    if (typeof ADI_RANKING_WITH_METRICS_ENABLED === "undefined" || !ADI_RANKING_WITH_METRICS_ENABLED) return null;
    const n = _normalizeSemanticText(trimmed);
    if (!n) return null;
    // exige una conjunción de anexo: "y" (que introduzca una 2da métrica)
    if (!/\by\b/.test(n)) return null;
    // patrones de métrica en orden de aparición (posición en la frase)
    const METRIC_RE = [
      { key: "ventas",       re: /\b(ventas|venta|venden|vende|facturaci[oó]n|facturan|factura)\b/g },
      { key: "contribucion", re: /\b(contribuci[oó]n|aporte|aportan|aporta)\b/g },
      { key: "margen",       re: /\b(margen|rentabilidad)\b/g },
      { key: "carga",        re: /\b(carga|rebate)\b/g },
    ];
    // recolectar todas las menciones con su índice de posición
    const hits = [];
    for (const m of METRIC_RE) {
      let mm;
      const re = new RegExp(m.re.source, "g");
      while ((mm = re.exec(n)) !== null) hits.push({ key: m.key, idx: mm.index });
    }
    if (hits.length < 2) return null;
    // ordenar por posición · la primera es principal, la siguiente DISTINTA es anexa
    hits.sort((a, b) => a.idx - b.idx);
    const principalBase = hits[0].key;
    let anexaBase = null;
    for (let i = 1; i < hits.length; i++) { if (hits[i].key !== principalBase) { anexaBase = hits[i].key; break; } }
    if (!anexaBase) return null;
    // verificar que entre la principal y la anexa haya una "y" (conjunción de anexo · no dos
    // métricas sueltas sin conectar). Tomamos la subcadena entre ambas posiciones.
    const pIdx = hits[0].idx;
    const aIdx = hits.find(h => h.key === anexaBase).idx;
    const between = n.slice(Math.min(pIdx, aIdx), Math.max(pIdx, aIdx));
    if (!/\by\b/.test(between)) return null;
    // mapear a keys del catálogo según entityType (sku usa sku_*)
    const toKey = (base) => {
      if (entityType === "sku" && (base === "margen" || base === "contribucion")) return "sku_" + base;
      return base;
    };
    const principal = toKey(principalBase);
    const anexa = toKey(anexaBase);
    if (principal === anexa) return null;
    // ambas deben existir en el catálogo y ser del entityType
    // excepción: ventas anexa para sku (el field `venta` existe en skusMargen aunque no haya
    // entrada sku_ventas en el catálogo · el composer lo resuelve · NO inventa)
    if (!RANKING_EXTREMES_METRICS[principal] || RANKING_EXTREMES_METRICS[principal].entityType !== entityType) return null;
    const anexaOk = (RANKING_EXTREMES_METRICS[anexa] && RANKING_EXTREMES_METRICS[anexa].entityType === entityType)
      || (anexa === "ventas" && entityType === "sku");
    if (!anexaOk) return null;
    return { principal, anexa };
  } catch (e) { return null; }
}

// ── _detectEntityTypeInText ──────────────────────────────────────────────
// Detecta si la query refiere a "cliente" / "cuenta" (client) o "SKU" /
// "producto" / "item" (sku). EXCLUSIÓN explícita de "mecanismo" (mitigación
// R2 · evita secuestro de composeMechanismRanking Ferrari).
function _detectEntityTypeInText(normalizedText) {
  const n = normalizedText;
  // Exclusión R2 · si menciona "mecanismo" · no es ranking-extremes
  if (/\b(mecanismo|mecanismos)\b/.test(n)) return null;
  if (/\b(cliente|clientes|cuenta|cuentas)\b/.test(n)) return "client";
  if (/\b(sku|skus|producto|productos|item|items|articulo|articulos)\b/.test(n)) return "sku";
  return null;
}

// ── _detectTopNInText ────────────────────────────────────────────────────
// Captura "los 3 peores" · "los 5 mejores" · "los peores" · "el peor".
// Decisión arquitecto D6: plural sin número explícito = 3 · singular = 1.
function _detectTopNInText(normalizedText) {
  const n = normalizedText;
  // Número explícito: "los 3 peores", "los 5 mejores", "3 peores"
  const numMatch = n.match(/\b(?:los|las)?\s*(\d+)\s+(?:peor|peores|mejor|mejores|mas|menor|menores|mayor|mayores)\b/);
  if (numMatch) {
    const n_int = parseInt(numMatch[1], 10);
    if (!Number.isNaN(n_int) && n_int >= 1 && n_int <= 50) return n_int;
  }
  // Plural sin número: "los peores clientes", "los mejores SKUs"
  if (/\b(los|las)\s+(peores|mejores|menores|mayores)\b/.test(n)) return 3;
  // Singular default
  return 1;
}

// ── _detectCrossMetricInText ─────────────────────────────────────────────
// Detecta patrón cross-metric: "del top X [metric_A]" · "del top contribución"
// · "entre los de mayor X". Retorna { rankMetric, rankDirection, rankN } o null.
// Decisión arquitecto D8: rankN default = 3.
function _detectCrossMetricInText(normalizedText, entityTypeHint) {
  const n = normalizedText;
  // Patrón 1 · "del top N contribución" / "del top contribución" / "del top 3"
  const topMatch = n.match(/\b(?:del?|entre)\s+(?:el\s+)?top\s*(\d+)?\s*(\w+)?/);
  if (topMatch) {
    const rankN = topMatch[1] ? parseInt(topMatch[1], 10) : 3;
    // Tratar de detectar la métrica que acompaña al "top".
    // PRIORIDAD: si topMatch[2] tiene una palabra · resolverla AISLADAMENTE
    // primero · evita que la métrica del sort-side ("peor margen") gane la
    // detección al precederla en el orden de tests del _detectMetricInText.
    const remainder = topMatch[2] ? topMatch[2] : "";
    let rankMetric = null;
    if (remainder) {
      rankMetric = _detectMetricInText(remainder, entityTypeHint);
    }
    if (!rankMetric) {
      // Fallback · escanear texto completo (puede capturar la métrica equivocada
      // en queries muy ambiguas · pero es la mejor heurística sin parser)
      rankMetric = _detectMetricInText(n, entityTypeHint);
    }
    if (rankMetric && rankN >= 1 && rankN <= 50) {
      return { rankMetric, rankDirection: "best", rankN };
    }
  }
  // Patrón 2 · "entre los de mayor X" / "de los con mayor X"
  const mayorMatch = n.match(/\b(?:entre\s+los|de\s+los\s+con|de\s+las\s+con)\s+(?:mayor|mas\s+alta?o?s?|mas)\s+(\w+)/);
  if (mayorMatch) {
    const rankMetric = _detectMetricInText(mayorMatch[1], entityTypeHint);
    if (rankMetric) {
      return { rankMetric, rankDirection: "best", rankN: 3 };
    }
  }
  return null;
}

// ── _inferMetricFromContext ──────────────────────────────────────────────
// Para coreferencia implícita ("y el peor de esos"): infiere qué métrica
// usar a partir del lastIntent del context.
//
// Decisión arquitecto D4: NO agregar lastSortMetric al context · mapping
// directo desde lastIntent. Si lastIntent no mapea limpio · retorna null
// (caller usa composeHonestUnavailable).
function _inferMetricFromContext(ctx) {
  if (!ctx || !ctx.lastIntent) return null;
  const map = {
    client_contribution_ranking: "contribucion",
    product_contribution:        "sku_contribucion",
    product_dual_comparison:     "sku_contribucion",
    growth_opportunity:          "margen",
    rotation_dive:               "rotacion",
    coverage_dive:               "cobertura",
    sku_operational:             "stockUSD",
    warehouse_dive:              "stockUSD",
    // ranking_extremes / cross_metric_ranking · si T1 fue ranking_extremes
    // T2 hereda la misma métrica desde lastRankingMetric (set por nosotros)
    ranking_extremes:            ctx.lastRankingMetric || null,
    cross_metric_ranking:        ctx.lastRankingMetric || null,
    // BRIEF L · QI ranked T1 → T2 hereda lastRankingMetric (poblado por
    // QI populator extendido). Sin lastRankingMetric · retorna null →
    // detector cae limpio a fallback honesto.
    query_interpreter:           ctx.lastRankingMetric || null,
  };
  return map[ctx.lastIntent] || null;
}

// ── _buildScopeForEntityType ─────────────────────────────────────────────
// Construye dataset filtrado por scenario para el composer. Resuelve el
// source correcto según RANKING_EXTREMES_METRICS[metric].source.
//
// Decisión arquitecto D2: applyScenarioToClientesMargen (13 raw · NO top-10).
function _buildScopeForMetric(metricKey, scenarioId) {
  const spec = RANKING_EXTREMES_METRICS[metricKey];
  if (!spec) return null;
  if (spec.source === "clientesMargen") {
    // 13 clientes raw · sin truncamiento PROTECTED_CLIENTS
    return applyScenarioToClientesMargen(scenarioId).filter(c => c.tipo === "cliente");
  }
  if (spec.source === "skuInventario") {
    return applyScenarioToSkuInventario(scenarioId);
  }
  if (spec.source === "skusMargen") {
    // skusMargen no tiene scenario transform · usar raw
    return skusMargen.filter(s => s.tipo === "sku");
  }
  return null;
}

// ── _getEntityNameField ──────────────────────────────────────────────────
// clientesMargen usa "nombre" · skuInventario usa "sku" · skusMargen usa
// "nombre". Devuelve el field correcto para mostrar el nombre/id.
function _getEntityNameField(metricKey) {
  const spec = RANKING_EXTREMES_METRICS[metricKey];
  if (!spec) return "nombre";
  if (spec.source === "skuInventario") return "sku";
  return "nombre";
}

// ── _formatMetricValue ───────────────────────────────────────────────────
// Formatea un valor según la unidad declarada en RANKING_EXTREMES_METRICS.
function _formatMetricValue(value, metricKey) {
  const spec = RANKING_EXTREMES_METRICS[metricKey];
  if (!spec || value == null || isNaN(value)) return String(value);
  if (spec.unit === "%") return `${value.toFixed(1)}%`;
  if (spec.unit === "x") return `${value.toFixed(1)}x`;
  if (spec.unit === "d") return `${Math.round(value)}d`;
  if (spec.unit === "$") {
    // Heurística escala: ≥1000 → K · ≥1M → M
    if (value >= 1000) return `$${(value/1000).toFixed(2)}M`;
    return `$${Math.round(value)}K`;
  }
  return String(value);
}

// ── detectRankingExtremesIntent ──────────────────────────────────────────
// Detector léxico para queries manuales tipo "¿quién es el peor cliente por
// margen?" · "los 3 mejores SKUs por rotación" · "el peor del top 3
// contribución por margen".
//
// Decisión arquitecto D5: invocado AFTER detectIntent · solo si retorna
// "module"/"generic". Mitiga R1 (no secuestra rotation_dive).
//
// Decisión arquitecto H4-fix: NO matchea "top" como bestPattern · solo
// tokens explícitos worst/best. QI conserva path para "top N por X".
//
// Retorna intent sintético o null.
function detectRankingExtremesIntent(text, ctx) {
  if (!VOICE_RANKING_EXTREMES_ENABLED) return null;
  if (!text || typeof text !== "string") return null;

  const normalized = text.toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[¿?¡!]/g, "")
    .trim();

  // Tokens worst/best (NO incluye "top" por H4-fix)
  // FIX_L_PRECEDENCE · eliminados mayor/menor/mayores/menores de los patterns.
  // Razón: queries tipo "clientes con mayor contribución" / "SKUs con menor
  // rotación" son retrieval ranked legítimo de QI o paths Ferrari · ranking-
  // extremes debe interceptar SOLO formas extremas explícitas (peor / mejor /
  // máximo / mínimo / más baja / más alta). Sin esta restricción · ranking-
  // extremes corriendo PRE-QI robaría queries QI legítimas. Trade-off
  // consciente: el caso "el cliente con menor margen" queda delegado a QI
  // (deuda #D-MENOR-MAYOR-DELEGADOS-A-QI-INTERPRETA-COMO-BEST).
  // Cubre masculino y femenino: bajo/baja/bajos/bajas · alto/alta/altos/altas
  const worstPatterns = /\b(peor|peores|mas\s+baj[oa]s?|minimo|ultimo|ultimos)\b/;
  const bestPatterns  = /\b(mejor|mejores|mas\s+alt[oa]s?|maximo|primero|primeros)\b/;
  const isWorst = worstPatterns.test(normalized);
  const isBest  = bestPatterns.test(normalized);
  if (!isWorst && !isBest) return null;

  // EntityType · primero intentamos detección explícita
  let entityType = _detectEntityTypeInText(normalized);

  // Si no hay entityType explícito · intentamos inferir desde la métrica:
  // métricas client-only (contribucion, margen, ventas, carga) → client
  // métricas sku-only (rotacion, cobertura, doh, stockUSD, sku_*) → sku
  let metric = _detectMetricInText(normalized, entityType);
  if (!entityType && metric) {
    const spec = RANKING_EXTREMES_METRICS[metric];
    if (spec) entityType = spec.entityType;
  }
  if (!entityType) return null;

  // Re-resolver métrica con entityType ya conocido (mejora desambiguación
  // margen → sku_margen vs margen según hint)
  metric = _detectMetricInText(normalized, entityType);
  if (!metric) return null;

  // Validar que el metric pertenece al entityType correcto
  const spec = RANKING_EXTREMES_METRICS[metric];
  if (!spec || spec.entityType !== entityType) return null;

  // Detectar cross-metric primero (patrón "del top X tiene peor Y")
  const cross = _detectCrossMetricInText(normalized, entityType);
  if (cross) {
    // Validar que rankMetric también es válido para el entityType
    const rankSpec = RANKING_EXTREMES_METRICS[cross.rankMetric];
    if (rankSpec && rankSpec.entityType === entityType) {
      return {
        type: "cross_metric_ranking",
        rankMetric: cross.rankMetric,
        rankDirection: cross.rankDirection,
        rankN: cross.rankN,
        sortMetric: metric,
        sortDirection: isWorst ? "worst" : "best",
        entityType,
      };
    }
  }

  // Familia A · ranking extremes simple
  const topN = _detectTopNInText(normalized);
  return {
    type: "ranking_extremes",
    direction: isWorst ? "worst" : "best",
    metric,
    entityType,
    topN,
  };
}

// ── detectImplicitRankingExtreme ─────────────────────────────────────────
// Decisión arquitecto D1 · Opción B: detector separado · NO toca BRIEF I.
//
// Cubre coreferencia implícita worst/best sobre lista heredada:
//   T1: "top 3 clientes por contribución" (QI ranked · pobla lastClientList)
//   T2: "y el peor de esos" → composeRankingExtremes con scope=lastClientList
//
// Precondiciones:
//   · text contiene tokens worst/best
//   · context tiene lastClientList o lastSkuList ≥ 2 entidades
//   · text NO contiene métrica explícita (si la tiene · va por
//     detectRankingExtremesIntent normal)
//
// Métrica inferida vía _inferMetricFromContext.
function detectImplicitRankingExtreme(text, ctx) {
  if (!VOICE_RANKING_EXTREMES_ENABLED) return null;
  if (!text || !ctx) return null;

  const normalized = text.toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[¿?¡!]/g, "")
    .trim();

  // Solo dispara con tokens explícitos worst/best
  const worstPatterns = /\b(peor|peores|mas\s+baj[oa]s?|menor|menores|minimo|ultimo)\b/;
  const bestPatterns  = /\b(mejor|mejores|mas\s+alt[oa]s?|mayor|mayores|maximo|primero)\b/;
  const isWorst = worstPatterns.test(normalized);
  const isBest  = bestPatterns.test(normalized);
  if (!isWorst && !isBest) return null;

  // Anti-double-fire: si el texto YA tiene métrica explícita Y entityType
  // explícito · que lo maneje detectRankingExtremesIntent (no implícito).
  const explicitMetric = _detectMetricInText(normalized, null);
  const explicitEntity = _detectEntityTypeInText(normalized);
  if (explicitMetric && explicitEntity) return null;

  // Resolver scope desde context · respetar precedencia BRIEF I/J:
  // si hay deíctico explícito "esos/estos" + entityType inferible · usar esa lista.
  // En implícito · default: priorizar lastClientList si lastIntent es de clientes.
  // Si T1 fue QI ranked · usamos lastRankingMetric (poblado por QI populator
  // extendido en BRIEF L) para inferir entityType del set heredado.
  let inheritedList = null;
  let entityType = null;
  const lastIntentIsClient = ctx.lastIntent === "client_contribution_ranking"
    || ctx.lastIntent === "growth_opportunity"
    || ctx.lastIntent === "client"
    || ctx.lastIntent === "client_followup"
    || ctx.lastIntent === "cross_domain_query"
    || ctx.lastIntent === "ranking_extremes"
    || ctx.lastIntent === "cross_metric_ranking";

  // BRIEF L · branch determinístico si T1 fue QI ranked
  if (ctx.lastIntent === "query_interpreter" && ctx.lastRankingMetric) {
    const rmSpec = RANKING_EXTREMES_METRICS[ctx.lastRankingMetric];
    if (rmSpec) {
      if (rmSpec.entityType === "client"
          && Array.isArray(ctx.lastClientList) && ctx.lastClientList.length >= 2) {
        inheritedList = ctx.lastClientList;
        entityType = "client";
      } else if (rmSpec.entityType === "sku"
                 && Array.isArray(ctx.lastSkuList) && ctx.lastSkuList.length >= 2) {
        inheritedList = ctx.lastSkuList;
        entityType = "sku";
      }
    }
  }

  if (!inheritedList && lastIntentIsClient && Array.isArray(ctx.lastClientList) && ctx.lastClientList.length >= 2) {
    inheritedList = ctx.lastClientList;
    entityType = "client";
  } else if (!inheritedList && Array.isArray(ctx.lastSkuList) && ctx.lastSkuList.length >= 2) {
    inheritedList = ctx.lastSkuList;
    entityType = "sku";
  } else if (Array.isArray(ctx.lastClientList) && ctx.lastClientList.length >= 2) {
    inheritedList = ctx.lastClientList;
    entityType = "client";
  }
  if (!inheritedList || !entityType) return null;

  // Inferir métrica del ranking previo
  const metric = _inferMetricFromContext(ctx);
  if (!metric) return null;

  // Validar metric ↔ entityType match
  const spec = RANKING_EXTREMES_METRICS[metric];
  if (!spec || spec.entityType !== entityType) return null;

  return {
    type: "ranking_extremes",
    direction: isWorst ? "worst" : "best",
    metric,
    entityType,
    topN: 1, // "el peor de esos" siempre singular
    inheritedScope: inheritedList,
  };
}

// ── detectRankingDeicticRerank ───────────────────────────────────────────
// FIX #D-FOLLOWUP-RANKING-DEICTIC · Opción A · fallback de re-ranking.
// Se llama SOLO cuando detectImplicitRankingExtreme devolvió null (lista <2).
// Si el texto tiene un superlativo claro (peor/mejor/menor/mayor/más bajo/más alto)
// Y hay dominio/métrica en contexto (lastRankingMetric / activeResult.metric vía
// _inferMetricFromContext) → construye un intent ranking_extremes sobre el UNIVERSO
// del dominio (scope completo · NO inheritedScope), recomputando el extremo con su cifra.
// NO baja el guard de detectImplicitRankingExtreme · re-rankea en vez.
// Cuidado "primero" (cláusula 5): "el primero" es ORDINAL (detectDeicticReference) ·
// NO se captura acá como superlativo (guard ordinal-exclusión).
function detectRankingDeicticRerank(text, ctx) {
  if (typeof ADI_RANKING_DEICTIC_RERANK_ENABLED === "undefined" || !ADI_RANKING_DEICTIC_RERANK_ENABLED) return null;
  if (!VOICE_RANKING_EXTREMES_ENABLED) return null;
  if (!text || !ctx) return null;

  const normalized = text.toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[¿?¡!]/g, "")
    .trim();

  // Cuidado "primero" (cláusula 5): si el texto es un ORDINAL puro ("el primero",
  // "el segundo", ..., "el ultimo"), NO es nuestro caso · lo maneja detectDeicticReference.
  // Excluimos para no reinterpretar "el primero" como "el mejor".
  const ordinalGuard = /\b(el|la|los|las)?\s*(primer[oa]?s?|segund[oa]s?|tercer[oa]?s?|cuart[oa]s?|ultim[oa]s?)\b/;
  if (ordinalGuard.test(normalized)) return null;

  // Superlativos (espejo EXACTO de detectImplicitRankingExtreme · misma semántica).
  // Nota: "primero" NO se incluye acá (lo cubre el ordinalGuard arriba · es ordinal).
  const worstPatterns = /\b(peor|peores|mas\s+baj[oa]s?|menor|menores|minimo)\b/;
  const bestPatterns  = /\b(mejor|mejores|mas\s+alt[oa]s?|mayor|mayores|maximo)\b/;
  const isWorst = worstPatterns.test(normalized);
  const isBest  = bestPatterns.test(normalized);
  if (!isWorst && !isBest) return null;

  // Anti-double-fire: si el texto YA trae métrica + entityType explícitos · que lo maneje
  // detectRankingExtremesIntent normal (no este fallback).
  const explicitMetric = _detectMetricInText(normalized, null);
  const explicitEntity = _detectEntityTypeInText(normalized);
  if (explicitMetric && explicitEntity) return null;

  // Guard del caso SINGULAR (cláusula 2): la lista contextual relevante tiene <2.
  // Si tiene ≥2 · el camino de detectImplicitRankingExtreme la cubre · NO entramos acá.
  const clientLen = Array.isArray(ctx.lastClientList) ? ctx.lastClientList.length : 0;
  const skuLen    = Array.isArray(ctx.lastSkuList)    ? ctx.lastSkuList.length    : 0;
  if (clientLen >= 2 || skuLen >= 2) return null;

  // Métrica del contexto (la del ranking previo · cero invención). Sin métrica → null (fallback honesto).
  const metric = _inferMetricFromContext(ctx);
  if (!metric) return null;
  const spec = RANKING_EXTREMES_METRICS[metric];
  if (!spec) return null;

  // Re-rankear el UNIVERSO del dominio por la métrica activa · dirección por superlativo.
  return {
    type: "ranking_extremes",
    direction: isWorst ? "worst" : "best",
    metric,
    entityType: spec.entityType,
    topN: 1,                 // el superlativo singular pide UN extremo
    inheritedScope: null,    // UNIVERSO (no la lista de 1) · re-rankea el dominio completo
  };
}

// ── _filterScopeByEntities ───────────────────────────────────────────────
// Para coreferencia implícita: filtra el dataset full por la lista de
// entidades heredada. Asegura que el sub-sort opere SOLO sobre el set
// previo (no sobre el universo).
function _filterScopeByEntities(scope, inheritedEntities, nameField) {
  if (!Array.isArray(scope) || !Array.isArray(inheritedEntities)) return scope;
  const set = new Set(inheritedEntities);
  return scope.filter(item => set.has(item[nameField]));
}

// ── composeRankingExtremes ───────────────────────────────────────────────
// Composer único parametrizado · familia A + familia C.
// Decisión arquitecto D9: usa buildResponseContract.
// Decisión arquitecto D7: topN=1 → sentrix deep dive · topN≥2 → selección.
function composeRankingExtremes({
  direction,
  metric,
  entityType,
  topN,
  scope,
  ctx,
  inheritedScope,
  anexaMetric,
}) {
  // Validación
  const spec = RANKING_EXTREMES_METRICS[metric];
  if (!spec || spec.entityType !== entityType) {
    const moduleCtx = entityType === "client" ? "margenes" : "inventario";
    return composeHonestUnavailable("la métrica solicitada no aplica a la dimensión consultada.", moduleCtx);
  }

  // FIX #D-RANKING-WITH-METRICS · resolver la métrica anexa (mostrar, NO ordenar).
  // El sort queda atado a `spec` (la principal · sin cambios). La anexa solo se lee para
  // mostrar la columna. Si no resuelve a un field trazable del mismo entityType → no se
  // muestra (I-RWM-NO-INVENTA). NUNCA entra al comparador (I-RWM-ORDEN).
  let anexaSpec = null;
  if (typeof ADI_RANKING_WITH_METRICS_ENABLED !== "undefined" && ADI_RANKING_WITH_METRICS_ENABLED
      && anexaMetric && anexaMetric !== metric) {
    let _as = RANKING_EXTREMES_METRICS[anexaMetric];
    // ventas anexa para sku: el catálogo no tiene sku_ventas, pero skusMargen tiene el field
    // `venta` (trazable). Sintetizamos un spec mínimo del mismo entityType (NO inventa: el
    // field existe en el dataset). Solo para mostrar · nunca para ordenar.
    if (!_as && anexaMetric === "ventas" && entityType === "sku") {
      _as = { entityType: "sku", field: "venta", unit: "$" };
    }
    if (_as && _as.entityType === entityType) anexaSpec = _as;
  }

  // Dataset base
  let dataset = scope || _buildScopeForMetric(metric, ctx?.scenarioId);
  if (!Array.isArray(dataset) || dataset.length === 0) {
    return composeHonestUnavailable("no hay datos disponibles en el escenario activo.", spec.domain);
  }

  // Si hay scope heredado · filtrar
  const nameField = _getEntityNameField(metric);
  if (Array.isArray(inheritedScope) && inheritedScope.length > 0) {
    dataset = _filterScopeByEntities(dataset, inheritedScope, nameField);
    if (dataset.length === 0) {
      return composeHonestUnavailable("las entidades referidas no se encuentran en el dataset activo.", spec.domain);
    }
  }

  // Sort estable con tiebreaker alfabético (V7)
  const sorted = [...dataset].sort((a, b) => {
    const va = a[spec.field];
    const vb = b[spec.field];
    if (va == null || isNaN(va)) return 1;
    if (vb == null || isNaN(vb)) return -1;
    const primary = direction === "worst" ? (va - vb) : (vb - va);
    if (primary !== 0) return primary;
    // Tiebreaker: alfabético por nameField
    return String(a[nameField]).localeCompare(String(b[nameField]));
  });

  const selected = sorted.slice(0, Math.max(1, topN));
  const moduleCtx = spec.domain;

  // Verbalización direction
  const directionWord = direction === "worst" ? "peor" : "mejor";
  const directionPlural = direction === "worst" ? "peores" : "mejores";
  const entityNoun = entityType === "client" ? "cliente" : "SKU";
  const entityNounPlural = entityType === "client" ? "clientes" : "SKUs";

  // Opener
  let opener;
  if (selected.length === 1) {
    const e = selected[0];
    const val = _formatMetricValue(e[spec.field], metric);
    opener = `El ${entityNoun} con ${directionWord} ${_metricNounEs(metric)} es ${e[nameField]} · ${val}.`;
    // FIX #D-RANKING-WITH-METRICS · anexa al lado (no reordena)
    if (anexaSpec) {
      const aval = _formatMetricValue(e[anexaSpec.field], anexaMetric);
      if (aval != null && aval !== "") {
        opener += ` Su ${_metricNounEs(anexaMetric)} es ${aval}.`;
      }
    }

    // Anclaje contextual cuando hay benchmark / mejor práctica conocida
    if (metric === "margen" && e.benchmark != null) {
      const gap = Math.abs(e.benchmark - e.margen).toFixed(1);
      const dir = e.margen < e.benchmark ? "bajo" : "sobre";
      opener += `\n\n${e[nameField]} opera ${gap}pp ${dir} el benchmark de industria (${e.benchmark}%).`;
      if (e.pctRebate != null) {
        opener += ` Su carga comercial es ${e.pctRebate.toFixed(1)}%.`;
      }
    } else if (metric === "rotacion" && e.doh != null) {
      opener += `\n\n${e[nameField]} acumula ${e.doh}d de DOH · señal de baja velocidad de conversión.`;
    } else if (metric === "stockUSD" && e.doh != null) {
      opener += `\n\n${e[nameField]} concentra capital con ${e.doh}d de cobertura.`;
    }
    opener += `\n\n*Confianza alta · cálculo determinístico sobre dataset runtime.*`;
  } else {
    // topN ≥ 2 · listado
    const _anexaHdr = anexaSpec ? ` (con ${_metricNounEs(anexaMetric)})` : "";
    opener = `Los ${selected.length} ${directionPlural} ${entityNounPlural} por ${_metricNounEs(metric)}${_anexaHdr}:\n\n`;
    selected.forEach((e, i) => {
      const val = _formatMetricValue(e[spec.field], metric);
      let line = `${i + 1}. ${e[nameField]} · ${val}`;
      // FIX #D-RANKING-WITH-METRICS · columna anexa (no reordena · el sort es por la principal)
      if (anexaSpec) {
        const aval = _formatMetricValue(e[anexaSpec.field], anexaMetric);
        if (aval != null && aval !== "") line += ` · ${_metricNounEs(anexaMetric)} ${aval}`;
      }
      opener += line + `\n`;
    });
    opener += `\n*Confianza alta · cálculo determinístico sobre dataset runtime.*`;
  }

  // Sentrix action · decisión D7
  const moduleChip = moduleCtx === "margenes" ? "Márgenes"
                   : moduleCtx === "ventas"    ? "Ventas"
                   : "Inventario";
  let sentrixAction;
  if (selected.length === 1) {
    const e = selected[0];
    sentrixAction = {
      label: `Ver ${e[nameField]} en ${moduleChip}`,
      moduleChip,
      payload: {
        modulo: moduleCtx,
        clientes: entityType === "client" ? [e[nameField]] : [],
        skus:     entityType === "sku"    ? [e[nameField]] : [],
        mechanismBanner: `${directionWord.charAt(0).toUpperCase() + directionWord.slice(1)} ${entityNoun} por ${_metricNounEs(metric)}`,
      },
    };
  } else {
    sentrixAction = {
      label: `Ver ${selected.length} ${entityNounPlural} en ${moduleChip}`,
      moduleChip,
      payload: {
        modulo: moduleCtx,
        clientes: entityType === "client" ? selected.map(e => e[nameField]) : [],
        skus:     entityType === "sku"    ? selected.map(e => e[nameField]) : [],
        mechanismBanner: `${selected.length} ${directionPlural} ${entityNounPlural} por ${_metricNounEs(metric)}`,
      },
    };
  }

  // Suggestions · BRIEF N-bis · vacías
  const suggestions = filterTextualSuggestions([]);

  // ── BRIEF M.B.1 · narrative_signals + posture_hint (spread D2) ──
  // Bajo flag OFF · ambos quedan null · return bitwise equivalente al legacy.
  let narrative_signals = null;
  let posture_hint = "validate";
  if (VOICE_NARRATIVE_LAYER_ENABLED) {
    try {
      narrative_signals = buildNarrativeSignalsForRankingExtremes(
        selected, direction, metric, entityType, dataset
      );
      // posture_hint: challenge si hay driver interno en el #1 · else validate
      const headSignals = Array.isArray(narrative_signals?.items)
        ? narrative_signals.items[0]
        : narrative_signals;
      if (headSignals?.implication?.counter_intuition === true) {
        posture_hint = "challenge";
      }
    } catch (sig_err) {
      // eslint-disable-next-line no-console
      console.warn("BRIEF M.B.1 narrative_signals error:", sig_err);
      narrative_signals = null;
    }
  }

  return {
    ...buildResponseContract({
      opener,
      suggestions,
      sentrixAction,
      decision: null,
      evidence: {
        ranking_direction: direction,
        ranking_metric: metric,
        ranking_topN: selected.length,
        ranking_entityType: entityType,
        ranking_entities: selected.map(e => e[nameField]),
        ranking_values: selected.map(e => e[spec.field]),
      },
      focus: "ranking_extremes",
      confidence: "alta",
      // BRIEF CONEXION1 (ARCO B) · clientList al hilo · gateado a entityType "client" (SKU/otros → vacío →
      // arco B declara límite honesto · evita servir un SKU como "cuenta") · entidades reales, cero recompute.
      clientList: entityType === "client" ? selected.map(e => _buildEntityId("client", e[nameField])) : [],
      materialMetrics: selected.map(e => ({
        entity: e[nameField],
        metric,
        value: e[spec.field],
      })),
      reasoningPattern: "ranking_extremes",
      suggestedNextActions: [],
    }),
    // BRIEF M · spread externo · narrative_layer consumirá si flag ON
    narrative_signals,
    posture_hint,
  };
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF M.B.1 · HELPERS NARRATIVOS PARA RANKING_EXTREMES
//
// Construye narrative_signals + posture_hint a partir del resultado del
// composer ranking-extremes. Reutiliza catálogo INTERNAL_DRIVER_RULES de M.A.
// Decisión D2: spread externo en el return final del composer.
//
// Diferenciador topN routing:
//   · topN=1 → narrativa con apertura "X es tu peor Y · Z%"
//   · topN≥2 → narrativas ordinales · #1 "es tu peor" · #2 "El segundo..."
//     · #3 "El tercero..." · etc. NO clonar la misma frase de apertura.
// ════════════════════════════════════════════════════════════════════════════

// ── _ordinalSpanishMasc · 1→"primero" · 2→"segundo" · ... · default fallback ──
function _ordinalSpanishMasc(n) {
  const map = {
    1: "primero", 2: "segundo", 3: "tercero", 4: "cuarto", 5: "quinto",
    6: "sexto", 7: "séptimo", 8: "octavo", 9: "noveno", 10: "décimo",
  };
  return map[n] || `${n}º`;
}

// ── buildNarrativeSignalsForRankingExtremes ──────────────────────────────
// Para topN=1 retorna 1 signals object (el campeón).
// Para topN≥2 retorna { items: [signals_#1, signals_#2, ...] } para que el
// composer ranking-extremes genere narrativas ordinales separadas.
//
// Cada signals item respeta la decisión F1 (cifras runtime reales · cifras
// pequeñas plantean juicio de oportunidad).
function buildNarrativeSignalsForRankingExtremes(selected, direction, metric, entityType, scope) {
  if (!Array.isArray(selected) || selected.length === 0) return null;
  const spec = RANKING_EXTREMES_METRICS[metric];
  if (!spec) return null;
  const nameField = _getEntityNameField(metric);

  // Construir signals para 1 entity (helper interno)
  const buildSignalsForEntity = (entity, rankPosition) => {
    const driver = detectInternalDriver(entity, metric, entityType, scope);
    const recoverable = driver ? calculateRecoverable(entity, metric, entityType, driver, scope) : 0;
    const action = driver ? buildSuggestedAction(entity, metric, entityType, scope, recoverable) : null;
    const reframe = driver ? buildReframe(driver) : null;
    const severity = classifySeverity(driver?.vs_promedio || 0, recoverable);

    return {
      direction,
      rank_position: rankPosition,
      what: {
        entity: entity[nameField],
        value: entity[spec.field],
        unit: spec.unit,
        metric,
        metricKey: metric,
        entityType,
      },
      why: driver ? {
        mechanism: driver.mechanism,
        origin: "internal", // todas las reglas activas de M.A son origen interno
        target_entity: entity[nameField],
        driver,
      } : null,
      implication: {
        severity,
        // counter_intuition: true si hay driver interno · false si null
        counter_intuition: !!driver,
        recoverable_value: recoverable,
        recoverability: classifyRecoverability(driver),
        action,
        reframe,
      },
    };
  };

  if (selected.length === 1) {
    return buildSignalsForEntity(selected[0], 1);
  }
  // topN ≥ 2 · array de signals ordinales
  return {
    items: selected.map((e, idx) => buildSignalsForEntity(e, idx + 1)),
    direction,
    metric,
    entityType,
  };
}

// ── composeOpeningOrdinal · apertura para rank_position ≥ 2 ──────────────
// Cuando hay topN≥2 · cada entity posterior abre con ordinal · NO con
// "es tu peor" (que solo aplica al #1). Patrón asesor: jerarquía clara.
function composeOpeningOrdinal(signals) {
  const w = signals.what;
  if (!w) return "";
  const rank = signals.rank_position || 1;
  const valStr = w.unit === "%" ? `${w.value.toFixed(1)}%` :
                 w.unit === "x" ? `${w.value.toFixed(1)}x` :
                 w.unit === "d" ? `${Math.round(w.value)}d` :
                 w.unit === "$" ? _fmtMoneyK(w.value) :
                 String(w.value);
  const directionLabel = signals.direction === "best" ? "mejor" : "peor";
  const entityNounSingular = w.entityType === "client" ? "cliente" : "SKU";
  // rank_position=2 → "El segundo cliente con peor margen es Falabella · 22.0%."
  // rank_position=3 → "El tercero con peor margen es Sodimac · 23.5%."
  if (rank === 2) {
    return `El segundo ${entityNounSingular} con ${directionLabel} ${METRIC_LABEL[w.metricKey] || w.metric} es ${w.entity} · ${valStr}.`;
  }
  if (rank === 3) {
    return `El tercero con ${directionLabel} ${METRIC_LABEL[w.metricKey] || w.metric} es ${w.entity} · ${valStr}.`;
  }
  // rank ≥ 4 · forma numerada
  return `En posición ${_ordinalSpanishMasc(rank)} aparece ${w.entity} con ${directionLabel} ${METRIC_LABEL[w.metricKey] || w.metric} · ${valStr}.`;
}

// ── composeNarrativeForRankingItem · selecciona apertura por rank_position ──
// rank_position=1 → reframe interpretativo (si driver interno) o direct
// rank_position≥2 → ordinal · sin reframe interpretativo
// Causal + acción se incluyen SOLO si hay driver y solo en posiciones 1-2
// (en posiciones ≥3 la narrativa es más escueta · evita ruido).
function composeNarrativeForRankingItem(signals, posture, ctx) {
  if (!signals) return "";
  const rank = signals.rank_position || 1;
  const movements = [];

  // MOVIMIENTO 1 · Apertura
  if (rank === 1) {
    if (posture === "challenge" && signals.implication?.counter_intuition && signals.why) {
      movements.push(composeOpeningReframe(signals));
    } else {
      movements.push(composeOpeningDirect(signals));
    }
  } else {
    movements.push(composeOpeningOrdinal(signals));
  }

  // MOVIMIENTO 2 · Causalidad (solo si why y rank ≤ 2)
  if (signals.why && rank <= 2) {
    const causal = composeCausalMovement(signals.why, posture);
    if (causal) movements.push(causal);
  }

  // MOVIMIENTO 3 · Acción/implicación (solo rank=1)
  if (rank === 1) {
    if (signals.implication?.action) {
      const action = composeActionMovement(signals.implication, posture);
      if (action) movements.push(action);
    } else if (signals.implication?.severity) {
      const imp = composeImplicationOnly(signals.implication, posture);
      if (imp) movements.push(imp);
    }
  }

  // MOVIMIENTO 4 (opcional · rank=1) · Reframe ejecutivo final
  if (rank === 1 && posture === "challenge" && signals.implication?.reframe) {
    movements.push(composeReframeClosing(signals.implication.reframe));
  }

  return integrateMovements(movements, posture);
}

// ── composeRankingExtremesNarrative · entry point usado por el composer ──
// Recibe los signals (objeto único o {items[]}) + posture + ctx, retorna
// narrativa final lista para opener (PRE voice calibration).
// ── detectGroupPattern · clasificar set de items por driver detectado ────
// Categoriza un array de items signals según patrón de drivers internos.
// Salidas:
//   "all_same_driver"  · todos los items tienen el mismo mechanism
//   "mixed_drivers"    · todos tienen driver · pero mechanisms diferentes
//   "partial_drivers"  · algunos tienen driver · otros no
//   "no_driver_group"  · ninguno tiene driver detectable
function detectGroupPattern(items) {
  if (!Array.isArray(items) || items.length === 0) return "no_driver_group";
  const drivers = items.map(i => i?.why?.mechanism || null);
  const withDriver = drivers.filter(d => d != null);
  if (withDriver.length === 0) return "no_driver_group";
  if (withDriver.length === items.length) {
    const unique = new Set(withDriver);
    return unique.size === 1 ? "all_same_driver" : "mixed_drivers";
  }
  return "partial_drivers";
}

// ── composeRankingGroupNarrative · narrativa integrada para topN≥2 ───────
// Reemplaza el patrón anterior (replicar narrativa #1 + ordinales escuetos
// para #2-#3 huérfanos). El cliente pidió "los N peores" · entrega N análisis
// integrados como GRUPO · con pattern detection y agregaciones.
//
// Estructura output (siempre · independiente del pattern):
//   1. Lista de N con cifras: "Los N peores X son A (v) · B (v) · C (v)."
//   2. Pattern movement (depende de detectGroupPattern)
//      · all_same_driver  → reframe común + agregado + reframe ejecutivo (1 vez)
//      · partial_drivers  → "X e Y comparten driver · Z es distinto" + análisis subset
//      · mixed_drivers    → "los N tienen origen interno distinto" + outline
//      · no_driver_group  → "no hay driver interno obvio · sugerir drilldown"
function composeRankingGroupNarrative(items, posture, ctx) {
  if (!Array.isArray(items) || items.length === 0) return "";

  const head = items[0];
  const entityType = head?.what?.entityType || "client";
  const metricKey = head?.what?.metricKey || "margen";
  const metricLabel = METRIC_LABEL[metricKey] || metricKey;
  const direction = head?.direction || "worst";
  const directionLabel = direction === "worst" ? "peores" : "mejores";
  const entityPlural = entityType === "client" ? "clientes" : "SKUs";

  // ── MOVIMIENTO 1 · Lista de N con cifras (siempre) ──
  const listParts = items.map(it => {
    const w = it.what;
    const v = w.unit === "%" ? `${w.value.toFixed(1)}%`
            : w.unit === "x" ? `${w.value.toFixed(1)}x`
            : w.unit === "d" ? `${Math.round(w.value)}d`
            : String(w.value);
    return `${w.entity} (${v})`;
  });
  // Verbalización natural: "A · B · C" para 2-3 · "A · B · ... · Z" para N≥4
  const listStr = listParts.join(" · ");
  const listMovement = `Los ${items.length} ${directionLabel} ${entityPlural} por ${metricLabel} son ${listStr}.`;

  // ── MOVIMIENTO 2 · Pattern movement ──
  const pattern = detectGroupPattern(items);
  let patternMovement = "";

  if (pattern === "all_same_driver") {
    // Reframe común + agregado + reframe ejecutivo (una sola vez)
    const sharedMechanism = head.why.mechanism;
    const sharedFactor = head.why.driver?.factor;

    if (sharedFactor === "carga_comercial") {
      // Promedio de pctRebate del grupo
      const cargas = items.map(it => it.why.driver.value);
      const avgCarga = cargas.reduce((a, b) => a + b, 0) / cargas.length;
      // gap del grupo (vs promedio interno · usamos vs_promedio del head como referencia)
      const recoverables = items.map(it => it.implication?.recoverable_value || 0);
      const totalRecoverable = recoverables.reduce((a, b) => a + b, 0);
      const recoverablesBP = items.map(it => it.implication?.action?.bestPractice_recoverable_K || 0);
      const totalRecoverableBP = recoverablesBP.reduce((a, b) => a + b, 0);

      patternMovement = `Antes de mirar al ${entityType === "client" ? "cliente" : "producto"} · vale mirar adentro: los ${items.length} comparten el mismo driver. La carga comercial promedio del grupo es ${avgCarga.toFixed(1)}%. Si los ${items.length} se llevan al promedio interno · son ${_fmtMoneyK(totalRecoverable)} anuales recuperables · si bajan a mejor práctica (3.0%) · ${_fmtMoneyK(totalRecoverableBP)}.`;
    } else if (sharedFactor === "doh_alto") {
      const stocks = items.map(it => it.implication?.recoverable_value || 0);
      const totalStock = stocks.reduce((a, b) => a + b, 0);
      const dohs = items.map(it => it.why.driver.value);
      const avgDoh = dohs.reduce((a, b) => a + b, 0) / dohs.length;
      patternMovement = `El driver compartido es DOH alto · promedio ${Math.round(avgDoh)}d en el grupo. El capital atrapado entre los ${items.length} suma ${_fmtMoneyK(totalStock / 1000)}.`;
    } else {
      patternMovement = `Los ${items.length} comparten el mismo driver interno.`;
    }
  } else if (pattern === "partial_drivers") {
    // X e Y comparten · Z es distinto
    const withDriver = items.filter(it => it.why);
    const withoutDriver = items.filter(it => !it.why);
    const withNames = withDriver.map(it => it.what.entity).join(" y ");
    const withoutNames = withoutDriver.map(it => it.what.entity).join(" y ");
    if (withDriver.length > 0 && withoutDriver.length > 0) {
      patternMovement = `${withNames} ${withDriver.length === 1 ? "tiene" : "comparten"} driver interno detectable; ${withoutNames} ${withoutDriver.length === 1 ? "no" : "no lo comparten"}.`;
      // Si el subset común tiene carga_comercial · agregar recoverable subset
      const subsetCarga = withDriver.filter(it => it.why.driver?.factor === "carga_comercial");
      if (subsetCarga.length > 0) {
        const subsetRec = subsetCarga.reduce((s, it) => s + (it.implication?.recoverable_value || 0), 0);
        patternMovement += ` Sobre ${withNames} · si llevás la carga al promedio interno · son ${_fmtMoneyK(subsetRec)} anuales recuperables.`;
      }
    }
  } else if (pattern === "mixed_drivers") {
    // Cada uno tiene driver distinto · solo outline
    const mechanisms = items.map(it => ({ name: it.what.entity, mech: it.why.mechanism }));
    const outlineParts = mechanisms.map(m => `${m.name} (${_humanizeMechanism(m.mech)})`);
    patternMovement = `Los ${items.length} tienen origen interno distinto: ${outlineParts.join(" · ")}. Cada uno requiere intervención puntual.`;
  } else { // no_driver_group
    patternMovement = `Sin driver interno obvio en los ${items.length}. El gap vs benchmark puede ser mix-effect o pricing · sugerir drilldown por cliente.`;
  }

  // ── MOVIMIENTO 3 · Reframe ejecutivo (solo si pattern tiene driver común) ──
  let reframeMovement = "";
  if (pattern === "all_same_driver" || (pattern === "partial_drivers" && head.implication?.reframe)) {
    const reframe = items[0].implication?.reframe;
    if (reframe) reframeMovement = reframe;
  }

  const movements = [listMovement, patternMovement, reframeMovement].filter(m => m && m.length > 0);
  return movements.join("\n\n");
}

// ── _humanizeMechanism · etiqueta corta de mechanism para outlines ───────
function _humanizeMechanism(mechanism) {
  const m = {
    internal_commercial_load:    "carga comercial",
    internal_margin_compression: "margen unitario",
    structural_dependency:       "dependencia estructural",
    operational_inefficiency:    "DOH alto",
  };
  return m[mechanism] || mechanism;
}

// ── composeCrossMetricNarrative · cross-metric con contraste real (Ajuste B) ──
// El cross-metric NO clona "X es tu peor Y" del topN=1. Usa el set como
// contraste · interpreta lo que importa del ángulo cross.
//
// Estructura output:
//   1. Apertura cross: "Del top N {rankMetric} (set) · {winner} es el {sortDir} {sortMetric}."
//   2. Contraste: "{winner} rinde {value} vs {others_avg} de los otros · spread {spread}pp."
//   3. Reframe interpretativo (si counter_intuition): "Antes de mirar al cliente · vale mirar adentro."
//   4. Causal (si driver): "La carga sobre {winner} es X% · gap..."
//   5. Acción (si action): "Si negociás esa carga..."
//   6. Reframe ejecutivo (catálogo · si reframe)
function composeCrossMetricNarrative(signals, posture, ctx) {
  if (!signals || !signals.cross_metric || !signals.rank_context) return "";

  const rc = signals.rank_context;
  const w = signals.what;
  const gap = signals.winner_vs_others_gap;
  const setNames = Array.isArray(rc.set_entities) ? rc.set_entities.join(" · ") : "";
  const rankMetricLabel = METRIC_LABEL[rc.rankMetric] || rc.rankMetric;
  const sortMetricLabel = METRIC_LABEL[w.metricKey] || w.metric;
  const sortWord = signals.direction === "worst" ? "peor" : "mejor";

  const valStr = (v) => w.unit === "%" ? `${v.toFixed(1)}%`
                      : w.unit === "x" ? `${v.toFixed(1)}x`
                      : w.unit === "d" ? `${Math.round(v)}d`
                      : String(v);

  const movements = [];

  // MOVIMIENTO 1 · Apertura cross-metric
  movements.push(`Del top ${rc.rankN} ${rankMetricLabel} (${setNames}) · ${w.entity} es el ${sortWord} ${sortMetricLabel}.`);

  // MOVIMIENTO 2 · Contraste · "X rinde V vs O de los otros"
  if (gap && gap.spread != null) {
    const winnerVal = valStr(gap.winner_value);
    const othersVal = valStr(gap.others_avg);
    const spreadStr = w.unit === "%" ? `${gap.spread.toFixed(1)}pp` : `${gap.spread.toFixed(1)}`;
    // Si spread es chico (<1pp para %) · matizar
    const isNarrow = (w.unit === "%" && gap.spread < 1) || (w.unit !== "%" && gap.spread < 5);
    if (isNarrow) {
      movements.push(`${w.entity} rinde ${winnerVal} vs ${othersVal} promedio de los otros · los ${rc.rankN} son parecidos pero ${w.entity} queda ${spreadStr} por ${signals.direction === "worst" ? "debajo" : "encima"}.`);
    } else {
      movements.push(`${w.entity} rinde ${winnerVal} vs ${othersVal} promedio de los otros · ${spreadStr} de spread en el set.`);
    }
  }

  // MOVIMIENTO 3 · Reframe interpretativo (si counter_intuition · postura challenge)
  if (posture === "challenge" && signals.implication?.counter_intuition && signals.why) {
    const entityNoun = w.entityType === "client" ? "cliente" : "producto";
    movements.push(`Antes de mirar al ${entityNoun} · vale mirar adentro.`);
  }

  // MOVIMIENTO 4 · Causal (reusa M.A composeCausalMovement)
  if (signals.why) {
    const causal = composeCausalMovement(signals.why, posture);
    if (causal) movements.push(causal);
  }

  // MOVIMIENTO 5 · Acción (reusa M.A composeActionMovement)
  if (signals.implication?.action) {
    const action = composeActionMovement(signals.implication, posture);
    if (action) movements.push(action);
  }

  // MOVIMIENTO 6 · Reframe ejecutivo (catálogo founder)
  if (posture === "challenge" && signals.implication?.reframe) {
    movements.push(composeReframeClosing(signals.implication.reframe));
  }

  return movements.filter(m => m && m.length > 0).join("\n\n");
}

function composeRankingExtremesNarrative(signals, posture, ctx) {
  if (!signals || !VOICE_NARRATIVE_LAYER_ENABLED) return null;
  try {
    if (Array.isArray(signals.items)) {
      // topN ≥ 2 · narrativa integrada de grupo (Ajuste A · founder M.B.1)
      // Reemplaza el patrón viejo "replicar #1 + ordinales escuetos huérfanos".
      return composeRankingGroupNarrative(signals.items, posture, ctx);
    }
    // Caso topN=1 o cross-metric
    // Cross-metric usa composer dedicado · NO reusa itemNarrative para evitar
    // clonar "X es tu peor Y". El contraste con el set es la voz del cross.
    if (signals.cross_metric && signals.rank_context) {
      return composeCrossMetricNarrative(signals, posture, ctx);
    }

    const itemNarrative = composeNarrativeForRankingItem(signals, posture, ctx);
    return itemNarrative;
  } catch (err) {
    // eslint-disable-next-line no-console
    console.warn("BRIEF M.B.1 composeRankingExtremesNarrative error:", err);
    return null;
  }
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF M.B.2 · MECHANISM NARRATIVE INFRASTRUCTURE
//
// Mecanismos NO son entidades · son patrones causales (commercial_erosion ·
// quality_growth_deterioration · customer_dependency_risk · trapped_capital ·
// liquidity_compression). El composer narrativo debe:
//   1. Verbalizar mecanismo con impacto cuantificado (datos del scan agregado)
//   2. Distinguir derivados de raíz (quality_growth deriva de commercial_erosion)
//   3. Priorizar por controlabilidad × magnitud (NO solo monto)
//
// MECHANISM_NARRATIVE_RULES encapsula esto · análogo a INTERNAL_DRIVER_RULES
// de M.A pero para mecanismos en lugar de entity.metric.
// ════════════════════════════════════════════════════════════════════════════

const MECHANISM_NARRATIVE_RULES = {
  commercial_erosion: {
    label: "Erosión comercial",
    nature: "raíz",                    // raíz · derivado · estructural
    controllability: "alta",            // alta · media · baja
    horizon: "inmediato",               // inmediato (3-6m) · medio (6-12m) · largo (12-18m)
    reframe_key: "internal_commercial_load",
    severity_signal: (m) => "critica",  // siempre crítica si activo
    // extractor para narrativa scan
    headline: (m) => {
      const recK = m.aggregate.recuperable_total_K || 0;
      const recM_bp = m.aggregate.recuperable_total_M_at_3_0 || 0;
      const top3 = m.instances.slice(0, 3).map(i => i.clientName);
      return {
        recoverable_K: recK,
        recoverable_M_at_bestPractice: recM_bp,
        instances_count: m.instances.length,
        top3_names: top3,
      };
    },
  },
  quality_of_growth_deterioration: {
    label: "Deterioro de calidad de crecimiento",
    nature: "derivado",
    derived_from: "commercial_erosion",
    controllability: "media",
    horizon: "medio",
    reframe_key: "quality_growth_derived",
    severity_signal: () => "atencion",
    headline: (m) => ({
      contribPerdida_M: m.aggregate.contribucion_perdida_M || 0,
      instances_count: m.instances.length,
      crecimiento_range: m.aggregate.crecimiento_range,
    }),
  },
  customer_dependency_risk: {
    label: "Riesgo de dependencia de cliente",
    nature: "estructural",
    controllability: "baja",
    horizon: "largo",
    reframe_key: "structural_dependency",
    severity_signal: () => "atencion",
    headline: (m) => ({
      top3_names: m.aggregate.top3_names || [],
      top3_participacion_pct: m.aggregate.top3_participacion_pct || 0,
      top3_contribucion_M: m.aggregate.top3_contribucion_M || 0,
    }),
  },
  trapped_capital: {
    label: "Capital atrapado",
    nature: "raíz",
    controllability: "alta",
    horizon: "inmediato",
    reframe_key: "operational_inefficiency",
    severity_signal: () => "atencion",
    headline: (m) => ({
      // placeholder · scanMechanisms hoy retorna false en bonanza
      instances_count: m.instances?.length || 0,
    }),
  },
  liquidity_compression: {
    label: "Compresión de liquidez",
    nature: "estructural",
    controllability: "media",
    horizon: "medio",
    reframe_key: "structural_dependency",  // re-uso temporal · founder puede definir nuevo
    severity_signal: () => "atencion",
    headline: (m) => ({
      instances_count: m.instances?.length || 0,
    }),
  },
};

// ── buildNarrativeSignalsForMechanismScan ────────────────────────────────
// Construye signals para "panorama / mecanismos activos" (composeMechanismScan).
// Devuelve estructura tipo hierarchy con N mecanismos · pattern detection
// detecta si hay relación causal (derivado → raíz).
function buildNarrativeSignalsForMechanismScan(scan) {
  if (!scan || typeof scan !== "object") return null;
  const activos = [];
  const inactivos = [];
  for (const [id, m] of Object.entries(scan)) {
    if (m.triggered) activos.push({ id, m });
    else inactivos.push({ id, m });
  }
  if (activos.length === 0) return null;

  // Orden canónico: raíces primero · derivados después · estructurales al final
  const orderByNature = { "raíz": 0, "derivado": 1, "estructural": 2 };
  activos.sort((a, b) => {
    const na = orderByNature[MECHANISM_NARRATIVE_RULES[a.id]?.nature || "raíz"];
    const nb = orderByNature[MECHANISM_NARRATIVE_RULES[b.id]?.nature || "raíz"];
    return na - nb;
  });

  // Detectar pattern · ¿hay derivados que apuntan a raíces activas?
  // Si sí · narrativa puede decir "X deriva de Y" (causalidad)
  const hasDerivedFromRoot = activos.some(({ id }) => {
    const rule = MECHANISM_NARRATIVE_RULES[id];
    if (!rule || rule.nature !== "derivado") return false;
    const rootId = rule.derived_from;
    return rootId && activos.some(a => a.id === rootId);
  });

  // Construir hierarchy con narrative chunks por mecanismo
  const hierarchy = activos.map(({ id, m }) => {
    const rule = MECHANISM_NARRATIVE_RULES[id] || {};
    return {
      mechanismId: id,
      label: rule.label || m.nombre,
      nature: rule.nature || "raíz",
      controllability: rule.controllability || "media",
      horizon: rule.horizon || "medio",
      derived_from: rule.derived_from || null,
      severity: rule.severity_signal ? rule.severity_signal(m) : "atencion",
      headline: rule.headline ? rule.headline(m) : {},
      reframe_key: rule.reframe_key || null,
    };
  });

  return {
    kind: "mechanism_scan",
    hierarchy,
    activos_count: activos.length,
    inactivos_count: inactivos.length,
    inactivos_names: inactivos.map(({ m }) => m.nombre),
    has_derived_from_root: hasDerivedFromRoot,
    // posture: prioritize · siempre para mechanism_scan
  };
}

// ── buildNarrativeSignalsForMechanismRanking ─────────────────────────────
// Construye signals para "cuál es el problema más grave" (composeMechanismRanking).
// Foca en el TOP mecanismo aplicando criterio controlabilidad × magnitud.
function buildNarrativeSignalsForMechanismRanking(scan) {
  if (!scan || typeof scan !== "object") return null;
  const activos = [];
  for (const [id, m] of Object.entries(scan)) {
    if (m.triggered) activos.push({ id, m });
  }
  if (activos.length === 0) return null;

  // Ranking ejecutivo: controlabilidad × magnitud (NO solo monto)
  // Heurística determinística · score por categoría:
  const controllabilityScore = { "alta": 3, "media": 2, "baja": 1 };
  const natureScore = { "raíz": 3, "derivado": 2, "estructural": 1 };
  activos.sort((a, b) => {
    const ra = MECHANISM_NARRATIVE_RULES[a.id] || {};
    const rb = MECHANISM_NARRATIVE_RULES[b.id] || {};
    const sa = (controllabilityScore[ra.controllability] || 2) + (natureScore[ra.nature] || 2);
    const sb = (controllabilityScore[rb.controllability] || 2) + (natureScore[rb.nature] || 2);
    return sb - sa;
  });

  const top = activos[0];
  const topRule = MECHANISM_NARRATIVE_RULES[top.id] || {};
  const others = activos.slice(1, 3).map(({ id, m }) => ({
    id, label: (MECHANISM_NARRATIVE_RULES[id]?.label || m.nombre),
    rule: MECHANISM_NARRATIVE_RULES[id] || {},
    headline: MECHANISM_NARRATIVE_RULES[id]?.headline ? MECHANISM_NARRATIVE_RULES[id].headline(m) : {},
  }));

  return {
    kind: "mechanism_ranking",
    top: {
      mechanismId: top.id,
      label: topRule.label || top.m.nombre,
      nature: topRule.nature || "raíz",
      controllability: topRule.controllability || "media",
      horizon: topRule.horizon || "medio",
      headline: topRule.headline ? topRule.headline(top.m) : {},
      reframe_key: topRule.reframe_key || null,
    },
    others,
    activos_count: activos.length,
  };
}

// ── composeMechanismScanNarrative · narrativa "panorama del negocio" ─────
// Postura: prioritize · jerarquía + interpretación causal + reframe ejecutivo.
function composeMechanismScanNarrative(signals, posture, ctx) {
  if (!signals || signals.kind !== "mechanism_scan") return null;
  const movements = [];

  // MOVIMIENTO 1 · Apertura jerárquica
  const N = signals.activos_count;
  const labels = signals.hierarchy.map(h => h.label);
  const labelStr = labels.length === 1 ? labels[0]
                 : labels.length === 2 ? labels.join(" y ")
                 : labels.slice(0, -1).join(" · ") + " · " + labels[labels.length - 1];
  movements.push(`La cartera presenta ${N} ${N === 1 ? "mecanismo activo" : "mecanismos activos"} hoy: ${labelStr}.`);

  // MOVIMIENTO 2 · Cuerpo por mecanismo · interpretación con cifras
  const bodyParts = signals.hierarchy.map(h => {
    const hl = h.headline || {};
    if (h.mechanismId === "commercial_erosion") {
      const recK = hl.recoverable_K || 0;
      const recM_bp = hl.recoverable_M_at_bestPractice || 0;
      const top3 = (hl.top3_names || []).join(" · ");
      const recM_bp_str = recM_bp >= 1 ? `$${recM_bp.toFixed(2)}M` : `${_fmtMoneyK(recM_bp * 1000)}`;
      return `${h.label} concentra ${_fmtMoneyK(recK)} anuales recuperables al promedio interno · ${recM_bp_str} si la carga baja a mejor práctica (3.0%). Opera sobre ${hl.instances_count} cuentas: ${top3}. Controlabilidad alta · intervención inmediata.`;
    }
    if (h.mechanismId === "quality_of_growth_deterioration") {
      const cp = hl.contribPerdida_M || 0;
      const range = hl.crecimiento_range || {};
      const rangeStr = range.min === range.max ? `+${range.min}%` : `entre +${range.min}% y +${range.max}%`;
      const cp_str = cp >= 1 ? `$${cp.toFixed(2)}M` : _fmtMoneyK(cp * 1000);
      const derivedNote = h.derived_from === "commercial_erosion"
        ? ` Es derivado de erosión comercial · la carga sostenida es la causa.`
        : "";
      return `${h.label} opera sobre ${hl.instances_count} cuentas creciendo ${rangeStr} a costa de margen unitario · ${cp_str} de contribución que se pierde vs benchmark.${derivedNote}`;
    }
    if (h.mechanismId === "customer_dependency_risk") {
      const top3 = (hl.top3_names || []).join(" · ");
      const part = hl.top3_participacion_pct || 0;
      const contrib = hl.top3_contribucion_M || 0;
      const contrib_str = contrib >= 1 ? `$${contrib.toFixed(2)}M` : _fmtMoneyK(contrib * 1000);
      return `${h.label}: ${top3} concentran ${part.toFixed(1)}% de la venta y ${contrib_str} de contribución. Estructural · horizonte 12-18 meses vía diversificación.`;
    }
    if (h.mechanismId === "trapped_capital") {
      return `${h.label} · revisar drilldown por categoría de inventario para cuantificación.`;
    }
    if (h.mechanismId === "liquidity_compression") {
      return `${h.label} · ${hl.instances_count} señales detectadas.`;
    }
    return "";
  }).filter(p => p && p.length > 0);
  movements.push(...bodyParts);

  // MOVIMIENTO 3 · Interpretación causal (si hay derivado → raíz activos)
  if (signals.has_derived_from_root) {
    const root = signals.hierarchy.find(h => h.nature === "raíz");
    const derived = signals.hierarchy.find(h => h.nature === "derivado" && h.derived_from === root?.mechanismId);
    if (root && derived) {
      movements.push(`Intervenir sobre ${root.label.toLowerCase()} reduce automáticamente parte del costo de ${derived.label.toLowerCase()}: atacar la raíz desactiva el síntoma.`);
    }
  }

  // MOVIMIENTO 4 · Reframe ejecutivo
  // Para scan multi-mecanismo · usar mechanism_priority_controllability (cuando hay >1 activo)
  if (N > 1 && EXECUTIVE_REFRAMES.mechanism_priority_controllability) {
    movements.push(EXECUTIVE_REFRAMES.mechanism_priority_controllability);
  }

  return movements.filter(m => m && m.length > 0).join("\n\n");
}

// ── composeMechanismRankingNarrative · "cuál es el problema más grave" ───
// Postura: prioritize · TOP mecanismo + interpretación de prioridad (NO monto).
function composeMechanismRankingNarrative(signals, posture, ctx) {
  if (!signals || signals.kind !== "mechanism_ranking") return null;
  const movements = [];
  const top = signals.top;
  const hl = top.headline || {};

  // MOVIMIENTO 1 · Apertura: TOP con criterio explícito
  // Asesor dice POR QUÉ es el más grave (controlabilidad × magnitud · NO solo monto)
  movements.push(`El problema más grave para atacar ahora es ${top.label.toLowerCase()} · combina alta controlabilidad y horizonte inmediato.`);

  // MOVIMIENTO 2 · Cuerpo del TOP con cifras
  if (top.mechanismId === "commercial_erosion") {
    const recK = hl.recoverable_K || 0;
    const recM_bp = hl.recoverable_M_at_bestPractice || 0;
    const top3 = (hl.top3_names || []).join(" · ");
    const recM_bp_str = recM_bp >= 1 ? `$${recM_bp.toFixed(2)}M` : _fmtMoneyK(recM_bp * 1000);
    movements.push(`Concentra ${_fmtMoneyK(recK)} anuales recuperables al promedio interno · ${recM_bp_str} si la carga baja a mejor práctica. Opera sobre ${hl.instances_count} cuentas: ${top3}.`);
  } else if (top.mechanismId === "quality_of_growth_deterioration") {
    const cp = hl.contribPerdida_M || 0;
    const cp_str = cp >= 1 ? `$${cp.toFixed(2)}M` : _fmtMoneyK(cp * 1000);
    movements.push(`${cp_str} de contribución perdida vs benchmark sobre ${hl.instances_count} cuentas.`);
  } else if (top.mechanismId === "customer_dependency_risk") {
    const top3 = (hl.top3_names || []).join(" · ");
    const part = hl.top3_participacion_pct || 0;
    movements.push(`${top3} concentran ${part.toFixed(1)}% de la venta.`);
  }

  // MOVIMIENTO 3 · Otros mecanismos · jerarquía explícita
  if (signals.others && signals.others.length > 0) {
    const otherLabels = signals.others.map(o => {
      const ohl = o.headline || {};
      if (o.id === "quality_of_growth_deterioration") {
        const cp = ohl.contribPerdida_M || 0;
        const cp_str = cp >= 1 ? `$${cp.toFixed(2)}M` : _fmtMoneyK(cp * 1000);
        return `${o.label.toLowerCase()} (${cp_str} · ${o.rule.controllability || "media"} controlabilidad)`;
      }
      if (o.id === "customer_dependency_risk") {
        const part = ohl.top3_participacion_pct || 0;
        return `${o.label.toLowerCase()} (${part.toFixed(1)}% concentración · estructural)`;
      }
      if (o.id === "commercial_erosion") {
        const recK = ohl.recoverable_K || 0;
        return `${o.label.toLowerCase()} (${_fmtMoneyK(recK)} · alta controlabilidad)`;
      }
      return o.label.toLowerCase();
    });
    movements.push(`Los otros mecanismos activos son ${otherLabels.join(" y ")}.`);
  }

  // MOVIMIENTO 4 · Reframe ejecutivo
  if (top.reframe_key && EXECUTIVE_REFRAMES[top.reframe_key]) {
    movements.push(EXECUTIVE_REFRAMES[top.reframe_key]);
  }

  return movements.filter(m => m && m.length > 0).join("\n\n");
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF M.B.3 · DEEP-DIVE NARRATIVE INFRASTRUCTURE
//
// Deep-dive es ficha ejecutiva interpretada · NO ranking. Estructura narrativa:
//   1. Identidad ejecutiva (posición en portafolio · Tier · contribución relativa)
//   2. Métricas críticas con anclaje (margen vs benchmark · carga vs promedio)
//   3. Driver interno si aplica (postura challenge · RULE-VOICE-001/002 heredadas)
//   4. Reframe ejecutivo del catálogo founder cuando hay driver
//
// Composers:
//   · getClientDeepDive          · direct add (struct plano)
//   · composeSkuDeepDive         · spread externo D2 (buildResponseContract)
//   · composeSkuOperationalAnalysis · direct add · usa composer DEDICADO
//                                     "composeSkuOperationalNarrative" porque
//                                     "capital atrapado" tiene voz distinta a
//                                     "los N peores por X" (D-MB3-3 aprobado).
//
// Helper local _detectSkuDeepDiveDriver evita extender M.A LOCKED (D-MB3-1).
// ════════════════════════════════════════════════════════════════════════════

// ── _deriveTierFromContribution · 3 tiers por participación (D-MB3-5) ────
// ≥10% → Tier 1 · 3-10% → Tier 2 · <3% → Tier 3.
// Founder puede ajustar umbrales en V_VISUAL si detecta cosa rara.
function _deriveTierFromContribution(entityName, ventasScope) {
  if (!entityName || !Array.isArray(ventasScope) || ventasScope.length === 0) return null;
  const total = ventasScope.reduce((s, c) => s + (c.actual || 0), 0);
  const entity = ventasScope.find(c => c.nombre === entityName);
  if (!entity || total === 0) return null;
  const pct = (entity.actual / total) * 100;
  let tier;
  if (pct >= 10) tier = 1;
  else if (pct >= 3) tier = 2;
  else tier = 3;
  return { tier, participacion_pct: +pct.toFixed(2), ventas_K: entity.actual };
}

// ── _detectSkuDeepDiveDriver · híbrido inventario+margen (D-MB3-1) ───────
// Combina campos de skuInventario (rotacion/doh/stockUSD) y skusMargen
// (margen/pctRebate/benchmark) para detectar driver interno operacional o
// comercial. Helper LOCAL a M.B.3 · NO toca catálogo M.A.
//
// Reglas:
//   · Si DOH > 90 → operational_inefficiency (prioritario · capital atrapado)
//   · Si margen < benchmark - 10 y pctRebate > avg + 0.5 → internal_commercial_load
//   · Si margen < benchmark - 10 sin gap pctRebate → internal_margin_compression
function _detectSkuDeepDiveDriver(skuInv, skuMargen, marginScope) {
  if (!skuInv && !skuMargen) return null;

  // 1. Operacional · DOH alto · prioridad
  if (skuInv && typeof skuInv.doh === "number" && skuInv.doh > 90) {
    return {
      mechanism: "operational_inefficiency",
      factor: "doh_alto",
      value: skuInv.doh,
      unit: "d",
      stockUSD: skuInv.stockUSD || 0,
      rotacion: skuInv.rotacion,
      chain: ["doh_alto", "capital_inmovilizado"],
    };
  }

  // 2. Comercial · margen bajo + carga alta
  if (skuMargen && skuMargen.benchmark && skuMargen.margen != null) {
    const gapBenchmark = skuMargen.benchmark - skuMargen.margen;
    if (gapBenchmark > 10) {
      const avgRebate = Array.isArray(marginScope) && marginScope.length > 0
        ? marginScope.reduce((s, k) => s + (k.pctRebate || 0), 0) / marginScope.length
        : 0;
      const gapRebate = (skuMargen.pctRebate || 0) - avgRebate;
      if (gapRebate > 0.5) {
        return {
          mechanism: "internal_commercial_load",
          factor: "carga_comercial",
          value: skuMargen.pctRebate,
          vs_promedio: +gapRebate.toFixed(2),
          unit: "pp",
          chain: ["carga_comercial_alta", "margen_unitario_bajo"],
          borderline: false,
        };
      }
      // Solo margen bajo · sin carga alta · driver = margen unitario
      return {
        mechanism: "internal_margin_compression",
        factor: "margen_unitario",
        value: skuMargen.margen,
        vs_benchmark: +gapBenchmark.toFixed(1),
        unit: "pp",
        chain: ["margen_unitario_bajo"],
      };
    }
  }
  return null;
}

// ── _calculateSkuDeepDiveRecoverable ─────────────────────────────────────
function _calculateSkuDeepDiveRecoverable(driver, skuMargen, skuInv) {
  if (!driver) return 0;
  if (driver.factor === "doh_alto") {
    return Math.round((skuInv?.stockUSD || 0) / 1000);  // en $K
  }
  if (driver.factor === "carga_comercial" && skuMargen) {
    return Math.round((skuMargen.venta || 0) * (driver.vs_promedio / 100));
  }
  if (driver.factor === "margen_unitario" && skuMargen) {
    return Math.round((skuMargen.venta || 0) * (driver.vs_benchmark / 100));
  }
  return 0;
}

// ── buildNarrativeSignalsForClientDeepDive ───────────────────────────────
// Construye signals para getClientDeepDive · identidad ejecutiva + driver
// (si aplica · reusa INTERNAL_DRIVER_RULES de M.A).
function buildNarrativeSignalsForClientDeepDive(clientName, scenarioId) {
  if (!clientName) return null;
  try {
    const ventasScope = applyScenarioToClientesVentas(scenarioId);
    const margenScope = applyScenarioToClientesMargen(scenarioId).filter(c => c.tipo === "cliente");
    const ventasEntity = ventasScope.find(c => c.nombre === clientName);
    const margenEntity = margenScope.find(c => c.nombre === clientName);
    if (!ventasEntity || !margenEntity) return null;

    const tierInfo = _deriveTierFromContribution(clientName, ventasScope);

    // Detector reusa catálogo M.A · cliente.margen
    const driver = detectInternalDriver(margenEntity, "margen", "client", margenScope);
    const recoverable = driver ? calculateRecoverable(margenEntity, "margen", "client", driver, margenScope) : 0;
    const action = driver ? buildSuggestedAction(margenEntity, "margen", "client", margenScope, recoverable) : null;
    const reframe = driver ? buildReframe(driver) : null;

    // Calcular total contribución para el % del cliente
    const totalContribucion = margenScope.reduce((s, c) => s + (c.contribucion || 0), 0);
    const contribucion_pct = totalContribucion > 0
      ? +((margenEntity.contribucion / totalContribucion) * 100).toFixed(1)
      : 0;

    return {
      kind: "client_deep_dive",
      identity: {
        entity: clientName,
        tier: tierInfo?.tier || null,
        participacion_pct: tierInfo?.participacion_pct || 0,
        ventas_K: tierInfo?.ventas_K || 0,
        contribucion_K: margenEntity.contribucion || 0,
        contribucion_pct,
      },
      what: {
        entity: clientName,
        margen: margenEntity.margen,
        benchmark: margenEntity.benchmark || 30.1,
        pctRebate: margenEntity.pctRebate,
      },
      why: driver ? {
        mechanism: driver.mechanism,
        origin: "internal",
        target_entity: clientName,
        driver,
      } : null,
      implication: {
        severity: classifySeverity(driver?.vs_promedio || 0, recoverable),
        counter_intuition: !!driver,
        recoverable_value: recoverable,
        recoverability: classifyRecoverability(driver),
        action,
        reframe,
      },
    };
  } catch (err) {
    // eslint-disable-next-line no-console
    console.warn("BRIEF M.B.3 client deep-dive signals error:", err);
    return null;
  }
}

// ── buildNarrativeSignalsForSkuDeepDive ──────────────────────────────────
// Para SKU deep-dive. Modo isCritico (DOH alto · driver operational) ·
// isVirtuoso (rotación alta · sin driver · postura validate) · intermedio.
function buildNarrativeSignalsForSkuDeepDive(skuName, scenarioId) {
  if (!skuName) return null;
  try {
    // Datasets · scenarioId aplica a inventario via applyScenarioToSkuInventario
    const invScope = applyScenarioToSkuInventario(scenarioId);
    const marginScope = skusMargen.filter(s => s.tipo === "sku");
    const skuInv = invScope.find(s => s.sku === skuName);
    const skuMargen = marginScope.find(s => s.nombre === skuName);
    if (!skuInv) return null;

    // Clasificación isCritico/isVirtuoso/intermedio (consistente con composer Ferrari)
    const isCritico = skuInv.alerta === "crit" || skuInv.estado === "120d" || (skuInv.doh && skuInv.doh > 90);
    const isVirtuoso = skuInv.rotacion >= 8 && skuInv.alerta === "ok" && (skuInv.margenPct || 0) >= 25;

    const driver = _detectSkuDeepDiveDriver(skuInv, skuMargen, marginScope);
    const recoverable = driver ? _calculateSkuDeepDiveRecoverable(driver, skuMargen, skuInv) : 0;
    const reframe = driver ? buildReframe(driver) : null;

    return {
      kind: "sku_deep_dive",
      sku_mode: isCritico ? "critico" : (isVirtuoso ? "virtuoso" : "intermedio"),
      identity: {
        entity: skuName,
        marca: skuInv.marca,
        sfamilia: skuInv.sfamilia,
        bodega: skuInv.bodega,
        stockUSD: skuInv.stockUSD,
      },
      what: {
        rotacion: skuInv.rotacion,
        doh: skuInv.doh,
        cobertura: skuInv.cobertura,
        margenPct: skuInv.margenPct,
        margenFin: skuMargen?.margen || null,
        benchmark: skuMargen?.benchmark || 30.1,
        pctRebate: skuMargen?.pctRebate || null,
      },
      why: driver ? {
        mechanism: driver.mechanism,
        origin: "internal",
        target_entity: skuName,
        driver,
      } : null,
      implication: {
        severity: isCritico ? "critica" : (isVirtuoso ? "seguir" : "atencion"),
        counter_intuition: !!driver,
        recoverable_value: recoverable,
        recoverability: classifyRecoverability(driver),
        action: driver ? {
          verb: driver.factor === "doh_alto" ? "liquidar" : "revisar_pricing",
          target_entity: skuName,
          recoverable_K: recoverable,
        } : null,
        reframe,
      },
    };
  } catch (err) {
    // eslint-disable-next-line no-console
    console.warn("BRIEF M.B.3 sku deep-dive signals error:", err);
    return null;
  }
}

// ── buildNarrativeSignalsForSkuOperational ───────────────────────────────
// Para composeSkuOperationalAnalysis · top4 SKUs críticos como grupo.
// Capital atrapado agregado · DOH promedio · acción liquidación.
// ── classifySkuOperationalProfile · perfil individual del SKU ────────────
// operational_inefficient · DOH > 90 ∧ rotación < 3 → driver activo · liquidar
// high_volume_healthy    · DOH ≤ 90 ∧ rotación ≥ 3 → stock alto pero saludable
// borderline             · cuadrantes mixtos (rotación lenta con stock bajo · o
//                          rotación buena con DOH alto) · sugerir drilldown
function classifySkuOperationalProfile(sku) {
  if (sku.doh > 90 && sku.rotacion < 3) return "operational_inefficient";
  if (sku.doh <= 90 && sku.rotacion >= 3) return "high_volume_healthy";
  return "borderline";
}

function buildNarrativeSignalsForSkuOperational(top4) {
  if (!Array.isArray(top4) || top4.length === 0) return null;
  // Clasificación por perfil (M.B.3 v2 · founder Caso E ajuste)
  const profiles = top4.map(s => ({
    sku: s.sku, marca: s.marca, sfamilia: s.sfamilia,
    stockUSD: s.stockUSD, doh: s.doh, rotacion: s.rotacion, alerta: s.alerta,
    profile: classifySkuOperationalProfile(s),
  }));
  const operationalCount = profiles.filter(p => p.profile === "operational_inefficient").length;
  const healthyCount = profiles.filter(p => p.profile === "high_volume_healthy").length;
  const borderlineCount = profiles.filter(p => p.profile === "borderline").length;

  // Pattern detection · 3 escenarios narrativos
  let pattern;
  if (operationalCount === top4.length) pattern = "all_operational";
  else if (operationalCount > 0 && healthyCount > 0) pattern = "mixed_operational_healthy";
  else pattern = "borderline_group";

  // Agregados · totales del grupo completo Y del subset operacional
  // Decisión founder Caso E: cifras agregadas SOLO sobre subset operacional
  // (no diluir el monto recuperable con SKUs que NO requieren intervención).
  const totalStockUSD = top4.reduce((s, k) => s + (k.stockUSD || 0), 0);
  const avgDoh = top4.reduce((s, k) => s + (k.doh || 0), 0) / top4.length;
  const operationalSubset = profiles.filter(p => p.profile === "operational_inefficient");
  const operationalStockUSD = operationalSubset.reduce((s, k) => s + (k.stockUSD || 0), 0);
  const operationalAvgDoh = operationalSubset.length > 0
    ? operationalSubset.reduce((s, k) => s + (k.doh || 0), 0) / operationalSubset.length
    : 0;
  const healthySubset = profiles.filter(p => p.profile === "high_volume_healthy");

  return {
    kind: "sku_operational_group",
    items: profiles,                         // todos los 4 con su profile tag
    operational_subset: operationalSubset,   // solo operacionales · para acción
    healthy_subset: healthySubset,           // solo saludables · para nota
    aggregate: {
      total_stockUSD: totalStockUSD,
      avg_doh: +avgDoh.toFixed(1),
      count: top4.length,
      // Subset operacional · cifras que importan para la acción
      operational_count: operationalCount,
      operational_stockUSD: operationalStockUSD,
      operational_avg_doh: +operationalAvgDoh.toFixed(1),
      healthy_count: healthyCount,
      borderline_count: borderlineCount,
    },
    pattern,
    reframe_key: "operational_inefficiency",
  };
}

// ── composeClientDeepDiveNarrative ───────────────────────────────────────
// Narrativa deep-dive cliente · identidad → métricas → driver → reframe.
function composeClientDeepDiveNarrative(signals, posture, ctx) {
  if (!signals || signals.kind !== "client_deep_dive") return null;
  const movements = [];
  const id = signals.identity;
  const w = signals.what;

  // MOVIMIENTO 1 · Identidad ejecutiva
  // "Falabella es tu cliente Tier 1 · 18.5% de la venta y 16.4% de contribución · $18.5M ventas anuales."
  const tierStr = id.tier ? `Tier ${id.tier}` : "Tier no clasificado";
  const ventasStr = id.ventas_K >= 1000
    ? `$${(id.ventas_K / 1000).toFixed(1)}M ventas anuales`
    : `${_fmtMoneyK(id.ventas_K)} ventas anuales`;
  movements.push(`${id.entity} es tu cliente ${tierStr} · ${id.participacion_pct.toFixed(1)}% de la venta y ${id.contribucion_pct.toFixed(1)}% de contribución · ${ventasStr}.`);

  // MOVIMIENTO 2 · Métricas críticas con anclaje
  const gapBench = (w.benchmark - w.margen).toFixed(1);
  const dirBench = w.margen < w.benchmark ? "bajo" : "sobre";
  const cargaClause = w.pctRebate != null ? ` La carga comercial es ${w.pctRebate.toFixed(1)}%.` : "";
  movements.push(`El margen está en ${w.margen.toFixed(1)}% · ${gapBench}pp ${dirBench} el benchmark de industria (${w.benchmark.toFixed(1)}%).${cargaClause}`);

  // MOVIMIENTO 3 · Driver interpretativo (postura challenge si counter_intuition)
  if (posture === "challenge" && signals.why) {
    movements.push(`Antes de mirar al cliente · vale mirar adentro.`);
    const causal = composeCausalMovement(signals.why, posture);
    if (causal) movements.push(causal);
    if (signals.implication?.action) {
      const action = composeActionMovement(signals.implication, posture);
      if (action) movements.push(action);
    }
  }

  // MOVIMIENTO 4 · Reframe ejecutivo founder
  if (posture === "challenge" && signals.implication?.reframe) {
    movements.push(composeReframeClosing(signals.implication.reframe));
  }

  return movements.filter(m => m && m.length > 0).join("\n\n");
}

// ── composeSkuDeepDiveNarrative ──────────────────────────────────────────
// Narrativa deep-dive SKU · 3 modos · identity → operacional → driver/reframe
function composeSkuDeepDiveNarrative(signals, posture, ctx) {
  if (!signals || signals.kind !== "sku_deep_dive") return null;
  const movements = [];
  const id = signals.identity;
  const w = signals.what;

  // MOVIMIENTO 1 · Identidad ejecutiva
  // "LG-DRYER8KG · marca LG · familia Línea Blanca · stock $13.6K en bodega Valparaíso."
  const stockStr = _fmtMoneyK(id.stockUSD / 1000);
  movements.push(`${id.entity} · marca ${id.marca} · familia ${id.sfamilia} · stock ${stockStr} en bodega ${id.bodega}.`);

  // MOVIMIENTO 2 · Métricas operacionales con calificación
  if (signals.sku_mode === "critico") {
    movements.push(`Rotación ${w.rotacion.toFixed(1)}x · DOH ${Math.round(w.doh)}d · margen ${w.margenPct}%. Es un SKU crítico por baja velocidad de conversión.`);
  } else if (signals.sku_mode === "virtuoso") {
    movements.push(`Rotación ${w.rotacion.toFixed(1)}x · DOH ${Math.round(w.doh)}d · margen ${w.margenPct}%. SKU virtuoso: alta rotación y margen sobre benchmark interno.`);
  } else {
    movements.push(`Rotación ${w.rotacion.toFixed(1)}x · DOH ${Math.round(w.doh)}d · margen ${w.margenPct}%. Operación dentro de rango intermedio.`);
  }

  // MOVIMIENTO 3 · Arco: Mecanismo · Impacto · Acción (siempre presente · gradúa por contenido).
  // ARCO_ENABLED: presencia del arco depende de signals.why (contenido), NO de posture (tono).
  if ((ARCO_ENABLED || posture === "challenge") && signals.why) {
    movements.push(`Antes de mirar al producto · vale mirar adentro.`);
    if (signals.why.driver.factor === "doh_alto") {
      const stockK = signals.implication?.recoverable_value || 0;
      movements.push(`El DOH acumula ${Math.round(signals.why.driver.value)} días · capital atrapado en stock que no rota.`);
      movements.push(`Acción: un plan de salida libera ${_fmtMoneyK(stockK)} de capital inmovilizado.`);
    } else if (signals.why.driver.factor === "carga_comercial") {
      const d = signals.why.driver;
      const recK = signals.implication?.recoverable_value || 0;
      movements.push(`La carga comercial sobre ${id.entity} es ${d.value.toFixed(1)}% · ${d.vs_promedio.toFixed(2)} puntos sobre el promedio interno.`);
      movements.push(`Acción: si se lleva la carga al promedio · son ${_fmtMoneyK(recK)} anuales recuperables.`);
    } else if (signals.why.driver.factor === "margen_unitario") {
      const d = signals.why.driver;
      const recK = signals.implication?.recoverable_value || 0;
      movements.push(`El margen unitario está ${d.vs_benchmark.toFixed(1)}pp bajo el benchmark de industria.`);
      movements.push(`Acción: recuperarlo al benchmark libera ${_fmtMoneyK(recK)} anuales en contribución.`);
    }
  } else if (ARCO_ENABLED && !signals.why) {
    // Rama SANA explícita (why === null) · fortaleza con cifras reales · contextualiza vs promedio
    // de CARTERA · puro render (promedios inline · patrón composeSkuDeepDive L16081) · sin tocar señales.
    const _avgRot = skuInventario.reduce((s, x) => s + x.rotacion, 0) / skuInventario.length;
    const _avgMrg = skuInventario.reduce((s, x) => s + x.margenPct, 0) / skuInventario.length;
    const _rotCtx = w.rotacion >= _avgRot + 1
      ? `Rotación ${w.rotacion.toFixed(1)}x sobre el promedio de cartera`
      : `Rotación ${w.rotacion.toFixed(1)}x en línea con el promedio de cartera`;
    const _mrgCtx = w.margenPct >= _avgMrg + 1
      ? `margen ${w.margenPct}% sobre el promedio`
      : (w.margenPct >= _avgMrg - 1 ? `margen ${w.margenPct}% en línea con el promedio` : `margen ${w.margenPct}% sólido`);
    movements.push(`${_rotCtx} · ${_mrgCtx}. Capital trabajando, sin gap que recuperar.`);
    const _rotWatch = w.rotacion >= _avgRot + 1
      ? `monitorear que rotación y margen no se deterioren`
      : `monitorear que la rotación no ceda`;
    movements.push(`Acción: mantener · es capital trabajando · ${_rotWatch}.`);
  } else if (signals.sku_mode === "virtuoso") {
    // Legacy (ARCO_ENABLED=false) · narrativa de fortaleza original.
    movements.push(`Es un SKU para proteger y escalar · referente operacional dentro del portafolio.`);
  }

  // MOVIMIENTO 4 · Reframe ejecutivo (sale si existe · null en sano · fail-safe · ya no gateado por tono)
  if (ARCO_ENABLED ? !!signals.implication?.reframe : (posture === "challenge" && signals.implication?.reframe)) {
    movements.push(composeReframeClosing(signals.implication.reframe));
  }

  return movements.filter(m => m && m.length > 0).join("\n\n");
}

// ── composeSkuOperationalNarrative · composer dedicado (D-MB3-3 · B.3.B) ──
// "Capital atrapado" tiene voz distinta a "los N peores por X". Composer
// dedicado · grupo + agregación + reframe operational_inefficiency.
function composeSkuOperationalNarrative(signals, posture, ctx) {
  if (!signals || signals.kind !== "sku_operational_group") return null;
  const movements = [];
  const N = signals.aggregate.count;
  const totalStockUSD = signals.aggregate.total_stockUSD;
  const avgDoh = signals.aggregate.avg_doh;
  const totalStr = _fmtMoneyK(totalStockUSD / 1000);

  // Helper local · formato SKU individual
  const fmtSku = (it) => {
    const stockK = _fmtMoneyK(it.stockUSD / 1000);
    return `${it.sku} (${stockK} · ${Math.round(it.doh)}d DOH · rotación ${it.rotacion.toFixed(1)}x)`;
  };

  // ── MOVIMIENTO 1 · Apertura · siempre menciona el grupo completo ──
  // M.B.3 v2: cambiar "concentran capital atrapado" por "concentran $X de stock"
  // porque no todos están atrapados (mixed_operational_healthy lo aclara después).
  if (signals.pattern === "all_operational") {
    movements.push(`${N} SKUs concentran capital atrapado · ${totalStr} de stock con DOH promedio ${Math.round(avgDoh)}d.`);
  } else {
    // mixed · borderline · usar lenguaje neutro
    movements.push(`${N} SKUs concentran ${totalStr} de stock con DOH promedio ${Math.round(avgDoh)}d.`);
  }

  // ── MOVIMIENTOS 2+3 · adaptativos por pattern ──

  if (signals.pattern === "all_operational") {
    // Patrón homogéneo · narrativa anterior preservada (founder validó esta voz)
    const listParts = signals.items.map(fmtSku);
    movements.push(`Los SKUs son ${listParts.join(" · ")}.`);
    movements.push(`Liquidar o redirigir los ${N} libera ${totalStr} de capital inmovilizado. Es intervención inmediata sobre el inventario.`);
  } else if (signals.pattern === "mixed_operational_healthy") {
    // Distinguir subset operacional del healthy
    const opCount = signals.aggregate.operational_count;
    const opStockStr = _fmtMoneyK(signals.aggregate.operational_stockUSD / 1000);
    const opListParts = signals.operational_subset.map(fmtSku);
    const opVerb = opCount === 1 ? "es operacional" : `son operacionales`;
    movements.push(`${opCount} ${opVerb} con baja velocidad de conversión: ${opListParts.join(" · ")}. Liquidar o redirigir ${opCount === 1 ? "ese SKU" : `los ${opCount}`} libera ${opStockStr} de capital inmovilizado · intervención inmediata.`);

    // Nota sobre healthy subset
    const healthyList = signals.healthy_subset.map(fmtSku);
    const hVerb = signals.healthy_subset.length === 1 ? "está" : "están";
    const hVerb2 = signals.healthy_subset.length === 1 ? "está" : "están";
    movements.push(`${healthyList.join(" · ")} ${hVerb} acá por valor absoluto de stock · su rotación es saludable. NO ${signals.healthy_subset.length === 1 ? "requiere" : "requieren"} intervención · es capital trabajando.`);
  } else { // borderline_group
    const listParts = signals.items.map(fmtSku);
    movements.push(`Los SKUs son ${listParts.join(" · ")}.`);
    movements.push(`El grupo está en rango medio · ni claramente operacional ni claramente saludable. Sugerir drilldown por SKU para evaluar intervención individual.`);
  }

  // ── MOVIMIENTO 4 · Reframe founder · solo si pattern tiene componente operacional ──
  // M.B.3 v2: borderline_group NO recibe reframe (no hay caso de acción clara)
  if (signals.pattern !== "borderline_group" && EXECUTIVE_REFRAMES[signals.reframe_key]) {
    // Para mixed · el reframe se acota al subset operacional · NO al grupo completo
    if (signals.pattern === "mixed_operational_healthy") {
      const opCount = signals.aggregate.operational_count;
      movements.push(`El problema no parece ser la demanda en ${opCount === 1 ? "ese SKU" : `los ${opCount} operacionales`}; el capital está moviéndose más lento de lo que el negocio necesita.`);
    } else {
      movements.push(EXECUTIVE_REFRAMES[signals.reframe_key]);
    }
  }

  return movements.filter(m => m && m.length > 0).join("\n\n");
}

// ── _metricNounEs ────────────────────────────────────────────────────────
// Verbalización en español natural de las metric keys.
function _metricNounEs(metricKey) {
  const m = {
    contribucion:     "contribución",
    margen:           "margen",
    ventas:           "ventas",
    carga:            "carga comercial",
    rotacion:         "rotación",
    stockUSD:         "stock USD",
    cobertura:        "cobertura",
    doh:              "DOH",
    sku_margen:       "margen",
    sku_contribucion: "contribución",
  };
  return m[metricKey] || metricKey;
}

// ── composeCrossMetricRanking ────────────────────────────────────────────
// Familia B · rankear set por rankMetric · sub-ordenar por sortMetric.
// Decisión D9: buildResponseContract.
function composeCrossMetricRanking({
  rankMetric,
  rankDirection,
  rankN,
  sortMetric,
  sortDirection,
  entityType,
  scope,
  ctx,
}) {
  // Validación métricas
  const rankSpec = RANKING_EXTREMES_METRICS[rankMetric];
  const sortSpec = RANKING_EXTREMES_METRICS[sortMetric];
  if (!rankSpec || !sortSpec) {
    return composeHonestUnavailable("una de las métricas solicitadas no está disponible.", "margenes");
  }
  if (rankSpec.entityType !== entityType || sortSpec.entityType !== entityType) {
    return composeHonestUnavailable("las métricas y la dimensión consultada no son consistentes.", "margenes");
  }

  // Dataset base · resolver source priorizando rankMetric (ej: contribución → clientesMargen)
  // si rankSpec.source y sortSpec.source coinciden · trivial. Si difieren · usar rankSpec.source
  // y leer ambos campos desde ahí · pero ojo: skusMargen y skuInventario tienen SKUs distintos.
  let dataset;
  if (rankSpec.source === sortSpec.source) {
    dataset = _buildScopeForMetric(rankMetric, ctx?.scenarioId);
  } else {
    // Mismo entityType pero distinto source · join por nameField
    const dsRank = _buildScopeForMetric(rankMetric, ctx?.scenarioId) || [];
    const dsSort = _buildScopeForMetric(sortMetric, ctx?.scenarioId) || [];
    const nameField = _getEntityNameField(rankMetric);
    const sortNameField = _getEntityNameField(sortMetric);
    const sortIdx = new Map();
    dsSort.forEach(s => sortIdx.set(s[sortNameField], s[sortSpec.field]));
    dataset = dsRank.map(r => ({
      ...r,
      [sortSpec.field + "__joined"]: sortIdx.get(r[nameField]),
    })).filter(r => r[sortSpec.field + "__joined"] != null);
  }

  if (!Array.isArray(dataset) || dataset.length === 0) {
    return composeHonestUnavailable("no hay datos disponibles para el cruce solicitado.", "margenes");
  }

  const nameField = _getEntityNameField(rankMetric);
  const sortField = (rankSpec.source === sortSpec.source)
    ? sortSpec.field
    : sortSpec.field + "__joined";

  // Paso 1 · rank por rankMetric · tomar top N
  const rankSorted = [...dataset].sort((a, b) => {
    const va = a[rankSpec.field];
    const vb = b[rankSpec.field];
    if (va == null || isNaN(va)) return 1;
    if (vb == null || isNaN(vb)) return -1;
    const primary = rankDirection === "worst" ? (va - vb) : (vb - va);
    if (primary !== 0) return primary;
    return String(a[nameField]).localeCompare(String(b[nameField]));
  });
  const topSet = rankSorted.slice(0, Math.max(1, rankN));

  // Paso 2 · sub-sort por sortMetric
  const subSorted = [...topSet].sort((a, b) => {
    const va = a[sortField];
    const vb = b[sortField];
    if (va == null || isNaN(va)) return 1;
    if (vb == null || isNaN(vb)) return -1;
    const primary = sortDirection === "worst" ? (va - vb) : (vb - va);
    if (primary !== 0) return primary;
    return String(a[nameField]).localeCompare(String(b[nameField]));
  });

  const winner = subSorted[0];
  if (!winner) {
    return composeHonestUnavailable("no se pudo identificar el resultado del cruce.", "margenes");
  }

  // Verbalización
  const entityNoun = entityType === "client" ? "cliente" : "SKU";
  const sortWord = sortDirection === "worst" ? "peor" : "mejor";
  const rankWord = rankDirection === "worst" ? "menor" : "mayor";
  const moduleCtx = sortSpec.domain;
  const moduleChip = moduleCtx === "margenes" ? "Márgenes" : moduleCtx === "ventas" ? "Ventas" : "Inventario";

  const setNames = topSet.map(e => e[nameField]).join(" · ");
  const winnerVal = _formatMetricValue(winner[sortField], sortMetric);

  let opener = `Del top ${rankN} por ${_metricNounEs(rankMetric)} (${setNames}), el de ${sortWord} ${_metricNounEs(sortMetric)} es ${winner[nameField]} · ${winnerVal}.`;

  // Detalle de los N · valores de sortMetric para cada uno
  opener += `\n\n`;
  topSet.forEach(e => {
    const v = _formatMetricValue(e[sortField], sortMetric);
    const r = _formatMetricValue(e[rankSpec.field], rankMetric);
    opener += `${e[nameField]}: ${_metricNounEs(rankMetric)} ${r} · ${_metricNounEs(sortMetric)} ${v}\n`;
  });

  opener += `\n${winner[nameField]} concentra ${sortDirection === "worst" ? "el menor" : "el mayor"} ${_metricNounEs(sortMetric)} del ${rankWord === "mayor" ? "top" : "set"} ${_metricNounEs(rankMetric)} · señal estructural sobre el cruce de dimensiones.`;
  opener += `\n\n*Confianza alta · cálculo determinístico sobre dataset runtime.*`;

  // Sentrix · selección múltiple del set rankeado
  const sentrixAction = {
    label: `Ver ${topSet.length} ${entityType === "client" ? "clientes" : "SKUs"} en ${moduleChip}`,
    moduleChip,
    payload: {
      modulo: moduleCtx,
      clientes: entityType === "client" ? topSet.map(e => e[nameField]) : [],
      skus:     entityType === "sku"    ? topSet.map(e => e[nameField]) : [],
      mechanismBanner: `Top ${rankN} ${_metricNounEs(rankMetric)} × ${sortWord} ${_metricNounEs(sortMetric)}`,
    },
  };

  // ── BRIEF M.B.1 · narrative_signals + posture_hint para cross-metric ──
  // Construye signals para el winner (entidad #1 sub-sorteada por sortMetric).
  // Reusa INTERNAL_DRIVER_RULES sobre la sortMetric (la pregunta dolorosa).
  //
  // Ajuste B (founder M.B.1): incluir set_metric_values + winner_vs_others_gap
  // para que la narrativa use el contraste real del set · NO solo nombrarlo
  // como decoración antes de hablar del winner.
  let narrative_signals = null;
  let posture_hint = "validate";
  if (VOICE_NARRATIVE_LAYER_ENABLED) {
    try {
      const winnerScope = _buildScopeForMetric(sortMetric, ctx?.scenarioId);
      const winnerEntity = Array.isArray(winnerScope)
        ? winnerScope.find(e => e[nameField] === winner[nameField]) || winner
        : winner;
      const driver = detectInternalDriver(winnerEntity, sortMetric, entityType, winnerScope || dataset);
      const recoverable = driver ? calculateRecoverable(winnerEntity, sortMetric, entityType, driver, winnerScope || dataset) : 0;
      const action = driver ? buildSuggestedAction(winnerEntity, sortMetric, entityType, winnerScope || dataset, recoverable) : null;
      const reframe = driver ? buildReframe(driver) : null;

      // Set metric values · sortMetric value para cada entity del topSet
      // Necesario para "Lider rinde 21.5% vs 23.0% promedio de los otros"
      const setMetricValues = topSet.map(e => {
        // Buscar la entity original en winnerScope para tener el sortMetric value
        const origEntity = Array.isArray(winnerScope)
          ? winnerScope.find(x => x[nameField] === e[nameField]) || e
          : e;
        return {
          entity: e[nameField],
          sortMetric_value: origEntity[sortSpec.field],
        };
      });

      // Winner vs others gap
      const winnerVal = winnerEntity[sortSpec.field];
      const others = setMetricValues.filter(x => x.entity !== winnerEntity[nameField]);
      const othersAvg = others.length > 0
        ? others.reduce((s, x) => s + x.sortMetric_value, 0) / others.length
        : winnerVal;
      const spread = +(Math.abs(othersAvg - winnerVal)).toFixed(2);

      narrative_signals = {
        cross_metric: true,
        rank_context: {
          rankMetric,
          rankDirection,
          rankN,
          set_entities: topSet.map(e => e[nameField]),
          set_metric_values: setMetricValues,
        },
        winner_vs_others_gap: {
          winner_value: winnerVal,
          others_avg: +othersAvg.toFixed(2),
          spread,
        },
        direction: sortDirection,
        what: {
          entity: winnerEntity[nameField],
          value: winnerEntity[sortSpec.field],
          unit: sortSpec.unit,
          metric: sortMetric,
          metricKey: sortMetric,
          entityType,
        },
        why: driver ? {
          mechanism: driver.mechanism,
          origin: "internal",
          target_entity: winnerEntity[nameField],
          driver,
        } : null,
        implication: {
          severity: classifySeverity(driver?.vs_promedio || 0, recoverable),
          counter_intuition: !!driver,
          recoverable_value: recoverable,
          recoverability: classifyRecoverability(driver),
          action,
          reframe,
        },
      };
      if (narrative_signals.implication.counter_intuition === true) {
        posture_hint = "challenge";
      }
    } catch (sig_err) {
      // eslint-disable-next-line no-console
      console.warn("BRIEF M.B.1 cross_metric narrative_signals error:", sig_err);
      narrative_signals = null;
    }
  }

  return {
    ...buildResponseContract({
      opener,
      suggestions: filterTextualSuggestions([]),
      sentrixAction,
      decision: null,
      evidence: {
        cross_metric_rankMetric: rankMetric,
        cross_metric_rankDirection: rankDirection,
        cross_metric_rankN: rankN,
        cross_metric_sortMetric: sortMetric,
        cross_metric_sortDirection: sortDirection,
        cross_metric_winner: winner[nameField],
        cross_metric_set: topSet.map(e => e[nameField]),
      },
      focus: "cross_metric_ranking",
      confidence: "alta",
      materialMetrics: topSet.map(e => ({
        entity: e[nameField],
        rankMetric, rankValue: e[rankSpec.field],
        sortMetric, sortValue: e[sortField],
      })),
      reasoningPattern: "cross_metric_ranking",
      suggestedNextActions: [],
    }),
    // BRIEF M · spread externo
    narrative_signals,
    posture_hint,
  };
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF L · cluster ranking extremes + cross-metric
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF M · NARRATIVE COMPOSITION LAYER · INFRAESTRUCTURA M.A
//
// Transformación desde "razonador de cifras" hacia "asesor narrativo". Capa de
// composición que toma datos crudos de composers + signals estructurados + 
// postura ejecutiva y produce narrativa fluida con voz de asesor senior.
//
// Decisiones arquitectónicas (autorizadas pre-flight):
//   F1 (founder) · Cifras runtime reales · cero hardcoded
//   F2 (founder) · 4 reframes placeholder · V_VISUAL puede ajustar
//   D2 (arquitecto) · Spread externo para composers con buildResponseContract
//   D-Mine-1 · 2 patrones de inyección signals (direct add + spread)
//   D-Mine-2 · composeGlobalHonestFallback emite narrativa propia · skip layer
//   D-Mine-3 · Dos patrones: 6 composers direct, 3 composers spread externo
//   D-Mine-4 · Guard narrativeLayerHandled análogo a isHonestFallback · RCE skip
//   D-Mine-5 · Cifras runtime computadas por INTERNAL_DRIVER_RULES
//
// Rollback granular: VOICE_NARRATIVE_LAYER_ENABLED = false → bitwise idéntico
// a post-FIX_L_PRECEDENCE. Cada composer respeta su opener legacy bajo flag OFF.
// ════════════════════════════════════════════════════════════════════════════
const VOICE_NARRATIVE_LAYER_ENABLED = true;

// ── EXECUTIVE_POSTURES · catálogo declarativo de posturas ────────────────
// 6 posturas reconocidas. recommend queda sin caso activo en M (simulation
// deferida a M.2 · deuda #D-SIMULATION-VOICE-LEGACY-DIFERIDA).
const EXECUTIVE_POSTURES = {
  validate: {
    description: "Confirma con cifras lo que el founder ya intuye",
    voice: "directa · sin sobre-explicar · cierra rápido",
  },
  reframe: {
    description: "Indica que la pregunta correcta es OTRA",
    voice: "honesta · provocadora · explica por qué Y > X",
  },
  prioritize: {
    description: "Ordena · jerarquiza · dice qué importa más AHORA",
    voice: "ejecutiva · cuantitativa · cierra con acción priorizada",
  },
  challenge: {
    description: "Cuestiona supuesto que el founder está dando por sentado",
    voice: "directa · contraintuitiva · respalda con evidencia",
  },
  explore: {
    description: "Sugiere ángulos que el founder no ha mirado",
    voice: "amplia · ofrece 2-3 caminos · invita a elegir",
  },
  recommend: {
    description: "Da recomendación específica con número y acción",
    voice: "asertiva · primera persona ejecutiva · sin hedges",
    // M-status: SIN_CASO_ACTIVO_EN_M · diferido M.2
  },
};

// ── EXECUTIVE_REFRAMES · catálogo de reframes por mecanismo causal ───────
// Reframes finales firmados por founder (post V_VISUAL M.A). Catálogo
// extensible (F3) · agregar más durante implementación es trivial.
// M.B.2 · agregados 2 reframes placeholder (founder valida en V_VISUAL):
//   · quality_growth_derived  · síntoma vs causa
//   · mechanism_priority_controllability · controlabilidad antes que monto
// Ambos respetan RULE-VOICE-002 (sin primera persona plural acusatoria).
const EXECUTIVE_REFRAMES = {
  internal_commercial_load:
    "El volumen ya está. La conversación que vale es si la carga comercial sigue justificándose al valor que hoy genera.",
  internal_margin_compression:
    "El problema no parece estar en el cliente; está en cuánto valor decidimos ceder para mantener la venta.",
  structural_dependency:
    "El riesgo no está en el cliente; está en cuánto depende el negocio de él.",
  operational_inefficiency:
    "El problema no parece ser la demanda; el capital está moviéndose más lento de lo que el negocio necesita.",
  // M.B.2 placeholders · founder valida
  quality_growth_derived:
    "El deterioro de calidad de crecimiento no es la enfermedad; es el síntoma. La causa está en la carga comercial sostenida.",
  mechanism_priority_controllability:
    "No todos los mecanismos cuestan lo mismo en intervención. Vale empezar por el más controlable.",
  // BRIEF N · reframes Executive Intelligence (firmados founder D-N-3)
  parallel_horizons:
    "Sembrar este mes lo que se cosecha en seis.",
  hidden_blind_spot:
    "El margen comprimido lo estás viendo · el margen ofrecido para sostener crecimiento · no.",
};

// ── METRIC_LABEL / METRIC_UNIT · verbalización + unidad por canonical key ──
const METRIC_LABEL = {
  margen:           "margen",
  contribucion:     "contribución",
  ventas:           "ventas",
  carga:            "carga comercial",
  rotacion:         "rotación",
  stockUSD:         "stock",
  cobertura:        "cobertura",
  doh:              "DOH",
  sku_margen:       "margen",
  sku_contribucion: "contribución",
};

// ── INTERNAL_DRIVER_RULES · detectores deterministas de causa interna ────
// 10 combinaciones entity × metric. 4 con detector activo · 6 placeholder.
// Cada detector retorna driver structure o null. Cifras computadas runtime
// sobre dataset · cero hardcoded (decisión F1).
//
// Schema driver:
//   { mechanism, factor, value, vs_promedio/vs_benchmark, unit, chain }
const INTERNAL_DRIVER_RULES = {
  // ── client.margen · driver = carga comercial sobre promedio interno ──
  // F1 (founder): cifras runtime reales · cuando gap > 0.5pp → driver activo
  // (mechanism "internal_commercial_load"). Cuando 0 < gap ≤ 0.5pp → driver
  // "borderline" para que narrativa plantee juicio de oportunidad explícito
  // (NO inflar el caso · pero tampoco silenciar el origen interno).
  "client.margen": {
    detect: (entity, scope) => {
      if (!entity || typeof entity.pctRebate !== "number" || !Array.isArray(scope)) return null;
      const avg = scope.reduce((s, c) => s + (c.pctRebate || 0), 0) / scope.length;
      const gap = entity.pctRebate - avg;
      if (gap > 0.5) {
        return {
          mechanism: "internal_commercial_load",
          factor: "carga_comercial",
          value: entity.pctRebate,
          vs_promedio: +gap.toFixed(2),
          unit: "pp",
          chain: ["carga_comercial_alta", "margen_unitario_bajo"],
          borderline: false,
        };
      }
      if (gap > 0) {
        // Borderline · gap positivo pero pequeño · narrativa plantea juicio
        return {
          mechanism: "internal_commercial_load",
          factor: "carga_comercial",
          value: entity.pctRebate,
          vs_promedio: +gap.toFixed(2),
          unit: "pp",
          chain: ["carga_comercial_levemente_alta"],
          borderline: true,
        };
      }
      return null;
    },
    calculateRecoverable: (entity, driver, scope) => {
      // Recoverable si entity baja pctRebate al promedio interno
      if (!entity || !Array.isArray(scope)) return 0;
      const avg = scope.reduce((s, c) => s + (c.pctRebate || 0), 0) / scope.length;
      const gap_pp = entity.pctRebate - avg;
      return Math.round(entity.venta * (gap_pp / 100)); // en $K (venta ya en $K)
    },
    suggestedAction: (entity, scope, recoverable) => {
      const avg = scope.reduce((s, c) => s + (c.pctRebate || 0), 0) / scope.length;
      const target_carga = +avg.toFixed(1);
      const target_margen = +(entity.margen + (entity.pctRebate - target_carga)).toFixed(1);
      return {
        verb: "renegociar_carga_comercial",
        target_entity: entity.nombre,
        expected_impact: { metric: "margen", from: entity.margen, to: target_margen },
        risk: "bajo",
        recoverable_K: recoverable,
        target_carga,
        // Cifras alternativas para narrativa con juicio de oportunidad
        bestPractice_carga: 3.0,
        bestPractice_recoverable_K: Math.round(entity.venta * ((entity.pctRebate - 3.0) / 100)),
      };
    },
  },

  // ── client.contribucion · driver = margen unitario bajo benchmark ──
  "client.contribucion": {
    detect: (entity) => {
      if (!entity || !entity.benchmark || typeof entity.margen !== "number") return null;
      const gap = entity.benchmark - entity.margen;
      if (gap > 5) {
        return {
          mechanism: "internal_margin_compression",
          factor: "margen_unitario",
          value: entity.margen,
          vs_benchmark: +gap.toFixed(1),
          unit: "pp",
          chain: ["margen_unitario_bajo", "contribucion_diluida"],
        };
      }
      return null;
    },
    calculateRecoverable: (entity) => {
      const gap = entity.benchmark - entity.margen;
      return Math.round(entity.venta * (gap / 100));
    },
    suggestedAction: (entity, scope, recoverable) => ({
      verb: "recuperar_margen_unitario",
      target_entity: entity.nombre,
      expected_impact: { metric: "margen", from: entity.margen, to: entity.benchmark },
      risk: "medio",
      recoverable_K: recoverable,
    }),
  },

  // ── sku.rotacion · driver = DOH alto · capital atrapado ──
  "sku.rotacion": {
    detect: (entity, scope) => {
      if (!entity || typeof entity.rotacion !== "number" || !Array.isArray(scope)) return null;
      const avg = scope.reduce((s, k) => s + (k.rotacion || 0), 0) / scope.length;
      if (entity.rotacion < avg / 2 && entity.doh > 90) {
        return {
          mechanism: "operational_inefficiency",
          factor: "doh_alto",
          value: entity.doh,
          vs_promedio_rotacion: +avg.toFixed(1),
          unit: "d",
          chain: ["rotacion_baja", "capital_inmovilizado"],
        };
      }
      return null;
    },
    calculateRecoverable: (entity) => entity.stockUSD || 0,
    suggestedAction: (entity, scope, recoverable) => ({
      verb: "plan_de_salida",
      target_entity: entity.sku,
      expected_impact: { metric: "stockUSD", from: entity.stockUSD, to: 0 },
      risk: "medio",
      recoverable_K: Math.round(recoverable / 1000),
    }),
  },

  // ── sku.stockUSD · driver = DOH alto ──
  "sku.stockUSD": {
    detect: (entity) => {
      if (!entity || typeof entity.doh !== "number") return null;
      if (entity.doh > 90) {
        return {
          mechanism: "operational_inefficiency",
          factor: "doh_alto",
          value: entity.doh,
          unit: "d",
          chain: ["doh_alto", "capital_inmovilizado"],
        };
      }
      return null;
    },
    calculateRecoverable: (entity) => entity.stockUSD || 0,
    suggestedAction: (entity, scope, recoverable) => ({
      verb: "liquidar",
      target_entity: entity.sku,
      expected_impact: { metric: "stockUSD", from: entity.stockUSD, to: 0 },
      risk: "alto",
      recoverable_K: Math.round(recoverable / 1000),
    }),
  },

  // ── Placeholders (null detector · narrativa salta movimiento causal) ──
  "client.ventas":       { detect: () => null, calculateRecoverable: () => 0, suggestedAction: () => null },
  "client.carga":        { detect: () => null, calculateRecoverable: () => 0, suggestedAction: () => null },
  "sku.cobertura":       { detect: () => null, calculateRecoverable: () => 0, suggestedAction: () => null },
  "sku.doh":             { detect: () => null, calculateRecoverable: () => 0, suggestedAction: () => null },
  "sku.sku_margen":      { detect: () => null, calculateRecoverable: () => 0, suggestedAction: () => null },
  "sku.sku_contribucion":{ detect: () => null, calculateRecoverable: () => 0, suggestedAction: () => null },
};

// ── HELPERS DE EXTRACCIÓN ────────────────────────────────────────────────

// classifyMagnitude · "alto" / "medio" / "bajo" según gap relativo
function classifyMagnitude(gap, unit) {
  if (gap == null) return "medio";
  const abs = Math.abs(gap);
  if (unit === "pp") {
    if (abs >= 5) return "alto";
    if (abs >= 2) return "medio";
    return "bajo";
  }
  // Default · numeric
  return abs >= 100 ? "alto" : abs >= 10 ? "medio" : "bajo";
}

// classifySeverity · "critica" / "atencion" / "seguir"
function classifySeverity(gap, recoverableK) {
  const gapAbs = Math.abs(gap || 0);
  const rec = recoverableK || 0;
  if (gapAbs >= 5 || rec >= 500) return "critica";
  if (gapAbs >= 1.5 || rec >= 100) return "atencion";
  return "seguir";
}

// classifyRecoverability · "alta" / "media" / "baja"
function classifyRecoverability(driver) {
  if (!driver) return "baja";
  if (driver.mechanism === "internal_commercial_load") return "alta";
  if (driver.mechanism === "internal_margin_compression") return "media";
  if (driver.mechanism === "operational_inefficiency") return "media";
  return "baja";
}

// buildReframe · resuelve el reframe ejecutivo desde el catálogo
function buildReframe(driver) {
  if (!driver || !driver.mechanism) return null;
  return EXECUTIVE_REFRAMES[driver.mechanism] || null;
}

// detectInternalDriver · router para INTERNAL_DRIVER_RULES
function detectInternalDriver(entity, metricKey, entityType, scope) {
  if (!entity || !metricKey || !entityType) return null;
  const ruleKey = entityType + "." + metricKey;
  const rule = INTERNAL_DRIVER_RULES[ruleKey];
  if (!rule || typeof rule.detect !== "function") return null;
  try {
    return rule.detect(entity, scope);
  } catch (err) {
    // eslint-disable-next-line no-console
    console.warn("BRIEF M detectInternalDriver error:", err);
    return null;
  }
}

// calculateRecoverable · router
function calculateRecoverable(entity, metricKey, entityType, driver, scope) {
  if (!entity || !metricKey || !entityType || !driver) return 0;
  const rule = INTERNAL_DRIVER_RULES[entityType + "." + metricKey];
  if (!rule || typeof rule.calculateRecoverable !== "function") return 0;
  try {
    return rule.calculateRecoverable(entity, driver, scope);
  } catch (err) {
    return 0;
  }
}

// buildSuggestedAction · router
function buildSuggestedAction(entity, metricKey, entityType, scope, recoverable) {
  if (!entity || !metricKey || !entityType) return null;
  const rule = INTERNAL_DRIVER_RULES[entityType + "." + metricKey];
  if (!rule || typeof rule.suggestedAction !== "function") return null;
  try {
    return rule.suggestedAction(entity, scope, recoverable);
  } catch (err) {
    return null;
  }
}

// ── _fmtMoneyK · formateo monetario para narrativa ───────────────────────
function _fmtMoneyK(valueK) {
  if (valueK == null || isNaN(valueK)) return "$0K";
  const abs = Math.abs(valueK);
  if (abs >= 1000) return `$${(valueK / 1000).toFixed(2)}M`;
  if (abs >= 100)  return `$${Math.round(valueK)}K`;
  return `$${Math.round(valueK)}K`;
}

// ── HELPERS NARRATIVOS · composición selectiva por movimientos ───────────
//
// Cada helper recibe signals + posture y emite UNA frase (no un párrafo).
// La integración final (integrateMovements) ensambla con conectores fluidos.
//
// Decisión arquitectónica clave: NO usar plantillas rígidas "QUÉ: X. POR QUÉ: Y."
// Las frases se construyen frase a frase con sujeto + verbo + dato inline.

// composeOpeningDirect · apertura validate · dato + ancla
function composeOpeningDirect(signals) {
  const w = signals.what;
  if (!w) return "";
  const valStr = w.unit === "%" ? `${w.value.toFixed(1)}%` :
                 w.unit === "x" ? `${w.value.toFixed(1)}x` :
                 w.unit === "d" ? `${Math.round(w.value)}d` :
                 w.unit === "$" ? _fmtMoneyK(w.value) :
                 String(w.value);
  return `El ${_entityNoun(w.entityType)} con ${signals.direction === "best" ? "mejor" : "peor"} ${METRIC_LABEL[w.metricKey] || w.metric} es ${w.entity} · ${valStr}.`;
}

// composeOpeningReframe · apertura challenge · reframe interpretativo ANTES del dato
// RULE-VOICE-001: NO acusatorio absoluto ("el origen es interno"). USO interpretativo
// que invita a mirar antes de afirmar ("vale mirar adentro" / "podría no estar afuera").
// Voz: asesor senior · no auditor.
function composeOpeningReframe(signals) {
  const w = signals.what;
  const why = signals.why;
  if (!w || !why) return composeOpeningDirect(signals);
  const valStr = w.unit === "%" ? `${w.value.toFixed(1)}%` :
                 w.unit === "x" ? `${w.value.toFixed(1)}x` :
                 _fmtMoneyK(w.value);
  // Estructura interpretativa: "X es tu peor Y · Z%. Antes de mirar al cliente · vale mirar adentro."
  const adversative = why.origin === "internal" ? "Antes de mirar al cliente · vale mirar adentro"
                    : why.origin === "structural" ? "Antes de mirar al cliente · vale mirar la dependencia estructural"
                    : "Antes de mirar al cliente · vale revisar la causa";
  return `${w.entity} es tu ${signals.direction === "best" ? "mejor" : "peor"} ${METRIC_LABEL[w.metricKey] || w.metric} · ${valStr}. ${adversative}.`;
}

// composeOpeningHierarchy · apertura prioritize · jerarquía + cifras
function composeOpeningHierarchy(signals) {
  const w = signals.what;
  if (!w) return "";
  // signals viene con array · adaptar según composer
  if (signals.hierarchy && Array.isArray(signals.hierarchy)) {
    const topName = signals.hierarchy[0]?.name || "el mecanismo principal";
    return `La cartera presenta ${signals.hierarchy.length} ${signals.hierarchy.length === 1 ? "mecanismo activo" : "mecanismos activos"} · el más caro es ${topName}.`;
  }
  return composeOpeningDirect(signals);
}

// composeCausalMovement · movimiento 2 · POR QUÉ
// RULE-VOICE-002: sujeto = métrica/fenómeno · NO primera persona plural acusatoria.
// "Le aplicamos / aceptamos / decidimos" convierte al usuario en cómplice acusado.
// "La carga es X · N puntos sobre el promedio" = métrica habla · usuario observa.
function composeCausalMovement(why, posture) {
  if (!why || !why.driver) return "";
  const d = why.driver;
  if (d.factor === "carga_comercial") {
    // Sujeto = "La carga comercial sobre X" · no "Le aplicamos"
    const targetName = why.target_entity || d.target_entity || "";
    const targetClause = targetName ? `sobre ${targetName}` : "";
    const gapStr = d.vs_promedio > 0
      ? `${Math.abs(d.vs_promedio).toFixed(2)} puntos sobre el promedio interno`
      : `${Math.abs(d.vs_promedio).toFixed(2)} puntos bajo el promedio interno`;
    return `La carga comercial ${targetClause} es ${d.value.toFixed(1)}% · ${gapStr}.`.replace(/\s+/g, " ");
  }
  if (d.factor === "margen_unitario") {
    return `El margen unitario está ${d.vs_benchmark.toFixed(1)}pp bajo el benchmark de industria.`;
  }
  if (d.factor === "doh_alto") {
    return `El DOH acumula ${Math.round(d.value)} días · capital atrapado por baja velocidad de conversión.`;
  }
  return "";
}

// composeActionMovement · movimiento 3 · QUÉ HACER (con cifra y juicio)
function composeActionMovement(implication, posture) {
  if (!implication || !implication.action) return "";
  const a = implication.action;
  if (a.verb === "renegociar_carga_comercial") {
    // Decisión F1: cifras runtime reales + juicio de oportunidad si gap pequeño
    const recK = a.recoverable_K || 0;
    const recBPK = a.bestPractice_recoverable_K || 0;
    const promedio = `Si negociás esa carga al promedio interno (${a.target_carga}%) · son ${_fmtMoneyK(recK)} anuales recuperables`;
    const bestPractice = recBPK > recK
      ? ` · si la bajás a mejor práctica (3.0%) · ${_fmtMoneyK(recBPK)}`
      : "";
    // Si recK es pequeño (<50K) · plantear juicio de oportunidad explícito
    const judgment = recK < 50
      ? `. El gap es pequeño · evaluar si el monto justifica priorizar esta cuenta sobre otras.`
      : `.`;
    return promedio + bestPractice + judgment;
  }
  if (a.verb === "recuperar_margen_unitario") {
    const recK = a.recoverable_K || 0;
    return `Recuperar el margen unitario al benchmark libera ${_fmtMoneyK(recK)} anuales en contribución.`;
  }
  if (a.verb === "plan_de_salida") {
    const recK = a.recoverable_K || 0;
    return `Un plan de salida sobre ${a.target_entity} libera ${_fmtMoneyK(recK)} de capital inmovilizado.`;
  }
  if (a.verb === "liquidar") {
    const recK = a.recoverable_K || 0;
    return `Liquidar ${a.target_entity} libera ${_fmtMoneyK(recK)} de capital.`;
  }
  return "";
}

// composeReframeClosing · movimiento 4 (opcional · challenge)
function composeReframeClosing(reframeText) {
  if (!reframeText) return "";
  return reframeText;
}

// composeImplicationOnly · cuando no hay action específica · solo severidad
function composeImplicationOnly(implication, posture) {
  if (!implication) return "";
  if (implication.severity === "critica") return "Requiere intervención inmediata.";
  if (implication.severity === "atencion") return "Requiere seguimiento activo.";
  return "";
}

// _entityNoun · "cliente" / "SKU" / "producto"
function _entityNoun(entityType) {
  if (entityType === "client") return "cliente";
  if (entityType === "sku") return "SKU";
  return "ítem";
}

// integrateMovements · ensambla movimientos con conectores fluidos
//   movements: array de strings · pueden ser frases o párrafos cortos
//   posture: para ajustar densidad y conectores
function integrateMovements(movements, posture) {
  const clean = movements.filter(m => m && typeof m === "string" && m.trim().length > 0);
  if (clean.length === 0) return "";
  if (clean.length === 1) return clean[0];
  // Para challenge · apertura · luego causal+acción en un párrafo · luego reframe closing
  // RULE-VOICE-003: el reframe del catálogo EXECUTIVE_REFRAMES es frase auto-contenida ·
  // NO forzar prefijo "La conversación que vale" · respetar texto exacto del catálogo.
  if (posture === "challenge") {
    const opener = clean[0];
    const middle = clean.slice(1, -1).join(" ");
    const closing = clean[clean.length - 1];
    if (middle) {
      return `${opener}\n\n${middle}\n\n${closing}`;
    }
    return `${opener}\n\n${closing}`;
  }
  // Default · separar por párrafos naturales
  return clean.join("\n\n");
}

// ── composeNarrativeResponse · composer narrativo principal ──────────────
function composeNarrativeResponse(signals, posture, ctx) {
  if (!signals || !VOICE_NARRATIVE_LAYER_ENABLED) return null;
  try {
    const movements = [];

    // MOVIMIENTO 1 · Apertura según postura
    if (posture === "challenge" && signals.implication?.counter_intuition) {
      movements.push(composeOpeningReframe(signals));
    } else if (posture === "prioritize") {
      movements.push(composeOpeningHierarchy(signals));
    } else {
      // validate · explore · default
      movements.push(composeOpeningDirect(signals));
    }

    // MOVIMIENTO 2 · Causalidad (solo si why existe)
    if (signals.why) {
      const causal = composeCausalMovement(signals.why, posture);
      if (causal) movements.push(causal);
    }

    // MOVIMIENTO 3 · Acción o implicación
    if (signals.implication?.action) {
      const action = composeActionMovement(signals.implication, posture);
      if (action) movements.push(action);
    } else if (signals.implication?.severity) {
      const imp = composeImplicationOnly(signals.implication, posture);
      if (imp) movements.push(imp);
    }

    // MOVIMIENTO 4 (opcional) · Reframe ejecutivo final
    if (posture === "challenge" && signals.implication?.reframe) {
      movements.push(composeReframeClosing(signals.implication.reframe));
    }

    return integrateMovements(movements, posture);
  } catch (err) {
    // eslint-disable-next-line no-console
    console.warn("BRIEF M composeNarrativeResponse error:", err);
    return null;
  }
}

// ── selectPosture · selector determinístico de postura ───────────────────
function selectPosture(intentType, signals, ctx) {
  // Reglas en orden de precedencia · NO probabilístico

  // 1 · Contraintuición gana · siempre challenge
  if (signals?.implication?.counter_intuition === true) {
    return "challenge";
  }

  // 2 · Severidad crítica + overview · prioritize
  if (signals?.implication?.severity === "critica" &&
      (intentType === "module" || intentType === "cross_domain_query")) {
    return "prioritize";
  }

  // 3 · Simulaciones · recommend (diferido a M.2 · placeholder)
  if (intentType === "simulation") {
    return "recommend";
  }

  // 4 · Mechanism scan / ranking · prioritize
  if (intentType === "cross_domain_query") {
    return "prioritize";
  }

  // 5 · Ad-hoc reasoning · validate (cifras pedidas explícitamente)
  if (intentType === "ad_hoc_reasoning") {
    return "validate";
  }

  // 6 · Ranking extremes · validate por default · challenge si causa interna
  if (intentType === "ranking_extremes" || intentType === "cross_metric_ranking") {
    return signals?.why?.origin === "internal" ? "challenge" : "validate";
  }

  // 7 · Honest fallback · explore (composer ya emite narrativa nativa)
  if (intentType === "global_honest_fallback") {
    return "explore";
  }

  // Default
  return "validate";
}

// ── applyVoiceCalibration · linter de voz sobre output narrativo ─────────
function applyVoiceCalibration(text, posture) {
  if (!text || typeof text !== "string") return text;
  let calibrated = text;

  // Eliminar hedges analista
  const HEDGE_PATTERNS = [
    /\bse\s+observa\s+que\s*/gi,
    /\bme\s+parece\s+que\s*/gi,
    /\bal\s+parecer\s*/gi,
    /\bpodr[ií]a\s+decirse\s+que\s*/gi,
    // Hedge "aproximadamente" solo si precede un número o símbolo $/€
    /\baproximadamente\s+(?=\$|\d)/gi,
  ];
  for (const pattern of HEDGE_PATTERNS) {
    calibrated = calibrated.replace(pattern, "");
  }

  // Eliminar disculpas
  const APOLOGY_PATTERNS = [/\bpor\s+favor\b/gi, /\bdisculpe\b/gi];
  for (const pattern of APOLOGY_PATTERNS) {
    calibrated = calibrated.replace(pattern, "");
  }

  // Eliminar emojis (rango unicode + dingbats)
  calibrated = calibrated.replace(/[\u{1F300}-\u{1F9FF}\u{2600}-\u{27BF}]/gu, "");

  // Limpiar espacios dobles y leading whitespace en líneas
  calibrated = calibrated.replace(/[ \t]+/g, " ");
  calibrated = calibrated.replace(/\n /g, "\n");
  calibrated = calibrated.trim();

  return calibrated;
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF M.A · Infraestructura · Narrative Layer
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF M.C · DISPATCHER NARRATIVE LAYER
//
// dispatchNarrativeComposer · routing por signals.kind hacia el composer
// narrativo correcto. Helper usado SOLO desde FASE 5 integration block.
// NO modifica composers M.A/M.B.* existentes · M.A LOCKED preservado.
//
// Mapeo:
//   cross_metric:true               → composeRankingExtremesNarrative (despacha internamente)
//   kind="mechanism_scan"           → composeMechanismScanNarrative (M.B.2)
//   kind="mechanism_ranking"        → composeMechanismRankingNarrative (M.B.2)
//   kind="client_deep_dive"         → composeClientDeepDiveNarrative (M.B.3)
//   kind="sku_deep_dive"            → composeSkuDeepDiveNarrative (M.B.3)
//   kind="sku_operational_group"    → composeSkuOperationalNarrative (M.B.3)
//   default (M.B.1 individual/grupo · sin kind) → composeRankingExtremesNarrative
//
// Composers que SKIP narrative_layer (M.B.4 fallback · M.B.5 QI) NO emiten
// signals · el guard previo en FASE 5 ya filtra esos casos.
// ════════════════════════════════════════════════════════════════════════════
function dispatchNarrativeComposer(signals, posture, ctx) {
  if (!signals) return null;
  // Cross-metric tiene su flag en signals · NO en .kind
  if (signals.cross_metric === true) {
    return composeRankingExtremesNarrative(signals, posture, ctx);
  }
  switch (signals.kind) {
    case "mechanism_scan":
      return composeMechanismScanNarrative(signals, posture, ctx);
    case "mechanism_ranking":
      return composeMechanismRankingNarrative(signals, posture, ctx);
    case "client_deep_dive":
      return composeClientDeepDiveNarrative(signals, posture, ctx);
    case "sku_deep_dive":
      return composeSkuDeepDiveNarrative(signals, posture, ctx);
    case "sku_operational_group":
      return composeSkuOperationalNarrative(signals, posture, ctx);
    // BRIEF N · 3 narrative composers nuevos (implementación en N.B.1/N.B.2/N.B.3)
    case "executive_action":
      return composeExecutiveActionNarrative(signals, posture, ctx);
    case "executive_opportunity":
      return composeHiddenOpportunityNarrative(signals, posture, ctx);
    case "executive_concern":
      return composeExecutiveConcernNarrative(signals, posture, ctx);
    default:
      // M.B.1 ranking individual + grupo · structure M.A-like · items[] o single
      return composeRankingExtremesNarrative(signals, posture, ctx);
  }
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF M.C · Dispatcher
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF N · EXECUTIVE INTELLIGENCE · QUERIES F
//
// 3 composers nuevos · NO refactor · postura recommend activa.
//   N.1 · composeExecutiveAction       · "si fueras gerente comercial qué harías"
//   N.2 · composeHiddenOpportunity     · "qué oportunidad estoy ignorando"
//   N.3 · composeExecutiveConcern      · "qué me preocuparía si fuera mi empresa"
//
// Detector compartido: detectExecutiveIntent · matchea patrones F · clasifica
// en subtype (action/opportunity/concern). Inserción ANTES de SKU detection
// en detectIntent (estrategia FIX_L_PRECEDENCE).
//
// N.A · Infraestructura compartida implementada acá:
//   · Flag VOICE_EXECUTIVE_INTELLIGENCE_ENABLED
//   · Detector detectExecutiveIntent
//   · 3 composer placeholders (N.B.1/N.B.2/N.B.3 implementan)
//   · 3 narrative placeholders (N.B.1/N.B.2/N.B.3 implementan)
//
// dispatchNarrativeComposer YA extendido con 3 kinds nuevos (arriba).
// EXECUTIVE_REFRAMES YA extendido con parallel_horizons + hidden_blind_spot.
// ════════════════════════════════════════════════════════════════════════════

const VOICE_EXECUTIVE_INTELLIGENCE_ENABLED = true;

// ── EXECUTIVE_INTENT_PATTERNS · 3 subtypes (D-N-4 extensiones aplicadas) ──
// action     · "si fueras X" / "qué harías" / "priorizo|prioridad" / "por dónde empezar"
// opportunity · "qué (no veo|me pierdo|estoy ignorando)" / "oportunidad" / "qué falta"
// concern    · "qué me preocuparía" / "riesgos?" / "si fuera mi empresa" / "qué vigilar"
// ═══ ENCARGO D3.a · DETECTOR DE PREGUNTA COMPUESTA · INERTE (sin consumidor) ═══
// detectCompoundQuestion(trimmed) → { compound:bool, eslabones:[...] } | null.
// Clasifica la frase en 5 familias y cuenta cuántas están presentes. NO orquesta (D3.b).
// INERTE: este corte no tiene consumidor de _d3Compound · su sello es clasificar bien Y
// que computarlo no cambie NINGUNA ruta. Conteo sobre las CAPAS LÉXICAS existentes
// (mismas listas que usan los detectores · GD3a · una sola fuente · cero parser nuevo).
// off = byte-idéntico D3.0-bis.
const VOICE_D3A_COMPOUND_ENABLED = true;

// ── _D3A_CROSS_ANCHORS · anclaje deíctico a cuentas (mismo léxico que detectCrossSkuFollowUp) ──
const _D3A_CROSS_ANCHORS = ["de esas cuentas", "de esos clientes", "en esos clientes",
  "en esas cuentas", "que me hacen perder", "que pierden", "haciendo perder",
  "que me estan haciendo perder", "que venden esas cuentas"];

// ── detectCompoundQuestion(trimmed) · PURA · solo lee · 5 familias (GD3a-4 ajustado) ──
// ranking_cuentas · causa · cruce_sku (exige anclaje) · sku_inventario (NO exige anclaje ·
// familia operacional R4) · medidas. Exclusiones (conteo por categoría · máx 1 por familia):
//   E1 · token-producto suprime ranking_cuentas SOLO si NO hay cláusula propia de ranking.
//   E2 · marcador causal suprime ranking_cuentas SOLO si NO hay cláusula propia.
//   E3 · cruce_sku exige token-producto Y anclaje deíctico (protege 16t idx6/11).
//   E4 · "rotación" suelta adyacente a cláusula de ranking es criterio, NO familia inventario.
function detectCompoundQuestion(trimmed) {
  try {
    if (typeof VOICE_D3A_COMPOUND_ENABLED === "undefined" || !VOICE_D3A_COMPOUND_ENABLED) return null;
    if (typeof trimmed !== "string" || !trimmed) return null;
    const n = _normalizeSemanticText(trimmed);
    if (!n) return null;
    const hasMarker = (list) => list.some(t => {
      const re = new RegExp("\\b" + String(t).replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "\\b", "i");
      return re.test(n);
    });
    const _causalVocab = (typeof SEMANTIC_INTENTS !== "undefined" && SEMANTIC_INTENTS.cause_query
      && SEMANTIC_INTENTS.cause_query.vocabulary_markers) || [];
    const _decisionVocab = (typeof SEMANTIC_INTENTS !== "undefined" && SEMANTIC_INTENTS.decision_query
      && SEMANTIC_INTENTS.decision_query.vocabulary_markers) || [];
    const causa = hasMarker(_causalVocab);
    const medidas = hasMarker(_decisionVocab) || /\bmedidas?\b/i.test(n) || /\bsoluci/i.test(n);
    const tokenProd = /\b(sku|skus|producto|productos)\b/i.test(n);
    const anchor = _D3A_CROSS_ANCHORS.some(a => n.indexOf(a) >= 0);
    const cruce = tokenProd && anchor;
    const rankClausePropia = /(clientes|cuentas)\s+(con\s+)?(bajo\s+margen|margen\s+bajo|margen\s+comprimido|margen\s+presionado)/i.test(n)
      || /(clientes|cuentas)\s+tienen\s+(bajo\s+margen|margen\s+bajo)/i.test(n);
    const rankRaw = rankClausePropia
      || /mejores clientes|peor margen|mayor contribuci|top \d+ (clientes|cuentas)/i.test(n);
    const ranking = rankRaw && (rankClausePropia || (!tokenProd && !causa));
    const invStrong = /\brotan\b|\brotando\b|\bdoh\b|capital inmovilizado|capital atrapado|stock detenido|rotan mal|dias sin venta|\bsin venta\b|\binventario\b|\bstock\b/i.test(n);
    const rotacionSuelta = /rotacion/i.test(n) && rankClausePropia;
    const invLex = invStrong || (/rotacion/i.test(n) && !rankClausePropia);
    const sku_inventario = invLex && !cruce && !rotacionSuelta;
    const eslabones = [];
    if (ranking) eslabones.push("ranking_cuentas");
    if (causa) eslabones.push("causa");
    if (cruce) eslabones.push("cruce_sku");
    if (sku_inventario) eslabones.push("sku_inventario");
    if (medidas) eslabones.push("medidas");
    return { compound: eslabones.length >= 2, eslabones };
  } catch (e) { return null; }
}
// ═══ FIN ENCARGO D3.a · símbolos top-level ═══

// ═══ ENCARGO D3.b · ORQUESTACIÓN DE ESLABONES · despierta detectCompoundQuestion ═══
// Cuando la frase es compuesta, ejecuta los eslabones en orden de ancla sobre un
// activeResult LOCAL, puebla la causa con el helper de D1 (IDÉNTICA · _d1ExtractCause),
// recolecta openers CRUDOS, persiste SOLO el final. D3.b ejecuta y recolecta · D3.c presenta.
// REGLA (founder): el hilo viaja por activeResult real o local, con la misma evidencia que
// usan los composers sellados. La causa es la de D1 · cada eslabón su cifra única · CRUDO.
// off = byte-idéntico D3.a (el canónico responde 1 eslabón, como hoy).
const VOICE_D3B_ORCHESTRATE_ENABLED = true;

// ── _d3bAnchorIsValidAccounts(ar) · ¿prev.activeResult es un hallazgo de cuentas vigente? ──
// GD3b-4 · I-D3b-ANCLA-CLON · si ya existe, se clona (no se re-ejecuta el composer).
function _d3bAnchorIsValidAccounts(ar) {
  try {
    return !!(ar && typeof ar === "object" && ar.entityType === "cliente"
      && Array.isArray(ar.entities) && ar.entities.length > 0);
  } catch (e) { return false; }
}

// ── _d3bIsDeictic(trimmed) · ¿la compuesta refiere a "esas cuentas" (anclaje deíctico)? ──
function _d3bIsDeictic(trimmed) {
  try {
    const n = _normalizeSemanticText(trimmed);
    return _D3A_CROSS_ANCHORS.some(a => n.indexOf(a) >= 0)
      || /\besas?\s+(cuentas|clientes)\b|\besos\s+clientes\b/i.test(n);
  } catch (e) { return false; }
}

// ── _d3bBuildAccountsAnchor(scenario, prevActiveResult, trimmed) ──
// Devuelve { localAR, lcr } · GD3b-4: CLONA si ya existe un hallazgo de cuentas válido y la
// compuesta es deíctica (preserva la MISMA instancia · cifra única entre turnos · Evidencia
// Única); EJECUTA el composer si no. El cruce NUNCA corre sin este ancla.
function _d3bBuildAccountsAnchor(scenario, prevActiveResult, trimmed) {
  // CLON · hallazgo de cuentas vigente + deíctico → misma instancia, sin recalcular
  if (_d3bAnchorIsValidAccounts(prevActiveResult) && _d3bIsDeictic(trimmed)) {
    const _clon = JSON.parse(JSON.stringify(prevActiveResult)); // clon profundo · misma cifra
    return { localAR: _clon, lcr: null, fromClone: true };
  }
  // EJECUTA · genera el ancla con el composer de cuentas (mismo que el dispatch)
  const lcr = composeMechanismResponse("commercial_erosion", scenario);
  const _driver = lcr && lcr.narrative_signals && lcr.narrative_signals.why && lcr.narrative_signals.why.driver;
  const _entities = (_driver && Array.isArray(_driver.top3_clientes) && _driver.top3_clientes.slice())
    || (lcr && lcr.evidence && Array.isArray(lcr.evidence.top3_clientes) && lcr.evidence.top3_clientes.slice())
    || ["Falabella", "Sodimac", "Lider"];
  const localAR = {
    entities: _entities,
    entityType: "cliente",
    cardinality: _entities.length === 1 ? "single" : "list",
    finding: {
      reasoningPattern: (lcr && lcr.reasoningPattern) || null,
      thesis: (lcr && lcr.focus) || null,
      // ═══ I-D3b-CAUSA-MISMA-FUENTE · la MISMA fn sobre el MISMO lcr que D1 (B4) ═══
      cause: (typeof VOICE_D1_CAUSE_ENABLED !== "undefined" && VOICE_D1_CAUSE_ENABLED)
        ? _d1ExtractCause(lcr) : null,
    },
  };
  return { localAR, lcr, fromClone: false };
}

// ── orchestrateCompound(d3, scenario, modulo, prevActiveResult) ──
// Ejecuta los eslabones en orden de ancla, recolecta CRUDO, devuelve el contrato del founder.
// NO toca openers · NO integra · NO deduplica (todo eso es D3.c). PURO salvo lectura · cero throw.
function orchestrateCompound(d3, scenario, modulo, prevActiveResult, trimmed) {
  try {
    if (!d3 || !d3.compound || !Array.isArray(d3.eslabones)) return null;
    const fams = d3.eslabones;
    const hasRanking = fams.indexOf("ranking_cuentas") >= 0;
    const hasCausa = fams.indexOf("causa") >= 0;
    const hasCruce = fams.indexOf("cruce_sku") >= 0;
    const hasSkuInv = fams.indexOf("sku_inventario") >= 0;
    const hasMedidas = fams.indexOf("medidas") >= 0;
    // ¿necesita ancla de cuentas? (ranking, cruce o causa dependen del hallazgo de cuentas)
    const needsAccounts = hasRanking || hasCruce || hasCausa;
    const parts = [];
    const executionOrder = [];
    let localAR = null;
    let finalActiveResultCandidate = null;

    if (needsAccounts) {
      // ESLABÓN ancla · cuentas (ejecutar o clonar · GD3b-4 · usa el trimmed real para deixis)
      const anchor = _d3bBuildAccountsAnchor(scenario, prevActiveResult, trimmed || "");
      localAR = anchor.localAR;
      // ranking_cuentas: el opener del composer de cuentas (si se ejecutó) o un re-render del clon
      if (hasRanking) {
        const _lcr = anchor.lcr || composeMechanismResponse("commercial_erosion", scenario);
        parts.push({ eslabon: "ranking_cuentas", opener: _lcr.opener || "", rawResult: _lcr, suggestions: _lcr.suggestions || [] });
        executionOrder.push("ranking_cuentas");
      }
      // causa: LEE localAR.finding.cause (idéntica a D1)
      if (hasCausa) {
        const r2 = composeCauseDevelopment(localAR, scenario);
        parts.push({ eslabon: "causa", opener: (r2 && r2.opener) || "", rawResult: r2, suggestions: (r2 && r2.suggestions) || [] });
        executionOrder.push("causa");
      }
      // cruce: LEE localAR.entities · NUNCA sin ancla
      if (hasCruce) {
        const r3 = composeCrossSkuNarrative(localAR, scenario);
        parts.push({ eslabon: "cruce_sku", opener: (r3 && r3.opener) || "", rawResult: r3, suggestions: (r3 && r3.suggestions) || [] });
        executionOrder.push("cruce_sku");
        // finalActiveResultCandidate · cuentas + crossSku anidado (GD3b-1 · firma C de D2)
        try {
          finalActiveResultCandidate = JSON.parse(JSON.stringify(localAR));
          if (r3 && r3._crossSku) finalActiveResultCandidate.crossSku = r3._crossSku;
        } catch (e) { finalActiveResultCandidate = localAR; }
      } else {
        // sin cruce · el ancla de cuentas es el candidato final
        finalActiveResultCandidate = localAR;
      }
    } else if (hasSkuInv) {
      // ancla SKU/inventario (independiente de cuentas)
      const _sku = (typeof composeSkuOperationalAnalysis === "function") ? composeSkuOperationalAnalysis(scenario) : null;
      if (_sku) {
        parts.push({ eslabon: "sku_inventario", opener: _sku.opener || "", rawResult: _sku, suggestions: _sku.suggestions || [] });
        executionOrder.push("sku_inventario");
        finalActiveResultCandidate = _sku.activeResult || null;
      }
    }

    // medidas · SIEMPRE al final · contexto MÍNIMO (GD3b-3 · headline figura-libre)
    if (hasMedidas) {
      const r4 = composeExecutiveAction(scenario, {}, modulo || "ventas");
      parts.push({ eslabon: "medidas", opener: (r4 && r4.opener) || "", rawResult: r4, suggestions: (r4 && r4.suggestions) || [] });
      executionOrder.push("medidas");
    }

    if (parts.length === 0) return null;
    return { compound: true, executionOrder, parts, finalActiveResultCandidate };
  } catch (e) { return null; }
}
// ═══ FIN ENCARGO D3.b · símbolos top-level ═══

// ═══ ENCARGO D3.c · PRESENTACIÓN POR SECCIONES (5 firmas founder) ═══
// presentCompound(orqResult, scenario) · toma las parts CRUDAS de D3.b, las ordena a
// narración canónica, les pone títulos, dedupa el lever causa↔medidas (con guarda de cifras),
// entra directo. PRESENTACIÓN PURA · NO recalcula · NO cambia cifras · NO re-ejecuta.
// off = render crudo de D3.b (byte-idéntico). D3.b queda intacto · D3.c es capa sobre su salida.
const VOICE_D3C_PRESENT_ENABLED = true;

// ── orden de NARRACIÓN canónico (GD3-3 · independiente del orden de EJECUCIÓN) ──
const _D3C_ORDEN_NARRATIVO = ["ranking_cuentas", "causa", "cruce_sku", "sku_inventario", "medidas"];
// ── mapa de títulos (GD3c-1 · firmado) ──
const _D3C_TITULOS = {
  ranking_cuentas: "Clientes con bajo margen",
  causa: "La causa",
  cruce_sku: "Los SKU que pesan en esas cuentas",
  sku_inventario: "Los SKU detenidos",
  medidas: "Qué hacer",
};
// ── dedup del lever (GD3c-2 · GUARDA DE CIFRAS dura) ──
// La línea "siguiente paso ... renegociación" se quita de la causa SOLO si: hay sección de
// medidas Y la línea NO contiene ningún dígito. Si alguna vez tuviera una cifra, se PRESERVA.
const _D3C_LEVER_RE = /siguiente paso.*renegociaci/i;
const _D3C_NUM_RE = /[0-9]/;

// ── presentCompound(orqResult, scenario) · PURA · solo transforma texto · cero throw ──
function presentCompound(orqResult, scenario) {
  try {
    if (!orqResult || !Array.isArray(orqResult.parts) || orqResult.parts.length === 0) return "";
    const parts = orqResult.parts;
    const hasMedidas = parts.some(p => p && p.eslabon === "medidas");
    // 1 · ordenar por narración canónica (sort estable por índice · independiente de ejecución)
    const ordenadas = parts.slice().sort((a, b) => {
      const ia = _D3C_ORDEN_NARRATIVO.indexOf(a.eslabon);
      const ib = _D3C_ORDEN_NARRATIVO.indexOf(b.eslabon);
      return (ia < 0 ? 99 : ia) - (ib < 0 ? 99 : ib);
    });
    // 2 + 3 · título + dedup del lever (solo en causa, con guarda de cifras)
    const bloques = ordenadas.map(pt => {
      let texto = (pt && typeof pt.opener === "string") ? pt.opener : "";
      if (pt && pt.eslabon === "causa" && hasMedidas && texto) {
        texto = texto.split("\n").filter(line => {
          // I-D3c-DEDUP-GUARDA · quita SOLO si es el lever Y NO tiene cifras
          if (_D3C_LEVER_RE.test(line) && !_D3C_NUM_RE.test(line)) return false;
          return true; // todo lo demás (incl. cualquier línea con dígitos) se conserva
        }).join("\n").trim();
      }
      const titulo = _D3C_TITULOS[pt && pt.eslabon] || (pt && pt.eslabon) || "";
      return "## " + titulo + "\n\n" + texto;
    });
    // 4 · concatenar con encabezados · sin intro (GD3c-4) · sin divisorias (GD3c-5)
    return bloques.join("\n\n");
  } catch (e) {
    // defensivo · si la presentación falla, el caller cae al crudo
    return "";
  }
}

// ── _d3cSelectSuggestions / _d3cSelectSentrix (GD3c-3 · SELECCIONA, no inventa) ──
function _d3cSelectSuggestions(orqResult) {
  try {
    const parts = orqResult && orqResult.parts;
    if (!Array.isArray(parts) || parts.length === 0) return [];
    // suggestions de la sección medidas (última narrativa); si no hay, de la última disponible
    const medidas = parts.find(p => p && p.eslabon === "medidas");
    const src = medidas || parts[parts.length - 1];
    return (src && Array.isArray(src.suggestions)) ? src.suggestions : [];
  } catch (e) { return []; }
}
function _d3cSelectSentrix(orqResult) {
  try {
    const parts = orqResult && orqResult.parts;
    if (!Array.isArray(parts)) return null;
    // sentrix del hallazgo de cuentas (ancla del hilo) cuando el compuesto incluye cuentas
    const cuentas = parts.find(p => p && p.eslabon === "ranking_cuentas");
    const src = cuentas || parts[0];
    return (src && src.rawResult && src.rawResult.sentrixAction) || null;
  } catch (e) { return null; }
}
// ═══ FIN ENCARGO D3.c · símbolos top-level ═══

// ═══ ENCARGO D3.d · "RESÚMEME LAS DOS COSAS" · DETERMINÍSTICO (7 firmas founder) ═══
// Cuando el usuario pide resumir tras conversar, ADI condensa LO QUE YA DIJO · extractivo
// determinístico desde chatMessages · CERO LLM · NO re-ejecuta composers · NO recalcula ·
// NO toca activeResult ni dataset. Fuente única: chatMessages (texto). Cierra el círculo:
// ADI conversa, responde compuesto, y RECUERDA. off = byte-idéntico D3.c.
const VOICE_D3D_SUMMARY_ENABLED = true;

// ── detectSummaryRequest(trimmed) · pre-dispatch · anti-colisión con "reporte ejecutivo" ──
const _D3D_SUMMARY_MARKERS = [
  "resumeme", "resumime", "hazme un resumen", "haceme un resumen",
  "resumen de ambas", "resumen de las dos", "resume lo anterior",
  "en resumen que vimos", "los dos temas", "ambas cosas", "las dos cosas",
  "resumen de lo que", "resumime lo", "resumeme lo",
];
function detectSummaryRequest(trimmed) {
  try {
    if (typeof VOICE_D3D_SUMMARY_ENABLED === "undefined" || !VOICE_D3D_SUMMARY_ENABLED) return null;
    if (typeof trimmed !== "string" || !trimmed) return null;
    const n = _normalizeSemanticText(trimmed);
    if (!n) return null;
    // ANTI-COLISIÓN: "resumen ejecutivo (del negocio)" genera análisis NUEVO → NO es D3.d.
    // D3.d resume el HILO conversado, no produce un reporte.
    if (/resumen\s+ejecutiv/i.test(n)) return null;
    const hit = _D3D_SUMMARY_MARKERS.some(m => n.indexOf(m) >= 0);
    return hit ? { summary: true } : null;
  } catch (e) { return null; }
}

// ── _d3dExtractCifras(texto) · todos los números/cifras del texto (para la guarda) ──
function _d3dExtractCifras(texto) {
  try {
    if (typeof texto !== "string") return [];
    // money $X(.Y)(K|M) · porcentajes X(.Y)% · pp/puntos · DOH/días numéricos
    const re = /\$[0-9][0-9.,]*\s*[KM]?|[0-9][0-9.,]*\s*%|[0-9][0-9.,]*\s*(?:pp|puntos|dias|días|d\b)/gi;
    return (texto.match(re) || []).map(s => s.replace(/\s+/g, "").toLowerCase());
  } catch (e) { return []; }
}

// ── _d3dIsSubstantive(text) · ¿el opener es un bloque analítico real? (D3d-SUSTANTIVO) ──
const _D3D_NON_SUBSTANTIVE_RE = [
  /no tengo evidencia determin/i,          // fallback
  /no las tengo servidas/i,                // fallback de cuentas
  /no las tengo servidas sin recalcul/i,
  /esas cifras no las tengo/i,
  /\bde ese an[aá]lisis son\b/i,           // eco de hallazgo (follow-up vacío)
  /las cifras de ese an[aá]lisis/i,        // eco de cifras
  /^\s*(ok|listo|dale|perfecto|gracias|hola|buenas)\b/i, // confirmaciones/saludos
];
function _d3dIsSubstantive(text) {
  try {
    if (typeof text !== "string" || text.trim().length < 20) return false;
    for (const re of _D3D_NON_SUBSTANTIVE_RE) if (re.test(text)) return false;
    return true; // tiene contenido analítico (hallazgo/causa/cruce/inventario/medidas/compuesta ##)
  } catch (e) { return false; }
}

// ── _d3dLastSubstantiveBlocks(chatMessages) · los 2 últimos sustantivos de ADI ──
function _d3dLastSubstantiveBlocks(chatMessages) {
  try {
    if (!Array.isArray(chatMessages)) return [];
    const adiOpeners = chatMessages
      .filter(m => m && m.role === "adi" && typeof m.text === "string")
      .map(m => m.text);
    const subst = adiOpeners.filter(_d3dIsSubstantive);
    return subst.slice(-2); // los 2 últimos (D3d-ALCANCE)
  } catch (e) { return []; }
}

// ── _d3dCondense(opener) · la(s) oración(es) tesis del bloque (primera de cada sección o la 1ra) ──
// ── _d3dCountCifras(linea) · cuántas cifras/entidades carga una línea (densidad de sustancia) ──
function _d3dCountCifras(linea) {
  try {
    if (typeof linea !== "string") return 0;
    const cifras = (linea.match(/\$[0-9][0-9.,]*\s*[KM]?|[0-9][0-9.,]*\s*%|\bDOH\s*[0-9]+|[0-9][0-9.,]*\s*(?:pp|puntos|dias|días)/gi) || []).length;
    return cifras;
  } catch (e) { return 0; }
}

// ── _d3dPickSubstanceLine(texto) · la línea-tesis CON cifras (no el encuadre genérico) ──
// FIX #D-D3d-EXTRACTOR-RECORTA-MAL: el extractor elegía la 1ra oración, que en muchos openers
// es un encuadre sin números ("6 cuentas están aportando volumen", "De lo que vendés en..."). 
// Ahora prefiere la línea con MÁS densidad de cifras (la sustancia). Si ninguna tiene cifras,
// cae a la 1ra oración (no rompe bloques sin números). NUNCA devuelve algo colgado/vacío.
function _d3dPickSubstanceLine(texto) {
  try {
    if (typeof texto !== "string" || !texto.trim()) return "";
    const crudas = texto.split("\n").map(l => l.trim()).filter(l => l.length > 0);
    const candidatas = [];
    for (const l of crudas) {
      if (/^##\s/.test(l)) continue;                 // título de sección
      if (/^en\s+[A-Z]/i.test(l) && /:$/.test(l)) continue; // "En Falabella:" (encabezado)
      candidatas.push(l.replace(/^[·\-]\s*/, ""));    // quitar bullet inicial
    }
    if (candidatas.length === 0) return "";
    // ── selección DOLOR-AWARE solo para líneas de SKU del cruce ("X se vende en...") ──
    // El brief pide "el SKU que más duele". Las líneas de SKU dicen "se vende en"; las de
    // cuenta ("Falabella → Margen X%") NO — esas van por densidad de cifras (no dolor).
    const skuLines = candidatas.filter(l => /\bse vende\b/i.test(l) && /margen\s*[0-9]/i.test(l));
    const dolorLines = skuLines.filter(l => /capital atrapado|rotaci[oó]n lenta|no se está vendiendo/i.test(l)
      && !/premium|rotaci[oó]n esperable|no capital atrapado/i.test(l));
    const pool = dolorLines.length ? dolorLines : skuLines;
    if (pool.length) {
      // peor margen primero (el dolor real)
      let peor = null, peorMargen = Infinity;
      for (const l of pool) {
        const m = (l.match(/margen\s*([0-9]+(?:\.[0-9]+)?)\s*%/i) || [])[1];
        const mv = (m != null) ? parseFloat(m) : Infinity;
        if (mv < peorMargen) { peorMargen = mv; peor = l; }
      }
      if (peor) return _d3dTrimLine(peor);
    }
    // ── caso general: la línea con MÁS densidad de cifras (la sustancia) ──
    let mejor = null, mejorScore = -1;
    for (const l of candidatas) {
      const sc = _d3dCountCifras(l);
      if (sc > mejorScore) { mejorScore = sc; mejor = l; }
    }
    const elegida = (mejorScore > 0) ? mejor : candidatas[0];
    return _d3dTrimLine(elegida);
  } catch (e) { return ""; }
}
// ── _d3dTrimLine · 1ra oración · NO-COLGADO (sin separador final vacío) ──
function _d3dTrimLine(linea) {
  try {
    let e = (String(linea).split(/(?<=[.])\s/)[0] || String(linea)).trim();
    e = e.replace(/[·:\-\s]+$/, "").trim();
    return e;
  } catch (err) { return String(linea || "").trim(); }
}

function _d3dCondense(opener) {
  try {
    if (typeof opener !== "string") return "";
    // si es compuesta D3.c (tiene ##): tomar la línea-sustancia de cada sección (no el encabezado)
    if (/##\s/.test(opener)) {
      const secs = opener.split(/\n##\s/).map((s, i) => i === 0 ? s.replace(/^##\s/, "") : s);
      const lineas = secs.map(sec => {
        const titulo = sec.split("\n")[0].trim();
        const cuerpo = sec.split("\n").slice(1).join("\n").trim();
        const sustancia = _d3dPickSubstanceLine(cuerpo);
        return sustancia ? (titulo + ": " + sustancia) : titulo;
      }).filter(Boolean);
      return lineas.join(" · ");
    }
    // bloque simple: la línea con sustancia (cifras), no la 1ra oración genérica (el FIX)
    const sustancia = _d3dPickSubstanceLine(opener);
    return sustancia || (opener.split(/(?<=[.·])\s/)[0] || "").trim() || opener.slice(0, 200).trim();
  } catch (e) { return (opener || "").slice(0, 200); }
}

// ── summarizeConversation(chatMessages) · el resumen extractivo · honestidad escalonada ──
// Devuelve { opener } | null. GUARDA I-D3d-CIFRA-TEXTUAL: cero cifras fuera de la fuente.
function summarizeConversation(chatMessages) {
  try {
    const bloques = _d3dLastSubstantiveBlocks(chatMessages);
    // NIVEL 1 · cero bloques → nada que resumir
    if (bloques.length === 0) {
      return { opener: "Todavía no hemos desarrollado un análisis que pueda resumir. Preguntame primero por clientes, margen, inventario o medidas y luego lo sintetizo." };
    }
    const fuente = bloques.join(" ");
    const cifrasFuente = _d3dExtractCifras(fuente);
    // NIVEL 2 · un bloque + pidió "las dos cosas" → resume ese, declara que hay uno
    if (bloques.length === 1) {
      const t1 = _d3dCondense(bloques[0]);
      let opener = "Hasta ahora solo hemos desarrollado un tema. Te resumo ese punto, y si querés después integramos otro.\n\n## Resumen\n\n· " + t1;
      // GUARDA · ninguna cifra del resumen fuera de la fuente
      opener = _d3dGuardCifras(opener, cifrasFuente);
      return { opener };
    }
    // NIVEL 3 · dos+ → resumen normal (los 2 últimos)
    const t1 = _d3dCondense(bloques[0]);
    const t2 = _d3dCondense(bloques[1]);
    // Lectura integrada · une IDEAS conversadas · CERO cifras nuevas (la guarda lo verifica)
    const integrada = _d3dLecturaIntegrada(bloques);
    let opener = "## Resumen\n\n· Tema 1: " + t1 + "\n· Tema 2: " + t2;
    if (integrada) opener += "\n\nLectura integrada: " + integrada;
    // GUARDA DURA · cada cifra del resumen debe existir textual en la fuente
    opener = _d3dGuardCifras(opener, cifrasFuente);
    return { opener };
  } catch (e) { return null; }
}

// ── _d3dGuardCifras(resumen, cifrasFuente) · I-D3d-CIFRA-TEXTUAL (la guarda dura) ──
// Si el resumen contiene una cifra que NO está en la fuente, se elimina la oración que la
// contiene (cifra fantasma → no pasa). Ninguna cifra del resumen puede ser nueva.
function _d3dGuardCifras(resumen, cifrasFuente) {
  try {
    const cifrasResumen = _d3dExtractCifras(resumen);
    const fantasmas = cifrasResumen.filter(c => cifrasFuente.indexOf(c) < 0);
    if (fantasmas.length === 0) return resumen;
    // hay cifra fantasma → recortar las líneas que la contienen (defensa)
    return resumen.split("\n").filter(linea => {
      const cifrasLinea = _d3dExtractCifras(linea);
      return !cifrasLinea.some(c => cifrasFuente.indexOf(c) < 0);
    }).join("\n");
  } catch (e) { return resumen; }
}

// ── _d3dLecturaIntegrada(bloques) · une ideas SIN cifras nuevas (licencia de síntesis) ──
function _d3dLecturaIntegrada(bloques) {
  try {
    const txt = bloques.join(" ").toLowerCase();
    const tieneCarga = /carga comercial/i.test(txt);
    const tieneSku = /sku|producto/i.test(txt);
    const tieneMedidas = /accion|renegociar|liquidar|plan/i.test(txt);
    // frases sin cifras · unen los temas conversados
    if (tieneCarga && tieneSku) return "el margen de las cuentas y el detalle por SKU apuntan al mismo origen comercial.";
    if (tieneCarga && tieneMedidas) return "la causa identificada y las medidas propuestas operan sobre la misma palanca.";
    return "";
  } catch (e) { return ""; }
}
// ═══ FIN ENCARGO D3.d · símbolos top-level ═══

// ═══ ENCARGO D3.0-bis · ruteo de "medidas" al composer ejecutivo (GD3-2 firmada) ═══
// El composer composeExecutiveAction (L11447) YA existe y tiene disciplina (cifras runtime,
// acciones trazables). El hueco era de DETECCIÓN: detectExecutiveIntent no reconocía
// "medidas"/"solucionar"/"qué hago". Esta pieza abre la puerta léxica · contenido cero nuevo.
// NO toca el orden de precedencia de detectIntent (la frase COMPUESTA es D3.a/b).
const VOICE_D30BIS_MEASURES_ENABLED = true;
// Patrones del hueco · familia `action` · anclados/word-boundary/acentos tolerados.
// Anti-colisión probada offline + en vivo: ninguna ruta sellada cambia.
const _D30BIS_MEASURES_PATTERNS = [
  /\bmedidas?\b/i,                                                  // "dame medidas", "qué medidas"
  /\b(soluci[oó]n(ar|arlo|arla|es)?|c[oó]mo\s+(lo\s+|la\s+)?soluciono)\b/i, // "solucionar", "cómo lo soluciono"
  /\bqu[eé]\s+hago\b/i,                                             // "qué hago" (sin requerir "primero")
];

const EXECUTIVE_INTENT_PATTERNS = {
  action: [
    /\b(si\s+fueras|qu[eé]\s+har[ií]as|qu[eé]\s+har[ií]a\s+yo|c[oó]mo\s+atacar|por\s+d[oó]nde\s+empi?ez)/i,
    /\b(priorizo|prioriz(ar|ar[ií]a)|prioridad\s+ahora|este\s+mes|esta\s+semana)/i,
    // RUTEO · familia estricta de priorización (cada patrón anclado · separados para legibilidad/seguridad)
    /\bqu[eé]\s+(deber[ií]a|tengo\s+que)\s+hacer\s+primero\b/i,
    /\bqu[eé]\s+hago\s+primero\b/i,
    /\bqu[eé]\s+hacer\s+primero\b/i,
    /\b(dame\s+una\s+recomendaci[oó]n|qu[eé]\s+(me\s+)?recom(i?e)nd(ar[ií]as|as|aci[oó]n))/i,
    /\blo\s+m[aá]s\s+(importante|urgente)\b/i,
  ],
  opportunity: [
    /\b(qu[eé]\s+(no\s+veo|me\s+pierdo|estoy\s+ignorando|oportunidad)|qu[eé]\s+falta)/i,
    /\b(angulo\s+ciego|ciego|no\s+veo)/i,
  ],
  concern: [
    /\b(qu[eé]\s+me\s+preocupar[ií]a|qu[eé]\s+miedo|qu[eé]\s+riesgos?|si\s+fuera\s+mi\s+empresa)/i,
    /\b(qu[eé]\s+podr[ií]a\s+salir\s+mal|qu[eé]\s+vigilar)/i,
  ],
};

// ── detectExecutiveIntent · clasificador subtype ─────────────────────────
// Retorna { type: "executive_intent", subtype: "action"|"opportunity"|"concern" }
// si matchea pattern · NULL si no. Sigue precedencia FIX_L_PRECEDENCE · llamar
// ANTES de SKU detection en detectIntent.
//
// Orden de prueba: concern → opportunity → action.
// Razón: "qué me preocuparía si fuera gerente comercial" contiene 'fueras'
// (action pattern weak) Y 'preocuparía' (concern · más específico).
// Concern primero evita falsos positivos action sobre queries concern.
function detectExecutiveIntent(text) {
  if (!text || typeof text !== "string") return null;
  // Probar concern (más específico semánticamente)
  for (const p of EXECUTIVE_INTENT_PATTERNS.concern) {
    if (p.test(text)) return { type: "executive_intent", subtype: "concern" };
  }
  // Probar opportunity
  for (const p of EXECUTIVE_INTENT_PATTERNS.opportunity) {
    if (p.test(text)) return { type: "executive_intent", subtype: "opportunity" };
  }
  // Probar action (último · patterns más amplios)
  for (const p of EXECUTIVE_INTENT_PATTERNS.action) {
    if (p.test(text)) return { type: "executive_intent", subtype: "action" };
  }
  // ═══ D3.0-bis · hueco léxico de "medidas" (GD3-2 · única fuente · flag-gated) ═══
  // Extensión de la familia `action` (medidas/solucionar/qué hago son acción ejecutiva).
  // Agregada acá (no en el const array) para gatear por flag sin tocar la estructura sellada.
  // Anti-colisión verificada: cero solape con 16t ni rutas selladas (rankings/causa/cruce/overview).
  // off = inerte ("medidas" vuelve a fallback K · byte-idéntico D2.b).
  if (typeof VOICE_D30BIS_MEASURES_ENABLED !== "undefined" && VOICE_D30BIS_MEASURES_ENABLED) {
    for (const p of _D30BIS_MEASURES_PATTERNS) {
      if (p.test(text)) return { type: "executive_intent", subtype: "action" };
    }
  }
  return null;
}

// ── Composer placeholders · N.B.1/N.B.2/N.B.3 implementan ─────────────────
// Por ahora retornan honest-unavailable shape · permiten test infraestructura
// sin crashes. Sub-fases B implementan lógica real.
// ── BRIEF N.B.1 · helpers ejecutivos ───────────────────────────────────────
// Scoring weights firmados founder D-N-1: 0.4 impact · 0.4 controllability · 0.2 urgency
const _EXEC_WEIGHTS = { impact: 0.4, controllability: 0.4, urgency: 0.2 };
const _EXEC_CTRL_MAP = { alta: 1.0, media: 0.6, baja: 0.3 };
const _EXEC_URG_MAP  = { critica: 1.0, atencion: 0.6, seguir: 0.3 };

function _scoreExecutiveAction(impactK, controllability, urgency) {
  // impactK normalizado: 1.0 = $1M+ · escala lineal por debajo
  const impactNorm = Math.min(1, Math.max(0, impactK / 1000));
  const ctrl = _EXEC_CTRL_MAP[controllability] || 0.3;
  const urg = _EXEC_URG_MAP[urgency] || 0.3;
  return +(
    impactNorm * _EXEC_WEIGHTS.impact +
    ctrl * _EXEC_WEIGHTS.controllability +
    urg * _EXEC_WEIGHTS.urgency
  ).toFixed(3);
}

// ── _deriveOpportunityAxes · MATERIALITY v1 · 5 ejes firmados sobre cada candidato ──
// NO score · NO ponderación · ejes OBSERVABLES y separados (valor_anual vs capital · regla de oro).
// Reusa _deriveTierFromContribution (L9022) para riesgo · _EXEC_CTRL_MAP como insumo de esfuerzo (NO peso).
const MATERIALITY_AXES_ENABLED = true;
const MATERIALITY_COMPLETE = true;  // MATERIALITY v1 · cierre formal · paridad VOICE_BRIEF_*_COMPLETE / ARCO
function _deriveOpportunityAxes(candidate, scenarioId) {
  if (!candidate) return null;
  const t = candidate.type;
  // EJE valor_anual vs capital_liberable · SEPARADOS por naturaleza (nunca sumar)
  let valor_anual = null, capital_liberable = null;
  if (t === "commercial_load_renegotiation") {
    valor_anual = candidate.recoverable_K || 0;        // flujo recurrente anual
  } else if (t === "sku_operational_exit") {
    capital_liberable = candidate.recoverable_K || 0;  // capital one-time liberable
  } else if (t === "tier2_diversification") {
    // Concentración: valor en RIESGO (exposed_M), NO captura ni capital liberable (firmado v1.1-B).
    // exposed_M queda como CONTEXTO NARRATIVO · NO es eje. valor/capital permanecen null.
    valor_anual = null; capital_liberable = null;
  } else {
    valor_anual = null; capital_liberable = null;
  }
  // EJE riesgo · ordinal alto/medio/bajo
  let riesgo = "bajo";
  if (t === "commercial_load_renegotiation") {
    // entities son clientes · riesgo = mayor Tier entre las entities (T1=alto · T2=medio · T3=bajo)
    try {
      // clientesVentas NO tiene campo `tipo` (sí clientesMargen) · patrón canónico L9120: sin filtro.
      const ventasScope = applyScenarioToClientesVentas(scenarioId);
      let maxTierRank = 0; // 0=bajo · 1=medio · 2=alto
      for (const name of (candidate.entities || [])) {
        const ti = _deriveTierFromContribution(name, ventasScope);
        const r = ti ? (ti.tier === 1 ? 2 : (ti.tier === 2 ? 1 : 0)) : 0;
        if (r > maxTierRank) maxTierRank = r;
      }
      riesgo = maxTierRank === 2 ? "alto" : (maxTierRank === 1 ? "medio" : "bajo");
    } catch (e) { riesgo = "bajo"; }
  } else if (t === "sku_operational_exit") {
    // SKUs · capital propio · sin cuenta estratégica en juego · riesgo de concentración bajo (v1)
    riesgo = "bajo";
  } else if (t === "tier2_diversification") {
    // Concentración: riesgo desde concentration_pct · umbral canónico ≥50 (= L11216 severity_threshold_hit)
    // Defendible: "riesgo alto porque 3 cuentas superan la mitad del negocio".
    const _conc = candidate.concentration_pct || 0;
    riesgo = _conc >= 50 ? "alto" : (_conc >= 35 ? "medio" : "bajo");
  }
  // EJE urgencia · del tag existente (critica/atencion/seguir → alta/media/baja)
  const _urgMap = { critica: "alta", atencion: "media", seguir: "baja" };
  const urgencia = _urgMap[candidate.urgency] || "media";
  // EJE esfuerzo · naturaleza de la acción × Tier (Tier agrava SOLO negociación · firmado)
  let esfuerzo;
  if (t === "sku_operational_exit") {
    esfuerzo = "bajo";          // liquidar/plan de salida = unilateral (Tier NO agrava)
  } else if (t === "commercial_load_renegotiation") {
    esfuerzo = (riesgo === "alto") ? "alto" : "medio";  // negociar · agravado si Tier 1
  } else if (t === "tier2_diversification") {
    esfuerzo = "medio";  // diversificar = coordinación estructural · ni unilateral ni negociación pura
  } else {
    esfuerzo = "medio";
  }
  return { valor_anual, capital_liberable, riesgo, urgencia, esfuerzo };
}

// ── _detectExecutiveActions · construye candidatos runtime ────────────────
// Retorna array de candidatos · cada uno pre-scoreado. El builder de signals
// se queda con top 3 por score (NO por orden de detección).
//
// Candidatos detectados:
//   1. Renegociar carga comercial sobre top contribuyentes con driver activo
//      (D-N-6 · D-N.B.1-1 opción b · filtra top-contribuyentes · ordena por recK)
//   2. Plan de salida sobre SKUs operacional_inefficient (cap 3)
//      (D-N-7 · runtime real · 3 SKUs bonanza/tensión · 1 SKU crisis)
//   3. Diversificación Tier 2 (customer_dependency_risk)
function _detectExecutiveActions(scenarioId, override) {
  const actions = [];

  // ── CANDIDATO 1 · renegociar carga top contribuyentes ──
  try {
    const cm = applyScenarioToClientesMargen(scenarioId, override).filter(c => c.tipo === "cliente");
    // Filtro D-N.B.1-1 (b): top contribuyentes con driver carga · luego ordenar por recK
    // Tomamos los 6 mayores contribuyentes como universo (cubre Tier 1+2)
    const topContrib = [...cm].sort((a, b) => (b.contribucion || 0) - (a.contribucion || 0)).slice(0, 6);
    const withDriver = [];
    for (const c of topContrib) {
      const driver = detectInternalDriver(c, "margen", "client", cm);
      if (driver && driver.factor === "carga_comercial") {
        const recK = calculateRecoverable(c, "margen", "client", driver, cm);
        // Recoverable a best practice 3.0% · cálculo paralelo
        const recK_BP = Math.round((c.venta || 0) * Math.max(0, (c.pctRebate || 0) - 3.0) / 100);
        withDriver.push({ nombre: c.nombre, recK, recK_BP, pctRebate: c.pctRebate });
      }
    }
    // Ordenar por recK desc · tomar top 3
    withDriver.sort((a, b) => b.recK - a.recK);
    const top3 = withDriver.slice(0, 3);
    if (top3.length >= 2) {
      const totalRecK = top3.reduce((s, c) => s + c.recK, 0);
      const totalRecK_BP = top3.reduce((s, c) => s + c.recK_BP, 0);
      // MAT-B2 · urgencia crítica si algún cliente del grupo opera bajo costo real (margen < 0 o muy bajo)
      // MAT-B3 · umbral relativo defendible: opera a menos de la mitad del benchmark de cartera.
      // (margen<0 era inalcanzable · clamp Math.max(6,...) · #L-MAT-B2-ELEVACION-AUN-INALCANZABLE)
      const _cargaCrit = top3.some(c => {
        const cm = applyScenarioToClientesMargen(scenarioId, override).find(x => x.nombre === c.nombre);
        const _bench = (cm && cm.benchmark) || 30.1;
        return cm && cm.margen != null && cm.margen < _bench / 2;
      });
      const _cargaUrgency = _cargaCrit ? "critica" : "atencion";
      actions.push({
        type: "commercial_load_renegotiation",
        entities: top3.map(c => c.nombre),
        recoverable_K: totalRecK,
        recoverable_BP_K: totalRecK_BP,
        controllability: "alta",
        urgency: _cargaUrgency,
        verb: "renegociar carga comercial",
        criterion: "alta controlabilidad · horizonte inmediato",
        instance_count: top3.length,
        score: _scoreExecutiveAction(totalRecK, "alta", _cargaUrgency),
      });
    }
  } catch (e) {
    // fail-safe · candidato no se agrega
  }

  // ── CANDIDATO 2 · plan de salida SKUs operacionales ──
  try {
    const inv = applyScenarioToSkuInventario(scenarioId, override);
    // Top 4 capital atrapado (cualquier alerta) · filtrar a operational_inefficient
    const critical = inv
      .filter(s => s.alerta === "crit" || s.alerta === "warn" || s.estado !== "Activo")
      .sort((a, b) => (b.stockUSD || 0) - (a.stockUSD || 0))
      .slice(0, 4);
    const operational = critical
      .filter(s => classifySkuOperationalProfile(s) === "operational_inefficient")
      .slice(0, 3);
    if (operational.length >= 1) {
      const stockK = Math.round(operational.reduce((s, k) => s + (k.stockUSD || 0), 0) / 1000);
      const avgDoh = Math.round(operational.reduce((s, k) => s + (k.doh || 0), 0) / operational.length);
      // MAT-B2 · urgencia derivada del deterioro real (no hardcode): DOH crítico o alerta crit
      const _hasCrit = operational.some(s => s.alerta === "crit") || avgDoh > 150;
      const _invUrgency = _hasCrit ? "critica" : "atencion";
      actions.push({
        type: "sku_operational_exit",
        entities: operational.map(s => s.sku),
        recoverable_K: stockK,
        avg_doh: avgDoh,
        controllability: "alta",
        urgency: _invUrgency,
        verb: "activar plan de salida",
        criterion: _invUrgency === "critica"
          ? "capital atrapado · deterioro crítico · libera liquidez para reinvertir"
          : "capital atrapado · libera liquidez para reinvertir",
        instance_count: operational.length,
        score: _scoreExecutiveAction(stockK, "alta", _invUrgency),
      });
    }
  } catch (e) { /* fail-safe */ }

  // ── CANDIDATO 3 · diversificación Tier 2 (customer_dependency_risk) ──
  try {
    const scan = scanMechanisms(scenarioId, override);
    const dep = scan?.customer_dependency_risk;
    if (dep?.triggered && dep.aggregate) {
      const agg = dep.aggregate;
      // Impacto estructural: el monto expuesto en $M → convertir a K para scoring uniforme
      const exposedK = Math.round((agg.top3_contribucion_M || 0) * 1000);
      // MAT-v1.1-C · urgencia crítica si una cuenta CONCENTRADA opera bajo media benchmark
      // (MISMA señal de deterioro que la carga · MAT-B3 · no se inventa otra definición).
      // Defendible: "dependés de estas cuentas y una opera bajo media benchmark".
      const _cmConc = applyScenarioToClientesMargen(scenarioId, override);
      const _concDeteriorada = (agg.top3_names || []).some(name => {
        const c = _cmConc.find(x => x.nombre === name);
        const _bench = (c && c.benchmark) || 30.1;
        return c && c.margen != null && c.margen < _bench / 2;
      });
      const _concUrgency = _concDeteriorada ? "critica" : "seguir";
      actions.push({
        type: "tier2_diversification",
        entities: agg.top3_names || [],
        concentration_pct: agg.top3_participacion_pct,
        exposed_M: agg.top3_contribucion_M,
        recoverable_K: exposedK,
        controllability: "baja",
        urgency: _concUrgency,
        verb: "activar plan de diversificación Tier 2",
        criterion: _concDeteriorada
          ? "estructural · exposición activa: una cuenta concentrada opera bajo media benchmark"
          : "estructural · horizonte 12-18 meses",
        instance_count: agg.instances_count || 3,
        score: _scoreExecutiveAction(exposedK, "baja", _concUrgency),
      });
    }
  } catch (e) { /* fail-safe */ }

  return actions;
}

// ── _compareByHierarchy · MATERIALITY v1 · jerarquía firmada (NO score) ──
// Nivel 1: elevación (riesgo alto × urgencia alta = riesgo estructural crítico).
// Fuera de nivel 1: valor económico > urgencia > esfuerzo. Reglas nombradas · sin pesos.
const HIERARCHY_ENABLED = true;
const _URG_RANK = { alta: 3, media: 2, baja: 1 };
const _RIESGO_RANK = { alto: 3, medio: 2, bajo: 1 };
const _ESF_RANK = { bajo: 3, medio: 2, alto: 1 }; // menor esfuerzo = mejor (rank más alto)
function _isStructuralCritical(ax) {
  // Regla de elevación nombrada: cuenta estratégica (riesgo alto) Y deterioro activo (urgencia alta)
  return ax && ax.riesgo === "alto" && ax.urgencia === "alta";
}
function _opportunityValue(ax) {
  // valor económico comparable: usa el monto disponible SIN sumar naturalezas distintas.
  // valor_anual y capital_liberable NO se suman · se compara por el que exista (regla de oro).
  // Para ordenar, se toma el monto presente (uno de los dos es null por construcción).
  if (!ax) return 0;
  if (ax.valor_anual != null) return ax.valor_anual;
  if (ax.capital_liberable != null) return ax.capital_liberable;
  return 0;
}
function _compareByHierarchy(a, b) {
  const ax = a.axes, bx = b.axes;
  // NIVEL 1 · elevación
  const aCrit = _isStructuralCritical(ax), bCrit = _isStructuralCritical(bx);
  if (aCrit !== bCrit) return aCrit ? -1 : 1;
  // FUERA de nivel 1 · jerarquía valor > urgencia > esfuerzo
  // 1. valor económico (desc)
  const av = _opportunityValue(ax), bv = _opportunityValue(bx);
  if (av !== bv) return bv - av;
  // 2. urgencia (desc)
  const au = _URG_RANK[ax?.urgencia] || 0, bu = _URG_RANK[bx?.urgencia] || 0;
  if (au !== bu) return bu - au;
  // 3. esfuerzo (menor esfuerzo primero · _ESF_RANK ya invertido)
  const ae = _ESF_RANK[ax?.esfuerzo] || 0, be = _ESF_RANK[bx?.esfuerzo] || 0;
  if (ae !== be) return be - ae;
  return 0;
}

// ── buildNarrativeSignalsForExecutiveAction · signals kind=executive_action ──
function buildNarrativeSignalsForExecutiveAction(scenarioId, conversationContext, modulo, override) {
  const candidates = _detectExecutiveActions(scenarioId, override);
  if (!candidates || candidates.length === 0) return null;
  // MATERIALITY v1 · ordenar por JERARQUÍA firmada (elevación > valor > urgencia > esfuerzo).
  // El score se preserva como CAMPO (Sentrix) pero ya NO decide el orden. Capa A pobló a.axes.
  if (HIERARCHY_ENABLED) {
    candidates.forEach(c => { if (!c.axes) c.axes = _deriveOpportunityAxes(c, scenarioId); });
    candidates.sort(_compareByHierarchy);
  } else {
    candidates.sort((a, b) => (b.score || 0) - (a.score || 0));
  }
  const top3Scored = candidates.slice(0, 3).map((a, i) => ({
    rank: i + 1, // rank matemático por score · preservado para Sentrix/consumidores
    type: a.type,
    entities: a.entities,
    recoverable_K: a.recoverable_K,
    recoverable_BP_K: a.recoverable_BP_K,
    avg_doh: a.avg_doh,
    concentration_pct: a.concentration_pct,
    exposed_M: a.exposed_M,
    controllability_tag: a.controllability,
    urgency_tag: a.urgency,
    verb: a.verb,
    criterion: a.criterion,
    instance_count: a.instance_count,
    score: a.score,
    axes: (typeof MATERIALITY_AXES_ENABLED !== "undefined" && MATERIALITY_AXES_ENABLED)
      ? _deriveOpportunityAxes(a, scenarioId) : null,
  }));
  // FIX D-N.B.1-2 · reorden de presentación · arco temporal coherente.
  // Mueve acciones de controlabilidad baja (structural-horizon · diversificación)
  // al final del array narrativo. El ranking matemático queda preservado en
  // actions[i].rank · pero el orden de iteración para narrativa cambia para
  // cerrar con la acción estructural + reframe parallel_horizons natural.
  // MAT-v1.1-D · la presentación NUNCA contradice el ranking. El arco temporal (estructural al
  // final) aplica solo a lo NO elevado · una oportunidad _isStructuralCritical dejó de ser horizonte
  // largo (es atención inmediata) → no va al bloque estructural · sigue a la jerarquía.
  const immediate = top3Scored.filter(a => a.controllability_tag !== "baja" || _isStructuralCritical(a.axes));
  const structural = top3Scored.filter(a => a.controllability_tag === "baja" && !_isStructuralCritical(a.axes));
  const presentationOrder = [...immediate, ...structural];
  // Priority rationale: criterio del action top1 por score (el de mayor score)
  const priorityRationale = top3Scored[0].criterion;
  // Detectar si hay structural action (para activar reframe parallel_horizons)
  const hasStructural = top3Scored.some(a => a.type === "tier2_diversification");
  return {
    kind: "executive_action",
    scenario: scenarioId,
    actions: presentationOrder,
    priority_rationale: priorityRationale,
    has_structural: hasStructural,
  };
}

// ── composeExecutiveActionNarrative · postura recommend · primera persona ──
function composeExecutiveActionNarrative(signals, posture, ctx) {
  if (!signals || signals.kind !== "executive_action") return null;
  if (!Array.isArray(signals.actions) || signals.actions.length === 0) return null;

  const actions = signals.actions;
  const movements = [];

  // MAT-VOZ · helpers de render PURO (no tocan jerarquía/ejes/detección/orden)
  const titleOf = (t) =>
    t === "commercial_load_renegotiation" ? "Recuperar margen en cuentas estratégicas" :
    t === "sku_operational_exit"          ? "Liberar capital inmovilizado" :
    t === "tier2_diversification"         ? "Reducir dependencia de cuentas concentradas" :
    "Movimiento prioritario";
  const fmtList = (arr) => !arr || arr.length === 0 ? "" :
    arr.length === 1 ? arr[0] :
    arr.length === 2 ? arr.join(" y ") :
    arr.slice(0, -1).join(" · ") + " y " + arr[arr.length - 1];
  // cuenta concentrada que opera bajo media benchmark (MISMA señal de deterioro · MAT-B3/C)
  const critClientOf = (a) => (a.entities || []).find(name => {
    const cm = applyScenarioToClientesMargen(signals.scenario).find(x => x.nombre === name);
    return cm && cm.margen != null && cm.margen < (cm.benchmark || 30.1) / 2;
  });

  // ── INTRO · materialidad (reemplaza la apertura en primera persona) ──
  movements.push(`Hay ${actions.length} ${actions.length === 1 ? "movimiento" : "movimientos"} que explican la mayor parte del resultado. Empezaría por este orden:`);

  // ── POR CADA acción (en orden de presentación · idéntico a build · la voz NO reordena) ──
  for (let i = 0; i < actions.length; i++) {
    const a = actions[i];
    const riesgoAlto = a.axes && a.axes.riesgo === "alto";
    const critico = _isStructuralCritical(a.axes);
    let body = "", reason = "";

    if (a.type === "commercial_load_renegotiation") {
      body = `${fmtList(a.entities)} operan con carga comercial sobre el estándar interno. Hay $${a.recoverable_K}K de margen anual recuperable (hasta $${a.recoverable_BP_K}K a mejor práctica).`;
      // jerarquía de razón · atada a riesgo alto (cuenta estratégica en juego) · NO fija
      if (riesgoAlto) {
        reason = critico
          ? ` Más importante aún: el deterioro toca cuentas estratégicas — no es solo rentabilidad, es proteger el valor de los principales clientes.`
          : ` Más importante aún: toca cuentas estratégicas (Tier 1) — no es solo rentabilidad, es el valor de los principales clientes.`;
      }
    } else if (a.type === "sku_operational_exit") {
      const verbo = (a.entities && a.entities.length === 1) ? "mantiene" : "mantienen";
      body = `${fmtList(a.entities)} ${verbo} ${a.avg_doh} días de cobertura y $${a.recoverable_K}K de capital detenido.`;
      // inventario es riesgo bajo · sin jerarquía de razón (atado a señal · no se inventa urgencia)
    } else if (a.type === "tier2_diversification") {
      body = `${a.entities.slice(0, 3).join(" · ")} concentran ${a.concentration_pct}% del negocio · $${a.exposed_M}M de contribución expuesta.`;
      // jerarquía de razón SOLO cuando la concentración se volvió crítica (elevación · atada a señal)
      if (critico) {
        const cc = critClientOf(a);
        reason = cc
          ? ` Más importante aún: el riesgo dejó de ser latente — ${cc} opera bajo media benchmark.`
          : ` Más importante aún: el riesgo de concentración dejó de ser latente.`;
      }
    } else {
      body = `${a.criterion}. Cifra clave $${a.recoverable_K}K.`;
    }

    // DECISIÓN · imperativo de cierre derivado de a.verb
    movements.push(`${i + 1}. ${titleOf(a.type)}. ${body}${reason} Decisión: ${a.verb}.`);
  }

  // ── LECTURA EJECUTIVA · reconstruye el criterio que ordenó (lee el #1 · NO toca _compareByHierarchy) ──
  const lead = actions[0];
  if (_isStructuralCritical(lead.axes)) {
    const cc = critClientOf(lead) || fmtList(lead.entities);
    movements.push(`La prioridad la define el riesgo, no el monto: ${cc} se está deteriorando y es cuenta estratégica. Por eso encabeza, aunque no sea la cifra más grande.`);
  } else {
    movements.push(`La prioridad no la define el monto más grande, sino la combinación de impacto, urgencia y capacidad de acción. ${titleOf(lead.type)} encabeza porque genera valor directo y puede ejecutarse ahora.`);
  }

  // ── HORIZONTE · SOLO si hay structural NO elevado al final (atado a señal · no fijo) ──
  // ── SÍNTESIS · conectar oportunidades que comparten entidad (firmado · solo si dato lo respalda) ──
  // Nivel 1: entidad compartida entre oportunidades de CLIENTE (carga ↔ concentración · mismo espacio
  // de nombres). Inventario (SKUs) queda fuera por naturaleza · no se fuerza vínculo.
  const _clientActions = actions.filter(a =>
    a.type === "commercial_load_renegotiation" || a.type === "tier2_diversification");
  if (_clientActions.length >= 2) {
    // intersección de entities entre las oportunidades de cliente
    const _sets = _clientActions.map(a => new Set(a.entities || []));
    const _shared = [...(_sets[0] || [])].filter(name => _sets.every(s => s.has(name)));
    if (_shared.length > 0) {
      const _list = _shared.length === 1 ? _shared[0]
        : _shared.slice(0, -1).join(", ") + " y " + _shared[_shared.length - 1];
      // Nivel 2 · causa común: ¿las oportunidades compartidas están elevadas por la misma entidad?
      const _ambasElevadas = _clientActions.every(a => _isStructuralCritical(a.axes));
      if (_ambasElevadas) {
        movements.push(`${_list} cruzan dos frentes a la vez: su carga comercial y la dependencia que genera. El mismo deterioro está elevando las dos — no son problemas separados, son la misma relación bajo presión.`);
      } else {
        movements.push(`${_list} aparecen en dos frentes: renegociar su carga y reducir la dependencia de esa cuenta. Son la misma relación comercial vista desde la rentabilidad y desde el riesgo.`);
      }
    }
  }

  const structuralPendiente = actions.find(a => a.controllability_tag === "baja" && !_isStructuralCritical(a.axes));
  if (structuralPendiente) {
    movements.push(`La concentración es el mayor riesgo en tamaño, pero su horizonte es de 12-18 meses: se aborda en paralelo, no antes que lo inmediato.`);
  }

  return movements.join("\n\n");
}

// ── composeExecutiveAction · COMPOSER REAL (reemplaza placeholder N.A) ────
function composeExecutiveAction(scenario, conversationContext, modulo) {
  // Build signals (cifras runtime · cero hardcoded)
  let signals = null;
  try {
    signals = buildNarrativeSignalsForExecutiveAction(scenario, conversationContext, modulo);
  } catch (e) {
    // eslint-disable-next-line no-console
    console.warn("BRIEF N.B.1 signals build error:", e);
    signals = null;
  }

  // Si no hay candidatos válidos · honest fallback
  if (!signals) {
    return {
      opener: "No tengo evidencia determinística suficiente para recomendar acciones ejecutivas con el escenario actual.",
      suggestions: [],
      sentrixAction: null,
      derivedIntentType: "executive_intent",
      reasoningPattern: "executive_action_unavailable",
      // SIN narrative_signals · SIN posture_hint · skip narrative_layer
    };
  }

  // Opener legacy (fallback rollback · flag OFF · FASE 5 skip)
  // Cuando narrative_layer aplica · reemplaza este opener con la narrativa fina
  const openerLegacy = `Top ${signals.actions.length} acciones priorizadas para el escenario ${scenario}: ${signals.actions.map(a => a.verb).join(" · ")}.`;

  return {
    opener: openerLegacy,
    suggestions: [],
    sentrixAction: null,
    derivedIntentType: "executive_intent",
    reasoningPattern: "executive_action",
    narrative_signals: signals,
    posture_hint: "recommend",
  };
}

// ── BRIEF N.B.2 · helpers hidden opportunity ──────────────────────────────
// _detectHiddenAngle · orden de precedencia determinístico (D-N.B.2-4).
// Usa campos REALES del conversationContext (D-N.B.2-1) · cero touch al shape.
// Reglas firmadas founder:
//   1. quality_of_growth_missed     · investigationMetric margen/carga o client_deep_dive
//   2. structural_concentration     · ranking previo · no se miró concentración
//   3. operational_capital_missed   · módulo ventas/margenes · no se miró inventario
//   4. commercial_load_missed       · módulo inventario · no se miró carga comercial
//   5. default (ctx vacío)          · revela quality_growth (D-N-8)
function _detectHiddenAngle(ctx, scenarioId) {
  // Regla 1 · quality_of_growth_missed
  if (ctx?.investigationMetric === "margen" ||
      ctx?.investigationMetric === "carga_comercial" ||
      ctx?.lastIntent === "client_deep_dive") {
    return {
      rule: "quality_of_growth_missed",
      reveal: "quality_growth_deterioration",
      reframe_key: "hidden_blind_spot",
      context_seen_label: "margen y carga comercial",
    };
  }
  // Regla 2 · structural_concentration_missed
  if (ctx?.lastIntent === "ranking_extremes" ||
      ctx?.lastIntent === "client_contribution_ranking" ||
      ctx?.lastIntent === "cross_metric_ranking") {
    return {
      rule: "structural_concentration_missed",
      reveal: "customer_dependency_risk",
      reframe_key: "structural_dependency",
      context_seen_label: "rankings de clientes",
    };
  }
  // Regla 3 · operational_capital_missed
  if (ctx?.lastModuleAsked === "ventas" || ctx?.lastModuleAsked === "margenes") {
    return {
      rule: "operational_capital_missed",
      reveal: "sku_operational",
      reframe_key: "operational_inefficiency",
      context_seen_label: ctx.lastModuleAsked === "ventas" ? "ventas" : "margenes",
    };
  }
  // Regla 4 · commercial_load_missed
  if (ctx?.lastModuleAsked === "inventario") {
    return {
      rule: "commercial_load_missed",
      reveal: "commercial_erosion",
      reframe_key: "internal_commercial_load",
      context_seen_label: "inventario y capital atrapado",
    };
  }
  // Regla 5 · default (ctx vacío · D-N-8)
  return {
    rule: "default_ctx_empty",
    reveal: "quality_growth_deterioration",
    reframe_key: "hidden_blind_spot",
    context_seen_label: null,
  };
}

// _buildHiddenAngleCifras · obtiene cifras runtime según reveal (D-N.B.2-5)
// Retorna { hidden_angle, has_data } o null si scenario no soporta el angle.
function _buildHiddenAngleCifras(reveal, scenarioId) {
  try {
    if (reveal === "quality_growth_deterioration") {
      const scan = scanMechanisms(scenarioId);
      const m = scan?.quality_of_growth_deterioration;
      if (!m?.triggered || !m.aggregate) return null;
      const agg = m.aggregate;
      return {
        dimension: "calidad_crecimiento",
        cifra_M: agg.contribucion_perdida_M,
        instances_count: agg.instances_count,
        growth_min: agg.crecimiento_range?.min,
        growth_max: agg.crecimiento_range?.max,
      };
    }
    if (reveal === "customer_dependency_risk") {
      const scan = scanMechanisms(scenarioId);
      const m = scan?.customer_dependency_risk;
      if (!m?.triggered || !m.aggregate) return null;
      const agg = m.aggregate;
      return {
        dimension: "concentración_estructural",
        top3_names: agg.top3_names || [],
        concentration_pct: agg.top3_participacion_pct,
        exposed_M: agg.top3_contribucion_M,
      };
    }
    if (reveal === "sku_operational") {
      // Reusa lógica de _detectExecutiveActions (N.B.1) · NO duplica helper.
      // SKUs operational_inefficient · top 3 por stockUSD descendente.
      const inv = applyScenarioToSkuInventario(scenarioId);
      const critical = inv
        .filter(s => s.alerta === "crit" || s.alerta === "warn" || s.estado !== "Activo")
        .sort((a, b) => (b.stockUSD || 0) - (a.stockUSD || 0))
        .slice(0, 4);
      const op = critical.filter(s => classifySkuOperationalProfile(s) === "operational_inefficient").slice(0, 3);
      if (op.length === 0) return null;
      const stockK = Math.round(op.reduce((s, k) => s + (k.stockUSD || 0), 0) / 1000);
      const avgDoh = Math.round(op.reduce((s, k) => s + (k.doh || 0), 0) / op.length);
      return {
        dimension: "capital_operacional_atrapado",
        instances_count: op.length,
        capital_K: stockK,
        avg_doh: avgDoh,
        sku_names: op.map(s => s.sku),
      };
    }
    if (reveal === "commercial_erosion") {
      const scan = scanMechanisms(scenarioId);
      const m = scan?.commercial_erosion;
      if (!m?.triggered || !m.aggregate) return null;
      const agg = m.aggregate;
      return {
        dimension: "erosión_comercial",
        recuperable_K: agg.recuperable_total_K,
        recuperable_BP_M: agg.recuperable_total_M_at_3_0,
        instances_count: agg.instances_count,
      };
    }
  } catch (e) {
    // fail-safe
    return null;
  }
  return null;
}

// buildNarrativeSignalsForHiddenOpportunity · kind=executive_opportunity
function buildNarrativeSignalsForHiddenOpportunity(scenarioId, conversationContext, modulo) {
  const angle = _detectHiddenAngle(conversationContext || {}, scenarioId);
  const cifras = _buildHiddenAngleCifras(angle.reveal, scenarioId);
  if (!cifras) return null; // scenario no soporta el angle · composer hará honest fallback
  return {
    kind: "executive_opportunity",
    scenario: scenarioId,
    context_seen: {
      label: angle.context_seen_label,
      last_intent: conversationContext?.lastIntent || null,
      last_module: conversationContext?.lastModuleAsked || null,
      investigation_metric: conversationContext?.investigationMetric || null,
      turn_count: conversationContext?.turnCount || 0,
    },
    hidden_angle: {
      rule: angle.rule,
      reveal: angle.reveal,
      ...cifras,
    },
    reframe_key: angle.reframe_key,
  };
}

// composeHiddenOpportunityNarrative · postura recommend · provocación
function composeHiddenOpportunityNarrative(signals, posture, ctx) {
  if (!signals || signals.kind !== "executive_opportunity") return null;
  if (!signals.hidden_angle) return null; // defensive · signals incompletos
  const ang = signals.hidden_angle;
  const seenLabel = signals.context_seen?.label;
  const movements = [];

  // ── APERTURA · "Estás mirando X · pero hay un ángulo que no aparece..." ──
  // Si ctx vacío (regla 5) · apertura sin "estás mirando X" (no hay X que mirar)
  let opener;
  if (ang.rule === "default_ctx_empty" || !seenLabel) {
    opener = `Hay un ángulo del negocio que no aparece naturalmente en las consultas obvias: ${_hiddenAngleNoun(ang.dimension)}.`;
  } else {
    opener = `Estás mirando ${seenLabel} · pero hay un ángulo que no aparece en tus consultas: ${_hiddenAngleNoun(ang.dimension)}.`;
  }
  movements.push(opener);

  // ── MOVIMIENTO 2 · Cifra contrastante ──
  let cifraBlock = null;
  if (ang.reveal === "quality_growth_deterioration") {
    cifraBlock = `${ang.instances_count} cuentas crecen entre +${ang.growth_min}% y +${ang.growth_max}% YoY · suena bien · pero capturan ese crecimiento a costa de margen unitario. Son $${ang.cifra_M}M de contribución que se pierde frente al benchmark · más que cualquier driver comercial individual.`;
  } else if (ang.reveal === "customer_dependency_risk") {
    const names = ang.top3_names.join(" · ");
    cifraBlock = `${names} concentran ${ang.concentration_pct}% del negocio y $${ang.exposed_M}M de contribución expuesta. Una salida simultánea de los 3 borra cerca de la mitad de la rentabilidad operativa.`;
  } else if (ang.reveal === "sku_operational") {
    const skuList = ang.sku_names.length === 1
      ? ang.sku_names[0]
      : ang.sku_names.slice(0, -1).join(" · ") + " y " + ang.sku_names[ang.sku_names.length - 1];
    cifraBlock = `${ang.instances_count === 1 ? "1 SKU concentra" : ang.instances_count + " SKUs concentran"} $${ang.capital_K}K de stock con DOH promedio ${ang.avg_doh} días: ${skuList}. Capital que no rota · que podría reinvertirse en SKUs rotacionales.`;
  } else if (ang.reveal === "commercial_erosion") {
    cifraBlock = `${ang.instances_count} cuentas operan con carga comercial sobre el promedio interno · $${ang.recuperable_K}K anuales recuperables al promedio · $${(ang.recuperable_BP_M * 1000).toFixed(0)}K si baja a mejor práctica (3.0%). Es la palanca operativa de mayor impacto · NO se ve mirando solo inventario.`;
  }
  if (cifraBlock) movements.push(cifraBlock);

  // ── MOVIMIENTO 3 · Provocación específica del reframe ──
  // hidden_blind_spot (R1+R5) ya es la provocación contextual.
  // Para R2/R3/R4 · agregamos provocación inline antes del reframe del catálogo.
  let provocationBlock = null;
  if (ang.reveal === "customer_dependency_risk") {
    provocationBlock = `La performance individual de cada cliente la estás viendo. La dependencia que generan en conjunto · no.`;
  } else if (ang.reveal === "sku_operational") {
    provocationBlock = `Los rankings comerciales los estás viendo. El capital atrapado en inventario · no.`;
  } else if (ang.reveal === "commercial_erosion") {
    provocationBlock = `La rotación operativa la estás viendo. La carga comercial que erosiona margen en clientes grandes · no.`;
  }
  if (provocationBlock) movements.push(provocationBlock);

  // ── MOVIMIENTO 4 · Reframe del catálogo (firmado founder D-N.B.2-3) ──
  const reframe = EXECUTIVE_REFRAMES[signals.reframe_key];
  if (reframe) movements.push(reframe);

  // ── CIERRE · "Esa es la oportunidad ignorada" si aplica ──
  // Solo cuando el reframe NO cierra naturalmente (R2/R3/R4 reframes M.A son
  // más densos · cierre adicional refuerza el punto). Para R1/R5 con
  // hidden_blind_spot el reframe YA es la provocación final · NO duplicar.
  if (signals.reframe_key !== "hidden_blind_spot") {
    movements.push("Esa es la oportunidad ignorada.");
  }

  return movements.join("\n\n");
}

// Helper léxico · dimension key → noun ejecutivo en español
function _hiddenAngleNoun(dimensionKey) {
  const map = {
    "calidad_crecimiento":           "calidad de crecimiento",
    "concentración_estructural":     "concentración estructural en Tier 1",
    "capital_operacional_atrapado":  "capital operacional atrapado",
    "erosión_comercial":             "erosión comercial sobre clientes grandes",
  };
  return map[dimensionKey] || dimensionKey;
}

// composeHiddenOpportunity · COMPOSER REAL (reemplaza placeholder N.A)
function composeHiddenOpportunity(scenario, conversationContext, modulo) {
  let signals = null;
  try {
    signals = buildNarrativeSignalsForHiddenOpportunity(scenario, conversationContext, modulo);
  } catch (e) {
    // eslint-disable-next-line no-console
    console.warn("BRIEF N.B.2 signals build error:", e);
    signals = null;
  }

  if (!signals) {
    return {
      opener: "No tengo evidencia determinística suficiente para revelar un ángulo no mirado con el escenario actual.",
      suggestions: [],
      sentrixAction: null,
      derivedIntentType: "executive_intent",
      reasoningPattern: "executive_opportunity_unavailable",
      // SIN narrative_signals · skip narrative_layer
    };
  }

  const ang = signals.hidden_angle;
  const openerLegacy = `Ángulo no cubierto detectado: ${_hiddenAngleNoun(ang.dimension)} (regla ${ang.rule}).`;

  return {
    opener: openerLegacy,
    suggestions: [],
    sentrixAction: null,
    derivedIntentType: "executive_intent",
    reasoningPattern: "executive_opportunity",
    narrative_signals: signals,
    posture_hint: "recommend",
  };
}

// ── BRIEF N.B.3 · helpers executive concern ────────────────────────────────
// Top 2 concerns priorizados por umbrales matemáticos (D-N.B.3-2 firmado).
//
// Reglas selección concern 1 (urgente/medio plazo):
//   · Si commercial_erosion.pct_of_total_contribution >= 5% → erosion
//   · Sino si quality_of_growth_deterioration.contribucion_perdida_M >= 2.0 → quality
//   · Sino si quality_of_growth.contribucion_perdida_M >= 0.5 → quality (umbral más bajo)
//   · Sino default → quality (siempre presente con instances_count >= 1)
//
// Concern 2 (estructural · D-N.B.3-3): siempre customer_dependency_risk si triggered.
// Coherente porque está activa en bonanza/tensión/crisis (los 3 escenarios demo).
//
// Horizon labels (D-N.B.3-4):
//   inmediato → "corto plazo"
//   medio     → "mediano plazo"
//   largo     → "estructural"
const _CONCERN_HORIZON_LABEL = {
  inmediato: "corto plazo",
  medio:     "mediano plazo",
  largo:     "estructural",
};

// Helper · mapeo horizon → frase "horizonte de X" para cierre narrativo
const _CONCERN_HORIZON_PHRASE = {
  inmediato: "meses",
  medio:     "trimestres",
  largo:     "años",
};

function _detectExecutiveConcerns(scenarioId) {
  let scan;
  try {
    scan = scanMechanisms(scenarioId);
  } catch (e) {
    return [];
  }
  if (!scan) return [];

  const concerns = [];

  // ── CANDIDATO 1 · commercial_erosion · alta urgencia si pct_contrib alta ──
  const ce = scan.commercial_erosion;
  if (ce?.triggered && ce.aggregate) {
    const pctContrib = ce.aggregate.pct_of_total_contribution || 0;
    // Score severity: usa pct_of_total_contribution (cuánto del margen total sufre)
    concerns.push({
      mechanism: "commercial_erosion",
      horizon: MECHANISM_NARRATIVE_RULES.commercial_erosion?.horizon || "inmediato",
      severity_score: pctContrib,
      severity_threshold_hit: pctContrib >= 5.0,
      cifras: {
        recuperable_K: ce.aggregate.recuperable_total_K,
        recuperable_BP_M: ce.aggregate.recuperable_total_M_at_3_0,
        instances_count: ce.aggregate.instances_count,
        pct_of_total_contribution: pctContrib,
      },
      reframe_key: "internal_commercial_load",
    });
  }

  // ── CANDIDATO 2 · quality_of_growth_deterioration ──
  const qog = scan.quality_of_growth_deterioration;
  if (qog?.triggered && qog.aggregate) {
    const contribM = qog.aggregate.contribucion_perdida_M || 0;
    concerns.push({
      mechanism: "quality_of_growth_deterioration",
      horizon: MECHANISM_NARRATIVE_RULES.quality_of_growth_deterioration?.horizon || "medio",
      severity_score: contribM,
      severity_threshold_hit: contribM >= 2.0,
      cifras: {
        contribucion_perdida_M: contribM,
        instances_count: qog.aggregate.instances_count,
        growth_min: qog.aggregate.crecimiento_range?.min,
        growth_max: qog.aggregate.crecimiento_range?.max,
      },
      reframe_key: "quality_growth_derived",
    });
  }

  // ── CANDIDATO 3 · customer_dependency_risk (siempre concern 2 si triggered) ──
  const cdr = scan.customer_dependency_risk;
  if (cdr?.triggered && cdr.aggregate) {
    concerns.push({
      mechanism: "customer_dependency_risk",
      horizon: MECHANISM_NARRATIVE_RULES.customer_dependency_risk?.horizon || "largo",
      severity_score: cdr.aggregate.top3_participacion_pct || 0,
      severity_threshold_hit: (cdr.aggregate.top3_participacion_pct || 0) >= 50,
      cifras: {
        top3_names: cdr.aggregate.top3_names || [],
        concentration_pct: cdr.aggregate.top3_participacion_pct,
        exposed_M: cdr.aggregate.top3_contribucion_M,
      },
      reframe_key: "structural_dependency",
    });
  }

  if (concerns.length === 0) return [];

  // ── Selección concern 1 (urgente/medio plazo) según umbrales D-N.B.3-2 ──
  let concern1 = null;
  // Prioridad 1: erosion alta (pct_contribución ≥5%)
  const erosionConcern = concerns.find(c => c.mechanism === "commercial_erosion" && c.severity_threshold_hit);
  if (erosionConcern) {
    concern1 = erosionConcern;
  } else {
    // Prioridad 2: quality_of_growth significativo (≥2M)
    const qogConcern = concerns.find(c => c.mechanism === "quality_of_growth_deterioration" && c.severity_threshold_hit);
    if (qogConcern) {
      concern1 = qogConcern;
    } else {
      // Prioridad 3: quality bajo umbral · usar si severity ≥ 0.5
      const qogMedium = concerns.find(c => c.mechanism === "quality_of_growth_deterioration" && c.severity_score >= 0.5);
      if (qogMedium) {
        concern1 = qogMedium;
      } else {
        // Último recurso: cualquier no-customer_dependency
        concern1 = concerns.find(c => c.mechanism !== "customer_dependency_risk") || null;
      }
    }
  }

  // ── Selección concern 2 (estructural · D-N.B.3-3) ──
  // Customer_dependency si triggered · NO duplicar con concern1
  let concern2 = null;
  if (concern1?.mechanism !== "customer_dependency_risk") {
    concern2 = concerns.find(c => c.mechanism === "customer_dependency_risk") || null;
  } else {
    // edge case · concern1 ya es customer_dependency (no debería suceder con scoring actual)
    concern2 = concerns.find(c => c.mechanism !== "customer_dependency_risk") || null;
  }

  // Retornar top 2 (rank 1 = urgente · rank 2 = estructural)
  const result = [];
  if (concern1) result.push({ ...concern1, rank: 1 });
  if (concern2) result.push({ ...concern2, rank: 2 });
  return result;
}

// buildNarrativeSignalsForExecutiveConcern · kind=executive_concern
function buildNarrativeSignalsForExecutiveConcern(scenarioId, conversationContext, modulo) {
  const concerns = _detectExecutiveConcerns(scenarioId);
  if (!concerns || concerns.length === 0) return null;
  return {
    kind: "executive_concern",
    scenario: scenarioId,
    concerns,
  };
}

// _renderConcernBody · template body por mecanismo (D-N.B.3-1: reframes M.A/M.B.2 reutilizados)
// La frase "deuda silenciosa" va EMBEDIDA en el body de customer_dependency · NO reframe nuevo.
function _renderConcernBody(concern) {
  const c = concern.cifras;
  if (concern.mechanism === "commercial_erosion") {
    const bp_K = Math.round((c.recuperable_BP_M || 0) * 1000);
    return `${c.instances_count} cuentas operan con carga comercial sobre el promedio interno · $${c.recuperable_K}K anuales recuperables al promedio · $${bp_K}K si baja a mejor práctica (3.0%). Es la palanca operativa de mayor impacto · cuanto más se sostiene · más naturaliza el cliente el descuento.`;
  }
  if (concern.mechanism === "quality_of_growth_deterioration") {
    const isSingleton = c.instances_count === 1;
    const rangeStr = c.growth_min === c.growth_max
      ? `+${c.growth_min}% YoY`
      : `entre +${c.growth_min}% y +${c.growth_max}% YoY`;
    const cuentasStr = isSingleton ? "1 cuenta crece" : `${c.instances_count} cuentas crecen`;
    return `${cuentasStr} ${rangeStr} · pero capturando ese crecimiento a costa de margen unitario. Son $${c.contribucion_perdida_M}M de contribución que se pierde frente al benchmark. Es el patrón clásico de "vende más · gana menos" · que se vuelve irreversible cuando el cliente naturaliza el descuento.`;
  }
  if (concern.mechanism === "customer_dependency_risk") {
    const names = (c.top3_names || []).join(" · ");
    // "Deuda silenciosa" embedida en el template body (D-N.B.3-1)
    return `${names} concentran ${c.concentration_pct}% del negocio y $${c.exposed_M}M de contribución expuesta. Una salida simultánea de los 3 borra cerca de la mitad de la rentabilidad operativa. No es plausible mañana · pero no tener un plan de Tier 2 ya activo es la deuda silenciosa: no se siente hasta que vence.`;
  }
  return null;
}

// composeExecutiveConcernNarrative · postura recommend · dimensión temporal
function composeExecutiveConcernNarrative(signals, posture, ctx) {
  if (!signals || signals.kind !== "executive_concern") return null;
  if (!Array.isArray(signals.concerns) || signals.concerns.length === 0) return null;

  const concerns = signals.concerns;
  const movements = [];

  // ── APERTURA · primera persona ejecutiva ──
  const opener = concerns.length === 1
    ? "Si esta fuera mi empresa · me preocuparía una cosa."
    : `Si esta fuera mi empresa · me preocuparían ${concerns.length === 2 ? "dos" : concerns.length} cosas.`;
  movements.push(opener);

  // ── MOVIMIENTO 2 · cada concern con dimensión temporal + body + reframe ──
  const ordinals = ["Lo primero", "Lo segundo"];
  for (let i = 0; i < concerns.length; i++) {
    const concern = concerns[i];
    const ordinal = ordinals[i] || `Lo ${i + 1}°`;
    const horizonLabel = _CONCERN_HORIZON_LABEL[concern.horizon] || concern.horizon;
    const body = _renderConcernBody(concern);
    const reframe = EXECUTIVE_REFRAMES[concern.reframe_key];
    // Estructura: "Lo primero es [horizon]: [body]. [reframe]"
    let block = `${ordinal} es ${horizonLabel}: ${body}`;
    if (reframe) block += `\n\n${reframe}`;
    movements.push(block);
  }

  // ── CIERRE · primera persona ejecutiva con dimensión temporal explícita ──
  if (concerns.length === 2) {
    const phrase1 = _CONCERN_HORIZON_PHRASE[concerns[0].horizon] || concerns[0].horizon;
    const phrase2 = _CONCERN_HORIZON_PHRASE[concerns[1].horizon] || concerns[1].horizon;
    movements.push(`Yo vigilaría esos dos frentes · uno en horizonte de ${phrase1} · el otro en horizonte de ${phrase2}.`);
  } else if (concerns.length === 1) {
    const phrase1 = _CONCERN_HORIZON_PHRASE[concerns[0].horizon] || concerns[0].horizon;
    movements.push(`Yo vigilaría ese frente · horizonte de ${phrase1}.`);
  }

  return movements.join("\n\n");
}

// composeExecutiveConcern · COMPOSER REAL (reemplaza placeholder N.A)
function composeExecutiveConcern(scenario, conversationContext, modulo) {
  let signals = null;
  try {
    signals = buildNarrativeSignalsForExecutiveConcern(scenario, conversationContext, modulo);
  } catch (e) {
    // eslint-disable-next-line no-console
    console.warn("BRIEF N.B.3 signals build error:", e);
    signals = null;
  }

  if (!signals) {
    return {
      opener: "No tengo evidencia determinística suficiente para identificar riesgos estructurales con el escenario actual.",
      suggestions: [],
      sentrixAction: null,
      derivedIntentType: "executive_intent",
      reasoningPattern: "executive_concern_unavailable",
      // SIN narrative_signals · skip narrative_layer
    };
  }

  const mechs = signals.concerns.map(c => c.mechanism).join(" + ");
  const openerLegacy = `Concerns priorizados para el escenario ${scenario}: ${mechs}.`;

  return {
    opener: openerLegacy,
    suggestions: [],
    sentrixAction: null,
    derivedIntentType: "executive_intent",
    reasoningPattern: "executive_concern",
    narrative_signals: signals,
    posture_hint: "recommend",
  };
}

