// FIN BRIEF N.A · Infraestructura compartida
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #25-ter · Detectores de acciones cognitivas escritas en texto libre
//
// El usuario puede ESCRIBIR la acción equivalente a clickear una suggestion
// del SGE. Cada detector identifica patterns lingüísticos + resuelve la
// entidad implícita desde conversationContext (memoria conversacional).
//
// Si el detector matchea Y la entidad está en memoria → retorna action.
// Si matchea pero entidad NO está en memoria → retorna null (fallback al
// flujo siguiente, no crashea).
//
// Las acciones detectadas se rutean al MISMO composer que usa el click en
// suggestion del SGE (BRIEF #25-bis) · cero duplicación, cero hardcoding.
// ════════════════════════════════════════════════════════════════════════════

// ── 1. EXIT PLAN ──
// "plan de salida", "cómo lo liquido", "qué hago con esto"
function detectExitPlanAction(text, context) {
  const t = text.toLowerCase();
  const matches = (
    t.includes("plan de salida") ||
    t.includes("plan de liquidacion") ||
    t.includes("plan de liquidación") ||
    t.includes("como lo liquido") ||
    t.includes("cómo lo liquido") ||
    t.includes("como liquido") ||
    t.includes("cómo liquido") ||
    t.includes("que hago con esto") ||
    t.includes("qué hago con esto") ||
    t.includes("que hago con este sku") ||
    t.includes("qué hago con este sku") ||
    t.includes("como saco este stock") ||
    t.includes("cómo saco este stock") ||
    t.includes("como me deshago") ||
    t.includes("cómo me deshago") ||
    t.includes("estrategia de salida") ||
    t.includes("salida del sku")
  );
  if (!matches) return null;

  // Resolver entidad desde memoria · necesitamos un SKU
  const sku = context?.lastSkuMentioned;
  if (!sku) return null;

  return {
    type: "exit_plan",
    payload: { sku },
  };
}

// ── 2. CONTINUE PENDING ──
// "y los otros", "sigamos con los demás", "el resto", "los pendientes"
function detectContinuePendingAction(text, context) {
  const t = text.toLowerCase().trim();
  const matches = (
    t.includes("y los otros") ||
    t.includes("sigamos con los demas") ||
    t.includes("sigamos con los demás") ||
    t.includes("sigamos con el resto") ||
    t.includes("y el resto") ||
    (t.includes("el resto") && t.length < 30) ||
    t.includes("los pendientes") ||
    t.includes("y los pendientes") ||
    t.includes("los demas") ||
    t.includes("los demás") ||
    t.includes("continuemos con los demas") ||
    t.includes("continuemos con los demás") ||
    (t.includes("sigamos") && t.length < 20) ||
    t.includes("que pasa con los otros") ||
    t.includes("qué pasa con los otros")
  );
  if (!matches) return null;

  // Necesitamos lista padre con elementos pendientes
  const hasSkuList = context?.lastSkuList?.length > 0;
  const hasClientList = context?.lastClientList?.length > 0;
  if (!hasSkuList && !hasClientList) return null;

  // Heurística de tipo: si hay ambas listas, prioridad por lastIntent
  // (que indica qué exploración estábamos haciendo).
  const lastIntent = context?.lastIntent || "";
  const intentSuggestsClient = lastIntent === "cross_domain_query"
                              || lastIntent === "client"
                              || lastIntent === "client_followup"
                              || lastIntent === "cross_domain_sku_to_client";
  const useClientList = hasClientList && (intentSuggestsClient || !hasSkuList);

  if (useClientList) {
    const seen = context.lastClientMentioned;
    const pending = context.lastClientList.filter(c => c !== seen);
    if (pending.length === 0) return null;
    return {
      type: "continue_pending",
      payload: {
        entityType: "client",
        entities: pending,
        sourceIntent: context.lastIntent || "mechanism_explore_erosion",
      },
    };
  } else {
    const seen = context.lastSkuMentioned;
    const pending = context.lastSkuList.filter(s => s !== seen);
    if (pending.length === 0) return null;
    return {
      type: "continue_pending",
      payload: {
        entityType: "sku",
        entities: pending,
        sourceIntent: context.lastIntent || "sku_operational",
      },
    };
  }
}

// ── 3. CROSS-DOMAIN SKU → CLIENT ──
// "qué clientes lo compran", "quién lo compra", "dónde se vende"
function detectSkuToClientAction(text, context) {
  const t = text.toLowerCase();
  const matches = (
    t.includes("que clientes lo compran") ||
    t.includes("qué clientes lo compran") ||
    t.includes("quien lo compra") ||
    t.includes("quién lo compra") ||
    t.includes("donde se vende") ||
    t.includes("dónde se vende") ||
    t.includes("quien compra esto") ||
    t.includes("quién compra esto") ||
    t.includes("que clientes lo tienen") ||
    t.includes("qué clientes lo tienen") ||
    t.includes("en que cuentas pesa") ||
    t.includes("en qué cuentas pesa") ||
    t.includes("a quien le vendo") ||
    t.includes("a quién le vendo")
  );
  if (!matches) return null;

  const sku = context?.lastSkuMentioned;
  if (!sku) return null;

  return {
    type: "cross_domain_sku_to_client",
    payload: { skuName: sku },
  };
}

// ── 4. CROSS-DOMAIN CLIENT → SKU ──
// "qué le vendo", "qué SKUs le pesan", "qué productos explican"
function detectClientToSkuAction(text, context) {
  const t = text.toLowerCase();
  const matches = (
    t.includes("que le vendo") ||
    t.includes("qué le vendo") ||
    t.includes("que skus le pesan") ||
    t.includes("qué skus le pesan") ||
    t.includes("que productos explican") ||
    t.includes("qué productos explican") ||
    t.includes("que productos aportan") ||
    t.includes("qué productos aportan") ||
    t.includes("que productos pesan") ||
    t.includes("qué productos pesan") ||
    t.includes("que skus aportan") ||
    t.includes("qué skus aportan") ||
    t.includes("que productos vende") ||
    t.includes("qué productos vende") ||
    t.includes("que skus tiene") ||
    t.includes("qué skus tiene")
  );
  if (!matches) return null;

  const client = context?.lastClientMentioned;
  if (!client) return null;

  return {
    type: "cross_domain_client_to_sku",
    payload: { clientName: client },
  };
}

// ── 5. COMPARE OPPOSITE ──
// "comparar con los buenos", "y los virtuosos", "contra los mejores"
function detectCompareOppositeAction(text, context) {
  const t = text.toLowerCase();
  const matches = (
    t.includes("comparar con los buenos") ||
    t.includes("y los virtuosos") ||
    t.includes("contra los mejores") ||
    t.includes("contra los virtuosos") ||
    t.includes("vs los virtuosos") ||
    t.includes("vs los buenos") ||
    t.includes("y los rotacionales") ||
    t.includes("contra los rotacionales") ||
    t.includes("los buenos del portafolio") ||
    t.includes("contra los que rotan") ||
    t.includes("mejores cuentas") ||
    t.includes("cuentas virtuosas") ||
    t.includes("skus virtuosos") ||
    t.includes("skus rotacionales") ||
    t.includes("comparar contra")
  );
  if (!matches) return null;

  // Determinar domain según contexto conversacional
  const lastIntent = context?.lastIntent || "";

  let domain, pattern;

  if (lastIntent.includes("client")
      || lastIntent === "cross_domain_query"
      || lastIntent === "mechanism_explore_erosion"
      || lastIntent === "mechanism_explore_quality"
      || (context?.lastClientMentioned && !context?.lastSkuMentioned)) {
    domain = "client";
    pattern = "virtuoso";
  } else if (lastIntent === "product_contribution") {
    domain = "sku";
    pattern = (t.includes("rotacional") || t.includes("rotan")) ? "rotacional" : "bottom_contrib";
  } else {
    // Default · si hay SKU en memoria, sku rotacional; si hay cliente, virtuoso
    domain = context?.lastSkuMentioned ? "sku" : "client";
    pattern = domain === "sku" ? "rotacional" : "virtuoso";
  }

  return {
    type: "compare_opposite",
    payload: { domain, pattern },
  };
}

// ── 6. SIMULATION (4 sub-tipos según métrica detectada) ──
function detectSimulationAction(text, context) {
  const t = text.toLowerCase();

  // Sub-tipo 6.a · load_reduction · "bajo carga", "reducir rebate"
  // BRIEF #26-bis · patterns ampliados para frases naturales de
  // compensación/concesión/renegociación que también deben rutear a
  // simulation_load_reduction sobre el último cliente mencionado.
  const isLoadReduction = (
    // Patterns originales
    ((t.includes("baj") || t.includes("reduc"))
     && (t.includes("carga") || t.includes("rebate")))
    // BRIEF #26-bis · simulación de compensación/concesión
    || (t.includes("ofrezco algo a cambio") && t.includes("rebate"))
    || (t.includes("ofrecer algo a cambio") && t.includes("rebate"))
    || (t.includes("ofrezco algo") && t.includes("cambio"))
    || t.includes("que le puedo dar a cambio")
    || t.includes("qué le puedo dar a cambio")
    || t.includes("que le doy a cambio")
    || t.includes("qué le doy a cambio")
    || (t.includes("compensar") && (t.includes("rebate") || t.includes("carga")))
    || (t.includes("compenso") && (t.includes("rebate") || t.includes("carga")))
    || (t.includes("compensa") && (t.includes("rebate") || t.includes("carga")))
    || t.includes("si le compenso")
    || t.includes("si renegocio")
    || t.includes("renegociar el rebate")
    || t.includes("renegociar la carga")
    || t.includes("si le doy mas volumen")
    || t.includes("si le doy más volumen")
    || t.includes("a cambio de bajar")
    || t.includes("y si bajo")
  );

  if (isLoadReduction) {
    const client = context?.lastClientMentioned;
    if (!client) return null;
    return {
      type: "simulation_load_reduction",
      payload: { entity: client, targetCarga: 3.5 },
    };
  }

  // Sub-tipo 6.b · rotation · "rotara más", "cuánto libero si rota"
  if (t.includes("rotar") || t.includes("rotación") || t.includes("rotacion")) {
    if (t.includes("si ") || t.includes("cuanto libero") || t.includes("cuánto libero")
        || t.includes("que pasa si") || t.includes("qué pasa si")
        || t.includes("alcanza") || t.includes("alcanzara") || t.includes("alcanzará")) {
      const sku = context?.lastSkuMentioned;
      if (!sku) return null;
      return {
        type: "simulation_rotation",
        payload: { sku, targetRotation: 9 },
      };
    }
  }

  // Sub-tipo 6.c · benchmark · "iguala el benchmark de margen"
  if ((t.includes("igualo") || t.includes("igualar") || t.includes("alcanza"))
      && (t.includes("benchmark") || t.includes("margen"))) {
    const client = context?.lastClientMentioned;
    const sku = context?.lastSkuMentioned;
    if (!client && !sku) return null;
    return {
      type: "simulation_benchmark",
      payload: {
        entity: client || sku,
        entityType: client ? "client" : "sku",
        metric: "margen",
        target: 30.1,
      },
    };
  }

  // Sub-tipo 6.d · contribución · "cierro el gap", "subir contribución"
  if (t.includes("cierro el gap") || t.includes("cierra el gap")
      || t.includes("subir contribucion") || t.includes("subir contribución")) {
    const client = context?.lastClientMentioned;
    const sku = context?.lastSkuMentioned;
    if (!client && !sku) return null;
    return {
      type: "simulation_contribution",
      payload: {
        entity: client || sku,
        entityType: client ? "client" : "sku",
        gap: 8,
      },
    };
  }

  return null;
}

// ── 7. CROSS-MODULE VIEW ──
// "y en márgenes", "cómo se ve en ventas", "qué pasa en inventario"
function detectCrossModuleViewAction(text, context) {
  const t = text.toLowerCase().trim();

  // Detectar módulo target
  let targetModule = null;
  if (t.includes("en margenes") || t.includes("en márgenes")
      || t.includes("en margen") || t.includes("desde margenes")
      || t.includes("desde márgenes")) {
    targetModule = "margenes";
  } else if (t.includes("en ventas") || t.includes("desde ventas")) {
    targetModule = "ventas";
  } else if (t.includes("en inventario") || t.includes("desde inventario")) {
    targetModule = "inventario";
  }

  if (!targetModule) return null;

  // Detectar intención de "ver en otro módulo"
  const isViewAction = (
    t.startsWith("y en ")
    || t.startsWith("como se ve")
    || t.startsWith("cómo se ve")
    || t.startsWith("que pasa en")
    || t.startsWith("qué pasa en")
    || t.startsWith("ahora en ")
    || t.includes("ver en " + targetModule)
    || t.includes("vamos a " + targetModule)
  );

  if (!isViewAction) return null;

  // Resolver entidad desde memoria · prioridad cliente sobre SKU
  // (la vista cross-module es más típicamente sobre cuentas)
  const client = context?.lastClientMentioned;
  const sku = context?.lastSkuMentioned;

  if (!client && !sku) return null;

  const entity = client || sku;
  const entityType = client ? "client" : "sku";

  return {
    type: "cross_module_view",
    payload: { entity, entityType, targetModule },
  };
}

// ── DETECTOR MAESTRO ──
// Evalúa los 7 detectores en orden de especificidad.
// Retorna la primera acción que matchea, o null si ninguno aplica.
//
// Orden de prioridad:
//   1. exit_plan (muy específico · pattern "plan de salida")
//   2. continue_pending (requiere lista padre)
//   3. cross_domain_sku_to_client (específico de SKU)
//   4. cross_domain_client_to_sku (específico de cliente)
//   5. compare_opposite (comparación · más amplio)
//   6. simulation (sub-tipos heterogéneos)
//   7. cross_module_view (cambio de módulo · más amplio aún)
function detectCognitiveAction(text, context) {
  return (
    detectExitPlanAction(text, context)
    || detectContinuePendingAction(text, context)
    || detectSkuToClientAction(text, context)
    || detectClientToSkuAction(text, context)
    || detectCompareOppositeAction(text, context)
    || detectSimulationAction(text, context)
    || detectCrossModuleViewAction(text, context)
    || null
  );
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #26-quater · Detector de intención de validación conversacional
//
// Identifica si la pregunta del usuario tiene tono de:
//   · validación de hipótesis ("¿es real?", "¿son ideas mías?")
//   · decisión binaria ("¿vale la pena?", "¿le doy?")
//   · imperativo de acción ("¿qué hago?", "¿qué priorizo?")
//
// Retorna {type} o null. NO resuelve entidad · eso lo hace el composer que
// produce el análisis. Función pura · determinismo bitwise.
// ════════════════════════════════════════════════════════════════════════════
function detectValidationIntent(text) {
  if (!text) return null;
  const t = text.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

  // TIPO 1 · VALIDATION_REAL · "¿es real?", "¿son ideas mías?"
  const isReal = (
    t.includes("es real")
    || t.includes("son ideas mias")
    || t.includes("son ideas mías")
    || t.includes("estoy viendo mal")
    || t.includes("es asi")
    || t.includes("es cierto")
    || t.includes("no me estoy equivocando")
    || t.includes("me estoy equivocando")
    || t.includes("es percepcion")
    || t.includes("es percepción")
    || t.includes("lo veo bien")
    || t.includes("lo estoy viendo bien")
    || t.includes("es verdad")
    || t.includes("es asi como lo veo")
    || t.includes("realmente esta pasando")
    || t.includes("realmente está pasando")
  );
  if (isReal) return { type: "validation_real" };

  // TIPO 2 · VALIDATION_DECISION · "¿vale la pena?", "¿conviene?"
  const isDecision = (
    t.includes("vale la pena")
    || t.includes("conviene")
    || t.includes("le doy o no")
    || t.includes("voy o no voy")
    || t.includes("lo hago o no")
    || t.includes("es buena decision")
    || t.includes("es buena decisión")
    || t.includes("me sirve")
    || t.includes("vale el esfuerzo")
    || t.includes("debo hacerlo")
    || t.includes("deberia hacerlo")
    || t.includes("debería hacerlo")
    || t.includes("tiene sentido")
  );
  if (isDecision) return { type: "validation_decision" };

  // TIPO 3 · VALIDATION_IMPERATIVE · "¿qué hago?", "¿por dónde empiezo?"
  const isImperative = (
    t.includes("que hago")
    || t.includes("qué hago")
    || t.includes("que priorizo")
    || t.includes("qué priorizo")
    || t.includes("por donde empiezo")
    || t.includes("por dónde empiezo")
    || t.includes("por donde arranco")
    || t.includes("por dónde arranco")
    || t.includes("que soltar")
    || t.includes("qué soltar")
    || t.includes("que proteger")
    || t.includes("qué proteger")
    || t.includes("que decision tomar")
    || t.includes("qué decisión tomar")
    || t.includes("que decido")
    || t.includes("qué decido")
    || t.includes("donde pongo foco")
    || t.includes("dónde pongo foco")
  );
  if (isImperative) return { type: "validation_imperative" };

  return null;
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #26-quater · Generador de opener de validación
//
// Construye la frase corta inicial que valida la intuición del usuario,
// derivada del cognitive state ya producido por el composer Ferrari/cognitivo.
//
// Este wrapper NO reemplaza el análisis del composer · lo complementa al
// inicio. El usuario ve: [validation opener] + [análisis técnico del composer].
//
// CERO HARDCODING NUMÉRICO: las frases son semánticas (afirmar/negar/priorizar),
// no contienen cifras fijas. La decisión binaria viene del anomaly/benchmark
// del cognitive state · cambiar el dataset cambia la decisión.
// ════════════════════════════════════════════════════════════════════════════
function buildValidationOpener(validationType, cognitiveState, intentType, scenarioId) {
  const entity = cognitiveState?.primaryEntity?.value;
  const anomalyType = cognitiveState?.anomaly?.type;
  const anomalySeverity = cognitiveState?.anomaly?.severity;
  const benchmarkGap = cognitiveState?.benchmark?.gap;

  // ── TIPO 1 · VALIDATION_REAL ──
  if (validationType === "validation_real") {
    const isAnomalyHigh = anomalySeverity === "high" || anomalySeverity === "medium";
    const isAnomalyAbsent = !anomalyType || anomalyType === "virtuoso" || anomalySeverity === "low";

    if (isAnomalyHigh && entity) {
      return `Sí · es real. ${entity} muestra patrón sostenido, no oscilación puntual.`;
    } else if (isAnomalyHigh && !entity) {
      return `Sí · es real. El patrón se sostiene en la cartera, no es ruido del trimestre.`;
    } else if (isAnomalyAbsent && entity) {
      return `No · son percepciones. ${entity} opera dentro de rango razonable del portafolio.`;
    } else if (isAnomalyAbsent) {
      return `No · el negocio opera dentro de rango razonable. No hay deterioro estructural.`;
    } else {
      return `Hay señales reales, pero la materialidad no es la principal del trimestre.`;
    }
  }

  // ── TIPO 2 · VALIDATION_DECISION ──
  if (validationType === "validation_decision") {
    const hasMaterialGap = benchmarkGap && benchmarkGap >= 1.0;

    if (hasMaterialGap && entity) {
      return `Sí · vale la pena. El gap es material y ${entity} tiene controlabilidad operativa directa.`;
    } else if (hasMaterialGap) {
      return `Sí · vale la pena. El gap es material y controlable desde decisión comercial.`;
    } else if (entity) {
      return `${entity} opera cerca de benchmark. La decisión depende más de horizonte que de impacto financiero inmediato.`;
    } else {
      return `El impacto cuantitativo es bajo. La decisión es estratégica, no financiera.`;
    }
  }

  // ── TIPO 3 · VALIDATION_IMPERATIVE ──
  if (validationType === "validation_imperative") {
    if (entity && intentType === "sku_operational") {
      return `Empezá por ${entity} · es la mayor exposición operativa del grupo.`;
    } else if (entity && (intentType === "mechanism_explore_erosion" || intentType === "cross_domain_query")) {
      return `Priorizá ${entity} · mayor materialidad + mayor controlabilidad operativa.`;
    } else if (entity && intentType === "exit_plan") {
      return `Soltá ${entity}. Capital atrapado vs cash recuperado · favorece cash.`;
    } else if (entity && intentType === "product_contribution") {
      return `Protegé ${entity} · es palanca estructural de rentabilidad.`;
    } else if (intentType === "sku_operational") {
      return `Empezá por el SKU con mayor combinación DOH × días sin venta. Ese es tu vector principal.`;
    } else if (intentType === "mechanism_explore_erosion") {
      return `Priorizá la cuenta con mayor materialidad sobre la carga. Esa es la palanca real.`;
    } else if (intentType === "growth_opportunity") {
      return `Empujá donde el margen ya es sano y la carga es baja. Ese es el upside real.`;
    } else if (intentType === "product_dual_comparison") {
      return `Protegé el virtuoso · decidí sobre el lastre. Esa es la dualidad operativa.`;
    } else if (intentType === "executive_intent") {
      // MAT-VOZ-OPENER2 · teaser premium FIJO de priorización (Ruta A · executive_action).
      // else-if específico (no se reemplaza el else: es catch-all de otros imperativos sin entity).
      // La inteligencia adaptativa vive en la lectura ejecutiva del narrative (no se toca).
      // EXEC-COMPRESSION · la tesis de negocio (sin cifras) reemplaza el teaser · fallback si null.
      const _thesis = composeBusinessThesisOpener(scenarioId);
      return _thesis || `Si este mes solo pudieras mover una pieza, empezaría por esta.`;
    } else {
      return `Empezá por la palanca de mayor materialidad. El resto sigue.`;
    }
  }

  return null;
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #26-quinquies-B · Conversational Opener Engine
//
// Reemplaza buildValidationOpener cuando el composer expone contrato v1.
// Lee SOLO los campos estructurados del response · NO parsea texto · NO
// inventa cifras. Las frases derivan de decision, focus, materialMetrics y
// reasoningPattern del contrato.
//
// Si el response no tiene contrato v1 → retorna null (defensivo). El caller
// debe hacer fallback a buildValidationOpener legacy.
//
// REGLAS DURAS:
//   · responseObjectVersion !== "v1" → null (no inventa)
//   · validationType === null → null (no prependea sin intent)
//   · Cero hardcoding numérico · cifras vienen de materialMetrics
//   · Determinismo bitwise · mismas entradas = mismo opener
// ════════════════════════════════════════════════════════════════════════════
function buildConversationalOpener(response, validationType) {
  // Guard 1: contrato v1 obligatorio
  if (!response || response.responseObjectVersion !== "v1") return null;
  // Guard 2: sin validation type no se prependea
  if (!validationType) return null;

  const { decision, focus, materialMetrics, reasoningPattern } = response;

  // ── VALIDATION_REAL ──
  // Afirma si el patrón es de problema real; niega si es virtuoso/oportunidad.
  if (validationType === "validation_real") {
    const affirmingPatterns = [
      "high_sales_low_contribution_via_load",
      "capital_trapped_low_rotation",
      "margin_compression",
      "dilution_pattern",
    ];
    const negatingPatterns = [
      "high_margin_low_load_with_upside",
      "high_rotation_high_margin",
      "portfolio_dual_efficiency_contrast",
    ];

    if (affirmingPatterns.includes(reasoningPattern) && decision) {
      const metric0 = materialMetrics[0] || "";
      const metric1 = materialMetrics[1] || "";
      return `Sí · te está apretando. ${decision} con ${metric1} y ${metric0}.`;
    }
    if (negatingPatterns.includes(reasoningPattern) && decision) {
      return `No · ${decision} opera dentro de patrón sano del portafolio.`;
    }
    return null;
  }

  // ── VALIDATION_DECISION ──
  // Reformula focus en minúsculas + cifras materiales como respaldo.
  if (validationType === "validation_decision") {
    if (decision && focus) {
      const metricsText = materialMetrics.slice(0, 2).join(" y ");
      return `Sí · ${focus.toLowerCase()}. ${decision} concentra ${metricsText}.`;
    }
    if (focus) {
      return `Sí · ${focus.toLowerCase()}.`;
    }
    return null;
  }

  // ── VALIDATION_IMPERATIVE ──
  // Voz directa según reasoningPattern · acción específica con cifras.
  if (validationType === "validation_imperative") {
    if (decision && focus) {
      if (reasoningPattern === "high_margin_low_load_with_upside") {
        const metric0 = materialMetrics[0] || "";
        const metric1 = materialMetrics[1] || "";
        const metric2 = materialMetrics[2] || "";
        return `Invertiría el esfuerzo adicional en ${decision}. Hoy combina ${metric0} y ${metric1}, con ${metric2} si captura crecimiento sobre la misma estructura.`;
      }
      if (reasoningPattern === "capital_trapped_low_rotation") {
        return `Soltá ${decision}. Capital atrapado vs cash recuperado · favorece cash.`;
      }
      if (reasoningPattern === "portfolio_dual_efficiency_contrast") {
        return `Protegé ${decision} primero · es palanca estructural del portafolio.`;
      }
      if (reasoningPattern === "high_sales_low_contribution_via_load") {
        return `Priorizá ${decision} · mayor materialidad + controlabilidad directa.`;
      }
      // Fallback derivado de focus + decision
      return `${focus} · empezá por ${decision}.`;
    }
    return null;
  }

  return null;
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #27 · Active Investigation Drilldown Detector
//
// Detecta cuando el usuario formula pregunta de DIMENSIÓN
// ("en qué bodega", "qué SKU explica", "dónde está concentrado")
// SIN introducir dominio nuevo explícito · si hay investigation activa en
// conversationContext, retorna {type: "contextual_drilldown", ...}.
//
// La prioridad en detectIntent garantiza que SKU canónico explícito y
// cliente canónico ganen antes que este detector · es decir, este solo
// dispara cuando el texto no nombra entidad concreta.
//
// CERO HARDCODING: dimensiones detectadas vienen de keywords + investigation
// context preexistente · el composer destino lee dataset en runtime.
// ════════════════════════════════════════════════════════════════════════════
function detectActiveInvestigation(text, context) {
  // Guard 1: debe haber investigation activa en context
  if (!context?.investigationDomain || !context?.investigationMetric) {
    return null;
  }
  if (!text) return null;

  // Normalizar + strip de signos iniciales (¿¡) para que startsWith funcione.
  // Patrón replicado de detectIntent (línea ~2893).
  const t = text.toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/^[¿¡?!.,;:\s]+/, "");

  // BRIEF #29-bis · Vocabulario semántico extendido de verbos de dimensión.
  // Cada raíz cubre singular Y plural · captura formas naturales del habla
  // ejecutiva ("qué SKU explican", "qué bodegas sostienen", etc.).
  // Boundary check con espacio o inicio/fin de string · evita falsos positivos
  // por substring dentro de otras palabras.
  const DIMENSION_VERBS = [
    "explica", "explican",
    "concentra", "concentran",
    "aporta", "aportan",
    "sostiene", "sostienen",
    "genera", "generan",
    "compone", "componen",
    "representa", "representan",
    "origina", "originan",
  ];
  const matchesDimensionVerb = DIMENSION_VERBS.some(v => {
    // Boundary: precedido por espacio O inicio · seguido por espacio,
    // fin de string, o puntuación común (¿!?.,;:). Cubre "explican?" al final.
    const pattern = new RegExp("(^|\\s)" + v + "(\\s|$|[?!.,;:])", "i");
    return pattern.test(t);
  });

  // Detectar pattern de DIMENSIÓN (la pregunta busca distribución, no entidad)
  const isDimensionQuery = (
    t.startsWith("en que ")
    || t.startsWith("en cual ")
    || (t.startsWith("que ") && matchesDimensionVerb)
    || t.startsWith("donde esta")
    || t.startsWith("dónde está")
    || t.includes("como se distribuye")
    || t.includes("cómo se distribuye")
    || t.includes("como se concentra")
    || t.includes("cómo se concentra")
    || matchesDimensionVerb  // BRIEF #29-bis · cualquier verbo de dimensión activa
  );

  if (!isDimensionQuery) return null;

  // Identificar la nueva dimensión solicitada por el usuario
  let newDimension = null;

  if (t.includes("bodega") || t.includes("sucursal") || t.includes("ciudad")) {
    newDimension = "bodega";
  } else if (
    t.includes("categoria") || t.includes("categoría")
    || t.includes("familia") || t.includes("linea") || t.includes("línea")
  ) {
    newDimension = "sfamilia";
  } else if (t.includes("sku") || t.includes("producto") || t.includes("productos")) {
    newDimension = "sku";
  } else if (t.includes("marca") || t.includes("brand")) {
    newDimension = "marca";
  } else if (t.includes("cliente") || t.includes("cuenta") || t.includes("cuentas")) {
    newDimension = "cliente";
  }

  if (!newDimension) return null;

  return {
    type: "contextual_drilldown",
    newDimension,
    investigationContext: {
      domain: context.investigationDomain,
      metric: context.investigationMetric,
      hypothesis: context.investigationHypothesis,
      lastIntent: context.investigationLastIntent,
      // BRIEF #27-bis · pass goal al composer (puede ser null si no fue poblado)
      goal: context.investigationGoal || null,
    },
  };
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #26 · Helper · identifica entidad canónica en texto
//
// Retorna {type: "sku"|"client", value: "..."} o null.
// Prioriza SKU canónico sobre cliente (más específico).
// ════════════════════════════════════════════════════════════════════════════
function detectEntityInText(text) {
  if (!text) return null;
  // Prioridad SKU canónico (más específico, código alfanumérico)
  const sku = detectSkuInText(text);
  if (sku) return { type: "sku", value: sku };
  // Cliente canónico
  const client = detectClientInText(text);
  if (client) return { type: "client", value: client };
  return null;
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #26 · Detector de disambiguación cognitiva
//
// Se evalúa DESPUÉS de que todos los detectores especializados retornaron
// null (SKU canónico, cognitive_action, deíctico, intent semántico).
//
// Si la pregunta menciona una entidad canónica pero NO matchea con ningún
// flujo conocido, retorna metadata para construir respuesta de redirección.
//
// Si no hay entidad → null (cae al fallback genérico tradicional).
// ════════════════════════════════════════════════════════════════════════════
function detectDisambiguationNeeded(text, context, scenario, modulo) {
  const entity = detectEntityInText(text);
  if (!entity) return null;
  return {
    type: "disambiguation",
    entity,
    originalText: text,
  };
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #25 · buildCognitiveState
//
// Construye el cognitive state del análisis recién completado.
// Es input del Suggestion Generator Engine (SGE).
//
// El cognitive state captura:
//   · intent procesado
//   · primaryEntity (SKU o cliente bajo análisis)
//   · parentList (lista de la cual viene el deep dive)
//   · pendingEntities (qué falta por revisar)
//   · módulo activo
//   · métrica dominante
//   · benchmark relevante con gap
//   · anomaly (severidad del estado)
//   · crossDomainAvailable (qué cruzamientos son posibles)
//   · depth analítica (0 inicial, 1 deep dive, 2+ sub-análisis)
//
// Determinístico · misma entrada → mismo state.
// ════════════════════════════════════════════════════════════════════════════
function buildCognitiveState({
  intent,                  // type string del intent
  intentParams,            // params del intent (skuName, clientName, etc)
  scenario,                // bonanza | tension | crisis
  modulo,                  // inventario | margenes | ventas
  conversationContext,     // memoria del usuario
  responseSentrixAction,   // payload de la respuesta
}) {
  const state = {
    intent: intent || null,
    primaryEntity: { type: null, value: null },
    parentList: { type: null, items: [], sourceIntent: null },
    module: modulo,
    metric: null,
    benchmark: { type: null, value: null, gap: null },
    anomaly: { type: null, severity: null },
    pendingEntities: [],
    crossDomainAvailable: [],
    depth: 0,
  };

  // === PRIMARY ENTITY ===
  if (intent === "sku_deep_dive" && intentParams?.skuName) {
    state.primaryEntity = { type: "sku", value: intentParams.skuName };
    state.depth = 1;
  } else if ((intent === "client" || intent === "client_dive" || intent === "client_followup")
             && intentParams?.clientName) {
    state.primaryEntity = { type: "client", value: intentParams.clientName };
    state.depth = 1;
  }

  // === PARENT LIST · de memoria conversacional ===
  // Si hay lastSkuList con sourceIntent conocido, esa es la lista padre.
  if (conversationContext.lastIntent === "sku_operational"
      && conversationContext.lastSkuList?.length > 0) {
    state.parentList = {
      type: "sku",
      items: conversationContext.lastSkuList,
      sourceIntent: "sku_operational",
    };
  } else if (conversationContext.lastIntent === "product_contribution"
             && conversationContext.lastSkuList?.length > 0) {
    state.parentList = {
      type: "sku",
      items: conversationContext.lastSkuList,
      sourceIntent: "product_contribution",
    };
  } else if (conversationContext.lastIntent === "cross_domain_query"
             && conversationContext.lastClientList?.length > 0) {
    // Inferir sub-archetype del cross_domain_query desde meta si disponible.
    // Por defecto: mechanism_explore_erosion (caso más común en demo).
    state.parentList = {
      type: "client",
      items: conversationContext.lastClientList,
      sourceIntent: "mechanism_explore_erosion",
    };
  } else if (conversationContext.lastSkuList?.length > 0) {
    // Fallback: si hay lista pero no intent identificable, asumir SKU
    // operacional.
    state.parentList = {
      type: "sku",
      items: conversationContext.lastSkuList,
      sourceIntent: conversationContext.lastIntent || "sku_operational",
    };
  } else if (conversationContext.lastClientList?.length > 0) {
    state.parentList = {
      type: "client",
      items: conversationContext.lastClientList,
      sourceIntent: conversationContext.lastIntent || "mechanism_explore_erosion",
    };
  }

  // === PENDING ENTITIES · elementos de parentList aún no analizados ===
  if (state.parentList.items.length > 0 && state.primaryEntity.value) {
    // Solo cuentan como pendientes si son del mismo tipo que la primary
    if (state.parentList.type === state.primaryEntity.type) {
      // BRIEF #26-quater · fix bug · dedupe y guardrail de tamaño.
      // Cuando el flujo procesa múltiples turnos, parentList.items puede
      // haberse contaminado con suggestions de turnos intermedios. Aplicamos
      // dedupe primero, después filtramos la entidad ya analizada, después
      // limitamos al tamaño determinístico de la lista padre original.
      const uniqueItems = [...new Set(state.parentList.items)];
      state.pendingEntities = uniqueItems.filter(
        e => e !== state.primaryEntity.value
      );
      // Guardrail · tamaño esperado de la lista padre por sourceIntent.
      // Conocemos los tamaños canónicos: erosion/cross_domain_query → 3,
      // sku_operational/product_contribution → 4. Limitar a (size - 1)
      // para excluir la entidad ya vista.
      const expectedSize = {
        "mechanism_explore_erosion": 3,
        "cross_domain_query": 3,
        "sku_operational": 4,
        "product_contribution": 4,
      }[state.parentList.sourceIntent] || uniqueItems.length;
      state.pendingEntities = state.pendingEntities.slice(0, expectedSize - 1);
    }
  }

  // === CROSS-DOMAIN AVAILABLE ===
  if (state.primaryEntity.type === "sku") {
    state.crossDomainAvailable = ["client_purchases_sku", "sku_in_margenes"];
  } else if (state.primaryEntity.type === "client") {
    state.crossDomainAvailable = ["client_skus_top", "client_in_ventas"];
  }

  // === METRIC + BENCHMARK + ANOMALY (por intent) ===
  if (intent === "sku_deep_dive" && intentParams?.skuName) {
    const sku = skuInventario.find(s => s.sku === intentParams.skuName);
    if (sku) {
      state.metric = sku.alerta === "crit" ? "capital_atrapado"
                   : sku.alerta === "warn" ? "rotacion"
                   : "contribucion";
      state.benchmark = {
        type: "rotacion_interna",
        value: 7,
        gap: Math.max(0, +(7 - sku.rotacion).toFixed(1)),
      };
      state.anomaly = sku.alerta === "crit"
        ? { type: "critical_state", severity: "high" }
        : sku.alerta === "warn"
        ? { type: "below_benchmark", severity: "medium" }
        : sku.rotacion >= 9
        ? { type: "virtuoso", severity: "low" }
        : { type: null, severity: null };
    }
  } else if (intent === "sku_operational") {
    state.metric = "capital_atrapado";
    state.benchmark = { type: "rotacion_interna", value: 7, gap: 5 };
    state.anomaly = { type: "high_concentration", severity: "high" };
  } else if (intent === "cross_domain_query") {
    // Default · erosion como más común. Si en el futuro se necesita
    // discriminar, propagar el archetype específico.
    state.metric = "carga_comercial";
    state.benchmark = { type: "carga_best_practice", value: 3.5, gap: 1 };
    state.anomaly = { type: "below_benchmark", severity: "medium" };
  } else if (intent === "product_contribution") {
    state.metric = "contribucion";
    state.benchmark = null;
    state.anomaly = { type: null, severity: null };
  } else if (intent === "product_dual_comparison") {
    // BRIEF #26-ter · Modo Oportunidad · dual SKU virtuoso vs lastre
    state.metric = "contribucion";
    state.benchmark = null;
    state.anomaly = { type: null, severity: null };
  } else if (intent === "growth_opportunity") {
    // BRIEF #26-ter · Modo Oportunidad · cuentas con upside
    state.metric = "contribucion";
    state.benchmark = { type: "margen_cartera", value: 30.1, gap: 0 };
    state.anomaly = { type: "virtuoso", severity: "low" };
  } else if (intent === "client" || intent === "client_dive" || intent === "client_followup") {
    state.metric = "contribucion";
    state.benchmark = { type: "margen_cartera", value: 30.1, gap: 8 };
    state.anomaly = { type: "below_benchmark", severity: "medium" };
  }

  return state;
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #25 · Suggestion Generator Engine (SGE)
//
// Recibe cognitiveState y produce 2-3 suggestions derivadas del razonamiento
// sobre el estado, NO plantillas seleccionadas por intent.
//
// 6 regiones de inferencia ordenadas por prioridad:
//   R1 · Pendientes en lista padre
//   R2 · Cross-domain disponible
//   R3 · Comparación con similares (opuestos)
//   R4 · Simulación desde benchmark
//   R5 · Anomalía relacionada
//   R6 · Cambio de módulo (fallback contextual)
//
// Las frases finales usan entidades reales del state, no placeholders.
// Determinístico · mismo state → mismas suggestions.
// ════════════════════════════════════════════════════════════════════════════
function generateContextualSuggestions(cognitiveState) {
  const suggestions = [];

  // ── REGIÓN 1 · PENDIENTES EN LISTA PADRE
  if (cognitiveState.parentList?.items?.length > 1
      && cognitiveState.primaryEntity?.value
      && cognitiveState.pendingEntities?.length > 0) {

    const n = cognitiveState.pendingEntities.length;
    const tipo = cognitiveState.parentList.type === "sku" ? "SKU" : "cuentas";

    // Traducir sourceIntent a etiqueta semántica del análisis padre.
    let grupoSemantico;
    switch (cognitiveState.parentList.sourceIntent) {
      case "sku_operational":
        grupoSemantico = "grupo crítico";
        break;
      case "product_contribution":
        grupoSemantico = "ranking de contribución";
        break;
      case "mechanism_explore_erosion":
      case "cross_domain_query":
        grupoSemantico = "grupo con presión comercial";
        break;
      case "mechanism_explore_quality":
        grupoSemantico = "grupo con dilución";
        break;
      default:
        grupoSemantico = "análisis";
    }

    suggestions.push({
      text: `Quedan ${n} ${tipo} del ${grupoSemantico} sin revisar. ¿Continuamos con ellos?`,
      action: {
        type: "continue_pending",
        payload: {
          entityType: cognitiveState.parentList.type,
          entities: [...cognitiveState.pendingEntities],
          sourceIntent: cognitiveState.parentList.sourceIntent,
        },
      },
    });
  }

  // ── REGIÓN 2 · CROSS-DOMAIN DISPONIBLE
  if (cognitiveState.primaryEntity?.value
      && cognitiveState.crossDomainAvailable?.length > 0
      && cognitiveState.depth < 2
      && suggestions.length < 3) {

    const entity = cognitiveState.primaryEntity.value;

    if (cognitiveState.primaryEntity.type === "sku") {
      suggestions.push({
        text: `¿Qué cliente compra ${entity}?`,
        action: { type: "cross_domain_sku_to_client", payload: { skuName: entity } },
      });
    } else if (cognitiveState.primaryEntity.type === "client") {
      suggestions.push({
        text: `¿Qué SKUs aportan más en ${entity}?`,
        action: { type: "cross_domain_client_to_sku", payload: { clientName: entity } },
      });
    }
  }

  // ── REGIÓN 3 · COMPARACIÓN CON SIMILARES (opuestos)
  if (cognitiveState.primaryEntity?.value
      && cognitiveState.parentList?.items?.length >= 2
      && cognitiveState.pendingEntities?.length === 0
      && cognitiveState.depth >= 1
      && suggestions.length < 3) {

    if (cognitiveState.parentList.sourceIntent === "mechanism_explore_erosion"
        || cognitiveState.parentList.sourceIntent === "cross_domain_query") {
      suggestions.push({
        text: "¿Comparar contra cuentas virtuosas del portafolio?",
        action: { type: "compare_opposite", payload: { domain: "client", pattern: "virtuoso" } },
      });
    } else if (cognitiveState.parentList.sourceIntent === "sku_operational") {
      suggestions.push({
        text: "¿Comparar contra SKUs rotacionales del portafolio?",
        action: { type: "compare_opposite", payload: { domain: "sku", pattern: "rotacional" } },
      });
    } else if (cognitiveState.parentList.sourceIntent === "product_contribution") {
      suggestions.push({
        text: "¿Ver SKUs de menor aporte económico?",
        action: { type: "compare_opposite", payload: { domain: "sku", pattern: "bottom_contrib" } },
      });
    }
  }

  // ── REGIÓN 4 · SIMULACIÓN DESDE BENCHMARK
  if (cognitiveState.benchmark?.gap > 0
      && cognitiveState.primaryEntity?.value
      && cognitiveState.depth >= 1
      && suggestions.length < 3) {

    const entity = cognitiveState.primaryEntity.value;
    const entityType = cognitiveState.primaryEntity.type;
    const benchValue = cognitiveState.benchmark.value;

    if (cognitiveState.metric === "margen") {
      suggestions.push({
        text: `¿Qué pasa si ${entity} iguala el benchmark de ${benchValue}%?`,
        action: {
          type: "simulation_benchmark",
          payload: { entity, entityType, metric: "margen", target: benchValue },
        },
      });
    } else if (cognitiveState.metric === "carga_comercial") {
      suggestions.push({
        text: `¿Cuánto recupero si bajo carga de ${entity} a ${benchValue}%?`,
        action: {
          type: "simulation_load_reduction",
          payload: { entity, targetCarga: benchValue },
        },
      });
    } else if (cognitiveState.metric === "rotacion" || cognitiveState.metric === "capital_atrapado") {
      suggestions.push({
        text: `¿Qué libero si ${entity} alcanza rotación 9x?`,
        action: {
          type: "simulation_rotation",
          payload: { sku: entity, targetRotation: 9 },
        },
      });
    } else if (cognitiveState.metric === "contribucion") {
      suggestions.push({
        text: `¿Cuánto sube contribución si ${entity} cierra el gap?`,
        action: {
          type: "simulation_contribution",
          payload: { entity, entityType, gap: cognitiveState.benchmark.gap },
        },
      });
    }
  }

  // ── REGIÓN 5 · ANOMALÍA RELACIONADA
  if (cognitiveState.anomaly?.severity === "high"
      && cognitiveState.primaryEntity?.value
      && suggestions.length < 3) {

    const entity = cognitiveState.primaryEntity.value;

    if (cognitiveState.anomaly.type === "critical_state") {
      suggestions.push({
        text: `¿Cuál es el plan de salida de ${entity}?`,
        action: { type: "exit_plan", payload: { sku: entity } },
      });
    } else if (cognitiveState.anomaly.type === "high_concentration") {
      suggestions.push({
        text: "¿Qué pasa si reducimos la concentración?",
        action: { type: "compare_opposite", payload: { domain: "sku", pattern: "rotacional" } },
      });
    }
  }

  // ── REGIÓN 6 · CAMBIO DE MÓDULO (FALLBACK CONTEXTUAL)
  if (cognitiveState.module
      && cognitiveState.primaryEntity?.value
      && suggestions.length < 3) {

    const entity = cognitiveState.primaryEntity.value;
    const entityType = cognitiveState.primaryEntity.type;

    if (cognitiveState.module === "inventario") {
      suggestions.push({
        text: `¿Cómo se ve ${entity} en Márgenes?`,
        action: {
          type: "cross_module_view",
          payload: { entity, entityType, targetModule: "margenes" },
        },
      });
    } else if (cognitiveState.module === "margenes") {
      suggestions.push({
        text: `¿Cómo se ve ${entity} en Ventas?`,
        action: {
          type: "cross_module_view",
          payload: { entity, entityType, targetModule: "ventas" },
        },
      });
    } else if (cognitiveState.module === "ventas") {
      suggestions.push({
        text: `¿Cómo se ve ${entity} en Márgenes?`,
        action: {
          type: "cross_module_view",
          payload: { entity, entityType, targetModule: "margenes" },
        },
      });
    }
  }

  // Devolver máximo 3
  return suggestions.slice(0, 3);
}

// Router principal de sugerencias clickeadas.
function routeSuggestion(suggestionText, scenarioId, moduloId, context) {
  const normalized = suggestionText
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
  // Versión sin signos iniciales (¿, ¡) para usar con .startsWith()
  const stripped = normalized.replace(/^[¿¡?!.,;:\s]+/, "");

  // BRIEF #14 · CATEGORÍA 0 · Cross-Domain Query (highest priority)
  // Procesa sugerencias que mezclan dominios o usan expresiones ejecutivas
  // amplias. Va antes de simulación porque "si tuviera que intervenir..." y
  // "si pierdo a mis 3 principales" son cross-domain, no simulación single.
  const crossDomain = detectCrossDomainQuery(suggestionText);
  if (crossDomain.isCrossDomainQuery) {
    return composeCrossDomainResponse(crossDomain, scenarioId);
  }

  // CATEGORÍA 1 · Cliente específico mencionado (Falabella, Lider, etc.)
  const clientMentioned = detectClientInText(normalized);

  // CATEGORÍA 3 · Simulación ("qué pasa si..."). Tiene prioridad sobre
  // cliente_directo cuando ambos aparecen, porque "qué pasa si pierdo a
  // Falabella" es una simulación con cliente, no un perfil de cliente.
  const isSimulation = (
    stripped.startsWith("que pasa si") ||
    stripped.startsWith("y si") ||
    normalized.includes("renegoci") ||
    normalized.includes("liquid") ||
    normalized.includes("pierdo") ||
    normalized.includes("subo precio")
  );
  if (isSimulation) {
    return generateSimulation(suggestionText, scenarioId, moduloId, context);
  }

  // CATEGORÍA 2 · Desglose por cliente ("por cliente", "qué clientes")
  if (
    normalized.includes("por cliente")  ||
    normalized.includes("que clientes") ||
    normalized.includes("que cliente ")
  ) {
    return generateClientBreakdown(scenarioId, moduloId);
  }

  // CATEGORÍA 4 · Análisis causal ("por qué...", "por que...")
  // Solo si NO viene de un cliente puramente nombrado (eso es cat 1).
  const isCausal = (
    normalized.includes("por que") ||
    stripped.startsWith("porque ") ||
    normalized.includes("crece") ||
    normalized.includes("cae")     ||
    normalized.includes("performa")
  );
  if (isCausal) {
    return generateCausalAnalysis(suggestionText, scenarioId, moduloId);
  }

  // CATEGORÍA 5 · Comparación
  if (
    normalized.includes("comparar") ||
    normalized.includes("comparalo") ||
    normalized.includes("comparame") ||
    normalized.includes(" vs ")     ||
    normalized.includes("se compara") ||
    normalized.includes("compara")
  ) {
    return generateComparison(suggestionText, scenarioId, moduloId);
  }

  // CATEGORÍA 6 · Acción / recuperación
  if (
    normalized.includes("recuperar") ||
    normalized.includes("recupero")  ||
    normalized.includes("vale la pena") ||
    normalized.includes("primero")   ||
    normalized.includes("en 30 dias") ||
    normalized.includes("en 90 dias")
  ) {
    return generateActionAnalysis(suggestionText, scenarioId, moduloId);
  }

  // CATEGORÍA 1 · Cliente directo (sin simulación, sin causal)
  if (clientMentioned) {
    // BRIEF #12-C.4 · Pass active module + prior conversation to deep dive
    const deepContext = getResponseContext({
      activeModule: moduloId,
      lastClientMentioned: context?.lastClientMentioned || null,
      lastModuleConsulted: context?.lastModuleAsked || null,
      turnCount: context?.turnCount || 0,
      userInputText: suggestionText,
    });
    return getClientDeepDive(clientMentioned, scenarioId, deepContext);
  }

  // FALLBACK · Profundización del módulo
  return generateModuleDeepDive(scenarioId, moduloId);
}

// ── Desglose por cliente: identifica los 3 con mayor erosión/caída/sobrestock
// y arma un ranking con cifras concretas + suggestions de profundización.
function generateClientBreakdown(scenarioId, moduloId) {
  if (moduloId === "margenes") {
    const margenes = getClientesMargenWithProtected(scenarioId);
    const benchmark = 30.1;

    // Calcular destrucción directa por cliente: venta × gap / 100. Esto es
    // la contribución NO capturada por estar bajo benchmark. Ordenamos por
    // destrucción descendente — los que más le duelen al negocio.
    const erosionados = margenes
      .filter(c => c.margen < benchmark)
      .map(c => ({
        ...c,
        gap:         benchmark - c.margen,
        destruccion: Math.round(c.venta * (benchmark - c.margen) / 100),
      }))
      .sort((a, b) => b.destruccion - a.destruccion)
      .slice(0, 3);

    if (erosionados.length === 0) {
      return {
        opener: `En este escenario, todos los clientes operan por encima del benchmark. La carga comercial está bien calibrada — algo poco común, vale celebrarlo.`,
        // BRIEF N-bis · Tipo A puro · filtradas
        suggestions: filterTextualSuggestions([
          "¿Cuál es el cliente más rentable?",
          "¿Hay espacio para crecer con alguien?",
          "Volver al margen general",
        ]),
      };
    }

    // BRIEF #8-cuatris · narrativa humanizada con suma total + pregunta de fondo
    const margenGeneral = getMargenKPI(scenarioId).pct;
    let opener = `El margen general (${margenGeneral.toFixed(1)}%) no se rompe en todos lados. Se rompe en tres clientes específicos:\n\n`;
    erosionados.forEach((c, i) => {
      opener += `${i + 1}. ${c.nombre} — opera al ${c.margen.toFixed(1)}% (${c.gap.toFixed(1)}pp bajo benchmark). Pierdes aproximadamente $${c.destruccion}K al año en esa cuenta.\n`;
    });
    const totalDestruccion = erosionados.reduce((s, c) => s + c.destruccion, 0);
    opener += `\nLos tres juntos destruyen aproximadamente $${totalDestruccion}K de contribución potencial.`;
    opener += `\n\nLa pregunta no es si renegociar — es por cuál empezar. Y eso no se decide solo por el monto. Se decide por qué cliente tiene menos alternativas a tu portafolio.`;

    return {
      opener,
      // BRIEF N-bis · Tipo A puro · filtradas
      suggestions: filterTextualSuggestions([
        `¿Qué pasa si renegocio a ${erosionados[0].nombre}?`,
        `¿Por qué ${erosionados[0].nombre} opera tan bajo?`,
        "¿Quién tiene menos alternativas a mi portafolio?",
      ]),
    };
  }

  if (moduloId === "ventas") {
    const ventas = applyScenarioToClientesVentas(scenarioId);
    const cayendo = ventas
      .map(c => ({ ...c, var_: ((c.actual - c.anterior) / c.anterior) * 100 }))
      .filter(c => c.var_ < 0)
      .sort((a, b) => a.var_ - b.var_)
      .slice(0, 3);

    if (cayendo.length === 0) {
      return {
        opener: "En este escenario, ningún cliente del Top 10 está en caída. El crecimiento es generalizado.",
        // BRIEF N-bis · Tipo A puro · filtradas
        suggestions: filterTextualSuggestions([
          "¿Quién crece más?",
          "¿Qué cliente tiene más potencial?",
          "Volver a las ventas generales",
        ]),
      };
    }

    let opener = `Los clientes en caída del Top 10:\n\n`;
    cayendo.forEach((c, i) => {
      const variacion = c.var_.toFixed(1);
      const perdida = c.anterior - c.actual;
      opener += `${i + 1}. ${c.nombre}: pasó de $${(c.anterior/1000).toFixed(1)}M a $${(c.actual/1000).toFixed(1)}M (${variacion}%, -$${perdida}K).\n`;
    });
    opener += `\nLa pregunta clave: ¿es deterioro de relación, de canal, o estructural?`;

    return {
      opener,
      // BRIEF N-bis · Tipo A puro · filtradas
      suggestions: filterTextualSuggestions([
        `¿Qué pasa con ${cayendo[0].nombre}?`,
        `¿Por qué ${cayendo[0].nombre} cae?`,
        "Volver a las ventas generales",
      ]),
    };
  }

  if (moduloId === "inventario") {
    return {
      opener: `El capital inmovilizado se concentra en dos categorías principales: Materiales de Construcción (sobrestock de baja rotación) y Línea Blanca (SKUs detenidos con +120 días sin movimiento). Juntas concentran aproximadamente el 73% del problema.\n\n¿Por dónde empezamos a desarmar el inventario?`,
      // BRIEF N-bis · Tipo A puro · filtradas
      suggestions: filterTextualSuggestions([
        "¿Qué SKUs liquido primero?",
        "¿Cuánto recupero si actúo ya?",
        "Volver al inventario general",
      ]),
    };
  }

  return generateModuleDeepDive(scenarioId, moduloId);
}

// ── Simulación: "qué pasa si pierdo a X", "renegocio con X", "subir precio"…
// BRIEF #8-cuatris · voz humanizada con observación inicial + saltos de línea
// + pregunta retórica final (no "vale la pena entender").
function generateSimulation(questionText, scenarioId, moduloId, context) {
  const normalized = questionText.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  const clientName = detectClientInText(normalized);

  // FIX A (Opción C1 · bug routing) · regex robustos para price_up/price_down.
  // Captura patrones con tokens intermedios entre verbo y objeto:
  //   "subo 5% el precio", "subo el precio 5%", "aumento de precio 4%",
  //   "incremento 5% al precio", "subir precio 3%".
  // Backward compat: includes("subir precio")/("subo precio") sigue capturado
  // implícitamente porque el regex es superset (palabra + 0-40 chars + palabra).
  // Orden inverso (price_up_rev) cubre "el precio sube" / "precio aumenta".
  const RE_PRICE_UP      = /\b(sub[ao]|subir|aumento|aumentar|incremento|incrementar)\b[^.]{0,40}\b(precio|precios)\b/i;
  const RE_PRICE_UP_REV  = /\b(precio|precios)\b[^.]{0,40}\b(sub[ao]|subir|aumento|aumentar|incremento|incrementar)\b/i;
  const RE_PRICE_DOWN    = /\b(baj[ao]|bajar|reducir|reduzco)\b[^.]{0,40}\b(precio|precios)\b/i;
  const RE_PRICE_DOWN_REV = /\b(precio|precios)\b[^.]{0,40}\b(baj[ao]|bajar|reducir|reduzco)\b/i;

  let actionType = "general";
  if (normalized.includes("renegoci"))               actionType = "renegotiate";
  else if (RE_PRICE_UP.test(normalized)
        || RE_PRICE_UP_REV.test(normalized))         actionType = "price_up";
  else if (RE_PRICE_DOWN.test(normalized)
        || RE_PRICE_DOWN_REV.test(normalized))       actionType = "price_down";
  else if (normalized.includes("liquid"))            actionType = "liquidate";
  else if (normalized.includes("pierdo")
        || normalized.includes("perder")
        || normalized.includes("perdiera"))          actionType = "lose";
  else if (normalized.includes("rebate")
        || normalized.includes("carga comercial"))   actionType = "rebate_change";

  // (1) "¿Qué pasa si pierdo a X?" — BRIEF #13 · cognitive pipeline
  if (actionType === "lose" && clientName) {
    const ventas = applyScenarioToClientesVentas(scenarioId);
    const cliente = ventas.find(c => c.nombre === clientName);
    if (!cliente) return generateModuleDeepDive(scenarioId, moduloId);

    // Run the full cognitive pipeline
    const trace = runReasoningEngine(clientName, scenarioId);

    // Auxiliary data
    const profile = getStrategicProfile(clientName);
    const substMap = getSubstitutionMap(clientName, scenarioId);
    const totalActual = ventas.reduce((s, c) => s + c.actual, 0);
    const totals = { totalActual };

    // Compose the counterfactual response (4 movements + plan B + confianza)
    const scenario = composeLoseScenario(trace, profile, substMap, totals);
    const planB = composeLosePlanB(trace, profile, substMap);
    const confianza = composeLoseConfianza(trace, profile, substMap);

    const opener = [scenario, planB, confianza].filter(p => p && p.length > 0).join("\n\n");

    // Suggestions · template-aware
    const suggestions = [];
    if (substMap.isUnique) {
      suggestions.push(`Cómo proteger este canal`);
      suggestions.push(`Qué riesgos tiene esta dependencia`);
      suggestions.push(`Cómo escalar ${clientName}`);
    } else if (profile && profile.tier === 1) {
      suggestions.push(`Cuáles cuentas pueden absorber el volumen`);
      suggestions.push(`Cómo arranco la diversificación`);
      suggestions.push(`Cuánto cuesta defender a ${clientName}`);
    } else {
      suggestions.push(`Cuáles cuentas son equivalentes a ${clientName}`);
      suggestions.push(`Cómo recupero ese volumen`);
      suggestions.push(`Vale la pena defender la cuenta`);
    }

    // BRIEF N-bis · Tipo A puro · suggestions filtradas en return
    return { opener, suggestions: filterTextualSuggestions(suggestions) };
  }

  // (2) "¿Qué pasa si renegocio a X?" — humanizado
  if (actionType === "renegotiate" && clientName) {
    const margenes      = applyScenarioToClientesMargen(scenarioId);
    const ventas        = applyScenarioToClientesVentas(scenarioId);
    const cliente       = margenes.find(c => c.nombre === clientName);
    const ventaCliente  = ventas.find(c => c.nombre === clientName);
    if (!cliente || !ventaCliente) return generateModuleDeepDive(scenarioId, moduloId);

    const cargaActual   = ventaCliente.pctRebate;
    const cargaObjetivo = Math.max(cargaActual - 1.5, 2.0);
    const recuperPp     = cargaActual - cargaObjetivo;
    const recuperacion  = Math.round(ventaCliente.actual * recuperPp / 100);

    let opener = `Bajar la carga comercial de ${clientName} de ${cargaActual.toFixed(1)}% a ${cargaObjetivo.toFixed(1)}% recupera aproximadamente $${recuperacion}K anuales de contribución (cálculo runtime sobre venta actual × delta carga).`;
    opener += `\n\nLa baja de carga típicamente se negocia con contraprestación: volumen comprometido, exclusividades, plazos. ADI no tiene histórico de negociación reciente con ${clientName} para estimar probabilidad de aceptación.`;
    opener += `\n\nEl leverage de negociación depende de la dependencia operativa hacia ${clientName} · ADI puede cuantificar concentración pero no la capacidad de defensa táctica.`;
    opener += `\n\n*Confianza media · cifra de recuperación es runtime · viabilidad de negociación requiere histórico que no está en el escenario activo.*`;

    return {
      opener,
      // BRIEF N-bis · Tipo A puro · filtradas
      suggestions: filterTextualSuggestions([
        `¿Qué alternativas tengo a ${clientName}?`,
        `¿Cómo se compara ${clientName} con sus pares?`,
        `¿Y si ofrezco algo a cambio del rebate?`,
      ]),
    };
  }

  // (3) "¿Qué pasa si subo precios?" — con o sin cliente
  if (actionType === "price_up") {
    let opener = "";
    if (clientName) {
      const ventas  = applyScenarioToClientesVentas(scenarioId);
      const cliente = ventas.find(c => c.nombre === clientName);
      if (cliente) {
        const aumento2pct = Math.round(cliente.actual * 0.02);
        opener  = `Subir precios a ${clientName} tiene un upside cuantificable de facturación · el resultado neto depende de la respuesta de ${clientName}, no estimable desde el dataset actual.`;
        opener += `\n\nEl resultado depende de la dependencia operativa de ${clientName} hacia el portafolio (productos únicos, marca fuerte, logística no replicable) · esa dependencia no está cuantificada en el dataset actual.`;
        opener += `\n\nUn aumento del 2% en ${clientName} suma aproximadamente $${aumento2pct}K al año en facturación (cálculo runtime sobre venta actual × delta precio). La absorción del aumento por ${clientName} requiere validación con relación comercial histórica · no estimable desde el dataset.`;
        opener += `\n\n*Confianza media · upside de facturación es runtime · absorción por ${clientName} requiere histórico que no está en el escenario activo.*`;
      }
    } else {
      // Sin cliente: hablar de Tier 1 vs Tier 2
      const margenes = getClientesMargenWithProtected(scenarioId);
      const tier2    = margenes
        .filter(c => c.contribucion >= 800 && c.contribucion <= 1800)
        .slice(0, 3);
      const nombresTier2 = tier2.map(c => c.nombre).join(", ") || "Ripley, La Polar, Easy";
      opener  = `El upside de subir precios depende del Tier · las cuentas Tier 1 (Falabella, Lider, Jumbo) concentran la mayor participación del portfolio pero su capacidad de respuesta táctica no está modelada en el dataset. Las Tier 2 (${nombresTier2}) tienen margen estructural mayor con participación menor.`;
      opener += `\n\nLa pregunta clave es elasticidad de demanda por cliente · ADI no tiene esa señal en el dataset · estimar requiere histórico de comportamiento ante cambios de precio.`;
      opener += `\n\n*Confianza media · estructura del portfolio es runtime sobre escenario activo · elasticidad de demanda no está modelada.*`;
    }

    return {
      opener,
      // BRIEF N-bis · Tipo A puro · filtradas
      suggestions: filterTextualSuggestions([
        clientName ? `¿${clientName} aceptaría el aumento?` : "¿En qué clientes funcionaría?",
        "¿Qué pasa si pierdo volumen al subir?",
        "Volver al análisis general",
      ]),
    };
  }

  // (4) Liquidar SKUs — humanizado
  if (actionType === "liquidate") {
    const kpi          = getInvKPI(scenarioId);
    const inmovilizado = kpi.inmovilizadoUSD;
    const recuperable  = Math.round(inmovilizado * 0.4);
    // CORTE 9 · WS1.3 · stock/inmovilizado son USD crudos → fmtK. OFF byte-idéntico.
    const _fmtInv = (v) => FEATURE_INVENTORY_PREMIUM ? "$" + (v / 1000).toFixed(1) + "K" : "$" + v + "K";

    let opener = `Liquidando los SKUs con +120 días sin movimiento recuperas aproximadamente ${_fmtInv(recuperable)} en 90 días, sobre un total de ${_fmtInv(inmovilizado)} inmovilizados.`;
    opener += `\n\nLa contracara es cuantificable: liquidar al 50%-60% del costo (supuesto comercial estándar · no validado en escenario) reduce margen del trimestre proporcional al descuento ejecutado. A cambio libera caja y libera bodega.`;
    opener += `\n\nLa pregunta es de horizonte: ¿el cash inmediato vale más que el margen sacrificado este trimestre?`;
    opener += `\n\n*Confianza media · recuperación estimada con supuesto comercial estándar (50-60% del costo) · margen sacrificado dependiente del descuento ejecutado.*`;

    return {
      opener,
      // BRIEF N-bis · Tipo A puro · filtradas
      suggestions: filterTextualSuggestions([
        "¿Cuáles SKUs liquido primero?",
        "¿Qué pierdo si liquido con descuento?",
        "Volver al inventario general",
      ]),
    };
  }

  // ════════════════════════════════════════════════════════════════════════
  // BRIEF #26-bis · Memoria conversacional ANTES del fallback robot
  //
  // Si la pregunta NO matchea ningún caso específico de simulación arriba,
  // pero hay cliente o SKU en memoria (lastClientMentioned/lastSkuMentioned),
  // compone simulación sobre esa entidad. Solo pide "anclar el caso" si
  // realmente no hay nada en memoria (chat fresh).
  //
  // Cero hardcoding · cifras vienen de clientesMargen y skuInventario.
  // Determinismo bitwise · misma entidad + mismo dataset = misma respuesta.
  // ════════════════════════════════════════════════════════════════════════
  const memClient = context?.lastClientMentioned;
  const memSku    = context?.lastSkuMentioned;

  if (memClient) {
    const margenes = getClientesMargenWithProtected(scenarioId);
    const cliente  = margenes.find(c => c.nombre === memClient);
    if (cliente) {
      const cargaActual = cliente.pctRebate;
      const target = 3.5;
      const gap = Math.max(0, cargaActual - target);
      const recuperable = Math.round(cliente.venta * gap / 100);
      const valorPorPunto = Math.round(cliente.venta / 100);

      let opener = `Sobre ${memClient}, una rebaja de carga comercial de ${cargaActual.toFixed(1)}% a ${target.toFixed(1)}% libera aproximadamente $${recuperable}K anuales de contribución (cálculo runtime sobre venta actual × delta carga).`;
      opener += `\n\nLa baja de carga típicamente se negocia con contraprestación: volumen comprometido, exclusividades, plazos. Cada punto de carga vale aproximadamente $${valorPorPunto}K (cálculo runtime sobre venta actual).`;
      opener += `\n\nEstimar probabilidad de aceptación requiere histórico de negociación reciente · ADI no tiene esos datos en el escenario activo.`;
      opener += `\n\n*Confianza media · cifra de recuperación es runtime · viabilidad de negociación requiere histórico que no está en el escenario activo.*`;

      return {
        opener,
        suggestions: [
          {
            text: `¿Cuánto recupero si bajo carga de ${memClient} a ${target}%?`,
            action: {
              type: "simulation_load_reduction",
              payload: { entity: memClient, targetCarga: target },
            },
          },
          {
            text: `¿Qué SKUs aportan más en ${memClient}?`,
            action: {
              type: "cross_domain_client_to_sku",
              payload: { clientName: memClient },
            },
          },
          {
            text: `¿Cómo se ve ${memClient} en Ventas?`,
            action: {
              type: "cross_module_view",
              payload: { entity: memClient, entityType: "client", targetModule: "ventas" },
            },
          },
        ],
        sentrixAction: {
          label: `Ver ${memClient}`,
          moduleChip: "Márgenes",
          payload: { modulo: "margenes", clientes: [memClient], skus: [] },
        },
      };
    }
  }

  if (memSku) {
    const sku = skuInventario.find(s => s.sku === memSku);
    if (sku) {
      const targetRot = 9;
      const capitalLiberadoRaw = sku.rotacion >= targetRot
        ? 0
        : sku.stockUSD * (1 - sku.rotacion / targetRot);
      const capitalLiberado = Math.round(capitalLiberadoRaw / 1000);  // en K

      let opener = `Sobre ${memSku}, si la rotación pasa de ${sku.rotacion}x a ${targetRot}x, libera aproximadamente $${capitalLiberado}K de capital atrapado.`;
      opener += `\n\nEsa rotación se gana por dos vías: aumento de demanda (canal, precio) o reducción de stock disponible (compra menor por ciclo). Ambas tienen contracaras.`;
      opener += `\n\nLa pregunta es operativa: ¿qué palanca tienes hoy para acelerar ${memSku} sin sacrificar contribución unitaria?`;
      opener += `\n\n*Confianza alta · cálculo determinístico sobre stock × rotación actuales del escenario.*`;

      return {
        opener,
        suggestions: [
          {
            text: `¿Qué libero si ${memSku} alcanza rotación 9x?`,
            action: {
              type: "simulation_rotation",
              payload: { sku: memSku, targetRotation: 9 },
            },
          },
          {
            text: `¿Cuál es el plan de salida de ${memSku}?`,
            action: { type: "exit_plan", payload: { sku: memSku } },
          },
          {
            text: `¿Qué cliente compra ${memSku}?`,
            action: {
              type: "cross_domain_sku_to_client",
              payload: { skuName: memSku },
            },
          },
        ],
        sentrixAction: {
          label: `Ver ${memSku} en Inventario`,
          moduleChip: "Inventario",
          payload: { modulo: "inventario", clientes: [], skus: [memSku] },
        },
      };
    }
  }

  // Fallback FINAL · solo si NO hay memoria conversacional
  // (mantener comportamiento legacy para chat fresh)
  return {
    opener: `Para simular eso con precisión necesito anclar mejor el caso. ¿Sobre qué cliente o segmento quieres que corra el escenario?`,
    // BRIEF N-bis · Tipo A puro · filtradas
    suggestions: filterTextualSuggestions([
      "Sobre Falabella",
      "Sobre Mercado Libre",
      "Sobre los clientes Tier 2",
    ]),
  };
}

// ── Análisis causal: "por qué X crece/cae"
function generateCausalAnalysis(questionText, scenarioId, moduloId) {
  const normalized = questionText.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  const clientName = detectClientInText(normalized);

  // Caso especial: Mercado Libre (BRIEF #8-cuatris · humanización)
  if (clientName === "Mercado Libre") {
    const ml = applyScenarioToClientesVentas(scenarioId).find(c => c.nombre === "Mercado Libre");
    if (!ml) return generateModuleDeepDive(scenarioId, moduloId);
    const variacion = (((ml.actual - ml.anterior) / ml.anterior) * 100).toFixed(1);

    if (scenarioId === "bonanza") {
      return {
        opener: `Mercado Libre crece +${variacion}% — el cliente que más sube de tu cartera. Y lo hace con apenas ${ml.pctRebate.toFixed(1)}% de carga comercial, la más baja de todos.\n\nEso es lo que llama la atención: no compraste su crecimiento con descuento, lo ganaste por canal. El comprador llega a tu marca por el algoritmo de búsqueda y por reputación de servicio, no por una oferta.\n\nHoy Mercado Libre representa apenas un dígito de tu facturación. La pregunta no es por qué crece — es por qué no le estás dando más espacio.`,
        // BRIEF N-bis · Tipo A puro · filtradas
        suggestions: filterTextualSuggestions([
          "¿Cómo aumento mi participación en Mercado Libre?",
          "¿Qué riesgos tiene crecer mucho con un canal?",
          "Compáralo con Falabella",
        ]),
      };
    } else if (scenarioId === "tension") {
      return {
        opener: `Mercado Libre crece +${variacion}% mientras el resto se queda plano. Eso no es coincidencia, es señal.\n\nEl canal tradicional (Falabella, Lider) ya no compra volumen con incentivo. Pero el comprador sigue existiendo — solo se movió de lugar. Ahora compra desde el celular, busca por precio, lee reseñas, y elige por servicio.\n\nMercado Libre captura ese cambio. Si tu negocio está plano mientras ML crece, el problema no es del producto. Es de los canales que no se adaptaron.`,
        // BRIEF N-bis · Tipo A puro · filtradas
        suggestions: filterTextualSuggestions([
          "¿Cómo recupero volumen en canal tradicional?",
          "¿Mercado Libre puede absorber más?",
          "¿Qué hago con los canales que caen?",
        ]),
      };
    } else {
      return {
        opener: `Mercado Libre crece +${variacion}% mientras todo lo demás cae. Es la única buena noticia del año.\n\nPero hay que leerla con cuidado. Puede ser migración estructural (el comprador se mudó al canal digital y se queda ahí) o puede ser canibalización (estás haciendo ofertas agresivas en ML que terminan robando ventas a tus otros canales).\n\nSi es lo primero, tienes una palanca de crecimiento real. Si es lo segundo, estás moviendo el problema, no resolviéndolo. La diferencia se ve en si el margen de ML se mantiene o se erosiona.`,
        // BRIEF N-bis · Tipo A puro · filtradas
        suggestions: filterTextualSuggestions([
          "¿El margen de Mercado Libre se está erosionando?",
          "¿Qué pasa si Mercado Libre cambia sus reglas?",
          "¿Cómo recupero los canales que cayeron?",
        ]),
      };
    }
  }

  // Caso general: otro cliente
  if (clientName) {
    const cliente = applyScenarioToClientesVentas(scenarioId).find(c => c.nombre === clientName);
    if (!cliente) return generateModuleDeepDive(scenarioId, moduloId);

    const variacionRaw = ((cliente.actual - cliente.anterior) / cliente.anterior) * 100;
    const variacion    = variacionRaw.toFixed(1);
    const cayendo      = variacionRaw < 0;
    const cargaAlta    = cliente.pctRebate > 4;

    return {
      opener: `${clientName} ${cayendo ? "cae" : "crece"} ${variacion}% en este escenario. Las posibles causas: (1) presión competitiva en su categoría (otras marcas o canales ganando share); (2) deterioro de la relación comercial (rotación de comprador, problemas operativos); (3) cambios en su estrategia interna (priorización de otras categorías).\n\n${cargaAlta ? `Su carga comercial está en ${cliente.pctRebate.toFixed(1)}% — ya alta. Subirla más no resuelve, profundiza.` : `Su carga comercial está en ${cliente.pctRebate.toFixed(1)}% — relativamente baja, hay espacio comercial.`}`,
      // BRIEF N-bis · Tipo A puro · filtradas
      suggestions: filterTextualSuggestions([
        `¿Cuándo empezó a ${cayendo ? "caer" : "crecer"} ${clientName}?`,
        `¿Vale la pena recuperar a ${clientName}?`,
        "Volver al análisis general",
      ]),
    };
  }

  return generateModuleDeepDive(scenarioId, moduloId);
}

// ── Comparación entre clientes / dimensiones
function generateComparison(questionText, scenarioId, moduloId) {
  return {
    opener: `Buena pregunta para comparar. En este escenario, los clientes que más se diferencian son: (1) Mercado Libre como contrapunto positivo (eficiente, en crecimiento, con carga baja); (2) los clientes Tier 2 (Ripley, La Polar, Easy) que muestran el patrón opuesto.\n\n¿Sobre qué dimensión quieres profundizar?`,
    // BRIEF N-bis · Tipo A puro · filtradas
    suggestions: filterTextualSuggestions([
      "Compárame todos por margen",
      "Compárame todos por crecimiento",
      "Compárame por eficiencia comercial",
    ]),
  };
}

// ── Acción / recuperación
function generateActionAnalysis(questionText, scenarioId, moduloId) {
  if (moduloId === "inventario") {
    const kpi          = getInvKPI(scenarioId);
    const inmovilizado = kpi.inmovilizadoUSD;
    const recuperable  = Math.round(inmovilizado * 0.4);
    const fondo        = inmovilizado - recuperable;
    // CORTE 9 · WS1.3 · stock/inmovilizado son USD crudos → fmtK. OFF byte-idéntico.
    const _fmtInv = (v) => FEATURE_INVENTORY_PREMIUM ? "$" + (v / 1000).toFixed(1) + "K" : "$" + v + "K";

    // BRIEF #8-cuatris · narrativa que separa urgencia vs estrategia
    let opener = `Tienes ${_fmtInv(inmovilizado)} en capital inmovilizado. No es un solo problema, son dos.`;
    opener += `\n\nAproximadamente ${_fmtInv(recuperable)} son recuperables en 90 días si actúas hoy: liquidaciones a precio agresivo en SKUs con +180 días sin movimiento, más redistribución entre bodegas para SKUs que sobran en una y faltan en otra. Eso libera caja rápido, pero con costo en margen.`;
    opener += `\n\nLos otros ${_fmtInv(fondo)} son deuda de inventario de fondo — productos del portafolio que ya no rotan al ritmo esperado. Esos no se solucionan con descuento. Se solucionan con decisiones sobre el portafolio: qué dejas de comprar, qué reformulas, qué descontinúas.`;
    opener += `\n\nLa urgencia es liberar los ${_fmtInv(recuperable)}. La estrategia es decidir qué hacer con los ${_fmtInv(fondo)}.`;

    return {
      opener,
      // BRIEF N-bis · Tipo A puro · filtradas
      suggestions: filterTextualSuggestions([
        "¿Cuáles SKUs liquido primero?",
        "¿Qué pierdo si liquido con descuento?",
        "¿Qué productos descontinúo?",
      ]),
    };
  }

  return {
    opener: `Para evaluar la acción correcta, necesito enfocarme en un cliente o categoría específica. ¿Cuál te preocupa más en este momento?`,
    // BRIEF N-bis · Tipo A puro · filtradas
    suggestions: filterTextualSuggestions([
      "Falabella",
      "Mercado Libre",
      "Ver Top 10 completo",
    ]),
  };
}

// ── Fallback: profundización genérica del módulo. Reutiliza
// composeModuleOverview (BRIEF #2 post-46-bis · runtime composer)
// prefijado con "Profundicemos." para diferenciarlo del opener original.
function generateModuleDeepDive(scenarioId, moduloId) {
  const overview = composeModuleOverview(scenarioId, moduloId);
  if (overview && overview.opener) {
    return {
      opener:      `Profundicemos. ${overview.opener}`,
      suggestions: overview.suggestions,
    };
  }
  return {
    opener: "Cuéntame qué quieres analizar en detalle.",
    // BRIEF N-bis · Tipo A puro · filtradas
    suggestions: filterTextualSuggestions(["Las ventas", "El margen", "El inventario"]),
  };
}

function InfoTip({ id, style={} }) {
  const [show, setShow] = useState(false);
  const txt = HELP[id];
  if (!txt) return null;
  return (
    <span style={{ position:"relative", display:"inline-flex", alignItems:"center", ...style }}
      onMouseEnter={()=>setShow(true)} onMouseLeave={()=>setShow(false)}>
      <span style={{
        cursor:"help", marginLeft:5, userSelect:"none",
        width:12, height:12, borderRadius:"50%",
        border:`1px solid rgba(255,255,255,0.15)`,
        display:"inline-flex", alignItems:"center", justifyContent:"center",
        opacity:0.55,
        transition:"opacity 0.18s, border-color 0.18s"
      }}
      onMouseEnter={e=>{ e.currentTarget.style.opacity="1"; e.currentTarget.style.borderColor="rgba(0,176,212,0.5)"; }}
      onMouseLeave={e=>{ e.currentTarget.style.opacity="0.55"; e.currentTarget.style.borderColor="rgba(255,255,255,0.15)"; }}>
        <svg width="6" height="6" viewBox="0 0 6 6" fill="none">
          <circle cx="3" cy="1.2" r="0.6" fill={C.textMuted}/>
          <rect x="2.5" y="2.4" width="1" height="2.6" rx="0.4" fill={C.textMuted}/>
        </svg>
      </span>
      {show && (
        <span style={{
          position:"absolute", bottom:"calc(100% + 6px)", left:"50%", transform:"translateX(-50%)",
          background:"#0d0d0d", border:`1px solid ${C.borderLight}`, borderRadius:7, padding:"7px 10px",
          fontSize:10.5, color:"#94a3b8", lineHeight:1.55, whiteSpace:"normal", maxWidth:240,
          zIndex:200, boxShadow:"0 8px 24px rgba(0,0,0,0.5)", pointerEvents:"none", minWidth:170
        }}>{txt}</span>
      )}
    </span>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// TYPEWRITER — efecto de escritura letra-por-letra
// Render-stable: el primer ciclo monta vacío y arranca un timer; cada tick
// incrementa el largo del texto mostrado. Cleanup en cada efecto evita fugas
// al desmontar o al cambiar el `text`. El cursor parpadea solo mientras escribe.
// ════════════════════════════════════════════════════════════════════════════
function TypewriterText({ text, speed = 8, startDelay = 0, showCursor = true, onComplete }) {
  const [displayed, setDisplayed] = useState("");
  const [started,   setStarted]   = useState(false);
  const [done,      setDone]      = useState(false);
  const completeRef = useRef(onComplete);
  completeRef.current = onComplete;

  // ── Reset al cambiar el texto fuente
  useEffect(() => {
    setDisplayed(""); setStarted(false); setDone(false);
  }, [text]);

  // ── Delay inicial antes de empezar a escribir
  useEffect(() => {
    const t = setTimeout(() => setStarted(true), startDelay);
    return () => clearTimeout(t);
  }, [startDelay, text]);

  // ── Tick por tick · velocidad estilo Claude (BRIEF #25)
  //    burst 2-4 chars por tick · smart word boundary · pausas semánticas
  //    refinadas. Resultado: ~500-700 chars/seg, lectura natural sin parecer
  //    descarga atropellada de texto.
  useEffect(() => {
    if (!started || done) return;
    if (displayed.length >= text.length) {
      setDone(true);
      if (completeRef.current) completeRef.current();
      return;
    }
    // Burst: 2-4 chars por tick (variabilidad sutil)
    const burst = 2 + Math.floor(Math.random() * 3);
    let nextEnd = Math.min(displayed.length + burst, text.length);
    // Smart word boundary: si terminamos a 2-3 chars del próximo espacio,
    // completar la palabra entera (lectura más natural)
    if (nextEnd < text.length && text[nextEnd] !== " ") {
      const nextSpace = text.indexOf(" ", nextEnd);
      if (nextSpace !== -1 && nextSpace - nextEnd <= 3) {
        nextEnd = nextSpace;
      }
    }
    // Pausas semánticas refinadas según último carácter
    const prevChar = text[nextEnd - 1] || "";
    let extra = 0;
    if (prevChar === ",")        extra = 28;
    else if (prevChar === ":")   extra = 30;
    else if (prevChar === ";")   extra = 35;
    else if (prevChar === ".")   extra = 55;
    else if (prevChar === "?" || prevChar === "!") extra = 60;
    else if (prevChar === "\n")  extra = 40;
    // doble salto de línea (párrafo nuevo) → pausa más larga
    if (text.slice(nextEnd-2, nextEnd) === "\n\n") extra = 90;

    let nextDelay = speed + (Math.random() * 4 - 2) + extra;
    const t = setTimeout(() => {
      setDisplayed(text.slice(0, nextEnd));
    }, Math.max(4, nextDelay));
    return () => clearTimeout(t);
  }, [started, displayed, text, speed, done]);

  return (
    <span>
      {displayed}
      {showCursor && !done && (
        <span style={{
          display:"inline-block", width:2, height:"1em",
          background:C.blue, marginLeft:2,
          verticalAlign:"text-bottom",
          animation:"blink 1s infinite"
        }}/>
      )}
    </span>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// SCENARIO SELECTOR — chips para alternar narrativa del demo (BRIEF #4)
// Vive en el header superior, a la izquierda del indicador "Live". Cada chip
// muestra el color del escenario (verde/ámbar/rojo) con un dot y tinte sutil
// cuando está activo. El cambio dispara setScenario en el padre.
// ════════════════════════════════════════════════════════════════════════════
function ScenarioSelector({ scenario, onChange }) {
  return (
    <div style={{
      display:"flex", alignItems:"center", gap:6,
      padding:"4px 8px",
      borderRadius:999,
      background:C.surface,
      border:`1px solid ${C.border}`
    }}>
      <span style={{
        fontSize:9, fontWeight:700,
        color:C.textMuted, letterSpacing:"0.08em",
        marginRight:4, textTransform:"uppercase"
      }}>
        Escenario
      </span>
      {Object.values(SCENARIOS).map(s => {
        const active = scenario === s.id;
        return (
          <button key={s.id}
            onClick={() => onChange(s.id)}
            title={s.sublabel}
            style={{
              display:"flex", alignItems:"center", gap:5,
              padding:"5px 11px",
              borderRadius:999,
              fontSize:11, fontWeight: active ? 700 : 600,
              border:"none", cursor:"pointer",
              background: active ? `${s.color}22` : "transparent",
              color: active ? s.color : C.textSub,
              transition:"all 0.18s ease"
            }}
            onMouseEnter={e=>{ if(!active){ e.currentTarget.style.color = s.color; } }}
            onMouseLeave={e=>{ if(!active){ e.currentTarget.style.color = C.textSub; } }}>
            <span style={{
              width:7, height:7, borderRadius:"50%",
              background:s.dotColor,
              boxShadow: active ? `0 0 8px ${s.dotColor}` : "none",
              transition:"box-shadow 0.18s ease"
            }}/>
            {s.label}
          </button>
        );
      })}
    </div>
  );
}

