// ═══════════════════════════════════════════════════════
// BRIEF #12-C.3 · Composition functions
//
// Each composer is a pure function:
//   · Receives the cognitive trace + auxiliary data
//   · Returns a string for that movement
//   · NEVER invents numbers (all numbers come from trace.evidence
//     or from auxiliary computations of dataset live values)
//
// composeInterpreta is the heart of the upgrade: it synthesizes
// detected templates into a tension-named narrative instead of
// selecting a fixed archetype phrase.
// ═══════════════════════════════════════════════════════

// Helper: convert a template id + severity into a phrase from the pool
function _phraseForTemplate(templateId, severity, clientName) {
  const pool = POOL_TEMPLATE_PHRASES[templateId];
  if (!pool) return null;
  const sevPool = pool[severity] || pool.medium || pool.high;
  if (!sevPool || sevPool.length === 0) return null;
  return selectFromPool(sevPool, clientName, `tmpl_${templateId}`);
}

// Helper: pick the causal closer based on which templates dominate
function _pickCausalCloser(templates, clientName) {
  const ids = templates.map(t => t.id);
  if (ids.includes("rebate_leakage") || ids.includes("low_quality_growth")) {
    return selectFromPool(POOL_INTERPRETA_CAUSAL_CLOSER.rebate_driven, clientName, "causal_closer");
  }
  if (ids.includes("dependency_risk") && ids.length >= 3) {
    return selectFromPool(POOL_INTERPRETA_CAUSAL_CLOSER.concentration_driven, clientName, "causal_closer");
  }
  if (ids.includes("margin_erosion") || ids.includes("benchmark_gap")) {
    return selectFromPool(POOL_INTERPRETA_CAUSAL_CLOSER.benchmark_driven, clientName, "causal_closer");
  }
  return null;
}

// composeInterpreta · synthesizes templates into narrative.
// This replaces the old POOL_INTERPRETA-by-archetype lookup.
function composeInterpreta(trace, profile, context = {}) {
  const clientName = trace.client;
  const templates = trace.layers.templates;

  // Helper · classifies templates as virtuous-side (from #12-C.3-bis)
  const isVirtuousSideTemplate = (t) => {
    if (t.id === "hidden_profitability") return true;
    if (t.id === "dependency_risk") {
      const ev = t.evidence || {};
      const isUnique = ev.isUnique === true;
      const lowParticipation = (ev.participacion === undefined) || ev.participacion < 15;
      return isUnique && lowParticipation;
    }
    return false;
  };

  const negativeTemplates = templates.filter(t => !isVirtuousSideTemplate(t));
  const hasHidden = templates.some(t => t.id === "hidden_profitability");
  const hasNegative = negativeTemplates.length > 0;

  // Pull primitives evidence
  const lastPeriod = trace.layers.primitives.compareVsLastPeriod;
  const benchmark = trace.layers.primitives.compareVsBenchmark;
  const leakage = trace.layers.primitives.detectLeakage;
  const concentration = trace.layers.primitives.detectConcentration;
  const variacion = lastPeriod.evidence.deltaPct;
  const margenPct = benchmark.evidence.margen;
  const gapBp = benchmark.evidence.gap;
  const benchmarkValue = benchmark.evidence.benchmark;
  const carga = leakage.evidence.pctRebate;
  const bestPractice = leakage.evidence.bestPractice;
  const leakagePp = leakage.evidence.leakagePp;
  const participacion = concentration.evidence.participacion;

  // BRIEF #15 · Mechanism link enrichment (controlled by flag)
  // If MECHANISM_LINK_ENABLED, append a sentence linking the client to its
  // primary mechanism. Skipped when flag is off → bitwise identical to BRIEF #13.5.
  let mechanismSentence = "";
  if (MECHANISM_LINK_ENABLED) {
    try {
      const scanForLink = scanMechanisms(trace.scenario);
      const mechanismLink = identifyPrimaryMechanism(clientName, scanForLink);
      if (mechanismLink) {
        mechanismSentence = ` La cuenta es instancia principal de ${mechanismLink.nombre} en la cartera.`;
      }
    } catch (e) { mechanismSentence = ""; }
  }

  // ─── RAMA C · DECLINE CON MARGEN SANO ────────────────
  // Variation strongly negative AND margin at or above benchmark.
  // Evaluated BEFORE virtuous to prevent declining clients with healthy margin
  // (e.g., La Polar with -12.5% YoY but margen 34% > benchmark) from falling
  // into virtuous + "scale" recommendation, which would be narratively incoherent.
  if (variacion < -5 && gapBp <= 0) {
    const firstSentence = composeReasoningSentence(trace, profile);
    const secondSentence = `El deterioro es de volumen, no de pricing ni de carga comercial.`;
    const thirdSentence = `La cuenta sostiene calidad de margen incluso bajo presión de ventas.`;
    return `${firstSentence} ${secondSentence} ${thirdSentence}${mechanismSentence}`;
  }

  // ─── RAMA B · VIRTUOUS ───────────────────────────────
  if (hasHidden && !hasNegative) {
    const firstSentence = composeReasoningSentence(trace, profile);
    let secondSentence = "";
    const profileRol = profile?.rolEstrategico || "";
    const profileCat = profile?.categoriaDominante || "";
    if (profileRol.includes("digital") || profileCat.includes("digital") || profileCat.includes("canal digital")) {
      secondSentence = `La cuenta sostiene esta combinación apoyada en el canal digital, donde el negocio no enfrenta la presión comercial directa que se observa en Tier 1 físico.`;
    } else if (variacion < 0) {
      secondSentence = `Pese a la caída de volumen, la cuenta sostiene calidad de margen, lo que indica deterioro de ventas pero no de pricing ni carga.`;
    } else {
      secondSentence = `La rentabilidad estructural se sostiene sobre carga comercial baja y mix de producto favorable.`;
    }
    return `${firstSentence} ${secondSentence}${mechanismSentence}`;
  }

  // ─── RAMA A · TENSIÓN DOMINANTE (default) ─────────────
  if (!hasNegative) {
    // Edge case: no negatives, no hidden · silent fallback
    return `La cuenta opera dentro de su perfil esperado, sin tensiones materiales detectadas.`;
  }

  // Priority list: identify the dominant tension (most actionable first)
  const DOMINANT_PRIORITY = [
    "rebate_leakage",
    "pricing_pressure",
    "low_quality_growth",
    "margin_erosion",
    "benchmark_gap",
    "dependency_risk",
  ];

  const sortedByPriority = [...negativeTemplates].sort((a, b) => {
    const idxA = DOMINANT_PRIORITY.indexOf(a.id);
    const idxB = DOMINANT_PRIORITY.indexOf(b.id);
    const safeA = idxA === -1 ? 999 : idxA;
    const safeB = idxB === -1 ? 999 : idxB;
    return safeA - safeB;
  });

  const dominant = sortedByPriority[0];

  let firstSentence = "";
  let secondSentence = "";
  let thirdSentence = "";

  switch (dominant.id) {
    case "rebate_leakage":
    case "low_quality_growth":
    case "pricing_pressure": {
      firstSentence = composeReasoningSentence(trace, profile);
      secondSentence = `El rebate alcanza ${carga}% de las ventas, ${leakagePp} puntos sobre la mejor práctica interna (${bestPractice}%).`;
      thirdSentence = `El crecimiento de la cuenta viene acompañado de mayor presión comercial, deteriorando progresivamente el margen frente al benchmark de cartera.`;
      break;
    }
    case "margin_erosion":
    case "benchmark_gap": {
      firstSentence = composeReasoningSentence(trace, profile);
      secondSentence = `El margen opera en ${margenPct}%, ${gapBp} puntos bajo el benchmark de cartera (${benchmarkValue}%).`;
      thirdSentence = `La brecha es estructural: la cuenta no captura el margen promedio de la categoría, lo que erosiona la contribución unitaria del negocio.`;
      break;
    }
    case "dependency_risk": {
      firstSentence = composeReasoningSentence(trace, profile);
      secondSentence = `${clientName} representa ${participacion}% del total de ventas, un nivel que supera el umbral prudencial de diversificación.`;
      thirdSentence = `La dependencia estructural amplifica el impacto de cualquier variación en la cuenta y reduce el margen de maniobra comercial.`;
      break;
    }
    default: {
      firstSentence = composeReasoningSentence(trace, profile);
      secondSentence = `El margen opera en ${margenPct}% y la carga comercial en ${carga}%.`;
      thirdSentence = `La combinación requiere monitoreo y revisión de la estrategia comercial.`;
    }
  }

  return `${firstSentence} ${secondSentence} ${thirdSentence}${mechanismSentence}`;
}

// composeCalcula · preserves the live numbers from the old logic.
// Numbers come from trace.layers.primitives directly.
function composeCalcula(trace, profile, context = {}) {
  const clientName = trace.client;
  const activeModule = context.activeModule || "ventas";

  const lastPeriod = trace.layers.primitives.compareVsLastPeriod;
  const benchmark = trace.layers.primitives.compareVsBenchmark;
  const concentration = trace.layers.primitives.detectConcentration;
  const leakage = trace.layers.primitives.detectLeakage;

  // Live metrics (read from primitives.evidence)
  const ventasM        = +(lastPeriod.evidence.actual / 1000).toFixed(1);
  const participacion  = concentration.evidence.participacion;
  const variacion      = lastPeriod.evidence.deltaPct;
  const variacionLabel = variacion >= 0 ? `+${variacion}%` : `${variacion}%`;
  const margenPct      = benchmark.evidence.margen;
  const gapBenchmark   = benchmark.evidence.gap;
  const carga          = leakage.evidence.pctRebate;

  // Contribucion still requires direct dataset read (not in primitives)
  const margenes = applyScenarioToClientesMargen(trace.scenario);
  const m = margenes.find(c => c.nombre === clientName);
  const contribucionM = m ? +(m.contribucion / 1000).toFixed(2) : null;

  // BRIEF #12-C.4 · Branch by active module
  if (activeModule === "margenes") {
    // Margin-led narrative
    let calcula = "";
    const gapClause = (gapBenchmark > 0)
      ? `${gapBenchmark} puntos bajo benchmark`
      : (gapBenchmark < 0 ? `${Math.abs(gapBenchmark)} puntos sobre benchmark` : "en línea con benchmark");

    if (profile && profile.tier === 1) {
      calcula = `${clientName} opera con margen ${margenPct}% (${gapClause}) y carga comercial de ${carga}%. La cuenta concentra ${participacion}% de la cartera con ventas de $${ventasM}M y variación ${variacionLabel} YoY`;
    } else if (profile && profile.tier === 2) {
      calcula = `${clientName} opera con margen ${margenPct}% (${gapClause}) y carga comercial de ${carga}%. Aporta $${ventasM}M (${participacion}% de la cartera) con variación ${variacionLabel} YoY`;
    } else {
      calcula = `${clientName} opera con margen ${margenPct}% (${gapClause}) y carga comercial de ${carga}%. Cuenta de menor escala: $${ventasM}M (${participacion}% de la cartera), variación ${variacionLabel} YoY`;
    }

    if (contribucionM !== null) {
      calcula += `. Contribución $${contribucionM}M.`;
    } else {
      calcula += `.`;
    }
    return calcula;
  }

  // Default branch (ventas / inventario / fallback): sales-led narrative
  // BRIEF #12-C.6 · Voice rewrite: dato + causa + consecuencia.
  // Add absolute $ delta alongside % YoY. Use "Sin embargo" conector when
  // margin is below benchmark. Carga comercial migrates to INTERPRETA.
  const deltaM = +((lastPeriod.evidence.delta) / 1000).toFixed(2);
  const deltaLabel = variacion >= 0 ? `+$${Math.abs(deltaM)}M` : `-$${Math.abs(deltaM)}M`;
  const deltaPhrase = variacion >= 0
    ? `crece ${variacionLabel} YoY, equivalente a aproximadamente ${deltaLabel} en ventas adicionales`
    : `cae ${variacionLabel} YoY, equivalente a aproximadamente ${deltaLabel} en ventas perdidas`;

  let calcula = "";
  if (profile && profile.tier === 1) {
    calcula = `${clientName} vende $${ventasM}M y representa ${participacion}% de la cartera total. La cuenta ${deltaPhrase}`;
  } else if (profile && profile.tier === 2) {
    calcula = `${clientName} aporta $${ventasM}M y representa ${participacion}% de la cartera total. La cuenta ${deltaPhrase}`;
  } else {
    calcula = `${clientName} aporta $${ventasM}M y representa ${participacion}% de la cartera total. La cuenta ${deltaPhrase}`;
  }

  if (contribucionM !== null) {
    const gapClause = (gapBenchmark > 0)
      ? `${gapBenchmark} puntos bajo el benchmark de cartera`
      : (gapBenchmark < 0 ? `${Math.abs(gapBenchmark)} puntos sobre el benchmark de cartera` : "en línea con el benchmark de cartera");
    const conectorMargen = (gapBenchmark > 0) ? ". Sin embargo, opera" : ". Opera";
    calcula += `${conectorMargen} con margen de ${margenPct}%, ${gapClause}, y aporta cerca de $${contribucionM}M de contribución.`;
  } else {
    calcula += `.`;
  }

  return calcula;
}

// composeContextualiza · bullets logic preserved, wrapped as composer
function composeContextualiza(trace, profile, incrementalGrowth, fullDataset) {
  const clientName = trace.client;
  const v = fullDataset.v;
  const variacion = trace.layers.primitives.compareVsLastPeriod.evidence.deltaPct;
  const benchmark = trace.layers.primitives.compareVsBenchmark.evidence.benchmark;
  const gapBenchmark = trace.layers.primitives.compareVsBenchmark.evidence.gap;
  const carga = +v.pctRebate.toFixed(1);
  const margenes = fullDataset.margenes;

  const bullets = [];

  // Bullet A · incremental growth share
  if (incrementalGrowth !== null && incrementalGrowth > 0) {
    bullets.push(`aproximadamente ${incrementalGrowth}% del crecimiento incremental anual de la cartera`);
  } else if (variacion < 0) {
    bullets.push(`pérdida directa de aproximadamente $${Math.abs(+(v.actual - v.anterior).toFixed(0))}K contra el año anterior`);
  }

  // Bullet B · categoría dominante
  if (profile && profile.categoriaDominante) {
    bullets.push(profile.categoriaDominante);
  }

  // Bullet C · posicionamiento estructural
  if (profile && profile.tier === 1 && gapBenchmark > 0) {
    const otrosTier1Presionados = Object.entries(CLIENTES_STRATEGIC_PROFILE)
      .filter(([name, p]) => name !== clientName && p.tier === 1)
      .filter(([name, p]) => {
        const otherM = margenes.find(c => c.nombre === name);
        return otherM && otherM.margen < benchmark;
      })
      .map(([name]) => name);

    if (otrosTier1Presionados.length === 1) {
      bullets.push(`una de las dos posiciones Tier 1 con margen bajo benchmark, junto a ${otrosTier1Presionados[0]}`);
    } else if (otrosTier1Presionados.length > 1) {
      bullets.push(`posición Tier 1 con margen bajo benchmark, junto a ${otrosTier1Presionados.join(" y ")}`);
    } else {
      bullets.push("única posición Tier 1 con margen bajo benchmark");
    }
  } else if (profile && profile.tier === 1) {
    bullets.push("posición Tier 1 con margen sobre el promedio de las cuentas grandes");
  } else if (profile && profile.poderNegociacion === "Alto" && profile.tier === 2) {
    bullets.push("Tier 2 con poder de negociación alto por canal o crecimiento");
  } else if (profile && profile.cargaComercial === "Alta") {
    bullets.push(`carga comercial de ${carga}% — alta para el tamaño de la cuenta`);
  } else if (profile && profile.tier === 3) {
    bullets.push("escala individual baja pero contribución unitaria sana");
  }

  // Compose CONTEXTUALIZA block
  const conector = selectFromPool(POOL_CONECTORES_CONTEXT, clientName, "conector");
  if (bullets.length >= 3) {
    return `${clientName} ${conector}:\n\n· ${bullets.map((b, i) => i === bullets.length - 1 ? `y ${b}` : b).join(",\n\n· ")}.`;
  } else if (bullets.length === 2) {
    return `${clientName} ${conector} ${bullets[0]} y ${bullets[1]}.`;
  } else if (bullets.length === 1) {
    return `${clientName} ${conector} ${bullets[0]}.`;
  }
  return "";
}

// composeProyecta · substitution narrative, preserved logic
function composeProyecta(trace, profile, substMap) {
  const clientName = trace.client;

  if (substMap.isUnique) {
    return `${clientName} no tiene reemplazo natural en la cartera actual: ${substMap.uniqueReason}. Una salida o deterioro de la cuenta no se compensa estructuralmente con las cuentas existentes.`;
  }

  if (substMap.substitutes.length > 0) {
    const subs = substMap.substitutes;
    if (subs.length === 1) {
      const s = subs[0];
      const shareTxt = s.currentShare !== null ? `${s.currentShare}% de la cartera` : "participación menor";
      return `El reemplazo natural sería ${s.calificator}. ${s.name} concentra ${shareTxt}, escala insuficiente para absorber una salida de esta magnitud en el corto plazo.`;
    } else {
      const s1 = subs[0];
      const s2 = subs[1];
      const share1Txt = s1.currentShare !== null ? `${s1.currentShare}% de la cartera` : "participación menor";
      const share2Txt = s2.currentShare !== null ? `apenas ${s2.currentShare}% de participación` : "participación marginal";
      if (s1.calificator === "parcial" && s2.calificator === "limitado") {
        let p = `El reemplazo natural sería parcial. ${s1.name} concentra ${share1Txt}`;
        const s1Profile = getStrategicProfile(s1.name);
        if (s1Profile && profile && s1Profile.rolEstrategico === profile.rolEstrategico) {
          p += ` pero opera con la misma presión de margen`;
        }
        p += `. ${s2.name} cubre la categoría con ${share2Txt}, escala insuficiente para absorber una salida de esta magnitud en el corto plazo.`;
        return p;
      }
      return `El reemplazo sería distribuido: ${s1.name} (${share1Txt}) y ${s2.name} (${share2Txt}). Ninguno tiene la escala para absorber una salida completa en el corto plazo.`;
    }
  }
  return "El reemplazo natural de la cuenta no es evidente con la cartera actual.";
}

// composeConcluye · concluding sentence; preserves decline override
function composeConcluye(trace, profile) {
  const clientName = trace.client;
  const variacion = trace.layers.primitives.compareVsLastPeriod.evidence.deltaPct;

  if (variacion < -10) {
    return selectFromPool(POOL_CONCLUYE_DECLINE, clientName, "concluye_decline");
  }
  if (profile && POOL_CONCLUYE_BASE[profile.rolEstrategico]) {
    return selectFromPool(POOL_CONCLUYE_BASE[profile.rolEstrategico], clientName, "concluye");
  }
  return selectFromPool(POOL_CONCLUYE_BASE["default"], clientName, "concluye");
}

// ═══════════════════════════════════════════════════════
// BRIEF #12-C.5 · Recommendation Composer
//
// Generates an action-block following Reasoning Constitution §5:
//   ACCIÓN · IMPACTO · RIESGO · CONFIANZA
//
// Triggered when triggered_templates show high-severity actionable
// tensions. Returns null if no recommendation is warranted.
//
// All numbers come from trace.layers.primitives.evidence.
// Zero literal numbers in composition.
// ═══════════════════════════════════════════════════════

// VOZ2 rec-gate · detección determinística de intent activador de recomendación.
// word-boundary \b evita falso positivo "porque hago" ⊃ "que hago".
// "recomend" como stem · cubre recomendá/recomendar/recomienda/recomiéndame.
function voz2WantsRecommendation(userInputText) {
  const t = (userInputText || "").toLowerCase();
  const activators = [
    "que hago", "qué hago", "como resuelvo", "cómo resuelvo",
    "que harias", "qué harías", "que deberia", "qué debería",
    "recomend", "necesito una recomend", "necesito una decisi",
  ];
  return activators.some(a =>
    new RegExp("\\b" + a.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")).test(t)
  );
}

function composeRecommendation(trace, profile, context = {}) {
  const templates = trace.layers.templates;
  const clientName = trace.client;

  // VOZ2 rec-gate · interpretativo por default · imperativo solo con activador explícito
  const _voz2Interp = (typeof VOZ2_ENABLED !== "undefined" && VOZ2_ENABLED)
    && !voz2WantsRecommendation(context.userInputText || "");

  // Helper · same virtuous-side classifier as composeInterpreta
  const isVirtuousSideTemplate = (t) => {
    if (t.id === "hidden_profitability") return true;
    if (t.id === "dependency_risk") {
      const ev = t.evidence || {};
      const isUnique = ev.isUnique === true;
      const lowParticipation = (ev.participacion === undefined) || ev.participacion < 15;
      return isUnique && lowParticipation;
    }
    return false;
  };

  const negativeTemplates = templates.filter(t => !isVirtuousSideTemplate(t));
  const hasHidden = templates.some(t => t.id === "hidden_profitability");
  const hasNegative = negativeTemplates.length > 0;

  // Pull primitives evidence
  const lastPeriod = trace.layers.primitives.compareVsLastPeriod;
  const benchmark = trace.layers.primitives.compareVsBenchmark;
  const leakage = trace.layers.primitives.detectLeakage;
  const concentration = trace.layers.primitives.detectConcentration;
  const variacion = lastPeriod.evidence.deltaPct;
  const margenPct = benchmark.evidence.margen;
  const gapBp = benchmark.evidence.gap;
  const carga = leakage.evidence.pctRebate;
  const bestPractice = leakage.evidence.bestPractice;
  const ventasK = lastPeriod.evidence.actual;
  const ventasM = +(ventasK / 1000).toFixed(1);
  const participacion = concentration.evidence.participacion;

  // Contribution from margin dataset
  const margenes = applyScenarioToClientesMargen(trace.scenario);
  const m = margenes.find(c => c.nombre === clientName);
  const contribucionM = m ? +(m.contribucion / 1000).toFixed(2) : null;

  // ─── RAMA C · MONITOR (decline sano) ──────────────────
  // Strong decline AND margin at or above benchmark.
  // Evaluated BEFORE opportunity to prevent declining clients from getting
  // a "scale" recommendation (e.g., La Polar -12.5% YoY should be monitored, not scaled).
  if (variacion < -5 && gapBp <= 0) {
    const action = `Monitorear evolución de ventas en los próximos 2-3 meses antes de definir acciones.`;
    const reason = `La prioridad es confirmar si la caída de volumen es transitoria o si comienza a deteriorar el margen de la cuenta.`;
    const risk = `La rentabilidad sana del margen permite mantener la cuenta sin urgencia operativa, pero un deterioro adicional sin recuperación de margen activaría revisión de la estrategia comercial.`;
    const mech = `El volumen cae pero el margen se mantiene sano · lo que define el siguiente paso es si la caída empieza a afectar el margen en los próximos 2-3 meses.`;
    return _voz2Interp
      ? `**Mecanismos disponibles**\n\n${mech}`
      : `**Recomendación**\n\n${action} ${reason} ${risk}`;
  }

  // ─── RAMA B · OPPORTUNITY (virtuous) ──────────────────
  if (hasHidden && !hasNegative) {
    const action = `Evaluar plan de inversión comercial específico para escalar ${clientName} en categorías de mayor participación.`;
    const reason = `La cuenta soporta crecimiento adicional sin requerir carga comercial elevada, lo que permitiría aumentar contribución absoluta de la cartera sin replicar la presión de margen que se observa en Tier 1 físico.`;
    const risk = `El principal riesgo es depender de una sola cuenta para sostener crecimiento digital.`;
    const mech = `${clientName} tiene espacio para crecer sin elevar carga comercial · escalarlo en categorías de mayor participación sumaría contribución sin replicar la presión de margen que se observa en el Tier 1 físico.`;
    return _voz2Interp
      ? `**Mecanismos disponibles**\n\n${mech}`
      : `**Recomendación**\n\n${action} ${reason} ${risk}`;
  }

  // ─── RAMA A · ACTION (default for negative tensions) ───
  if (!hasNegative) return null;

  const DOMINANT_PRIORITY = [
    "rebate_leakage",
    "pricing_pressure",
    "low_quality_growth",
    "margin_erosion",
    "benchmark_gap",
    "dependency_risk",
  ];
  const sortedByPriority = [...negativeTemplates].sort((a, b) => {
    const idxA = DOMINANT_PRIORITY.indexOf(a.id);
    const idxB = DOMINANT_PRIORITY.indexOf(b.id);
    const safeA = idxA === -1 ? 999 : idxA;
    const safeB = idxB === -1 ? 999 : idxB;
    return safeA - safeB;
  });
  const dominant = sortedByPriority[0];

  // Decision threshold: only emit recommendation if dominant is high severity
  // OR there are 2+ medium-severity actionables
  const actionableHigh = negativeTemplates.filter(t => t.severity === "high");
  const actionableMedium = negativeTemplates.filter(t => t.severity === "medium");
  if (actionableHigh.length === 0 && actionableMedium.length < 2) return null;

  let action = "";
  let reason = "";
  let risk = "";
  let mech = "";

  switch (dominant.id) {
    case "rebate_leakage":
    case "low_quality_growth":
    case "pricing_pressure": {
      // Operational target: 3.5% (between best practice 3% and current load)
      const operationalTarget = 3.5;
      const pointsToReduce = +(carga - operationalTarget).toFixed(1);
      const impactK = Math.round(ventasK * pointsToReduce / 100);
      action = `Reducir gradualmente la carga comercial desde ${carga}% hacia niveles cercanos al benchmark interno de ${operationalTarget}% permitiría recuperar aproximadamente $${impactK}K anuales de contribución.`;
      reason = `El objetivo no es reducir volumen, sino frenar el deterioro del margen y mejorar la rentabilidad de la cuenta sin afectar participación en el corto plazo.`;
      risk = `El principal riesgo está en próximas negociaciones comerciales, donde ${clientName} podría exigir compensaciones para mantener las condiciones actuales.`;
      mech = `La carga comercial está en ${carga}% · acercarla al benchmark interno de ${operationalTarget}% liberaría aproximadamente $${impactK}K anuales de contribución · la palanca está en la carga, no en el volumen.`;
      break;
    }
    case "margin_erosion":
    case "benchmark_gap": {
      const targetMargin = +(margenPct + gapBp / 2).toFixed(1);
      action = `Revisar mix de producto o estructura de costo de ${clientName} para cerrar parcialmente el gap de margen frente al benchmark de cartera.`;
      reason = `Cerrar la mitad del gap (${(gapBp / 2).toFixed(1)} puntos sobre ${gapBp} actuales) elevaría el margen de la cuenta de ${margenPct}% a aproximadamente ${targetMargin}%, recuperando contribución sin afectar volumen.`;
      risk = `Acción sobre precio puede generar pérdida de volumen, mientras acción sobre costo depende del poder de negociación con proveedores.`;
      mech = `El gap de margen es ${gapBp} puntos · cerrar la mitad llevaría el margen de ${margenPct}% a aproximadamente ${targetMargin}% · el mecanismo está asociado al mix o a la estructura de costo.`;
      break;
    }
    case "dependency_risk": {
      const ventasToReplace = +(ventasM * (participacion - 15) / participacion).toFixed(1);
      action = `Diversificar la cartera reduciendo participación de ${clientName} desde ${participacion}% hacia niveles cercanos al 15%.`;
      reason = `Bajar la participación al umbral prudencial requiere desarrollar cuentas equivalentes a aproximadamente $${ventasToReplace}M en ventas alternativas, lo que reduce el impacto estructural de cualquier variación en la cuenta.`;
      risk = `La diversificación toma 12-18 meses; durante ese período, la pérdida de ${clientName} representaría ${participacion}% de los ingresos del negocio.`;
      mech = `${clientName} concentra ${participacion}% del negocio · llevar esa concentración hacia un nivel más equilibrado (~15%) requeriría desarrollar aproximadamente $${ventasToReplace}M en cuentas alternativas · el margen de diversificación existe, toma 12-18 meses.`;
      break;
    }
    default:
      return null;
  }

  return _voz2Interp
    ? `**Mecanismos disponibles**\n\n${mech}`
    : `**Recomendación**\n\n${action} ${reason} ${risk}`;
}

// ═══════════════════════════════════════════════════════
// BRIEF #12-C.6 · Confidence Composer
//
// Returns a separate italic line stating confidence level
// and what backs the analysis. Always emitted when there is
// a recommendation OR when the response is MEDIUM/EXPANDED.
//
// Returns null if no analytical confidence can be stated
// (extreme edge case · should not happen with current pipeline).
// ═══════════════════════════════════════════════════════

function composeConfianza(trace, profile, context = {}) {
  const templates = trace.layers.templates;

  // Same virtuous-side helper
  const isVirtuousSideTemplate = (t) => {
    if (t.id === "hidden_profitability") return true;
    if (t.id === "dependency_risk") {
      const ev = t.evidence || {};
      const isUnique = ev.isUnique === true;
      const lowParticipation = (ev.participacion === undefined) || ev.participacion < 15;
      return isUnique && lowParticipation;
    }
    return false;
  };

  const negativeTemplates = templates.filter(t => !isVirtuousSideTemplate(t));
  const hasHidden = templates.some(t => t.id === "hidden_profitability");
  const hasNegative = negativeTemplates.length > 0;
  const variacion = trace.layers.primitives.compareVsLastPeriod.evidence.deltaPct;
  const gapBp = trace.layers.primitives.compareVsBenchmark.evidence.gap;

  // Determine confidence level + backing statement based on branch
  let level = "alta";
  let backing = "";

  // Decline-sano branch (evaluated first to align with composeInterpreta order)
  if (variacion < -5 && gapBp <= 0) {
    level = "media";
    backing = `La caída de volumen es consistente, pero todavía no hay evidencia suficiente para confirmar una tendencia estructural.`;
  }
  // Virtuous branch
  else if (hasHidden && !hasNegative) {
    level = "alta";
    backing = `La combinación de margen, carga comercial y crecimiento de ${trace.client} se sostiene como excepción consistente en el histórico de la cartera.`;
  }
  // High severity actionable branch
  else if (negativeTemplates.some(t => t.severity === "high")) {
    level = "alta";
    backing = `La relación entre carga comercial, benchmark y deterioro de margen se repite consistentemente en el histórico reciente de la cartera.`;
  }
  // Medium severity branch
  else if (negativeTemplates.length >= 2) {
    level = "media";
    backing = `Los indicadores de presión son consistentes con el perfil de la cuenta, aunque la magnitud individual de cada tensión es moderada.`;
  }
  else {
    return null;
  }

  return `*Confianza ${level}. ${backing}*`;
}

// ═══════════════════════════════════════════════════════
// BRIEF #13 · Counterfactual Scenario Composers
//
// Compose responses for "what if I lose X" simulations.
// Five-movement structure paralleling deep dive composer,
// but framed in conditional / future tense.
//
// All numbers come from trace.layers.primitives.evidence
// or from auxiliary computations on the live dataset.
// ═══════════════════════════════════════════════════════

function composeLoseScenario(trace, profile, substMap, totals) {
  const clientName = trace.client;
  const lastPeriod = trace.layers.primitives.compareVsLastPeriod;
  const benchmark = trace.layers.primitives.compareVsBenchmark;
  const concentration = trace.layers.primitives.detectConcentration;
  const leakage = trace.layers.primitives.detectLeakage;

  const ventasM = +(lastPeriod.evidence.actual / 1000).toFixed(1);
  const participacion = concentration.evidence.participacion;
  const totalActual = concentration.evidence.totalActual;
  const totalM = +(totalActual / 1000).toFixed(1);
  const resultM = +((totalActual - lastPeriod.evidence.actual) / 1000).toFixed(1);

  const margenes = applyScenarioToClientesMargen(trace.scenario);
  const m = margenes.find(c => c.nombre === clientName);
  const contribucionM = m ? +(m.contribucion / 1000).toFixed(2) : null;
  const margenPct = benchmark.evidence.margen;
  const benchValue = benchmark.evidence.benchmark;
  const gapBp = benchmark.evidence.gap;
  const isAboveBenchmark = gapBp < 0;
  const carga = leakage.evidence.pctRebate;

  // ─── PERFIL D · TIER 3 CHICO (sin cambios respecto a #13-bis) ─
  if (profile && profile.tier === 3) {
    let m1 = `${clientName} representa solo ${participacion}% de la cartera, por lo que una salida sería absorbible en términos comerciales. El impacto sería cercano a -$${ventasM}M en ventas anuales`;
    if (contribucionM !== null) {
      m1 += ` y aproximadamente -$${contribucionM}M de contribución`;
    }
    m1 += `.`;

    let m2 = "";
    if (isAboveBenchmark) {
      m2 = `La principal pérdida estaría en rentabilidad, no en escala. ${clientName} opera sobre benchmark de cartera (${margenPct}% vs ${benchValue}%) y mantiene calidad de margen`;
      if (lastPeriod.evidence.deltaPct < 0) {
        m2 += ` pese a la caída de volumen`;
      }
      m2 += `.`;
    } else {
      m2 = `La principal pérdida estaría en escala individual del Tier 3, no en margen estructural. ${clientName} opera con margen de ${margenPct}%, ${Math.abs(gapBp)} puntos del benchmark de cartera.`;
    }

    let m3 = "";
    if (substMap.substitutes && substMap.substitutes.length >= 2) {
      const s1 = substMap.substitutes[0];
      const s2 = substMap.substitutes[1];
      m3 = `El reemplazo comercial es factible dentro del Tier 3. ${s1.name} concentra ${s1.currentShare}% de la cartera y ${s2.name} participa con ${s2.currentShare}%, ambas con escala equivalente para absorber el volumen`;
      if (isAboveBenchmark) {
        m3 += `, aunque probablemente con menor calidad de margen relativa`;
      }
      m3 += `.`;
    } else if (substMap.substitutes && substMap.substitutes.length === 1) {
      const s1 = substMap.substitutes[0];
      m3 = `El reemplazo comercial es factible dentro del Tier 3. ${s1.name} concentra ${s1.currentShare}% de la cartera con escala equivalente para absorber el volumen`;
      if (isAboveBenchmark) {
        m3 += `, aunque probablemente con menor calidad de margen relativa`;
      }
      m3 += `.`;
    } else {
      m3 = `El reemplazo comercial es factible dentro del Tier 3, aunque requiere desarrollo activo de cuentas alternativas.`;
    }
    return [m1, m2, m3].join("\n\n");
  }

  // ─── PERFIL A · UNIQUE CHANNEL (cambio léxico: capacidad digital) ─
  if (substMap.isUnique) {
    let m1 = `Una salida de ${clientName} significaría aproximadamente -$${ventasM}M en ventas anuales`;
    if (contribucionM !== null) m1 += ` y -$${contribucionM}M de contribución`;
    m1 += `, equivalente al ${participacion}% del total de la cartera. Las ventas del negocio pasarían de $${totalM}M a $${resultM}M.`;

    const m2 = composeReasoningSentence(trace, profile);

    const m3 = `La cartera hoy no tiene otra cuenta digital con escala comparable para sostener el crecimiento del canal. Una salida de la cuenta representaría pérdida de capacidad digital, no solo de la cuenta.`;

    const m4 = `Sostener ${clientName} es estratégico para preservar el canal, no solo la facturación.`;

    return [m1, m2, m3, m4].join("\n\n");
  }

  // ─── MOVIMIENTO 1 (común a B, C.1, C.2) · IMPACTO CUANTIFICADO ─
  let m1 = `Una salida de ${clientName} significaría aproximadamente -$${ventasM}M en ventas anuales`;
  if (contribucionM !== null) m1 += ` y -$${contribucionM}M de contribución`;
  m1 += `, equivalente al ${participacion}% del total de la cartera. Las ventas del negocio pasarían de $${totalM}M a $${resultM}M.`;

  // ─── PERFIL B · TIER 1 HIGH CONCENTRATION ──────────────
  if (profile && profile.tier === 1) {
    const m2 = composeReasoningSentence(trace, profile);

    let m3 = _composeSubstitutesParagraph(clientName, substMap, margenes, benchValue);

    let m4 = `Reemplazar una salida de ${clientName} requeriría reconstruir aproximadamente $${ventasM}M en ventas`;
    if (margenPct < benchValue) {
      m4 += ` sin replicar el deterioro de margen que hoy ya existe en parte del Tier 1`;
    }
    m4 += `.`;
    return [m1, m2, m3, m4].join("\n\n");
  }

  // ─── PERFIL C.1 · MARGEN COMPRIMIDO TIPO TIER 1 ────────
  // profile.tier === 2 && gapBp >= 6
  if (profile && profile.tier === 2 && gapBp >= 6) {
    let m2 = `El impacto sería material para la cartera, especialmente en términos de rentabilidad. ${clientName} opera con margen de ${margenPct}%, ${gapBp} puntos bajo el benchmark de cartera, y carga comercial de ${carga}%. La cuenta replica el patrón de presión comercial del Tier 1, en menor escala.`;

    let m3 = _composeSubstitutesParagraph(clientName, substMap, margenes, benchValue);

    let m4 = `Una salida de ${clientName} requeriría reemplazo comercial activo en su categoría. La pérdida real estaría en la combinación de volumen y carga comercial elevada, no en margen sano.`;

    return [m1, m2, m3, m4].join("\n\n");
  }

  // ─── PERFIL C.2 · PERFIL SANO TIER 2 ───────────────────
  // profile.tier === 2 && gapBp < 6
  let m2 = `El impacto sería material para la cartera, manejable en términos comerciales. ${clientName} opera con margen de ${margenPct}%`;
  if (gapBp > 0) {
    m2 += `, cerca del benchmark de cartera (${benchValue}%)`;
  } else if (gapBp <= 0) {
    m2 += `, en línea o sobre el benchmark de cartera (${benchValue}%)`;
  }
  m2 += `, y carga comercial controlada (${carga}%). La cuenta tiene perfil sano dentro del Tier 2.`;

  let m3 = _composeSubstitutesParagraph(clientName, substMap, margenes, benchValue);

  let m4 = `Una salida de ${clientName} requeriría reemplazo comercial activo en su categoría, sin presión inmediata sobre la estructura general de la cartera.`;

  return [m1, m2, m3, m4].join("\n\n");
}

// ═══════════════════════════════════════════════════════
// BRIEF #13-ter · Substitutes paragraph helper
//
// Encapsula la lógica de Movement 3 (sustitutos) para que
// Perfiles B, C.1 y C.2 la usen sin duplicar código.
// El cuerpo es idéntico al actual de #13-bis · solo se
// encapsuló como helper.
// ═══════════════════════════════════════════════════════

function _composeSubstitutesParagraph(clientName, substMap, margenes, benchValue) {
  if (substMap.substitutes && substMap.substitutes.length > 0) {
    const subs = substMap.substitutes;
    if (subs.length === 1) {
      const s = subs[0];
      return `El reemplazo natural sería ${s.calificator || "parcial"}. ${s.name} concentra ${s.currentShare}% de la cartera, escala insuficiente para absorber una salida de esta magnitud en el corto plazo.`;
    }
    const s1 = subs[0];
    const s2 = subs[1];
    const s1Margen = margenes.find(c => c.nombre === s1.name);
    const s1HasPressure = s1Margen && s1Margen.margen < benchValue;

    let m3 = `El reemplazo natural sería parcial. ${s1.name} concentra ${s1.currentShare}% de la cartera`;
    if (s1HasPressure) {
      m3 += ` pero opera con la misma presión de margen (${s1Margen.margen}% vs benchmark de ${benchValue}%), por lo que absorber el flujo de ${clientName} no resuelve la rentabilidad estructural`;
    }
    m3 += `. ${s2.name} participa con ${s2.currentShare}%, escala insuficiente para absorber una salida de esta magnitud en el corto plazo.`;
    return m3;
  }
  return `El reemplazo natural de ${clientName} no es evidente con la cartera actual. Una salida exigiría desarrollo de cuentas alternativas con escala equivalente.`;
}

function composeLosePlanB(trace, profile, substMap) {
  const clientName = trace.client;
  const concentration = trace.layers.primitives.detectConcentration;
  const benchmark = trace.layers.primitives.compareVsBenchmark;
  const participacion = concentration.evidence.participacion;
  const gapBp = benchmark.evidence.gap;

  // PERFIL D · TIER 3 CHICO · no Plan B
  if (profile && profile.tier === 3) {
    return null;
  }

  // BRIEF #13-ter · Variación léxica determinística por hash.
  // CERO "**Plan B**" como heading visible. Transiciones por hash
  // del nombre del cliente para que Falabella, Lider y Jumbo
  // (mismo Perfil B) reciban frases distintas.

  // BRANCH A · UNIQUE CHANNEL (Mercado Libre)
  if (substMap.isUnique) {
    const transitions = [
      `La unicidad del canal obliga a actuar antes de que la dependencia se vuelva crítica.`,
      `La ausencia de alternativas equivalentes exige construir capacidad antes de que la dependencia se vuelva crítica.`,
      `Sin reemplazo natural disponible, el negocio debe construir capacidad digital en paralelo a la cuenta.`,
    ];
    const idx = hashClientName(clientName + "_planB_A") % transitions.length;
    const transition = transitions[idx];

    const body = `El foco debería estar en consolidar la posición de ${clientName} mientras se construyen capacidades para diversificar el canal en horizonte de 18-24 meses, evitando perder capacidad de crecimiento digital en la cartera. El principal riesgo es subinvertir en la diversificación del canal por la estabilidad actual de la cuenta, lo que dejaría al negocio expuesto ante cualquier cambio estratégico de ${clientName}.`;

    return `${transition} ${body}`;
  }

  // BRANCH B · TIER 1 HIGH CONCENTRATION (Falabella, Lider, Jumbo)
  if (profile && profile.tier === 1 && participacion >= 15) {
    const transitions = [
      `La dependencia actual obliga a construir alternativas antes de que una salida sea forzada.`,
      `La concentración estructural exige construir alternativas mientras la cuenta sigue activa.`,
      `Reducir la dependencia requiere construir alternativas en paralelo, no en reemplazo reactivo.`,
    ];
    const idx = hashClientName(clientName + "_planB_B") % transitions.length;
    const transition = transitions[idx];

    const body = `El foco debería estar en fortalecer 2-3 cuentas Tier 2 con capacidad de crecer 50-80% en participación durante 18 meses, alcanzando un total combinado equivalente a 8-10pp de la cartera, sin replicar el deterioro de margen del Tier 1. El principal riesgo es ejecutar la diversificación bajo presión reactiva, cuando ya no hay tiempo para construir alternativas con margen sano.`;

    return `${transition} ${body}`;
  }

  // BRANCH C.1 · MARGEN COMPRIMIDO TIPO TIER 1 (Sodimac, Paris, Ripley)
  if (profile && profile.tier === 2 && gapBp >= 6) {
    const transitions = [
      `Recuperar la posición de ${clientName} requiere desarrollo de cuentas con perfil de categoría similar, evitando replicar la carga comercial actual.`,
      `Reemplazar a ${clientName} sin replicar su carga comercial requiere desarrollo activo en su categoría.`,
      `El reemplazo debe construirse evitando la combinación de margen comprimido y carga comercial alta que caracteriza a la cuenta.`,
    ];
    const idx = hashClientName(clientName + "_planB_C1") % transitions.length;
    const transition = transitions[idx];

    const body = `El foco debería estar en identificar 1-2 cuentas Tier 2 con perfil comercial equivalente en su categoría, acelerando su crecimiento en horizonte de 12 meses. El principal riesgo es absorber un cliente equivalente con la misma estructura de carga comercial alta, lo que no mejoraría la rentabilidad estructural.`;

    return `${transition} ${body}`;
  }

  // BRANCH C.2 · PERFIL SANO TIER 2 (Tottus, Easy)
  const transitions = [
    `Recuperar la posición de ${clientName} requiere desarrollo proactivo de cuentas con perfil equivalente.`,
    `El reemplazo natural debe construirse de manera estructurada en su categoría comercial.`,
    `Reemplazar a ${clientName} es factible con desarrollo proactivo de cuentas Tier 2 con perfil similar.`,
  ];
  const idx = hashClientName(clientName + "_planB_C2") % transitions.length;
  const transition = transitions[idx];

  const body = `El foco debería estar en identificar 1-2 cuentas Tier 2 con perfil comercial similar en su categoría, acelerando su desarrollo en horizonte de 12 meses. El principal riesgo es subestimar el tiempo de maduración comercial de las cuentas alternativas, que típicamente requieren 9-12 meses para alcanzar volumen equivalente.`;

  return `${transition} ${body}`;
}

function composeLoseConfianza(trace, profile, substMap) {
  const clientName = trace.client;

  // BRIEF #13-bis · Tier 3 chico tiene Confianza simplificada
  // (sin referencia a Plan B porque no hay Plan B).
  if (profile && profile.tier === 3) {
    return `*Confianza media · la sustitución es cuantificable, pero recuperar el perfil de margen de ${clientName} requiere desarrollo activo del Tier 3, no solo migración de volumen.*`;
  }

  if (substMap.isUnique) {
    return `*Confianza alta · la unicidad estructural del canal de ${clientName} se sostiene como hecho estructural en el escenario activo, sin alternativa equivalente en la cartera actual.*`;
  }

  if (substMap.substitutes && substMap.substitutes.length >= 2) {
    return `*Confianza media · la sustitución parcial es cuantificable, pero la ejecución depende del tiempo de respuesta y de la capacidad comercial de la cartera para absorber el crecimiento incremental.*`;
  }

  return `*Confianza media · el reemplazo natural es limitado en la cartera actual, lo que exige desarrollo activo de alternativas con horizontes de 12-18 meses.*`;
}

// Deterministic hash from clientName to integer.
// Simple djb2-style hash. Same input always returns same output.
function hashClientName(name) {
  let hash = 5381;
  for (let i = 0; i < name.length; i++) {
    hash = ((hash << 5) + hash) + name.charCodeAt(i);
    hash = hash | 0; // Force 32-bit integer
  }
  return Math.abs(hash);
}

// ═══════════════════════════════════════════════════════
// BRIEF #13.5 · Reasoning Sentence Composer
//
// Returns one sentence that communicates HOW ADI prioritized
// the analysis, without exposing the cognitive machinery.
//
// 3 linguistic patterns:
//   · Tensión dominante  → "X porque Y"
//   · Excepción virtuosa → "X, algo poco frecuente"
//   · Decline sano       → "X, por lo que Y"
//
// Within each pattern, 3 variants selected by hash for léxica
// variation between similar clients.
// ═══════════════════════════════════════════════════════

function composeReasoningSentence(trace, profile) {
  const clientName = trace.client;
  const lastPeriod = trace.layers.primitives.compareVsLastPeriod;
  const benchmark = trace.layers.primitives.compareVsBenchmark;
  const variacion = lastPeriod.evidence.deltaPct;
  const gapBp = benchmark.evidence.gap;
  const templates = trace.layers.templates;

  const isVirtuousSideTemplate = (t) => {
    if (t.id === "hidden_profitability") return true;
    if (t.id === "dependency_risk") {
      const ev = t.evidence || {};
      const isUnique = ev.isUnique === true;
      const lowParticipation = (ev.participacion === undefined) || ev.participacion < 15;
      return isUnique && lowParticipation;
    }
    return false;
  };

  const negativeTemplates = templates.filter(t => !isVirtuousSideTemplate(t));
  const hasHidden = templates.some(t => t.id === "hidden_profitability");
  const hasNegative = negativeTemplates.length > 0;

  // ─── PATRÓN 3 · DECLINE SANO ──────────────────────────
  if (variacion < -5 && gapBp <= 0) {
    const variants = [
      `La caída de volumen todavía no deteriora el margen, por lo que la principal lectura sigue estando en la calidad de contribución`,
      `La presión está en volumen pero no en margen, por lo que la lectura principal sigue siendo de rentabilidad estructural`,
      `El margen no se ha visto afectado por la caída de ventas, por lo que la atención debería estar en la calidad de contribución antes que en la escala`,
    ];
    const idx = hashClientName(clientName + "_reasoning_decline") % variants.length;
    return variants[idx] + ".";
  }

  // ─── PATRÓN 2 · EXCEPCIÓN VIRTUOSA ────────────────────
  if (hasHidden && !hasNegative) {
    const variants = [
      `${clientName} destaca por combinar crecimiento alto con carga comercial baja, algo poco frecuente en la cartera actual`,
      `${clientName} sostiene un perfil estructural sano que se diferencia del patrón de presión de Tier 1`,
      `${clientName} mantiene una combinación de margen, carga y crecimiento que no se replica en el resto de la cartera`,
    ];
    const idx = hashClientName(clientName + "_reasoning_virtuous") % variants.length;
    return variants[idx] + ".";
  }

  // ─── PATRÓN 1 · TENSIÓN DOMINANTE ─────────────────────
  if (!hasNegative) {
    return `El perfil comercial es estable, sin tensiones materiales detectadas.`;
  }

  const DOMINANT_PRIORITY = [
    "rebate_leakage", "pricing_pressure", "low_quality_growth",
    "margin_erosion", "benchmark_gap", "dependency_risk",
  ];
  const sortedByPriority = [...negativeTemplates].sort((a, b) => {
    const idxA = DOMINANT_PRIORITY.indexOf(a.id);
    const idxB = DOMINANT_PRIORITY.indexOf(b.id);
    const safeA = idxA === -1 ? 999 : idxA;
    const safeB = idxB === -1 ? 999 : idxB;
    return safeA - safeB;
  });
  const dominant = sortedByPriority[0];

  let variants = [];

  if (["rebate_leakage", "low_quality_growth", "pricing_pressure"].includes(dominant.id)) {
    variants = [
      `La principal presión está en la carga comercial porque hoy es la variable más controlable y la que más deteriora el benchmark`,
      `La carga comercial concentra el problema porque acumula sobre el margen sin retornar volumen incremental al benchmark`,
      `El deterioro del margen se explica principalmente por la carga comercial, que opera por encima de la mejor práctica sin compensar con volumen incremental`,
    ];
  } else if (["margin_erosion", "benchmark_gap"].includes(dominant.id)) {
    variants = [
      `La principal presión está en el margen porque la brecha frente al benchmark de cartera es estructural y comprime la contribución sistemáticamente`,
      `El margen concentra la lectura porque opera por debajo del benchmark de cartera sin ajustes en costo o pricing que compensen`,
      `El gap de margen frente al benchmark es la lectura central, porque la cuenta no captura la rentabilidad promedio de la categoría`,
    ];
  } else if (dominant.id === "dependency_risk") {
    variants = [
      `La exposición de cartera concentra el riesgo porque la participación de la cuenta supera el umbral prudencial de diversificación`,
      `La concentración de la cuenta es la lectura central porque amplifica el impacto de cualquier variación comercial`,
      `La dependencia estructural concentra el riesgo porque reduce el margen de maniobra ante cambios en la relación comercial`,
    ];
  } else {
    variants = [
      `La cuenta presenta presión material en su perfil comercial, lectura que requiere monitoreo activo`,
    ];
  }

  const idx = hashClientName(clientName + "_reasoning_" + dominant.id) % variants.length;
  return variants[idx] + ".";
}

// Select one entry from a pool deterministically.
// salt allows different selections for the same client in different movements.
function selectFromPool(pool, clientName, salt = "") {
  if (!Array.isArray(pool) || pool.length === 0) return "";
  const idx = hashClientName(clientName + salt) % pool.length;
  return pool[idx];
}

// Module adjectives by numerical thresholds.
// The cifra determines the adjective intensity, so the adjective stays
// consistent with the data instead of being fixed text.
// Implements §5.2.2 (Quantified Tone) + §6.2.3 (Benchmark) of the
// Response Composition Constitution.
function moduleAdjective(kind, value) {
  if (value === null || value === undefined) return "";
  switch (kind) {
    case "carga":
      // pctRebate intensity
      if (value >= 5.0) return "elevada";
      if (value >= 4.0) return "alta";
      if (value >= 3.0) return "moderada";
      return "contenida";
    case "gap_benchmark":
      // Distance below benchmark (positive = below)
      if (value >= 8) return "muy bajo";
      if (value >= 4) return "bajo";
      if (value >= 0) return "levemente bajo";
      return "sobre benchmark";
    case "variacion":
      // YoY variation intensity
      if (value >= 20) return "muy fuerte";
      if (value >= 10) return "fuerte";
      if (value >= 0)  return "positiva";
      if (value >= -10) return "negativa";
      return "muy negativa";
    case "tamano_cuenta":
      // Participation share
      if (value >= 15) return "de mayor escala";
      if (value >= 8)  return "de escala media";
      return "de menor escala";
    default:
      return "";
  }
}

// ═══════════════════════════════════════════════════════
// BRIEF #12-C.1 · Template detection engine
//
// Implements the 10 implicit templates of the Response
// Composition Constitution §8.2.
//
// Pure function: receives client + scenario context, returns
// array of templates that apply, ordered by relevance.
//
// Returns: [{ id, name, severity, evidence }]
//   id        · template identifier (e.g., "rebate_leakage")
//   name      · constitutional name (e.g., "Rebate Leakage")
//   severity  · "high" | "medium" | "low"
//   evidence  · object with the metrics that triggered detection
//
// The detection is data-driven: thresholds use live numbers
// from the scenario, never hardcoded conclusions.
// Templates §8.2.2 (Trapped Capital), §8.2.8 (Mix Deterioration)
// and §8.2.10 (Inventory Aging) are not applicable from client
// deep-dive context — they require inventory / sfamilia data.
// ═══════════════════════════════════════════════════════
// detectTemplates · refactored in BRIEF #12-C.2 to consume
// PRIMITIVES + CAUSAL instead of duplicating logic.
// Each template now subscribes to specific primitives/causals
// and surfaces severity + evidence.
function detectTemplates(clientName, scenarioId) {
  const templates = [];

  // §8.2.1 · Margin Erosion → consumes detectErosion primitive
  const erosion = PRIMITIVES.detectErosion(clientName, scenarioId);
  if (erosion.triggered) {
    templates.push({
      id: "margin_erosion",
      name: "Margin Erosion",
      severity: erosion.severity,
      evidence: erosion.evidence,
      driven_by: ["detectErosion"],
    });
  }

  // §8.2.3 · Benchmark Gap → suppressed if margin_erosion already fired
  // (both have same root cause, avoid double-reporting)
  const benchmark = PRIMITIVES.compareVsBenchmark(clientName, scenarioId);
  if (benchmark.triggered && benchmark.evidence.position === "below"
      && !templates.find(t => t.id === "margin_erosion")) {
    templates.push({
      id: "benchmark_gap",
      name: "Benchmark Gap",
      severity: benchmark.severity,
      evidence: benchmark.evidence,
      driven_by: ["compareVsBenchmark"],
    });
  }

  // §8.2.4 · Rebate Leakage → consumes detectLeakage primitive
  const leakage = PRIMITIVES.detectLeakage(clientName, scenarioId);
  if (leakage.triggered) {
    templates.push({
      id: "rebate_leakage",
      name: "Rebate Leakage",
      severity: leakage.severity,
      evidence: leakage.evidence,
      driven_by: ["detectLeakage"],
    });
  }

  // §8.2.5 · Dependency Risk → consumes CAUSAL.dependencyRisk
  const depRisk = CAUSAL.dependencyRisk(clientName, scenarioId);
  if (depRisk.triggered) {
    templates.push({
      id: "dependency_risk",
      name: "Dependency Risk",
      severity: depRisk.severity,
      evidence: depRisk.evidence,
      driven_by: depRisk.primitives_involved,
    });
  }

  // §8.2.6 · Hidden Profitability → consumes detectHiddenProfitability primitive
  // (now with PATH A + PATH B threshold from #12-C.1 audit)
  const hidden = PRIMITIVES.detectHiddenProfitability(clientName, scenarioId);
  if (hidden.triggered) {
    templates.push({
      id: "hidden_profitability",
      name: "Hidden Profitability",
      severity: hidden.severity,
      evidence: hidden.evidence,
      driven_by: ["detectHiddenProfitability"],
    });
  }

  // §8.2.7 · Low Quality Growth → consumes CAUSAL.lowQualityGrowth
  const lqg = CAUSAL.lowQualityGrowth(clientName, scenarioId);
  if (lqg.triggered) {
    templates.push({
      id: "low_quality_growth",
      name: "Low Quality Growth",
      severity: lqg.severity,
      evidence: lqg.evidence,
      driven_by: lqg.primitives_involved,
    });
  }

  // §8.2.9 · Pricing Pressure → consumes CAUSAL.marginCompression
  const pricing = CAUSAL.marginCompression(clientName, scenarioId);
  if (pricing.triggered) {
    templates.push({
      id: "pricing_pressure",
      name: "Pricing Pressure",
      severity: pricing.severity,
      evidence: pricing.evidence,
      driven_by: pricing.primitives_involved,
    });
  }

  // §8.2.2 · Trapped Capital, §8.2.8 · Mix Deterioration, §8.2.10 · Inventory Aging
  // Not applicable at client deep-dive level. Skipped.

  // Sort by severity: high > medium > low
  const severityOrder = { high: 0, medium: 1, low: 2 };
  templates.sort((a, b) => severityOrder[a.severity] - severityOrder[b.severity]);

  return templates;
}

// ═══════════════════════════════════════════════════════
// BRIEF #12-C.2 · Reasoning Primitives Namespace
//
// Implements the 14 atomic reasoning primitives defined in
// Executive Reasoning Constitution §3.2. Each primitive is
// a pure function that:
//   · Receives clientName + scenarioId
//   · Returns { triggered, severity, confidence, evidence, silent_reason }
//   · NEVER invents data
//   · STAYS SILENT when data insufficient (triggered=false + silent_reason)
//   · Reads ALL numbers from the live dataset
//
// Primitives are atomic: they do not call other primitives.
// Composition into causal patterns happens in CAUSAL layer.
// ═══════════════════════════════════════════════════════

const PRIMITIVES = {

  // §3.2.1 · COMPARE_VS_LASTPERIOD
  // Detects delta between current period and prior year.
  compareVsLastPeriod(clientName, scenarioId) {
    const ventas = applyScenarioToClientesVentas(scenarioId);
    const v = ventas.find(c => c.nombre === clientName);
    if (!v) return { triggered: false, severity: null, confidence: "high", evidence: {}, silent_reason: "client not in dataset" };

    const delta    = v.actual - v.anterior;
    const deltaPct = (delta / v.anterior) * 100;
    const absMaterial = Math.abs(deltaPct) >= 3; // 3% materiality threshold

    return {
      triggered: absMaterial,
      severity: Math.abs(deltaPct) >= 10 ? "high" : Math.abs(deltaPct) >= 3 ? "medium" : "low",
      confidence: "high",
      evidence: {
        actual: v.actual,
        anterior: v.anterior,
        delta: delta,
        deltaPct: +deltaPct.toFixed(1),
        direction: deltaPct >= 0 ? "growth" : "decline",
      },
      silent_reason: absMaterial ? null : "delta below materiality threshold (<3%)",
    };
  },

  // §3.2.2 · COMPARE_VS_BUDGET
  // Detects variance between actual and budgeted target.
  compareVsBudget(clientName, scenarioId) {
    const ventas = applyScenarioToClientesVentas(scenarioId);
    const v = ventas.find(c => c.nombre === clientName);
    if (!v) return { triggered: false, severity: null, confidence: "high", evidence: {}, silent_reason: "client not in dataset" };
    if (!v.presupuesto) return { triggered: false, severity: null, confidence: "low", evidence: {}, silent_reason: "no budget data" };

    const variance    = v.actual - v.presupuesto;
    const variancePct = (variance / v.presupuesto) * 100;
    const material    = Math.abs(variancePct) >= 5; // 5% materiality for budget

    return {
      triggered: material,
      severity: Math.abs(variancePct) >= 10 ? "high" : "medium",
      confidence: "high",
      evidence: {
        actual: v.actual,
        budget: v.presupuesto,
        variance: variance,
        variancePct: +variancePct.toFixed(1),
        favorable: variance >= 0,
      },
      silent_reason: material ? null : "variance below materiality threshold (<5%)",
    };
  },

  // §3.2.3 · COMPARE_VS_BENCHMARK
  // Detects positioning against category/market norm.
  compareVsBenchmark(clientName, scenarioId) {
    const margenes = applyScenarioToClientesMargen(scenarioId);
    const m = margenes.find(c => c.nombre === clientName);
    if (!m) return { triggered: false, severity: null, confidence: "high", evidence: {}, silent_reason: "client not in margin dataset" };

    const benchmark = m.benchmark || 30.1;
    const gap       = benchmark - m.margen;  // positive = below benchmark
    const material  = Math.abs(gap) >= 2;    // 2pp materiality

    return {
      triggered: material,
      severity: Math.abs(gap) >= 8 ? "high" : Math.abs(gap) >= 4 ? "medium" : "low",
      confidence: "high",
      evidence: {
        margen: m.margen,
        benchmark: benchmark,
        gap: +gap.toFixed(1),
        position: gap > 0 ? "below" : gap < 0 ? "above" : "at",
      },
      silent_reason: material ? null : "gap below materiality threshold (<2pp)",
    };
  },

  // §3.2.4 · DETECT_CONCENTRATION
  // Identifies business dependency on a customer.
  detectConcentration(clientName, scenarioId) {
    const ventas = applyScenarioToClientesVentas(scenarioId);
    const v = ventas.find(c => c.nombre === clientName);
    if (!v) return { triggered: false, severity: null, confidence: "high", evidence: {}, silent_reason: "client not in dataset" };

    const totalActual   = ventas.reduce((s, c) => s + c.actual, 0);
    const participacion = (v.actual / totalActual) * 100;
    const material      = participacion >= 8; // 8% materiality for concentration

    return {
      triggered: material,
      severity: participacion >= 18 ? "high" : participacion >= 12 ? "medium" : "low",
      confidence: "high",
      evidence: {
        participacion: +participacion.toFixed(1),
        actual: v.actual,
        totalActual: totalActual,
      },
      silent_reason: material ? null : "participation below materiality threshold (<8%)",
    };
  },

  // §3.2.5 · DETECT_EROSION
  // Identifies margin or pricing deterioration.
  // For client-level: erosion = margin gap below benchmark + (optional) rebate climbing.
  detectErosion(clientName, scenarioId) {
    const margenes = applyScenarioToClientesMargen(scenarioId);
    const m = margenes.find(c => c.nombre === clientName);
    if (!m) return { triggered: false, severity: null, confidence: "medium", evidence: {}, silent_reason: "client not in margin dataset" };

    const benchmark = m.benchmark || 30.1;
    const gap       = benchmark - m.margen;
    const eroded    = gap >= 4; // 4pp threshold for erosion

    return {
      triggered: eroded,
      severity: gap >= 8 ? "high" : "medium",
      confidence: "medium", // medium because true erosion requires time-series; we approximate via gap
      evidence: {
        margen: m.margen,
        benchmark: benchmark,
        gap: +gap.toFixed(1),
      },
      silent_reason: eroded ? null : "margin within benchmark band",
    };
  },

  // §3.2.6 · DETECT_CAUSALRELATION
  // Identifies cause-effect relationships. At primitive level, returns
  // candidate pairs of observed metrics that suggest causality.
  // CAUSAL layer composes these into named relations.
  detectCausalRelation(clientName, scenarioId) {
    const ventas   = applyScenarioToClientesVentas(scenarioId);
    const margenes = applyScenarioToClientesMargen(scenarioId);
    const v = ventas.find(c => c.nombre === clientName);
    const m = margenes.find(c => c.nombre === clientName);
    if (!v || !m) return { triggered: false, severity: null, confidence: "low", evidence: {}, silent_reason: "incomplete data for causal analysis" };

    const variacion = ((v.actual - v.anterior) / v.anterior) * 100;
    const gap       = (m.benchmark || 30.1) - m.margen;
    const carga     = v.pctRebate;

    // Surface signals that pair (CAUSAL layer interprets them)
    const signals = [];
    if (variacion >= 5 && gap >= 4) signals.push("sales_growth_with_margin_gap");
    if (carga >= 4 && gap >= 4)     signals.push("high_rebate_with_margin_gap");
    if (variacion < 0 && carga >= 4) signals.push("decline_with_sustained_rebate");

    return {
      triggered: signals.length > 0,
      severity: signals.length >= 2 ? "high" : signals.length === 1 ? "medium" : null,
      confidence: "medium",
      evidence: {
        signals: signals,
        variacion: +variacion.toFixed(1),
        gap: +gap.toFixed(1),
        carga: +carga.toFixed(1),
      },
      silent_reason: signals.length === 0 ? "no causal signals detected" : null,
    };
  },

  // §3.2.7 · DETECT_TRADEOFF
  // Identifies inverse relationships (e.g., volume up but margin down).
  detectTradeoff(clientName, scenarioId) {
    const ventas   = applyScenarioToClientesVentas(scenarioId);
    const margenes = applyScenarioToClientesMargen(scenarioId);
    const v = ventas.find(c => c.nombre === clientName);
    const m = margenes.find(c => c.nombre === clientName);
    if (!v || !m) return { triggered: false, severity: null, confidence: "low", evidence: {}, silent_reason: "incomplete data" };

    const variacion = ((v.actual - v.anterior) / v.anterior) * 100;
    const gap       = (m.benchmark || 30.1) - m.margen;
    // Tradeoff: sales growth + margin below benchmark + high rebate
    const tradeoff = variacion >= 5 && gap >= 4 && v.pctRebate >= 4;

    return {
      triggered: tradeoff,
      severity: tradeoff ? (variacion >= 10 ? "high" : "medium") : null,
      confidence: "medium",
      evidence: {
        variacion: +variacion.toFixed(1),
        gap: +gap.toFixed(1),
        carga: +v.pctRebate.toFixed(1),
        tradeoff_axis: tradeoff ? "volume_vs_profitability" : null,
      },
      silent_reason: tradeoff ? null : "no significant tradeoff detected",
    };
  },

  // §3.2.8 · DETECT_ANOMALY
  // Identifies outliers vs cartera average.
  detectAnomaly(clientName, scenarioId) {
    const ventas = applyScenarioToClientesVentas(scenarioId);
    const v = ventas.find(c => c.nombre === clientName);
    if (!v) return { triggered: false, severity: null, confidence: "high", evidence: {}, silent_reason: "client not in dataset" };

    // Compute cartera average pctRebate (excluding this client)
    const others = ventas.filter(c => c.nombre !== clientName);
    const avgRebate = others.reduce((s, c) => s + c.pctRebate, 0) / others.length;
    const deviation = v.pctRebate - avgRebate;
    const anomalous = Math.abs(deviation) >= 1.5; // 1.5pp from cartera average

    return {
      triggered: anomalous,
      severity: Math.abs(deviation) >= 2.5 ? "high" : "medium",
      confidence: "medium",
      evidence: {
        pctRebate: +v.pctRebate.toFixed(1),
        avgCarteraRebate: +avgRebate.toFixed(2),
        deviation: +deviation.toFixed(2),
        direction: deviation > 0 ? "above_average" : "below_average",
      },
      silent_reason: anomalous ? null : "rebate within cartera band",
    };
  },

  // §3.2.9 · DETECT_MIXSHIFT
  // At client level: detect if client's sfamilia composition is structurally
  // shifting the cartera mix. For deep-dive, returns position in sfamilia.
  detectMixShift(clientName, scenarioId) {
    const ventas = applyScenarioToClientesVentas(scenarioId);
    const v = ventas.find(c => c.nombre === clientName);
    if (!v) return { triggered: false, severity: null, confidence: "low", evidence: {}, silent_reason: "client not in dataset" };

    // Calculate share within client's sfamilia
    const sameSfamilia = ventas.filter(c => c.sfamilia === v.sfamilia);
    const sfamiliaTotal = sameSfamilia.reduce((s, c) => s + c.actual, 0);
    const shareInSfamilia = (v.actual / sfamiliaTotal) * 100;

    // Mix shift is silent at client level — meaningful at sfamilia aggregate.
    // We surface position only as low-confidence evidence.
    return {
      triggered: false, // Always silent at client level
      severity: null,
      confidence: "low",
      evidence: {
        sfamilia: v.sfamilia,
        shareInSfamilia: +shareInSfamilia.toFixed(1),
      },
      silent_reason: "mix shift detection requires sfamilia-level aggregation (not client-level)",
    };
  },

  // §3.2.10 · DETECT_TRAPPEDCAPITAL
  // Working capital locked in inventory. NOT available at client deep-dive
  // (requires inventory data per client which dataset does not expose).
  detectTrappedCapital(clientName, scenarioId) {
    return {
      triggered: false,
      severity: null,
      confidence: "low",
      evidence: {},
      silent_reason: "trapped capital detection requires inventory-level data not available at client deep-dive",
    };
  },

  // §3.2.11 · DETECT_HIDDENPROFITABILITY
  // Identifies profit pockets. Two paths:
  //   PATH A: margin >= benchmark (classic hidden profitability)
  //   PATH B: structurally virtuous profile (margin near benchmark + low rebate + strong growth)
  // This implements the threshold extension discussed in audit of #12-C.1.
  detectHiddenProfitability(clientName, scenarioId) {
    const ventas   = applyScenarioToClientesVentas(scenarioId);
    const margenes = applyScenarioToClientesMargen(scenarioId);
    const v = ventas.find(c => c.nombre === clientName);
    const m = margenes.find(c => c.nombre === clientName);
    if (!v || !m) return { triggered: false, severity: null, confidence: "high", evidence: {}, silent_reason: "incomplete data" };

    const benchmark    = m.benchmark || 30.1;
    const variacion    = ((v.actual - v.anterior) / v.anterior) * 100;
    const totalActual  = ventas.reduce((s, c) => s + c.actual, 0);
    const participacion = (v.actual / totalActual) * 100;

    // PATH A: classic hidden profitability — margin above benchmark
    const pathA = m.margen >= benchmark;
    // PATH B: structurally virtuous — margin near benchmark + low rebate + strong growth
    const pathB = m.margen >= benchmark - 2 && v.pctRebate < 2.5 && variacion >= 10;

    const triggered = pathA || pathB;

    return {
      triggered: triggered,
      severity: pathA && m.margen >= benchmark + 3 ? "high"
              : triggered ? "medium" : null,
      confidence: "high",
      evidence: {
        margen: m.margen,
        benchmark: benchmark,
        marginPremium: +(m.margen - benchmark).toFixed(1),
        pctRebate: +v.pctRebate.toFixed(1),
        variacion: +variacion.toFixed(1),
        participacion: +participacion.toFixed(1),
        detected_via: pathA ? "classic" : pathB ? "structural_virtue" : null,
      },
      silent_reason: triggered ? null : "no hidden profitability pattern detected",
    };
  },

  // §3.2.12 · DETECT_LEAKAGE
  // Profit/margin leakage. At client level: rebate as % of sales vs best practice.
  detectLeakage(clientName, scenarioId) {
    const ventas = applyScenarioToClientesVentas(scenarioId);
    const v = ventas.find(c => c.nombre === clientName);
    if (!v) return { triggered: false, severity: null, confidence: "high", evidence: {}, silent_reason: "client not in dataset" };

    const bestPracticeRebate = 3.0; // constitutional reference
    const leakagePp = v.pctRebate - bestPracticeRebate;
    const leakage = leakagePp >= 1.0; // 1pp threshold for leakage

    return {
      triggered: leakage,
      severity: leakagePp >= 2.0 ? "high" : "medium",
      confidence: "high",
      evidence: {
        pctRebate: +v.pctRebate.toFixed(1),
        bestPractice: bestPracticeRebate,
        leakagePp: +leakagePp.toFixed(1),
        leakageAbsolute: Math.round(v.actual * leakagePp / 100), // approx $K leakage
      },
      silent_reason: leakage ? null : "rebate at or below best practice",
    };
  },

  // §3.2.13 · DETECT_DEPENDENCYRISK
  // Excessive reliance on a single customer.
  detectDependencyRisk(clientName, scenarioId) {
    const ventas = applyScenarioToClientesVentas(scenarioId);
    const v = ventas.find(c => c.nombre === clientName);
    if (!v) return { triggered: false, severity: null, confidence: "high", evidence: {}, silent_reason: "client not in dataset" };

    const totalActual   = ventas.reduce((s, c) => s + c.actual, 0);
    const participacion = (v.actual / totalActual) * 100;
    const substMap      = getSubstitutionMap(clientName, scenarioId);
    const isUnique      = substMap.isUnique;

    // Risk if: high participation (>= 15%) OR unique customer with no substitute
    const risk = participacion >= 15 || isUnique;

    return {
      triggered: risk,
      severity: participacion >= 18 ? "high"
              : (isUnique || participacion >= 15) ? "medium" : null,
      confidence: "high",
      evidence: {
        participacion: +participacion.toFixed(1),
        isUnique: isUnique,
        uniqueReason: isUnique ? (substMap.uniqueReason || null) : null,
      },
      silent_reason: risk ? null : "participation below threshold and substitutes available",
    };
  },

  // §3.2.14 · DETECT_GROWTHDETERIORATION
  // Quality of growth: sales up + margin below benchmark = low quality.
  detectGrowthDeterioration(clientName, scenarioId) {
    const ventas   = applyScenarioToClientesVentas(scenarioId);
    const margenes = applyScenarioToClientesMargen(scenarioId);
    const v = ventas.find(c => c.nombre === clientName);
    const m = margenes.find(c => c.nombre === clientName);
    if (!v || !m) return { triggered: false, severity: null, confidence: "low", evidence: {}, silent_reason: "incomplete data" };

    const variacion = ((v.actual - v.anterior) / v.anterior) * 100;
    const gap       = (m.benchmark || 30.1) - m.margen;
    // Low quality growth: client is growing, but margin is below benchmark
    const deterioration = variacion >= 5 && gap >= 4;

    return {
      triggered: deterioration,
      severity: deterioration ? (variacion >= 10 && gap >= 6 ? "high" : "medium") : null,
      confidence: "high",
      evidence: {
        variacion: +variacion.toFixed(1),
        margen: m.margen,
        gap: +gap.toFixed(1),
        quality: deterioration ? "low" : "acceptable",
      },
      silent_reason: deterioration ? null : "growth quality acceptable or no growth",
    };
  },
};

// ═══════════════════════════════════════════════════════
// BRIEF #12-C.2 · Causal Relations Namespace
//
// Implements the 5 cross-domain causal relationships defined
// in Executive Reasoning Constitution §4.2.
//
// Each causal relation COMPOSES 2-3 primitives into a named
// business pattern. Causals do not have their own logic for
// reading data — they orchestrate primitives.
// ═══════════════════════════════════════════════════════

const CAUSAL = {

  // §4.2.1 · Sales Growth + Contribution Decline = Low Quality Growth
  lowQualityGrowth(clientName, scenarioId) {
    const lastPeriod = PRIMITIVES.compareVsLastPeriod(clientName, scenarioId);
    const benchmark  = PRIMITIVES.compareVsBenchmark(clientName, scenarioId);
    const growthQual = PRIMITIVES.detectGrowthDeterioration(clientName, scenarioId);

    const triggered = growthQual.triggered;
    return {
      triggered: triggered,
      severity: growthQual.severity,
      confidence: "high",
      evidence: {
        variation: lastPeriod.evidence.deltaPct,
        marginGap: benchmark.evidence.gap,
        quality: growthQual.evidence.quality,
      },
      primitives_involved: ["compareVsLastPeriod", "compareVsBenchmark", "detectGrowthDeterioration"],
      silent_reason: triggered ? null : "no low-quality growth pattern",
    };
  },

  // §4.2.2 · Rebates Up + Margin Down = Commercial Erosion
  commercialErosion(clientName, scenarioId) {
    const leakage   = PRIMITIVES.detectLeakage(clientName, scenarioId);
    const erosion   = PRIMITIVES.detectErosion(clientName, scenarioId);

    const triggered = leakage.triggered && erosion.triggered;
    return {
      triggered: triggered,
      severity: triggered ? (leakage.severity === "high" || erosion.severity === "high" ? "high" : "medium") : null,
      confidence: "high",
      evidence: {
        pctRebate: leakage.evidence.pctRebate,
        bestPractice: leakage.evidence.bestPractice,
        leakagePp: leakage.evidence.leakagePp,
        marginGap: erosion.evidence.gap,
      },
      primitives_involved: ["detectLeakage", "detectErosion"],
      silent_reason: triggered ? null : "no commercial erosion pattern (requires both leakage and erosion)",
    };
  },

  // §4.2.3 · Inventory Up + Flat Sell-Out = Trapped Capital
  // NOT applicable at client deep-dive level. Stub returns silent.
  trappedCapital(clientName, scenarioId) {
    return {
      triggered: false,
      severity: null,
      confidence: "low",
      evidence: {},
      primitives_involved: ["detectTrappedCapital"],
      silent_reason: "trapped capital is inventory-level pattern, not client-level",
    };
  },

  // §4.2.4 · Customer Concentration → Dependency Risk
  dependencyRisk(clientName, scenarioId) {
    const concentration = PRIMITIVES.detectConcentration(clientName, scenarioId);
    const dependency    = PRIMITIVES.detectDependencyRisk(clientName, scenarioId);

    const triggered = dependency.triggered;
    return {
      triggered: triggered,
      severity: dependency.severity,
      confidence: "high",
      evidence: {
        participacion: dependency.evidence.participacion,
        isUnique: dependency.evidence.isUnique,
        uniqueReason: dependency.evidence.uniqueReason,
      },
      primitives_involved: ["detectConcentration", "detectDependencyRisk"],
      silent_reason: triggered ? null : "no dependency risk pattern",
    };
  },

  // §4.2.5 · Pricing Below Benchmark + Rising Costs = Margin Compression
  // At client level, approximated by: benchmark gap + leakage (the rebate
  // proxy for cost-of-business with the client).
  marginCompression(clientName, scenarioId) {
    const benchmark = PRIMITIVES.compareVsBenchmark(clientName, scenarioId);
    const leakage   = PRIMITIVES.detectLeakage(clientName, scenarioId);
    const tradeoff  = PRIMITIVES.detectTradeoff(clientName, scenarioId);

    const triggered = benchmark.triggered && benchmark.evidence.position === "below"
                   && (leakage.triggered || tradeoff.triggered);
    return {
      triggered: triggered,
      severity: triggered ? (benchmark.severity === "high" ? "high" : "medium") : null,
      confidence: "medium",
      evidence: {
        marginGap: benchmark.evidence.gap,
        leakagePresent: leakage.triggered,
        tradeoffPresent: tradeoff.triggered,
      },
      primitives_involved: ["compareVsBenchmark", "detectLeakage", "detectTradeoff"],
      silent_reason: triggered ? null : "no margin compression pattern",
    };
  },
};

// ═══════════════════════════════════════════════════════
// BRIEF #15 · Mechanism Registry
//
// Los 5 mecanismos económicos formalizados por §4 Executive
// Reasoning como entidades de primera clase del motor.
// ═══════════════════════════════════════════════════════

const MECHANISM_REGISTRY = {
  commercial_erosion: {
    id: "commercial_erosion",
    nombre: "erosión comercial",
    nombre_capitalizado: "Erosión comercial",
    clausula: "§4.2.2",
    descripcion_humana: "La presión aparece cuando la carga comercial aumenta más rápido que el margen que genera",

    detect: function(clientName, scenarioId) {
      const benchmark = PRIMITIVES.compareVsBenchmark(clientName, scenarioId);
      const leakage = PRIMITIVES.detectLeakage(clientName, scenarioId);
      return benchmark.triggered &&
             benchmark.evidence.position === "below" &&
             leakage.triggered;
    },

    gatherEvidence: function(clientName, scenarioId) {
      const benchmark = PRIMITIVES.compareVsBenchmark(clientName, scenarioId);
      const leakage = PRIMITIVES.detectLeakage(clientName, scenarioId);
      const ventas = applyScenarioToClientesVentas(scenarioId);
      const margenes = applyScenarioToClientesMargen(scenarioId);
      const cliente = ventas.find(c => c.nombre === clientName);
      const margenCliente = margenes.find(c => c.nombre === clientName);

      if (!cliente || !margenCliente) return null;

      const bestPractice = 3.0;
      const gap_carga_pp = leakage.evidence.pctRebate - bestPractice;
      const target_carga = 3.5;
      const recuperable_at_target = gap_carga_pp > 0 && leakage.evidence.pctRebate > target_carga
        ? ((leakage.evidence.pctRebate - target_carga) / 100) * cliente.actual
        : 0;
      const recuperable_at_bestPractice = (gap_carga_pp / 100) * cliente.actual;

      return {
        clientName,
        ventas_M: +(cliente.actual / 1000).toFixed(2),
        margen_pct: margenCliente.margen,
        gap_margen_pp: +(benchmark.evidence.gap).toFixed(1),
        carga_pct: leakage.evidence.pctRebate,
        gap_carga_pp: +gap_carga_pp.toFixed(1),
        bestPractice_pct: bestPractice,
        recuperable_at_target_3_5: Math.round(recuperable_at_target),
        recuperable_at_bestPractice_3_0: Math.round(recuperable_at_bestPractice),
        contribucion_M: +(margenCliente.contribucion / 1000).toFixed(2),
      };
    },

    severityOfInstance: function(instance) {
      if (instance.gap_carga_pp >= 1.5 && instance.gap_margen_pp >= 6) return "alta";
      if (instance.gap_carga_pp >= 1.0 || instance.gap_margen_pp >= 4) return "media";
      return "baja";
    },

    relations: {
      quality_of_growth_deterioration: "causal_proximal",
    },
  },

  quality_of_growth_deterioration: {
    id: "quality_of_growth_deterioration",
    nombre: "deterioro de calidad de crecimiento",
    nombre_capitalizado: "Deterioro de calidad de crecimiento",
    clausula: "§4.2.1",
    descripcion_humana: "El crecimiento se captura a costa del margen unitario",

    detect: function(clientName, scenarioId) {
      const lastPeriod = PRIMITIVES.compareVsLastPeriod(clientName, scenarioId);
      const benchmark = PRIMITIVES.compareVsBenchmark(clientName, scenarioId);
      return lastPeriod.triggered &&
             lastPeriod.evidence.deltaPct > 3 &&
             benchmark.triggered &&
             benchmark.evidence.position === "below" &&
             benchmark.evidence.gap >= 4;
    },

    gatherEvidence: function(clientName, scenarioId) {
      const lastPeriod = PRIMITIVES.compareVsLastPeriod(clientName, scenarioId);
      const benchmark = PRIMITIVES.compareVsBenchmark(clientName, scenarioId);
      const ventas = applyScenarioToClientesVentas(scenarioId);
      const margenes = applyScenarioToClientesMargen(scenarioId);
      const cliente = ventas.find(c => c.nombre === clientName);
      const margenCliente = margenes.find(c => c.nombre === clientName);

      if (!cliente || !margenCliente) return null;

      const crecimiento_M = +((cliente.actual - cliente.anterior) / 1000).toFixed(2);
      const benchmark_pct = 30.1;
      const contrib_teorica = (cliente.actual * benchmark_pct) / 100 / 1000;
      const contrib_real = margenCliente.contribucion / 1000;
      const contribucion_perdida = +(contrib_teorica - contrib_real).toFixed(2);

      return {
        clientName,
        ventas_M: +(cliente.actual / 1000).toFixed(2),
        crecimiento_pct: lastPeriod.evidence.deltaPct,
        crecimiento_M: crecimiento_M,
        margen_pct: margenCliente.margen,
        benchmark_pct: benchmark_pct,
        gap_margen_pp: +benchmark.evidence.gap.toFixed(1),
        contribucion_perdida_M: contribucion_perdida,
      };
    },

    severityOfInstance: function(instance) {
      if (instance.crecimiento_pct >= 10 && instance.gap_margen_pp >= 6) return "alta";
      if (instance.crecimiento_pct >= 5 || instance.gap_margen_pp >= 4) return "media";
      return "baja";
    },

    relations: {
      commercial_erosion: "causal_consequence",
    },
  },

  customer_dependency_risk: {
    id: "customer_dependency_risk",
    nombre: "riesgo de dependencia de cliente",
    nombre_capitalizado: "Riesgo de dependencia de cliente",
    clausula: "§4.2.4",
    descripcion_humana: "La concentración aumenta el costo de cualquier pérdida estructural",

    detect: function(clientName, scenarioId) {
      const concentration = PRIMITIVES.detectConcentration(clientName, scenarioId);
      return concentration.triggered && concentration.evidence.participacion >= 10;
    },

    gatherEvidence: function(clientName, scenarioId) {
      const concentration = PRIMITIVES.detectConcentration(clientName, scenarioId);
      const ventas = applyScenarioToClientesVentas(scenarioId);
      const margenes = applyScenarioToClientesMargen(scenarioId);
      const cliente = ventas.find(c => c.nombre === clientName);
      const margenCliente = margenes.find(c => c.nombre === clientName);

      if (!cliente || !margenCliente) return null;

      return {
        clientName,
        ventas_M: +(cliente.actual / 1000).toFixed(2),
        participacion_pct: concentration.evidence.participacion,
        contribucion_M: +(margenCliente.contribucion / 1000).toFixed(2),
        contribucion_expuesta_M: +(margenCliente.contribucion / 1000).toFixed(2),
      };
    },

    severityOfInstance: function(instance) {
      if (instance.participacion_pct >= 15) return "alta";
      if (instance.participacion_pct >= 10) return "media";
      return "baja";
    },

    relations: {},
  },

  trapped_capital: {
    id: "trapped_capital",
    nombre: "capital atrapado",
    nombre_capitalizado: "Capital atrapado",
    clausula: "§4.2.3",
    descripcion_humana: "El inventario congela liquidez sin retornar al ciclo comercial",
    detect: function(clientName, scenarioId) { return false; },
    gatherEvidence: function(clientName, scenarioId) { return null; },
    severityOfInstance: function(instance) { return "baja"; },
    relations: { liquidity_compression: "causal_proximal" },
  },

  liquidity_compression: {
    id: "liquidity_compression",
    nombre: "compresión de liquidez",
    nombre_capitalizado: "Compresión de liquidez",
    clausula: "§4.2.5",
    descripcion_humana: "El flujo de caja se comprime cuando capital de trabajo absorbe más recursos de los esperados",
    detect: function(clientName, scenarioId) { return false; },
    gatherEvidence: function(clientName, scenarioId) { return null; },
    severityOfInstance: function(instance) { return "baja"; },
    relations: {},
  },
};

// ═══════════════════════════════════════════════════════
// deriveBusinessThesis · MOTOR DE TESIS DE NEGOCIO (THESIS_ENGINE · determinístico)
// Detecta 4 patrones (P1-P4), aplica dominancia (causal→raíz / independiente→severidad)
// y corona la tesis como OBJETO (fuente de verdad · el render es brief aparte).
// 100% atado a dato · nada recitado. Reusa PERFIL_BRIEF_MATERIALITY (taxonomía + dominancia
// + mapa causal). NO toca composers/jerarquía/ejes/guion · solo consume y AGREGA.
// _resolveThesisDominance es el núcleo PURO (testeable con detectores sintéticos · T2/T3/T5/T9).
// ═══════════════════════════════════════════════════════

// Núcleo PURO de dominancia · recibe detectores {P1,P2,P3,P4} y corona. Sin I/O ni scenario.
// Cada detector: { patron, activo, entities:[...], magnitud_K:<$K>, naturaleza:<"flujo"|"exposicion"|"stock"> }
function _resolveThesisDominance(detectores) {
  const { P1, P2, P3, P4 } = detectores;
  const activos = [P1, P2, P3, P4].filter(p => p && p.activo);
  const _inter = (a, b) => { const s = new Set(b || []); return (a || []).filter(x => s.has(x)); };

  let titular = "ninguno", requires_review = false, es_causal = false, raiz = null;
  let sintomas = [], secundarios = [];

  // ── 2a · CAUSAL · dependencia (P2) es RAÍZ si comparte cuentas con erosión (P3) o baja_calidad (P1) ──
  if (P2 && P2.activo) {
    const causados = [];
    if (P3 && P3.activo && _inter(P2.entities, P3.entities).length > 0) causados.push(P3);
    if (P1 && P1.activo && _inter(P2.entities, P1.entities).length > 0) causados.push(P1);
    if (causados.length > 0) {
      es_causal = true;
      titular = "dependencia";
      raiz = "dependencia";
      sintomas = causados.map(p => p.patron);
      secundarios = activos.filter(p => p !== P2 && !causados.includes(p)).map(p => p.patron);
    }
  }

  // ── 2b · SEVERIDAD (sin causalidad) · corona SOLO si naturaleza comparable u orden evidente ──
  if (!es_causal) {
    if (activos.length === 0) {
      titular = "ninguno";
    } else if (activos.length === 1) {
      titular = activos[0].patron;
    } else {
      const byMag = [...activos].sort((a, b) => (b.magnitud_K || 0) - (a.magnitud_K || 0));
      const naturalezas = new Set(activos.map(p => p.naturaleza));
      // orden evidente = el mayor ≥ 3× el segundo (diferencia de orden · misma unidad $K)
      const ordenEvidente = byMag.length >= 2 && (byMag[1].magnitud_K || 0) > 0 &&
        (byMag[0].magnitud_K || 0) >= 3 * (byMag[1].magnitud_K || 0);
      if (naturalezas.size === 1) {
        // misma naturaleza · comparable · corona el mayor
        titular = byMag[0].patron;
        secundarios = byMag.slice(1).map(p => p.patron);
      } else if (ordenEvidente) {
        // naturalezas distintas pero diferencia de ORDEN evidente · corona el grande (PASO 2b)
        titular = byMag[0].patron;
        secundarios = byMag.slice(1).map(p => p.patron);
      } else {
        // naturalezas incomparables + magnitudes del mismo orden · NO forzar ganador
        titular = "multiple";
        requires_review = true;
        secundarios = activos.map(p => p.patron);
      }
    }
  }

  const titularDet = activos.find(p => p.patron === titular);
  const entities_clave = es_causal ? (P2.entities || []) : (titularDet ? titularDet.entities : []);

  return {
    titular,
    requires_review,
    es_causal,
    raiz,
    sintomas,
    secundarios,
    entities_clave,
    confianza: activos.length > 0 ? "presente" : "ausente", // BINARIA v1 · derivada (NO texto hardcoded)
  };
}

// Construye los detectores desde el scenario (atados a dato) y delega la coronación al núcleo puro.
function deriveBusinessThesis(scenarioId, override) {
  const benchmark = 30.1; // umbral de cartera (consistente con el código · const local)
  const scan = scanMechanisms(scenarioId, override);
  const clientes = applyScenarioToClientesMargen(scenarioId, override);
  const skus = applyScenarioToSkuInventario(scenarioId, override);

  // ── PASO 1 · 4 detectores binarios ──
  // P1 · baja calidad de crecimiento: instancias con crecimiento_pct≥10 && gap_margen_pp≥6
  const _p1m = (scan && scan.quality_of_growth_deterioration) || {};
  const _p1inst = (_p1m.instances || []).filter(i => (i.crecimiento_pct || 0) >= 10 && (i.gap_margen_pp || 0) >= 6);
  const P1 = {
    patron: "baja_calidad",
    activo: _p1inst.length > 0,
    entities: _p1inst.map(i => i.clientName),
    magnitud_K: Math.round(_p1inst.reduce((s, i) => s + (i.contribucion_perdida_M || 0), 0) * 1000),
    naturaleza: "flujo",
  };

  // P2 · dependencia de cuentas concentradas: aggregate.top3_participacion_pct ≥ 50
  const _p2agg = (scan && scan.customer_dependency_risk && scan.customer_dependency_risk.aggregate) || {};
  const P2 = {
    patron: "dependencia",
    activo: (_p2agg.top3_participacion_pct || 0) >= 50,
    entities: _p2agg.top3_names || [],
    magnitud_K: Math.round((_p2agg.top3_contribucion_M || 0) * 1000),
    naturaleza: "exposicion",
  };

  // P3 · erosión de margen: GENÉRICO (anti-hardcode · sin nombres fijos) · cuentas con margen < benchmark
  const _p3acc = clientes.filter(c => c.margen != null && c.margen < benchmark);
  const P3 = {
    patron: "erosion",
    activo: _p3acc.length > 0,
    entities: _p3acc.map(c => c.nombre),
    magnitud_K: Math.round(_p3acc.reduce((s, c) => s + (c.contribucion || 0), 0)),
    naturaleza: "flujo",
  };

  // P4 · capital atrapado: SKUs con DOH > 120 (umbral canónico de sobrestock · L57) · independiente
  const _p4sku = skus.filter(s => (s.doh || 0) > 120);
  const P4 = {
    patron: "capital",
    activo: _p4sku.length > 0,
    entities: _p4sku.map(s => s.sku),
    magnitud_K: Math.round(_p4sku.reduce((s, k) => s + (k.stockUSD || 0), 0) / 1000),
    naturaleza: "stock",
  };

  const detectores = { P1, P2, P3, P4 };

  // ── PASO 2-3 · dominancia + coronación (núcleo puro) ──
  const coronacion = _resolveThesisDominance(detectores);

  return Object.assign({}, coronacion, { _detectores: detectores }); // _detectores para telemetría/tests · no es texto
}

// ── composeBusinessThesisOpener · viste el objeto-tesis en 1-2 frases PURAS (sin cifras) ──
// Render PURO de deriveBusinessThesis · base="riesgo de fondo" / crisis="problema del mes" (adaptativo).
// La cifra es respaldo · vive en los movimientos de abajo (anti-eco). titular="ninguno" → null (fallback).
function composeBusinessThesisOpener(scenarioId) {
  if (!scenarioId) return null;
  const t = deriveBusinessThesis(scenarioId);
  if (!t || t.titular === "ninguno") return null; // sin patrones → cae al teaser genérico

  if (t.requires_review || t.titular === "multiple") {
    return `Tu negocio tiene dos frentes grandes de naturaleza distinta que conviene mirar por separado.`;
  }

  if (t.es_causal && t.titular === "dependencia") {
    // crisis = alguna entity_clave opera bajo media benchmark (MISMA señal · MAT-B3/C · no se inventa)
    const benchmark = 30.1;
    const clientes = applyScenarioToClientesMargen(scenarioId);
    const agudo = (t.entities_clave || []).some(name => {
      const c = clientes.find(x => x.nombre === name);
      return c && c.margen != null && c.margen < benchmark / 2;
    });
    return agudo
      ? `Tu negocio depende de unas pocas cuentas grandes, y ahora una de ellas se está deteriorando — la concentración dejó de ser un riesgo de fondo y se volvió el problema del mes.`
      : `Tu negocio depende de unas pocas cuentas grandes, y esa concentración es lo que te está comprimiendo el margen. El resto son consecuencias de eso.`;
  }

  // titular coronado por severidad (independiente · capital/erosion/baja_calidad) · tesis sin cifras
  const _porSeveridad = {
    capital: `El frente principal es capital inmovilizado en inventario: hay stock que no rota y conviene liberarlo.`,
    erosion: `El frente principal es la erosión de margen en tus cuentas: estás vendiendo con menos rentabilidad de la que corresponde.`,
    baja_calidad: `El frente principal es la calidad del crecimiento: estás creciendo, pero a costa del margen unitario.`,
  };
  return _porSeveridad[t.titular] || null;
}

// ── shouldAnchorToThesis · MEMORIA DE CRITERIO · consumo ESTRICTO de la tesis previa ──
// Decide si un follow-up debe abrir con una referencia breve a la tesis que ADI ya concluyó.
// 4 validaciones: V1 hay tesis · V2 mismo escenario · V3 turno contiguo · V4 toca el sujeto.
// Mecanismo GENERAL sobre el objeto-tesis (entidad ∩ entities del titular | drill-down por forma) ·
// NO listas hardcoded · NO match de frase específica. Entities desde _detectores (fuente canónica).
function shouldAnchorToThesis(userText, context, scenarioActual) {
  if (!context) return { anchor: false };
  const t = context.lastThesis;
  if (!t) return { anchor: false };                                              // V1: hay tesis
  if (context.lastThesisScenario !== scenarioActual) return { anchor: false };   // V2: mismo escenario
  if ((context.turnCount - context.lastThesisTurn) > 1) return { anchor: false };// V3: turno contiguo
  // V4 (ESTRICTO): entidad del titular mencionada O intención de drill-down (forma genérica)
  const titularDet = t._detectores
    ? Object.values(t._detectores).find(d => d && d.patron === t.titular)
    : null;
  const _entidadesTesis = (titularDet && titularDet.entities) || [];
  const mentioned = detectClientInText(userText || "");
  const tocaEntity = !!mentioned && _entidadesTesis.includes(mentioned);
  const esDrilldown = /\b(cu[aá]nto\s+recupero|c[oó]mo\s+lo\s+hago|lo\s+primero|con\s+eso)\b/i.test(userText || "");
  if (!tocaEntity && !esDrilldown) return { anchor: false };                     // V4: fuera de tema → no ancla
  const _result = { anchor: true, entity: mentioned || _entidadesTesis[0] || null, thesis: t };
  // DRILL-RESPONSE · si es drill-down sobre "lo primero", adjuntar la respuesta del MOVIMIENTO priorizado
  // (actions[0] del motor · determinístico · NO recalcula · ancla al movimiento, NO a la entity del titular).
  // Ancla + respuesta UNIFICADAS acá (mismo gatillo · no se desincronizan).
  if (esDrilldown) {
    try {
      const _sig = buildNarrativeSignalsForExecutiveAction(scenarioActual);
      const _a0 = _sig && _sig.actions && _sig.actions[0];
      if (_a0) {
        const _titleOfMov = (ty) =>
          ty === "commercial_load_renegotiation" ? "Recuperar margen en cuentas estratégicas" :
          ty === "sku_operational_exit"          ? "Liberar capital inmovilizado" :
          ty === "tier2_diversification"         ? "Reducir dependencia de cuentas concentradas" :
          "Movimiento prioritario";
        _result.drilldownAnswer = {
          movimiento: _titleOfMov(_a0.type),
          recoverable_K: _a0.recoverable_K,
          recoverable_BP_K: _a0.recoverable_BP_K,
          entities: _a0.entities,
        };
      }
    } catch (e) { /* degradación segura · anchor sin drilldownAnswer */ }
  }
  return _result;
}

// ── detectVirtuousException · OBSERVACIÓN ADITIVA · la cuenta virtuosa no cubierta (tipo C · nivel cuenta) ──
// Cuenta que va a contramano del grupo (rentable/eficiente · hidden_profitability && SIN template negativo),
// material, y NO nombrada por la tesis. Default null (SILENCIO). Máximo UNA (la más material).
// Derivada del motor (detectTemplates) · NO hardcode. Clasificador virtuoso replicado de isVirtuousSideTemplate
// (L13892 · nested · no accesible desde módulo-level).
function detectVirtuousException(scenarioId, thesis) {
  if (!thesis || thesis.titular === "ninguno") return null;
  const clientes = applyScenarioToClientesMargen(scenarioId);
  // "cubierta" = la cuenta está entre las entities que la tesis CORONÓ (titular · las que ADI nombró)
  const titularDet = thesis._detectores
    ? Object.values(thesis._detectores).find(d => d && d.patron === thesis.titular)
    : null;
  const _cubiertas = new Set((titularDet && titularDet.entities) || []);
  // clasificador virtuoso (replica isVirtuousSideTemplate · motor)
  const _isVirtuousSide = (t) => {
    if (t.id === "hidden_profitability") return true;
    if (t.id === "dependency_risk") {
      const ev = t.evidence || {};
      const isUnique = ev.isUnique === true;
      const lowPart = (ev.participacion === undefined) || ev.participacion < 15;
      return isUnique && lowPart;
    }
    return false;
  };
  const virtuosas = [];
  for (const c of clientes) {
    const tpls = detectTemplates(c.nombre, scenarioId) || [];
    const hasHidden = tpls.some(t => t.id === "hidden_profitability");
    const hasNegative = tpls.some(t => !_isVirtuousSide(t));
    if (!hasHidden || hasNegative) continue;                 // virtuosa pura: hidden && sin negativo
    if (_cubiertas.has(c.nombre)) continue;                  // FILTRO "no cubierta" (titular)
    const hp = tpls.find(t => t.id === "hidden_profitability");
    const ev = (hp && hp.evidence) || {};
    if ((c.contribucion || 0) < 500) continue;               // FILTRO "material" (floor prudencial · contribución K)
    virtuosas.push({
      cuenta: c.nombre,
      evidencia: { participacion: ev.participacion, variacion: ev.variacion, margen: ev.margen, pctRebate: ev.pctRebate },
      _mat: c.contribucion || 0,
    });
  }
  if (virtuosas.length === 0) return null;                   // → SILENCIO (default)
  virtuosas.sort((a, b) => b._mat - a._mat);                 // CORONA la más material (contribución desc)
  const top = virtuosas[0];
  return { cuenta: top.cuenta, evidencia: top.evidencia };
}

// ── deriveKpis(scenarioId) · CÁLCULO PURO de los KPIs agregados desde las cuentas transformadas ──
// Función nueva, pura, AISLADA · NO enchufada al motor (Pre-flight A es un GATE, no integración).
// ventas/margen derivados · inventario PRESERVADO del literal (v1 · margen no mueve inventario).
// pctAnt preservado del literal (período anterior · no derivable de las transformaciones actuales).
function deriveKpis(scenarioId, override) {
  const ventas = applyScenarioToClientesVentas(scenarioId, override);
  const margenes = applyScenarioToClientesMargen(scenarioId, override);

  // VENTAS (puro · redondeo por cuenta ya viene de applyScenarioToClientesVentas)
  const totalActual = ventas.reduce((s, c) => s + (c.actual || 0), 0);
  const totalAnterior = ventas.reduce((s, c) => s + (c.anterior || 0), 0);
  const totalPresup = ventas.reduce((s, c) => s + (c.presupuesto || 0), 0);

  // MARGEN (puro · pct = contribución agregada / ventas agregadas)
  const totalUSD = margenes.reduce((s, c) => s + (c.contribucion || 0), 0);
  const pct = totalActual > 0 ? +((totalUSD / totalActual) * 100).toFixed(1) : 0;
  const benchmark = 30.1;

  // pctAnt e inventario: PRESERVADOS del literal (no derivables del estado actual · v1)
  const lit = (typeof SCENARIO_TRANSFORMS !== "undefined" && SCENARIO_TRANSFORMS[scenarioId] && SCENARIO_TRANSFORMS[scenarioId].kpis) || {};
  const litMargen = lit.margen || {};
  const litVentas = lit.ventas || {};
  const pctAnt = litMargen.pctAnt != null ? litMargen.pctAnt : null;
  const gapPuntos = pctAnt != null ? +(pct - pctAnt).toFixed(1) : null;   // gapPuntos = pct - pctAnt (NO vs benchmark)

  const vsAnterior = totalAnterior > 0 ? +(((totalActual / totalAnterior) - 1) * 100).toFixed(1) : null;
  const totalPresupuesto = totalPresup > 0 ? totalPresup : (litVentas.totalPresupuesto != null ? litVentas.totalPresupuesto : null);
  const vsPresupuesto = totalPresupuesto ? +(((totalActual / totalPresupuesto) - 1) * 100).toFixed(1) : null;

  return {
    ventas: { totalActual, totalAnterior, totalPresupuesto, vsAnterior, vsPresupuesto },
    margen: { pct, pctAnt, totalUSD, gapPuntos, benchmark },
    inventario: lit.inventario || null,   // PRESERVADO del literal · v1 no recalcula inventario
  };
}

// ── SIMULATION LAYER · resolveTransform / mergeTransform (B1a · plomería) ──────────────
// resolveTransform unifica el acceso al transform de un escenario: sin override devuelve el base
// (byte-idéntico a hoy · anti-regresión central) · con override fusiona la realidad hipotética.
// override por PARÁMETRO · funciones puras · cero estado módulo-level mutable · determinismo intacto.
function mergeTransform(base, override) {
  if (!override) return base;
  // fusión por NATURALEZA del campo (firmado): DELTA suma sobre el base · SET/fijación reemplaza.
  const DELTA_FIELDS = { marginErosion: true, growth: true, rebateDelta: true };
  const merged = Object.assign({}, base);
  const baseClientes = (base && base.clientes) || {};
  const ovClientes = (override && override.clientes) || {};
  const mergedClientes = Object.assign({}, baseClientes);
  for (const acct of Object.keys(ovClientes)) {
    const baseAcct = baseClientes[acct] || {};
    const ovAcct = ovClientes[acct] || {};
    const newAcct = Object.assign({}, baseAcct);
    for (const field of Object.keys(ovAcct)) {
      if (field === "__set__") {
        // SET/FIJACIÓN absoluta · imposición que reemplaza (slot · B1a ejercita solo delta)
        Object.assign(newAcct, ovAcct.__set__);
      } else if (DELTA_FIELDS[field]) {
        newAcct[field] = (baseAcct[field] || 0) + ovAcct[field];   // DELTA · suma sobre el base
      } else {
        newAcct[field] = ovAcct[field];                            // campo no-delta · reemplaza
      }
    }
    mergedClientes[acct] = newAcct;
  }
  merged.clientes = mergedClientes;
  return merged;
}

function resolveTransform(scenarioId, override) {
  const base = (typeof SCENARIO_TRANSFORMS !== "undefined") ? SCENARIO_TRANSFORMS[scenarioId] : undefined;
  if (!override) return base;                 // SIN simulación → el transform fijo intacto
  return mergeTransform(base, override);      // base + override (delta suma · set reemplaza)
}

// ── extractMarginSimulation(text, scenarioId) · EXTRACTOR DE MARGEN (B1b) ──────────────
// Traduce vocabulario → estructura override (forma B1a). CERO lógica de resultado (el motor deriva).
// Disjunto del legacy de pérdida (si pierdo/perder → null → cae al legacy). ADITIVO · no toca el ruteo.
// Devuelve:
//   null                                   → no es simulación de margen (deja pasar al legacy/fallback)
//   { override, magnitud, unidad, alcance }→ intención completa · override listo para resolveTransform
//   { needsPrecision, question, options }  → intención de margen pero falta alcance o unidad ambigua (%)
function extractMarginSimulation(text, scenarioId) {
  const raw = text || "";
  // PASO 1 · detector de intención de margen (disjunto del legacy de pérdida)
  if (/\b(pierd\w*|perd\w*)\b/i.test(raw)) return null;        // pérdida → legacy (client_simulation_lose)
  const accionMejora = /(recuper|aument|mejor)\w*|\bsub[ieoíé]\w*|\bgan[aeáo]\w*/i.test(raw);
  const variableMargen = /margen|m[aá]rgenes|rentabilidad/i.test(raw);
  if (!(accionMejora && variableMargen)) return null;          // no es simulación de margen

  // PASO 2 · magnitud + unidad (taxonomía delta de B1a)
  const numMatch = raw.match(/(\d+(?:[.,]\d+)?)/);
  const magnitud = numMatch ? parseFloat(numMatch[1].replace(",", ".")) : null;
  const esPP = /\b\d+(?:[.,]\d+)?\s*(pp|puntos?|punto)\b/i.test(raw) || /puntos?\s+de\s+margen/i.test(raw);
  const esPct = /\b\d+(?:[.,]\d+)?\s*(%|por\s*ciento|porciento)/i.test(raw);
  // ambigüedad "%" en margen → precisión puntual (caso B · puntos/pp es el camino limpio)
  if (esPct && !esPP) {
    return { needsPrecision: true, question: "¿" + (magnitud || "X") + " puntos de margen (pp) o " + (magnitud || "X") + "% relativo?", options: ["puntos (pp)", "% relativo"] };
  }

  // PASO 3 · resolver alcance (cuenta nombrada O grupo erosionado · SIN default)
  let alcance = null;
  const cuenta = (typeof detectClientInText === "function") ? detectClientInText(raw) : null;
  if (cuenta) {
    alcance = [cuenta];                                        // a · cuenta nombrada
  } else if (/erosionad|que\s+pierden\s+margen|bajo\s+benchmark/i.test(raw)) {
    // b · grupo erosionado = entities del movimiento de carga que ADI narra (top3 commercial_erosion)
    //     DERIVADO en runtime · NO lista hardcodeada · NO el filtro crudo L4014
    const acts = (typeof buildNarrativeSignalsForExecutiveAction === "function")
      ? (buildNarrativeSignalsForExecutiveAction(scenarioId).actions || []) : [];
    const carga = acts.find(a => a.type === "commercial_load_renegotiation");
    if (carga && Array.isArray(carga.entities) && carga.entities.length) alcance = carga.entities.slice();
  }
  if (!alcance || !alcance.length) {
    // c · sin alcance → transform INCOMPLETO → pedir precisión de ALCANCE (NO default · firmado)
    return { needsPrecision: true, question: "¿En qué cuentas? Lider · el grupo erosionado · todas", options: ["una cuenta", "el grupo erosionado", "todas"] };
  }
  if (magnitud == null) {
    // alcance resuelto pero falta magnitud → precisión de magnitud
    return { needsPrecision: true, question: "¿Cuántos puntos de margen?", options: [] };
  }

  // PASO 4 · generar el override (forma B1a · marginErosion DELTA +)
  const marginDelta = +magnitud;                               // dirección POSITIVA (recuperar/subir/aumentar/mejorar)
  const clientes = {};
  for (const nombre of alcance) clientes[nombre] = { marginErosion: marginDelta };
  return { override: { clientes }, magnitud, unidad: "pp", alcance };
}

// ── SIMULATION LAYER · buildSimulationState / compareStates (B2a · comparador) ──────────
// buildSimulationState arma las 4 capas de un estado desde scenarioId + override (undefined = actual).
// compareStates es GENÉRICO: orquesta LAYER_SPECS auto-descriptivas · no conoce "margen" (primer pasajero).
// Materialidad asimétrica POR CAPA: métrica = umbral · tesis/prioridad/mecanismos = cualquier cambio.
const UMBRAL_MATERIALITY_MARGEN_PP = 0.5;   // pp · umbral de materialidad de la métrica de margen

function buildSimulationState(scenarioId, override) {
  const sig = buildNarrativeSignalsForExecutiveAction(scenarioId, null, null, override);
  return {
    tesis:      deriveBusinessThesis(scenarioId, override),
    prioridad:  (sig && sig.actions) ? sig.actions : [],
    metrica:    deriveKpis(scenarioId, override),
    mecanismos: scanMechanisms(scenarioId, override),
  };
}

function _activeMechanisms(mecs) {
  return Object.keys(mecs || {}).filter(k => mecs[k] && mecs[k].triggered === true).sort();
}

function compareStates(actual, simulado) {
  const LAYER_SPECS = [
    { tipo: "metrica",
      extrae: s => (s.metrica && s.metrica.margen) ? s.metrica.margen.pct : null,
      difiere: (a, b) => Math.abs((a || 0) - (b || 0)) > 1e-9,
      material: (a, b) => Math.abs((a || 0) - (b || 0)) >= UMBRAL_MATERIALITY_MARGEN_PP },
    { tipo: "tesis",
      extrae: s => ({ titular: s.tesis.titular, es_causal: s.tesis.es_causal, entities_clave: s.tesis.entities_clave }),
      difiere: (a, b) => JSON.stringify(a) !== JSON.stringify(b),
      material: (a, b) => JSON.stringify(a) !== JSON.stringify(b) },
    { tipo: "prioridad",
      extrae: s => (s.prioridad || []).map(a => a.type),
      difiere: (a, b) => JSON.stringify(a) !== JSON.stringify(b),
      material: (a, b) => JSON.stringify(a) !== JSON.stringify(b) },
    { tipo: "mecanismos",
      extrae: s => _activeMechanisms(s.mecanismos),
      difiere: (a, b) => JSON.stringify(a) !== JSON.stringify(b),
      material: (a, b) => JSON.stringify(a) !== JSON.stringify(b) },
  ];
  const result = {};
  for (const spec of LAYER_SPECS) {
    const va = spec.extrae(actual), vs = spec.extrae(simulado);
    const cambio = spec.difiere(va, vs);
    const entry = { tipo: spec.tipo, cambió: cambio, material: cambio ? spec.material(va, vs) : false, valorActual: va, valorSimulado: vs };
    if (spec.tipo === "mecanismos") {
      entry.persistentes = (va || []).filter(m => (vs || []).includes(m));   // activos en AMBOS estados (no-mudanza causal · B2b)
    }
    result[spec.tipo] = entry;
  }
  return result;
}

// ── composeSimulationDelta(simState, scenarioId) · VOZ DEL DELTA (B2b · culminación Nivel 2) ──
// Consume el diff de B2a (simulationDiffRef) y lo narra como asesor ejecutivo: qué cambió, por qué,
// qué mejora, qué NO toca. Descendente · grado 2 (explica, no dicta) · no-mudanza causal.
// REGLA CIFRA: la magnitud = delta de metrica.margen.totalUSD (simulado − actual) · NUNCA recoverable_K.
function _mechanismPersistencePhrase(mechId) {
  const M = {
    customer_dependency_risk: "la dependencia sigue concentrada en las mismas cuentas",
    commercial_erosion: "la erosión de margen continúa, con menor intensidad",
    quality_of_growth_deterioration: "la calidad del crecimiento sigue presionada",
    trapped_capital: "el capital sigue inmovilizado",
    liquidity_compression: "la liquidez sigue comprimida",
  };
  return M[mechId] || null;
}

function composeSimulationDelta(simState, scenarioId) {
  if (!simState || !simState.diff) return null;
  const diff = simState.diff;
  const override = simState.ov && simState.ov.override;
  const alcance = (simState.ov && simState.ov.alcance) || [];

  // REGLA CIFRA · delta = simulado.totalUSD − actual.totalUSD (recomputado · NO recoverable_K)
  const actual = deriveKpis(scenarioId);
  const simulado = deriveKpis(scenarioId, override);
  const deltaUSD = Math.round(simulado.margen.totalUSD - actual.margen.totalUSD);
  const pctActual = actual.margen.pct;
  const pctSim = simulado.margen.pct;

  // formateador de lista inline (fmtList es anidado · no accesible a módulo)
  const _fmtList = (arr) => !arr || !arr.length ? "las cuentas señaladas"
    : arr.length === 1 ? arr[0]
    : arr.slice(0, -1).join(", ") + " y " + arr[arr.length - 1];
  const cuentasTxt = _fmtList(alcance);

  // CASO PÉRDIDA (__remove__) · trade-off REAL leído del CÁLCULO (NO asumir el signo de la dependencia)
  if (simState.ov && simState.ov.tipo === "perdida") {
    const cuenta = simState.ov.cuenta || cuentasTxt;
    const costo = Math.abs(deltaUSD);
    let depFrase = "";
    let _reconcentra = false;          // BRIEF CONTRATO1 · ¿la pérdida reconcentra (cuenta chica) o reparte (cuenta grande)?
    let _simTopNames = [];             // BRIEF CONTRATO1 · cuentas que encabezan tras la pérdida (fuente única · scanMechanisms · NO recompute)
    try {
      const _depA = scanMechanisms(scenarioId).customer_dependency_risk;
      const _depS = scanMechanisms(scenarioId, override).customer_dependency_risk;
      const _tA = _depA && _depA.aggregate && _depA.aggregate.top3_participacion_pct;
      const _tS = _depS && _depS.aggregate && _depS.aggregate.top3_participacion_pct;
      _simTopNames = (_depS && _depS.aggregate && _depS.aggregate.top3_names) || [];
      if (_tA != null && _tS != null) {
        if (_tS < _tA - 1) {
          // PASO 2 enriquecido · nombrar las mayores TRAS la pérdida (paso 3 "el riesgo se reparte" byte-idéntico)
          depFrase = ` — tu dependencia bajaría (del ${Math.round(_tA)}% al ${Math.round(_tS)}% en las mayores, ahora ${_fmtList(_simTopNames)}), el riesgo se reparte`;
        } else {
          _reconcentra = true;
          const _rest = _simTopNames.slice(0, 2);
          depFrase = ` — y tu dependencia no baja: ${_rest.join(" y ")} pasarían a pesar aún más, el riesgo se reconcentra en menos cuentas`;
        }
      }
    } catch (e) { depFrase = ""; }
    const _tf = { dependencia: "la concentración en pocos clientes", erosion: "la erosión de margen", baja_calidad: "la calidad del crecimiento", capital: "el capital inmovilizado" };
    const tShift = diff.tesis.cambió
      ? ` Tu lectura del negocio se movería: el problema central pasaría de ${_tf[diff.tesis.valorActual.titular] || diff.tesis.valorActual.titular} a ${_tf[diff.tesis.valorSimulado.titular] || diff.tesis.valorSimulado.titular}.`
      : "";
    // PASO 5 · ABRIR EL SIGUIENTE NIVEL · derivado del diff · ADI empuja la continuidad (no la tironea el usuario).
    // GUARD honestidad: NO emite números · abre una línea REAL y seguible · "en cuánto tiempo" queda como
    // pregunta (no derivable · no se promete el número · solo se abre lo que ADI sí puede seguir).
    let _paso5 = "";
    if (diff.tesis.cambió) {
      _paso5 = ` Lo siguiente que miraría: qué cuentas de la cartera podrían absorber ese volumen y en cuánto tiempo se recuperaría la contribución.`;
    } else if (_reconcentra) {
      const _foco = _simTopNames[0] || cuenta;
      _paso5 = ` Lo siguiente que miraría: cuánto sube la exposición a ${_foco} y si conviene diversificar antes de que el riesgo se concentre más.`;
    }
    // BRIEF FORMATO · bloques (\n\n entre movimientos · wording VERBATIM · solo cambia el separador " "→"\n\n")
    const _lossB1 = `Perder ${cuenta} te costaría aproximadamente $${costo}K de contribución${depFrase}.`;
    return [_lossB1, tShift.replace(/^ +/, ""), _paso5.replace(/^ +/, "")].filter(Boolean).join("\n\n");
  }

  // PASO 1 · significancia narrativa (derivada del diff · NO hardcode)
  const significancia = diff.prioridad.cambió ? "ALTA"
    : (diff.tesis.cambió ? "MEDIA"
      : (diff.metrica.material ? "BAJA" : "NULA"));

  if (significancia === "NULA") {
    return "Esta acción no mueve nada relevante: el margen no cambia de forma material y tu lectura del negocio se mantiene.";
  }

  // MAGNITUD · la cifra de la simulación · descendente
  const signo = deltaUSD >= 0 ? "Recuperarías" : "Perderías";
  const magnitud = `${signo} aproximadamente $${Math.abs(deltaUSD)}K de contribución — el margen pasa de ${pctActual}% a ${pctSim}% en ${cuentasTxt}.`;

  if (significancia === "ALTA") {
    // liderar con el cambio de prioridad (no canónico · forma base · se sella en vivo cuando aparezca)
    const prioActual = (diff.prioridad.valorActual || [])[0];
    const prioSim = (diff.prioridad.valorSimulado || [])[0];
    return `Esto cambiaría tu decisión: el primer movimiento pasaría de ${prioActual} a ${prioSim}. ${magnitud}`;
  }
  if (significancia === "MEDIA") {
    // liderar con el cambio de tesis (no canónico · forma base)
    const tActual = diff.tesis.valorActual && diff.tesis.valorActual.titular;
    const tSim = diff.tesis.valorSimulado && diff.tesis.valorSimulado.titular;
    return `Tu lectura del negocio se movería: de ${tActual} a ${tSim}. ${magnitud} La prioridad, en cambio, no se mueve.`;
  }

  // BAJA (el canónico) · MAGNITUD + NO-MUDANZA CAUSAL + VEREDICTO
  const orden = ["customer_dependency_risk", "commercial_erosion", "quality_of_growth_deterioration", "trapped_capital", "liquidity_compression"];
  const persist = (diff.mecanismos.persistentes || []).slice()
    .sort((a, b) => orden.indexOf(a) - orden.indexOf(b));
  const frases = persist.map(_mechanismPersistencePhrase).filter(Boolean).slice(0, 2);
  const noMudanza = frases.length ? `Pero ${frases.join(", y ")}.` : "";
  const veredicto = "Por eso tu lectura del negocio y tu prioridad no cambian: esto mejora el número, no toca el problema de fondo.";
  // BRIEF FORMATO · bloques (\n\n entre movimientos · wording sellado VERBATIM · solo cambia el separador) +
  // P5 nuevo (abre el umbral · honesto · CUALITATIVO · sin número de cruce · igual que VOZ2)
  const _paso5Margen = "Lo siguiente que analizaría: cuánto debería reducirse la concentración de estas cuentas para que la prioridad cambie.";
  return [magnitud, noMudanza, veredicto, _paso5Margen].filter(Boolean).join("\n\n");
}

// ── DELTA CONTINUITY v1 · shouldDefendDelta / composeDeltaDefense ──────────────────────
// Un asesor no termina al entregar la simulación · defiende la no-mudanza si el follow-up la desafía.
// Replica el patrón PROBADO de memoria de criterio (shouldAnchorToThesis · V1-V4). NO re-simula:
// la defensa sale del delta RETENIDO (diff.mecanismos.persistentes ya calculados por B2a).
function shouldDefendDelta(userText, context, scenarioActual) {
  if (!context) return { defend: false };
  const d = context.lastDelta;
  if (!d) return { defend: false };                                                // V1: hay delta retenido
  if (context.lastDeltaScenario !== scenarioActual) return { defend: false };       // V2: mismo escenario
  if ((context.turnCount - context.lastDeltaTurn) > 3) return { defend: false };    // V3: ventana ~3 turnos (relajada)
  // V3.5: la defensa de no-mudanza SOLO aplica a deltas que NO movieron la tesis (margen · BAJA) ·
  // un delta de pérdida (mueve tesis · sin persistentes coherentes) NO se defiende → cae al flujo normal LIMPIO
  if (d.tipo === "perdida" || d.tesisChange === true) return { defend: false };
  const txt = userText || "";
  // VOZ2 · PIEZA 2 · pregunta de UMBRAL (qué cambiaría la prioridad) · distinta del desafío de no-mudanza ·
  // va ANTES de V4 porque "qué tendría que cambiar" NO matchea el marcadorDesafio (hoy caería al fallback)
  const preguntaUmbral = /\b(qu[eé]\s+tendr[ií]a\s+que\s+cambiar|qu[eé]\s+har[ií]a\s+que\s+cambie|cu[aá]ndo\s+cambiar[ií]a|qu[eé]\s+cambiar[ií]a\s+(tu|la)\s+(prioridad|lectura|tesis)|bajo\s+qu[eé]\s+condici)/i.test(txt);
  if (preguntaUmbral) return { defend: true, modo: "umbral", delta: d };
  // V4: DESAFÍA la no-mudanza (marcador de desafío + sujeto prioridad/lectura/decisión)
  const marcadorDesafio = /\b(por\s*qu[eé]|c[oó]mo\s+que|igual|sigue\s+igual|no\s+cambia|misma\s+prioridad|no\s+cambi)\b/i.test(txt);
  const sujetoNoMudanza = /\b(prioridad|lectura|tesis|cambia|cambi|foco|decisi[oó]n)\b/i.test(txt);
  if (!(marcadorDesafio && sujetoNoMudanza)) return { defend: false };              // V4: no es desafío → flujo normal
  return { defend: true, modo: "no-mudanza", delta: d };
}

function composeDeltaDefense(delta) {
  if (!delta || !delta.diff) return null;
  // ordenar persistentes: la raíz de la tesis (dependencia) primero, luego erosión
  const orden = ["customer_dependency_risk", "commercial_erosion", "quality_of_growth_deterioration", "trapped_capital", "liquidity_compression"];
  const persist = ((delta.diff.mecanismos && delta.diff.mecanismos.persistentes) || []).slice()
    .sort((a, b) => orden.indexOf(a) - orden.indexOf(b));
  const frases = persist.map(_mechanismPersistencePhrase).filter(Boolean).slice(0, 2);  // REUSA el mapa de B2b
  if (!frases.length) return null;
  return `Esos $${delta.cifra_K}K mejoran el resultado, pero no cambian los factores que explican el ` +
         `problema: ${frases.join(" y ")}. Mientras sigan ahí, la prioridad es la misma.`;
}

// ── VOZ2 · PIEZA 2 · composeThresholdExplanation(delta, scenarioId) ────────────
// Responde "¿qué tendría que cambiar para que cambie la prioridad?" sobre un delta de margen retenido.
// Deriva la CONDICIÓN de la estructura causal real (raiz/sintomas) · NO inventa umbrales numéricos.
// NOTA: diff.tesis.valorActual es una proyección reducida {titular, es_causal, entities_clave} · raiz/sintomas
// se re-derivan con deriveBusinessThesis(scenarioId) (estructura causal BASE · determinista · NO re-simulación).
function composeThresholdExplanation(delta, scenarioId) {
  if (!delta || !delta.diff || !delta.diff.tesis) return null;
  const tv = delta.diff.tesis.valorActual;
  if (!tv) return null;
  // mapa nombre-de-tesis → frase legible (mismo _tf que composeSimulationDelta · replicado inline)
  const _tf = { dependencia: "la concentración en pocas cuentas", erosion: "la erosión de margen", baja_calidad: "la calidad del crecimiento", capital: "el capital inmovilizado" };
  const base = (typeof deriveBusinessThesis === "function") ? deriveBusinessThesis(scenarioId) : null;
  // CAUSAL · la raíz causa los síntomas → la condición es romper ese vínculo (cualitativo · honesto)
  if (tv.es_causal && base && base.raiz) {
    const raizFrase = _tf[base.raiz] || base.raiz;
    const sint = (base.sintomas && base.sintomas.length) ? base.sintomas[0] : null;
    const sintFrase = sint ? (_tf[sint] || sint) : "ese síntoma";
    return `La prioridad cambiaría si ${raizFrase} dejara de ser la causa de fondo. ` +
           `Hoy lo es porque las mismas cuentas concentradas arrastran ${sintFrase}. ` +
           `Tendría que romperse ese vínculo: que la concentración baje lo suficiente como para que ${sintFrase} deje de depender de ella. ` +
           `Recuperar margen no hace eso — reduce el síntoma, no la raíz.`;
  }
  // NO-CAUSAL · otro frente tendría que superar al titular en peso
  if (tv.titular) {
    const titFrase = _tf[tv.titular] || tv.titular;
    return `La prioridad cambiaría si otro frente pasara a pesar más que ${titFrase}, que hoy domina la lectura. ` +
           `Recuperar margen no mueve ese orden.`;
  }
  // honesto genérico · sin estructura causal clara
  return `La prioridad cambiaría si cambiara el mecanismo que hoy domina la lectura. Recuperar margen no toca ese mecanismo.`;
}

// ── VOZ3 · PIEZA 3 · shouldDeepenThreshold(userText, context, scenarioActual) ──
// Detecta el follow-up corto de PROFUNDIZACIÓN del umbral ("dame un ejemplo", "cómo sería") sobre el
// umbral retenido (lastUmbral). Hermana de shouldDefendDelta · estado propio (lastUmbral, no lastDelta).
function shouldDeepenThreshold(userText, context, scenarioActual) {
  if (!context) return { deepen: false };
  const u = context.lastUmbral;
  if (!u) return { deepen: false };                                                // V1: hay umbral retenido
  if (context.lastUmbralScenario !== scenarioActual) return { deepen: false };      // V2: mismo escenario
  if ((context.turnCount - context.lastUmbralTurn) > 3) return { deepen: false };   // V3: ventana ~3 turnos
  const txt = userText || "";
  // V4: profundización (corto · referente implícito el umbral) · disjunto de "cuánto vende X" (otro intent)
  const esProfundizacion = /\b(dame\s+un\s+ejemplo|un\s+ejemplo|por\s+ejemplo|c[oó]mo\s+ser[ií]a|c[oó]mo\s+se\s+ver[ií]a|qu[eé]\s+significar[ií]a)/i.test(txt);
  if (!esProfundizacion) return { deepen: false };
  return { deepen: true, umbral: u };
}

// ── VOZ3 · PIEZA 3 · composeThresholdExample(umbral) · el ejemplo CUALITATIVO ──
// Arma el ejemplo desde la estructura causal retenida (raiz/sintoma) · CUALITATIVO · sin números inventados.
function composeThresholdExample(umbral) {
  if (!umbral || !umbral.raiz) return null;
  const _tf = { dependencia: "la concentración en pocas cuentas", erosion: "la erosión de margen", baja_calidad: "la calidad del crecimiento", capital: "el capital inmovilizado" };
  const raizFrase = _tf[umbral.raiz] || umbral.raiz;
  const sintFrase = umbral.sintoma ? (_tf[umbral.sintoma] || umbral.sintoma) : "ese síntoma";
  return `Por ejemplo, si ${raizFrase} bajara lo suficiente como para que ${sintFrase} ` +
         `dejara de depender de las mismas cuentas, la prioridad podría desplazarse hacia rentabilidad.`;
}

// ── BRIEF THREAD1 · shouldContinueThread(userText, context, scenarioActual) ──────
// Detector de CONTINUACIÓN del hilo · consulta el activeThread (capa de coordinación POR ENCIMA),
// NO un anclaje suelto. Frescura (V3 · ventana del hilo) SEPARADA de reconocimiento (V4 · forma del
// follow-up) · invariante 4. Disjunto de defensa/umbral/ejemplo (corre DESPUÉS de ellos en la cascada).
function shouldContinueThread(userText, context, scenarioActual) {
  if (!context) return { continue: false };
  const th = context.activeThread;
  if (!th) return { continue: false };                                          // V1: hay hilo vivo
  if (th.scenario !== scenarioActual) return { continue: false };               // V2: mismo escenario
  if ((context.turnCount - th.turn) > 3) return { continue: false };            // V3: ventana de frescura (se refresca con cada profundización)
  const txt = userText || "";
  // V4 (PASO 1 · acotado a las formas de la captura) · reconocimiento, separado de la frescura
  const esCuentas = /\b(cu[aá]les?\s+cuentas?|qu[eé]\s+cuentas?)\b/i.test(txt);
  const esCifras  = /\b(quiero\s+cifras?|las?\s+cifras?|con\s+cifras?|cu[aá]nto\s+exact)/i.test(txt);
  if (!esCuentas && !esCifras) return { continue: false };                      // V4: no es continuación de la captura
  const intent = (esCuentas && esCifras) ? "ambos" : (esCifras ? "cifras" : "cuentas");
  return { continue: true, thread: th, intent };
}

// ── BRIEF THREAD1 · composeThreadContinuation(thread, intent) · responde honesto ──
// Resuelve el follow-up desde el estado epistémico del hilo:
//  · derivable.cuentas → nombra las entidades reales (derivadas de la tesis · misma SoT · invariante 3).
//  · derivable.cifras_cruce === false → sostiene el tema Y declara el límite · NUNCA fabrica un número de cruce.
// Honestidad a nivel TESIS: la concentración (raíz) arrastra la erosión (síntoma) · no afirma erosión por cuenta.
function composeThreadContinuation(thread, intent) {
  if (!thread) return null;
  const ents = Array.isArray(thread.entidades) ? thread.entidades.filter(Boolean) : [];
  const lista = ents.length === 0 ? "las cuentas concentradas"
    : ents.length === 1 ? ents[0]
    : ents.slice(0, -1).join(", ") + " y " + ents[ents.length - 1];
  const puedeCuentas = !!(thread.derivable && thread.derivable.cuentas) && ents.length > 0;
  const cuentasFrase =
    `Las cuentas que concentran la cartera son ${lista}. ` +
    `Esa concentración es la raíz que arrastra la erosión de margen, por eso la prioridad no se mueve.`;
  const cifrasFrase =
    `El número exacto al que la concentración tendría que bajar para mover la prioridad no lo tengo sin calcularlo — ` +
    `sería inventar un umbral que el dato todavía no sostiene. Las cuentas en juego son ${lista}; ` +
    `si querés, lo derivo, pero no voy a darte una cifra que no salga del cálculo.`;
  // GUARD CRÍTICO · cifras del cruce no calculadas (derivable.cifras_cruce === false en PASO 1) · nunca fabrica
  if (intent === "cuentas") return puedeCuentas ? cuentasFrase : null;
  if (intent === "cifras")  return cifrasFrase;
  // "ambos" (la captura: "cuáles cuentas, quiero cifras") · nombra Y declara el límite, en un solo arco
  if (!puedeCuentas) return cifrasFrase;
  return `Las cuentas que concentran la cartera son ${lista} — esa concentración es la raíz que arrastra la erosión de margen. ` +
    `El número exacto al que tendría que bajar para mover la prioridad no lo tengo sin calcularlo; sería inventar un umbral que el dato todavía no sostiene. ` +
    `Si querés lo derivo, pero no voy a darte una cifra que no salga del cálculo.`;
}

// ── BRIEF EVIDENCIA1 (ARCO B) · shouldServeEvidence(userText, context) ──────────
// Detector de profundización UNIVERSAL · hermano de shouldContinueThread (que sigue sirviendo simulación).
// Sirve la evidencia del último análisis capturada en investigationContext. Frescura (V2) separada del
// reconocimiento (V3) · invariante 4. Disjunto del drill dimensional ("por bodega/familia" no entra acá).
function shouldServeEvidence(userText, context) {
  if (!context) return { serve: false };
  const ents = context.investigationEntidades;
  const evi  = context.investigationEvidencia;
  const hayHilo = (Array.isArray(ents) && ents.length > 0) || (evi != null && (Array.isArray(evi) ? evi.length > 0 : true));
  if (!hayHilo) return { serve: false };                                         // V1: hay un hilo con evidencia capturada
  if (typeof context.investigationTurn === "number" && (context.turnCount - context.investigationTurn) > 3) return { serve: false }; // V2: ventana de frescura
  const txt = userText || "";
  // V3 · follow-up de EVIDENCIA (el que hoy rompe) · separado de la frescura
  const esEntidades = /\b(cu[aá]les?\s+(son|cuentas?|clientes?|productos?|sku)|qu[eé]\s+(cuentas?|clientes?|productos?))\b/i.test(txt);
  const esCifras    = /\b(dame\s+(las?\s+)?cifras?|cu[aá]nto\s+(pesan?|vale|valen|es|son)|las?\s+cifras?|sus?\s+ventas?)\b/i.test(txt);
  if (!esEntidades && !esCifras) return { serve: false };
  return {
    serve: true,
    tipo: esCifras ? "cifras" : "entidades",
    entidades: ents || [],
    evidencia: evi || null,
    dim: context.investigationEntityDim || null,                                  // RETRIEVALFIX · sustantivo por dimensión
    derivable: context.investigationDerivable || { entidades: (ents || []).length > 0, cifras: !!evi },
  };
}

// ═══════════════════════════════════════════════════════════════════════════
// EA.1 · FUENTE ÚNICA DE LECTURA · resolveContinuity
// Capa de lectura unificada que DELEGA a las 6 funciones puras existentes (NO reimplementa).
// Llama cada función con sus args reales y expone el objeto de retorno COMPLETO.
// flag off (VOICE_EA1_RESOLVER_ENABLED=false): las ramas usan su llamada inline de hoy → idéntico.
// flag on: las ramas consumen resolveContinuity(...).canX (= la misma función, mismos args).
// No toca escrituras, no colapsa relojes (cada función conserva su ancla), null-safe (las 6 ya lo son).
// Args: trimmed (texto), ctx (= conversationContextRef.current, ref vivo), scenarioActual, currentModule.
// ═══════════════════════════════════════════════════════════════════════════
const VOICE_EA1_RESOLVER_ENABLED = true;    // EA.1 ACTIVADO · reroute on · base de EA.3. (off recupera el cerebro pre-EA.1.)
// ── C1 · Foco Conversacional · helpers PUROS (read-only · sin estado · sin escritor) ──
// c1FocusIdentity: clave estable del foco (entityType+domain+entidades ordenadas). Dos focos
// con la misma identidad = mismo tema (re-preguntar no es cambio). c1DeriveFocusTopic: etiqueta
// humana del tema desde activeResult. NO conflacta con Memoria Organizacional ni superficie UI.
function c1FocusIdentity(ar) {
  if (!ar || !Array.isArray(ar.entities) || ar.entities.length === 0) return null;
  return (ar.entityType || "") + ":" + (ar.domain || "") + ":" + ar.entities.slice().sort().join("|");
}
function c1DeriveFocusTopic(ar) {
  if (!ar || !Array.isArray(ar.entities) || ar.entities.length === 0) return null;
  const et = ar.entityType || null, dom = ar.domain || null;
  if (et === "cliente") return (dom === "inventario") ? "inventario de cuentas" : "margen de cuentas";
  if (et === "sku")     return (dom === "inventario") ? "capital inmovilizado en SKUs" : "margen de SKUs";
  if (et === "familia") return "rentabilidad por familia";
  if (et === "marca")   return "contribución por marca";
  return (dom || "análisis") + (et ? " (" + et + ")" : "");
}

// ── C4 punto-1 · tema del foco AMBIENTAL · dominio → "[dominio] general" (señal de experiencia, display-only) ──
function c4AmbientTopic(domain) {
  if (domain === "inventario") return "inventario general";
  if (domain === "ventas")     return "ventas general";
  if (domain === "margenes")   return "margen general";
  return (domain || "negocio") + " general";
}

// ── C3(i) · Evidence-linking bajo EVIDENCIA ÚNICA · ROUTING puro (read-only · sin recompute) ──
// Arma el payload de handleSentrixAction ENTERAMENTE desde activeResult: entityType→campo de
// filtro, activeResult.entities como valor (la MISMA instancia que ADI usó), domain→módulo.
// NUNCA fabrica grupos (no deriva Tier1 ni recomputa sets). Si el activeResult es comparativo
// (compare_opposite, ambos grupos en entities), enruta ambos — pero NO los inventa el linker.
function c3DerivePayload(ar) {
  if (!ar || !Array.isArray(ar.entities) || ar.entities.length === 0) return null;
  const et = ar.entityType;
  const field = et === "cliente" ? "clientes"
              : et === "sku"     ? "skus"
              : et === "marca"   ? "marcas"
              : et === "familia" ? "sfamilias"
              : null;
  if (!field) return null; // entityType no enrutable → no auto-link (honesto, no inventa)
  const payload = { [field]: ar.entities.slice() }; // misma instancia (copia defensiva, mismo set)
  // módulo = la vista-de-prueba (P2): domain→módulo. margenes muestra la carga (columna); inventario el capital.
  if (ar.domain === "margenes") payload.modulo = "margenes";
  else if (ar.domain === "inventario") payload.modulo = "inventario";
  return payload;
}

function resolveContinuity(trimmed, ctx, scenarioActual, currentModule) {
  return {
    // familia investigation (delega)
    canServeEvidence: shouldServeEvidence(trimmed, ctx),
    implicitInheritance: ((typeof canInheritImplicitContext === "function") && canInheritImplicitContext(trimmed, ctx, currentModule))
      ? { entityType: _resolveImplicitEntityType(ctx) }     // delega ambas; la glue (isClient/list) queda en la rama
      : null,
    // familia activeThread (delega · cada una con su ancla)
    canContinue: shouldContinueThread(trimmed, ctx, scenarioActual),
    canDefend:   shouldDefendDelta(trimmed, ctx, scenarioActual),
    canDeepen:   shouldDeepenThreshold(trimmed, ctx, scenarioActual),
    // estado crudo de lectura (no recálculo)
    thread: (ctx && ctx.activeThread) || null,
    // R2 · activeResult · exponer el resultado activo como raw-read (hermano de thread · inerte · R3 lo consumirá).
    // gated con el flag de R1 vía spread → flag off: la clave no existe → retorno byte-idéntico a EA.1.
    ...(VOICE_ACTIVE_RESULT_ENABLED ? { activeResult: (ctx && ctx.activeResult) || null } : {}),
  };
}

// ── BRIEF EVIDENCIA1 (ARCO B) · composeEvidenceFromThread(tipo, entidades, evidencia, derivable) ──
// Sirve SOLO lo que el composer real produjo (capturado en investigationContext) · CERO recompute · CERO
// cifras inventadas. Si lo pedido no está servido y no es derivable → declara el límite (patrón honesto).
function composeEvidenceFromThread(tipo, entidades, evidencia, derivable, dim) {
  const _list = (arr) => { const a = (arr || []).filter(Boolean); if (!a.length) return ""; if (a.length === 1) return a[0]; return a.slice(0, -1).join(", ") + " y " + a[a.length - 1]; };
  if (tipo === "entidades") {
    if (derivable && derivable.entidades && Array.isArray(entidades) && entidades.length) {
      // RETRIEVALFIX · sustantivo según entityDim · default "Las cuentas" (backward compat si no hay dim)
      const _sust = (dim === "sku" || dim === "producto") ? "Los productos"
                  : (dim === "familia") ? "Las familias"
                  : (dim === "marca") ? "Las marcas"
                  : "Las cuentas";
      // CONTRATO (ARCO B · obligación 2) · si TAMBIÉN hay cifras servibles, un asesor
      // responde "cuáles son" con la entidad Y su cifra juntas. Cruce nombre↔cifra por
      // e.entity === nom (nombres canónicos) · si un nombre no matchea → se sirve sin
      // cifra (no inventa ni pega la cifra de otra entidad). CERO recompute.
      if (derivable.cifras && Array.isArray(evidencia) && evidencia.length) {
        const _conCifra = entidades.map(nom => {
          const m = evidencia.find(e => e && typeof e === "object" && e.entity === nom);
          const val = m ? ((m.value != null) ? m.value : (m.rankValue != null ? m.rankValue : null)) : null;
          return (val != null) ? `${nom} (${val})` : nom;
        });
        return `${_sust} de ese análisis son ${_list(_conCifra)}.`;
      }
      // sin cifras servibles → solo nombres (honesto · comportamiento previo)
      return `${_sust} de ese análisis son ${_list(entidades)}.`;
    }
    return `Las cuentas exactas no las tengo servidas sin recalcularlo — puedo derivarlas si querés.`;
  }
  // cifras
  if (derivable && derivable.cifras && evidencia != null) {
    const filas = (Array.isArray(evidencia) ? evidencia : [evidencia]).map(m => {
      if (m == null) return null;
      if (typeof m === "string") return m;                                       // materialMetrics ya formateadas (ej "$194 recuperable")
      const ent = m.entity || "";
      const val = (m.value != null) ? m.value : (m.rankValue != null ? m.rankValue : null);
      const met = m.metric || m.rankMetric || "";
      if (ent && val != null) return met ? `${ent} (${met}: ${val})` : `${ent}: ${val}`;
      return ent || null;
    }).filter(Boolean);
    if (filas.length) return `Las cifras de ese análisis: ${filas.join("; ")}.`;
  }
  return `Esas cifras no las tengo servidas sin recalcularlas — puedo derivarlas si querés, pero no voy a darte un número que no salga del cálculo.`;
}

// ── extractLossSimulation(text, scenarioId) · EXTRACTOR DE PÉRDIDA (perder cuenta = remover) ──
// Función HERMANA de extractMarginSimulation (intención distinta: pérdida ≠ mejora de margen · más limpio).
// "perder/pierdo X" + cuenta nombrada → override de remoción { clientes: { "<cuenta>": { __remove__: true } } }
// Redirige del legacy (client_simulation_lose) al camino nuevo (set tipo remover · primer paso de migración).
function extractLossSimulation(text, scenarioId) {
  const raw = text || "";
  if (!/\b(pierd\w*|perd\w*|perder)\b/i.test(raw)) return null;        // intención de pérdida
  const cuenta = (typeof detectClientInText === "function") ? detectClientInText(raw) : null;
  if (!cuenta) return null;                                            // v1: requiere cuenta nombrada
  return { override: { clientes: { [cuenta]: { __remove__: true } } }, tipo: "perdida", cuenta };
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 2 · extractGrowthSimulation · hermana de extractMargin/LossSimulation.
// Detecta proyección top-line (crece/cae X%) para cliente o familia. Va DESPUÉS
// de margen y pérdida en el chain (excluye ambos). NO devuelve un override de
// compareStates: devuelve { growth: { scope, scopeType, pct, signo } } para el
// composer propio (Opción A). Sin alcance/magnitud → needsPrecision.
// ════════════════════════════════════════════════════════════════════════════
function extractGrowthSimulation(text, scenarioId) {
  if (!FEATURE_GROWTH_PROJECTION) return null;
  const raw = text || "";
  // Excluir margen (→ extractMarginSimulation) y pérdida (→ extractLossSimulation).
  if (/margen|m[aá]rgenes|rentabilidad/i.test(raw)) return null;
  if (/\b(pierd\w*|perd\w*|perder)\b/i.test(raw)) return null;
  // CORTE 3 · guarda de precio: "sube/aumenta el precio" es palanca de precio, no
  // crecimiento de volumen. Gateada → con FEATURE_PRICE_LEVER OFF, growth se comporta
  // como en 2efdb9db (cazaría "aumenta el precio" como volumen).
  if (FEATURE_PRICE_LEVER && /\bprecios?\b/i.test(raw)) return null;
  // Contexto condicional.
  const norm = normalizeText(raw);
  const condicional = norm.startsWith("si ") || norm.includes(" si ")
    || norm.startsWith("que pasa si") || norm.startsWith("y si");
  // Verbo de crecimiento (+) o caída (−).
  const subeRe = /\b(crece\w*|crezca\w*|crecier\w*|aument\w*|sube\w*|suben\w*|subier\w*)\b/i;
  const caeRe  = /\b(cae|caen|caer\w*|caiga\w*|cayer\w*|baja\w*|bajen\w*|bajar\w*)\b/i;
  const esCae  = caeRe.test(raw);
  const esSube = subeRe.test(raw);
  if (!esSube && !esCae) return null;                 // no es growth top-line
  const signo = esCae ? -1 : 1;                       // caída explícita gana; sino crecimiento
  // MICRO-CORTE · magnitud parseada ANTES del guard. ON: prefiere número adyacente
  // a %/por ciento, excluyendo dígitos embebidos en tokens (códigos de SKU como
  // SAM-REF500L). OFF: parser viejo (byte-idéntico a 64204032).
  const numMatch = FEATURE_LEVER_NO_SI
    ? (raw.match(/(?<![A-Za-z])(\d+(?:[.,]\d+)?)\s*(?:%|por\s*ciento)/i)
       || raw.match(/(?<![A-Za-z0-9-])(\d+(?:[.,]\d+)?)(?![A-Za-z0-9-])/))
    : raw.match(/(\d+(?:[.,]\d+)?)/);
  const pct = numMatch ? parseFloat(numMatch[1].replace(",", ".")) : null;
  // MICRO-CORTE · disparo por magnitud (no por "si"). ON: con número dispara aunque
  // no haya "si"; sin número y sin "si" → null (cae al dive · no regresiona
  // descriptivos). OFF: exige condicional (comportamiento 64204032).
  if (FEATURE_LEVER_NO_SI) {
    if (pct == null && !condicional) return null;
  } else {
    if (!condicional) return null;
  }
  // Alcance: cliente (detectClientInText) o familia (SUPERFAMILIAS + alias del Corte 1).
  let scope = null, scopeType = null;
  const cli = (typeof detectClientInText === "function") ? detectClientInText(raw) : null;
  if (cli) { scope = cli; scopeType = "cliente"; }
  else {
    const _famAliases = { "Electrodomésticos": ["electro"], "Materiales de Construcción": ["construccion", "materiales"] };
    for (const fam of SUPERFAMILIAS.slice(1)) {
      const tokens = [normalizeText(fam), ...(_famAliases[fam] || [])];
      if (tokens.some(t => t && norm.includes(t))) { scope = fam; scopeType = "familia"; break; }
    }
  }
  if (!scope) return { needsPrecision: true, question: "¿De qué cliente o familia? (p. ej. Falabella · Línea Blanca)", options: [] };
  if (pct == null) return { needsPrecision: true, question: "¿Cuánto " + (signo < 0 ? "cae" : "crece") + "? (p. ej. 2%)", options: [] };
  return { growth: { scope, scopeType, pct, signo } };
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 2 · composeGrowthProjection · cálculo Opción A + voz del delta + supuesto.
// Fuente = funciones scenario-aware selladas (Corte 1) → reconcilia con el dive.
// Invariante: delta = round(contribución_actual × pct/100) × signo; proy = actual+delta.
// Familia "se expande por mundo-cliente" sin código extra: su contribución ya es
// Σ contribuciones de clientes (applyScenarioToSfamiliasMargen).
// ════════════════════════════════════════════════════════════════════════════
function composeGrowthProjection(payload, scenarioId) {
  if (!FEATURE_GROWTH_PROJECTION || !payload || !payload.growth) return null;
  const { scope, scopeType, pct, signo } = payload.growth;
  let row = null;
  if (scopeType === "cliente") {
    row = applyScenarioToClientesMargen(scenarioId).find(c => c.nombre === scope);
  } else {
    row = applyScenarioToSfamiliasMargen(scenarioId).find(f => f.sfamilia === scope);
  }
  if (!row) return null;

  const contribActual = row.contribucion;
  // INVARIANTE del founder · exacto sobre la cifra actual del escenario.
  const deltaAporte = Math.round(contribActual * pct / 100) * signo;
  const contribProy = contribActual + deltaAporte;

  const fmt = (v) => "$" + Math.round(v).toLocaleString() + "K";   // formato del dive (Corte 1)
  const deltaAbs = Math.abs(deltaAporte);
  const verbo = signo < 0 ? "cae" : "crece";
  const dirVerbo = signo < 0 ? "baja" : "sube";
  const deltaTxt = (signo < 0 ? "\u2212" : "+") + fmt(deltaAbs);   // U+2212 minus para la caída

  const lines = [];
  lines.push(`Si ${scope} ${verbo} ${pct}%, su contribución ${dirVerbo} de ${fmt(contribActual)} a ${fmt(contribProy)} (${deltaTxt}).`);
  // Supuesto declarado · texto literal del founder.
  lines.push(`Modelo simple: crecimiento sobre la venta actual del escenario, manteniendo margen constante.`);

  return {
    opener: lines.join("\n\n"),
    suggestions: filterTextualSuggestions([]),
    derivedClient: scopeType === "cliente" ? scope : null,
    derivedFamily: scopeType === "familia" ? scope : null,
    derivedModule: "margenes",
  };
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 3 · _priceOrphanSkusForFamily · detección DINÁMICA de SKUs huérfanos.
// Un SKU es huérfano si su marca NO aparece en ninguna fila de clientesMargen
// (mundo-cliente). Hoy: marcas con cliente = {Samsung, LG, Philips, Bosch};
// Makita no → MAK-SAW18V, MAK-COMP-AIR huérfanos. NO hardcodeado.
// ════════════════════════════════════════════════════════════════════════════
function _priceOrphanSkusForFamily(familyName) {
  const brandsWithClient = new Set();
  for (const c of clientesMargen) { if (c.marca) brandsWithClient.add(c.marca); }
  const orphans = [];
  for (const s of skusMargen) {
    if (s.sfamilia === familyName && s.marca && !brandsWithClient.has(s.marca)) {
      orphans.push(s.nombre);
    }
  }
  return orphans;
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 3 · extractPriceSimulation · hermana de extractGrowthSimulation.
// REQUIERE "precio". Excluye margen y pérdida. Va DESPUÉS de growth en el chain
// (doble defensa: growth también excluye precio). Devuelve { price: {...} }, NO
// un override. Alcance: SKU > cliente > familia (el SKU es lo más específico).
// ════════════════════════════════════════════════════════════════════════════
function extractPriceSimulation(text, scenarioId) {
  if (!FEATURE_PRICE_LEVER) return null;
  const raw = text || "";
  // REQUIERE precio. Excluye margen (→ margen sim) y pérdida (→ legacy).
  if (!/\bprecios?\b/i.test(raw)) return null;
  if (/margen|m[aá]rgenes|rentabilidad/i.test(raw)) return null;
  if (/\b(pierd\w*|perd\w*|perder)\b/i.test(raw)) return null;
  // Condicional.
  const norm = normalizeText(raw);
  const condicional = norm.startsWith("si ") || norm.includes(" si ")
    || norm.startsWith("que pasa si") || norm.startsWith("y si");
  // Verbo de precio: sube (↑) / baja (↓).
  const subeRe = /\b(sub\w*|aument\w*|increment\w*)\b/i;
  const bajaRe = /\b(baj\w*|reduc\w*|rebaj\w*|disminu\w*|recort\w*)\b/i;
  const esBaja = bajaRe.test(raw);
  const esSube = subeRe.test(raw);
  if (!esSube && !esBaja) return null;
  const signo = esBaja ? -1 : 1;
  // MICRO-CORTE · magnitud robusta ANTES del guard. ON: número adyacente a
  // %/por ciento o número suelto no embebido en token (evita el "500" de
  // SAM-REF500L). OFF: parser viejo (byte-idéntico a 64204032).
  const numMatch = FEATURE_LEVER_NO_SI
    ? (raw.match(/(?<![A-Za-z])(\d+(?:[.,]\d+)?)\s*(?:%|por\s*ciento)/i)
       || raw.match(/(?<![A-Za-z0-9-])(\d+(?:[.,]\d+)?)(?![A-Za-z0-9-])/))
    : raw.match(/(\d+(?:[.,]\d+)?)/);
  const pct = numMatch ? parseFloat(numMatch[1].replace(",", ".")) : null;
  // MICRO-CORTE · disparo por magnitud (no por "si"). ON: con número dispara sin
  // "si"; sin número y sin "si" → null (cae al dive). OFF: exige condicional.
  if (FEATURE_LEVER_NO_SI) {
    if (pct == null && !condicional) return null;
  } else {
    if (!condicional) return null;
  }
  // Alcance: SKU > cliente > familia.
  let scope = null, scopeType = null;
  const sku = (typeof detectSkuInText === "function") ? detectSkuInText(raw) : null;
  if (sku) { scope = sku; scopeType = "sku"; }
  else {
    const cli = (typeof detectClientInText === "function") ? detectClientInText(raw) : null;
    if (cli) { scope = cli; scopeType = "cliente"; }
    else {
      const _famAliases = { "Electrodomésticos": ["electro"], "Materiales de Construcción": ["construccion", "materiales"] };
      for (const fam of SUPERFAMILIAS.slice(1)) {
        const tokens = [normalizeText(fam), ...(_famAliases[fam] || [])];
        if (tokens.some(t => t && norm.includes(t))) { scope = fam; scopeType = "familia"; break; }
      }
    }
  }
  if (!scope) return { needsPrecision: true, question: "¿De qué SKU, cliente o familia? (p. ej. SAM-REF500L · Falabella · Línea Blanca)", options: [] };
  if (pct == null) return { needsPrecision: true, question: "¿Cuánto " + (signo < 0 ? "baja" : "sube") + " el precio? (p. ej. 2%)", options: [] };
  return { price: { scope, scopeType, pct, signo } };
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 7 · _parseCurrencyK · monto en moneda → $K (la data está en $K · venta
// 19413 = $19.413M). "$1M"/"1 millón" → 1000; "$500K"/"500 mil" → 500; "$2M" → 2000.
// Excluye dígitos pegados a letras/guiones (no agarra el "500" de SAM-REF500L).
// ════════════════════════════════════════════════════════════════════════════
function _parseCurrencyK(raw) {
  if (!raw) return null;
  const t = normalizeText(raw);
  // millones: "$2M" · "2 millones" · "2 millon"
  let m = t.match(/(?<![a-z0-9-])(\d+(?:[.,]\d+)?)\s*(?:m\b|millon(?:es)?\b)/);
  if (m) return Math.round(parseFloat(m[1].replace(",", ".")) * 1000);
  // miles: "$500K" · "500 mil" · "500k"
  m = t.match(/(?<![a-z0-9-])(\d+(?:[.,]\d+)?)\s*(?:k\b|mil\b)/);
  if (m) return Math.round(parseFloat(m[1].replace(",", ".")));
  return null;
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 7 · extractInverseProjection · marco de objetivo de contribución + monto
// en moneda + entidad (SKU > cliente > familia). Detecta total/adicional (sin
// marcador → ambiguo, el composer aplica el default + declara). Sin entidad →
// { inverse:{ noEntity:true } }. NO devuelve .override (no toca compareStates).
// Disjunto de growth/precio (ellos exigen %; esta exige monto + contribución).
// ════════════════════════════════════════════════════════════════════════════
function extractInverseProjection(text, scenarioId) {
  if (!FEATURE_INVERSE_PROJECTION || !text || typeof text !== "string") return null;
  const raw = text;
  const norm = normalizeText(text);
  // Marco de objetivo de contribución: verbo de aporte O la palabra "contribución".
  const aporteVerb = /\b(aportar|aporte|aporta|generar|genere|genera|lograr|logre|contribuir|contribuya)\b/.test(norm);
  const contribWord = /\bcontribucion(es)?\b/.test(norm);
  if (!aporteVerb && !contribWord) return null;
  // Monto en moneda (distinto del % de los levers).
  const target = _parseCurrencyK(raw);
  if (target == null) return null;
  // Alcance · precedencia SKU > cliente > familia.
  let scope = null, scopeType = null;
  const skuM = detectSkuInText(raw);
  if (skuM) { scope = skuM; scopeType = "sku"; }
  else {
    const cliM = detectClientInText(raw);
    if (cliM) { scope = cliM; scopeType = "cliente"; }
    else {
      const _famAliases = { "Electrodomésticos": ["electro"], "Materiales de Construcción": ["construccion", "materiales"] };
      for (const fam of SUPERFAMILIAS.slice(1)) {
        const tokens = [normalizeText(fam), ...(_famAliases[fam] || [])];
        if (tokens.some(t => t && norm.includes(t))) { scope = fam; scopeType = "familia"; break; }
      }
    }
  }
  // Total vs adicional (§3). Total marcado tiene prioridad; luego adicional; si no, ambiguo.
  let modo = "ambiguo";
  if (/\b(adicional(es)?|extra|sumar)\b/.test(norm) || /\bmas\b/.test(norm) || /\bcrecer\b/.test(norm)) modo = "adicional";
  if (/\b(llegar a|alcanzar|un total de|total|que aporte|que genere|que contribuya)\b/.test(norm)) modo = "total";
  // Sin entidad pero con objetivo → honestidad de cartera (§6) / sobre determinístico
  // del capstone (§2-§4). Se incluye `modo` (reusando la detección de arriba) para que
  // composePortfolioInverse distinga total/adicional. OFF: el modo extra es inerte.
  if (!scope) return { inverse: { noEntity: true, target, modo } };
  return { inverse: { scope, scopeType, target, modo } };
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 3 · composePriceLever · cálculo §2 + caveat §3 + declaración huérfanos §5.
// Fuentes §4: SKU=skusMargen (estático), cliente/familia=scenario-aware sellada
// (familia=mundo-cliente, NO suma de SKUs → reconcilia con el dive del Corte 1).
// Invariante: Δ=round(venta×pct/100)×signo; venta_proy=round(venta×(1±pct/100));
// contrib_proy=contrib+Δ; margen_proy=contrib_proy/venta_proy.
// ════════════════════════════════════════════════════════════════════════════
function composePriceLever(payload, scenarioId) {
  if (!FEATURE_PRICE_LEVER || !payload || !payload.price) return null;
  const { scope, scopeType, pct, signo } = payload.price;
  let row = null;
  if (scopeType === "sku") {
    row = skusMargen.find(s => s.nombre === scope);                          // estático (§4 · no scenario-aware)
  } else if (scopeType === "cliente") {
    row = applyScenarioToClientesMargen(scenarioId).find(c => c.nombre === scope);
  } else {
    row = applyScenarioToSfamiliasMargen(scenarioId).find(f => f.sfamilia === scope);  // mundo-cliente sellado
  }
  if (!row) return null;

  const ventaActual   = row.venta;
  const contribActual = row.contribucion;
  // INVARIANTE · precio +X% con volumen/costo/rebate constantes → toda la suba es margen.
  const deltaAporte = Math.round(ventaActual * pct / 100) * signo;
  const contribProy = contribActual + deltaAporte;
  const ventaProy   = Math.round(ventaActual * (1 + signo * pct / 100));
  const margenProy  = ventaProy > 0 ? Math.round((contribProy / ventaProy) * 1000) / 10 : 0;

  const fmt = (v) => "$" + Math.round(v).toLocaleString() + "K";            // formato del dive (Corte 1)
  const deltaAbs = Math.abs(deltaAporte);
  const verbo    = signo < 0 ? "bajás" : "subís";
  const dirVerbo = signo < 0 ? "baja"  : "sube";
  const deltaTxt = (signo < 0 ? "\u2212" : "+") + fmt(deltaAbs);            // U+2212 minus para la baja

  const lines = [];
  lines.push(`Si ${verbo} ${pct}% el precio de ${scope}, su contribución ${dirVerbo} de ${fmt(contribActual)} a ${fmt(contribProy)} (${deltaTxt}). Sobre una venta de ${fmt(ventaActual)} \u2192 ${fmt(ventaProy)}, el margen pasa a ${margenProy}%.`);
  // Caveat sellado · prominente (texto literal del founder).
  lines.push(`Esto es el techo bruto de la palanca: asume que no perdés volumen. En la práctica, una suba de precio puede reducir la cantidad vendida.`);
  // Familia con SKUs huérfanos → declaración (§5 · texto literal).
  if (scopeType === "familia") {
    const orphans = _priceOrphanSkusForFamily(scope);
    if (orphans.length) {
      lines.push(`${scope} se proyecta sobre la venta cliente sellada del escenario. Los SKUs ${orphans.join(" y ")} tienen venta de SKU pero no cliente asignado en este dataset; se pueden simular como SKU, pero no se incorporan al total de familia sin inventar relación.`);
    }
  }

  return {
    opener: lines.join("\n\n"),
    suggestions: filterTextualSuggestions([]),
    derivedSku: scopeType === "sku" ? scope : null,
    derivedClient: scopeType === "cliente" ? scope : null,
    derivedFamily: scopeType === "familia" ? scope : null,
    derivedModule: "margenes",
  };
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 7 · composeInverseProjection · aplica el modelo §2 + total/adicional §3 +
// fuente §4. Devuelve los 6 números + la declaración de interpretación + el edge
// honesto "ya por encima". Cierra algebraicamente: venta_nec × margen_ef == objetivo.
// Cero número nuevo: venta/contribución salen del agregador sellado de la entidad.
// ════════════════════════════════════════════════════════════════════════════
// CAPSTONE · composePortfolioInverse · inversa de cartera (sin entidad).
// Sobre determinístico: uniforme (blended) + rango (mín vía mayor margen, máx vía
// menor margen) + límite declarado del óptimo (§4). Fuente: applyScenarioToClientes
// Margen (mundo-cliente scenario-aware). Margen efectivo = contrib/venta (exacto, no
// redondeado). Cierre algebraico: venta_X × margen_X = incrementoContrib (§2).
// NO recomienda un mix óptimo (el borde eficiente es límite matemático, no plan).
// ════════════════════════════════════════════════════════════════════════════
function composePortfolioInverse(inv, scenarioId) {
  const fmtM = (k) => `$${(k / 1000).toFixed(2)}M`;       // $K → $X.XXM
  const pct  = (x) => `${(x * 100).toFixed(1)}%`;
  const cm = applyScenarioToClientesMargen(scenarioId) || [];

  // Degradación honesta (§5.5): <2 entidades con margen calculable, o ΣV=0.
  const valid = cm.filter(c => c && c.venta > 0 && typeof c.contribucion === "number");
  if (valid.length < 2) {
    return {
      opener: `No tengo base suficiente para el sobre de cartera en este escenario: necesito al menos dos entidades con venta y margen calculables.`,
      suggestions: filterTextualSuggestions([]),
      sentrixAction: null,
      derivedModule: "margenes",
    };
  }
  const SV = valid.reduce((a, c) => a + c.venta, 0);
  const SC = valid.reduce((a, c) => a + c.contribucion, 0);
  if (!(SV > 0)) {
    return {
      opener: `No tengo base suficiente: la cartera no tiene venta agregada en este escenario.`,
      suggestions: filterTextualSuggestions([]),
      sentrixAction: null,
      derivedModule: "margenes",
    };
  }
  const blended = SC / SV;

  // Entidades de mayor / menor margen efectivo (reales · §2).
  let eMax = valid[0], eMin = valid[0];
  for (const c of valid) {
    const m = c.contribucion / c.venta;
    if (m > eMax.contribucion / eMax.venta) eMax = c;
    if (m < eMin.contribucion / eMin.venta) eMin = c;
  }
  const mMax = eMax.contribucion / eMax.venta;   // borde eficiente (mínima venta)
  const mMin = eMin.contribucion / eMin.venta;   // borde caro (máxima venta)

  // Total vs adicional (§3) · ambiguo → default Corte 7, declarado.
  const target = inv.target;
  let modo = inv.modo || "ambiguo";
  let ambiguo = false;
  if (modo === "ambiguo") { ambiguo = true; modo = target > SC ? "total" : "adicional"; }
  const incrementoContrib = modo === "adicional" ? target : (target - SC);

  // Edge (§3): total ya superado.
  if (incrementoContrib <= 0) {
    return {
      opener: `La cartera ya aporta ${fmtM(SC)} de contribución, por encima del objetivo de ${fmtM(target)}. No necesitás crecer para llegar ahí.`,
      suggestions: filterTextualSuggestions(["Margen por cliente", "Cuánto debe vender Falabella para aportar $1M adicional"]),
      sentrixAction: { label: "Ver márgenes", moduleChip: "Márgenes", payload: { modulo: "margenes", clientes: [], skus: [] } },
      derivedModule: "margenes",
    };
  }

  // El sobre (§2).
  const ventaUniforme = incrementoContrib / blended;
  const ventaMin = incrementoContrib / mMax;     // vía mayor margen
  const ventaMax = incrementoContrib / mMin;     // vía menor margen

  // Interpretación SIEMPRE explícita (§3).
  const interp = modo === "adicional"
    ? `interpreto como adicional sobre los ${fmtM(SC)} actuales`
    : (ambiguo
        ? `interpreto como total — alcanzar ${fmtM(target)} desde los ${fmtM(SC)} actuales; si era adicional, decímelo`
        : `interpreto como total: alcanzar ${fmtM(target)} desde los ${fmtM(SC)} actuales`);
  const head = modo === "adicional"
    ? `Para +${fmtM(target)} de contribución adicional`
    : `Para ${fmtM(target)} de contribución total`;

  let opener = `${head} (${interp}): si toda la cartera crece proporcionalmente (margen blended ${pct(blended)}), necesitás vender +${fmtM(ventaUniforme)}. `;
  opener += `El rango determinístico va de +${fmtM(ventaMin)} (si todo creciera vía la entidad de mayor margen, ${eMax.nombre} ${pct(mMax)}) a +${fmtM(ventaMax)} (vía la de menor margen, ${eMin.nombre} ${pct(mMin)}).`;
  // Límite del óptimo (§4) · borde como límite, NO como plan.
  opener += `\n\nEl borde eficiente (+${fmtM(ventaMin)}) asume que todo el crecimiento ocurre en la entidad de mayor margen (${eMax.nombre}, ${pct(mMax)}). Es un límite matemático, no un plan operativo. Recomendar un mix óptimo real requiere capacidad/topes de crecimiento por entidad, que este dataset no trae.`;

  return {
    opener,
    suggestions: filterTextualSuggestions([`Cuánto debe vender ${eMin.nombre} para aportar ${fmtM(target)}`, "Margen por cliente"]),
    sentrixAction: { label: "Ver márgenes", moduleChip: "Márgenes", payload: { modulo: "margenes", clientes: [], skus: [] } },
    derivedModule: "margenes",
  };
}

// ════════════════════════════════════════════════════════════════════════════
function composeInverseProjection(payload, scenarioId) {
  if (!FEATURE_INVERSE_PROJECTION || !payload || !payload.inverse) return null;
  const inv = payload.inverse;
  const fmtM = (k) => `$${(k / 1000).toFixed(2)}M`;   // $K → $X.XXM

  // ── Honestidad de cartera (§6) · objetivo sin entidad ──
  // ON → sobre determinístico (composePortfolioInverse). OFF → fallback Corte 7 intacto.
  if (inv.noEntity) {
    if (FEATURE_PORTFOLIO_INVERSE) return composePortfolioInverse(inv, scenarioId);
    return {
      opener: `Sin elegir dónde crecer, hay múltiples soluciones: la venta requerida depende del margen de la entidad que empuje el crecimiento. Puedo calcularlo para un cliente, familia o SKU específico, o mostrarte el rango entre la entidad de menor y mayor margen.`,
      suggestions: filterTextualSuggestions(["Cuánto debe vender Falabella para aportar $5M", "Cuánto debe vender Línea Blanca para aportar $500K adicional"]),
      sentrixAction: null,
      derivedModule: "margenes",
    };
  }

  // ── Resolver entidad · venta/contribución actuales (fuente §4) ──
  let venta = null, contrib = null, nombre = inv.scope, fuenteNota = "";
  if (inv.scopeType === "cliente") {
    const r = applyScenarioToClientesMargen(scenarioId).find(c => c.nombre === inv.scope);
    if (r) { venta = r.venta; contrib = r.contribucion; nombre = r.nombre; }
  } else if (inv.scopeType === "familia") {
    const r = applyScenarioToSfamiliasMargen(scenarioId).find(f => f.sfamilia === inv.scope);
    if (r) { venta = r.venta; contrib = r.contribucion; nombre = r.sfamilia; }
  } else if (inv.scopeType === "sku") {
    const r = skusMargen.find(s => s.nombre === inv.scope);
    if (r) { venta = r.venta; contrib = r.contribucion; nombre = r.nombre; fuenteNota = " (dato directo del SKU)"; }
  }
  if (venta == null || !venta) {
    return { opener: `No tengo a ${inv.scope} en el detalle de este escenario.`, suggestions: filterTextualSuggestions([]), sentrixAction: null, derivedModule: "margenes" };
  }

  const margenEf = contrib / venta;   // margen EFECTIVO (criterio 2 · cierra el álgebra)

  // ── Resolver modo (ambiguo → default §3) ──
  let modo = inv.modo;
  if (modo === "ambiguo") modo = inv.target > contrib ? "total" : "adicional";

  // ── Cálculo §2 ──
  let ventaNec, ventaInc, contribObjetivoTotal;
  if (modo === "total") {
    contribObjetivoTotal = inv.target;
    ventaNec = inv.target / margenEf;
    ventaInc = ventaNec - venta;
  } else {
    ventaInc = inv.target / margenEf;
    ventaNec = venta + ventaInc;
    contribObjetivoTotal = contrib + inv.target;
  }
  const crecimiento = ventaInc / venta * 100;

  const _calc = { venta, contrib, margenEf, modo, target: inv.target, ventaNec, ventaInc, crecimiento, contribObjetivoTotal };
  const _derived = {
    derivedClient: inv.scopeType === "cliente" ? nombre : null,
    derivedFamily: inv.scopeType === "familia" ? nombre : null,
    derivedSku: inv.scopeType === "sku" ? nombre : null,
    derivedModule: "margenes",
  };

  // ── Edge honesto (§3) · ya en o por encima del objetivo ──
  if (crecimiento <= 0) {
    return {
      opener: `${nombre} ya aporta ${fmtM(contrib)}, por encima de ese objetivo — no requiere crecimiento.`,
      suggestions: filterTextualSuggestions([`Cuánto vende ${nombre}`, `Margen de ${nombre}`]),
      sentrixAction: { label: "Ver márgenes", moduleChip: "Márgenes", payload: { modulo: "margenes", clientes: [], skus: [] } },
      _calc, ..._derived,
    };
  }

  // ── Veredicto ejecutivo (§7) · la cuenta a la vista + declaración total/adicional ──
  let opener;
  if (modo === "total") {
    opener = `Para que ${nombre} alcance ${fmtM(contribObjetivoTotal)} de contribución total (interpreto los ${fmtM(inv.target)} como meta total): a su margen efectivo de ${(margenEf * 100).toFixed(1)}%${fuenteNota}, necesita vender ${fmtM(ventaNec)} — hoy vende ${fmtM(venta)} (aporta ${fmtM(contrib)}), así que requiere +${fmtM(ventaInc)} (crecer ${crecimiento.toFixed(1)}%).`;
  } else {
    opener = `Para que ${nombre} sume ${fmtM(inv.target)} de contribución adicional (sobre los ${fmtM(contrib)} actuales): a su margen efectivo de ${(margenEf * 100).toFixed(1)}%${fuenteNota}, necesita vender ${fmtM(ventaNec)} — hoy vende ${fmtM(venta)}, así que requiere +${fmtM(ventaInc)} (crecer ${crecimiento.toFixed(1)}%).`;
  }
  return {
    opener,
    suggestions: filterTextualSuggestions([`Cuánto vende ${nombre}`, `Margen de ${nombre}`, "Otra meta de contribución"]),
    sentrixAction: { label: "Ver márgenes", moduleChip: "Márgenes", payload: { modulo: "margenes", clientes: inv.scopeType === "cliente" ? [nombre] : [], skus: inv.scopeType === "sku" ? [nombre] : [] } },
    _calc, ..._derived,
  };
}

// ═══════════════════════════════════════════════════════
// BRIEF #15 · scanMechanisms
//
// Escanea los 5 mecanismos contra todos los clientes y
// devuelve mapa de qué está activo + métricas agregadas.
// Es la NUEVA FUENTE DE VERDAD del motor.
// ═══════════════════════════════════════════════════════

function scanMechanisms(scenarioId, override) {
  const ventas = applyScenarioToClientesVentas(scenarioId, override);
  const margenes = applyScenarioToClientesMargen(scenarioId, override);
  const totalVentas = ventas.reduce((s, c) => s + c.actual, 0);
  const totalContribucion = margenes.reduce((s, c) => s + c.contribucion, 0);
  const clientNames = ventas.map(c => c.nombre);

  const scan = {};

  for (const [mechanismId, mechanism] of Object.entries(MECHANISM_REGISTRY)) {
    const instances = [];

    for (const clientName of clientNames) {
      if (mechanism.detect(clientName, scenarioId)) {
        const evidence = mechanism.gatherEvidence(clientName, scenarioId);
        if (evidence) {
          const severity = mechanism.severityOfInstance(evidence);
          instances.push({ ...evidence, severity });
        }
      }
    }

    // Sort instances by materiality descending
    if (mechanismId === "commercial_erosion") {
      instances.sort((a, b) => b.recuperable_at_target_3_5 - a.recuperable_at_target_3_5);
    } else if (mechanismId === "quality_of_growth_deterioration") {
      instances.sort((a, b) => b.contribucion_perdida_M - a.contribucion_perdida_M);
    } else if (mechanismId === "customer_dependency_risk") {
      instances.sort((a, b) => b.contribucion_M - a.contribucion_M);
    }

    let aggregateMetrics = {};

    if (mechanismId === "commercial_erosion" && instances.length > 0) {
      const total_recuperable_3_5 = instances.reduce((s, i) => s + i.recuperable_at_target_3_5, 0);
      const total_recuperable_3_0 = instances.reduce((s, i) => s + i.recuperable_at_bestPractice_3_0, 0);

      // BRIEF #15-bis · FIX 1
      // pct_of_total_sales calcula sobre TOP3 (que es lo que el composer muestra),
      // NO sobre todas las instances. Adicionalmente: corregir bug de unidad ·
      // ventas_M está en M ($M, equivalente a 1000K), totalVentas viene de
      // c.actual que está en K. La conversión correcta es sum_ventas_M * 1000
      // dividido por totalVentas_K. El bug previo aplicaba esa multiplicación
      // sobre TODAS las instances, sumando hasta 100% en Crisis o 76.7% en Tensión.
      const top3_instances = instances.slice(0, 3);
      const sum_ventas_top3_M = top3_instances.reduce((s, i) => s + i.ventas_M, 0);
      const sum_ventas_top3_K = sum_ventas_top3_M * 1000;

      aggregateMetrics = {
        recuperable_total_K: Math.round(total_recuperable_3_5),
        recuperable_total_M_at_3_0: +(total_recuperable_3_0 / 1000).toFixed(2),
        recuperable_total_M_at_3_5: +(total_recuperable_3_5 / 1000).toFixed(2),
        pct_of_total_sales: +((sum_ventas_top3_K / totalVentas) * 100).toFixed(1),
        pct_of_total_contribution: +((total_recuperable_3_5 / totalContribucion) * 100).toFixed(1),
        instances_count: instances.length,
        top3_count: top3_instances.length,
      };
    }

    if (mechanismId === "quality_of_growth_deterioration" && instances.length > 0) {
      const total_contribucion_perdida = instances.reduce((s, i) => s + i.contribucion_perdida_M, 0);
      aggregateMetrics = {
        contribucion_perdida_M: +total_contribucion_perdida.toFixed(2),
        instances_count: instances.length,
        crecimiento_range: {
          min: Math.min(...instances.map(i => i.crecimiento_pct)),
          max: Math.max(...instances.map(i => i.crecimiento_pct)),
        },
      };
    }

    if (mechanismId === "customer_dependency_risk" && instances.length > 0) {
      const top3 = instances.slice(0, 3);
      const top3_participacion = top3.reduce((s, i) => s + i.participacion_pct, 0);
      const top3_contribucion = top3.reduce((s, i) => s + i.contribucion_M, 0);
      aggregateMetrics = {
        instances_count: instances.length,
        top3_names: top3.map(i => i.clientName),
        top3_participacion_pct: +top3_participacion.toFixed(1),
        top3_contribucion_M: +top3_contribucion.toFixed(2),
      };
    }

    scan[mechanismId] = {
      mechanismId,
      nombre: mechanism.nombre,
      nombre_capitalizado: mechanism.nombre_capitalizado,
      clausula: mechanism.clausula,
      descripcion_humana: mechanism.descripcion_humana,
      triggered: instances.length > 0,
      instances,
      aggregate: aggregateMetrics,
      relations: mechanism.relations,
    };
  }

  return scan;
}

// ═══════════════════════════════════════════════════════
// BRIEF #15 · R7 Helpers + identifyPrimaryMechanism
// ═══════════════════════════════════════════════════════

function r7_formatCurrencyK(amount) {
  if (amount >= 1000) return `aproximadamente $${+(amount / 1000).toFixed(1)}M`;
  return `aproximadamente $${Math.round(amount)}K`;
}

function r7_formatCurrencyM(amountM) {
  return `$${amountM.toFixed(2)}M`;
}

function r7_listInstances(instances, maxNames = 3) {
  const names = instances.slice(0, maxNames).map(i => i.clientName);
  if (names.length === 1) return names[0];
  if (names.length === 2) return `${names[0]} y ${names[1]}`;
  const allButLast = names.slice(0, -1).join(", ");
  return `${allButLast} y ${names[names.length - 1]}`;
}

// ═══════════════════════════════════════════════════════
// BRIEF #16 · composeSentrixAction
//
// Genera el payload del botón contextual que abre Sentrix
// con filtros + banner pre-aplicados desde una respuesta
// específica de ADI. Transferencia de contexto cognitivo
// ADI → Sentrix (NO solo navegación).
// ═══════════════════════════════════════════════════════

function composeSentrixAction(composerType, payload) {
  if (composerType === "client_deep_dive") {
    const banner = payload.primaryMechanism
      ? (payload.primaryMechanism.nombre_capitalizado
         || (payload.primaryMechanism.nombre
             ? payload.primaryMechanism.nombre.charAt(0).toUpperCase() + payload.primaryMechanism.nombre.slice(1)
             : null))
      : null;
    return {
      label: `Ver ${payload.clientName}`,
      moduleChip: "Márgenes",
      payload: {
        modulo: "margenes",
        clientes: [payload.clientName],
        mechanismBanner: banner,
      },
    };
  }

  if (composerType === "mechanism_commercial_erosion") {
    const top3 = payload.instances.slice(0, 3);
    const clientNames = top3.map(i => i.clientName);
    return {
      label: `Ver ${clientNames.length} cuentas con erosión`,
      moduleChip: "Márgenes",
      payload: {
        modulo: "margenes",
        clientes: clientNames,
        mechanismBanner: "Erosión comercial",
      },
    };
  }

  if (composerType === "mechanism_quality_growth") {
    const instances = payload.instances;
    const clientNames = instances.map(i => i.clientName);
    return {
      label: `Ver ${clientNames.length} cuentas en deterioro`,
      moduleChip: "Márgenes",
      payload: {
        modulo: "margenes",
        clientes: clientNames,
        mechanismBanner: "Deterioro de calidad de crecimiento",
      },
    };
  }

  if (composerType === "mechanism_dependency_risk") {
    const top3Names = payload.top3_names;
    return {
      label: `Ver Top 3`,
      moduleChip: "Márgenes",
      payload: {
        modulo: "margenes",
        clientes: top3Names,
        mechanismBanner: "Riesgo de dependencia de cliente",
      },
    };
  }

  if (composerType === "mechanism_ranking") {
    const topMechId = payload.topMechanismId;
    if (topMechId === "commercial_erosion") {
      const top3 = payload.instances.slice(0, 3);
      return {
        label: `Ver ${top3.length} cuentas con erosión`,
        moduleChip: "Márgenes",
        payload: {
          modulo: "margenes",
          clientes: top3.map(i => i.clientName),
          mechanismBanner: "Erosión comercial",
        },
      };
    }
    return null;
  }

  if (composerType === "priority_recommendation") {
    return {
      label: `Ver ${payload.primaryClient}`,
      moduleChip: "Márgenes",
      payload: {
        modulo: "margenes",
        clientes: [payload.primaryClient],
        mechanismBanner: "Erosión comercial",
      },
    };
  }

  if (composerType === "fuga_distribuida") {
    return {
      label: `Ver ${payload.tier1Names.length} cuentas con presión`,
      moduleChip: "Márgenes",
      payload: {
        modulo: "margenes",
        clientes: payload.tier1Names,
        mechanismBanner: "Erosión comercial",
      },
    };
  }

  return null;
}

function identifyPrimaryMechanism(clientName, scan) {
  for (const [mechanismId, m] of Object.entries(scan)) {
    if (!m.triggered) continue;
    const top3 = m.instances.slice(0, 3);
    if (top3.some(i => i.clientName === clientName)) {
      return { id: mechanismId, nombre: m.nombre };
    }
  }
  return null;
}

// ═══════════════════════════════════════════════════════
// BRIEF #21-A · composeOutOfDomainResponse
//
// Compone respuesta honesta cuando el usuario pregunta por métricas
// financieras fuera del dominio actual de ADI (EBITDA, OPEX, flujo de
// caja, utilidad neta, etc.).
//
// Principio: ADI NO inventa. Declina con claridad y redirige al
// dominio modelado (comercial-operacional).
// ═══════════════════════════════════════════════════════

function composeOutOfDomainResponse(scenarioId) {
  const opener = `ADI hoy opera sobre dominio comercial y operacional · no es un motor financiero completo. Métricas como EBITDA, utilidad neta, gastos administrativos o flujo de caja no están modeladas en el sistema actual.\n\nLo que sí puedo mostrarte es: contribución por cliente y producto, margen vs benchmark, capital inmovilizado por SKU, rotación de inventario, erosión comercial y dependencia de cartera.\n\n¿Por dónde profundizamos?`;

  const suggestions = [
    "Cómo está la contribución por cliente",
    "Dónde tengo capital inmovilizado",
    "Qué clientes presionan el margen",
  ];

  // BRIEF N-bis · Tipo A puro · suggestions filtradas en return
  return { opener, suggestions: filterTextualSuggestions(suggestions), sentrixAction: null };
}

// ═══════════════════════════════════════════════════════
// BRIEF #21-B · Helper · enriquece skuInventario con cálculos
// determinísticos para análisis de contribución:
//   · valor_unitario        = stockUSD / stockUnd
//   · ventas_mensuales      = vendidoMes × valor_unitario
//   · contribucion_mensual  = ventas_mensuales × (margenPct/100)
//
// Determinístico bitwise sobre el dataset estático.
// ═══════════════════════════════════════════════════════

function enrichSkuWithContribution() {
  return skuInventario.map(s => {
    const valorUnitario = s.stockUnd > 0 ? s.stockUSD / s.stockUnd : 0;
    const ventasMensuales = s.vendidoMes * valorUnitario;
    const contribucionMensual = ventasMensuales * (s.margenPct / 100);

    return {
      ...s,
      valorUnitario,
      ventasMensuales,
      contribucionMensual,
    };
  });
}

// ═══════════════════════════════════════════════════════
// BRIEF #21-B · composeProductContributionAnalysis
//
// Responde preguntas ambiguas tipo "qué productos dejan más plata" /
// "qué SKUs rinden más" / "qué items aportan más valor".
//
// FORMATO MIXTO (decisión locked del founder):
//   1. Ranking estructurado: SKU → Contribución $X | Ventas $Y | Margen Z%
//   2. Lectura ejecutiva: interpretación comparativa
//
// Resolución interna del lenguaje ambiguo:
//   Concepto ambiguo: "plata" / "deja" / "aporta" / "rinde"
//   Métrica principal: Contribución mensual
//   Métricas de contexto: Ventas mensuales + Margen %
// ═══════════════════════════════════════════════════════

function composeProductContributionAnalysis(scenarioId) {
  const enriched = enrichSkuWithContribution();

  // Ordenar por contribución descendente y tomar top 4 (Ferrari corto)
  const sorted = [...enriched].sort((a, b) => b.contribucionMensual - a.contribucionMensual);

  // BRIEF #21-C · Benchmarks de cartera para causalidad inferida.
  // Promedios deterministicos sobre el portafolio completo.
  const totalCartera = enriched.length;
  const promedioMargen = enriched.reduce((sum, s) => sum + s.margenPct, 0) / totalCartera;
  const promedioRotacion = enriched.reduce((sum, s) => sum + s.rotacion, 0) / totalCartera;
  const promedioVentas = enriched.reduce((sum, s) => sum + s.ventasMensuales, 0) / totalCartera;

  const top4 = sorted.slice(0, 4);

  if (top4.length === 0) {
    return {
      opener: "No tengo datos suficientes para calcular contribución por SKU en el escenario actual.",
      suggestions: [],
      sentrixAction: null,
    };
  }

  // Formato compacto de cifras
  const fmtK = (val) => {
    if (val >= 1000) return `$${(val/1000).toFixed(1)}K`;
    return `$${Math.round(val)}`;
  };

  // BRIEF #21-C · Detectar patrón económico de cada SKU del top.
  // Retorna etiqueta según comportamiento real de los datos.
  // Prioridad de detección: severidad operativa primero, virtuosismo
  // después, casos disonantes (volumen/margen) al final.
  //
  // REGLA DURA (founder): solo afirma lo que el dataset sostiene.
  // Campos usados: margenPct, rotacion, ventaDiaria, vendidoMes,
  // doh, diasSinVenta. NO inventa carga comercial, convenios,
  // acciones del retail.
  function detectSkuPattern(s) {
    // Prioridad 1 · Capital inmovilizado (severo)
    if (s.doh > 90 || s.diasSinVenta > 60) {
      return "capital_inmovilizado";
    }
    // Prioridad 2 · Exposición / continuidad
    if (s.diasSinVenta > 30) {
      return "exposicion_continuidad";
    }
    // Prioridad 3 · Virtuoso (lidera múltiples dimensiones)
    if (s.margenPct > promedioMargen &&
        s.rotacion > promedioRotacion &&
        s.ventasMensuales > promedioVentas) {
      return "virtuoso";
    }
    // Prioridad 4 · Alto volumen con margen relativo bajo
    if (s.ventasMensuales > promedioVentas * 1.3 &&
        s.margenPct < promedioMargen) {
      return "alto_volumen_baja_contribucion";
    }
    // Prioridad 5 · Margen alto subexplotado
    if (s.margenPct > promedioMargen * 1.15 &&
        s.ventasMensuales < promedioVentas * 0.7) {
      return "margen_alto_subexplotado";
    }
    // Default · estable (sin señales fuertes)
    return "estable";
  }

  // Anotar cada SKU del top con su patrón detectado
  top4.forEach(s => { s.pattern = detectSkuPattern(s); });

  // ── M1 · Ranking estructurado (pieza estructurada del formato mixto)
  const rankingLines = top4.map(s =>
    `${s.sku} → Contribución ${fmtK(s.contribucionMensual)} | Ventas ${fmtK(s.ventasMensuales)} | Margen ${s.margenPct}%`
  ).join("\n");

  const m1 = `Los productos con mayor contribución mensual son:\n\n${rankingLines}`;

  // ── M2 · Lectura ejecutiva CAUSAL (BRIEF #21-C)
  //
  // Construye explicación basada en el comportamiento real de los
  // datos del top 1 y comparación con promedios de cartera. REGLA:
  // solo afirma lo que el dataset sostiene (margen, rotación, ventas,
  // venta diaria, DOH, días sin venta). NO inventa convenios, carga
  // comercial, presión de proveedores ni acciones del retail.
  const topByVentas = [...top4].sort((a, b) => b.ventasMensuales - a.ventasMensuales)[0];
  const topByContrib = top4[0];

  let lecturaCausal = "";

  if (topByVentas.sku !== topByContrib.sku) {
    // CASO DISONANTE · top en ventas ≠ top en contribución
    // Causa explicable: margen unitario superior del líder de contribución.
    const gapMargen = (topByContrib.margenPct - topByVentas.margenPct).toFixed(0);
    lecturaCausal = `${topByContrib.sku} lidera el aporte económico aunque ${topByVentas.sku} tiene ventas más altas (${fmtK(topByVentas.ventasMensuales)} vs ${fmtK(topByContrib.ventasMensuales)}). La diferencia se explica por margen unitario superior (${topByContrib.margenPct}% vs ${topByVentas.margenPct}%, ${gapMargen} puntos arriba) que mejora la conversión de venta a contribución.`;
  } else {
    // CASO VIRTUOSO · líder absoluto · agregar CAUSALIDAD desde datos
    const sku = topByContrib;
    const razones = [];
    // BRIEF #21-C · solo afirmar razones con gap significativo
    // (≥ 1 punto en margen, ≥ 0.5x en rotación). Gap 0 no es causa.
    const gapMargenNum = sku.margenPct - promedioMargen;
    if (gapMargenNum >= 1) {
      razones.push(`margen ${sku.margenPct}% (${gapMargenNum.toFixed(0)} puntos sobre el promedio cartera de ${promedioMargen.toFixed(0)}%)`);
    }
    const gapRotacion = sku.rotacion - promedioRotacion;
    if (gapRotacion >= 0.5) {
      razones.push(`rotación ${sku.rotacion}x (sobre el promedio cartera de ${promedioRotacion.toFixed(1)}x)`);
    }
    if (sku.diasSinVenta === 0) {
      razones.push(`venta diaria sostenida (${sku.ventaDiaria} unidades/día)`);
    }

    const razonesText = razones.length > 0
      ? `La conversión de venta a contribución se sostiene en ${razones.join(", ")}.`
      : `Combina volumen y margen en niveles superiores al portafolio.`;

    lecturaCausal = `${sku.sku} lidera tanto ventas como contribución del portafolio. ${razonesText}`;
  }

  // Patrón de categoría dominante (se mantiene del BRIEF #21-B)
  const categoriasTop = {};
  top4.forEach(s => {
    categoriasTop[s.sfamilia] = (categoriasTop[s.sfamilia] || 0) + 1;
  });
  const catDominanteEntry = Object.entries(categoriasTop).sort((a, b) => b[1] - a[1])[0];

  let patronCategoria = "";
  if (catDominanteEntry && catDominanteEntry[1] >= 2) {
    patronCategoria = ` La categoría ${catDominanteEntry[0]} concentra ${catDominanteEntry[1]} de los 4 SKUs del top, mostrando un patrón estructural en el portafolio.`;
  }

  const m2 = `${lecturaCausal}${patronCategoria}`;

  // ── M3 · FOCO DINÁMICO (BRIEF #21-C)
  //
  // Recomendación accionable basada en los patrones detectados en
  // el top 4. Combina hasta 2 patrones priorizados para construir
  // foco específico (no plantilla genérica).
  function focoForPattern(pattern, sku) {
    switch (pattern) {
      case "virtuoso":
        return `sostener ${sku.sku} (líder absoluto del portafolio) y proteger sus condiciones operativas`;
      case "alto_volumen_baja_contribucion":
        return `revisar la presión económica sobre ${sku.sku} (alto volumen pero margen ${sku.margenPct}% bajo el promedio cartera)`;
      case "margen_alto_subexplotado":
        return `evaluar escalar ${sku.sku} (margen ${sku.margenPct}% superior pero volumen aún bajo)`;
      case "capital_inmovilizado":
        return `revisar capital inmovilizado en ${sku.sku} (DOH ${sku.doh}d, ${sku.diasSinVenta} días sin venta)`;
      case "exposicion_continuidad":
        return `revisar continuidad comercial de ${sku.sku} (${sku.diasSinVenta} días sin venta)`;
      case "estable":
        return null;
      default:
        return null;
    }
  }

  // Extraer focos del top 4 (filtrar nulls de "estable")
  // BRIEF #21-C · cada foco anotado con su patrón para permitir
  // deduplicación inteligente abajo.
  const focosAnotados = top4
    .map(s => {
      const text = focoForPattern(s.pattern, s);
      return text === null ? null : { sku: s.sku, pattern: s.pattern, text };
    })
    .filter(f => f !== null);

  let m3 = "";
  if (focosAnotados.length === 0) {
    m3 = `Sin patrones críticos detectados en el top 4 · la composición actual opera dentro del rango healthy.`;
  } else {
    // Deduplicación: si todos los focos son del mismo patrón (caso
    // típico: 2+ virtuosos), mencionar solo el líder y resumir el resto.
    const patronesUnicos = [...new Set(focosAnotados.map(f => f.pattern))];
    if (patronesUnicos.length === 1 && focosAnotados.length >= 2) {
      const lider = focosAnotados[0];
      const restantes = focosAnotados.slice(1).map(f => f.sku).join(", ");
      m3 = `El foco operativo está en ${lider.text}. Los SKUs ${restantes} sostienen el mismo patrón en el top.`;
    } else if (focosAnotados.length === 1) {
      m3 = `El foco operativo está en ${focosAnotados[0].text}.`;
    } else {
      // Multiples patrones distintos · tomar 2 primeros
      const focosPriorizados = focosAnotados.slice(0, 2);
      m3 = `Dos focos operativos: ${focosPriorizados[0].text}; y ${focosPriorizados[1].text}.`;
    }
  }

  // ── Confianza
  const totalContribucion = enriched.reduce((sum, s) => sum + s.contribucionMensual, 0);
  const top4Contribucion = top4.reduce((sum, s) => sum + s.contribucionMensual, 0);
  const pctConcentracion = totalContribucion > 0
    ? ((top4Contribucion / totalContribucion) * 100).toFixed(0)
    : "0";

  const confianza = `*Confianza alta · ${pctConcentracion}% de la contribución mensual del portafolio se concentra en estos 4 SKUs. Cifras determinísticas sobre dataset actual.*`;

  const opener = `${m1}\n\n${m2}\n\n${m3}\n\n${confianza}`;

  // Suggestions contextuales
  const suggestions = [
    `Profundizar en ${topByContrib.sku}`,
    `Cómo está la contribución por categoría`,
    `Qué SKUs tienen el peor aporte económico`,
  ];

  // Sentrix action · abre Inventario filtrado por los SKUs del top.
  // BRIEF #23 · payload.skus sincroniza la tabla Sentrix con exactamente
  // los SKUs que ADI mencionó en el ranking (no los 13 del portafolio).
  const sentrixAction = {
    label: `Ver ${top4.length} SKUs de mayor contribución`,
    moduleChip: "Inventario",
    payload: {
      modulo: "inventario",
      clientes: [],
      skus: top4.map(s => s.sku),
      mechanismBanner: "Aporte económico por producto",
    },
  };

  // BRIEF N-bis · Tipo A puro · suggestions filtradas en return
  return { opener, suggestions: filterTextualSuggestions(suggestions), sentrixAction };
}

// ═══════════════════════════════════════════════════════
// BRIEF #20 · composeSkuOperationalAnalysis
//
// Composer Ferrari nivel SKU. Responde preguntas operacionales con
// Top SKUs críticos ordenados por capital atrapado, DOH y días sin
// venta. Usa el dataset skuInventario (13 SKUs) que es estático en
// los 3 escenarios — el filtro determinístico identifica los SKUs
// críticos por alerta/estado y los rankea por stockUSD.
//
// Estructura: 4 movimientos M1/M2/M3/M4 + Confianza. R7 compliant
// (cifras 2-3 por movimiento, voz humana, sin maquinaria visible).
// ═══════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════
// BRIEF #24 · composeSkuDeepDive
//
// Análisis individual de un SKU específico cuando el usuario lo menciona
// (por nombre canónico LG-DRYER8KG o resuelto por deíctico "el primero").
//
// Estructura Ferrari · Evidencia + Lectura causal + Foco + Confianza,
// sin etiquetas visibles (consistente con BRIEF #22-bis).
//
// Causalidad SOLO desde campos del dataset skuInventario:
//   stockUSD, stockUnd, vendidoMes, rotacion, doh, cobertura, margenPct,
//   diasSinVenta, alerta, estado, marca, sfamilia, bodega.
//
// Determinismo bitwise · misma entrada → misma salida.
// R7 compliant · voz humana, sin "criterios formales" ni "maquinaria".
// ═══════════════════════════════════════════════════════

function composeSkuDeepDive(skuName, scenarioId) {
  const sku = skuInventario.find(s => s.sku === skuName);

  if (!sku) {
    return {
      opener: `No tengo datos del SKU ${skuName} en el escenario actual.`,
      // BRIEF N-bis · Tipo A puro · filtradas
      suggestions: filterTextualSuggestions([
        "Cuáles son los SKUs críticos del portafolio",
        "Qué productos dejan más plata",
      ]),
      sentrixAction: null,
    };
  }

  // ── Helpers formato consistentes con otros composers Ferrari
  const fmtK = (val) => {
    if (val >= 1000) {
      const k = val / 1000;
      return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`;
    }
    return `$${Math.round(val)}`;
  };

  // ── Cálculos derivados desde dataset
  const valorUnitario = sku.stockUnd > 0 ? sku.stockUSD / sku.stockUnd : 0;
  const ventasMensualesUSD = sku.vendidoMes * valorUnitario;
  const contribucionMensual = ventasMensualesUSD * (sku.margenPct / 100);

  // ── Benchmarks de cartera (promedios determinísticos)
  const totalInventario = skuInventario.reduce((sum, s) => sum + s.stockUSD, 0);
  const promedioMargen = skuInventario.reduce((sum, s) => sum + s.margenPct, 0) / skuInventario.length;
  const promedioRotacion = skuInventario.reduce((sum, s) => sum + s.rotacion, 0) / skuInventario.length;
  const pctInventario = ((sku.stockUSD / totalInventario) * 100).toFixed(1);

  // ── M1 · EVIDENCIA · ficha del SKU
  const m1 = `${sku.sku} · ${sku.marca} · ${sku.sfamilia}\n\nStock ${fmtK(sku.stockUSD)} (${sku.stockUnd} unidades en ${sku.bodega}) | Margen ${sku.margenPct}% | Rotación ${sku.rotacion}x | DOH ${sku.doh}d | ${sku.diasSinVenta} días sin venta | Estado ${sku.estado}.`;

  // ── M2 · LECTURA causal con razones desde dataset
  const razones = [];

  // Margen vs promedio (gap >= 2 puntos para considerar relevante)
  const gapMargen = sku.margenPct - promedioMargen;
  if (gapMargen >= 2) {
    razones.push(`margen ${sku.margenPct}% (${gapMargen.toFixed(0)} puntos sobre el promedio cartera de ${promedioMargen.toFixed(0)}%)`);
  } else if (gapMargen <= -2) {
    razones.push(`margen ${sku.margenPct}% (${Math.abs(gapMargen).toFixed(0)} puntos bajo el promedio cartera de ${promedioMargen.toFixed(0)}%)`);
  }

  // Rotación
  if (sku.rotacion >= promedioRotacion + 1) {
    razones.push(`rotación ${sku.rotacion}x sobre el promedio cartera de ${promedioRotacion.toFixed(1)}x`);
  } else if (sku.rotacion <= 2) {
    razones.push(`rotación crítica de ${sku.rotacion}x muy bajo el benchmark interno de 7x+`);
  }

  // Días sin venta crítico
  if (sku.diasSinVenta >= 60) {
    razones.push(`${sku.diasSinVenta} días sin movimiento`);
  }

  // Concentración del inventario
  if (parseFloat(pctInventario) >= 8) {
    razones.push(`representa ${pctInventario}% del inventario total`);
  }

  // Estado del SKU como discriminador del tono de la lectura
  let lectura;
  if (sku.alerta === "crit" || sku.diasSinVenta > 60) {
    lectura = `${sku.sku} concentra una exposición operativa relevante. ${
      razones.length > 0 ? "Las señales convergen: " + razones.join(", ") + ". " : ""
    }El capital comprometido (${fmtK(sku.stockUSD)}) no está convirtiéndose a contribución al ritmo del portafolio.`;
  } else if (sku.alerta === "ok" && sku.rotacion >= promedioRotacion) {
    lectura = `${sku.sku} opera en patrón virtuoso del portafolio. ${
      razones.length > 0 ? "La conversión de venta a contribución se sostiene en " + razones.join(", ") + ". " : ""
    }Genera aproximadamente ${fmtK(contribucionMensual)} de contribución mensual.`;
  } else {
    lectura = `${sku.sku} opera dentro de rango. ${
      razones.length > 0 ? "Muestra " + razones.join(", ") + ". " : ""
    }La contribución mensual aproximada es ${fmtK(contribucionMensual)}.`;
  }

  const m2 = lectura;

  // ── M3 · MECANISMOS DISPONIBLES según patrón detectado (v1.1 · interpretativo)
  let foco;
  if (sku.alerta === "crit" || sku.diasSinVenta > 60) {
    foco = `Mecanismo disponible: ${sku.sku} concentra capital atrapado (${fmtK(sku.stockUSD)}) · zona donde la palanca de liquidación o revisión comercial libera reinversión hacia SKUs rotacionales del portafolio (rotación sobre 9x).`;
  } else if (sku.rotacion >= 9 && sku.margenPct >= promedioMargen) {
    foco = `${sku.sku} opera como pilar de rentabilidad del portafolio · disponibilidad y condiciones operativas son la zona estructural a preservar.`;
  } else if (sku.margenPct >= promedioMargen + 3 && sku.vendidoMes < 50) {
    foco = `${sku.sku} combina margen ${sku.margenPct}% superior al promedio con volumen aún bajo (${sku.vendidoMes} unidades mes) · zona de upside de escalamiento cuantificable.`;
  } else {
    foco = `${sku.sku} opera dentro del rango healthy · sin palancas activas · rotación y días sin venta son las métricas de seguimiento natural.`;
  }

  const m3 = foco;

  // ── Confianza
  const confianza = `*Confianza alta · datos determinísticos del inventario actual.*`;

  const opener = `${m1}\n\n${m2}\n\n${m3}\n\n${confianza}`;

  // ── Suggestions accionables con entidad real
  const suggestions = [
    `Cuánto recupero si liquido ${sku.sku}`,
    `Volver a los SKUs críticos`,
    `Qué cliente compra ${sku.sku}`,
  ];

  // ── Sentrix action · filtra ese SKU específico
  const sentrixAction = {
    label: `Ver ${sku.sku} en Inventario`,
    moduleChip: "Inventario",
    payload: {
      modulo: "inventario",
      clientes: [],
      skus: [sku.sku],
      mechanismBanner: `${sku.sku} · ${sku.estado}`,
    },
  };

  // BRIEF #26-quinquies-B · enriquecimiento con contrato v1.
  const isCritico = sku.alerta === "crit";
  const isVirtuoso = sku.rotacion >= 9 && sku.margenPct >= 22;

  // ── BRIEF M.B.3 · narrative_signals + posture_hint (spread D2) ──
  // isCritico → challenge (driver operational_inefficiency esperado)
  // isVirtuoso → validate (sin driver · narrativa de fortaleza)
  // intermedio → validate (default M.A)
  let narrative_signals = null;
  let posture_hint = "validate";
  if (VOICE_NARRATIVE_LAYER_ENABLED) {
    try {
      narrative_signals = buildNarrativeSignalsForSkuDeepDive(skuName, scenarioId);
      if (narrative_signals?.implication?.counter_intuition === true) {
        posture_hint = "challenge";
      }
    } catch (sig_err) {
      // eslint-disable-next-line no-console
      console.warn("BRIEF M.B.3 sku deep-dive narrative_signals error:", sig_err);
      narrative_signals = null;
    }
  }

  return {
    ...buildResponseContract({
      opener,
      // BRIEF N-bis · Tipo A puro · suggestions filtradas
      suggestions: filterTextualSuggestions(suggestions),
      sentrixAction,
      decision: sku.sku,
      evidence: {
        sku: sku.sku,
        categoria: sku.sfamilia,
        marca: sku.marca,
        stock_USD: sku.stockUSD,
        stock_und: sku.stockUnd,
        bodega: sku.bodega,
        rotacion: sku.rotacion,
        benchmark_rotacion: 7,
        gap_rotacion: Math.max(0, 7 - sku.rotacion),
        margen_pct: sku.margenPct,
        doh: sku.doh,
        dias_sin_venta: sku.diasSinVenta,
        alerta: sku.alerta,
        contribucion_mensual_K: Math.round(sku.vendidoMes * (sku.margenPct / 100)),
        pct_inventario_total: +((sku.stockUSD / 135000) * 100).toFixed(1),
      },
      focus: isCritico
        ? `Liquidar o redirigir ${sku.sku}`
        : isVirtuoso
        ? `Proteger y escalar ${sku.sku}`
        : `Monitorear ${sku.sku}`,
      confidence: "alta",
      materialMetrics: [
        `${sku.margenPct}% margen`,
        `${sku.rotacion}x rotación`,
        `$${(sku.stockUSD / 1000).toFixed(1)}K stock`,
      ],
      reasoningPattern: isCritico
        ? "capital_trapped_low_rotation"
        : isVirtuoso
        ? "high_rotation_high_margin"
        : "intermediate_operational",
      suggestedNextActions: isCritico
        ? ["Plan de salida", "Capital liberado si rota", "Quién compra"]
        : isVirtuoso
        ? ["Ver clientes que compran", "Ver evolución temporal", "Comparar contra portafolio"]
        : ["Detalle operativo", "Comparar contra rotacionales", "Plan de monitoreo"],
    }),
    // BRIEF M · spread externo
    narrative_signals,
    posture_hint,
  };
}

// ════════════════════════════════════════════════════════
// BRIEF #26-quinquies-B · ComposerResponseContract_v1
//
// Contrato estructurado que TODO composer enriquecido debe retornar.
// Validado en 4 composers piloto · base para Conversational Opener Engine.
//
// CAMPOS OBLIGATORIOS (los 12 deben existir siempre · null o [] si no aplica):
//   opener                  · string · texto Ferrari del análisis
//   suggestions             · array · suggestions string o {text, action}
//   sentrixAction           · object | null · payload de Sentrix
//   decision                · string | null · entidad/foco principal
//   evidence                · object | null · cifras crudas estructuradas
//   focus                   · string | null · intención accionable
//   confidence              · "alta" | "media" | "baja"
//   materialMetrics         · string[] · cifras formateadas (máx 3)
//   reasoningPattern        · string | null · patrón cognitivo
//   suggestedNextActions    · string[] · etiquetas semánticas de actions
//   clientList              · string[] | null · IDs canónicos ·
//                             habilita ring poblamiento AN+ + Evidence Sync futura
//   responseObjectVersion   · "v1" · obligatorio
//
// REGLA DURA: cero hardcoding · valores derivados del dataset/state.
// Backward compat: composers no piloto siguen retornando {opener, suggestions,
// sentrixAction} sin contrato · buildConversationalOpener retorna null para
// ellos y el flujo cae al buildValidationOpener legacy.
// ════════════════════════════════════════════════════════
function buildResponseContract({
  opener,
  suggestions = [],
  sentrixAction = null,
  decision = null,
  evidence = null,
  focus = null,
  confidence = "alta",
  materialMetrics = [],
  reasoningPattern = null,
  suggestedNextActions = [],
  clientList = null,              // 🆕 AN+.FIX2-5 · habilita ring poblamiento AN+
}) {
  return {
    opener,
    suggestions,
    sentrixAction,
    decision,
    evidence,
    focus,
    confidence,
    materialMetrics,
    reasoningPattern,
    suggestedNextActions,
    clientList,                     // 🆕 AN+.FIX2-5
    responseObjectVersion: "v1",
  };
}

// ═══════════════════════════════════════════════════════════════════════════
// BRIEF #38 · PREMISE VALIDATION LAYER
//
// Capa cognitiva PRE-composer que detecta disonancia entre premisa del
// usuario y realidad del dataset en escenario activo. Si el usuario afirma
// algo direccional sobre una entidad/métrica (ej. "Tier 1 está cayendo")
// y el dataset dice lo contrario (Tier 1 +8.2%/+14.9%/+12.2% en Bonanza),
// ADI enuncia la disonancia explícitamente ANTES del análisis técnico
// downstream. Sin hardcoding · cifras runtime via applyScenarioToClientesVentas.
//
// Principio: voz controller chileno honesta · no redirige silenciosamente.
//
// 3 funciones:
//   · detectUserClaim(text, concepts)
//       Detecta claim direccional + sujeto (cliente / Tier / métrica).
//   · validateClaimAgainstScenario(claim, scenarioId)
//       Compara claim vs realidad del dataset · severity hard/soft/valid.
//   · composePremiseCorrection(claim, validation, scenarioId)
//       Compone opener breve con cifras runtime + oferta de redirección.
//
// Falsos negativos preferibles a falsos positivos (regla del BRIEF):
// si la capa no detecta una premisa falsa, ADI responde como antes
// (silencioso pero válido). Si la capa corrige una premisa verdadera,
// daño reputacional alto. Threshold severity=hard conservador (>3pp).
// ═══════════════════════════════════════════════════════════════════════════

// ── PIEZA 1 · detectUserClaim ────────────────────────────────────────────
// Retorna shape con hasDirectionalClaim, claimType, claimSubject, claimVerb.
// Determinístico · sin LLM.
function detectUserClaim(text, concepts) {
  const norm = (text || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  const signalTypes = new Set();
  (concepts || []).forEach(c => {
    (c.signals_matched_types || []).forEach(t => signalTypes.add(t));
  });

  // 1. Detectar claimType direccional desde signals canónicos (F3/F4/F5)
  //    o legacy patterns. Orden: F-signals primero (más confiables).
  let claimType = null;
  if (signalTypes.has("volume_decline_canonical")) claimType = "decline";
  else if (signalTypes.has("volume_growth_canonical")) claimType = "growth";
  else if (signalTypes.has("margin_erosion_canonical")) claimType = "negative";

  // Fallback léxico solo si NO hay canonical (evita doble lectura).
  // Verbos direccionales explícitos en pregunta del usuario.
  // BRIEF #38 V3 · incluir pretéritos comunes en preguntas "¿por qué X?"
  // (cayó/subió/creció/bajó) para capturar premisas falsas en pasado.
  // BRIEF #44 · expansión léxica · stems ESPECÍFICOS (gerundios/pretéritos
  // completos) para evitar FPs en cascadas existentes:
  //   - "perd"/"perdi"/"pierd" NO agregadas (rompen "qué pasa si pierdo",
  //     "perdiendo plata" intencional, "perder a Falabella" hipotético).
  //   - Solo gerundios y pretéritos específicos: perdiendo/perdio/perdieron,
  //     hundiendo/hundio/hundieron, desplomando/desplomo/desplomaron.
  //
  // BRIEF #46 · SINCRONIZACIÓN con SEMANTIC_FAMILIES F4/F5 stateMatchers.
  // detectUserClaim opera en capa léxica paralela al SemanticNormalizer.
  // Si se agregan nuevos stateMatchers a F4/F5 en BRIEFs futuros,
  // sincronizar aquí también (ambas capas requieren update coordinado).
  // Sincronización post #45:
  //   F4 stateMatchers nuevos → declineVerbs: descenso, caida, desploma,
  //     desplomandose, hundimiento (decae/decayo/decayendo ya estaban post #44).
  //   F5 stateMatchers nuevos → growthVerbs: alza (disparad/expand ya estaban
  //     post #44 · expand stem cubre expansion/expansión como substring).
  if (!claimType) {
    const declineVerbs = ["esta cayendo", "estan cayendo", "cae", "caen",
      "cayendo", "cayo", "cayeron", "baja", "bajan", "bajando", "bajo",
      "bajaron", "retroced", "se desplom", "se hundi", "no crece",
      "no esta creciendo",
      // BRIEF #44 · gerundios/pretéritos específicos · sin FPs en cascadas
      "perdiendo", "perdio", "perdieron",
      "hundiendo", "hundio", "hundieron",
      "desplomando", "desplomo", "desplomaron",
      "retrocedio", "retrocediendo",
      "decae", "decayo", "decayendo",
      "se cae", "se caen", "se cayo",
      // BRIEF #46 · sincronización F4 (#45 stateMatchers post-NFD sin tilde)
      "descenso", "caida",
      "desploma", "desplomandose",
      "hundimiento"];
    const growthVerbs = ["esta creciendo", "estan creciendo", "crece",
      "crecen", "creciendo", "crecio", "crecieron", "sube", "suben",
      "subiendo", "subio", "subieron", "aument", "expand",
      // BRIEF #44 · expansión growthVerbs · variantes complementarias
      "aumenta", "aumento", "aumentando", "aumentaron",
      "expandio", "expandiendo",
      "disparad", "se dispara", "se disparo",
      // BRIEF #46 · sincronización F5 (expand stem cubre expansion/expansión)
      "alza", "en alza"];
    if (declineVerbs.some(v => norm.includes(v))) claimType = "decline";
    else if (growthVerbs.some(v => norm.includes(v))) claimType = "growth";
  }

  if (!claimType) {
    return {
      hasDirectionalClaim: false,
      claimType: null,
      claimSubject: { type: null, value: null },
      claimVerb: null,
    };
  }

  // 2. Detectar sujeto del claim. Prioridad:
  //    a) Tier explícito ("Tier 1", "tier 1", etc.) o alias de Tier
  //       (BRIEF #44 · "cuentas grandes/top/principales" → Tier 1)
  //    b) Cliente específico (via detectClientInText)
  //    c) Métrica genérica (ventas, margen, contribucion, rotacion)
  //    d) Métrica global (BRIEF #44 · negocio/empresa/cartera/portafolio)
  //    e) Módulo (inventario, stock)
  let claimSubject = { type: null, value: null };

  const tierMatch = norm.match(/\btier\s*([123])\b/);
  if (tierMatch) {
    claimSubject = { type: "tier", value: `Tier ${tierMatch[1]}` };
  } else {
    // BRIEF #44 · Tier aliases ejecutivos (cuentas grandes ≡ Tier 1).
    // Detectados ANTES de detectClientInText para evitar que "principales
    // clientes" caiga a "cliente" sin entidad.
    const tierAliases = [
      { keywords: ["cuentas grandes", "cuentas top", "principales clientes", "top clientes"], value: "Tier 1" },
      { keywords: ["cuentas chicas", "cuentas pequeñas", "cuentas pequenas"], value: "Tier 3" },
    ];
    let aliasMatched = null;
    for (const a of tierAliases) {
      if (a.keywords.some(k => norm.includes(k))) {
        aliasMatched = a.value;
        break;
      }
    }
    if (aliasMatched) {
      claimSubject = { type: "tier", value: aliasMatched };
    } else {
      const clientName = (typeof detectClientInText === "function")
        ? detectClientInText(text)
        : null;
      if (clientName) {
        claimSubject = { type: "client", value: clientName };
      } else {
        // Métricas genéricas en orden de especificidad
        const metricsMap = [
          { keywords: ["ventas", "facturacion", "topline", "ingresos"], value: "ventas" },
          { keywords: ["margen", "rentabilidad", "contribucion"], value: "margen" },
          { keywords: ["rotacion", "doh", "cobertura"], value: "rotacion" },
        ];
        for (const m of metricsMap) {
          if (m.keywords.some(k => norm.includes(k))) {
            claimSubject = { type: "metric", value: m.value };
            break;
          }
        }
        // BRIEF #44 · subject metric_global (negocio/empresa/cartera).
        // Permite validar contra crecimiento agregado del portafolio
        // (CASO 4 en validateClaimAgainstScenario).
        // Detectado DESPUÉS de métricas específicas para preservar
        // precedencia (si dice "ventas del negocio" → metric=ventas).
        if (claimSubject.type === null) {
          const globalKeywords = ["negocio", "empresa", "cartera", "portafolio"];
          if (globalKeywords.some(k => norm.includes(k))) {
            const matched = globalKeywords.find(k => norm.includes(k));
            claimSubject = { type: "metric_global", value: matched };
          }
        }
        if (claimSubject.type === null) {
          const moduleKeywords = ["inventario", "stock"];
          if (moduleKeywords.some(k => norm.includes(k))) {
            claimSubject = { type: "module", value: "inventario" };
          }
        }
      }
    }
  }

  return {
    hasDirectionalClaim: true,
    claimType,
    claimSubject,
    claimVerb: null,
  };
}

// ── PIEZA 2 · validateClaimAgainstScenario ───────────────────────────────
// Compara claim con realidad del dataset · cifras runtime.
// severity hard: gap direccional >3pp · severity soft: gap <=3pp opuesto.
function validateClaimAgainstScenario(claim, scenarioId) {
  if (!claim || !claim.hasDirectionalClaim || !claim.claimSubject || !claim.claimSubject.value) {
    return { isPremiseValid: true, reality: null, contradiction: null };
  }

  // Calcular crecimiento runtime para un cliente del dataset.
  // Single source of truth: applyScenarioToClientesVentas(scenarioId).
  function _growthPct(client) {
    if (!client || !client.anterior || client.anterior === 0) return 0;
    return ((client.actual - client.anterior) / client.anterior) * 100;
  }

  let clientesEscenario = null;
  try {
    clientesEscenario = applyScenarioToClientesVentas(scenarioId);
  } catch (e) {
    // Dataset no accesible · default: no contradecir
    return { isPremiseValid: true, reality: null, contradiction: null };
  }
  if (!Array.isArray(clientesEscenario) || clientesEscenario.length === 0) {
    return { isPremiseValid: true, reality: null, contradiction: null };
  }

  // CASO 1 · Tier 1/2/3 agregado.
  // Tier 1 canonical: top 3 por venta actual (Falabella + Lider + Jumbo en Bonanza).
  // Calculado runtime · no hardcoded.
  if (claim.claimSubject.type === "tier") {
    const tierNum = parseInt(claim.claimSubject.value.replace(/[^123]/g, ""), 10);
    const sortedByActual = [...clientesEscenario].sort((a, b) => b.actual - a.actual);
    let tierClientes = [];
    if (tierNum === 1) tierClientes = sortedByActual.slice(0, 3);
    else if (tierNum === 2) tierClientes = sortedByActual.slice(3, 7);
    else if (tierNum === 3) tierClientes = sortedByActual.slice(7);

    if (tierClientes.length === 0) return { isPremiseValid: true, reality: null, contradiction: null };

    // Crecimiento ponderado por participación
    const totalActual = tierClientes.reduce((s, c) => s + c.actual, 0);
    const totalAnterior = tierClientes.reduce((s, c) => s + c.anterior, 0);
    const growthAggregate = totalAnterior > 0
      ? ((totalActual - totalAnterior) / totalAnterior) * 100
      : 0;

    const actualDirection = growthAggregate > 1 ? "growth"
      : growthAggregate < -1 ? "decline"
      : "stable";

    // Severity: gap entre claim y realidad
    const gap = Math.abs(growthAggregate);
    let severity = null;
    let isPremiseValid = true;
    if (claim.claimType === "decline" && actualDirection === "growth" && gap > 3) {
      isPremiseValid = false;
      severity = "hard";
    } else if (claim.claimType === "growth" && actualDirection === "decline" && gap > 3) {
      isPremiseValid = false;
      severity = "hard";
    } else if (claim.claimType === "decline" && actualDirection !== "decline" && gap <= 3) {
      isPremiseValid = false;
      severity = "soft";
    } else if (claim.claimType === "growth" && actualDirection !== "growth" && gap <= 3) {
      isPremiseValid = false;
      severity = "soft";
    }

    return {
      isPremiseValid,
      reality: {
        subject: claim.claimSubject.value,
        actualDirection,
        magnitude: +growthAggregate.toFixed(1),
        dataPoints: tierClientes.map(c => ({
          nombre: c.nombre,
          actual: c.actual,
          anterior: c.anterior,
          growthPct: +_growthPct(c).toFixed(1),
          pctRebate: c.pctRebate,
        })),
      },
      contradiction: !isPremiseValid ? {
        userClaimed: claim.claimType,
        datasetSays: actualDirection,
        severity,
      } : null,
    };
  }

  // CASO 2 · Cliente específico.
  if (claim.claimSubject.type === "client") {
    const c = clientesEscenario.find(x => x.nombre === claim.claimSubject.value);
    if (!c) return { isPremiseValid: true, reality: null, contradiction: null };

    const growth = _growthPct(c);
    const actualDirection = growth > 1 ? "growth"
      : growth < -1 ? "decline"
      : "stable";

    const gap = Math.abs(growth);
    let severity = null;
    let isPremiseValid = true;
    if (claim.claimType === "decline" && actualDirection === "growth" && gap > 3) {
      isPremiseValid = false; severity = "hard";
    } else if (claim.claimType === "growth" && actualDirection === "decline" && gap > 3) {
      isPremiseValid = false; severity = "hard";
    } else if (claim.claimType === "decline" && actualDirection !== "decline" && gap <= 3) {
      isPremiseValid = false; severity = "soft";
    } else if (claim.claimType === "growth" && actualDirection !== "growth" && gap <= 3) {
      isPremiseValid = false; severity = "soft";
    }

    return {
      isPremiseValid,
      reality: {
        subject: c.nombre,
        actualDirection,
        magnitude: +growth.toFixed(1),
        dataPoints: [{
          nombre: c.nombre,
          actual: c.actual,
          anterior: c.anterior,
          growthPct: +growth.toFixed(1),
          pctRebate: c.pctRebate,
        }],
      },
      contradiction: !isPremiseValid ? {
        userClaimed: claim.claimType,
        datasetSays: actualDirection,
        severity,
      } : null,
    };
  }

  // BRIEF #44 · CASO 4 · subject metric_global (negocio/empresa/cartera).
  // Valida claim contra crecimiento AGREGADO del portafolio completo.
  // Single source of truth: applyScenarioToClientesVentas(scenarioId)
  // sumado sobre todos los clientes.
  if (claim.claimSubject.type === "metric_global") {
    const totalActual = clientesEscenario.reduce((s, c) => s + c.actual, 0);
    const totalAnterior = clientesEscenario.reduce((s, c) => s + c.anterior, 0);
    const growthAggregate = totalAnterior > 0
      ? ((totalActual - totalAnterior) / totalAnterior) * 100
      : 0;

    const actualDirection = growthAggregate > 1 ? "growth"
      : growthAggregate < -1 ? "decline"
      : "stable";
    const gap = Math.abs(growthAggregate);
    let severity = null;
    let isPremiseValid = true;
    if (claim.claimType === "decline" && actualDirection === "growth" && gap > 3) {
      isPremiseValid = false; severity = "hard";
    } else if (claim.claimType === "growth" && actualDirection === "decline" && gap > 3) {
      isPremiseValid = false; severity = "hard";
    } else if (claim.claimType === "decline" && actualDirection !== "decline" && gap <= 3) {
      isPremiseValid = false; severity = "soft";
    } else if (claim.claimType === "growth" && actualDirection !== "growth" && gap <= 3) {
      isPremiseValid = false; severity = "soft";
    }

    // Top 3 clientes por venta para datapoints de la corrección
    const top3 = [...clientesEscenario]
      .sort((a, b) => b.actual - a.actual)
      .slice(0, 3);

    return {
      isPremiseValid,
      reality: {
        subject: "el " + claim.claimSubject.value,
        actualDirection,
        magnitude: +growthAggregate.toFixed(1),
        dataPoints: top3.map(c => ({
          nombre: c.nombre,
          actual: c.actual,
          anterior: c.anterior,
          growthPct: +_growthPct(c).toFixed(1),
          pctRebate: c.pctRebate,
        })),
      },
      contradiction: !isPremiseValid ? {
        userClaimed: claim.claimType,
        datasetSays: actualDirection,
        severity,
      } : null,
    };
  }

  // CASO 3 · Métrica genérica / módulo sin sujeto específico.
  // No contradecir globalmente · falsos negativos preferibles.
  // (Excepción Fase 2: si métrica = "ventas" sin sujeto · se podría validar
  //  contra total cartera · diferido para evitar FPs ambiguos).
  return { isPremiseValid: true, reality: null, contradiction: null };
}

// ── PIEZA 3 · composePremiseCorrection ───────────────────────────────────
// Construye opener breve · 4 frases · voz controller chileno honesta.
// Cifras 100% runtime de la validation.
function composePremiseCorrection(claim, validation, scenarioId) {
  if (!claim || !validation || !validation.contradiction) return null;
  if (!validation.reality || !validation.reality.dataPoints) return null;

  const reality = validation.reality;
  const sev = validation.contradiction.severity;

  // Verbo direccional opuesto al claim para nombrar la realidad
  const realDirVerb = reality.actualDirection === "growth" ? "crece"
    : reality.actualDirection === "decline" ? "cae"
    : "se mantiene estable";
  const userClaimVerb = claim.claimType === "decline" ? "cayendo"
    : claim.claimType === "growth" ? "creciendo"
    : "deteriorándose";

  // Formato de growth: +N.N% o -N.N%
  function _pctStr(n) {
    const sign = n > 0 ? "+" : "";
    return `${sign}${n.toFixed(1)}%`;
  }

  // SOFT contradictions: nota corta al final (no prepend completo).
  if (sev === "soft") {
    return ` · Nota: el escenario activo muestra ${reality.subject} ${realDirVerb} ${_pctStr(reality.magnitude)}, no ${userClaimVerb} como sugería la pregunta.`;
  }

  // HARD contradictions: prepend completo de 4 frases.
  // Frase 1: reconocimiento + cifra agregada
  const headerSubject = reality.subject;
  const f1 = `En el escenario activo ${headerSubject} no está ${userClaimVerb} · ${realDirVerb} ${_pctStr(reality.magnitude)} agregado.`;

  // Frase 2: cifras runtime de cada datapoint
  const points = reality.dataPoints.slice(0, 3);
  const pointsLine = points.map(p =>
    `${p.nombre} ${_pctStr(p.growthPct)}`
  ).join(", ");
  const f2 = `${pointsLine}.`;

  // Frase 3: reformulación honesta + redirección
  // Identificar el cliente "más interesante" de la cartera completa
  // (mayor crecimiento con menor rebate · señal de eficiencia comercial).
  let f3 = "";
  let f4 = "";
  try {
    const allClientes = applyScenarioToClientesVentas(scenarioId);
    if (Array.isArray(allClientes) && allClientes.length > 0) {
      const enriched = allClientes
        .filter(c => c.anterior > 0)
        .map(c => ({
          nombre: c.nombre,
          growthPct: ((c.actual - c.anterior) / c.anterior) * 100,
          pctRebate: c.pctRebate,
          actual: c.actual,
        }));
      // Top growth con bajo rebate · eficiencia comercial
      const eficiente = [...enriched]
        .filter(c => c.growthPct > Math.abs(reality.magnitude))
        .sort((a, b) => (b.growthPct / Math.max(b.pctRebate, 0.1)) - (a.growthPct / Math.max(a.pctRebate, 0.1)))[0];
      if (eficiente && !points.some(p => p.nombre === eficiente.nombre)) {
        f3 = `Lo que sí merece atención es ${eficiente.nombre} que ${eficiente.growthPct > 0 ? "crece" : "cae"} ${_pctStr(+eficiente.growthPct.toFixed(1))} con apenas ${eficiente.pctRebate.toFixed(1)}% de carga.`;
        f4 = `¿Analizo eso o querés mirar ${headerSubject} en otro escenario?`;
      }
    }
  } catch (e) {
    // applyScenarioToClientesVentas no disponible · fallback sin redirección
  }

  if (!f3) {
    f3 = `La dirección del dataset es opuesta a la premisa.`;
    f4 = `¿Querés mirar ${headerSubject} en otro escenario?`;
  }

  return `${f1} ${f2} ${f3} ${f4}`;
}

// ═══════════════════════════════════════════════════════
// BRIEF #25-bis · Composers cognitivos del Suggestion Generator Engine
//
// 10 composers Ferrari para cada tipo de acción cognitiva que emite el SGE.
// Estructura Ferrari sin etiquetas visibles · Evidencia + Lectura + Foco.
// Determinismo bitwise · todas las cifras desde el dataset.
// CERO HARDCODING · ninguna frase con valores fijos.
// ═══════════════════════════════════════════════════════

// Helper · formato monetario consistente
function _fmtKBis(val) {
  if (val == null || isNaN(val)) return "$0";
  if (Math.abs(val) >= 1000) {
    const k = val / 1000;
    return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`;
  }
  return `$${Math.round(val)}`;
}

// ──────────────────────────────────────
// 4.1 · composeContinuePending
// Razonamiento: el usuario quiere profundizar en los pendientes
// de la lista padre. Sintetiza un resumen comparativo con cada
// entidad y sus métricas clave, identifica el patrón común y
// señala foco prioritario.
// ──────────────────────────────────────
function composeContinuePending(payload, scenarioId) {
  const { entityType, entities, sourceIntent } = payload;

  if (!entities || entities.length === 0) {
    return {
      opener: "No quedan pendientes del análisis anterior.",
      suggestions: [],
      sentrixAction: null,
    };
  }

  // ── Construcción para tipo SKU
  if (entityType === "sku") {
    const skus = entities
      .map(s => skuInventario.find(x => x.sku === s))
      .filter(Boolean);

    if (skus.length === 0) {
      return {
        opener: `No tengo datos de los ${entities.length} SKU pendientes.`,
        suggestions: [],
        sentrixAction: null,
      };
    }

    // Métricas por SKU (3 clave: Stock, DOH, Rotación)
    const lineas = skus.map(s =>
      `${s.sku} → Stock ${_fmtKBis(s.stockUSD)} | DOH ${s.doh}d | Rotación ${s.rotacion}x`
    );

    // Lectura · patrón común
    const criticos = skus.filter(s => s.alerta === "crit");
    const warns    = skus.filter(s => s.alerta === "warn");
    const peor = skus.reduce((acc, s) =>
      (s.doh + s.diasSinVenta) > (acc.doh + acc.diasSinVenta) ? s : acc,
      skus[0]
    );
    const totalCap = skus.reduce((s, x) => s + x.stockUSD, 0);

    let lectura;
    if (criticos.length > 0) {
      lectura = `Los ${skus.length} SKU comparten señales de exposición operativa. ${criticos.length} están en estado crítico, ${warns.length} en alerta de rotación. Capital combinado bloqueado: ${_fmtKBis(totalCap)}.`;
    } else {
      lectura = `Los ${skus.length} SKU operan en rangos similares de rotación reducida. Capital combinado: ${_fmtKBis(totalCap)}.`;
    }

    // Foco · cuál revisar primero
    const foco = `Mecanismo disponible: ${peor.sku} concentra la peor convergencia operativa del grupo · ${peor.doh}d DOH con ${peor.diasSinVenta} días sin venta · zona con mayor materialidad para palanca operativa.`;

    const opener = `${skus.length} SKU pendientes del análisis previo:\n\n${lineas.join("\n")}\n\n${lectura}\n\n${foco}\n\n*Confianza alta · datos determinísticos del inventario actual.*`;

    return {
      opener,
      suggestions: [],  // El SGE generará nuevas suggestions
      sentrixAction: {
        label: `Ver ${skus.length} SKUs en Inventario`,
        moduleChip: "Inventario",
        payload: {
          modulo: "inventario",
          clientes: [],
          skus: skus.map(s => s.sku),
          mechanismBanner: `${skus.length} SKUs pendientes`,
        },
      },
    };
  }

  // ── Construcción para tipo cliente
  if (entityType === "client") {
    const clis = entities
      .map(c => clientesMargen.find(x => x.nombre === c))
      .filter(Boolean);

    if (clis.length === 0) {
      return {
        opener: `No tengo datos de las ${entities.length} cuentas pendientes.`,
        suggestions: [],
        sentrixAction: null,
      };
    }

    const lineas = clis.map(c =>
      `${c.nombre} → Margen ${c.margen}% | Contribución ${_fmtKBis(c.contribucion * 1000)} | Carga ${c.pctRebate}%`
    );

    const benchmark = 30.1;
    const targetCarga = 3.5;
    const totalContrib = clis.reduce((s, c) => s + c.contribucion, 0) * 1000;
    const peor = clis.reduce((acc, c) =>
      (benchmark - c.margen) > (benchmark - acc.margen) ? c : acc,
      clis[0]
    );

    const lectura = `Las ${clis.length} cuentas comparten un margen por debajo del benchmark de ${benchmark}%. Contribución combinada: ${_fmtKBis(totalContrib)}. El gap promedio vs benchmark erosiona la economía de la relación.`;

    const foco = `Mecanismo disponible: ${peor.nombre} concentra mayor distancia del benchmark · margen ${peor.margen}% con carga ${peor.pctRebate}% sobre target de ${targetCarga}% · zona con mayor materialidad para palanca operativa.`;

    const opener = `${clis.length} cuentas pendientes del análisis previo:\n\n${lineas.join("\n")}\n\n${lectura}\n\n${foco}\n\n*Confianza alta · datos determinísticos de márgenes actuales.*`;

    return {
      opener,
      suggestions: [],
      sentrixAction: {
        label: `Ver ${clis.length} cuentas en Márgenes`,
        moduleChip: "Márgenes",
        payload: {
          modulo: "margenes",
          clientes: clis.map(c => c.nombre),
          skus: [],
          mechanismBanner: `${clis.length} cuentas pendientes`,
        },
      },
    };
  }

  return {
    opener: "No hay datos suficientes para continuar el análisis.",
    suggestions: [],
    sentrixAction: null,
  };
}

// ──────────────────────────────────────
// 4.2 · composeSkuToClient
// Razonamiento: identificar clientes que compran la sfamilia del SKU.
// Proxy: skuInventario.sfamilia → clientesMargen.sfamilia dominante.
// Top 3 clientes ordenados por ventas en esa sfamilia.
// ──────────────────────────────────────
function composeSkuToClient(skuName, scenarioId) {
  const sku = skuInventario.find(s => s.sku === skuName);
  if (!sku) {
    return {
      opener: `No tengo datos del SKU ${skuName}.`,
      suggestions: [],
      sentrixAction: null,
    };
  }

  // Cruce por sfamilia (proxy más fiable disponible)
  const clientesEnFamilia = clientesMargen
    .filter(c => c.sfamilia === sku.sfamilia)
    .sort((a, b) => b.venta - a.venta);

  if (clientesEnFamilia.length === 0) {
    return {
      opener: `No tengo cruce explícito entre ${skuName} y clientes específicos en el escenario actual. El SKU pertenece a ${sku.sfamilia}, pero ningún cliente del dataset tiene esa familia como dominante.`,
      suggestions: [],
      sentrixAction: null,
    };
  }

  const top3 = clientesEnFamilia.slice(0, 3);
  const totalVenta = top3.reduce((s, c) => s + c.venta, 0);
  const top1 = top3[0];
  const concentracion = ((top1.venta / totalVenta) * 100).toFixed(0);

  // Evidencia · ranking
  const lineas = top3.map(c =>
    `${c.nombre} → Venta ${_fmtKBis(c.venta * 1000)} | Margen ${c.margen}% | Carga ${c.pctRebate}%`
  );

  // Lectura
  const lectura = `${sku.sku} pertenece a ${sku.sfamilia}. ${top1.nombre} concentra el ${concentracion}% de la venta de esta familia entre los top 3 cuentas, lo que lo posiciona como el cliente más relevante para acciones comerciales sobre el SKU.`;

  // Foco
  const foco = `Si la decisión sobre ${sku.sku} es comercial (precio, surtido, recambio), ${top1.nombre} es la cuenta de mayor materialidad.`;

  const opener = `${sku.sku} · ${sku.sfamilia}\n\nTop 3 cuentas en la familia:\n\n${lineas.join("\n")}\n\n${lectura}\n\n${foco}\n\n*Confianza media · cruce inferido por sfamilia dominante (no transaccional directo).*`;

  return {
    opener,
    suggestions: [],
    sentrixAction: {
      label: `Ver clientes de ${sku.sfamilia}`,
      moduleChip: "Márgenes",
      payload: {
        modulo: "margenes",
        clientes: top3.map(c => c.nombre),
        skus: [],
        sfamilias: [sku.sfamilia],
        mechanismBanner: `${sku.sku} · cuentas de ${sku.sfamilia}`,
      },
    },
  };
}

// ──────────────────────────────────────
// 4.3 · composeClientToSku
// Razonamiento simétrico al anterior.
// Identifica SKUs que aportan más a la sfamilia que el cliente compra.
// ──────────────────────────────────────
function composeClientToSku(clientName, scenarioId) {
  const cliente = clientesMargen.find(c => c.nombre === clientName);
  if (!cliente) {
    return {
      opener: `No tengo datos de ${clientName}.`,
      suggestions: [],
      sentrixAction: null,
    };
  }

  // SKUs de la sfamilia dominante del cliente, ordenados por contribución
  const skusEnFamilia = skuInventario
    .filter(s => s.sfamilia === cliente.sfamilia)
    .map(s => {
      const valorUnit = s.stockUnd > 0 ? s.stockUSD / s.stockUnd : 0;
      const contribMensual = s.vendidoMes * valorUnit * (s.margenPct / 100);
      return { ...s, contribMensual };
    })
    .sort((a, b) => b.contribMensual - a.contribMensual);

  if (skusEnFamilia.length === 0) {
    return {
      opener: `${cliente.nombre} compra principalmente ${cliente.sfamilia}, pero el inventario actual no tiene SKUs de esa familia para cruzar.`,
      suggestions: [],
      sentrixAction: null,
    };
  }

  const top3 = skusEnFamilia.slice(0, 3);
  const lineas = top3.map(s =>
    `${s.sku} → Contribución ${_fmtKBis(s.contribMensual)}/mes | Margen ${s.margenPct}% | Rotación ${s.rotacion}x`
  );

  const top1 = top3[0];
  const lectura = `${cliente.nombre} concentra compras en ${cliente.sfamilia}. ${top1.sku} es el SKU del portafolio con mayor aporte económico en esa familia (${_fmtKBis(top1.contribMensual)} mensuales).`;
  const foco = `Para proteger contribución en ${cliente.nombre}, ${top1.sku} es el SKU de mayor materialidad en la relación.`;

  const opener = `${cliente.nombre} · familia dominante: ${cliente.sfamilia}\n\nTop 3 SKUs por aporte:\n\n${lineas.join("\n")}\n\n${lectura}\n\n${foco}\n\n*Confianza media · aporte inferido desde inventario × margen, no transaccional cruzado.*`;

  return {
    opener,
    suggestions: [],
    sentrixAction: {
      label: `Ver SKUs de ${cliente.sfamilia}`,
      moduleChip: "Inventario",
      payload: {
        modulo: "inventario",
        clientes: [],
        skus: top3.map(s => s.sku),
        sfamilias: [cliente.sfamilia],
        mechanismBanner: `${cliente.nombre} · SKUs de ${cliente.sfamilia}`,
      },
    },
  };
}

// ──────────────────────────────────────
// 4.4 · composeSimulationBenchmark
// Razonamiento: simular cierre de gap vs benchmark de margen.
// Aplica a clientes (margen vs 30.1%) y SKUs (margen vs promedio cartera).
// ──────────────────────────────────────
function composeSimulationBenchmark(payload, scenarioId) {
  const { entity, entityType, metric, target } = payload;

  if (entityType === "client") {
    const cliente = clientesMargen.find(c => c.nombre === entity);
    if (!cliente) {
      return { opener: `No tengo datos de ${entity}.`, suggestions: [], sentrixAction: null };
    }
    const gapPuntos = target - cliente.margen;
    if (gapPuntos <= 0) {
      return {
        opener: `${entity} ya opera al benchmark de ${target}% o por encima (margen ${cliente.margen}%). No hay gap que cerrar.`,
        suggestions: [],
        sentrixAction: null,
      };
    }

    // BRIEF MICRO · FIX EPISTÉMICO PARALELO (D2 LOCKED · cifra canónica scaled)
    // Mismo patrón que composeSimulationLoadReduction. Usar clientesVentas.actual
    // (scaled · 19433 para Falabella) en lugar de clientesMargen.venta (18500 raw).
    const ventas = applyScenarioToClientesVentas(scenarioId);
    const ventaCliente = ventas.find(c => c.nombre === entity);
    if (!ventaCliente) {
      return { opener: `No tengo datos de ventas de ${entity}.`, suggestions: [], sentrixAction: null };
    }
    // Recuperable en escala K (ventaCliente.actual en miles · gapPuntos en pp)
    const recuperable = Math.round((gapPuntos / 100) * ventaCliente.actual);
    const ventaFmt = `$${(ventaCliente.actual / 1000).toFixed(1)}M`;

    const ev = `${entity} · margen ${cliente.margen}% · benchmark ${target}% · gap ${gapPuntos.toFixed(1)} puntos.`;
    // BRIEF MICRO · D3 LOCKED · wording honestidad alineado con memClient.
    // Voice Contract dictionary ya transforma "sin sacrificar volumen" runtime ·
    // aquí escribimos directamente el wording final ("sin compromiso explícito
    // de volumen") para evitar dependencia y emitir lenguaje canónico de origen.
    const lectura = `Si ${entity} iguala el benchmark de ${target}%, la contribución incremental anual sería de aproximadamente $${recuperable}K, sin compromiso explícito de volumen (${ventaFmt} de venta anual · cálculo runtime sobre venta actual × gap de margen).`;
    const honestidad_neg = `Cerrar el gap a benchmark típicamente se negocia con contraprestación: carga comercial (actualmente ${cliente.pctRebate}%), mix hacia categorías de mayor margen, o condiciones operativas. ADI no tiene histórico de negociación reciente con ${entity} para estimar probabilidad de aceptación.`;
    const foco = `El leverage de negociación depende de la dependencia operativa hacia ${entity} · ADI puede cuantificar el gap pero no la capacidad de defensa táctica.`;

    // Confianza media calibrada (D3 · wording bitwise memClient).
    const opener = `${ev}\n\n${lectura}\n\n${honestidad_neg}\n\n${foco}\n\n*Confianza media · cifra de recuperación es runtime · viabilidad de negociación requiere histórico que no está en el escenario activo.*`;

    return {
      opener,
      suggestions: [],
      sentrixAction: {
        label: `Ver ${entity} en Márgenes`,
        moduleChip: "Márgenes",
        payload: {
          modulo: "margenes",
          clientes: [entity],
          skus: [],
          mechanismBanner: `${entity} · simulación gap ${gapPuntos.toFixed(1)}pp`,
        },
      },
    };
  }

  // Fallback SKU
  return {
    opener: `Simulación de benchmark para SKU no implementada en versión actual.`,
    suggestions: [],
    sentrixAction: null,
  };
}

// ──────────────────────────────────────
// 4.5 · composeSimulationLoadReduction
// Razonamiento: simular reducción de carga comercial.
// Recuperable = ventas × (carga_actual - target) / 100.
// ──────────────────────────────────────
function composeSimulationLoadReduction(payload, scenarioId) {
  const { entity, targetCarga } = payload;
  const cliente = clientesMargen.find(c => c.nombre === entity);
  if (!cliente) {
    return { opener: `No tengo datos de ${entity}.`, suggestions: [], sentrixAction: null };
  }
  const gapCarga = cliente.pctRebate - targetCarga;
  if (gapCarga <= 0) {
    return {
      opener: `${entity} ya opera con carga comercial de ${cliente.pctRebate}%, por debajo del target ${targetCarga}%. No hay reducción posible.`,
      suggestions: [],
      sentrixAction: null,
    };
  }

  // BRIEF MICRO · FIX EPISTÉMICO (D2 LOCKED · cifra canónica $194K)
  // Usar clientesVentas.actual (scaled · runtime) en lugar de clientesMargen.venta
  // (raw · 18500). Coherencia con generateSimulation memClient (línea 6589),
  // composePriorityRecommendationV2 (#12) y OBSERVABLE_RELATIONS (#13).
  const ventas = applyScenarioToClientesVentas(scenarioId);
  const ventaCliente = ventas.find(c => c.nombre === entity);
  if (!ventaCliente) {
    return { opener: `No tengo datos de ventas de ${entity}.`, suggestions: [], sentrixAction: null };
  }
  // recuperable en escala "K" (cliente_v.actual está en miles · 19433 = $19.4M)
  const recuperable = Math.round((cliente.pctRebate - targetCarga) / 100 * ventaCliente.actual);
  // Formato venta · escala M (evita "$18500K" del formatter anterior)
  const ventaFmt = `$${(ventaCliente.actual / 1000).toFixed(1)}M`;

  const ev = `${entity} · carga actual ${cliente.pctRebate}% · target ${targetCarga}% · gap ${gapCarga.toFixed(1)} puntos.`;

  // BRIEF MICRO · WORDING HONESTIDAD LOCKED (D3 · copiado bitwise de memClient
  // línea 6591-6594). Cero ajuste editorial · ya validado V_VISUAL post-EPISTEMIC.
  const lectura = `Si la carga comercial de ${entity} baja a ${targetCarga.toFixed(1)}%, se recupera aproximadamente $${recuperable}K anuales en contribución, manteniendo la venta de ${ventaFmt} (cálculo runtime sobre venta actual × delta carga).`;
  const honestidad_neg = `La baja de carga típicamente se negocia con contraprestación: volumen comprometido, exclusividades, plazos. ADI no tiene histórico de negociación reciente con ${entity} para estimar probabilidad de aceptación.`;
  const foco = `El leverage de negociación depende de la dependencia operativa hacia ${entity} · ADI puede cuantificar concentración pero no la capacidad de defensa táctica.`;

  // Confianza media calibrada (D3 · wording bitwise memClient).
  const opener = `${ev}\n\n${lectura}\n\n${honestidad_neg}\n\n${foco}\n\n*Confianza media · cifra de recuperación es runtime · viabilidad de negociación requiere histórico que no está en el escenario activo.*`;

  return {
    opener,
    suggestions: [],
    sentrixAction: {
      label: `Ver ${entity} en Márgenes`,
      moduleChip: "Márgenes",
      payload: {
        modulo: "margenes",
        clientes: [entity],
        skus: [],
        mechanismBanner: `${entity} · simulación carga ${gapCarga.toFixed(1)}pp`,
      },
    },
  };
}

// ──────────────────────────────────────
// 4.6 · composeSimulationRotation
// Razonamiento: capital liberado si SKU pasa de rotación actual a target.
// liberado = stockUSD × (1 - rotación_actual / target)
// ──────────────────────────────────────
function composeSimulationRotation(payload, scenarioId) {
  const { sku, targetRotation } = payload;
  const s = skuInventario.find(x => x.sku === sku);
  if (!s) {
    return { opener: `No tengo datos del SKU ${sku}.`, suggestions: [], sentrixAction: null };
  }
  if (s.rotacion >= targetRotation) {
    return {
      opener: `${sku} ya rota a ${s.rotacion}x, igual o por encima del target de ${targetRotation}x. No hay capital adicional que liberar.`,
      suggestions: [],
      sentrixAction: null,
    };
  }
  // Capital liberado = stockUSD × (1 - rotacion_actual / target)
  const factor = 1 - (s.rotacion / targetRotation);
  const liberado = s.stockUSD * factor;

  const ev = `${sku} · rotación actual ${s.rotacion}x · target ${targetRotation}x · stock comprometido ${_fmtKBis(s.stockUSD)}.`;
  const lectura = `Si ${sku} alcanza rotación ${targetRotation}x, se liberan aproximadamente ${_fmtKBis(liberado)} de capital atrapado (${(factor * 100).toFixed(0)}% del stock actual), redirigibles a SKUs rotacionales del portafolio.`;
  const foco = `La rotación se acelera con promociones, descuentos quirúrgicos o reducción de pedido al proveedor. Para ${sku}, el cambio operativo cierra el gap de ${(targetRotation - s.rotacion).toFixed(1)} vueltas.`;

  const opener = `${ev}\n\n${lectura}\n\n${foco}\n\n*Confianza alta · cálculo determinístico desde stock y rotación actuales.*`;

  return {
    opener,
    suggestions: [],
    sentrixAction: {
      label: `Ver ${sku} en Inventario`,
      moduleChip: "Inventario",
      payload: {
        modulo: "inventario",
        clientes: [],
        skus: [sku],
        mechanismBanner: `${sku} · simulación rotación ${targetRotation}x`,
      },
    },
  };
}

// ──────────────────────────────────────
// 4.7 · composeSimulationContribution
// Razonamiento: simular cierre de gap de contribución (genérico).
// Si entity es cliente: gap × venta. Si es SKU: gap × ventas_mensuales.
// ──────────────────────────────────────
function composeSimulationContribution(payload, scenarioId) {
  const { entity, entityType, gap } = payload;

  if (entityType === "client") {
    const cliente = clientesMargen.find(c => c.nombre === entity);
    if (!cliente) {
      return { opener: `No tengo datos de ${entity}.`, suggestions: [], sentrixAction: null };
    }
    const recuperableUSD = (cliente.venta * gap) / 100 * 1000;
    const ev = `${entity} · contribución actual ${_fmtKBis(cliente.contribucion * 1000)} · gap de ${gap}pp vs benchmark.`;
    const lectura = `Si ${entity} cierra el gap de ${gap}pp, recupera aproximadamente ${_fmtKBis(recuperableUSD)} adicionales de contribución anual.`;
    const foco = `El cierre puede venir por dos palancas: subir margen vía mix o renegociar carga (actualmente ${cliente.pctRebate}%).`;
    const opener = `${ev}\n\n${lectura}\n\n${foco}\n\n*Confianza alta · cálculo determinístico.*`;
    return {
      opener,
      suggestions: [],
      sentrixAction: {
        label: `Ver ${entity} en Márgenes`,
        moduleChip: "Márgenes",
        payload: {
          modulo: "margenes",
          clientes: [entity],
          skus: [],
          mechanismBanner: `${entity} · gap ${gap}pp`,
        },
      },
    };
  }

  return {
    opener: `Simulación de contribución para tipo ${entityType} no implementada.`,
    suggestions: [],
    sentrixAction: null,
  };
}

// ──────────────────────────────────────
// 4.8 · composeExitPlan
// Razonamiento: plan de liquidación de SKU crítico.
// Capital, castigo estimado (50-60%), recuperación neta, tiempo estimado.
// ──────────────────────────────────────
function composeExitPlan(skuName, scenarioId) {
  const s = skuInventario.find(x => x.sku === skuName);
  if (!s) {
    return { opener: `No tengo datos del SKU ${skuName}.`, suggestions: [], sentrixAction: null };
  }

  // Castigo estimado · 50% si rotación crítica, 40% si warn
  const pctCastigo = s.alerta === "crit" ? 0.55 : 0.40;
  const castigoUSD = s.stockUSD * pctCastigo;
  const recuperacionNetaUSD = s.stockUSD - castigoUSD;
  const tiempoEstimado = s.alerta === "crit" ? "60-90 días" : "30-60 días";

  const ev = `${skuName} · ${s.marca} · ${s.sfamilia} · capital atrapado ${_fmtKBis(s.stockUSD)} (${s.stockUnd} unidades) · ${s.diasSinVenta} días sin movimiento.`;
  const lectura = `Plan de salida estimado: castigo ${(pctCastigo * 100).toFixed(0)}% sobre stock actual (${_fmtKBis(castigoUSD)}), con recuperación neta de ${_fmtKBis(recuperacionNetaUSD)}. Ese cash recuperado redirigido a SKUs rotacionales del portafolio convierte capital muerto en contribución.`;
  const foco = `Ejecutar requiere acordar el canal de liquidación (mayorista, outlet, B2B) y aceptar el castigo en P&L del trimestre. Tiempo estimado: ${tiempoEstimado}.`;

  const opener = `${ev}\n\n${lectura}\n\n${foco}\n\n*Confianza alta · cifras determinísticas del inventario actual.*`;

  return {
    opener,
    suggestions: [],
    sentrixAction: {
      label: `Ver ${skuName} en Inventario`,
      moduleChip: "Inventario",
      payload: {
        modulo: "inventario",
        clientes: [],
        skus: [skuName],
        mechanismBanner: `${skuName} · plan de salida`,
      },
    },
  };
}

// ──────────────────────────────────────
// 4.9 · composeCrossModuleView
// Razonamiento: ver entidad desde otro módulo.
// Cliente desde Márgenes: perfil margen + carga + contribución.
// Cliente desde Ventas: tracción comercial.
// SKU desde Márgenes: contribución + margen.
// ──────────────────────────────────────
function composeCrossModuleView(payload, scenarioId) {
  const { entity, entityType, targetModule } = payload;

  if (entityType === "client") {
    const cliente = clientesMargen.find(c => c.nombre === entity);
    if (!cliente) {
      return { opener: `No tengo datos de ${entity}.`, suggestions: [], sentrixAction: null };
    }

    if (targetModule === "margenes") {
      const benchmark = 30.1;
      const gap = benchmark - cliente.margen;
      const ev = `${entity} · margen ${cliente.margen}% | contribución ${_fmtKBis(cliente.contribucion * 1000)} | carga ${cliente.pctRebate}% | venta ${_fmtKBis(cliente.venta * 1000)}.`;
      const lectura = gap > 0
        ? `${entity} opera ${gap.toFixed(1)} puntos por debajo del benchmark de ${benchmark}%. La carga comercial (${cliente.pctRebate}%) y la composición de margen explican la mayor parte del gap.`
        : `${entity} opera al benchmark de ${benchmark}% o por encima. Es una cuenta saludable desde la perspectiva de márgenes.`;
      const foco = gap > 0
        ? `Si se actúa, la palanca de carga comercial es la más directa.`
        : `Conviene proteger las condiciones operativas actuales.`;
      const opener = `${ev}\n\n${lectura}\n\n${foco}\n\n*Confianza alta · datos determinísticos de márgenes.*`;
      return {
        opener,
        suggestions: [],
        sentrixAction: {
          label: `Ver ${entity} en Márgenes`,
          moduleChip: "Márgenes",
          payload: {
            modulo: "margenes",
            clientes: [entity],
            skus: [],
            mechanismBanner: `${entity} · vista márgenes`,
          },
        },
      };
    }

    if (targetModule === "ventas") {
      // Tracción comercial · venta + unidades + marca dominante
      const ev = `${entity} · venta ${_fmtKBis(cliente.venta * 1000)} | unidades ${cliente.unidades} | marca dominante ${cliente.marca} | familia ${cliente.sfamilia}.`;
      const lectura = `${entity} representa ${_fmtKBis(cliente.venta * 1000)} de venta anual, concentrada en ${cliente.sfamilia} con marca ${cliente.marca} como pilar principal del mix comercial.`;
      const foco = `La relación es estratégica desde el punto de vista comercial. Su evolución de tracción es lectura prioritaria.`;
      const opener = `${ev}\n\n${lectura}\n\n${foco}\n\n*Confianza alta · datos determinísticos.*`;
      return {
        opener,
        suggestions: [],
        sentrixAction: {
          label: `Ver ${entity} en Ventas`,
          moduleChip: "Ventas",
          payload: {
            modulo: "ventas",
            clientes: [entity],
            skus: [],
            mechanismBanner: `${entity} · vista ventas`,
          },
        },
      };
    }
  }

  if (entityType === "sku") {
    const s = skuInventario.find(x => x.sku === entity);
    if (!s) {
      return { opener: `No tengo datos del SKU ${entity}.`, suggestions: [], sentrixAction: null };
    }

    if (targetModule === "margenes") {
      const valorUnit = s.stockUnd > 0 ? s.stockUSD / s.stockUnd : 0;
      const contribMensual = s.vendidoMes * valorUnit * (s.margenPct / 100);
      const ev = `${entity} · margen ${s.margenPct}% | contribución mensual ${_fmtKBis(contribMensual)} | ventas mensuales ${s.vendidoMes} unidades.`;
      const lectura = `${entity} aporta aproximadamente ${_fmtKBis(contribMensual)} de contribución mensual al portafolio, con margen ${s.margenPct}% sobre venta.`;
      const foco = s.margenPct >= 25
        ? `El SKU está en zona virtuosa de margen · sostener composición.`
        : `El margen está por debajo del promedio del portafolio · evaluar mix o costo.`;
      const opener = `${ev}\n\n${lectura}\n\n${foco}\n\n*Confianza alta · datos determinísticos.*`;
      return {
        opener,
        suggestions: [],
        sentrixAction: {
          label: `Ver ${entity} en Márgenes`,
          moduleChip: "Márgenes",
          payload: {
            modulo: "margenes",
            clientes: [],
            skus: [entity],
            mechanismBanner: `${entity} · vista márgenes`,
          },
        },
      };
    }
  }

  return {
    opener: `Vista cruzada para ${entityType} en ${targetModule} no implementada.`,
    suggestions: [],
    sentrixAction: null,
  };
}

// ──────────────────────────────────────
// 4.10 · composeCompareOpposite
// Razonamiento: contrastar contra patrón opuesto.
// virtuoso (clientes): margen >= benchmark.
// rotacional (SKUs): rotación >= 9x.
// bottom_contrib (SKUs): contribución más baja.
// ──────────────────────────────────────
function composeCompareOpposite(payload, scenarioId) {
  const { domain, pattern } = payload;

  if (domain === "client" && pattern === "virtuoso") {
    const benchmark = 30.1;
    const virtuosos = clientesMargen
      .filter(c => c.margen >= benchmark)
      .sort((a, b) => b.contribucion - a.contribucion)
      .slice(0, 3);

    if (virtuosos.length === 0) {
      return {
        opener: `No hay cuentas operando por encima del benchmark de ${benchmark}% en el escenario actual.`,
        suggestions: [],
        sentrixAction: null,
      };
    }

    const lineas = virtuosos.map(c =>
      `${c.nombre} → Margen ${c.margen}% | Contribución ${_fmtKBis(c.contribucion * 1000)} | Carga ${c.pctRebate}%`
    );
    const promedioMargenVirt = virtuosos.reduce((s, c) => s + c.margen, 0) / virtuosos.length;
    const promedioCarga = virtuosos.reduce((s, c) => s + c.pctRebate, 0) / virtuosos.length;

    const lectura = `Las cuentas virtuosas comparten una característica: margen promedio ${promedioMargenVirt.toFixed(1)}% (sobre el benchmark de ${benchmark}%) y carga comercial promedio ${promedioCarga.toFixed(1)}%, considerablemente menor que las cuentas con presión.`;
    const foco = `El contraste muestra que la palanca crítica es la carga · las virtuosas mantienen disciplina de descuento, las cuentas presionadas la han diluido.`;

    const opener = `Top 3 cuentas virtuosas del portafolio:\n\n${lineas.join("\n")}\n\n${lectura}\n\n${foco}\n\n*Confianza alta · datos determinísticos.*`;

    return {
      opener,
      suggestions: [],
      sentrixAction: {
        label: `Ver cuentas virtuosas en Márgenes`,
        moduleChip: "Márgenes",
        payload: {
          modulo: "margenes",
          clientes: virtuosos.map(c => c.nombre),
          skus: [],
          mechanismBanner: `${virtuosos.length} cuentas virtuosas`,
        },
      },
    };
  }

  if (domain === "sku" && pattern === "rotacional") {
    const rotacionales = skuInventario
      .filter(s => s.rotacion >= 9)
      .sort((a, b) => b.rotacion - a.rotacion)
      .slice(0, 3);

    if (rotacionales.length === 0) {
      return {
        opener: `No hay SKUs rotando por encima de 9x en el inventario actual.`,
        suggestions: [],
        sentrixAction: null,
      };
    }

    const lineas = rotacionales.map(s =>
      `${s.sku} → Rotación ${s.rotacion}x | DOH ${s.doh}d | Margen ${s.margenPct}%`
    );
    const promedioRot = rotacionales.reduce((s, x) => s + x.rotacion, 0) / rotacionales.length;

    const lectura = `Los SKU rotacionales convierten stock a venta a ${promedioRot.toFixed(1)}x promedio · su DOH es bajo, su margen se sostiene en zona virtuosa, no requieren capital ocioso.`;
    const foco = `Estos son los SKU a sobre-invertir y replicar en el portafolio · el contraste con los críticos muestra que el portafolio sí tiene casos exitosos.`;

    const opener = `Top 3 SKUs rotacionales del portafolio:\n\n${lineas.join("\n")}\n\n${lectura}\n\n${foco}\n\n*Confianza alta · datos determinísticos.*`;

    return {
      opener,
      suggestions: [],
      sentrixAction: {
        label: `Ver SKUs rotacionales en Inventario`,
        moduleChip: "Inventario",
        payload: {
          modulo: "inventario",
          clientes: [],
          skus: rotacionales.map(s => s.sku),
          mechanismBanner: `${rotacionales.length} SKUs rotacionales`,
        },
      },
    };
  }

  if (domain === "sku" && pattern === "bottom_contrib") {
    // SKUs de menor aporte económico (contribución mensual)
    const skusBottom = skuInventario
      .map(s => {
        const valorUnit = s.stockUnd > 0 ? s.stockUSD / s.stockUnd : 0;
        const contribMensual = s.vendidoMes * valorUnit * (s.margenPct / 100);
        return { ...s, contribMensual };
      })
      .sort((a, b) => a.contribMensual - b.contribMensual)
      .slice(0, 3);

    const lineas = skusBottom.map(s =>
      `${s.sku} → Contribución ${_fmtKBis(s.contribMensual)}/mes | Margen ${s.margenPct}% | Rotación ${s.rotacion}x`
    );
    const totalContrib = skusBottom.reduce((acc, s) => acc + s.contribMensual, 0);

    const lectura = `Los 3 SKU de menor aporte aportan combinados ${_fmtKBis(totalContrib)} mensuales · su contribución es marginal frente al esfuerzo de mantenerlos en stock.`;
    const foco = `Evaluar si el portafolio puede simplificarse · cada SKU bottom mantiene costo operativo (gestión, espacio, capital) que podría redirigirse.`;

    const opener = `Top 3 SKUs de menor aporte económico:\n\n${lineas.join("\n")}\n\n${lectura}\n\n${foco}\n\n*Confianza alta · datos determinísticos.*`;

    return {
      opener,
      suggestions: [],
      sentrixAction: {
        label: `Ver SKUs bottom en Inventario`,
        moduleChip: "Inventario",
        payload: {
          modulo: "inventario",
          clientes: [],
          skus: skusBottom.map(s => s.sku),
          mechanismBanner: `SKUs de menor aporte`,
        },
      },
    };
  }

  return {
    opener: `Comparación contra ${pattern} en dominio ${domain} no implementada.`,
    suggestions: [],
    sentrixAction: null,
  };
}

// ═══════════════════════════════════════════════════════
// BRIEF #26-ter · Composer dual comparación SKU
// "Caballo de carrera vs lastre"
//
// Modo Oportunidad: contrasta lo que rinde con lo que pesa.
// No es solo descripción · es decisión: qué proteger, qué soltar,
// qué patrón común explica la diferencia. Estructura Ferrari.
// Cero hardcoding · cifras del dataset en runtime.
// ═══════════════════════════════════════════════════════
function composeProductDualComparison(scenarioId) {
  const todosSkus = skuInventario.map(s => ({
    ...s,
    contribucion_mensual: Math.round(s.vendidoMes * (s.margenPct / 100) * 1000),
  }));

  // TOP virtuosos: rotación alta + margen sobre benchmark + alerta limpia
  const virtuosos = todosSkus
    .filter(s => s.rotacion >= 7 && s.margenPct >= 22 && s.alerta !== "crit" && s.alerta !== "warn")
    .sort((a, b) => b.contribucion_mensual - a.contribucion_mensual)
    .slice(0, 3);

  // BOTTOM lastres: alerta crit/warn o rotación muy baja
  const lastres = todosSkus
    .filter(s => s.alerta === "crit" || s.alerta === "warn" || s.rotacion < 2)
    .sort((a, b) => b.stockUSD - a.stockUSD)
    .slice(0, 3);

  if (virtuosos.length === 0 || lastres.length === 0) {
    return {
      opener: "El portafolio no muestra contraste claro entre virtuosos y lastres en el escenario actual. Todas las líneas operan en rangos similares.",
      suggestions: [],
      sentrixAction: null,
    };
  }

  // Bloque virtuosos
  let opener = `Caballo de carrera del portafolio:\n\n`;
  virtuosos.forEach(s => {
    opener += `${s.sku} → Contribución $${s.contribucion_mensual}/mes | Margen ${s.margenPct}% | Rotación ${s.rotacion}x\n`;
  });

  opener += `\nLastre del portafolio:\n\n`;
  lastres.forEach(s => {
    opener += `${s.sku} → Stock $${(s.stockUSD / 1000).toFixed(1)}K | DOH ${s.doh}d | Rotación ${s.rotacion}x | ${s.diasSinVenta}d sin venta\n`;
  });

  // Lectura comparativa
  const promMargenVirt = (virtuosos.reduce((s, r) => s + r.margenPct, 0) / virtuosos.length).toFixed(1);
  const promRotVirt    = (virtuosos.reduce((s, r) => s + r.rotacion, 0) / virtuosos.length).toFixed(1);
  const promRotLastre  = (lastres.reduce((s, r) => s + r.rotacion, 0) / lastres.length).toFixed(1);
  const capitalLastre  = lastres.reduce((s, r) => s + r.stockUSD, 0);
  const contribVirt    = virtuosos.reduce((s, r) => s + r.contribucion_mensual, 0);

  opener += `\nLos virtuosos operan con rotación promedio ${promRotVirt}x y margen ${promMargenVirt}%. Los lastres rotan ${promRotLastre}x. La diferencia no es de categoría · es de eficiencia operativa: misma cartera, mismo cliente, distinta velocidad de conversión.\n`;
  opener += `\nLos virtuosos generan aproximadamente $${contribVirt.toLocaleString()}/mes en contribución. Los lastres tienen $${(capitalLastre / 1000).toFixed(1)}K de capital atrapado que NO está convirtiéndose al ritmo del portafolio.\n`;

  // Foco accionable
  const topVirtuoso = virtuosos[0].sku;
  const topLastre   = lastres[0].sku;

  opener += `\n${topVirtuoso} opera como palanca de rentabilidad · zona estructural a preservar en composición · ${topLastre} concentra capital con espacio de reinversión disponible hacia SKUs rotacionales del portafolio.`;
  opener += `\n\n*Confianza alta · datos determinísticos del portafolio actual.*`;

  // BRIEF #26-quinquies-B · enriquecimiento con contrato v1.
  const capitalLastres = lastres.reduce((s, r) => s + r.stockUSD, 0);
  const contribVirtuosos = virtuosos.reduce(
    (s, r) => s + Math.round(r.vendidoMes * (r.margenPct / 100)),
    0
  );
  return buildResponseContract({
    opener,
    suggestions: [
      {
        text: `¿Cuál es el plan de salida de ${topLastre}?`,
        action: { type: "exit_plan", payload: { sku: topLastre } },
      },
      {
        text: `¿Qué libero si ${topLastre} alcanza rotación 9x?`,
        action: { type: "simulation_rotation", payload: { sku: topLastre, targetRotation: 9 } },
      },
      {
        text: `¿Cuál es el análisis operativo de ${topVirtuoso}?`,
        action: { type: "sku_deep_dive_action", payload: { skuName: topVirtuoso } },
      },
    ],
    sentrixAction: {
      label: `Ver ${virtuosos.length + lastres.length} SKUs comparados`,
      moduleChip: "Inventario",
      payload: {
        modulo: "inventario",
        clientes: [],
        skus: [...virtuosos.map(s => s.sku), ...lastres.map(s => s.sku)],
      },
    },
    decision: virtuosos[0].sku,
    evidence: {
      caballo_carrera: virtuosos[0].sku,
      caballo_carrera_rotacion: virtuosos[0].rotacion,
      caballo_carrera_margen: virtuosos[0].margenPct,
      caballo_carrera_contribucion_mes_K: Math.round(
        virtuosos[0].vendidoMes * (virtuosos[0].margenPct / 100)
      ),
      lastre_principal: lastres[0].sku,
      lastre_doh: lastres[0].doh,
      lastre_dias_sin_venta: lastres[0].diasSinVenta,
      lastre_capital_K: +(lastres[0].stockUSD / 1000).toFixed(1),
      virtuosos_count: virtuosos.length,
      lastres_count: lastres.length,
      promedio_rotacion_virtuosos: +(
        virtuosos.reduce((s, r) => s + r.rotacion, 0) / virtuosos.length
      ).toFixed(1),
      promedio_rotacion_lastres: +(
        lastres.reduce((s, r) => s + r.rotacion, 0) / lastres.length
      ).toFixed(1),
      contribucion_virtuosos_K: contribVirtuosos,
      capital_lastres_K: +(capitalLastres / 1000).toFixed(1),
    },
    focus: `Proteger ${virtuosos[0].sku} y decidir sobre ${lastres[0].sku}`,
    confidence: "alta",
    materialMetrics: [
      `${virtuosos[0].rotacion}x vs ${lastres[0].rotacion}x rotación`,
      `${virtuosos[0].margenPct}% vs ${lastres[0].margenPct}% margen`,
      `$${(capitalLastres / 1000).toFixed(1)}K capital atrapado`,
    ],
    reasoningPattern: "portfolio_dual_efficiency_contrast",
    suggestedNextActions: [
      "Plan de salida del lastre principal",
      "Análisis operativo del caballo de carrera",
      "Capital liberado por rotación",
    ],
  });
}

// ═══════════════════════════════════════════════════════
// BRIEF #26-ter · Composer Growth Opportunity
// "Dónde vale la pena invertir esfuerzo comercial"
//
// Modo Oportunidad: contrasta el ranking de problemas con el ranking
// de potencial. ADI razona sobre upside, no solo downside.
// Cero hardcoding · cifras del dataset en runtime.
// ═══════════════════════════════════════════════════════
function composeGrowthOpportunity(scenarioId) {
  const margenes = getClientesMargenWithProtected(scenarioId);

  // Cliente con margen sobre benchmark + carga baja + espacio de crecimiento
  const oportunidades = margenes
    .filter(c => c.margen >= 27 && c.pctRebate <= 4.0)
    .map(c => ({
      ...c,
      // Score · prioriza margen alto sobre carga baja
      score: c.margen * (1 / Math.max(c.pctRebate, 1)),
    }))
    .sort((a, b) => b.score - a.score)
    .slice(0, 3);

  if (oportunidades.length === 0) {
    return {
      opener: "En el escenario actual no hay cuentas con combinación clara de margen alto y carga comercial baja. Todas las cuentas operan con presión similar.",
      suggestions: [],
      sentrixAction: null,
    };
  }

  // Bloque oportunidades
  let opener = `Cuentas con upside operativo real:\n\n`;
  oportunidades.forEach(c => {
    opener += `${c.nombre} → Margen ${c.margen.toFixed(1)}% | Carga ${c.pctRebate.toFixed(1)}% | Ventas $${(c.venta / 1000).toFixed(2)}M | Contribución $${c.contribucion}K\n`;
  });

  // Lectura
  const top = oportunidades[0];
  const promMargen = (oportunidades.reduce((s, c) => s + c.margen, 0) / oportunidades.length).toFixed(1);
  const promCarga  = (oportunidades.reduce((s, c) => s + c.pctRebate, 0) / oportunidades.length).toFixed(1);

  opener += `\nEstas cuentas comparten una característica: operan con margen promedio ${promMargen}% y carga comercial promedio ${promCarga}%, considerablemente menor a las Tier 1 erosionadas (4-5% de carga). No están pidiendo concesiones que diluyan rentabilidad.\n`;

  opener += `\n${top.nombre} es el caso de mayor eficiencia · margen ${top.margen}% con apenas ${top.pctRebate}% de carga. Si su materialidad crece 25%, libera aproximadamente $${Math.round(top.contribucion * 0.25)}K adicionales de contribución sin renegociar nada · solo capturando más volumen sobre la misma estructura.\n`;

  // Foco accionable
  opener += `\nMecanismo disponible: ${top.nombre} combina tracción + margen sano + carga baja · zona donde el empuje comercial convierte cada dólar de venta adicional a contribución a ritmo del portafolio virtuoso, sin las concesiones que están pagando Falabella o Lider.`;
  opener += `\n\n*Confianza alta · datos determinísticos del escenario activo.*`;

  return buildResponseContract({
    opener,
    suggestions: [
      {
        text: `¿Cómo se ve ${top.nombre} en Ventas?`,
        action: { type: "cross_module_view", payload: { entity: top.nombre, entityType: "client", targetModule: "ventas" } },
      },
      {
        text: `¿Qué SKUs aportan más en ${top.nombre}?`,
        action: { type: "cross_domain_client_to_sku", payload: { clientName: top.nombre } },
      },
      {
        text: "¿Comparar contra cuentas presionadas?",
        action: { type: "compare_opposite", payload: { domain: "client", pattern: "virtuoso" } },
      },
    ],
    sentrixAction: {
      label: `Ver ${oportunidades.length} cuentas con upside`,
      moduleChip: "Márgenes",
      payload: {
        modulo: "margenes",
        clientes: oportunidades.map(c => c.nombre),
        skus: [],
      },
    },
    // BRIEF #26-quinquies-B · contrato v1
    decision: top.nombre,
    evidence: {
      entidad_principal: top.nombre,
      margen_principal: top.margen,
      benchmark_margen: 30.1,
      carga_principal: top.pctRebate,
      best_practice_carga: 3.0,
      ventas_principal_M: +(top.venta / 1000).toFixed(2),
      contribucion_actual_K: top.contribucion,
      upside_estimado_K: Math.round(top.contribucion * 0.25),
      escenario_crecimiento_pct: 25,
      cuentas_oportunidad_count: oportunidades.length,
      cuentas_oportunidad_list: oportunidades.map(c => c.nombre),
      promedio_margen_oportunidades: +(oportunidades.reduce((s, c) => s + c.margen, 0) / oportunidades.length).toFixed(1),
      promedio_carga_oportunidades: +(oportunidades.reduce((s, c) => s + c.pctRebate, 0) / oportunidades.length).toFixed(1),
    },
    focus: `Empujar tracción comercial en ${top.nombre}`,
    confidence: "alta",
    materialMetrics: [
      `${top.margen.toFixed(1)}% margen`,
      `${top.pctRebate.toFixed(1)}% carga`,
      `$${Math.round(top.contribucion * 0.25)}K upside`,
    ],
    reasoningPattern: "high_margin_low_load_with_upside",
    suggestedNextActions: [
      "Ver tracción comercial",
      "Identificar SKUs clave",
      "Comparar contra erosionadas",
    ],
  });
}

// ═══ ENCARGO D-VOICE-POLISH-ECL · VARIANTES DE REGISTRO · cero LLM · cero cifra nueva ═══
// El disco rayado de cuentas (composeAccountDevelopment) da el MISMO párrafo de 1489 chars a
// toda meta-pregunta. Este corte detecta el REGISTRO pedido (llano/ejecutivo) y reformatea los
// facts que `dev` YA computó — sin tocar una cifra, sin LLM, sin síntesis nueva. La voz cambia
// el FORMATO, nunca el DATO (invariante absoluto). El composer base NO se modifica: el `dev`, su
// cómputo y el texto default quedan idénticos · las variantes son funciones que LEEN `dev`.
// off = el disco completo para todas (byte-idéntico).
const ADI_ECL_VOICE_POLISH_ENABLED = true;

// ── _detectVoiceRegister(trimmed) · marcador EXPLÍCITO de registro (cláusula 5) ──
// Devuelve "llano" | "ejecutivo" | null. SOLO dispara con marcador · "profundiza"/continuaciones
// normales → null (disco completo). El telegráfico "en una frase" queda FUERA (deuda #D-VOICE-FRASE-BIS).
function _detectVoiceRegister(trimmed) {
  try {
    if (typeof ADI_ECL_VOICE_POLISH_ENABLED === "undefined" || !ADI_ECL_VOICE_POLISH_ENABLED) return null;
    if (typeof trimmed !== "string" || !trimmed) return null;
    const n = _normalizeSemanticText(trimmed);
    if (!n) return null;
    // LLANO · sin tecnicismos / simple / fácil / sin jerga
    if (/sin\s+tecnicismos|sin\s+tanta\s+jerga|sin\s+jerga|explicamelo\s+simple|explicamelo\s+facil|mas\s+simple|en\s+simple|mas\s+facil/.test(n)) return "llano";
    // EJECUTIVO/DIRECTORIO · al directorio / lectura ejecutiva / a gerencia
    if (/al\s+directorio|le\s+dirias\s+al\s+directorio|diras\s+al\s+directorio|lectura\s+ejecutiva|a\s+gerencia|lo\s+dirias\s+a\s+gerencia|para\s+el\s+directorio/.test(n)) return "ejecutivo";
    return null;
  } catch (e) { return null; }
}

// ── _eclRenderLlano(dev, mayorPot, masRentable, menorCarga) · los mismos facts SIN jerga ──
// Lenguaje claro · omite carga%/ticket/DOH/benchmark · mismos números de `dev`. Cero cifra nueva.
function _eclRenderLlano(dev, mayorPot, masRentable, menorCarga) {
  let o = "En simple: estas cuentas dejan plata sobre la mesa, pero por razones distintas.\n\n";
  o += `${mayorPot.nombre} es la que más puede crecer: hasta +$${mayorPot.potencial}K si le vendés más volumen, sin tocar precios ni dar mejores condiciones.\n`;
  o += `${masRentable.nombre} es la que mejor margen te deja (${masRentable.margen}% de cada venta).\n`;
  o += `${menorCarga.nombre} es la que menos te cuesta en descuentos comerciales.\n`;
  o += `\nLo que comparten las tres: no te están pidiendo rebajas. El espacio está en venderles más, no en darles condiciones más blandas. Por eso el camino es empujar volumen donde el margen ya es bueno.\n`;
  o += `\n¿Querés que arme el plan para venderle más a ${mayorPot.nombre}?`;
  return o;
}

// ── _eclRenderEjecutivo(dev, mayorPot, masRentable, menorCarga) · tesis + razón + acción ──
// Extrae lo que YA está (la tesis literal del composer + mayorPot + "no piden concesiones").
// NO suma potenciales (esa cifra NO está pre-computada · sería cifra nueva · prohibido). Usa
// mayorPot.potencial individual. Cero cifra nueva.
function _eclRenderEjecutivo(dev, mayorPot, masRentable, menorCarga) {
  let o = `Tesis: hay contribución capturable en las cuentas grandes sin renegociar nada — solo escalando volumen donde el margen ya es sano.\n\n`;
  o += `Razón: su carga comercial es baja frente a las cuentas erosionadas. No están pidiendo concesiones que diluyan rentabilidad.\n\n`;
  o += `Acción: plan de empuje comercial, empezando por ${mayorPot.nombre} — el mayor upside (+$${mayorPot.potencial}K sobre la misma estructura). ${masRentable.nombre} es la cuenta más rentable (margen ${masRentable.margen}%) para sostener el margen del esfuerzo.\n`;
  return o;
}
// ═══ FIN ENCARGO D-VOICE-POLISH-ECL · símbolos top-level ═══

// ═══════════════════════════════════════════════════════════════════════════
// R3 · composeAccountDevelopment · desarrollo per-cuenta de un hallazgo de
// cuentas (activeResult.entityType === "cliente"). MARCO VOLUMEN/CARGA (lógica 2
// de upside · escalar estructura sana), NO benchmark — coherente con growth, que
// no usa benchmark. Lee activeResult.entities y busca cada cuenta por nombre en
// getClientesMargenWithProtected (NO recomputa el ranking · invariante del set).
// INVARIANTE DURO: si el set no se recupera completo (escenario cambió) → re-ancla
// honesto, jamás fabrica. Cifras del dataset enriquecido (potencial =
// contribucion×0.25, idéntica a growth · volumen +25% sobre misma estructura).
// Mix como CAUSA (familia+marca dominante por sfamilia sumando actual), no lista.
// Orden por TESIS (potencial desc), no por orden de entities. Tesis/cierre = voz
// fija del composer; las cifras rellenan el desglose. Rama honesta si falta mix.
// ═══════════════════════════════════════════════════════════════════════════
function composeAccountDevelopment(activeResult, scenarioId, voiceRegister) {
  const reanchor = (m) => ({ opener: m, suggestions: [], sentrixAction: null, reasoningPattern: "account_dev_honest_reanchor", _r3: "honest_reanchor" });
  if (!activeResult || !Array.isArray(activeResult.entities) || activeResult.entities.length === 0)
    return reanchor("No tengo un análisis de cuentas activo para profundizar.");
  const arr = getClientesMargenWithProtected(scenarioId);
  const accounts = activeResult.entities.map(n => arr.find(x => x.nombre === n)).filter(Boolean);
  // INVARIANTE DURO · el set recomputable debe coincidir con activeResult.entities.
  if (accounts.length !== activeResult.entities.length)
    return reanchor("El análisis era sobre " + activeResult.entities.join(", ") + ", pero no puedo recuperar todas esas cuentas con datos coherentes en el escenario actual. ¿Reanclamos al análisis original?");
  const dev = accounts.map(c => {
    const ticket = +(c.venta / c.unidades).toFixed(1);
    const potencial = Math.round(c.contribucion * 0.25); // idéntica a growth · volumen +25% sobre misma estructura
    const skus = (typeof skusPorCliente !== "undefined" ? skusPorCliente[c.nombre] : null) || [];
    const famAgg = {}, famMarca = {};
    skus.forEach(s => {
      famAgg[s.sfamilia] = (famAgg[s.sfamilia] || 0) + s.actual;
      (famMarca[s.sfamilia] = famMarca[s.sfamilia] || {});
      famMarca[s.sfamilia][s.marca] = (famMarca[s.sfamilia][s.marca] || 0) + s.actual;
    });
    const famKeys = Object.keys(famAgg);
    const domFam = famKeys.length ? famKeys.sort((a, b) => famAgg[b] - famAgg[a])[0] : null;
    const domMarca = domFam ? Object.keys(famMarca[domFam]).sort((a, b) => famMarca[domFam][b] - famMarca[domFam][a])[0] : null;
    return { nombre: c.nombre, margen: c.margen, carga: c.pctRebate, ticket, contribucion: c.contribucion, potencial, domFam, domMarca, hasMix: !!domFam };
  });
  // ORDEN POR TESIS · oportunidad económica (potencial desc) · NO orden de entities.
  dev.sort((a, b) => b.potencial - a.potencial);
  const masRentable = dev.reduce((a, c) => c.margen > a.margen ? c : a);
  const mayorPot = dev[0];
  const menorCarga = dev.reduce((a, c) => c.carga < a.carga ? c : a);
  let o = "Las tres aportan, pero no por la misma razón — vale separarlas.\n\n";
  for (const d of dev) {
    const mix = d.hasMix
      ? ` Se concentra en ${d.domFam.toLowerCase()} ${d.domMarca}, donde la presión comercial es menor.`
      : " No tengo el detalle de mix de productos para esta cuenta.";
    o += `${d.nombre}: margen ${d.margen}%, carga ${d.carga}% (baja frente a las erosionadas, entre 4% y 5%), ticket $${d.ticket}K, contribución $${d.contribucion}K. Potencial +$${d.potencial}K escalando volumen sobre la misma estructura, sin renegociar.${mix}\n`;
  }
  o += `\n${mayorPot.nombre} es la mayor oportunidad económica (+$${mayorPot.potencial}K). ${masRentable.nombre} es la más rentable (margen ${masRentable.margen}%). ${menorCarga.nombre} es la prueba de concepto — carga ${menorCarga.carga}%, la más baja de la cartera.\n`;
  o += `\nLas tres comparten lo mismo: carga comercial baja frente a las Tier 1 erosionadas. No están pidiendo concesiones que diluyan rentabilidad.\n`;
  o += `\nEl upside no viene de vender más caro ni de renegociar, sino de empujar volumen donde el margen ya es sano y la estructura ya es virtuosa — capturar más contribución sobre la misma base.\n`;
  o += `\n¿Quieres que arme el plan de empuje comercial para ${mayorPot.nombre}, o comparamos las tres contra las cuentas erosionadas?`;
  // ── D-VOICE-POLISH-ECL · si se pidió un registro, sustituir el texto (NO el dato) ──
  // El `dev` y sus derivados (arriba) quedan idénticos · solo cambia la PRESENTACIÓN. Las variantes
  // leen mayorPot/masRentable/menorCarga (facts ya computados) · cero cifra nueva. off → el disco.
  if (typeof ADI_ECL_VOICE_POLISH_ENABLED !== "undefined" && ADI_ECL_VOICE_POLISH_ENABLED && voiceRegister) {
    if (voiceRegister === "llano") {
      o = _eclRenderLlano(dev, mayorPot, masRentable, menorCarga);
    } else if (voiceRegister === "ejecutivo") {
      o = _eclRenderEjecutivo(dev, mayorPot, masRentable, menorCarga);
    }
  }
  return {
    opener: o,
    suggestions: ["Plan de empuje comercial", "Comparar contra erosionadas", "Ver mix por cuenta"],
    sentrixAction: null,
    reasoningPattern: "account_development_volume_upside",
    _r3: "account_development",
    _order: dev.map(d => d.nombre),
  };
}

// ═══════════════════════════════════════════════════════════════════════════
// R4 · composeSkuDevelopment · desarrollo del hallazgo de SKU (análogo a R3).
// Jerarquía del founder: impacto económico → clasificación → evidencia → acción
// → priorización. El dinero (stockUSD) lidera; DOH/rotación justifican.
// CERO criterio inventado: la acción de cada SKU SALE de classifySkuOperationalProfile
// (el motor), R4 no reimplementa la regla. El "por qué" usa valores reales del SKU +
// el outcome del clasificador, sin citar el umbral 90/3 (decisión b del founder).
// Set estable: skuInventario no depende de escenario → lee activeResult, no recomputa.
// ═══════════════════════════════════════════════════════════════════════════
function composeSkuDevelopment(activeResult, scenarioId) {
  const reanchor = (m) => ({ opener: m, suggestions: [], sentrixAction: null, reasoningPattern: "sku_dev_honest_reanchor", _r4: "honest_reanchor" });
  if (!activeResult || !Array.isArray(activeResult.entities) || activeResult.entities.length === 0)
    return reanchor("No tengo un análisis de SKU activo para profundizar.");
  // set estable · busca por sku en skuInventario · NO recomputa por escenario
  const found = activeResult.entities.map(n => skuInventario.find(s => s.sku === n)).filter(Boolean);
  if (found.length !== activeResult.entities.length)
    return reanchor("El análisis era sobre " + activeResult.entities.join(", ") + ", pero no puedo recuperar todos esos SKUs con datos coherentes. ¿Reanclamos al análisis original?");
  // ACCIÓN TRAZABLE · R4 LLAMA al clasificador del motor (no reimplementa la regla)
  const ACCION = { operational_inefficient: "liquidar", high_volume_healthy: "mantener", borderline: "revisar pricing" };
  const dev = found.map(s => {
    const profile = classifySkuOperationalProfile(s);
    return { sku: s.sku, stockUSD: s.stockUSD, doh: s.doh, rotacion: s.rotacion, diasSinVenta: s.diasSinVenta, margenPct: s.margenPct, profile, accion: ACCION[profile] || "revisar pricing" };
  });
  const fmtK = (v) => "$" + (v / 1000).toFixed(1) + "K";
  // operational_inefficient = liberable · orden de ejecución por capital atrapado (stockUSD desc = money-first)
  const liquidar = dev.filter(d => d.profile === "operational_inefficient").sort((a, b) => b.stockUSD - a.stockUSD);
  const mantener = dev.filter(d => d.profile === "high_volume_healthy");
  const revisar  = dev.filter(d => d.profile === "borderline");
  const liberable = liquidar.reduce((sum, d) => sum + d.stockUSD, 0); // suma stockUSD · cero-hardcoding
  // ── 1. APERTURA ECONÓMICA · el dinero lidera
  let o = "";
  if (liquidar.length === 0) {
    o += "Profundizando en estos SKUs: ninguno requiere liquidación — el capital inmovilizado está en posiciones que aún rotan.\n";
  } else {
    o += `Profundizando en los SKUs con mayor capital inmovilizado, no todos requieren la misma acción. Hoy hay ${fmtK(liberable)} de capital que puede liberarse actuando sobre ${liquidar.length === 1 ? "un producto" : liquidar.length + " productos"} específicos.\n\n`;
  }
  // ── 2. PER-SKU · monto primero · DOH/rotación como respaldo (valores reales + outcome, sin umbral)
  liquidar.forEach((d, i) => {
    if (i === 0) {
      o += `${d.sku} concentra el mayor problema. Mantiene ${fmtK(d.stockUSD)} inmovilizados y prácticamente no rota (rotación ${d.rotacion}x, ${d.doh} días de cobertura, ${d.diasSinVenta} sin venta) — ineficiencia operativa: capital atrapado que no se mueve.\n`;
    } else {
      o += `${d.sku} mantiene ${fmtK(d.stockUSD)} inmovilizados, rotación ${d.rotacion}x con ${d.doh} días de cobertura (${d.diasSinVenta} sin venta) — mismo patrón de ineficiencia operativa.\n`;
    }
  });
  // ── 3. LA EXCEPCIÓN EXPLÍCITA (principio · la excepción valiosa > recomendaciones idénticas)
  mantener.forEach(d => {
    o += `\n${d.sku} es caso aparte: no se toca. Aunque aparece en la alerta de capital, rota sano (rotación ${d.rotacion}x, ${d.doh} días de cobertura) — su capital está trabajando. Liquidarlo destruiría una posición que rinde.\n`;
  });
  revisar.forEach(d => {
    o += `\n${d.sku}: zona intermedia (rotación ${d.rotacion}x, ${d.doh} días de cobertura) — revisar pricing antes de decidir.\n`;
  });
  // ── 4. PRIORIZACIÓN + cierre accionable
  if (liquidar.length > 0) {
    const orden = liquidar.map(d => `${d.sku} (${fmtK(d.stockUSD)})`).join(" → ");
    o += `\nOrden de ejecución por capital atrapado: ${orden}. Liberás ${fmtK(liberable)} sin tocar lo que funciona.`;
  }
  return {
    opener: o,
    suggestions: ["Plan de liquidación", "Ver destino de reinversión", "Comparar con SKUs sanos"],
    sentrixAction: null,
    reasoningPattern: "sku_development_capital_release",
    _r4: "sku_development",
    _actions: Object.fromEntries(dev.map(d => [d.sku, d.accion])), // trazabilidad · invariante
    _liberable: liberable,
    _order: liquidar.map(d => d.sku),
  };
}

// ═══════════════════════════════════════════════════════════════════════════
// BRIEF #29-ter · Helpers de concordancia gramatical
//
// Resuelven género (masculino/femenino) y plural (regular/irregular) de las
// dimensiones del drilldown para que el output diga "la bodega"/"el sku"/
// "ninguna marca"/"3 sucursales" gramaticalmente correcto, no "el bodega"/
// "ningún marca"/"3 sucursals".
//
// Tabla interna · única fuente de verdad para 9 dimensiones (5 del demo +
// 4 future-proof). Lookup determinístico case-insensitive (.toLowerCase()).
//
// Fallback: dimensión desconocida → masculino "el ${X}" + plural ingenuo ("Xs").
// Cero impacto en BRIEFs previos · solo afecta concatenaciones de
// artículos/cuantificadores en el scope del drilldown.
// ═══════════════════════════════════════════════════════════════════════════
function _dimensionGrammar(dimensionLabel) {
  // Lookup case-insensitive (composer pasa "Bodega", helper pasa "bodega").
  const key = (dimensionLabel || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  const TABLE = {
    "bodega":    { gender: "f", article: "la", negArticle: "ninguna", uno: "una sola", singular: "bodega",    plural: "bodegas" },
    "sku":       { gender: "m", article: "el", negArticle: "ningún",  uno: "un solo",  singular: "sku",       plural: "skus" },
    "cliente":   { gender: "m", article: "el", negArticle: "ningún",  uno: "un solo",  singular: "cliente",   plural: "clientes" },
    "marca":     { gender: "f", article: "la", negArticle: "ninguna", uno: "una sola", singular: "marca",     plural: "marcas" },
    "sfamilia":  { gender: "f", article: "la", negArticle: "ninguna", uno: "una sola", singular: "sfamilia",  plural: "sfamilias" },
    "familia":   { gender: "f", article: "la", negArticle: "ninguna", uno: "una sola", singular: "familia",   plural: "familias" },
    "categoria": { gender: "f", article: "la", negArticle: "ninguna", uno: "una sola", singular: "categoría", plural: "categorías" },
    "canal":     { gender: "m", article: "el", negArticle: "ningún",  uno: "un solo",  singular: "canal",     plural: "canales" },
    "sucursal":  { gender: "f", article: "la", negArticle: "ninguna", uno: "una sola", singular: "sucursal",  plural: "sucursales" },
  };
  // Fallback masculino seguro (cero regresión visible en dimensiones nuevas).
  return TABLE[key] || {
    gender: "m",
    article: "el",
    negArticle: "ningún",
    uno: "un solo",
    singular: dimensionLabel.toLowerCase(),
    plural: dimensionLabel.toLowerCase() + "s",
  };
}

function _pluralize(count, dimensionLabel) {
  // Retorna "N bodega" si count === 1, "N bodegas" si count !== 1.
  // count puede venir como número o string · coerción soft.
  const grammar = _dimensionGrammar(dimensionLabel);
  const n = Number(count);
  if (n === 1) return `${n} ${grammar.singular}`;
  return `${count} ${grammar.plural}`;
}

// ═══════════════════════════════════════════════════════════════════════════
// BRIEF #29-quater · Helper de interpretación causal del drilldown
//
// Transforma la "Lectura comparativa" del drilldown de descripción mecánica
// a interpretación de controller. Razona sobre el ranking ya ordenado y
// retorna 2-3 frases que clasifican el nivel de concentración y modulan el
// cierre causal según el goal de la investigación.
//
// 5 niveles de concentración (determinístico por umbrales):
//   · top1 >= 50%               → concentración alta · "un solo X concentra"
//   · top1 entre 35-50%         → moderada-alta · "X lidera con materialidad"
//   · top1 < 35% Y top2 >= 50%  → bipolar · "dos X concentran"
//   · top3 >= 60% (resto)       → moderada · "3 X explican el grueso"
//   · resto                     → distribuida · "patrón estructural"
//
// 5 cierres causales por goal · misma estructura, distinta lente ejecutiva:
//   · liberar_capital      → "cobertura excesiva" / "stock detenido"
//   · recuperar_margen     → "presión de carga estructural" / "erosión sistemática"
//   · maximizar_contribucion → "concentración de valor" / "palanca de upside"
//   · proteger_rentabilidad → "núcleo virtuoso del portafolio"
//   · entender_problema|null → cierre neutro "patrón estructural"
//
// 2 variantes por nivel · seleccionadas por hashClientName(top.name) % 2.
// Determinístico bitwise. Cero hardcoding numérico (solo umbrales 50/35/60).
// ═══════════════════════════════════════════════════════════════════════════
function _composeDrilldownReading(ranking, totalValue, dimensionLabel, metricLabel, goal) {
  // Guard mínimo · ranking vacío no debería llegar acá (ya hay guard upstream)
  if (!ranking || ranking.length === 0) return "";

  const dim = dimensionLabel.toLowerCase();
  const top1 = ranking[0];
  const top2 = ranking[1] || null;
  const top3 = ranking[2] || null;

  const top1Share = top1.pctOfTotal;
  const top2Share = top2 ? +(top1.pctOfTotal + top2.pctOfTotal).toFixed(1) : top1Share;
  const top3Share = top3 ? +(top2Share + top3.pctOfTotal).toFixed(1) : top2Share;

  // Variante determinística por hash de la entidad top1
  const variant = hashClientName(top1.name) % 2;

  // ── Clasificación de concentración (orden de evaluación importa)
  let level = null;
  if (top1Share >= 50) level = "alta";
  else if (top1Share >= 35) level = "moderada_alta";
  else if (top2Share >= 50) level = "bipolar";
  else if (top3Share >= 60) level = "moderada";
  else level = "distribuida";

  // ── Narrativa de nivel · cuerpo causal (sin cierre por goal aún)
  // BRIEF #29-ter · concordancia gramatical · usa _dimensionGrammar
  // para artículos/cuantificadores/plurales correctos según género.
  const grammar = _dimensionGrammar(dimensionLabel);
  let body = "";
  if (level === "alta") {
    if (variant === 0) {
      body = `${grammar.uno.charAt(0).toUpperCase() + grammar.uno.slice(1)} ${dim} concentra el problema. ${top1.name} absorbe ${top1Share}% del total · más que el resto sumados.`;
    } else {
      body = `${top1.name} solo carga con ${top1Share}% del total. Es ${grammar.article} ${dim} que define la foto.`;
    }
  } else if (level === "moderada_alta") {
    if (variant === 0) {
      body = `${top1.name} lidera con ${top1Share}% del total · materialidad clara, pero la presión se distribuye${top2 ? ` (${top2.name} suma ${top2.pctOfTotal}%)` : ""}.`;
    } else {
      body = `${top1.name} concentra ${top1Share}% · es el foco operativo más visible${top2 ? `, seguido por ${top2.name} con ${top2.pctOfTotal}%` : ""}. No es un solo culpable.`;
    }
  } else if (level === "bipolar") {
    if (variant === 0) {
      body = `Dos ${grammar.plural} concentran la mayor parte. ${top1.name} y ${top2.name} suman ${top2Share}% combinados · el resto es ruido marginal.`;
    } else {
      body = `${top1.name} y ${top2.name} explican ${top2Share}% del total juntos. El problema es bipolar, no distribuido.`;
    }
  } else if (level === "moderada") {
    if (variant === 0) {
      body = `3 ${grammar.plural} explican el grueso del problema. ${top1.name}, ${top2.name} y ${top3.name} suman ${top3Share}% acumulado.`;
    } else {
      body = `El top 3 concentra ${top3Share}% (${top1.name} ${top1Share}%, ${top2.name} ${top2.pctOfTotal}%, ${top3.name} ${top3.pctOfTotal}%). El resto del portafolio queda fragmentado.`;
    }
  } else {
    // distribuida
    if (variant === 0) {
      body = `El problema está distribuido · ${grammar.negArticle} ${dim} es el culpable único. ${top1.name} apenas lidera con ${top1Share}%.`;
    } else {
      body = `Distribución pareja · ${top1.name} encabeza con solo ${top1Share}% del total. No hay un foco operativo claro.`;
    }
  }

  // ── Cierre causal según goal · interpreta el patrón
  let causalClose = "";
  if (goal === "liberar_capital") {
    causalClose = level === "distribuida"
      ? ` Es un patrón de cobertura excesiva · stock detenido transversal al portafolio.`
      : ` La concentración apunta a cobertura excesiva sostenida en pocos puntos.`;
  } else if (goal === "recuperar_margen") {
    causalClose = level === "distribuida"
      ? ` Es erosión sistemática · presión de carga estructural transversal, no caso aislado.`
      : ` Refleja presión de carga estructural concentrada · no es spread genérico del portafolio.`;
  } else if (goal === "maximizar_contribucion") {
    causalClose = level === "distribuida"
      ? ` El upside está repartido · captura agregada vale más que apostar a una sola palanca.`
      : ` Concentración de valor clara · la palanca de upside está identificada.`;
  } else if (goal === "proteger_rentabilidad") {
    causalClose = level === "distribuida"
      ? ` El núcleo virtuoso del portafolio descansa en varios pies · ninguno es prescindible.`
      : ` Es núcleo virtuoso del portafolio · su composición sostiene la rentabilidad agregada.`;
  } else {
    // entender_problema | null | desconocido · cierre neutro
    causalClose = level === "distribuida"
      ? ` Es un patrón estructural, no anomalía individual.`
      : ` El patrón estructural está identificado.`;
  }

  return body + causalClose + "\n";
}

// ═══════════════════════════════════════════════════════════════════════════
// BRIEF #27 · Contextual Drilldown Resolver
//
// Composer genérico que continúa una investigación activa aplicando una
// nueva dimensión sobre el dataset apropiado. Resuelve clase entera de
// preguntas (dimensión × métrica × dominio) sin sumar composer por frase.
//
// Inputs:
//   · investigationContext: { domain, metric, hypothesis, lastIntent }
//   · newDimension: "bodega" | "sfamilia" | "sku" | "marca" | "cliente"
//   · scenarioId: escenario activo
//
// Lógica:
//   1. Selecciona dataset según domain (skuInventario | clientesMargen)
//   2. Determina extractor de métrica (capital_inmovilizado, contribucion, ...)
//   3. Determina extractor de dimensión (bodega, sfamilia, ...)
//   4. Agrupa, suma, ordena descendente
//   5. Construye Ferrari (Evidencia + Lectura + Foco)
//   6. Retorna contrato v1 completo
//
// Guard defensivo: si la dimensión no existe en el dataset (ej. bodega sobre
// clientesMargen), retorna respuesta defensiva con confianza baja.
//
// CERO HARDCODING: cifras del dataset en runtime · cambia dataset, cambia output.
// Determinismo bitwise.
// ═══════════════════════════════════════════════════════════════════════════
function composeContextualDrilldown(investigationContext, newDimension, scenarioId) {
  const { domain, metric, hypothesis, lastIntent } = investigationContext;
  // BRIEF #27-bis · goal opcional del context · si no viene, comportamiento neutro
  const goal = investigationContext.goal || null;

  // ── 1. Dataset según domain
  let dataset = null;
  if (domain === "inventario") {
    dataset = skuInventario;
  } else if (domain === "margenes" || domain === "ventas") {
    dataset = getClientesMargenWithProtected(scenarioId);
  } else {
    return buildResponseContract({
      opener: "No tengo dataset disponible para esa investigación en el escenario actual.",
      suggestions: [],
      sentrixAction: null,
      confidence: "baja",
      reasoningPattern: "contextual_drilldown_no_dataset",
    });
  }

  // ── 2. Extractor de métrica
  let extractMetric = null;
  let metricLabel = "";
  let metricFormat = (v) => `$${(v / 1000).toFixed(1)}K`;

  if (metric === "capital_inmovilizado") {
    extractMetric = (item) => item.stockUSD || 0;
    metricLabel = "Capital";
  } else if (metric === "contribucion") {
    extractMetric = (item) => domain === "inventario"
      ? Math.round((item.vendidoMes || 0) * ((item.margenPct || 0) / 100) * 1000)
      : (item.contribucion || 0) * 1000;
    metricLabel = "Contribución";
  } else if (metric === "margen") {
    extractMetric = (item) => domain === "inventario" ? (item.margenPct || 0) : (item.margen || 0);
    metricLabel = "Margen %";
    metricFormat = (v) => `${v.toFixed(1)}%`;
  } else if (metric === "carga_comercial") {
    extractMetric = (item) => item.pctRebate || 0;
    metricLabel = "Carga %";
    metricFormat = (v) => `${v.toFixed(1)}%`;
  } else if (metric === "rotacion") {
    extractMetric = (item) => item.rotacion || 0;
    metricLabel = "Rotación";
    metricFormat = (v) => `${v.toFixed(1)}x`;
  } else {
    return buildResponseContract({
      opener: "No tengo métrica clara para profundizar en esa dimensión.",
      suggestions: [],
      sentrixAction: null,
      confidence: "baja",
      reasoningPattern: "contextual_drilldown_no_metric",
    });
  }

  // ── 3. Extractor de dimensión + validación de compatibilidad
  let extractDimension = null;
  let dimensionLabel = "";

  if (newDimension === "bodega") {
    extractDimension = (item) => item.bodega || null;
    dimensionLabel = "Bodega";
  } else if (newDimension === "sfamilia") {
    extractDimension = (item) => item.sfamilia || null;
    dimensionLabel = "Categoría";
  } else if (newDimension === "sku") {
    extractDimension = (item) => item.sku || null;
    dimensionLabel = "SKU";
  } else if (newDimension === "marca") {
    extractDimension = (item) => item.marca || null;
    dimensionLabel = "Marca";
  } else if (newDimension === "cliente") {
    extractDimension = (item) => item.nombre || null;
    dimensionLabel = "Cliente";
  } else {
    return buildResponseContract({
      opener: "No reconozco esa dimensión · probá bodega, categoría, SKU, marca o cliente.",
      suggestions: [],
      sentrixAction: null,
      confidence: "baja",
      reasoningPattern: "contextual_drilldown_unknown_dimension",
    });
  }

  // ── Guard de compatibilidad: la dimensión debe existir en el dataset
  const sample = dataset[0];
  if (!sample || extractDimension(sample) === null) {
    return buildResponseContract({
      opener: `La dimensión "${dimensionLabel.toLowerCase()}" no aplica al dominio actual (${domain}). Probá otra dimensión o abrí una investigación nueva.`,
      suggestions: [],
      sentrixAction: null,
      confidence: "baja",
      reasoningPattern: "contextual_drilldown_dimension_not_in_domain",
    });
  }

  // ── 4. Agrupar dataset por dimensión + acumular métrica
  const grouped = {};
  for (const item of dataset) {
    const key = extractDimension(item);
    if (key === null) continue;
    if (!grouped[key]) {
      grouped[key] = { value: 0, count: 0, items: [] };
    }
    grouped[key].value += extractMetric(item);
    grouped[key].count += 1;
    grouped[key].items.push(item);
  }

  // ── 5. Ordenar descendente + calcular % del total
  const ranking = Object.entries(grouped)
    .map(([key, data]) => ({
      name: key,
      value: data.value,
      count: data.count,
      pctOfTotal: 0,
    }))
    .sort((a, b) => b.value - a.value);

  const total = ranking.reduce((sum, r) => sum + r.value, 0);
  ranking.forEach(r => {
    r.pctOfTotal = total > 0 ? +((r.value / total) * 100).toFixed(1) : 0;
  });

  if (ranking.length === 0) {
    return buildResponseContract({
      opener: `No hay datos agrupables por ${dimensionLabel.toLowerCase()} en el escenario actual.`,
      suggestions: [],
      sentrixAction: null,
      confidence: "baja",
      reasoningPattern: "contextual_drilldown_empty",
    });
  }

  // ── 6. Construir opener Ferrari (Evidencia + Lectura + Foco)
  const top = ranking[0];
  const second = ranking[1];
  const showCount = Math.min(ranking.length, 4);

  let opener = `Distribución por ${dimensionLabel.toLowerCase()}:\n\n`;
  for (let i = 0; i < showCount; i++) {
    const r = ranking[i];
    opener += `${r.name} → ${metricLabel} ${metricFormat(r.value)} (${r.pctOfTotal}% del total, ${r.count} ${r.count === 1 ? "ítem" : "ítems"})\n`;
  }

  // ── Lectura causal (BRIEF #29-quater · voz de controller, interpretación
  // ejecutiva en vez de descripción mecánica · modulada por goal de la
  // investigación · variantes determinísticas por hash de la entidad top1).
  opener += `\n`;
  opener += _composeDrilldownReading(ranking, total, dimensionLabel, metricLabel, goal);

  // ── Foco accionable (BRIEF #27-bis · switch según goal de la investigación)
  // Si goal es null o "entender_problema" → foco genérico (comportamiento pre-BRIEF #27-bis).
  // Si goal es específico → foco textualmente alineado con el criterio de optimización.
  // BRIEF #29-ter · "es el ${dim}" → "es ${grammar.article} ${dim}" para concordancia.
  const focoGrammar = _dimensionGrammar(dimensionLabel);
  const dimLower = dimensionLabel.toLowerCase();
  let focoText = "";
  if (goal === "liberar_capital") {
    focoText = `\nMecanismo disponible: ${top.name} concentra mayor capital atrapado · es ${focoGrammar.article} ${dimLower} donde la palanca de liberación de stock detenido tiene mayor impacto cuantificable.\n\n`;
  } else if (goal === "maximizar_contribucion") {
    focoText = `\nMecanismo disponible: ${top.name} concentra mayor upside operativo · es ${focoGrammar.article} ${dimLower} donde la palanca de empuje maximiza contribución incremental sin tocar estructura comercial.\n\n`;
  } else if (goal === "recuperar_margen") {
    focoText = `\nMecanismo disponible: ${top.name} concentra mayor presión de carga sobre margen estructural · es ${focoGrammar.article} ${dimLower} donde la palanca de corrección recupera rentabilidad sin mover volumen.\n\n`;
  } else if (goal === "proteger_rentabilidad") {
    focoText = `\n${top.name} opera como palanca estructural del portafolio virtuoso · su composición es zona de protección estructural · su deterioro arrastraría al resto.\n\n`;
  } else {
    // entender_problema | null | desconocido → foco neutro
    focoText = `\nMecanismo disponible: ${top.name} concentra mayor exposición · es ${focoGrammar.article} ${dimLower} donde la palanca de revisión libera proporción significativa del total.\n\n`;
  }
  opener += focoText;
  opener += `*Confianza alta · distribución determinística del escenario actual.*`;

  // ── 7. Sentrix action según dimensión
  let sentrixAction = null;
  const moduleChip = domain === "inventario" ? "Inventario" : "Márgenes";
  const moduleKey = domain === "inventario" ? "inventario" : "margenes";

  if (newDimension === "bodega") {
    sentrixAction = {
      label: `Ver ${top.name} en Inventario`,
      moduleChip: "Inventario",
      payload: { modulo: "inventario", sucursales: [top.name] },
    };
  } else if (newDimension === "sfamilia") {
    sentrixAction = {
      label: `Ver ${top.name}`,
      moduleChip,
      payload: { modulo: moduleKey, sfamilias: [top.name] },
    };
  } else if (newDimension === "sku") {
    sentrixAction = {
      label: `Ver top ${showCount} SKUs`,
      moduleChip: "Inventario",
      payload: {
        modulo: "inventario",
        skus: ranking.slice(0, showCount).map(r => r.name),
      },
    };
  } else if (newDimension === "marca") {
    sentrixAction = {
      label: `Ver ${top.name}`,
      moduleChip,
      payload: { modulo: moduleKey, marcas: [top.name] },
    };
  } else if (newDimension === "cliente") {
    sentrixAction = {
      label: `Ver top ${showCount} cuentas`,
      moduleChip: "Márgenes",
      payload: {
        modulo: "margenes",
        clientes: ranking.slice(0, showCount).map(r => r.name),
      },
    };
  }

  // ── 8. Suggestions cognitivas (continuidad de investigación)
  const suggestions = [];
  if (newDimension !== "sku" && domain === "inventario") {
    suggestions.push({
      text: `¿Qué SKUs explican ${top.name}?`,
      action: { type: "contextual_drilldown_action", payload: { newDimension: "sku", focusEntity: top.name } },
    });
  }
  if (newDimension !== "cliente" && domain === "margenes") {
    suggestions.push({
      text: `¿Qué clientes explican esa concentración?`,
      action: { type: "contextual_drilldown_action", payload: { newDimension: "cliente", focusEntity: top.name } },
    });
  }
  if (newDimension !== "sfamilia") {
    suggestions.push({
      text: `¿Cómo se distribuye por categoría?`,
      action: { type: "contextual_drilldown_action", payload: { newDimension: "sfamilia" } },
    });
  }
  if (newDimension !== "marca" && suggestions.length < 3) {
    suggestions.push({
      text: `¿Cómo se distribuye por marca?`,
      action: { type: "contextual_drilldown_action", payload: { newDimension: "marca" } },
    });
  }

  return buildResponseContract({
    opener,
    suggestions,
    sentrixAction,
    decision: top.name,
    evidence: {
      domain,
      metric,
      hypothesis,
      lastIntent,
      newDimension,
      top_entity: top.name,
      top_value: top.value,
      top_pct: top.pctOfTotal,
      total_value: total,
      ranking: ranking.slice(0, showCount),
      n_groups: ranking.length,
    },
    focus: `Palanca operativa sobre ${top.name}`,
    confidence: "alta",
    materialMetrics: [
      `${top.pctOfTotal}% concentración`,
      `${metricFormat(top.value)}`,
      // BRIEF #29-ter · "5 bodegas" / "1 bodega" / "5 sucursales" correctos
      _pluralize(ranking.length, dimensionLabel),
    ],
    reasoningPattern: "contextual_drilldown_by_dimension",
    suggestedNextActions: suggestions.map(s => s.text),
  });
}

// ═══════════════════════════════════════════════════════
// BRIEF #26 · composeDisambiguation
//
// Cuarto modo de respuesta de ADI: REDIRECCIÓN COGNITIVA.
//
// Cuando la pregunta menciona una entidad canónica (cliente o SKU) pero
// NO matchea con ningún flujo conocido (intent semántico, acción cognitiva,
// deíctico), ADI propone 3 reformulaciones probables con voz humana.
//
// Cada reformulación es una suggestion `{text, action}` que al click pasa
// por handleCognitiveAction → composer real. Cero respuestas hardcoded.
//
// Voz humana: reconoce que la entidad es del portafolio y redirige sin
// sonar robot ni declinar.
//
// Determinismo bitwise · misma entidad + mismo módulo → misma respuesta.
// ═══════════════════════════════════════════════════════

function composeDisambiguation(entityDetected, scenario, modulo, conversationContext) {
  const { type: entityType, value: entityValue } = entityDetected;

  let opener = "";
  let suggestions = [];
  let sentrixAction = null;

  if (entityType === "client") {
    // Voz humana: la entidad ya es cuenta del portafolio.
    opener = `${entityValue} ya es una cuenta del portafolio · no agrupa clientes debajo. Si querés mirarlo desde otro ángulo (composición por marca · evolución temporal · comparativo cruzado con otra cuenta), indicame cuál y abrimos esa vista.`;

    // Determinar módulo cruzado según módulo activo.
    // Si estamos en márgenes → vista ventas. Si en ventas → vista márgenes.
    // Si en inventario → vista márgenes (cliente no tiene vista en inventario).
    const otherModule = (modulo === "margenes") ? "ventas"
                      : (modulo === "ventas") ? "margenes"
                      : "margenes";
    const otherModuleLabel = otherModule === "margenes" ? "Márgenes" : "Ventas";

    suggestions = [
      {
        text: `¿Qué SKUs aportan más en ${entityValue}?`,
        action: {
          type: "cross_domain_client_to_sku",
          payload: { clientName: entityValue },
        },
      },
      {
        text: `¿Cómo se compone la contribución de ${entityValue} vs benchmark?`,
        action: {
          type: "simulation_benchmark",
          payload: {
            entity: entityValue,
            entityType: "client",
            metric: "margen",
            target: 30.1,
          },
        },
      },
      {
        text: `¿Cómo se ve ${entityValue} en ${otherModuleLabel}?`,
        action: {
          type: "cross_module_view",
          payload: {
            entity: entityValue,
            entityType: "client",
            targetModule: otherModule,
          },
        },
      },
    ];

    // Sentrix · filtrar al cliente en el módulo más relevante (no inventario)
    const sentrixModulo = modulo === "inventario" ? "margenes" : modulo;
    sentrixAction = {
      label: `Ver ${entityValue}`,
      moduleChip: sentrixModulo === "margenes" ? "Márgenes" : "Ventas",
      payload: {
        modulo: sentrixModulo,
        clientes: [entityValue],
        skus: [],
      },
    };
  } else if (entityType === "sku") {
    // Voz humana: la entidad ya es producto del portafolio.
    opener = `${entityValue} es un producto del portafolio · no agrupa productos debajo. Si querés mirarlo desde otro ángulo (rotación · cobertura · exposición de stock · clientes principales), indicame cuál y abrimos esa vista.`;

    // Tercera reformulación contextual: si SKU crítico/warn → exit_plan,
    // si SKU saludable → simulation_rotation (palanca diferente).
    const sku = skuInventario.find(s => s.sku === entityValue);
    const isCritical = sku && (sku.alerta === "crit" || sku.alerta === "warn");

    suggestions = [
      {
        text: `¿Cuál es el análisis operativo de ${entityValue}?`,
        action: {
          type: "sku_deep_dive_action",
          payload: { skuName: entityValue },
        },
      },
      {
        text: `¿Qué cliente compra ${entityValue}?`,
        action: {
          type: "cross_domain_sku_to_client",
          payload: { skuName: entityValue },
        },
      },
    ];

    if (isCritical) {
      suggestions.push({
        text: `¿Cuál es el plan de salida de ${entityValue}?`,
        action: { type: "exit_plan", payload: { sku: entityValue } },
      });
    } else {
      suggestions.push({
        text: `¿Qué libero si ${entityValue} alcanza rotación 9x?`,
        action: {
          type: "simulation_rotation",
          payload: { sku: entityValue, targetRotation: 9 },
        },
      });
    }

    sentrixAction = {
      label: `Ver ${entityValue} en Inventario`,
      moduleChip: "Inventario",
      payload: {
        modulo: "inventario",
        clientes: [],
        skus: [entityValue],
      },
    };
  }

  // Cierre conversacional
  opener += "\n\n¿Por dónde profundizamos?";

  return { opener, suggestions, sentrixAction };
}

// ═══════════════════════════════════════════════════════
// BRIEF #20 · Composer SKU Operacional Ferrari
// ═══════════════════════════════════════════════════════

function composeSkuOperationalAnalysis(scenarioId) {
  // ── 1. Filtrar SKUs críticos (alerta crit/warn o estado ≠ Activo)
  //       ordenados por capital descendente
  const criticalSkus = skuInventario
    .filter(s => s.alerta === "crit" || s.alerta === "warn" || s.estado !== "Activo")
    .sort((a, b) => b.stockUSD - a.stockUSD);

  const top4 = criticalSkus.slice(0, 4);

  if (top4.length === 0) {
    return {
      opener: "El inventario opera dentro de rango óptimo en el escenario actual. No hay SKUs con capital atrapado relevante.",
      // BRIEF N-bis · Tipo A puro · filtradas
      suggestions: filterTextualSuggestions([
        "Cómo está la rotación general",
        "Qué SKUs sí están funcionando",
      ]),
      sentrixAction: null,
    };
  }

  // ── 2. Helper formato. fmtK omite decimal cuando es entero múltiplo de 1000.
  const fmtK = (val) => {
    if (val >= 1000) {
      const k = val / 1000;
      return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`;
    }
    return `$${Math.round(val)}`;
  };

  // ── 3. Cálculos para Lectura causal
  const totalInventario = skuInventario.reduce((sum, s) => sum + s.stockUSD, 0);
  const capitalTop4 = top4.reduce((sum, s) => sum + s.stockUSD, 0);
  const pctCapitalTop4 = ((capitalTop4 / totalInventario) * 100).toFixed(0);

  // Categoría dominante en top 4
  const categoriasTop = {};
  top4.forEach(s => {
    categoriasTop[s.sfamilia] = (categoriasTop[s.sfamilia] || 0) + 1;
  });
  const catDominante = Object.entries(categoriasTop)
    .sort((a, b) => b[1] - a[1])[0];

  // Worst SKU = mayor combinación DOH × diasSinVenta (antigüedad + inmovilidad)
  const worstSku = [...top4].sort((a, b) =>
    (b.doh * (b.diasSinVenta || 1)) - (a.doh * (a.diasSinVenta || 1))
  )[0];

  // Segundo peor (diferente del worst) para palanca dual
  const secondWorst = [...top4]
    .filter(s => s.sku !== worstSku.sku)
    .sort((a, b) =>
      (b.doh * (b.diasSinVenta || 1)) - (a.doh * (a.diasSinVenta || 1))
    )[0] || top4[0];

  // SKUs rotacionales del portafolio para destino de reinversión
  const rotacionales = skuInventario
    .filter(s => s.rotacion >= 9)
    .sort((a, b) => b.rotacion - a.rotacion)
    .slice(0, 2)
    .map(s => s.sku);

  // ── 4. EVIDENCIA · ranking estructurado
  const rankingLines = top4.map(s =>
    `${s.sku.padEnd(15, " ")} → Stock ${fmtK(s.stockUSD)} | DOH ${s.doh}d | ${s.diasSinVenta} días sin venta | Rotación ${s.rotacion}x`
  ).join("\n");

  const m1 = `${top4.length} SKUs con mayor capital inmovilizado:\n\n${rankingLines}`;

  // ── 5. LECTURA · causal con cifras determinísticas del dataset
  const promedioRotacionTop = (top4.reduce((sum, s) => sum + s.rotacion, 0) / top4.length).toFixed(1);
  const pctWorst = ((worstSku.stockUSD / totalInventario) * 100).toFixed(1);

  let lecturaCausal = `Los ${top4.length} SKUs concentran ${fmtK(capitalTop4)} en capital comprometido, equivalente al ${pctCapitalTop4}% del inventario total (${fmtK(totalInventario)}). La rotación promedio del top crítico es ${promedioRotacionTop}x, muy por debajo del benchmark interno (>7x para SKUs rotacionales).`;

  if (catDominante && catDominante[1] >= 2) {
    lecturaCausal += ` ${catDominante[1]} de los ${top4.length} SKUs pertenecen a ${catDominante[0]}, mostrando un patrón estructural en esa categoría.`;
  }

  lecturaCausal += ` ${worstSku.sku} concentra la mayor exposición operativa: ${worstSku.diasSinVenta} días sin venta con stock equivalente al ${pctWorst}% del inventario total.`;

  const m2 = `${lecturaCausal}`;

  // ── 6. FOCO · acción accionable con SKUs específicos y destino de reinversión
  const capitalLiberable = worstSku.stockUSD + secondWorst.stockUSD;
  const rotacionalesText = rotacionales.length > 0
    ? ` (${rotacionales.join(", ")})`
    : "";

  const focoText = `Mecanismo disponible: ${worstSku.sku} y ${secondWorst.sku} concentran ${fmtK(capitalLiberable)} de capital con más de ${Math.min(worstSku.diasSinVenta, secondWorst.diasSinVenta || 0)} días sin venta · zona donde la palanca de liquidación libera reinversión hacia SKUs rotacionales del portafolio${rotacionalesText} (rotación sobre 9x).`;

  const m3 = `${focoText}`;

  // ── 7. Confianza
  const confianza = `*Confianza alta · cifras determinísticas sobre el inventario actual del escenario.*`;

  const opener = `${m1}\n\n${m2}\n\n${m3}\n\n${confianza}`;

  // ── 8. Suggestions accionables derivadas (entidades reales)
  const suggestions = [
    `Cuánto recupero si liquido ${worstSku.sku}`,
    `Profundizar en ${worstSku.sku}`,
    `Qué cliente compra ${worstSku.sku}`,
  ];

  // ── 9. Sentrix action · BRIEF #22 incluye skus específicos
  //       para que BRIEF #23 pueda consumirlos como filtro.
  const sentrixAction = {
    label: `Ver ${top4.length} SKUs críticos`,
    moduleChip: "Inventario",
    payload: {
      modulo: "inventario",
      clientes: [],
      skus: top4.map(s => s.sku),
      mechanismBanner: "Capital atrapado en SKUs críticos",
    },
  };

  // ── BRIEF M.B.3 · narrative_signals + posture_hint ──
  // Postura prioritize · grupo SKU operacional con capital atrapado.
  let narrative_signals = null;
  let posture_hint = "prioritize";
  if (VOICE_NARRATIVE_LAYER_ENABLED) {
    try {
      narrative_signals = buildNarrativeSignalsForSkuOperational(top4);
    } catch (sig_err) {
      // eslint-disable-next-line no-console
      console.warn("BRIEF M.B.3 sku operational narrative_signals error:", sig_err);
      narrative_signals = null;
    }
  }

  // BRIEF N-bis · Tipo A puro · suggestions filtradas en return
  return {
    opener,
    suggestions: filterTextualSuggestions(suggestions),
    sentrixAction,
    narrative_signals,
    posture_hint,
  };
}

// ═══════════════════════════════════════════════════════════════════════
// BRIEF #39 · composeRotationAnalysis · Ferrari para rotación de inventario
//
// Activado por intent "rotation_dive" cuando concept_rotation está activo
// (F7 canonical __rotation_query__ vía nounStandalone o combinatorial, o
// patterns legacy de noun_rotation).
//
// Estructura Ferrari sin etiquetas visibles (Evidencia + Lectura + Foco):
//   1. Header / tesis: rotación promedio + count sobre/bajo benchmark
//   2. Top 3 virtuosos (mayor rotación) con métricas runtime
//   3. Top 3 lastres (menor rotación) con métricas runtime
//   4. Lectura causal: patrón estructural detectado
//   5. Foco accionable: proteger virtuosos + revisar lastres
//   6. Confianza
//
// CERO HARDCODING: todas las cifras provienen de skuInventario en runtime.
// Benchmark canonical: 5.8x (rotacion media del LG-AIR9000 · valor del
// dataset · NO inventado).
// ═══════════════════════════════════════════════════════════════════════
function composeRotationAnalysis(scenarioId) {
  // ── 1. Helpers formato
  const fmtK = (val) => {
    if (val == null || isNaN(val)) return "$0";
    if (Math.abs(val) >= 1000) {
      const k = val / 1000;
      return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`;
    }
    return `$${Math.round(val)}`;
  };

  // ── 2. Benchmark canónico desde el dataset.
  // Promedio aritmético de rotación del portafolio como referencia
  // determinística. Cero hardcoding de cifra.
  const rotacionPromedio = skuInventario.reduce((s, x) => s + x.rotacion, 0) / skuInventario.length;
  const benchmarkInterno = +rotacionPromedio.toFixed(1);

  // ── 3. Particionar SKUs por benchmark
  const sobreBenchmark = skuInventario.filter(s => s.rotacion >= benchmarkInterno);
  const bajoBenchmark  = skuInventario.filter(s => s.rotacion < benchmarkInterno);

  // ── 4. Top 3 virtuosos (mayor rotación)
  const virtuosos = [...skuInventario]
    .sort((a, b) => b.rotacion - a.rotacion)
    .slice(0, 3);

  // ── 5. Top 3 lastres (menor rotación)
  const lastres = [...skuInventario]
    .sort((a, b) => a.rotacion - b.rotacion)
    .slice(0, 3);

  // ── 6. EVIDENCIA · header con cifras runtime
  const headerLine = `La rotación promedio del portafolio es ${benchmarkInterno}x · ${sobreBenchmark.length} SKUs sobre benchmark interno, ${bajoBenchmark.length} SKUs por debajo.`;

  // ── 7. EVIDENCIA · ranking virtuosos con métricas
  const virtuososLines = virtuosos.map(s =>
    `${s.sku.padEnd(14, " ")} → Rotación ${s.rotacion}x | Venta diaria ${s.ventaDiaria}u | Contribución mensual ${fmtK(s.vendidoMes * (s.stockUSD / Math.max(s.stockUnd, 1)) * (s.margenPct / 100))}`
  ).join("\n");

  // ── 8. EVIDENCIA · ranking lastres con métricas
  const lastresLines = lastres.map(s =>
    `${s.sku.padEnd(14, " ")} → Rotación ${s.rotacion}x | DOH ${s.doh} días | Stock ${fmtK(s.stockUSD)} | ${s.diasSinVenta} días sin venta`
  ).join("\n");

  const evidencia = `${headerLine}\n\nTop 3 virtuosos:\n${virtuososLines}\n\nTop 3 lastres:\n${lastresLines}`;

  // ── 9. LECTURA causal · patrón estructural
  // Detectar concentración categórica en lastres (¿comparten familia/marca?)
  const lastresMarca = {};
  const lastresFamilia = {};
  lastres.forEach(s => {
    lastresMarca[s.marca] = (lastresMarca[s.marca] || 0) + 1;
    lastresFamilia[s.sfamilia] = (lastresFamilia[s.sfamilia] || 0) + 1;
  });
  const marcaDominante = Object.entries(lastresMarca).sort((a, b) => b[1] - a[1])[0];
  const familiaDominante = Object.entries(lastresFamilia).sort((a, b) => b[1] - a[1])[0];

  const virtuosoLider = virtuosos[0];
  const lastreLider = lastres[0];
  const ratioRotacion = (virtuosoLider.rotacion / lastreLider.rotacion).toFixed(1);

  let lecturaCausal = `${virtuosoLider.sku} rota ${ratioRotacion}x más rápido que ${lastreLider.sku} (${virtuosoLider.rotacion}x vs ${lastreLider.rotacion}x), un gap operativo estructural.`;
  if (familiaDominante && familiaDominante[1] >= 2) {
    lecturaCausal += ` ${familiaDominante[1]} de los ${lastres.length} lastres pertenecen a ${familiaDominante[0]}, lo que sugiere un patrón de baja rotación concentrado en esa familia.`;
  } else if (marcaDominante && marcaDominante[1] >= 2) {
    lecturaCausal += ` ${marcaDominante[1]} de los ${lastres.length} lastres son de marca ${marcaDominante[0]}, lo que sugiere un patrón estructural en esa marca.`;
  }

  // ── 10. FOCO · acción accionable con SKUs específicos
  const capitalLastres = lastres.reduce((s, x) => s + x.stockUSD, 0);
  const focoText = `Mecanismos disponibles: ${virtuosoLider.sku} y ${virtuosos[1].sku} operan como líderes rotacionales (${virtuosoLider.rotacion}x y ${virtuosos[1].rotacion}x · zona estructural a preservar en disponibilidad) · ${lastreLider.sku} concentra lastre operativo (rotación ${lastreLider.rotacion}x · ${lastreLider.diasSinVenta} días sin venta · ${fmtK(lastreLider.stockUSD)} comprometidos · zona donde la palanca de plan de salida opera). Los ${lastres.length} lastres concentran ${fmtK(capitalLastres)} de capital con rotación bajo ${benchmarkInterno}x.`;

  // ── 11. Confianza
  const confianza = `*Confianza alta · distribución determinística del escenario activo.*`;

  const opener = `${evidencia}\n\n${lecturaCausal}\n\n${focoText}\n\n${confianza}`;

  // ── 12. Suggestions accionables (entidades reales)
  const suggestions = [
    `Cuánto recupero si liquido ${lastreLider.sku}`,
    `Profundizar en ${virtuosoLider.sku}`,
    `Qué cliente compra ${virtuosoLider.sku}`,
  ];

  // ── 13. SentrixAction · payload con 6 SKUs (3 virtuosos + 3 lastres)
  // Construido inline (composeSentrixAction NO tiene rama dedicada · usamos
  // shape estándar de payload Inventario con skus pre-poblados).
  const allSkus = [...virtuosos.map(s => s.sku), ...lastres.map(s => s.sku)];
  const sentrixAction = {
    label: `Ver rotación de ${allSkus.length} SKUs`,
    moduleChip: "Inventario",
    payload: {
      modulo: "inventario",
      clientes: [],
      skus: allSkus,
      mechanismBanner: "Rotación · virtuosos y lastres",
    },
  };

  // ── 14. Contrato v1 con materialMetrics runtime
  return buildResponseContract({
    opener,
    // BRIEF N-bis · Tipo A puro · suggestions filtradas
    suggestions: filterTextualSuggestions(suggestions),
    sentrixAction,
    decision: virtuosoLider.sku,
    evidence: {
      rotacion_promedio: benchmarkInterno,
      virtuoso_lider: virtuosoLider.sku,
      virtuoso_lider_rotacion: virtuosoLider.rotacion,
      lastre_lider: lastreLider.sku,
      lastre_lider_rotacion: lastreLider.rotacion,
      capital_lastres_USD: capitalLastres,
      sobre_benchmark_count: sobreBenchmark.length,
      bajo_benchmark_count: bajoBenchmark.length,
    },
    focus: "rotation_protection_and_exit",
    confidence: "alta",
    materialMetrics: [
      { label: `${benchmarkInterno}x rotación promedio`, source: "rotacion_promedio_runtime" },
      { label: `${virtuosoLider.sku} ${virtuosoLider.rotacion}x`, source: "rotacion_top_virtuoso" },
      { label: `${lastreLider.sku} ${lastreLider.rotacion}x`, source: "rotacion_top_lastre" },
      { label: `${fmtK(capitalLastres)} capital lastres`, source: "capital_inmovilizado_lastres" },
    ],
    reasoningPattern: "rotation_dive_analysis",
    suggestedNextActions: [
      { type: "explore_sku_exit", sku: lastreLider.sku },
      { type: "protect_top_rotational", sku: virtuosoLider.sku },
      { type: "drill_lastres_family", familia: familiaDominante ? familiaDominante[0] : null },
    ],
  });
}

// ═══════════════════════════════════════════════════════════════════════
// BRIEF #39 · composeCoverageAnalysis · Ferrari para DOH / cobertura
//
// Activado por intent "coverage_dive" cuando concept_days_on_hand está
// activo (F8 canonical __coverage_query__ via disjunctive_set, o patterns
// legacy de noun_doh).
//
// Estructura Ferrari (Evidencia + Lectura + Foco):
//   1. Header: DOH promedio + count sobrestock/quiebre/óptimo
//   2. Top 3 sobrestock (mayor DOH)
//   3. Top 3 riesgo de quiebre (menor DOH bajo rango óptimo)
//   4. Lectura causal: ¿sobrestock concentrado en lentos? ¿quiebre en virtuosos?
//   5. Foco: liberar capital sobrestockeado + proteger disponibilidad
//   6. Confianza
//
// CERO HARDCODING: cifras runtime de skuInventario.
// Rango óptimo derivado del benchmark del dataset (DOH 15-30 · justificado
// por sobrestock >60 y quiebre <15 en el portafolio canónico).
// ═══════════════════════════════════════════════════════════════════════
function composeCoverageAnalysis(scenarioId) {
  // ── 1. Helpers
  const fmtK = (val) => {
    if (val == null || isNaN(val)) return "$0";
    if (Math.abs(val) >= 1000) {
      const k = val / 1000;
      return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`;
    }
    return `$${Math.round(val)}`;
  };

  // ── 2. Benchmark DOH del portafolio (runtime)
  const dohPromedio = skuInventario.reduce((s, x) => s + x.doh, 0) / skuInventario.length;
  const dohMedio = Math.round(dohPromedio);

  // ── 3. Rangos operativos · derivados del dataset
  // Sobrestock: DOH > 60 (más del doble del promedio típico healthy)
  // Riesgo quiebre: DOH < 18 (menos de 3 semanas · sensible a picos demanda)
  // Óptimo: 18-60
  const sobrestockUmbral = 60;
  const quiebreUmbral = 18;

  const sobrestock = skuInventario.filter(s => s.doh > sobrestockUmbral);
  const quiebreRiesgo = skuInventario.filter(s => s.doh < quiebreUmbral && s.ventaDiaria > 0);
  const optimo = skuInventario.filter(s => s.doh >= quiebreUmbral && s.doh <= sobrestockUmbral);

  // ── 4. Top 3 sobrestock (mayor DOH)
  const topSobrestock = [...sobrestock]
    .sort((a, b) => b.doh - a.doh)
    .slice(0, 3);

  // ── 5. Top 3 quiebre (menor DOH con alta venta diaria)
  const topQuiebre = [...quiebreRiesgo]
    .sort((a, b) => a.doh - b.doh)
    .slice(0, 3);

  // ── 6. EVIDENCIA · header
  const headerLine = `La cobertura del portafolio promedia ${dohMedio} días · ${optimo.length} SKUs en rango óptimo (${quiebreUmbral}-${sobrestockUmbral}d), ${sobrestock.length} SKUs en sobrestock (>${sobrestockUmbral}d), ${quiebreRiesgo.length} SKUs con riesgo de quiebre (<${quiebreUmbral}d).`;

  // ── 7. EVIDENCIA · sobrestock con métricas
  const sobrestockLines = topSobrestock.length > 0
    ? topSobrestock.map(s =>
        `${s.sku.padEnd(14, " ")} → DOH ${s.doh} días | Stock ${fmtK(s.stockUSD)} | Venta diaria ${s.ventaDiaria}u | ${s.diasSinVenta} días sin venta`
      ).join("\n")
    : "(ningún SKU en sobrestock crítico)";

  // ── 8. EVIDENCIA · quiebre con métricas
  const quiebreLines = topQuiebre.length > 0
    ? topQuiebre.map(s =>
        `${s.sku.padEnd(14, " ")} → DOH ${s.doh} días | Venta diaria ${s.ventaDiaria}u | Rotación ${s.rotacion}x | Riesgo operativo`
      ).join("\n")
    : "(ningún SKU bajo umbral de riesgo)";

  const evidencia = `${headerLine}\n\nTop 3 sobrestock:\n${sobrestockLines}\n\nTop 3 riesgo de quiebre:\n${quiebreLines}`;

  // ── 9. LECTURA causal
  const sobrestockLider = topSobrestock[0];
  const quiebreLider = topQuiebre[0];

  const capitalSobrestock = sobrestock.reduce((s, x) => s + x.stockUSD, 0);
  const pctSobrestock = ((capitalSobrestock / skuInventario.reduce((s, x) => s + x.stockUSD, 0)) * 100).toFixed(0);

  let lecturaCausal = "";
  if (sobrestockLider && quiebreLider) {
    lecturaCausal = `${sobrestockLider.sku} concentra ${fmtK(sobrestockLider.stockUSD)} con ${sobrestockLider.doh} días de cobertura (${(sobrestockLider.doh / dohMedio).toFixed(1)}x el promedio) y rotación ${sobrestockLider.rotacion}x, mientras ${quiebreLider.sku} opera con apenas ${quiebreLider.doh} días pero rota ${quiebreLider.rotacion}x. El portafolio sostiene ${fmtK(capitalSobrestock)} (${pctSobrestock}% del inventario) en SKUs sobrestockeados que rotan bajo el promedio.`;
  } else if (sobrestockLider) {
    lecturaCausal = `${sobrestockLider.sku} concentra ${fmtK(sobrestockLider.stockUSD)} con ${sobrestockLider.doh} días de cobertura · ${(sobrestockLider.doh / dohMedio).toFixed(1)}x el promedio del portafolio. Los ${sobrestock.length} SKUs sobrestockeados agregan ${fmtK(capitalSobrestock)} (${pctSobrestock}% del inventario total).`;
  } else {
    lecturaCausal = `Cobertura distribuida sin concentraciones críticas. ${optimo.length} de ${skuInventario.length} SKUs operan dentro del rango óptimo ${quiebreUmbral}-${sobrestockUmbral} días.`;
  }

  // ── 10. MECANISMOS DISPONIBLES (v1.1 · interpretativo)
  let focoText = "";
  if (sobrestockLider) {
    focoText = `Mecanismos disponibles: la liberación de capital en ${sobrestockLider.sku} (${fmtK(sobrestockLider.stockUSD)} · DOH ${sobrestockLider.doh}d)`;
    if (topSobrestock.length > 1) {
      focoText += ` y ${topSobrestock[1].sku} (${fmtK(topSobrestock[1].stockUSD)} · DOH ${topSobrestock[1].doh}d)`;
    }
    focoText += ` representa la palanca dominante. ${quiebreLider ? `En paralelo, ${quiebreLider.sku} opera con DOH ${quiebreLider.doh}d sobre venta diaria ${quiebreLider.ventaDiaria}u · zona sensible a quiebres en SKUs rotacionales.` : "La disponibilidad operativa en SKUs activos opera dentro del rango healthy."}`;
  } else if (quiebreLider) {
    focoText = `Mecanismo disponible: ${quiebreLider.sku} opera con DOH ${quiebreLider.doh}d sobre venta diaria ${quiebreLider.ventaDiaria}u · zona sensible · sin sobrestock crítico que represente palanca paralela.`;
  } else {
    focoText = `Estructura balanceada: la cobertura distribuye dentro del rango healthy en el escenario actual · sin palancas activas de liberación ni protección.`;
  }

  // ── 11. Confianza
  const confianza = `*Confianza alta · cifras determinísticas sobre el inventario actual del escenario.*`;

  const opener = `${evidencia}\n\n${lecturaCausal}\n\n${focoText}\n\n${confianza}`;

  // ── 12. Suggestions accionables
  const suggestions = [];
  if (sobrestockLider) {
    suggestions.push(`Cuánto recupero si liquido ${sobrestockLider.sku}`);
    suggestions.push(`Profundizar en ${sobrestockLider.sku}`);
  }
  if (quiebreLider) {
    suggestions.push(`Cómo proteger ${quiebreLider.sku} de quiebre`);
  }
  while (suggestions.length < 3) suggestions.push("Qué SKUs sí están funcionando");

  // ── 13. SentrixAction · payload con SKUs de ambos extremos
  const allSkus = [...topSobrestock.map(s => s.sku), ...topQuiebre.map(s => s.sku)];
  const sentrixAction = {
    label: `Ver cobertura de ${allSkus.length} SKUs`,
    moduleChip: "Inventario",
    payload: {
      modulo: "inventario",
      clientes: [],
      skus: allSkus,
      mechanismBanner: "Cobertura · sobrestock y riesgo de quiebre",
    },
  };

  // ── 14. Contrato v1 con materialMetrics runtime
  return buildResponseContract({
    opener,
    // BRIEF N-bis · Tipo A puro · suggestions filtradas
    suggestions: filterTextualSuggestions(suggestions.slice(0, 3)),
    sentrixAction,
    decision: sobrestockLider ? sobrestockLider.sku : (quiebreLider ? quiebreLider.sku : null),
    evidence: {
      doh_promedio: dohMedio,
      sobrestock_lider: sobrestockLider ? sobrestockLider.sku : null,
      sobrestock_lider_doh: sobrestockLider ? sobrestockLider.doh : null,
      quiebre_lider: quiebreLider ? quiebreLider.sku : null,
      quiebre_lider_doh: quiebreLider ? quiebreLider.doh : null,
      capital_sobrestock_USD: capitalSobrestock,
      sobrestock_count: sobrestock.length,
      quiebre_count: quiebreRiesgo.length,
      optimo_count: optimo.length,
    },
    focus: "coverage_liberation_and_protection",
    confidence: "alta",
    materialMetrics: [
      { label: `${dohMedio}d DOH promedio`, source: "doh_promedio_runtime" },
      { label: sobrestockLider ? `${sobrestockLider.sku} ${sobrestockLider.doh}d` : "sin sobrestock", source: "doh_top_sobrestock" },
      { label: quiebreLider ? `${quiebreLider.sku} ${quiebreLider.doh}d` : "sin riesgo quiebre", source: "doh_top_quiebre" },
      { label: `${fmtK(capitalSobrestock)} capital sobrestock`, source: "capital_sobrestockeado" },
    ],
    reasoningPattern: "coverage_dive_analysis",
    suggestedNextActions: [
      { type: "liberate_overstock", sku: sobrestockLider ? sobrestockLider.sku : null },
      { type: "protect_stockout_risk", sku: quiebreLider ? quiebreLider.sku : null },
      { type: "drill_optimal_range", count: optimo.length },
    ],
  });
}

// ════════════════════════════════════════════════════════════════════════════
// FASE 2 · composeParetoDimensional (wrapper Pareto · ventas + margenes)
//
// Reemplaza el streaming LLM de BloquePareto80Card y BloquePareto80MargenCard
// con análisis determinístico unified que cubre 4 dimensiones de pareto
// (cliente/marca/sfamilia/sku) en ambos módulos.
//
// Threshold de concentración preservado del prompt LLM original:
//   pctElementos > 60       → diversificado · estructura sana
//   pctElementos 50-60      → intermedio · vigilar evolución
//   pctElementos < 50       → concentrado · riesgo de dependencia
//
// Si modulo === "margenes" · agrega análisis margen vs benchmark (30.1%).
//
// Decisión D-FASE-2-NO-CALIBRAR-VOZ-AUN firmada · voz se ajusta post-FASE-4
// vía BRIEF VOZ INTEGRAL · iteración composer por composer es trabajo perdido.
// ════════════════════════════════════════════════════════════════════════════
function composeParetoDimensional(paretoData, paretoDim, modulo, scenario, hasActiveFilter) {
  // Guard inicial · dataset vacío
  if (!paretoData || !Array.isArray(paretoData) || paretoData.length === 0) {
    return {
      opener: `No tengo datos Pareto disponibles para esta dimensión en el escenario actual. Verificá si hay filtros aplicados que vacían el universo.`,
    };
  }

  // Calcular items según hasActiveFilter (mismo flag que LLM original)
  let items;
  if (hasActiveFilter && paretoData.length > 0) {
    items = paretoData;
  } else {
    const bloque = paretoData.filter(d => d.pctAcum <= 80);
    items = bloque.length ? bloque : paretoData.slice(0, 1);
  }

  // Métricas base
  const universo = paretoData.length;
  const pctElementos = +((items.length / universo) * 100).toFixed(0);
  const concLabel = pctElementos > 60 ? "diversificado · estructura sana"
                  : pctElementos >= 50 ? "intermedio · vigilar evolución"
                  : "concentrado · riesgo de dependencia";

  // Métrica monetaria según módulo
  const valueKey = modulo === "margenes" ? "contribucion" : "actual";
  const totalGral = paretoData.reduce((s, r) => s + (r[valueKey] || 0), 0);
  const pctAcumBloque = items[items.length - 1].pctAcum;

  // Label dimensional · respeta el original
  const dimLabel = paretoDim === "cliente" ? "Clientes"
                 : paretoDim === "marca" ? "Marcas"
                 : paretoDim === "sfamilia" ? "Superfamilias"
                 : paretoDim === "sku" ? "SKUs"
                 : "Elementos";
  const dimSingular = dimLabel.toLowerCase().slice(0, -1);

  const top1 = items[0];
  const top2 = items.length >= 2 ? items[1] : null;

  // Helper format $K → $M (igual que composers anteriores)
  const fmtM = (v) => `$${(v / 1000).toFixed(1)}M`;

  // ═══ BLOQUE 1 · RESUMEN ═══
  let opener = `Concentración Pareto · ${items.length} ${dimLabel.toLowerCase()} explican el ${pctAcumBloque.toFixed(0)}% `;
  opener += modulo === "margenes" ? `de la contribución` : `de las ventas`;
  opener += ` · representan el ${pctElementos}% del universo total · estructura **${concLabel}**.\n\n`;

  // ═══ BLOQUE 2 · EVIDENCIA ═══
  const top1Value = fmtM(top1[valueKey]);
  opener += `**Evidencia:** ${top1.nombre} lidera con ${top1Value} (${top1.pctPart.toFixed(1)}% participación)`;
  if (top2) {
    const top2Value = fmtM(top2[valueKey]);
    opener += `, seguido por ${top2.nombre} con ${top2Value} (${top2.pctPart.toFixed(1)}%)`;
  }
  if (items.length >= 3) {
    opener += `. Los primeros ${items.length} elementos concentran el ${pctAcumBloque.toFixed(1)}% `;
    opener += modulo === "margenes" ? `de la contribución total.` : `del volumen comercial.`;
  } else {
    opener += `.`;
  }
  opener += `\n\n`;

  // ═══ BLOQUE 2-bis · MARGEN (solo módulo margenes) ═══
  if (modulo === "margenes") {
    const benchmark = 30.1;
    const itemsConMargen = items.filter(r => r.margen != null);
    if (itemsConMargen.length > 0) {
      const totalContribBloque = itemsConMargen.reduce((s, r) => s + r.contribucion, 0);
      const margenPromBloque = totalContribBloque > 0
        ? +((itemsConMargen.reduce((s, r) => s + (r.margen || 0) * (r.contribucion || 0), 0) / totalContribBloque)).toFixed(1)
        : null;

      const bajo = itemsConMargen.filter(r => r.margen < benchmark);
      const sobre = itemsConMargen.filter(r => r.margen >= benchmark);

      if (margenPromBloque != null) {
        opener += `**Margen del bloque:** ${margenPromBloque}% ponderado por contribución · `;
        const gapBench = +(margenPromBloque - benchmark).toFixed(1);
        opener += `${Math.abs(gapBench)}pp ${gapBench >= 0 ? "sobre" : "bajo"} benchmark de industria (${benchmark}%). `;
        if (bajo.length > 0 && sobre.length > 0) {
          opener += `${bajo.length} ${dimSingular}${bajo.length > 1 ? "s" : ""} bajo benchmark · ${sobre.length} sobre.`;
        } else if (bajo.length > 0) {
          opener += `Todos los elementos del bloque operan bajo benchmark.`;
        } else {
          opener += `Todos los elementos del bloque operan sobre benchmark.`;
        }
        opener += `\n\n`;
      }
    }
  }

  // ═══ BLOQUE 3 · LECTURA ═══
  opener += `**Lectura:** `;
  if (pctElementos < 30) {
    opener += `${items.length} ${dimLabel.toLowerCase()} de ${universo} sostienen el grueso del negocio · pérdida de cualquiera de las top 2 impacta directamente sobre el portafolio. Modelo estructuralmente frágil ante salida o renegociación de las cuentas líderes.`;
  } else if (pctElementos < 50) {
    opener += `Pocas ${dimLabel.toLowerCase()} sostienen la mayor parte · si el top 1 se desploma, el portafolio absorbe el impacto pero pierde escala. Importante diversificar antes de que la concentración pase a riesgo.`;
  } else if (pctElementos <= 60) {
    opener += `Estructura intermedia · ningún ${dimSingular} concentra peso desproporcionado, pero la base no es lo suficientemente amplia para resistir caída de un líder.`;
  } else {
    opener += `Estructura amplia · el negocio no depende de pocos ${dimLabel.toLowerCase()}. La resiliencia es alta · cualquier salida individual se absorbe con baja fricción.`;
  }
  opener += `\n\n`;

  // ═══ BLOQUE 4 · MECANISMOS DISPONIBLES (v1.1 · interpretativo) ═══
  opener += `**Mecanismos disponibles:**\n`;
  if (pctElementos < 50) {
    opener += `· La palanca comercial sobre ${top1.nombre} tiene espacio: concentra ${top1.pctPart.toFixed(1)}% del volumen con peso desproporcionado\n`;
    opener += `· Las ${dimLabel.toLowerCase()} rank 4-7 representan zona de aceleración estructural disponible para diversificar peso\n`;
    opener += `· El riesgo de concentración top 1-2 es cuantificable: ${(items[0].pctPart + (items[1]?.pctPart || 0)).toFixed(1)}% del volumen depende de 2 elementos`;
  } else if (pctElementos <= 60) {
    opener += `· La relación con top 2 representa zona de consolidación · cuantifica ${(items[0].pctPart + (items[1]?.pctPart || 0)).toFixed(1)}% del volumen\n`;
    opener += `· La evolución de concentración entre trimestres es métrica de seguimiento natural\n`;
    opener += `· Existen ${universo - items.length} elementos fuera del bloque 80% · zona de exploración disponible`;
  } else {
    opener += `· Estructura amplia · ningún elemento concentra peso desproporcionado\n`;
    opener += `· Las categorías con margen sobre benchmark representan zona de inversión comercial natural\n`;
    opener += `· La diversificación actual habilita experimentación sobre nuevas líneas`;
  }

  opener += `\n\n*Confianza alta · Pareto runtime sobre escenario ${scenario}.*`;

  return { opener };
}

// ═══════════════════════════════════════════════════════════════════════
// BRIEF #40 · composeWarehouseAnalysis · Ferrari para bodega/sucursal
//
// Activado por intent "warehouse_dive" cuando concept_warehouse está
// activo (F11 canonical __warehouse_location__ o noun_warehouse legacy).
//
// Dos modos según params.specificSucursal:
//   Caso A (sucursal específica): foco en Santiago/Valparaíso/etc.
//   Caso B (cold-start agregado): ranking 4 sucursales por capital.
//
// CERO HARDCODING: cifras runtime de skuInventario.bodega agregado.
// SUCURSALES (const línea 6189) es single source of truth.
// ═══════════════════════════════════════════════════════════════════════
// FIX #D-CAPITAL-NAVEGABLE · detecta el foco "capital inmovilizado" para ofrecer las puertas navegables.
// Match léxico: (capital|inventario|stock|plata|dinero|caja) + (inmovilizad|atrapad|detenid|parad|muert|
// estancad|varad|frenad|amarrad) en proximidad. Solo para ESTE foco (cláusula I-CAP-SOLO-CAPITAL).
function _isCapitalInmovilizadoFocus(text) {
  if (typeof ADI_CAPITAL_CIFRA_REAL_ENABLED === "undefined" || !ADI_CAPITAL_CIFRA_REAL_ENABLED) return false;
  if (!text || typeof text !== "string") return false;
  const t = text.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  const noun = /(capital|inventario|stock|plata|dinero|caja)/.test(t);
  const state = /(inmovilizad|atrapad|detenid|parad|muert|estancad|varad|frenad|amarrad)/.test(t);
  return noun && state;
}

// FIX #D-CAPITAL-NAVEGABLE · las 2 puertas navegables que pasaron el gate (RUTEO puro · cálculo
// existente): bodega (warehouse_dive · arreglado) + SKU (sku_operational · ya filtra por DOH). Objetos
// {text, action} accionables. NO se ofrecen familia/antigüedad/rotación (deudas · requieren cálculo).
function _buildCapitalNavegablePuertas() {
  return [
    { text: "¿Lo desglozamos por bodega?", action: { type: "capital_drill_bodega" } },
    { text: "¿Qué SKUs están atrapando más capital?", action: { type: "capital_drill_sku" } },
  ];
}

function composeWarehouseAnalysis(scenarioId, params) {
  // ── 1. Helpers formato
  const fmtK = (val) => {
    if (val == null || isNaN(val)) return "$0";
    if (Math.abs(val) >= 1000) {
      const k = val / 1000;
      return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`;
    }
    return `$${Math.round(val)}`;
  };
  const safeParams = params || {};
  const specificSucursal = safeParams.specificSucursal || null;

  // CORTE 4 · fuente única del inventario. ON → scenario-aware (reacciona en
  // tensión/crisis vía DOH/alerta; en bonanza === skuInventario). OFF → estático
  // (≡ 0f4d36ac). Se usa en las 5 referencias de abajo (incluido el closure).
  const _invSource = FEATURE_WAREHOUSE_AS_ENTITY
    ? applyScenarioToSkuInventario(scenarioId)
    : skuInventario;

  // ── 2. Agregación runtime por sucursal
  // Single source of truth: skuInventario.bodega field.
  function _aggregateBySucursal(sucursalName) {
    const skus = _invSource.filter(s => s.bodega === sucursalName);
    if (skus.length === 0) {
      return { sucursal: sucursalName, skus: [], totalStock: 0, dohPromedio: 0, sfamilias: {} };
    }
    const totalStock = skus.reduce((acc, s) => acc + s.stockUSD, 0);
    // FIX #D-CAPITAL-CIFRA-REAL · el capital INMOVILIZADO real (def L60 · diasSinVenta > 60), no el total.
    const inmovilizadoUSD = skus
      .filter(s => s.diasSinVenta > 60)
      .reduce((acc, s) => acc + s.stockUSD, 0);
    // FIX #D-CAPITAL-DEF-CANONICA · el inmovilizado Def 2 (alerta crit/warn O rotacion<2) por sucursal.
    const inmovilizadoDef2USD = skus
      .filter(s => s.alerta === "crit" || s.alerta === "warn" || s.rotacion < 2)
      .reduce((acc, s) => acc + s.stockUSD, 0);
    const dohPromedio = skus.reduce((acc, s) => acc + s.doh, 0) / skus.length;
    const sfamilias = {};
    skus.forEach(s => {
      if (!sfamilias[s.sfamilia]) sfamilias[s.sfamilia] = { count: 0, stockUSD: 0, dohSum: 0 };
      sfamilias[s.sfamilia].count++;
      sfamilias[s.sfamilia].stockUSD += s.stockUSD;
      sfamilias[s.sfamilia].dohSum += s.doh;
    });
    Object.values(sfamilias).forEach(f => { f.dohPromedio = f.dohSum / f.count; });
    return { sucursal: sucursalName, skus, totalStock, inmovilizadoUSD, inmovilizadoDef2USD, dohPromedio: +dohPromedio.toFixed(0), sfamilias };
  }

  const stockTotalCartera = _invSource.reduce((acc, s) => acc + s.stockUSD, 0);
  // FIX #D-CAPITAL-CIFRA-REAL · el inmovilizado total de la cartera (def L60) para contexto honesto.
  const inmovilizadoTotalCartera = _invSource
    .filter(s => s.diasSinVenta > 60)
    .reduce((acc, s) => acc + s.stockUSD, 0);
  // FIX #D-CAPITAL-DEF-CANONICA · las cifras canónicas (Def 2 + submétrica) vía el single source of truth.
  const _capCanon = _capitalInmovilizado(_invSource);
  const _capDefOn = (typeof ADI_CAPITAL_DEF_CANONICA_ENABLED !== "undefined" && ADI_CAPITAL_DEF_CANONICA_ENABLED);

  // ─────────────────────────────────────────────────────────────────────
  // CASO A · sucursal específica
  // ─────────────────────────────────────────────────────────────────────
  if (specificSucursal) {
    const agg = _aggregateBySucursal(specificSucursal);

    // Guard defensivo: si la sucursal no tiene SKUs en el dataset actual.
    if (agg.skus.length === 0) {
      const opener = `${specificSucursal} no registra SKUs activos en el dataset actual. Las 4 sucursales canónicas (${SUCURSALES.join(", ")}) tienen distribución desigual del inventario.\n\n*Confianza alta · inventario distribuido desde el dataset base.*`;
      return buildResponseContract({
        opener,
        // BRIEF N-bis · Tipo A puro · filtradas
        suggestions: filterTextualSuggestions(["¿Qué pasa en las bodegas?", "Cómo está la rotación", "Cuál es la cobertura"]),
        sentrixAction: {
          label: "Ver inventario por bodega",
          moduleChip: "Inventario",
          payload: { modulo: "inventario", clientes: [], skus: [], mechanismBanner: `Sucursal ${specificSucursal} sin SKUs` },
        },
        decision: null,
        evidence: { sucursal: specificSucursal, sku_count: 0 },
        focus: "warehouse_specific_empty",
        confidence: "alta",
        materialMetrics: [{ label: `0 SKUs en ${specificSucursal}`, source: "sucursal_empty_runtime" }],
        reasoningPattern: "warehouse_dive_analysis",
        suggestedNextActions: [{ type: "drill_all_warehouses" }],
      });
    }

    const pctCartera = ((agg.totalStock / stockTotalCartera) * 100).toFixed(1);

    // ── 3. EVIDENCIA · header
    // FIX #D-CAPITAL-CIFRA-REAL · distinguir inventario TOTAL de capital INMOVILIZADO (def L60).
    // OFF: el header decía "capital inmovilizado {totalStock}" (la mentira · el total etiquetado mal).
    const headerLine = (typeof ADI_CAPITAL_DEF_CANONICA_ENABLED !== "undefined" && ADI_CAPITAL_DEF_CANONICA_ENABLED)
      ? `${specificSucursal} concentra ${pctCartera}% del inventario total · ${agg.skus.length} SKUs activos · inventario ${fmtK(agg.totalStock)} · de eso, capital inmovilizado ${fmtK(agg.inmovilizadoDef2USD)} (SKUs críticos o rotación muy baja) · DOH promedio ${agg.dohPromedio} días.`
      : ((typeof ADI_CAPITAL_CIFRA_REAL_ENABLED !== "undefined" && ADI_CAPITAL_CIFRA_REAL_ENABLED)
        ? `${specificSucursal} concentra ${pctCartera}% del inventario total · ${agg.skus.length} SKUs activos · inventario ${fmtK(agg.totalStock)} · de eso, capital inmovilizado ${fmtK(agg.inmovilizadoUSD)} · DOH promedio ${agg.dohPromedio} días.`
        : `${specificSucursal} concentra ${pctCartera}% del inventario total · ${agg.skus.length} SKUs activos · capital inmovilizado ${fmtK(agg.totalStock)} · DOH promedio ${agg.dohPromedio} días.`);

    // ── 4. EVIDENCIA · top 3 sfamilia por stock
    const topFamilias = Object.entries(agg.sfamilias)
      .sort((a, b) => b[1].stockUSD - a[1].stockUSD)
      .slice(0, 3);
    const familiasLines = topFamilias.map(([name, f]) => {
      const pct = ((f.stockUSD / agg.totalStock) * 100).toFixed(0);
      return `${name.padEnd(34, " ")} → Stock ${fmtK(f.stockUSD)} · DOH ${Math.round(f.dohPromedio)}d · ${pct}% de la bodega`;
    }).join("\n");

    // ── 5. EVIDENCIA · top 3 SKUs por stockUSD
    const topSkus = [...agg.skus].sort((a, b) => b.stockUSD - a.stockUSD).slice(0, 3);
    const skusLines = topSkus.map(s =>
      `${s.sku.padEnd(14, " ")} → Stock ${fmtK(s.stockUSD)} · DOH ${s.doh}d · Rotación ${s.rotacion}x · ${s.diasSinVenta}d sin venta`
    ).join("\n");

    const evidencia = `${headerLine}\n\nComposición por familia:\n${familiasLines}\n\nTop 3 SKUs por capital:\n${skusLines}`;

    // ── 6. LECTURA causal
    const topFamiliaName = topFamilias[0] ? topFamilias[0][0] : null;
    const topFamiliaPct = topFamilias[0] ? ((topFamilias[0][1].stockUSD / agg.totalStock) * 100).toFixed(0) : "0";
    const topSku = topSkus[0];
    const promedioCartera = +(_invSource.reduce((s, x) => s + x.doh, 0) / _invSource.length).toFixed(0);
    const dohGap = agg.dohPromedio - promedioCartera;

    let lecturaCausal = "";
    if (topFamiliaName) {
      lecturaCausal = `${topFamiliaName} concentra ${topFamiliaPct}% del capital de ${specificSucursal}. ${topSku ? `${topSku.sku} es el SKU más pesado (${fmtK(topSku.stockUSD)}, DOH ${topSku.doh}d).` : ""}`;
      if (Math.abs(dohGap) > 10) {
        lecturaCausal += ` La cobertura está ${dohGap > 0 ? "por encima" : "por debajo"} del promedio cartera (${agg.dohPromedio}d vs ${promedioCartera}d).`;
      } else {
        lecturaCausal += ` La cobertura está alineada con el promedio cartera (${agg.dohPromedio}d vs ${promedioCartera}d).`;
      }
    }

    // ── 7. FOCO
    const lentos = agg.skus.filter(s => s.doh > 60).sort((a, b) => b.stockUSD - a.stockUSD);
    const rapidos = agg.skus.filter(s => s.rotacion >= 5).sort((a, b) => b.rotacion - a.rotacion);
    let focoText = "";
    if (lentos.length > 0) {
      const top = lentos[0];
      focoText = `Mecanismo disponible en ${specificSucursal}: ${top.sku} concentra capital atrapado (${fmtK(top.stockUSD)} · DOH ${top.doh}d · ${top.diasSinVenta}d sin venta) · zona donde la palanca de plan de salida opera.`;
      if (rapidos.length > 0) {
        focoText += ` En paralelo, ${rapidos[0].sku} opera con rotación ${rapidos[0].rotacion}x · zona estructuralmente sana en disponibilidad.`;
      }
    } else if (rapidos.length > 0) {
      focoText = `Estructura sana: ${specificSucursal} opera con SKUs rotacionales healthy (${rapidos[0].sku} ${rapidos[0].rotacion}x) · la disponibilidad operativa está dentro del rango natural.`;
    } else {
      focoText = `Estructura balanceada: ${specificSucursal} opera sin SKUs en estado crítico ni rotacionales destacados · la evolución mensual es la métrica de seguimiento natural.`;
    }

    const confianza = `*Confianza alta · cifras determinísticas del inventario actual.*`;
    const opener = `${evidencia}\n\n${lecturaCausal}\n\n${focoText}\n\n${confianza}`;

    // ── 8. Suggestions + SentrixAction
    const allSkus = agg.skus.map(s => s.sku);
    const suggestions = [];
    if (lentos.length > 0) suggestions.push(`Cuánto recupero si liquido ${lentos[0].sku}`);
    if (rapidos.length > 0) suggestions.push(`Profundizar en ${rapidos[0].sku}`);
    suggestions.push(`Comparar ${specificSucursal} con otras bodegas`);
    while (suggestions.length < 3) suggestions.push("Qué SKUs sí están funcionando");

    const sentrixAction = {
      label: `Ver ${allSkus.length} SKUs en ${specificSucursal}`,
      moduleChip: "Inventario",
      payload: {
        modulo: "inventario",
        clientes: [],
        skus: allSkus,
        bodegas: [specificSucursal],
        mechanismBanner: `Inventario en ${specificSucursal}`,
      },
    };

    return buildResponseContract({
      opener,
      // BRIEF N-bis · Tipo A puro · suggestions filtradas
      suggestions: filterTextualSuggestions(suggestions.slice(0, 3)),
      sentrixAction,
      decision: topSku ? topSku.sku : null,
      evidence: {
        sucursal: specificSucursal,
        pct_cartera: +pctCartera,
        capital_sucursal_USD: agg.totalStock,
        doh_promedio_sucursal: agg.dohPromedio,
        sku_count: agg.skus.length,
        top_familia: topFamiliaName,
      },
      focus: "warehouse_specific",
      confidence: "alta",
      materialMetrics: [
        { label: `${pctCartera}% del inventario`, source: "sucursal_capital_share_runtime" },
        { label: `${agg.dohPromedio}d DOH promedio`, source: "sucursal_doh_promedio_runtime" },
        { label: `${fmtK(agg.totalStock)} capital`, source: "sucursal_capital_USD_runtime" },
        { label: topFamiliaName ? `${topFamiliaPct}% ${topFamiliaName}` : "sin top familia", source: "sucursal_top_familia_runtime" },
      ],
      reasoningPattern: "warehouse_dive_analysis",
      suggestedNextActions: [
        { type: "drill_slow_movers", sucursal: specificSucursal, sku: lentos[0] ? lentos[0].sku : null },
        { type: "protect_top_rotational", sucursal: specificSucursal, sku: rapidos[0] ? rapidos[0].sku : null },
        { type: "compare_warehouses", sucursal: specificSucursal },
      ],
    });
  }

  // ─────────────────────────────────────────────────────────────────────
  // CASO B · cold-start agregado de 4 sucursales
  // ─────────────────────────────────────────────────────────────────────
  const aggs = SUCURSALES.map(s => _aggregateBySucursal(s));
  const aggsConData = aggs.filter(a => a.skus.length > 0);
  // FIX #D-CAPITAL-CIFRA-REAL · rankear por el INMOVILIZADO real, no el total (la def L60).
  const _capRealOn = (typeof ADI_CAPITAL_CIFRA_REAL_ENABLED !== "undefined" && ADI_CAPITAL_CIFRA_REAL_ENABLED);
  // FIX #D-CAPITAL-DEF-CANONICA · el valor por sucursal según la def vigente: Def 2 (canon) > >60d > total.
  const _valFor = (a) => _capDefOn ? a.inmovilizadoDef2USD : (_capRealOn ? a.inmovilizadoUSD : a.totalStock);
  const _baseCartera = _capDefOn ? (_capCanon.total || 1) : (_capRealOn ? (inmovilizadoTotalCartera || 1) : stockTotalCartera);
  const aggsRanked = [...aggsConData].sort((a, b) => _valFor(b) - _valFor(a));

  // ── 3. EVIDENCIA · header agregado
  // FIX #D-CAPITAL-DEF-CANONICA · cifra dual: Def 2 ($56K) principal + submétrica >60d ($33.2K) sub-lectura.
  // FIX #D-CAPITAL-CIFRA-REAL (OFF de canon): el header del TOTAL es honesto · ranking por >60d.
  const headerLine = _capDefOn
    ? `El inventario total entre ${aggsConData.length} sucursales (${aggsConData.map(a => a.sucursal).join(", ")}) suma ${fmtK(stockTotalCartera)}. De eso, ${fmtK(_capCanon.total)} es capital inmovilizado en SKUs críticos o de rotación muy baja. De eso, ${fmtK(_capCanon.estricto60d)} corresponde a stock sin venta por más de 60 días. Distribución por bodega:`
    : (_capRealOn
        ? `El inventario total entre ${aggsConData.length} sucursales (${aggsConData.map(a => a.sucursal).join(", ")}) suma ${fmtK(stockTotalCartera)}. De eso, ${fmtK(inmovilizadoTotalCartera)} es capital inmovilizado (más de 60 días sin movimiento), distribuido así:`
        : `El inventario distribuido entre ${aggsConData.length} sucursales (${aggsConData.map(a => a.sucursal).join(", ")}) suma ${fmtK(stockTotalCartera)} totales.`);

  // ── 4. EVIDENCIA · ranking por capital inmovilizado (Def 2 canónica)
  const rankingLines = aggsRanked.map(a => {
    const _val = _valFor(a);
    const pct = ((_val / _baseCartera) * 100).toFixed(1);
    return `${a.sucursal.padEnd(13, " ")} → ${fmtK(_val)} · ${pct}% · DOH promedio ${a.dohPromedio}d · ${a.skus.length} SKUs`;
  }).join("\n");

  const evidencia = `${headerLine}\n\nRanking por capital inmovilizado:\n${rankingLines}`;

  // ── 5. LECTURA causal
  const top = aggsRanked[0];
  const bottom = aggsRanked[aggsRanked.length - 1];
  const _topVal = top ? _valFor(top) : 0;
  const _bottomVal = bottom ? _valFor(bottom) : 0;
  const _baseCausal = _baseCartera;
  const topPct = top ? ((_topVal / _baseCausal) * 100).toFixed(0) : "0";
  const _capInmovWording = _capDefOn || _capRealOn;
  let lecturaCausal = "";
  if (top && bottom && top !== bottom && _topVal > 0) {
    const ratio = (_topVal / Math.max(_bottomVal, 1)).toFixed(1);
    lecturaCausal = _capInmovWording
      ? `${top.sucursal} concentra ${topPct}% del capital inmovilizado, ${ratio}x lo que mantiene ${bottom.sucursal}.`
      : `${top.sucursal} concentra ${topPct}% del capital, ${ratio}x lo que mantiene ${bottom.sucursal}.`;
    // Detectar bodega con DOH crítico
    const dohCritica = aggsRanked.find(a => a.dohPromedio > 80);
    if (dohCritica) {
      lecturaCausal += ` ${dohCritica.sucursal} opera con cobertura más alta del portafolio (${dohCritica.dohPromedio}d promedio).`;
    }
  } else if (_capInmovWording && top && _topVal > 0) {
    lecturaCausal = `${top.sucursal} concentra el capital inmovilizado del portafolio (${fmtK(_topVal)}).`;
  }

  // ── 6. FOCO
  const sucursalCritica = aggsRanked.find(a => a.dohPromedio > 80) || aggsRanked[0];
  const _critVal = sucursalCritica ? _valFor(sucursalCritica) : 0;
  const focoText = sucursalCritica
    ? (_capInmovWording
        ? `Mecanismo disponible: ${sucursalCritica.sucursal} concentra mayor presión (${fmtK(_critVal)} inmovilizado · DOH ${sucursalCritica.dohPromedio}d) · zona estructural a profundizar antes que la palanca de redistribución o liquidación opere.`
        : `Mecanismo disponible: ${sucursalCritica.sucursal} concentra mayor presión (${fmtK(_critVal)} · DOH ${sucursalCritica.dohPromedio}d) · zona estructural a profundizar antes que la palanca de redistribución o liquidación opere.`)
    : `Estructura balanceada: la distribución opera dentro del rango healthy · la evolución mensual es la métrica de seguimiento natural.`;

  const confianza = `*Confianza alta · distribución determinística sobre el inventario actual.*`;
  const opener = `${evidencia}\n\n${lecturaCausal}\n\n${focoText}\n\n${confianza}`;

  // ── 7. Suggestions + SentrixAction
  const suggestions = [
    `Qué pasa en ${aggsRanked[0] ? aggsRanked[0].sucursal : "Santiago"}`,
    aggsRanked[1] ? `Qué pasa en ${aggsRanked[1].sucursal}` : "Cómo está la rotación",
    "Cuál es la cobertura del inventario",
  ];

  const allSkus = aggsConData.flatMap(a => a.skus.map(s => s.sku)).slice(0, 6);
  const sentrixAction = {
    label: `Ver ${aggsConData.length} sucursales`,
    moduleChip: "Inventario",
    payload: {
      modulo: "inventario",
      clientes: [],
      skus: allSkus,
      bodegas: aggsConData.map(a => a.sucursal),
      mechanismBanner: "Inventario por sucursal",
    },
  };

  return buildResponseContract({
    opener,
    // BRIEF N-bis · Tipo A puro · suggestions filtradas
    suggestions: filterTextualSuggestions(suggestions.slice(0, 3)),
    sentrixAction,
    decision: top ? top.sucursal : null,
    evidence: {
      sucursales_count: aggsConData.length,
      capital_total_USD: stockTotalCartera,
      top_sucursal: top ? top.sucursal : null,
      top_sucursal_pct: +topPct,
      sucursal_doh_critica: sucursalCritica && sucursalCritica.dohPromedio > 80 ? sucursalCritica.sucursal : null,
    },
    focus: "warehouse_distribution",
    confidence: "alta",
    materialMetrics: aggsRanked.slice(0, 4).map(a => ({
      label: `${a.sucursal} ${fmtK(a.totalStock)}`,
      source: `warehouse_${a.sucursal.toLowerCase()}_runtime`,
    })),
    reasoningPattern: "warehouse_dive_analysis",
    suggestedNextActions: [
      { type: "drill_top_warehouse", sucursal: top ? top.sucursal : null },
      { type: "drill_critical_doh", sucursal: sucursalCritica && sucursalCritica.dohPromedio > 80 ? sucursalCritica.sucursal : null },
      { type: "compare_distribution", count: aggsConData.length },
    ],
  });
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 5 · _familyInventoryAgg · inventario físico por familia (mundo-físico).
// Suma stockUSD de SKUs por sfamilia/bodega desde la fuente scenario-aware. Incluye
// SKUs huérfanos (marca ∉ clientesMargen · p. ej. Makita) y los marca para declararlos.
// SKU→familia→bodega es relación DIRECTA → dato físico, no proxy.
// ════════════════════════════════════════════════════════════════════════════
function _familyInventoryAgg(scenarioId) {
  const inv = FEATURE_FAMILY_INVENTORY ? applyScenarioToSkuInventario(scenarioId) : skuInventario;
  const brandsWithClient = new Set();
  for (const c of clientesMargen) { if (c.marca) brandsWithClient.add(c.marca); }
  const fams = {};
  for (const s of inv) {
    if (!fams[s.sfamilia]) fams[s.sfamilia] = { sfamilia: s.sfamilia, total: 0, inmovilizado: 0, bodegas: {}, skus: [], orphanStock: 0, orphanSkus: [] };
    const f = fams[s.sfamilia];
    f.total += s.stockUSD;
    f.bodegas[s.bodega] = (f.bodegas[s.bodega] || 0) + s.stockUSD;
    f.skus.push(s);
    // Inmovilizado Def 2 (alerta crit/warn O rotación < 2) · misma def que el módulo.
    if (s.alerta === "crit" || s.alerta === "warn" || s.rotacion < 2) f.inmovilizado += s.stockUSD;
    // Huérfano: marca sin cliente asignado en mundo-cliente.
    if (s.marca && !brandsWithClient.has(s.marca)) { f.orphanStock += s.stockUSD; f.orphanSkus.push(s); }
  }
  return fams;
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 5 · composeFamilyInventory · familia como sujeto del inventario.
// 3 modos: (a) familia sola → composición + desglose por bodega + inmovilizado +
// declaración de huérfanos; (b) familia + bodega → detalle SKU; (c) ranking →
// familias por inventario/inmovilizado. Mundo-físico; declara linaje cuando hay
// huérfanos (no fuerza reconciliación falsa con la venta mundo-cliente).
// ════════════════════════════════════════════════════════════════════════════
function composeFamilyInventory(scenarioId, params) {
  const fmtK = (val) => {
    if (val == null || isNaN(val)) return "$0";
    if (Math.abs(val) >= 1000) { const k = val / 1000; return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`; }
    return `$${Math.round(val)}`;
  };
  // Lista en español: "A, B y C".
  const joinEs = (arr) => arr.length <= 1 ? (arr[0] || "") : arr.slice(0, -1).join(", ") + " y " + arr[arr.length - 1];
  const sp = params || {};
  const fams = _familyInventoryAgg(scenarioId);
  const famList = Object.values(fams);

  // ── Modo C · RANKING de familias por inventario o inmovilizado ──────────────
  if (sp.ranking) {
    const porInmov = !!sp.inmovilizado;
    const ranked = [...famList].sort((a, b) => (porInmov ? b.inmovilizado - a.inmovilizado : b.total - a.total));
    const linea = ranked.map(f => `${f.sfamilia} ${fmtK(porInmov ? f.inmovilizado : f.total)}`).join(" · ");
    const titulo = porInmov ? "Inventario inmovilizado por familia" : "Inventario por familia";
    const topF = ranked[0];
    const opener = `${titulo} (mayor a menor): ${linea}.\n\n${topF.sfamilia} encabeza con ${fmtK(porInmov ? topF.inmovilizado : topF.total)}${porInmov ? " de capital inmovilizado (SKUs críticos o de rotación muy baja)" : " de inventario físico"}.`;
    return {
      opener,
      suggestions: filterTextualSuggestions([`Qué hay en ${topF.sfamilia}`, "Inventario por bodega", "Qué SKUs están inmovilizados"]),
      sentrixAction: { label: "Ver inventario por familia", moduleChip: "Inventario", payload: { modulo: "inventario", clientes: [], skus: [] } },
      derivedModule: "inventario",
      familyResolved: null,
    };
  }

  // Resolver la familia (tolerante: match por nombre exacto en el agg).
  const fam = sp.familyName ? fams[sp.familyName] : null;
  if (!fam) {
    // Sin familia resuelta → fallback al ranking total (defensivo).
    return composeFamilyInventory(scenarioId, { ranking: true, inmovilizado: false });
  }

  const bodegasOrden = Object.entries(fam.bodegas).sort((a, b) => b[1] - a[1]);

  // ── Modo B · FAMILIA + BODEGA · detalle SKU ────────────────────────────────
  if (sp.bodega) {
    const skusEnBodega = fam.skus.filter(s => s.bodega === sp.bodega).sort((a, b) => b.stockUSD - a.stockUSD);
    if (skusEnBodega.length === 0) {
      return {
        opener: `${fam.sfamilia} no tiene SKUs en ${sp.bodega} en este escenario. Está repartido en ${joinEs(bodegasOrden.map(([b]) => b))}.`,
        suggestions: filterTextualSuggestions([`Qué hay en ${fam.sfamilia}`, `Qué hay en ${sp.bodega}`]),
        sentrixAction: { label: "Ver inventario", moduleChip: "Inventario", payload: { modulo: "inventario", clientes: [], skus: [] } },
        derivedModule: "inventario",
        familyResolved: fam.sfamilia,
      };
    }
    const totalBodega = skusEnBodega.reduce((a, s) => a + s.stockUSD, 0);
    const detalle = skusEnBodega.map(s => `${s.sku} (${fmtK(s.stockUSD)} · DOH ${s.doh}d · rotación ${s.rotacion}x)`).join(", ");
    const opener = `En ${sp.bodega}, ${fam.sfamilia} tiene ${skusEnBodega.length} ${skusEnBodega.length === 1 ? "SKU" : "SKUs"} por ${fmtK(totalBodega)}: ${detalle}.`;
    return {
      opener,
      suggestions: filterTextualSuggestions([`Qué hay en ${fam.sfamilia}`, `Qué hay en ${sp.bodega}`, "Inventario por familia"]),
      sentrixAction: { label: "Ver inventario", moduleChip: "Inventario", payload: { modulo: "inventario", clientes: [], skus: skusEnBodega.map(s => s.sku) } },
      derivedModule: "inventario",
      familyResolved: fam.sfamilia,
    };
  }

  // ── Modo A · FAMILIA SOLA · composición + bodegas + inmovilizado + huérfanos ──
  const bodegasTxt = joinEs(bodegasOrden.map(([b, v]) => `${b} (${fmtK(v)})`));
  let opener = `Inventario de ${fam.sfamilia}: ${fmtK(fam.total)}, repartido en ${bodegasTxt}. De eso, ${fmtK(fam.inmovilizado)} es capital inmovilizado (SKUs críticos o de rotación muy baja).`;
  // Declaración de huérfanos (decisión 2 · linaje de dato · texto del founder).
  if (fam.orphanStock > 0 && fam.orphanSkus.length > 0) {
    const orphanBrands = [...new Set(fam.orphanSkus.map(s => s.marca))];
    const orphanBodegas = [...new Set(fam.orphanSkus.map(s => s.bodega))];
    opener += ` Incluye SKUs ${joinEs(orphanBrands)} por ${fmtK(fam.orphanStock)} en ${joinEs(orphanBodegas)} con stock físico, pero sin cliente asignado en este dataset. Por eso el inventario físico de ${fam.sfamilia} no necesariamente reconcilia con su venta mundo-cliente.`;
  }
  return {
    opener,
    suggestions: filterTextualSuggestions([`Qué SKUs de ${fam.sfamilia} hay en ${bodegasOrden[0][0]}`, "Inventario inmovilizado por familia", "Inventario por bodega"]),
    sentrixAction: { label: "Ver inventario", moduleChip: "Inventario", payload: { modulo: "inventario", clientes: [], skus: fam.skus.map(s => s.sku) } },
    derivedModule: "inventario",
    familyResolved: fam.sfamilia,
  };
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 6 · _warehouseInvAgg · agregación física por bodega (replica las fórmulas
// EXACTAS de _aggregateBySucursal de C4 · totalStock, inmovilizadoDef2, dohPromedio)
// para que la comparación reconcilie con el dive de bodega. No se reutiliza el
// closure de C4 (no tocar C4); se replica y se verifica reconciliación por test.
// ════════════════════════════════════════════════════════════════════════════
function _warehouseInvAgg(scenarioId, sucursal) {
  const inv = FEATURE_ENTITY_COMPARISON ? applyScenarioToSkuInventario(scenarioId) : skuInventario;
  const skus = inv.filter(s => s.bodega === sucursal);
  const brandsWithClient = new Set();
  for (const c of clientesMargen) { if (c.marca) brandsWithClient.add(c.marca); }
  const totalStock = skus.reduce((a, s) => a + s.stockUSD, 0);
  const inmovilizadoDef2 = skus.filter(s => s.alerta === "crit" || s.alerta === "warn" || s.rotacion < 2).reduce((a, s) => a + s.stockUSD, 0);
  const dohPromedio = skus.length ? +(skus.reduce((a, s) => a + s.doh, 0) / skus.length).toFixed(0) : 0;
  const famStock = {};
  for (const s of skus) famStock[s.sfamilia] = (famStock[s.sfamilia] || 0) + s.stockUSD;
  const topFamilias = Object.entries(famStock).sort((a, b) => b[1] - a[1]);
  const orphanSkus = skus.filter(s => s.marca && !brandsWithClient.has(s.marca));
  return { sucursal, totalStock, inmovilizadoDef2, dohPromedio, topFamilias, orphanSkus, skus };
}

// Helpers de formato compartidos por los composers de comparación.
function _cmpFmtK(val) {
  if (val == null || isNaN(val)) return "$0";
  if (Math.abs(val) >= 1000) { const k = val / 1000; return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`; }
  return `$${Math.round(val)}`;
}
function _cmpSigned(v) { return (v >= 0 ? "+" : "\u2212") + _cmpFmtK(Math.abs(v)); }
function _cmpRatio(a, b) { if (!b) return 0; const r = a / b; return r >= 1 ? r : 1 / r; }
// Declaración de linaje Makita para una familia con huérfanos (mundo-físico).
function _cmpOrphanCaveat(famAggRow) {
  if (!famAggRow || !famAggRow.orphanStock || !famAggRow.orphanSkus || famAggRow.orphanSkus.length === 0) return "";
  const brands = [...new Set(famAggRow.orphanSkus.map(s => s.marca))];
  const bodegas = [...new Set(famAggRow.orphanSkus.map(s => s.bodega))];
  const joinEs = (arr) => arr.length <= 1 ? (arr[0] || "") : arr.slice(0, -1).join(", ") + " y " + arr[arr.length - 1];
  return `${famAggRow.sfamilia} incluye SKUs ${joinEs(brands)} por ${_cmpFmtK(famAggRow.orphanStock)} (${joinEs(bodegas)}) con stock físico sin cliente asignado — su inventario físico no reconcilia con su venta mundo-cliente.`;
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 6 · composeFamilyComparison · module-aware. modulo==="inventario" →
// mundo-físico (_familyInventoryAgg · incluye Makita + declara); si no → comercial
// (applyScenarioToSfamiliasMargen · mundo-cliente). Veredicto ejecutivo breve.
// Cero número nuevo: todo de los agregadores sellados → reconcilia con el dive.
// ════════════════════════════════════════════════════════════════════════════
function composeFamilyComparison(famA, famB, scenario, modulo) {
  const esInventario = modulo === "inventario";
  if (esInventario) {
    const agg = _familyInventoryAgg(scenario);
    const A = agg[famA], B = agg[famB];
    if (!A || !B) return { opener: `No tengo a ${!A ? famA : famB} en el inventario de este escenario.`, suggestions: filterTextualSuggestions([]), sentrixAction: null, derivedModule: "inventario" };
    const dStock = A.total - B.total;
    const masInmov = A.inmovilizado >= B.inmovilizado ? famA : famB;
    const masStock = A.total >= B.total ? famA : famB;
    const dohA = A.skus.length ? Math.round(A.skus.reduce((s, x) => s + x.doh, 0) / A.skus.length) : 0;
    const dohB = B.skus.length ? Math.round(B.skus.reduce((s, x) => s + x.doh, 0) / B.skus.length) : 0;
    const stockParejo = Math.abs(dStock) / Math.max(A.total, B.total) < 0.1;
    const lead = stockParejo ? `stock parejo, ${masInmov} con más capital atrapado.` : `${masStock} con más stock; ${masInmov} con más capital atrapado.`;
    let opener = `**${famA} vs ${famB}** (inventario) · ${lead}\n\n`;
    opener += `Stock físico: ${_cmpFmtK(A.total)} vs ${_cmpFmtK(B.total)} (Δ ${_cmpSigned(dStock)}). Inmovilizado: ${_cmpFmtK(A.inmovilizado)} vs ${_cmpFmtK(B.inmovilizado)} (${masInmov} peor). DOH: ${dohA} vs ${dohB} días.\n\n`;
    opener += `Veredicto: ${stockParejo ? "inventario similar" : masStock + " concentra más stock"}, pero ${masInmov} tiene más capital inmovilizado.`;
    // Caveat de linaje (decisión 3) · solo en inventario, solo familias con huérfanos.
    const caveats = [_cmpOrphanCaveat(A), _cmpOrphanCaveat(B)].filter(Boolean);
    if (caveats.length) opener += `\n\n${caveats.join(" ")}`;
    return {
      opener,
      suggestions: filterTextualSuggestions([`Qué hay en ${famA}`, `Qué hay en ${famB}`, "Inventario inmovilizado por familia"]),
      sentrixAction: { label: "Ver inventario", moduleChip: "Inventario", payload: { modulo: "inventario", clientes: [], skus: [] } },
      derivedModule: "inventario",
    };
  }
  // ── Comercial · mundo-cliente ──
  const ds = applyScenarioToSfamiliasMargen(scenario);
  const A = ds.find(f => f.sfamilia === famA), B = ds.find(f => f.sfamilia === famB);
  if (!A || !B) return { opener: `No tengo a ${!A ? famA : famB} en la cartera de este escenario.`, suggestions: filterTextualSuggestions([]), sentrixAction: null, derivedModule: "ventas" };
  const dVenta = A.venta - B.venta;
  const dContrib = A.contribucion - B.contribucion;
  const dMargen = A.margen - B.margen;
  const ganaEscala = A.venta >= B.venta ? famA : famB;
  const ganaMargen = A.margen >= B.margen ? famA : famB;
  const margenParejo = Math.abs(dMargen) < 1;   // <1pp = ruido (mismo umbral que composeClientComparison)
  const lead = margenParejo
    ? `${ganaEscala} gana escala, margen parejo.`
    : (ganaEscala === ganaMargen ? `${ganaEscala} domina en escala y eficiencia.` : `${ganaEscala} gana escala, ${ganaMargen} gana margen.`);
  let opener = `**${famA} vs ${famB}** (ventas) · ${lead}\n\n`;
  opener += `Venta: ${_cmpFmtK(A.venta)} vs ${_cmpFmtK(B.venta)} (${ganaEscala} ${_cmpRatio(A.venta, B.venta).toFixed(1)}× · Δ ${_cmpSigned(dVenta)}). Contribución: ${_cmpFmtK(A.contribucion)} vs ${_cmpFmtK(B.contribucion)}. Margen: ${A.margen}% vs ${B.margen}% (${margenParejo ? "parejo" : ganaMargen + " +" + Math.abs(dMargen).toFixed(1) + "pp"}).\n\n`;
  opener += `Veredicto: ${ganaEscala} pesa más en la cartera${margenParejo ? "; márgenes parejos" : "; " + ganaMargen + " rinde mejor por peso vendido"}.`;
  return {
    opener,
    suggestions: filterTextualSuggestions([`Cuánto vende ${famA}`, `Cuánto vende ${famB}`, "Margen por familia"]),
    sentrixAction: { label: "Ver márgenes", moduleChip: "Márgenes", payload: { modulo: "margenes", clientes: [], skus: [] } },
    derivedModule: "margenes",
  };
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 6 · composeWarehouseComparison · inventario (mundo-físico). Lee
// _warehouseInvAgg (reconcilia con el dive de bodega de C4). Veredicto ejecutivo.
// ════════════════════════════════════════════════════════════════════════════
function composeWarehouseComparison(whA, whB, scenario) {
  const A = _warehouseInvAgg(scenario, whA), B = _warehouseInvAgg(scenario, whB);
  const dStock = A.totalStock - B.totalStock;
  const masGrande = A.totalStock >= B.totalStock ? whA : whB;
  const masSano = A.dohPromedio <= B.dohPromedio ? whA : whB;       // menor DOH = más sano
  const masAtrapado = A.inmovilizadoDef2 >= B.inmovilizadoDef2 ? whA : whB;
  // MICRO-FIX FEATURE_CMP_DOH_FIX · el veredicto pega "con DOH crítico" a masAtrapado,
  // así que el umbral debe mirar el DOH PROPIO de masAtrapado, no el máximo de ambas.
  const masAtrapadoDoh = masAtrapado === whA ? A.dohPromedio : B.dohPromedio;
  const dohCritico = FEATURE_CMP_DOH_FIX
    ? (masAtrapadoDoh >= 80)
    : (Math.max(A.dohPromedio, B.dohPromedio) >= 80);
  const masLento = A.dohPromedio >= B.dohPromedio ? whA : whB;
  const lead = `${masGrande} más grande${masSano === masGrande ? " y más sano" : ""}; ${masAtrapado} con más capital atrapado.`;
  let opener = `**${whA} vs ${whB}** (inventario) · ${lead}\n\n`;
  opener += `Stock: ${_cmpFmtK(A.totalStock)} vs ${_cmpFmtK(B.totalStock)} (${masGrande} ${_cmpRatio(A.totalStock, B.totalStock).toFixed(1)}× · Δ ${_cmpSigned(dStock)}). Inmovilizado: ${_cmpFmtK(A.inmovilizadoDef2)} vs ${_cmpFmtK(B.inmovilizadoDef2)} (${masAtrapado} peor). DOH: ${A.dohPromedio} vs ${B.dohPromedio} días${Math.abs(A.dohPromedio - B.dohPromedio) >= 20 ? ` (${masLento} mucho más lento)` : ""}.\n\n`;
  opener += `Veredicto: ${masGrande} concentra más stock${masSano === masGrande ? " y rota mejor" : ""}; ${masAtrapado} tiene más capital inmovilizado${dohCritico ? " con DOH crítico" : ""}.`;
  return {
    opener,
    suggestions: filterTextualSuggestions([`Qué hay en ${whA}`, `Qué hay en ${whB}`, "Inventario por bodega"]),
    sentrixAction: { label: "Ver inventario", moduleChip: "Inventario", payload: { modulo: "inventario", clientes: [], skus: [] } },
    derivedModule: "inventario",
  };
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 8 · _brandRow / _brandInventory · marca desde marcasMargen (estático) e
// inventario físico por marca (suma stockUSD por marca · reconcilia con familia).
// ════════════════════════════════════════════════════════════════════════════
function _brandRow(marca) { return marcasMargen.find(m => m.marca === marca) || null; }
function _brandInventory(marca, scenarioId) {
  const inv = FEATURE_BRAND_AS_ENTITY ? applyScenarioToSkuInventario(scenarioId) : skuInventario;
  const skus = inv.filter(s => s.marca === marca);
  const total = skus.reduce((a, s) => a + s.stockUSD, 0);
  const bodegas = [...new Set(skus.map(s => s.bodega))];
  return { total, bodegas, skus: skus.map(s => s.sku) };
}
// ¿La marca tiene cobertura comercial por cliente? (Makita no · mundo-cliente.)
function _brandHasClientWorld(marca) {
  for (const c of clientesMargen) { if (c.marca === marca) return true; }
  return false;
}
// Formatos de marca: venta/inventario 1 decimal, contribución 2 decimales.
function _bFmt1(v) { return `$${(v / 1000).toFixed(1)}K`; }
function _bFmt2(v) { return `$${(Math.round(v / 10) / 100).toFixed(2)}K`; }

// ════════════════════════════════════════════════════════════════════════════
// CORTE 8 · composeBrandDive · marca como sujeto (espejo de composeFamilyDive).
// Métricas de marcasMargen (estático), composición por SKUs, inventario físico,
// declaración de linaje mundo-marca. Makita COMPLETA (35.5%) + nota de linaje §4.
// ════════════════════════════════════════════════════════════════════════════
function composeBrandDive(marca, scenarioId, opts = {}) {
  const subFocus = (opts && opts.subFocus) || null;
  const r = _brandRow(marca);
  if (!r) {
    return { opener: `No tengo a ${marca} en la vista de marca de este dataset.`, suggestions: filterTextualSuggestions([]), brandResolved: null, derivedModule: "margenes" };
  }
  const joinEs = (arr) => arr.length <= 1 ? (arr[0] || "") : arr.slice(0, -1).join(", ") + " y " + arr[arr.length - 1];
  const skusDir = skusMargen.filter(s => s.marca === marca).map(s => s.nombre);
  const invAgg = _brandInventory(marca, scenarioId);
  const sinCliente = !_brandHasClientWorld(marca);   // Makita

  // ── subFocus margen ──
  if (subFocus === "margen") {
    let op = `${marca} tiene ${r.margen.toFixed(1)}% de margen (vista de marca, estática).`;
    if (sinCliente) op += ` ${marca} está completa en la vista de marca (venta, margen, contribución e inventario); lo que no tiene en este dataset es cobertura comercial por cliente.`;
    return { opener: op, suggestions: filterTextualSuggestions([`Qué vende ${marca}`, `Qué inventario tiene ${marca}`]), brandResolved: marca, derivedModule: "margenes" };
  }
  // ── subFocus inventario ──
  if (subFocus === "inventario") {
    const op = `Inventario de ${marca}: ${_bFmt1(invAgg.total)} (${joinEs(invAgg.skus)}) en ${joinEs(invAgg.bodegas)}.`;
    return { opener: op, suggestions: filterTextualSuggestions([`Qué vende ${marca}`, `Qué margen tiene ${marca}`]), brandResolved: marca, derivedModule: "inventario" };
  }
  // ── subFocus skus ──
  if (subFocus === "skus") {
    const op = `${marca} agrupa ${skusDir.length} ${skusDir.length === 1 ? "SKU" : "SKUs"}: ${joinEs(skusDir)}.`;
    return { opener: op, suggestions: filterTextualSuggestions([`Qué inventario tiene ${marca}`, `Qué margen tiene ${marca}`]), brandResolved: marca, derivedModule: "ventas" };
  }
  // ── Dive completo ──
  let opener = `${marca} (marca): vende ${_bFmt1(r.venta)} con ${_bFmt2(r.contribucion)} de contribución (margen ${r.margen.toFixed(1)}%). ${skusDir.length} ${skusDir.length === 1 ? "SKU" : "SKUs"}: ${joinEs(skusDir)}. Inventario físico ${_bFmt1(invAgg.total)} en ${joinEs(invAgg.bodegas)}.`;
  // Declaración de linaje (§3/§4).
  if (sinCliente) {
    opener += ` Nota: ${marca} está completa en la vista de marca, pero no tiene cobertura comercial por cliente en este dataset — por eso aparece en mundo-marca pero no en mundo-cliente.`;
  } else {
    opener += ` (Cifras de la vista de marca, estáticas — pueden no reconciliar con la venta por clientes scenario-aware: son linajes distintos.)`;
  }
  return {
    opener,
    suggestions: filterTextualSuggestions([`Qué margen tiene ${marca}`, `Qué inventario tiene ${marca}`, `Qué SKUs forman ${marca}`]),
    sentrixAction: { label: "Ver márgenes", moduleChip: "Márgenes", payload: { modulo: "margenes", clientes: [], skus: skusDir } },
    brandResolved: marca,
    derivedModule: "margenes",
  };
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 8 · composeBrandComparison · marca vs marca (mundo-marca estático · espejo
// del C6 comercial). Dimensiones venta/contribución/margen. Makita con datos reales.
// ════════════════════════════════════════════════════════════════════════════
function composeBrandComparison(brandA, brandB, scenarioId) {
  const A = _brandRow(brandA), B = _brandRow(brandB);
  if (!A || !B) return { opener: `No tengo a ${!A ? brandA : brandB} en la vista de marca.`, suggestions: filterTextualSuggestions([]), sentrixAction: null, derivedModule: "margenes" };
  const dVenta = A.venta - B.venta;
  const dContrib = A.contribucion - B.contribucion;
  const dMargen = A.margen - B.margen;
  const ganaEscala = A.venta >= B.venta ? brandA : brandB;
  const ganaMargen = A.margen >= B.margen ? brandA : brandB;
  const margenParejo = Math.abs(dMargen) < 1;
  const lead = margenParejo
    ? `${ganaEscala} gana escala, margen parejo.`
    : (ganaEscala === ganaMargen ? `${ganaEscala} domina en escala y eficiencia.` : `${ganaEscala} gana escala, ${ganaMargen} gana margen.`);
  let opener = `**${brandA} vs ${brandB}** (vista de marca) · ${lead}\n\n`;
  opener += `Venta: ${_bFmt1(A.venta)} vs ${_bFmt1(B.venta)} (${ganaEscala} ${_cmpRatio(A.venta, B.venta).toFixed(1)}× · Δ ${(dVenta >= 0 ? "+" : "\u2212") + _bFmt1(Math.abs(dVenta))}). Contribución: ${_bFmt2(A.contribucion)} vs ${_bFmt2(B.contribucion)}. Margen: ${A.margen.toFixed(1)}% vs ${B.margen.toFixed(1)}% (${margenParejo ? "parejo" : ganaMargen + " +" + Math.abs(dMargen).toFixed(1) + "pp"}).\n\n`;
  opener += `Veredicto: ${ganaEscala} pesa más${margenParejo ? "; márgenes parejos" : "; " + ganaMargen + " rinde mejor por peso vendido"}.`;
  // Linaje: si alguna no tiene mundo-cliente (Makita), declararlo.
  const sinCli = [brandA, brandB].filter(b => !_brandHasClientWorld(b));
  if (sinCli.length) opener += `\n\n${sinCli.join(" y ")} está completa en la vista de marca pero sin cobertura comercial por cliente — la comparación es mundo-marca (estática), no reconcilia con el mundo-cliente scenario-aware.`;
  return {
    opener,
    suggestions: filterTextualSuggestions([`Háblame de ${brandA}`, `Háblame de ${brandB}`, "Margen por marca"]),
    sentrixAction: { label: "Ver márgenes", moduleChip: "Márgenes", payload: { modulo: "margenes", clientes: [], skus: [] } },
    derivedModule: "margenes",
  };
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 9 · helpers de detección · lineage self-knowledge + honestidad predictiva.
// ════════════════════════════════════════════════════════════════════════════
function _invLineageQuery(norm) {
  if (/\b(mundo-?cliente|mundo cliente|mundo-?fisico|mundo fisico)\b/.test(norm) && /\binventario\b/.test(norm)) return true;
  if (/\bpor que\b/.test(norm) && /\bmateriales\b/.test(norm) && /\b(makita|venta|inventario|cliente)\b/.test(norm)) return true;
  if (/\b(no coincide|no cuadra|no reconcilia|no calza|difiere)\b/.test(norm) && /\b(venta|inventario)\b/.test(norm)) return true;
  if (/\b(dato directo|directo o inferido|directo o derivado|que dato es directo)\b/.test(norm) && /\binventario\b/.test(norm)) return true;
  if (/\b(que no puedes calcular|que no podes calcular|no puedes calcular|que no sabes)\b/.test(norm) && /\binventario\b/.test(norm)) return true;
  return false;
}
function _invLineageKind(norm) {
  if (/\b(mundo-?cliente|mundo cliente|mundo-?fisico|mundo fisico)\b/.test(norm)) return "world";
  if (/\bmakita\b/.test(norm) || (/\bmateriales\b/.test(norm) && /\bcliente\b/.test(norm))) return "makita";
  if (/\b(no coincide|no cuadra|no reconcilia|no calza|difiere)\b/.test(norm)) return "reconcile";
  if (/\b(dato directo|directo o inferido|directo o derivado|que dato es directo)\b/.test(norm)) return "direct_vs_derived";
  if (/\b(no puedes calcular|que no sabes|no podes calcular)\b/.test(norm)) return "limits";
  return "world";
}
function _invPredictiveQuery(norm) {
  if (/\b(se quedara sin stock|sin stock el proximo|se agotara|se agota primero|quiebre de stock|stockout)\b/.test(norm)) return true;
  if (/\b(demanda futura|proximo mes|proxima semana|el proximo trimestre)\b/.test(norm) && /\b(stock|inventario|sku|skus|bodega)\b/.test(norm)) return true;
  if (/\belasticidad\b/.test(norm)) return true;
  if (/\bmix optimo\b/.test(norm) || (/\bmix\b/.test(norm) && /\b(optim\w*|reducir (el )?inventario)\b/.test(norm))) return true;
  if (/\b(liquidar|vender)\b/.test(norm) && /\b(todo el inventario|todo el stock|el inventario completo)\b/.test(norm)) return true;
  return false;
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 9 · detectInventoryPremium · router de inventario físico. Intercepta las
// consultas físicas ANTES del template comercial (world-lock) y las resuelve en la
// capa premium. NO roba los dives que ya andan (bodega sola → C4; familia-inventario
// → C5; marca-inventario → C8; familia×bodega→SKUs → C5). Flag OFF → null.
// ════════════════════════════════════════════════════════════════════════════
function detectInventoryPremium(text, context) {
  if (!FEATURE_INVENTORY_PREMIUM || !text || typeof text !== "string") return null;
  const norm = normalizeText(text);

  if (_invLineageQuery(norm)) return { type: "inv_premium", mode: "lineage", lineageKind: _invLineageKind(norm) };
  if (_invPredictiveQuery(norm)) return { type: "inv_premium", mode: "predictive" };

  const whs = detectAllWarehousesInText(text);
  const wh = whs[0] || null;
  const brand = (FEATURE_BRAND_AS_ENTITY && typeof detectBrandInText === "function") ? detectBrandInText(text) : null;
  const fams = detectAllFamiliesInText(text);
  const fam = fams[0] || null;
  // Palabra de detalle de inventario (familias/SKUs/críticos/dominante).
  const detailKw = /\b(familias?|skus?|criticos?|domina|dominante|concentra|concentr\w*|alertas?)\b/.test(norm);
  const invSignal = /\b(inventario|inventarios|stock|stocks|inmovilizad\w*|bodega|bodegas|doh|rotacion)\b/.test(norm) || /\bskus?\b/.test(norm) || (wh && detailKw);
  if (!invSignal) return null;

  // WS2.6 · cruce explícito a comercial (declarado).
  if (/\b(impacta|impacto|afecta|afectan)\b/.test(norm) && /\b(margen|contribucion|rentabilidad)\b/.test(norm) && /\b(inventario|stock|inmovilizad\w*)\b/.test(norm)) {
    return { type: "inv_premium", mode: "cross_commercial" };
  }

  // WS3.8 · marca × bodega (fix #5) · gana sobre familia.
  if (brand && wh) return { type: "inv_premium", mode: "brand_warehouse", brand, warehouse: wh };

  // WS3.7 / WS3.9 · bodega + sub-foco.
  if (wh) {
    const wantsFamilias = /\bfamilias?\b/.test(norm);
    const wantsDominant = /\b(domina|dominante|concentra|concentr\w*|mayor stock|mas stock)\b/.test(norm);
    const wantsCriticos = /\bcriticos?\b/.test(norm) || /\balertas?\b/.test(norm);
    const wantsSkus = /\bskus?\b/.test(norm);
    const wantsImmob = /\b(capital inmovilizado|inmovilizad\w*)\b/.test(norm);
    if (fam && wantsSkus) return null;                       // familia×bodega→SKUs ya lo maneja C5
    if (wantsDominant) return { type: "inv_premium", mode: "warehouse_dominant", warehouse: wh };
    if (wantsFamilias) return { type: "inv_premium", mode: "warehouse_families", warehouse: wh };
    if (wantsCriticos) return { type: "inv_premium", mode: "warehouse_criticos", warehouse: wh };
    if (wantsImmob) return { type: "inv_premium", mode: "warehouse_immobilized", warehouse: wh };
    if (wantsSkus && !fam) return { type: "inv_premium", mode: "warehouse_skus", warehouse: wh };
    return null;                                             // bodega sola → C4 warehouse_dive
  }

  // WS1.4 · total global (sin entidad).
  if (!brand && !fam) {
    const immob = /\b(inmovilizad\w*|capital)\b/.test(norm);
    const isTotal = /\b(total|totales|global|globales)\b/.test(norm) || /\b(cuanto|cuanta)\b[\s\S]*\binventario\b/.test(norm) || /\binventario\b[\s\S]*\b(tengo|hay)\b/.test(norm);
    if (isTotal) return { type: "inv_premium", mode: immob ? "immobilized_total" : "total" };
  }
  return null;
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 9 · composeInventoryPremium · todas las cifras desde la capa premium
// (applyScenarioToSkuInventario · mundo-físico). stockUSD/inmovilizado crudos →
// SIEMPRE vía fmtK (÷1000). inmovilizadoDef2 = alerta crit/warn ∨ rotación<2.
// ════════════════════════════════════════════════════════════════════════════
function composeInventoryPremium(intent, scenarioId) {
  if (!FEATURE_INVENTORY_PREMIUM || !intent) return null;
  const fmtK = (v) => "$" + (v / 1000).toFixed(1) + "K";
  const joinEs = (a) => a.length <= 1 ? (a[0] || "") : a.slice(0, -1).join(", ") + " y " + a[a.length - 1];
  const _isImmob = (s) => s.alerta === "crit" || s.alerta === "warn" || s.rotacion < 2;
  const inv = applyScenarioToSkuInventario(scenarioId);
  const m = intent.mode;
  const invSent = { label: "Ver inventario", moduleChip: "Inventario", payload: { modulo: "inventario", clientes: [], skus: [] } };

  if (m === "lineage") {
    let op;
    switch (intent.lineageKind) {
      case "makita":
        op = "Es linaje, no inconsistencia: Makita está completa en mundo-marca y mundo-físico — tiene inventario real (MAK-COMP-AIR y MAK-SAW18V en Antofagasta), pero no tiene cobertura comercial por cliente en este dataset. Por eso Materiales tiene inventario Makita pero no venta-cliente de Makita; no es que falte un cliente como Falabella, es que ese linaje no existe aquí."; break;
      case "reconcile":
        op = "Son dos linajes distintos: la venta de Materiales viene de mundo-cliente (scenario-aware) y su inventario viene de mundo-físico (stock real por SKU). No se cruzan automáticamente. El inventario sí reconcilia por marca (Bosch + Makita = Materiales); la venta comercial no se cruza con el stock."; break;
      case "direct_vs_derived":
        op = "Dato directo del inventario: stockUSD (valor en bodega) y DOH (días de cobertura), medidos por SKU. Dato derivado: el capital inmovilizado (calculado sobre alerta crítica/warning o rotación<2) y la rotación. Lo directo lo leo; lo derivado lo calculo con una definición declarada."; break;
      case "limits":
        op = "Sobre inventario todavía no calculo: predicción de demanda futura (qué bodega o SKU se quedará sin stock), elasticidad, ni mix óptimo para reducir stock sin perder margen — no tengo modelo para eso. Sí te doy stock actual, rotación, DOH, capital inmovilizado y stock crítico."; break;
      case "world":
      default:
        op = "El inventario vive en mundo-físico (stock real por SKU, por bodega); cliente y familia comercial viven en mundo-cliente scenario-aware. Son linajes distintos: el inventario no se mueve con el escenario igual que la venta."; break;
    }
    return { opener: op, suggestions: filterTextualSuggestions(["Cuánto inventario total tengo", "Capital inmovilizado total"]), sentrixAction: null, derivedModule: "inventario" };
  }

  if (m === "predictive") {
    return { opener: "No tengo modelo de demanda futura, elasticidad ni optimización de mix para calcular eso de forma determinística. Puedo mostrarte rotación actual, DOH, stock crítico o escenarios simples (bonanza/tensión/crisis).", suggestions: filterTextualSuggestions(["Cuáles son los SKUs críticos", "Capital inmovilizado total"]), sentrixAction: invSent, derivedModule: "inventario" };
  }

  if (m === "cross_commercial") {
    const totStock = inv.reduce((a, s) => a + s.stockUSD, 0);
    const immob = inv.filter(_isImmob).reduce((a, s) => a + s.stockUSD, 0);
    return { opener: `Cruzo mundo-físico con mundo-cliente para leer impacto económico; las cifras vienen de linajes distintos. En lo físico: inventario total ${fmtK(totStock)}, de eso ${fmtK(immob)} de capital inmovilizado (alerta o rotación<2). Ese capital atrapado es contribución que no circula; el impacto fino por cliente baja a cada cuenta, que vive en el otro linaje.`, suggestions: filterTextualSuggestions(["Capital inmovilizado por bodega", "Cuáles SKUs liquido primero"]), sentrixAction: invSent, derivedModule: "inventario" };
  }

  if (m === "total") {
    const totStock = inv.reduce((a, s) => a + s.stockUSD, 0);
    const nB = new Set(inv.map(s => s.bodega)).size;
    return { opener: `Inventario total físico: ${fmtK(totStock)} en ${nB} bodegas.`, suggestions: filterTextualSuggestions(["Capital inmovilizado total", "Qué bodega concentra más inventario", "Cuáles son los SKUs críticos"]), sentrixAction: invSent, derivedModule: "inventario" };
  }
  if (m === "immobilized_total") {
    const totStock = inv.reduce((a, s) => a + s.stockUSD, 0);
    const immob = inv.filter(_isImmob).reduce((a, s) => a + s.stockUSD, 0);
    const pct = totStock ? (immob / totStock * 100).toFixed(1) : "0";
    return { opener: `Capital inmovilizado total: ${fmtK(immob)} (${pct}% del inventario físico de ${fmtK(totStock)}) · definición: SKUs con alerta crítica/warning o rotación menor a 2.`, suggestions: filterTextualSuggestions(["Qué bodega tiene más capital inmovilizado", "Cuáles son los SKUs críticos"]), sentrixAction: invSent, derivedModule: "inventario" };
  }

  // marca × bodega (fix #5).
  if (m === "brand_warehouse") {
    const wh = intent.warehouse;
    const skus = inv.filter(s => s.marca === intent.brand && s.bodega === wh);
    if (!skus.length) return { opener: `No tengo SKUs de ${intent.brand} en ${wh}.`, suggestions: filterTextualSuggestions([`Qué inventario tiene ${intent.brand}`]), sentrixAction: null, derivedModule: "inventario" };
    const totB = skus.reduce((a, s) => a + s.stockUSD, 0);
    return { opener: `SKUs de ${intent.brand} en ${wh}: ${joinEs(skus.map(s => `${s.sku} (${fmtK(s.stockUSD)})`))} · total ${fmtK(totB)}.`, suggestions: filterTextualSuggestions([`Qué inventario tiene ${intent.brand}`, `Qué familias hay en ${wh}`]), sentrixAction: { label: "Ver inventario", moduleChip: "Inventario", payload: { modulo: "inventario", clientes: [], skus: skus.map(s => s.sku) } }, derivedModule: "inventario" };
  }

  // bodega → detalle (scoped).
  const wh = intent.warehouse;
  const inWh = inv.filter(s => s.bodega === wh);
  if (!inWh.length) return { opener: `No tengo inventario registrado en ${wh}.`, suggestions: filterTextualSuggestions([]), sentrixAction: null, derivedModule: "inventario" };
  const famAgg = {};
  for (const s of inWh) famAgg[s.sfamilia] = (famAgg[s.sfamilia] || 0) + s.stockUSD;
  const famRanked = Object.entries(famAgg).sort((a, b) => b[1] - a[1]);
  const totWh = inWh.reduce((a, s) => a + s.stockUSD, 0);

  if (m === "warehouse_families") {
    return { opener: `Familias en ${wh}: ${famRanked.map(([f, v]) => `${f} ${fmtK(v)}`).join(" · ")}.`, suggestions: filterTextualSuggestions([`Qué familia domina el inventario de ${wh}`, `Cuáles son los SKUs críticos de ${wh}`]), sentrixAction: invSent, derivedModule: "inventario" };
  }
  if (m === "warehouse_dominant") {
    const [f, v] = famRanked[0];
    return { opener: `En ${wh}, ${f} domina el inventario con ${fmtK(v)} (${(v / totWh * 100).toFixed(0)}% de ${fmtK(totWh)}).`, suggestions: filterTextualSuggestions([`Qué familias hay en ${wh}`, `Cuáles son los SKUs críticos de ${wh}`]), sentrixAction: invSent, derivedModule: "inventario" };
  }
  if (m === "warehouse_skus") {
    const ordered = [...inWh].sort((a, b) => b.stockUSD - a.stockUSD);
    return { opener: `SKUs en ${wh}: ${ordered.map(s => `${s.sku} ${fmtK(s.stockUSD)}`).join(" · ")}.`, suggestions: filterTextualSuggestions([`Cuáles son los SKUs críticos de ${wh}`, `Qué familias hay en ${wh}`]), sentrixAction: invSent, derivedModule: "inventario" };
  }
  if (m === "warehouse_criticos") {
    const crit = inWh.filter(s => s.alerta === "crit" || s.alerta === "warn");
    const op = crit.length ? `SKUs críticos en ${wh}: ${crit.map(s => `${s.sku} (${s.alerta}, ${fmtK(s.stockUSD)})`).join(" · ")}.` : `${wh} no tiene SKUs en alerta crítica o warning.`;
    return { opener: op, suggestions: filterTextualSuggestions([`Qué familias hay en ${wh}`, `Capital inmovilizado de ${wh}`]), sentrixAction: invSent, derivedModule: "inventario" };
  }
  if (m === "warehouse_immobilized") {
    const immobWh = inWh.filter(_isImmob).reduce((a, s) => a + s.stockUSD, 0);
    const doh = Math.round(inWh.reduce((a, s) => a + s.doh, 0) / inWh.length);
    return { opener: `Capital inmovilizado en ${wh}: ${fmtK(immobWh)} sobre un inventario de ${fmtK(totWh)} (SKUs con alerta o rotación<2) · DOH promedio ${doh} días.`, suggestions: filterTextualSuggestions([`Cuáles son los SKUs críticos de ${wh}`, `Qué familias hay en ${wh}`]), sentrixAction: invSent, derivedModule: "inventario" };
  }

  return null;
}

// ═══════════════════════════════════════════════════════════════════════
// BRIEF #46 · composeClientContributionRanking · Ferrari ranking cliente
//
// Activado por intent "client_contribution_ranking" cuando F9 emite
// __economic_value_query__ SIN concept_sku_query.
// Captura: "¿qué clientes dan más?", "¿quiénes aportan más al margen?",
// "¿qué cuentas rinden más?".
//
// CERO HARDCODING: cifras runtime de clientesMargen (contribucion + venta).
// ═══════════════════════════════════════════════════════════════════════
function composeClientContributionRanking(scenarioId) {
  // ── 1. Helpers formato
  const fmtM = (val) => {
    if (val == null || isNaN(val)) return "$0M";
    return `$${(val / 1000).toFixed(2)}M`;
  };

  // ── 2. Ranking runtime sobre clientesMargen
  // clientesMargen tiene contribucion en miles USD. Ordenar desc.
  const ranked = [...clientesMargen]
    .filter(c => c.tipo === "cliente")
    .sort((a, b) => b.contribucion - a.contribucion);

  if (ranked.length === 0) {
    return buildResponseContract({
      opener: "El portafolio no registra clientes con contribución activa en el dataset actual.\n\n*Confianza alta.*",
      // BRIEF N-bis · Tipo A puro · filtradas
      suggestions: filterTextualSuggestions(["¿Qué productos dejan más plata?", "¿Cómo está la rotación?", "Cuál es la cobertura"]),
      sentrixAction: null,
      decision: null,
      evidence: { client_count: 0 },
      focus: "client_contribution_empty",
      confidence: "alta",
      materialMetrics: [],
      reasoningPattern: "client_contribution_ranking",
      suggestedNextActions: [],
    });
  }

  const totalContrib = ranked.reduce((s, c) => s + c.contribucion, 0);
  const top3 = ranked.slice(0, 3);
  const top3Contrib = top3.reduce((s, c) => s + c.contribucion, 0);
  const pctTop3 = ((top3Contrib / totalContrib) * 100).toFixed(0);

  // ── 3. EVIDENCIA · ranking visual
  const rankingLines = top3.map(c => {
    const pct = ((c.contribucion / totalContrib) * 100).toFixed(0);
    return `${c.nombre.padEnd(14, " ")} → Contribución ${fmtM(c.contribucion)} · ${pct}% del total · Margen ${c.margen}% · Carga ${c.pctRebate}%`;
  }).join("\n");

  const headerLine = `Los ${ranked.length} clientes aportan ${fmtM(totalContrib)} de contribución mensual agregada. Top 3 concentra ${pctTop3}%.`;
  const evidencia = `${headerLine}\n\nRanking por contribución mensual:\n${rankingLines}`;

  // ── 4. LECTURA causal
  const top1 = top3[0];
  const top1pct = ((top1.contribucion / totalContrib) * 100).toFixed(0);
  const bottom = ranked[ranked.length - 1];
  const ratio = bottom ? (top1.contribucion / Math.max(bottom.contribucion, 1)).toFixed(1) : "1";

  // Detectar cliente con margen alto + contribución alta (estrella) vs
  // cliente con margen bajo + contribución alta (palanca riesgosa)
  const margenAlto = top3.find(c => c.margen >= 25);
  const margenBajo = top3.find(c => c.margen < 23);

  let lecturaCausal = `${top1.nombre} concentra ${top1pct}% de la contribución (${fmtM(top1.contribucion)}), ${ratio}x lo que aporta ${bottom.nombre}.`;
  if (margenAlto && margenBajo && margenAlto !== margenBajo) {
    lecturaCausal += ` ${margenAlto.nombre} (${margenAlto.margen}% margen) y ${margenBajo.nombre} (${margenBajo.margen}% margen) coexisten en el top: el segundo aporta volumen pero a costo de carga comercial (${margenBajo.pctRebate}%) sobre la mejor práctica interna.`;
  } else if (margenAlto) {
    lecturaCausal += ` ${margenAlto.nombre} opera con margen ${margenAlto.margen}%, ${margenAlto.margen >= 25 ? "por encima" : "alineado"} del benchmark cartera (30.1%).`;
  }

  // ── 5. FOCO accionable
  const ascendiendo = ranked.find(c => c.margen >= 28 && c.pctRebate <= 2.5);
  const recuperable = ranked.find(c => c.pctRebate >= 4.5);
  let focoText;
  if (ascendiendo && recuperable) {
    focoText = `Dos mecanismos disponibles: ${ascendiendo.nombre} opera con margen sano (${ascendiendo.margen}%, carga ${ascendiendo.pctRebate}%) · ${recuperable.nombre} concentra carga sobre benchmark (${recuperable.pctRebate}% vs 3%) · espacio comercial cuantificable.`;
  } else if (recuperable) {
    focoText = `${recuperable.nombre} opera con carga sobre mejor práctica (${recuperable.pctRebate}%) · la palanca comercial sobre este cliente tiene espacio cuantificable de recuperación de contribución.`;
  } else {
    focoText = `${top1.nombre} opera como cuenta ancla del top 3 · la base de diversificación está concentrada en pocas cuentas.`;
  }

  const confianza = `*Confianza alta · ranking determinístico sobre cartera mensual.*`;
  const opener = `${evidencia}\n\n${lecturaCausal}\n\n${focoText}\n\n${confianza}`;

  // ── 6. Suggestions + SentrixAction
  const suggestions = [
    `Profundizar en ${top1.nombre}`,
    margenBajo ? `Por qué ${margenBajo.nombre} tiene margen bajo` : `Comparar top 3 cuentas`,
    "Qué productos dejan más plata",
  ];

  const sentrixAction = {
    label: `Ver ranking de ${ranked.length} clientes`,
    moduleChip: "Margenes",
    payload: {
      modulo: "margenes",
      clientes: top3.map(c => c.nombre),
      skus: [],
      mechanismBanner: "Ranking por contribución mensual",
    },
  };

  return buildResponseContract({
    opener,
    // BRIEF N-bis · Tipo A puro · filtradas (suggestions: array dinámico construido arriba)
    suggestions: filterTextualSuggestions(suggestions.slice(0, 3)),
    sentrixAction,
    decision: top1.nombre,
    evidence: {
      client_count: ranked.length,
      total_contribucion_M: +totalContrib / 1000,
      top_cliente: top1.nombre,
      top_cliente_contribucion_pct: +top1pct,
      top3_concentration_pct: +pctTop3,
    },
    focus: "client_contribution_ranking",
    confidence: "alta",
    // BRIEF CONEXION1 (ARCO B) · conectar al hilo de evidencia · clientList + materialMetrics per-entidad
    // EXACTAMENTE lo que muestra la tabla (top3 · c.nombre · fmtM(c.contribucion)) · CERO recompute · CERO cifra nueva.
    // (Reemplaza el materialMetrics de resumen [{label,source}] · verificado NO consumido para render en este pattern.)
    clientList: top3.map(c => _buildEntityId("client", c.nombre)),
    materialMetrics: top3.map(c => `${c.nombre}: ${fmtM(c.contribucion)} de contribución`),
    reasoningPattern: "client_contribution_ranking",
    suggestedNextActions: [
      { type: "drill_top_client", clientName: top1.nombre },
      { type: "review_high_load", clientName: recuperable ? recuperable.nombre : null },
      { type: "compare_top3", count: 3 },
    ],
  });
}

// ═══════════════════════════════════════════════════════
// BRIEF #15 · Mechanism Response Composer (4 movimientos)
// ═══════════════════════════════════════════════════════

function composeMechanismResponse(mechanismId, scenarioId) {
  const scan = scanMechanisms(scenarioId);
  const m = scan[mechanismId];

  if (!m || !m.triggered) {
    return composeMechanismInactiveResponse(mechanismId, scan);
  }

  if (mechanismId === "commercial_erosion") {
    return composeCommercialErosionResponse(m, scan, scenarioId);
  }
  if (mechanismId === "quality_of_growth_deterioration") {
    return composeQualityGrowthDeteriorationResponse(m, scan, scenarioId);
  }
  if (mechanismId === "customer_dependency_risk") {
    return composeCustomerDependencyRiskResponse(m, scan, scenarioId);
  }

  return composeMechanismInactiveResponse(mechanismId, scan);
}

function composeCommercialErosionResponse(m, scan, scenarioId) {
  // BRIEF #22 · Estructura tripartita Evidencia + Lectura + Foco.
  // Preserva cifras determinísticas del aggregate (recuperable_total_K,
  // recuperable_at_target_3_5 por instance) y campos del dataset
  // (carga_pct, margen_pct, contribucion_M, ventas_M).
  const top3 = m.instances.slice(0, 3);
  const top_instance = top3[0];

  // ── Helpers formato (preservan R2 magnitud absoluta).
  // fmtK omite decimal cuando el valor es entero múltiplo de 1000.
  const fmtK = (val) => {
    if (val >= 1000) {
      const k = val / 1000;
      return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`;
    }
    return `$${Math.round(val)}`;
  };
  const fmtM = (val) => `$${val.toFixed(2)}M`;

  // ── EVIDENCIA · ranking estructurado con cifras canónicas
  const rankingLines = top3.map(inst =>
    `${inst.clientName.padEnd(12, " ")} → Margen ${inst.margen_pct}% | Ventas ${fmtM(inst.ventas_M)} | Contribución ${fmtM(inst.contribucion_M)} | Carga ${inst.carga_pct}%`
  ).join("\n");

  const cuentasWord = top3.length === 1 ? "cuenta" : "cuentas";
  const evidencia = `${top3.length} ${cuentasWord} Tier 1 con margen bajo benchmark pero contribución alta:\n\n${rankingLines}`;

  // ── LECTURA · interpretación causal desde datos
  const totalContribTier = top3.reduce((sum, i) => sum + i.contribucion_M, 0);
  const pctSales = m.aggregate.pct_of_total_sales;
  const margenes = top3.map(i => i.margen_pct);
  const cargas = top3.map(i => i.carga_pct);
  const rangoMargen = margenes.length === 1
    ? `${margenes[0]}%`
    : `${Math.min(...margenes).toFixed(1)}% y ${Math.max(...margenes).toFixed(1)}%`;
  const rangoCarga = cargas.length === 1
    ? `${cargas[0]}%`
    : `${Math.min(...cargas).toFixed(1)}% y ${Math.max(...cargas).toFixed(1)}%`;
  const bestPractice = top_instance.bestPractice_pct || 3.0;

  const _voz2 = (typeof VOZ2_ENABLED !== "undefined" && VOZ2_ENABLED);
  const lectura = _voz2
    ? `Las ${top3.length} ${cuentasWord} aportan ${fmtM(totalContribTier)} al año (${pctSales}% de las ventas de la cartera), pero todas rinden por debajo del promedio de la cartera (30.1%). La diferencia se concentra en la carga comercial, que está entre ${rangoCarga} y por encima de lo sano internamente (${bestPractice}%). Cada punto adicional en esa carga reduce el aporte que la cuenta podría generar.`
    : `Las ${top3.length} ${cuentasWord} sostienen ${fmtM(totalContribTier)} anuales en contribución agregada (${pctSales}% del total de ventas cartera) pero operan con márgenes entre ${rangoMargen}, todos bajo el benchmark de cartera (30.1%). La presión sobre el margen unitario proviene de carga comercial alta (${rangoCarga}, sobre la mejor práctica interna de ${bestPractice}%). Cada punto de carga sobre la mejor práctica se traduce directamente en contribución que no se captura.`;

  // ── FOCO · acción accionable con cliente líder + recuperable
  // NOTA · recuperable_at_target_3_5 viene en USD raw. recuperable_total_K
  // viene en unidades K (canónico aggregate). Convertir a USD antes de fmtK.
  const recuperablePalanca = top_instance.recuperable_at_target_3_5;
  const recuperableTotalUSD = m.aggregate.recuperable_total_K * 1000;
  const otros = top3.slice(1).map(i => i.clientName).join(" y ");

  let focoText = `Mecanismo disponible: ${top_instance.clientName} concentra mayor materialidad (${fmtM(top_instance.contribucion_M)}) y mayor gap de carga (${top_instance.carga_pct}% vs 3.5%) · la palanca de renegociación opera sobre ese cliente. Una reducción gradual desde ${top_instance.carga_pct}% hacia 3.5% recuperaría aproximadamente ${fmtK(recuperablePalanca)} anuales sin afectar volumen presente.`;
  if (otros) {
    focoText += ` La misma lógica progresiva sobre ${otros} liberaría aproximadamente ${fmtK(recuperableTotalUSD)} agregados de contribución.`;
  }

  const foco = `${focoText}`;

  // ── Confianza
  const confianza = `*Confianza alta · las ${top3.length} instancias y la materialidad son determinísticas sobre el escenario activo.*`;

  const opener = `${evidencia}\n\n${lectura}\n\n${foco}\n\n${confianza}`;

  // ── Suggestions accionables (entidades reales)
  const suggestions = [
    `Cómo arranco la renegociación con ${top_instance.clientName}`,
    `Cuál es el impacto exacto de bajar carga 1pp`,
    `Profundizar en ${top_instance.clientName}`,
  ];

  // BRIEF #16 · acción Sentrix contextual (preservado)
  const sentrixAction = composeSentrixAction("mechanism_commercial_erosion", {
    instances: m.instances,
  });

  // BRIEF #26-quinquies-B · enriquecimiento con contrato v1.
  // Usa nombres REALES de campos del composer (clientName, contribucion_M,
  // carga_pct, recuperable_at_target_3_5, m.aggregate.recuperable_total_K).
  return buildResponseContract({
    opener,
    // BRIEF N-bis · Tipo A puro · suggestions filtradas
    suggestions: filterTextualSuggestions(suggestions),
    sentrixAction,
    decision: top_instance.clientName,
    evidence: {
      cliente_principal: top_instance.clientName,
      margen_pct: top_instance.margen_pct,
      benchmark_margen: 30.1,
      carga_actual: top_instance.carga_pct,
      best_practice_carga: 3.5,
      gap_carga_pp: +(top_instance.carga_pct - 3.5).toFixed(1),
      contribucion_principal_M: top_instance.contribucion_M,
      recuperable_principal_USD: top_instance.recuperable_at_target_3_5,
      recuperable_agregado_K: m.aggregate.recuperable_total_K,
      top3_clientes: top3.map(t => t.clientName),
    },
    focus: `Palanca de carga comercial sobre ${top_instance.clientName}`,
    confidence: "alta",
    materialMetrics: [
      `${fmtK(top_instance.recuperable_at_target_3_5)} recuperable`,
      `${top_instance.carga_pct}% carga`,
      `${top_instance.margen_pct}% margen`,
    ],
    reasoningPattern: "high_sales_low_contribution_via_load",
    suggestedNextActions: [
      "Ver detalle del cliente principal",
      "Comparar contra cuentas virtuosas",
      "Simular impacto de bajar carga",
    ],
    // 🆕 AN+.FIX2 D-AN+.FIX2-2=A · clientList aditivo (paridad BRIEF #22 contrato preservado)
    // Habilita poblamiento lastClientList post-Q1 → AN.B Capa 4 ring poblado → AN+ dispara Q2.
    // IDs canónicos consumibles por AN.B + Evidence Sync Layer futura.
    clientList: top3.map(t => _buildEntityId("client", t.clientName)),
  });
}

function composeQualityGrowthDeteriorationResponse(m, scan, scenarioId) {
  // BRIEF #22 · Estructura tripartita Evidencia + Lectura + Foco.
  // Quality instances tienen: clientName, ventas_M, crecimiento_pct,
  // crecimiento_M, margen_pct, benchmark_pct, gap_margen_pp,
  // contribucion_perdida_M. NO traen carga ni contribución absoluta
  // por cliente. Para enriquecer ranking con carga, hacemos
  // cross-lookup contra erosion instances (mismo cliente, mismo scan).
  // Para contribución absoluta usamos ventas_M × (margen_pct/100).
  const instances = m.instances;
  const top = instances.slice(0, Math.min(instances.length, 4));
  const top_instance = top[0];

  // ── Helpers formato. fmtK omite decimal cuando es entero múltiplo de 1000.
  const fmtK = (val) => {
    if (val >= 1000) {
      const k = val / 1000;
      return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`;
    }
    return `$${Math.round(val)}`;
  };
  const fmtM = (val) => `$${val.toFixed(2)}M`;

  // ── Cross-lookup a erosion instances (si triggered) para enriquecer
  //    carga_pct + recuperable por cliente. NO inventa: usa data del scan.
  const erosionByClient = {};
  if (scan.commercial_erosion && scan.commercial_erosion.triggered) {
    scan.commercial_erosion.instances.forEach(ei => {
      erosionByClient[ei.clientName] = ei;
    });
  }

  // ── EVIDENCIA · ranking estructurado
  const rankingLines = top.map(inst => {
    // Contribución absoluta determinística: ventas_M × margen_pct/100
    const contribAbsoluta = inst.ventas_M * (inst.margen_pct / 100);
    const erosionMatch = erosionByClient[inst.clientName];
    const cargaText = erosionMatch ? ` | Carga ${erosionMatch.carga_pct}%` : "";
    const yoyStr = inst.crecimiento_pct > 0 ? `+${inst.crecimiento_pct}` : `${inst.crecimiento_pct}`;
    return `${inst.clientName.padEnd(12, " ")} → Ventas ${yoyStr}% YoY | Margen ${inst.margen_pct}%${cargaText} | Contribución ${fmtM(contribAbsoluta)}`;
  }).join("\n");

  const evidencia = `Clientes con crecimiento pero contribución bajo benchmark:\n\n${rankingLines}`;

  // ── LECTURA · interpretación causal
  const crec_min = m.aggregate.crecimiento_range.min;
  const crec_max = m.aggregate.crecimiento_range.max;
  const rangoYoY = crec_min === crec_max
    ? `+${crec_min}%`
    : `entre +${crec_min}% y +${crec_max}%`;
  const margenes = top.map(i => i.margen_pct);
  const rangoMargen = margenes.length === 1
    ? `${margenes[0]}%`
    : `${Math.min(...margenes).toFixed(1)}% y ${Math.max(...margenes).toFixed(1)}%`;
  const benchmark = top_instance.benchmark_pct || 30.1;
  const totalRecuperable = m.aggregate.contribucion_perdida_M;
  const totalRecuperableStr = `$${Math.round(totalRecuperable * 1000)}K`;

  const cuentasWord = top.length === 1 ? "cuenta crece" : "cuentas crecen";

  const _voz2 = (typeof VOZ2_ENABLED !== "undefined" && VOZ2_ENABLED);
  const lectura = _voz2
    ? `Las ${top.length} ${cuentasWord} ${rangoYoY}, pero ese crecimiento rinde poco: sus márgenes operan entre ${rangoMargen}, todos por debajo del promedio de la cartera (${benchmark}%). Venden más, pero ese crecimiento no se transforma en aporte al mismo ritmo — alrededor de ${totalRecuperableStr} anuales de contribución no llega a capturarse.`
    : `Las ${top.length} ${cuentasWord} ${rangoYoY} pero capturan ese crecimiento a costa de margen unitario. Sus márgenes operan entre ${rangoMargen}, todos bajo el benchmark de cartera (${benchmark}%). El crecimiento es estructuralmente diluido: el volumen incremental no convierte a contribución al mismo ritmo. Aproximadamente ${totalRecuperableStr} anuales de contribución se pierden por este mecanismo.`;

  // ── FOCO · cliente líder con materialidad y recuperable
  const erosionLider = erosionByClient[top_instance.clientName];
  const lider_contribAbs = top_instance.ventas_M * (top_instance.margen_pct / 100);

  let focoText;
  if (erosionLider) {
    // Si el líder también está en erosion, tenemos carga y recuperable
    const recuperableLider = erosionLider.recuperable_at_target_3_5;
    focoText = `Mecanismo disponible: ${top_instance.clientName} combina mayor materialidad de cartera (${fmtM(lider_contribAbs)} de contribución) y mayor controlabilidad operativa (carga comercial ${erosionLider.carga_pct}%) · zona donde la palanca tiene mayor impacto cuantificable. Una reducción gradual desde ${erosionLider.carga_pct}% hacia 3.5% recuperaría aproximadamente ${fmtK(recuperableLider)} anuales sin sacrificar volumen presente.`;
  } else {
    // Sin datos de carga · foco basado en materialidad y deterioro de margen
    const contribPerdida = top_instance.contribucion_perdida_M;
    const contribPerdidaStr = `$${Math.round(contribPerdida * 1000)}K`;
    focoText = `Mecanismo disponible: ${top_instance.clientName} concentra mayor materialidad (${fmtM(lider_contribAbs)} de contribución) y mayor gap vs benchmark (${top_instance.gap_margen_pp}pp) · cuantifica zona donde el cierre de gap recuperaría aproximadamente ${contribPerdidaStr} anuales.`;
  }

  const foco = `${focoText}`;

  // ── Confianza
  const confianza = `*Confianza alta · la relación crecimiento-margen es observable en el escenario activo.*`;

  const opener = `${evidencia}\n\n${lectura}\n\n${foco}\n\n${confianza}`;

  // ── Suggestions accionables (entidades reales)
  const suggestions = [
    `Cómo arranco la renegociación con ${top_instance.clientName}`,
    `Qué pasa si bajo carga de ${top_instance.clientName} 1pp`,
    `Profundizar en ${top_instance.clientName}`,
  ];

  // BRIEF #16 · acción Sentrix contextual (preservado)
  const sentrixAction = composeSentrixAction("mechanism_quality_growth", {
    instances: m.instances,
  });

  // BRIEF N-bis · Tipo A puro · suggestions filtradas en return
  // 🆕 AN+.FIX2 D-AN+.FIX2-2=A · clientList aditivo (shape distinto: variable `top` no `top3`)
  // Quality growth usa top = instances.slice(0, Math.min(instances.length, 4)) · objetos con .clientName
  return {
    opener,
    suggestions: filterTextualSuggestions(suggestions),
    sentrixAction,
    clientList: top.map(t => _buildEntityId("client", t.clientName)),
  };
}

function composeCustomerDependencyRiskResponse(m, scan, scenarioId) {
  const top3_names = m.aggregate.top3_names;
  const top3_participacion = m.aggregate.top3_participacion_pct;
  const top3_contribucion = m.aggregate.top3_contribucion_M;
  const namesList = r7_listInstances(top3_names.map(n => ({ clientName: n })));

  const M1 = `El riesgo de dependencia se concentra en ${namesList}. Los tres concentran ${top3_participacion}% de las ventas y ${r7_formatCurrencyM(top3_contribucion)} de contribución.`;

  const _voz2dep = (typeof VOZ2_ENABLED !== "undefined" && VOZ2_ENABLED);
  const M2 = _voz2dep
    ? `Cuando pocas cuentas concentran buena parte de la cartera, perder cualquiera golpea fuerte y reemplazarla cuesta.`
    : `La dependencia aumenta cuando pocas cuentas concentran proporción mayor de la cartera. Cualquier pérdida estructural sobre estas cuentas tiene impacto desproporcionado, y la capacidad de reemplazo se vuelve crítica.`;

  const M3 = _voz2dep
    ? `Las tres comparten el mismo perfil: pesan mucho, rinden por debajo del promedio y sostienen carga comercial alta. Reemplazarlas exige reconstruir simultáneamente volumen, margen y mecanismo comercial.`
    : `Las tres cuentas operan con el mismo patrón estructural: alta participación, margen bajo benchmark, carga comercial sostenida. La dependencia no es solo de volumen: es del modelo comercial actual que estas cuentas absorben. Reemplazarlas exige reconstruir simultáneamente volumen, margen y mecanismo comercial.`;

  const M4 = `La palanca prioritaria es diversificación proactiva de Tier 2 mientras los Tier 1 siguen activos. El objetivo no es reemplazar volumen, es construir capacidad comercial alternativa con perfil de margen sano antes de que la salida sea forzada.`;

  const confianza = `*Confianza alta · la cuantificación de exposición es determinística sobre el escenario activo.*`;

  const opener = [M1, M2, M3, M4, confianza].join("\n\n");

  const suggestions = [
    `Qué pasa si pierdo a los tres simultáneamente`,
    `Cómo arranco la diversificación de Tier 2`,
    `Qué cuentas Tier 2 tienen mayor potencial`,
  ];

  // BRIEF #16 · acción Sentrix contextual
  const sentrixAction = composeSentrixAction("mechanism_dependency_risk", {
    top3_names: m.aggregate.top3_names,
  });

  // BRIEF N-bis · Tipo A puro · suggestions filtradas en return
  // 🆕 AN+.FIX2 D-AN+.FIX2-2=A · clientList aditivo (shape distinto: top3_names son STRINGS directos)
  // NO usar .clientName · top3_names viene de m.aggregate.top3_names ya como array de strings.
  return {
    opener,
    suggestions: filterTextualSuggestions(suggestions),
    sentrixAction,
    clientList: top3_names.map(name => _buildEntityId("client", name)),
  };
}

function composeMechanismInactiveResponse(mechanismId, scan) {
  const mech = MECHANISM_REGISTRY[mechanismId];

  let mensaje = "";
  if (mechanismId === "trapped_capital") {
    mensaje = `${mech.nombre_capitalizado} no se evalúa con precisión cuantitativa sin drilldown por categoría de inventario. La lectura agregada del módulo sugiere presión, pero la confirmación causal requiere desglose por categoría que no está disponible en el escenario actual.`;
  } else if (mechanismId === "liquidity_compression") {
    mensaje = `${mech.nombre_capitalizado} no se manifiesta materialmente en el escenario activo. El flujo de caja se sostiene en los rangos esperados.`;
  } else {
    mensaje = `${mech.nombre_capitalizado} no presenta instancias activas en el escenario actual.`;
  }

  const opener = `${mensaje}\n\n*Confianza ${mechanismId === "trapped_capital" ? "media" : "alta"}.*`;

  return { opener, suggestions: [] };
}

// ═══════════════════════════════════════════════════════
// BRIEF #15 · Mechanism Scan Composer
// ═══════════════════════════════════════════════════════

function composeMechanismScan(scenarioId) {
  const scan = scanMechanisms(scenarioId);

  const activos = [];
  const inactivos = [];

  for (const [mechanismId, m] of Object.entries(scan)) {
    if (m.triggered) {
      activos.push({ mechanismId, m });
    } else {
      inactivos.push({ mechanismId, m });
    }
  }

  activos.sort((a, b) => {
    const order = ["commercial_erosion", "quality_of_growth_deterioration", "customer_dependency_risk"];
    return order.indexOf(a.mechanismId) - order.indexOf(b.mechanismId);
  });

  let opener = `La cartera presenta ${activos.length} mecanismos activos y ${inactivos.length} inactivos en el escenario actual.`;

  for (const { mechanismId, m } of activos) {
    let parrafo = "";

    if (mechanismId === "commercial_erosion") {
      const top3 = m.instances.slice(0, 3);
      const namesList = r7_listInstances(top3);
      const recuperable_str = r7_formatCurrencyK(m.aggregate.recuperable_total_K);
      parrafo = `**Erosión comercial** concentra la mayor oportunidad recuperable: ${recuperable_str} anuales sobre ${top3.length} cuentas con presión activa (${namesList}). Es el mecanismo de mayor controlabilidad operativa: las ${top3.length} operan con carga sobre la mejor práctica interna · palanca comercial disponible con horizonte inmediato.`;
    }

    if (mechanismId === "quality_of_growth_deterioration") {
      const crec_min = m.aggregate.crecimiento_range.min;
      const crec_max = m.aggregate.crecimiento_range.max;
      const contrib_perdida = m.aggregate.contribucion_perdida_M;
      const contrib_perdida_str = `aproximadamente $${Math.round(contrib_perdida * 1000)}K`;

      // BRIEF #15-bis · FIX 2 y 3 · idem composeQualityGrowthDeteriorationResponse
      const cuentasWord_s = m.instances.length === 1 ? "cuenta" : "cuentas";
      const cuentasLabel_s = `${m.instances.length} ${cuentasWord_s}`;
      const rangoCrecimiento_s = crec_min === crec_max
        ? `+${crec_min}%`
        : `entre +${crec_min}% y +${crec_max}%`;
      const verboPlur_s = m.instances.length === 1 ? "" : "n";

      parrafo = `**Deterioro de calidad de crecimiento** opera sobre ${cuentasLabel_s} que crece${verboPlur_s} ${rangoCrecimiento_s} pero captura${verboPlur_s} ese crecimiento a costa de margen unitario. Equivale a ${contrib_perdida_str} anuales de contribución que se pierden respecto al estándar del benchmark. Es derivado de erosión comercial: la carga sostenida es la causa.`;
    }

    if (mechanismId === "customer_dependency_risk") {
      const top3_names = m.aggregate.top3_names;
      const top3_participacion = m.aggregate.top3_participacion_pct;
      const top3_contribucion = m.aggregate.top3_contribucion_M;
      const namesList = r7_listInstances(top3_names.map(n => ({ clientName: n })));
      parrafo = `**Riesgo de dependencia de cliente** es estructural: ${namesList} concentran ${top3_participacion}% de las ventas y ${r7_formatCurrencyM(top3_contribucion)} de contribución. Una salida simultánea representaría la pérdida de aproximadamente la mitad de la rentabilidad operativa. Mecanismo de horizonte largo · la palanca de diversificación opera sobre cuentas Tier 2.`;
    }

    opener += "\n\n" + parrafo;
  }

  if (inactivos.length > 0) {
    const inactivosNombres = inactivos.map(({ m }) => `**${m.nombre}**`);
    let inactivosTxt = "Los mecanismos inactivos son ";
    if (inactivosNombres.length === 1) {
      inactivosTxt += inactivosNombres[0] + ".";
    } else {
      inactivosTxt += inactivosNombres.slice(0, -1).join(", ") + " y " + inactivosNombres[inactivosNombres.length - 1] + ".";
    }

    if (scan.trapped_capital && !scan.trapped_capital.triggered) {
      inactivosTxt += ` Capital atrapado requiere drilldown por categoría de inventario para evaluación cuantitativa precisa.`;
    }

    opener += "\n\n" + inactivosTxt;
  }

  opener += `\n\n*Confianza alta · mecanismos activos con cifras determinísticas del escenario.*`;

  const suggestions = activos.length > 0 ? [
    `Profundizar en ${activos[0].m.nombre}`,
    `Cuál es el mecanismo más caro`,
    `Qué pasa si intervengo en una sola palanca`,
  ] : [];

  // ── BRIEF M.B.2 · narrative_signals + posture_hint ──
  // Bajo flag OFF · narrative_signals queda null · output bitwise equivalente.
  let narrative_signals = null;
  let posture_hint = "prioritize";
  if (VOICE_NARRATIVE_LAYER_ENABLED) {
    try {
      narrative_signals = buildNarrativeSignalsForMechanismScan(scan);
    } catch (sig_err) {
      // eslint-disable-next-line no-console
      console.warn("BRIEF M.B.2 mechanism scan narrative_signals error:", sig_err);
      narrative_signals = null;
    }
  }

  return {
    opener,
    suggestions,
    narrative_signals,
    posture_hint,
  };
}

// ═══════════════════════════════════════════════════════
// BRIEF #15 · Mechanism Ranking Composer
// ═══════════════════════════════════════════════════════

function composeMechanismRanking(scenarioId) {
  const scan = scanMechanisms(scenarioId);
  const activos = Object.entries(scan)
    .filter(([_, m]) => m.triggered)
    .map(([id, m]) => ({ id, m }));

  if (activos.length === 0) {
    return {
      opener: `La cartera no presenta mecanismos activos en el escenario actual.\n\n*Confianza alta.*`,
      suggestions: [],
    };
  }

  const order = ["commercial_erosion", "quality_of_growth_deterioration", "customer_dependency_risk"];
  activos.sort((a, b) => order.indexOf(a.id) - order.indexOf(b.id));

  const top = activos[0];

  let opener = "";

  if (top.id === "commercial_erosion") {
    const recuperable_M = top.m.aggregate.recuperable_total_M_at_3_5;
    const pct_contribucion = top.m.aggregate.pct_of_total_contribution;
    const top_instance = top.m.instances[0];
    const top_recuperable_K = Math.round(top_instance.recuperable_at_target_3_5);

    opener = `El mecanismo de mayor costo activo es **erosión comercial**, con ${r7_formatCurrencyM(recuperable_M)} anuales recuperables sobre ${top.m.instances.length} cuentas con presión activa. Equivale a ${pct_contribucion}% de la contribución total de la cartera.`;
    opener += `\n\nCada punto de reducción de carga sobre la mejor práctica libera contribución en proporción al volumen de la cuenta. En ${top_instance.clientName}, la mayor de las ${top.m.instances.length}, equivale a aproximadamente $${top_recuperable_K}K anuales.`;

    const second = activos[1];
    if (second && second.id === "quality_of_growth_deterioration") {
      const contrib_perdida = second.m.aggregate.contribucion_perdida_M;
      opener += `\n\nEl segundo mecanismo más caro es **deterioro de calidad de crecimiento**, con aproximadamente $${Math.round(contrib_perdida * 1000)}K anuales en contribución que se pierde respecto al estándar del benchmark. Opera como consecuencia del primero: la carga sostenida en las cuentas que crecen es lo que comprime margen unitario. Intervenir sobre erosión comercial reduce automáticamente parte del costo de este segundo mecanismo.`;
    }

    const third = activos[2];
    if (third && third.id === "customer_dependency_risk") {
      const top3_contribucion = third.m.aggregate.top3_contribucion_M;
      const top3_participacion = third.m.aggregate.top3_participacion_pct;
      opener += `\n\nEl tercer mecanismo activo es **riesgo de dependencia de cliente**, con materialidad estructural mayor (${r7_formatCurrencyM(top3_contribucion)} de contribución expuesta, ${top3_participacion}% de cartera) pero menor controlabilidad inmediata. La intervención requiere diversificación con horizonte 12-18 meses.`;
    }

    opener += `\n\nLa principal oportunidad está en erosión comercial porque combina tres cosas: mayor impacto económico, capacidad de intervención inmediata, y recuperación rápida en 3-6 meses.`;

    opener += `\n\n*Confianza alta · las ${activos.length} materialidades son determinísticas sobre el escenario activo.*`;
  }

  const suggestions = [
    `Profundizar en ${top.m.nombre}`,
    `Cómo arranco la intervención`,
    `Cuáles son las cuentas más afectadas`,
  ];

  // BRIEF #16 · acción Sentrix contextual basada en el top mecanismo activo
  const sentrixAction = composeSentrixAction("mechanism_ranking", {
    topMechanismId: top.id,
    instances: top.m.instances,
  });

  // ── BRIEF M.B.2 · narrative_signals + posture_hint ──
  let narrative_signals = null;
  let posture_hint = "prioritize";
  if (VOICE_NARRATIVE_LAYER_ENABLED) {
    try {
      narrative_signals = buildNarrativeSignalsForMechanismRanking(scan);
    } catch (sig_err) {
      // eslint-disable-next-line no-console
      console.warn("BRIEF M.B.2 mechanism ranking narrative_signals error:", sig_err);
      narrative_signals = null;
    }
  }

  // BRIEF N-bis · Tipo A puro · suggestions filtradas en return
  return {
    opener,
    suggestions: filterTextualSuggestions(suggestions),
    sentrixAction,
    narrative_signals,
    posture_hint,
  };
}

// BRIEF #15 · Flag for mechanism link enrichment in composeInterpreta
const MECHANISM_LINK_ENABLED = true;

// ═══════════════════════════════════════════════════════
// BRIEF #12-C.2 · Reasoning Engine Orchestrator
//
// Single entry point that returns the COMPLETE cognitive trace
// for a given client + scenario. Used by:
//   · getClientDeepDive (in #12-C.3) for composition
//   · trace inspection in console for auditability
//   · future LLM integration as context payload
//
// Returns deterministic, fully-auditable trace.
// ═══════════════════════════════════════════════════════

function runReasoningEngine(clientName, scenarioId) {
  // Layer 1: run all 14 primitives
  const primitives = {};
  Object.keys(PRIMITIVES).forEach(key => {
    primitives[key] = PRIMITIVES[key](clientName, scenarioId);
  });

  // Layer 2: run all 5 causal relations
  const causal = {};
  Object.keys(CAUSAL).forEach(key => {
    causal[key] = CAUSAL[key](clientName, scenarioId);
  });

  // Layer 3: detect templates (consumes primitives + causal)
  const templates = detectTemplates(clientName, scenarioId);

  // Summary: count triggered patterns at each layer
  const summary = {
    primitives_triggered: Object.entries(primitives).filter(([, v]) => v.triggered).map(([k]) => k),
    causal_triggered: Object.entries(causal).filter(([, v]) => v.triggered).map(([k]) => k),
    templates_triggered: templates.map(t => t.id),
    highest_severity_template: templates[0]?.id || null,
  };

  return {
    client: clientName,
    scenario: scenarioId,
    layers: {
      primitives: primitives,
      causal: causal,
      templates: templates,
    },
    summary: summary,
    timestamp: Date.now(),
  };
}

// ═══════════════════════════════════════════════════════
// BRIEF #12-C.4 · Context Awareness Layer
//
// Builds a context object that getClientDeepDive consumes to
// adapt response composition. Implements 5 of 6 dimensions
// from Composition Constitution §9.2 (drilldown depth excluded).
//
// Context is built from UI state at call time. Pure function:
// receives UI state, returns serializable context object.
// ═══════════════════════════════════════════════════════

function getResponseContext(uiState = {}) {
  // uiState shape (expected from React component):
  //   {
  //     activeModule, activeFilters, lastClientMentioned,
  //     lastTemplateMentioned, lastModuleConsulted, turnCount,
  //     userInputText, surfaceLocation
  //   }
  // All fields optional. Defaults are conservative.

  const {
    activeModule = "ventas",
    activeFilters = {},
    lastClientMentioned = null,
    lastTemplateMentioned = null,
    lastModuleConsulted = null,
    turnCount = 0,
    userInputText = "",
    surfaceLocation = "chat",
  } = uiState;

  // Detect comparison from user input
  // Pattern: "compara X con Y", "X vs Y", "diferencia entre X y Y"
  const comparisonActive = _detectComparison(userInputText);

  return {
    activeModule: activeModule,
    activeFilters: activeFilters,
    priorConversation: {
      lastClientMentioned: lastClientMentioned,
      lastTemplateMentioned: lastTemplateMentioned,
      lastModuleConsulted: lastModuleConsulted,
      turnCount: turnCount,
    },
    comparisonActive: comparisonActive,
    surfaceLocation: surfaceLocation,
  };
}

// _detectComparison · pure helper that parses user input for
// comparison intent. Returns { isComparing, entityA, entityB }.
// Heuristic only · BRIEF #14 (comparison handler) will harden this.
function _detectComparison(userText) {
  if (!userText || typeof userText !== "string") {
    return { isComparing: false, entityA: null, entityB: null };
  }
  const lower = userText.toLowerCase();
  // Pattern A: "compara X con Y" / "compara X y Y"
  const patternA = /compara\s+a?\s*([\wáéíóúñ\s]+?)\s+(?:con|y|vs)\s+([\wáéíóúñ\s]+?)(?:\?|$|\.)/i;
  const matchA = lower.match(patternA);
  if (matchA) {
    return {
      isComparing: true,
      entityA: matchA[1].trim(),
      entityB: matchA[2].trim(),
    };
  }
  // Pattern B: "X vs Y"
  const patternB = /([\wáéíóúñ]+(?:\s[\wáéíóúñ]+)?)\s+vs\s+([\wáéíóúñ]+(?:\s[\wáéíóúñ]+)?)/i;
  const matchB = lower.match(patternB);
  if (matchB) {
    return {
      isComparing: true,
      entityA: matchB[1].trim(),
      entityB: matchB[2].trim(),
    };
  }
  return { isComparing: false, entityA: null, entityB: null };
}

// ═══════════════════════════════════════════════════════
// BRIEF #12-C.5 · Brevity Selector
//
// Selects response brevity from 4 levels (Composition §7).
// Decision derived from trace + context, never invented.
//
// Returns: "micro" | "short" | "medium" | "expanded"
// ═══════════════════════════════════════════════════════

function selectBrevity(trace, context = {}, userInputText = "") {
  const text = (userInputText || "").toLowerCase().trim();

  // MICRO triggers: pure affirmative or negative replies
  const microPatterns = ["sí", "si", "ok", "okay", "dale", "claro", "no", "nope"];
  if (microPatterns.includes(text)) return "micro";

  // EXPANDED triggers: explicit drill request keywords
  const expandedKeywords = ["explícame", "explicame", "profundiza", "profundizá",
                            "detalle", "más detalle", "en profundidad", "drill",
                            "drilldown"];
  if (expandedKeywords.some(k => text.includes(k))) return "expanded";

  // SHORT triggers: follow-up on same client (turnCount >= 2 + already mentioned)
  const turnCount = context.priorConversation?.turnCount || 0;
  const lastClient = context.priorConversation?.lastClientMentioned;
  if (turnCount >= 2 && lastClient === trace.client) return "short";

  // MEDIUM: default for first deep-dive
  return "medium";
}

