// ── PRNG determinístico por (scenario, sku) para que los cambios de estado de
// inventario sean estables entre renders sin necesidad de useMemo extra.
function _seededRand(seedStr) {
  let h = 2166136261;
  for (let i = 0; i < seedStr.length; i++) {
    h ^= seedStr.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  // Convertir a [0,1)
  return ((h >>> 0) % 100000) / 100000;
}

// ── Transforma clientesVentas usando growth rates del escenario.
// actual = anterior * (1 + growth/100). El "anterior" se preserva (es histórico fijo).
function applyScenarioToClientesVentas(scenarioId, override) {
  const t = resolveTransform(scenarioId, override)?.clientes;
  if (!t) return clientesVentas;
  // __remove__ · "perder cuenta" saca la entidad del universo (set tipo remover · filtrar ANTES del map)
  const _removed = new Set(Object.keys(t).filter(n => t[n] && t[n].__remove__));
  return clientesVentas.filter(c => !_removed.has(c.nombre)).map(c => {
    const tc = t[c.nombre];
    if (!tc) return c;
    // Crecimiento aplicado sobre el "anterior" (estado base independiente del escenario)
    const newActual    = Math.round(c.anterior * (1 + tc.growth / 100));
    // Unidades crecen al 70% del ritmo de ventas (mix de volumen + precio)
    const unidadesAnt  = c.unidadesAnt || Math.round(c.unidades * 0.95);
    const newUnidades  = Math.round(unidadesAnt * (1 + (tc.growth / 100) * 0.7));
    return {
      ...c,
      actual:    newActual,
      unidades:  newUnidades,
      unidadesAnt,
      pctRebate: Math.round((c.pctRebate + (tc.rebateDelta || 0)) * 10) / 10,
      // anterior, presupuesto se preservan
    };
  }).sort((a,b) => b.actual - a.actual);
}

// ── Re-agrupa por marca a partir de los clientes transformados
function applyScenarioToMarcasVentas(scenarioId) {
  if (!SCENARIO_TRANSFORMS[scenarioId]?.clientes) return marcasVentas;
  const clientes = applyScenarioToClientesVentas(scenarioId);
  const byMarca = {};
  clientes.forEach(c => {
    if (!byMarca[c.marca]) {
      byMarca[c.marca] = {
        nombre:c.marca, marca:c.marca, sfamilia:c.sfamilia, canal:c.canal,
        actual:0, anterior:0, unidades:0, unidadesAnt:0, presupuesto:0,
        pctRebate:0, _count:0,
      };
    }
    const g = byMarca[c.marca];
    g.actual      += c.actual;
    g.anterior    += c.anterior;
    g.unidades    += c.unidades;
    g.unidadesAnt += (c.unidadesAnt || c.unidades);
    g.presupuesto += (c.presupuesto || 0);
    g.pctRebate   += c.pctRebate;
    g._count++;
  });
  return Object.values(byMarca).map(g => ({
    ...g,
    pctRebate: Math.round((g.pctRebate / g._count) * 10) / 10,
  })).sort((a,b) => b.actual - a.actual);
}

function applyScenarioToSfamiliasVentas(scenarioId) {
  if (!SCENARIO_TRANSFORMS[scenarioId]?.clientes) return sfamiliasVentas;
  const clientes = applyScenarioToClientesVentas(scenarioId);
  const bySfam = {};
  clientes.forEach(c => {
    if (!bySfam[c.sfamilia]) {
      bySfam[c.sfamilia] = {
        nombre:c.sfamilia, sfamilia:c.sfamilia, marca:c.marca, canal:c.canal,
        actual:0, anterior:0, unidades:0, unidadesAnt:0, presupuesto:0,
        pctRebate:0, _count:0,
      };
    }
    const g = bySfam[c.sfamilia];
    g.actual      += c.actual;
    g.anterior    += c.anterior;
    g.unidades    += c.unidades;
    g.unidadesAnt += (c.unidadesAnt || c.unidades);
    g.presupuesto += (c.presupuesto || 0);
    g.pctRebate   += c.pctRebate;
    g._count++;
  });
  return Object.values(bySfam).map(g => ({
    ...g,
    pctRebate: Math.round((g.pctRebate / g._count) * 10) / 10,
  })).sort((a,b) => b.actual - a.actual);
}

// ── Ajusta clientesMargen aplicando: venta_escenario (de ventas) + marginErosion
// específica por cliente. Sin jitter ni Math.random: 100% determinístico.
// La contribución se recalcula como venta_escenario × margen_nuevo / 100, lo cual
// garantiza que el agregado de la tabla coincida con el KPI principal del módulo.
function applyScenarioToClientesMargen(scenarioId, override) {
  const t = resolveTransform(scenarioId, override)?.clientes;
  if (!t) return clientesMargen;
  // Indexar ventas del escenario para lookup por nombre
  const ventasScn   = applyScenarioToClientesVentas(scenarioId, override);
  const ventaByName = Object.fromEntries(ventasScn.map(v => [v.nombre, v.actual]));
  // __remove__ · misma remoción que ventas (consistencia · no media-cuenta)
  const _removed = new Set(Object.keys(t).filter(n => t[n] && t[n].__remove__));

  return clientesMargen.filter(c => !_removed.has(c.nombre)).map(c => {
    const tc = t[c.nombre];
    if (!tc) return c;
    const newMargen = Math.max(6, +(c.margen + (tc.marginErosion || 0)).toFixed(1));
    const newVenta  = ventaByName[c.nombre] ?? c.venta;
    const newContrib= Math.round(newVenta * (newMargen / 100));
    return {
      ...c,
      venta:        newVenta,
      contribucion: newContrib,
      margen:       newMargen,
      pctRebate:    Math.round((c.pctRebate + (tc.rebateDelta || 0)) * 10) / 10,
    };
  }).sort((a,b) => b.contribucion - a.contribucion);
}

// ════════════════════════════════════════════════════════════════════════════
// PROTECTED_CLIENTS (BRIEF #6-FINAL) — clientes "obligatorios" en Top 10 por
// escenario. ADI los menciona en sus tesis ("Lider, Ripley, La Polar operan
// bajo costo real..."); si la tabla no los muestra, la narrativa pierde anclaje.
// ════════════════════════════════════════════════════════════════════════════
const PROTECTED_CLIENTS = {
  tension: {
    ventas:   ["Mercado Libre", "La Polar", "Ripley"],
    margenes: ["Mercado Libre", "La Polar"],
  },
  crisis: {
    ventas:   ["Mercado Libre", "La Polar", "Ripley", "Lider"],
    margenes: ["La Polar", "Lider", "Ripley", "Mercado Libre"],
  },
};

// Garantiza que los clientes protegidos aparezcan en el Top 10 por contribución,
// desplazando al último cliente NO protegido del Top 10 natural si es necesario.
// ════════════════════════════════════════════════════════════════════════════
// getClientesMargenWithProtected (BRIEF #6-DEFINITIVE) — devuelve EXACTAMENTE el
// Top 10 con los clientes protegidos garantizados en él, ordenado por contribución.
//
// Estrategia: separar `protectedClients` y `nonProtectedClients`, ordenar cada
// grupo por contribución DESC, llenar 10 slots — primero todos los protegidos,
// luego los top no-protegidos hasta completar 10, y re-ordenar el resultado.
//
// IMPORTANTE: devuelve solo 10 elementos (no la lista completa). Esto evita que
// la TablaMargen del módulo (que itera todas las filas que recibe) muestre a
// los desplazados al final de la tabla.
// ════════════════════════════════════════════════════════════════════════════
function getClientesMargenWithProtected(scenarioId) {
  const allClients = applyScenarioToClientesMargen(scenarioId);
  const protectedNames = PROTECTED_CLIENTS[scenarioId]?.margenes || [];

  // Sin protección: devolver top 10 natural
  if (protectedNames.length === 0) return allClients.slice(0, 10);

  // Separar en dos grupos
  const protectedClients = [];
  const nonProtectedClients = [];
  allClients.forEach(c => {
    if (protectedNames.includes(c.nombre)) protectedClients.push(c);
    else                                   nonProtectedClients.push(c);
  });

  // Ordenar ambos por contribución descendente
  protectedClients.sort((a, b) => b.contribucion - a.contribucion);
  nonProtectedClients.sort((a, b) => b.contribucion - a.contribucion);

  // Llenar 10 slots: TODOS los protegidos + top no-protegidos hasta completar 10
  const slotsForNonProtected = Math.max(0, 10 - protectedClients.length);
  const result = [
    ...protectedClients,
    ...nonProtectedClients.slice(0, slotsForNonProtected),
  ];

  // Re-ordenar el resultado final por contribución DESC para presentación
  return result.sort((a, b) => b.contribucion - a.contribucion);
}

// ── Ajusta sfamiliasMargen re-agregando desde los clientes transformados
function applyScenarioToSfamiliasMargen(scenarioId) {
  if (!SCENARIO_TRANSFORMS[scenarioId]?.clientes) return sfamiliasMargen;
  const cli = applyScenarioToClientesMargen(scenarioId);
  const by = {};
  cli.forEach(c => {
    if (!by[c.sfamilia]) {
      by[c.sfamilia] = {
        nombre:c.sfamilia, tipo:"sfamilia", marca:c.marca, sfamilia:c.sfamilia,
        venta:0, costo:0, rebates:0, contribucion:0, unidades:0,
        pctRebate:0, margen:0, costoMedio:0, precioLista:0, benchmark:30.1,
        _count:0,
      };
    }
    const g = by[c.sfamilia];
    g.venta        += c.venta;
    g.costo        += (c.costo || 0);
    g.rebates      += (c.rebates || 0);
    g.contribucion += c.contribucion;
    g.unidades     += c.unidades;
    g.pctRebate    += c.pctRebate;
    g.margen       += c.margen;
    g._count++;
  });
  return Object.values(by).map(g => ({
    ...g,
    pctRebate: Math.round((g.pctRebate / g._count) * 10) / 10,
    // MICRO-CORTE · margen blended real (contribución/venta) cuando el flag está ON.
    // contribucion y venta ya vienen sumadas (venta-ponderadas) en g; el margen viejo
    // promediaba sin ponderar (g.margen/_count) e inflaba → venta×margen≠contribución.
    // Rama OFF = expresión original byte-idéntica. _count y g.margen se preservan.
    margen: FEATURE_FAMILY_MARGEN_BLENDED
      ? (g.venta > 0 ? Math.round((g.contribucion / g.venta) * 1000) / 10 : 0)
      : Math.round((g.margen / g._count) * 10) / 10,
  })).sort((a,b) => b.venta - a.venta);
}

// ── Ajusta skuInventario: en Tensión 30% Activo→Lento; en Crisis 50% Activo→Lento
//    y 40% Lento→120d (los estados reales son "Activo", "Lento", "60d", "90d", "120d").
function applyScenarioToSkuInventario(scenarioId, override) {
  if (!resolveTransform(scenarioId, override)) return skuInventario;
  if (scenarioId === "bonanza") return skuInventario;

  return skuInventario.map(sku => {
    const r = _seededRand(scenarioId + sku.sku);
    let nuevoEstado = sku.estado;
    let nuevaDoh    = sku.doh;
    let nuevaAlerta = sku.alerta;

    if (scenarioId === "tension") {
      if (sku.estado === "Activo" && r < 0.30) {
        nuevoEstado = "Lento";
        nuevaDoh    = Math.round(sku.doh * 1.6);
        nuevaAlerta = "warn";
      } else if (sku.estado === "Lento") {
        nuevaDoh = Math.round(sku.doh * 1.25);
      }
    } else if (scenarioId === "crisis") {
      if (sku.estado === "Activo" && r < 0.50) {
        nuevoEstado = "Lento";
        nuevaDoh    = Math.round(sku.doh * 2.0);
        nuevaAlerta = "warn";
      } else if (sku.estado === "Lento" && r < 0.40) {
        nuevoEstado = "120d";
        nuevaDoh    = Math.round(sku.doh * 2.5);
        nuevaAlerta = "crit";
      } else if (sku.estado === "60d" || sku.estado === "90d") {
        nuevoEstado = "120d";
        nuevaDoh    = Math.round(sku.doh * 1.4);
        nuevaAlerta = "crit";
      }
    }
    return { ...sku, estado:nuevoEstado, doh:nuevaDoh, alerta:nuevaAlerta };
  });
}

// ── KPIs derivados por escenario (Márgenes e Inventario)
function getMargenKPI(scenarioId) {
  const k = SCENARIO_TRANSFORMS[scenarioId]?.kpis?.margen;
  if (!k) return margenKPI;
  return { ...margenKPI, ...k };
}
function getInvKPI(scenarioId) {
  const k = SCENARIO_TRANSFORMS[scenarioId]?.kpis?.inventario;
  if (!k) return invKPI;
  return { ...invKPI, ...k };
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #2 (post-46-bis) · composeModuleOverview · runtime composer que
// reemplaza el EXPLAIN_MESSAGES hardcoded. Todas las cifras provienen del
// dataset runtime via getInvKPI / getMargenKPI / applyScenarioToClientesVentas
// / applyScenarioToSkuInventario. Cero cifras inventadas.
//
// Disparado desde 3 callsites:
//   1. generateModuleDeepDive (fallback profundización módulo)
//   2. explainTriggered useEffect (botón "✨ Explícame" desde Sentrix)
//   3. handleUserSubmit branch intent.type === "module" (cold-start módulo)
//
// Shape de retorno bitwise compatible con EXPLAIN_MESSAGES legacy:
//   { opener: string, suggestions: string[] }
//
// Decisiones arquitectónicas locked (BRIEF #2 autorización):
//   · Inventario · usar getInvKPI(scenarioId) como fuente canónica.
//   · Margen · usar getMargenKPI(scenarioId).pct (no recalcular ponderado).
//   · "% fuera de rango" inventario · usar inmovilizadoPct canónico.
//   · Top categoría inmovilizado · agregado runtime sobre
//     applyScenarioToSkuInventario filtrado por estado !== "Activo".
//   · Suggestions hardcoded por scenario · son sugerencias (no afirmaciones)
//     · cero violación de coherencia.
//
// Voz ADI · constitución R1-R8:
//   R1 orden cronológico (anterior → actual).
//   R2 magnitud absoluta junto a porcentaje.
//   R3 proporción antes de explicación.
//   R4 lenguaje ejecutivo (erosiona/concentra/explica).
//   R5 nombres propios sobre generalizaciones.
//   R7 una interpretación por oración.
//   R8 todo dato explica su causa.
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #15 · EXECUTIVE READING V1 · OLEADA 1
// composeModuleOverviewV2 · función nueva con formato 6 bloques Executive V1.
//
// Pipeline LOCKED:
//   ETLG prepend → B1 thesis (module_overview_{ventas|margenes|inventario})
//   composer V2  → B2 (qué pasa) + B3 (evidencia concatenada) + B4 (riesgo
//                  observable) + B5 (foco) + B6 (Confianza)
//
// 3 branches × 3 scenarios = 9 variantes wording LOCKED.
// Suggestions intactas (D5 mantener bitwise).
// Flag rollback: VOICE_EXEC_MODULE_OVERVIEW_ENABLED = false → composer legacy.
// ════════════════════════════════════════════════════════════════════════════
function composeModuleOverviewV2(scenarioId, moduloId) {
  // Helpers internos (mismo formato que legacy)
  const fmtM = (val) => {
    const m = val / 1000;
    return Number.isInteger(m) ? `$${m}M` : `$${m.toFixed(1)}M`;
  };
  const fmtK = (val) => {
    if (val >= 1000) {
      const k = val / 1000;
      return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`;
    }
    return `$${Math.round(val)}K`;
  };
  const pct1 = (val) => `${val >= 0 ? "+" : ""}${val.toFixed(1)}%`;

  // ────────────────────────────────────────────────────────────────────────
  // BRANCH VENTAS
  // ────────────────────────────────────────────────────────────────────────
  if (moduloId === "ventas") {
    const kpi = getVentasKPI("Anual", null, scenarioId);
    const totalActual = kpi.totalActual;
    const totalAnterior = kpi.totalAnterior;
    const growth = kpi.vsAnterior;
    const deltaUSD = totalActual - totalAnterior;

    const dataset = applyScenarioToClientesVentas(scenarioId);
    const sorted = [...dataset].sort((a, b) => b.actual - a.actual);
    const top3 = sorted.slice(0, 3);
    const top3Sum = top3.reduce((s, c) => s + c.actual, 0);
    const top3Pct = (top3Sum / totalActual) * 100;
    const top3Names = top3.map(c => c.nombre).join(", ");

    const growers = dataset
      .filter(c => c.actual > c.anterior)
      .map(c => ({ ...c, g: ((c.actual - c.anterior) / c.anterior) * 100 }))
      .sort((a, b) => b.g - a.g);
    const fastest = growers[0] || null;

    const decliners = dataset
      .filter(c => c.actual < c.anterior)
      .map(c => ({ ...c, g: ((c.actual - c.anterior) / c.anterior) * 100 }))
      .sort((a, b) => a.g - b.g);
    const worst = decliners[0] || null;

    let b2, b3, b4, b5;
    if (scenarioId === "bonanza") {
      b2 = `Las ventas crecen ${pct1(growth)} YoY · la contribución crece a menor velocidad.`;
      b3 = `Total ${fmtM(totalActual)} · variación +${fmtM(Math.abs(deltaUSD))} · top 3 (${top3Names}) concentran ${top3Pct.toFixed(1)}%${fastest ? ` · ${fastest.nombre} crece ${pct1(fastest.g)} con carga ${fastest.pctRebate}%` : ""}.`;
      b4 = `El motor de eficiencia opera fuera del top de concentración.`;
      b5 = `Profundizaría primero en cuentas Tier 1 · luego en canal digital.`;
    } else if (scenarioId === "tension") {
      b2 = `Las ventas se quedaron planas YoY (${pct1(growth)}) · el portafolio dejó de traccionar.`;
      b3 = `Total ${fmtM(totalActual)} · variación ${fmtM(deltaUSD)}${worst ? ` · ${worst.nombre} cae ${pct1(worst.g)}` : ""} · top 3 (${top3Names}) concentran ${top3Pct.toFixed(1)}%.`;
      b4 = `El deterioro empezó por la periferia · el núcleo Tier 1 todavía no muestra caída.`;
      b5 = `Profundizaría primero en las cuentas en caída · luego revisaría Tier 1.`;
    } else if (scenarioId === "crisis") {
      b2 = `Las ventas cayeron ${pct1(growth)} YoY · la cartera está perdiendo volumen.`;
      b3 = `Total ${fmtM(totalActual)} · variación ${fmtM(deltaUSD)}${worst ? ` · ${worst.nombre} cae ${pct1(worst.g)}` : ""}${fastest ? ` · ${fastest.nombre} crece ${pct1(fastest.g)}` : ""} · top 3 concentran ${top3Pct.toFixed(1)}%.`;
      b4 = `El canal tradicional cae · el e-commerce absorbe parcialmente la pérdida.`;
      b5 = `Profundizaría primero en las cuentas con mayor caída · luego canal digital.`;
    } else {
      // Fallback genérico
      b2 = `Las ventas presentan variación ${pct1(growth)} YoY.`;
      b3 = `Total ${fmtM(totalActual)} · variación ${fmtM(deltaUSD)} · top 3 (${top3Names}) concentran ${top3Pct.toFixed(1)}%.`;
      b4 = `La dinámica de la cartera depende de tres cuentas.`;
      b5 = `Profundizaría primero por cuenta · luego por canal.`;
    }
    const b6 = `*Confianza alta · cifras runtime sobre escenario ${scenarioId}.*`;
    const opener = [b2, b3, b4, b5, b6].filter(Boolean).join("\n\n");

    // Suggestions intactas (D5 mantener bitwise · legacy wording)
    const suggestionsByScenario = {
      bonanza: [
        "¿Por qué Mercado Libre crece tanto?",
        "¿Qué pasa si pierdo a Falabella?",
        "¿Dónde están los clientes que caen?",
      ],
      tension: [
        "¿Qué clientes están en caída?",
        "¿La carga comercial está subiendo sin retorno?",
        "¿Dónde podemos recuperar volumen?",
      ],
      crisis: [
        "¿Qué clientes están perdiendo más volumen?",
        "¿Mercado Libre puede compensar?",
        "¿Dónde corto y dónde sostengo?",
      ],
    };
    const suggestions = suggestionsByScenario[scenarioId] || suggestionsByScenario.bonanza;
    // BRIEF N-bis · Tipo A puro · suggestionsByScenario filtradas
    return { opener, suggestions: filterTextualSuggestions(suggestions) };
  }

  // ────────────────────────────────────────────────────────────────────────
  // BRANCH MARGENES
  // ────────────────────────────────────────────────────────────────────────
  if (moduloId === "margenes") {
    const k = getMargenKPI(scenarioId);
    const vk = getVentasKPI("Anual", null, scenarioId);
    const margenPct = k.pct;
    const margenAnt = k.pctAnt;
    const gap = k.gapPuntos;
    const benchmark = k.benchmark || 30.1;
    const deltaPp = margenPct - margenAnt;
    const ventaActual = vk.totalActual;

    // FIX #D-MARGEN-GAP-BENCHMARK-MIENTE · el gap a benchmark se calcula margen − benchmark (no gapPuntos
    // que es YoY). _gapBench < 0 = bajo benchmark · >= 0 = sobre. OFF: usa gapPuntos (el bug).
    const _marginGapFixOn = (typeof ADI_MARGIN_BENCHMARK_GAP_FIX_ENABLED !== "undefined" && ADI_MARGIN_BENCHMARK_GAP_FIX_ENABLED);
    const _gapBench = _marginGapFixOn ? (margenPct - benchmark) : gap;

    const gapContrib = ventaActual * (Math.abs(_gapBench) / 100);
    const erosionContrib = ventaActual * (Math.abs(deltaPp) / 100);

    const marg = clientesMargen;
    const ml = marg.find(c => c.nombre === "Mercado Libre");
    const topRebate = [...marg].sort((a, b) => b.rebates - a.rebates)[0];

    let b2, b3, b4, b5;
    if (scenarioId === "bonanza") {
      b2 = `El margen general está en ${margenPct.toFixed(1)}% · ${Math.abs(_gapBench).toFixed(1)}pp ${_gapBench >= 0 ? "sobre" : "bajo"} benchmark de industria.`;
      // D2 ajuste LOCKED: NO repetir "Margen X%" de B2.
      b3 = `Benchmark ${benchmark.toFixed(1)}% · gap ${fmtM(gapContrib)} · ${topRebate.nombre} concentra ${fmtM(topRebate.rebates)} en carga${ml ? ` · ${ml.nombre} opera con margen ${ml.margen.toFixed(1)}% y carga ${ml.pctRebate}%` : ""}.`;
      b4 = `La presión sobre margen se concentra en Tier 1.`;
      b5 = `Negociaría primero la carga comercial de ${topRebate.nombre} · luego revisaría Tier 2.`;
    } else if (scenarioId === "tension") {
      // D2-bis LOCKED: "erosionada" → "menos de contribución capturada"
      b2 = `El margen cayó de ${margenAnt.toFixed(1)}% a ${margenPct.toFixed(1)}% (${deltaPp >= 0 ? "+" : ""}${deltaPp.toFixed(1)}pp) · aproximadamente ${fmtM(erosionContrib)} menos de contribución capturada.`;
      // D2 ajuste LOCKED: NO repetir "Margen X%" de B2.
      b3 = `YoY ${deltaPp.toFixed(1)}pp · brecha de captura ${fmtM(erosionContrib)} · ${topRebate.nombre} concentra ${fmtM(topRebate.rebates)} en carga con margen ${topRebate.margen.toFixed(1)}%.`;
      b4 = `La caída de margen se origina en las cuentas que más pesan.`;
      b5 = `Negociaría primero la carga comercial de ${topRebate.nombre} · luego revisaría Tier 1 restante.`;
    } else if (scenarioId === "crisis") {
      // D2-bis LOCKED: "colapsó" → "cayó" · "destruida" → "menos de contribución capturada"
      b2 = `El margen cayó de ${margenAnt.toFixed(1)}% a ${margenPct.toFixed(1)}% (${deltaPp.toFixed(1)}pp) · aproximadamente ${fmtM(erosionContrib)} menos de contribución capturada.`;
      // D2 ajuste LOCKED: NO repetir "Margen X%" de B2.
      b3 = `YoY ${deltaPp.toFixed(1)}pp · brecha de captura ${fmtM(erosionContrib)} · ${topRebate.nombre} concentra ${fmtM(topRebate.rebates)} en carga sobre margen ${topRebate.margen.toFixed(1)}%.`;
      b4 = `Algunas cuentas Tier 1 operan cerca o bajo costo real.`;
      b5 = `Revisaría primero las cuentas con margen sub-costo · luego negociaría Tier 1 restante.`;
    } else {
      b2 = `El margen general está en ${margenPct.toFixed(1)}% · gap ${Math.abs(_gapBench).toFixed(1)}pp ${_gapBench >= 0 ? "sobre" : "bajo"} benchmark.`;
      b3 = `Benchmark ${benchmark.toFixed(1)}% · ${topRebate.nombre} concentra ${fmtM(topRebate.rebates)} en carga.`;
      b4 = `La presión sobre margen se concentra en Tier 1.`;
      b5 = `Negociaría primero la carga comercial de ${topRebate.nombre}.`;
    }
    const b6 = `*Confianza alta · cifras runtime sobre escenario ${scenarioId}.*`;
    const opener = [b2, b3, b4, b5, b6].filter(Boolean).join("\n\n");

    const suggestionsByScenario = {
      bonanza: [
        "¿Cuánto margen perdemos por cliente?",
        "¿Falabella está pagando lo que vale?",
        "¿Qué pasa si bajo la carga comercial de Lider?",
      ],
      tension: [
        "¿Dónde se está yendo el margen?",
        "¿Qué cliente concentra la pérdida?",
        "¿Cuánto recupero si renegocio la carga comercial?",
      ],
      crisis: [
        "¿Qué clientes están en pérdida real?",
        "¿Cuánto cuesta sostener a Ripley?",
        "¿Qué pasa si subo precios a los Tier 2?",
      ],
    };
    const suggestions = suggestionsByScenario[scenarioId] || suggestionsByScenario.bonanza;
    // BRIEF N-bis · Tipo A puro · suggestionsByScenario filtradas
    return { opener, suggestions: filterTextualSuggestions(suggestions) };
  }

  // ────────────────────────────────────────────────────────────────────────
  // BRANCH INVENTARIO
  // ────────────────────────────────────────────────────────────────────────
  if (moduloId === "inventario") {
    const k = getInvKPI(scenarioId);
    const totalInvUSD = k.totalUSD;
    const inmovUSD = k.inmovilizadoUSD;
    const inmovPct = k.inmovilizadoPct;
    const doh = k.doh;

    const skuScn = applyScenarioToSkuInventario(scenarioId);
    const inmovSkus = skuScn.filter(s => s.estado !== "Activo");

    let topCatName = null;
    let topCatPct = 0;
    if (inmovSkus.length > 0) {
      const byCat = {};
      inmovSkus.forEach(s => { byCat[s.sfamilia] = (byCat[s.sfamilia] || 0) + s.stockUSD; });
      const sumInmovUSD = inmovSkus.reduce((s, x) => s + x.stockUSD, 0);
      const sortedCat = Object.entries(byCat).sort((a, b) => b[1] - a[1]);
      topCatName = sortedCat[0][0];
      const topCatUSD = sortedCat[0][1];
      topCatPct = (topCatUSD / sumInmovUSD) * 100;
    }
    // C3.2 · SKU principal (pieza 4-5) · el top del set inmovSkus YA cargado (decisión (a) del founder · misma
    // data · seleccionar el top, no recompute externo). La categoría es el frente; el SKU es el responsable.
    const _topInmovSku = (VOICE_C32_EVIDENCE_ENABLED && inmovSkus.length > 0)
      ? [...inmovSkus].sort((a, b) => b.stockUSD - a.stockUSD)[0]
      : null;

    let b2, b3, b4, b5;
    if (scenarioId === "bonanza") {
      b2 = `El ${inmovPct.toFixed(1)}% del inventario opera fuera de rango óptimo · cobertura promedio ${doh} días.`;
      b3 = `Inmovilizado ${fmtK(inmovUSD)} · total ${fmtK(totalInvUSD)}${topCatName ? ` · ${topCatName} concentra ${topCatPct.toFixed(1)}% del capital detenido` : ""}.`;
      // D2 ajuste LOCKED: B4 lectura ejecutiva · topCatName ya está en B3.
      b4 = `El problema es estructural en una sola línea de producto.`;
      b5 = topCatName
        ? `Atacaría primero los SKUs de ${topCatName} · luego revisaría rotación por familia.`
        : `Atacaría primero los SKUs de la categoría más concentrada · luego revisaría rotación por familia.`;
    } else if (scenarioId === "tension") {
      // D2-bis LOCKED: "velocidad de deterioro creciente" → "SKUs cruzando a estado lento"
      b2 = `El ${inmovPct.toFixed(1)}% del inventario opera fuera de rango óptimo · cobertura ${doh} días · SKUs cruzando a estado lento.`;
      b3 = `Inmovilizado ${fmtK(inmovUSD)} · total ${fmtK(totalInvUSD)}${topCatName ? ` · ${topCatName} concentra ${topCatPct.toFixed(1)}% del capital detenido · SKUs activos hace meses cruzaron a estado lento` : ""}.`;
      // D2 ajuste LOCKED: "pesa más que" → "está en velocidad de cambio · no en magnitud absoluta"
      b4 = `El problema está en velocidad de cambio · no en magnitud absoluta.`;
      b5 = topCatName
        ? `Atacaría primero los SKUs recién cruzados a lento · luego revisaría ${topCatName}.`
        : `Atacaría primero los SKUs recién cruzados a lento · luego revisaría por familia.`;
    } else if (scenarioId === "crisis") {
      // D2-bis LOCKED: "comprometido duplicado vs base" → "sobre el doble del rango base"
      b2 = `El ${inmovPct.toFixed(1)}% del inventario opera fuera de rango óptimo · cobertura ${doh} días · capital detenido sobre el doble del rango base.`;
      b3 = `Inmovilizado ${fmtK(inmovUSD)} · total ${fmtK(totalInvUSD)}${topCatName ? ` · ${topCatName} concentra ${topCatPct.toFixed(1)}% del capital detenido` : ""}.`;
      // D2-bis LOCKED: "presiona" → "impacta el ciclo de caja"
      b4 = `El capital detenido impacta el ciclo de caja.`;
      b5 = topCatName
        ? `Liquidaría primero los SKUs de ${topCatName} · luego priorizaría categorías por cobertura.`
        : `Liquidaría primero los SKUs de la categoría más concentrada · luego priorizaría por cobertura.`;
    } else {
      b2 = `El ${inmovPct.toFixed(1)}% del inventario opera fuera de rango óptimo · cobertura ${doh} días.`;
      b3 = `Inmovilizado ${fmtK(inmovUSD)} · total ${fmtK(totalInvUSD)}.`;
      b4 = `El stock detenido requiere lectura por familia.`;
      b5 = `Revisaría rotación por familia.`;
    }
    const b6 = `*Confianza alta · cifras runtime sobre escenario ${scenarioId}.*`;
    const opener = [b2, b3, b4, b5, b6].filter(Boolean).join("\n\n");

    const suggestionsByScenario = {
      bonanza: [
        "¿Qué SKUs están atrapando más capital?",
        "¿Por qué Materiales de Construcción se desbordó?",
        "¿Cuánto puedo recuperar si actúo ahora?",
      ],
      tension: [
        "¿Qué productos están deteniéndose?",
        "¿Por qué Línea Blanca dejó de rotar?",
        "¿Cuánto pierdo si los liquido?",
      ],
      crisis: [
        "¿Qué SKUs liquido primero?",
        "¿Cuánto puedo recuperar en 90 días?",
        "¿Qué productos están en quiebre próximo?",
      ],
    };
    const suggestions = suggestionsByScenario[scenarioId] || suggestionsByScenario.bonanza;
    // BRIEF N-bis · Tipo A puro · suggestionsByScenario filtradas
    // C3.2 · EVIDENCIA DE LA TESIS (nivel 2) · ADITIVO read-only · las 5 piezas con los valores YA computados
    // arriba (inmovUSD/topCatName/topCatPct = los mismos que el opener interpoló · _topInmovSku derivado de
    // inmovSkus ya cargado). SEÑAL DE EXPERIENCIA para Sentrix · NUNCA leída por razonamiento. El opener (prosa)
    // queda byte-idéntico — esto solo deja de DESCARTAR lo computado. Valores RAW (Sentrix formatea igual que el opener).
    return {
      opener,
      suggestions: filterTextualSuggestions(suggestions),
      ...(VOICE_C32_EVIDENCE_ENABLED ? {
        evidencia: {
          capital_inmovilizado_USD: inmovUSD,                       // pieza 1 · = el inmovUSD del opener
          categoria_responsable:    topCatName,                     // pieza 2 · = el topCatName del opener
          participacion_pct:        topCatPct,                      // pieza 3 · = el topCatPct del opener
          sku_principal:            _topInmovSku ? _topInmovSku.sku : null,       // pieza 4 · top de inmovSkus
          capital_asociado_USD:     _topInmovSku ? _topInmovSku.stockUSD : null,  // pieza 5 · su stockUSD
        },
      } : {}),
    };
  }

  // Fallback defensivo · módulo no reconocido
  return {
    opener: "Cuéntame qué módulo quieres explorar: ventas, márgenes o inventario.",
    // BRIEF N-bis · Tipo A puro · filtradas
    suggestions: filterTextualSuggestions(["Las ventas", "El margen", "El inventario"]),
  };
}

// ════════════════════════════════════════════════════════════════════════════
function composeModuleOverview(scenarioId, moduloId) {
  // ════════════════════════════════════════════════════════════════════════
  // BRIEF #15 · Executive V1 dispatch · Oleada 1
  // Flag rollback: cambiar a false → composer legacy se ejecuta bitwise.
  // ════════════════════════════════════════════════════════════════════════
  const VOICE_EXEC_MODULE_OVERVIEW_ENABLED = true;
  if (VOICE_EXEC_MODULE_OVERVIEW_ENABLED) {
    return composeModuleOverviewV2(scenarioId, moduloId);
  }
  // ── Helpers internos ───────────────────────────────────────────────────
  const fmtM = (val) => {
    // val expressed in same scale as ventasKPI.totalActual (e.g. 100000 = $100M)
    const m = val / 1000;
    return Number.isInteger(m) ? `$${m}M` : `$${m.toFixed(1)}M`;
  };
  const fmtK = (val) => {
    if (val >= 1000) {
      const k = val / 1000;
      return Number.isInteger(k) ? `$${k}K` : `$${k.toFixed(1)}K`;
    }
    return `$${Math.round(val)}`;
  };
  const pct1 = (v) => `${v >= 0 ? "+" : ""}${v.toFixed(1)}%`;

  // ────────────────────────────────────────────────────────────────────────
  // BRANCH VENTAS
  //   Cifra principal · vsAnterior · delta absoluto · cifras CANÓNICAS via
  //   getVentasKPI(scenarioId). Runtime se usa SOLO para enriquecimiento:
  //   top 3 ranking, fastest grower y worst decliner.
  //   Regla LOCKED: dashboard muestra KPI canónico · narrativa debe coincidir.
  // ────────────────────────────────────────────────────────────────────────
  if (moduloId === "ventas") {
    // ── KPI canónico (scenario-aware · misma fuente que el dashboard)
    const kpi = getVentasKPI("Anual", null, scenarioId);
    const totalActual   = kpi.totalActual;     // escala miles (99,999 = $99.999M)
    const totalAnterior = kpi.totalAnterior;
    const growth        = kpi.vsAnterior;      // canónico 7.6 / 0 / -12.6
    const deltaUSD      = totalActual - totalAnterior; // escala miles

    // ── Runtime (enriquecimiento · top 3, fastest, worst)
    const dataset = applyScenarioToClientesVentas(scenarioId);
    const sorted = [...dataset].sort((a, b) => b.actual - a.actual);
    const top3 = sorted.slice(0, 3);
    const top3Sum = top3.reduce((s, c) => s + c.actual, 0);
    const top3Pct = (top3Sum / totalActual) * 100;
    const top3Names = top3.map(c => c.nombre).join(", ");

    const growers = dataset
      .filter(c => c.actual > c.anterior)
      .map(c => ({ ...c, g: ((c.actual - c.anterior) / c.anterior) * 100 }))
      .sort((a, b) => b.g - a.g);
    const fastest = growers[0] || null;

    const decliners = dataset
      .filter(c => c.actual < c.anterior)
      .map(c => ({ ...c, g: ((c.actual - c.anterior) / c.anterior) * 100 }))
      .sort((a, b) => a.g - b.g);
    const worst = decliners[0] || null;

    // ── Header · cifra principal canónica (escala miles → fmtM)
    const m1 = `El año cerró en ${fmtM(totalActual)} con crecimiento de ${pct1(growth)} versus el período anterior, equivalente a ${fmtM(Math.abs(deltaUSD))} de variación absoluta.`;

    // ── Cuerpo · top 3 + concentración (R3 + R5)
    const m2 = `${top3Names} concentran el ${top3Pct.toFixed(1)}% de la facturación, lo que explica que la dinámica de la cartera dependa de tres cuentas.`;

    // ── Lectura · pattern estructural + outlier (R8)
    let m3 = "";
    if (scenarioId === "bonanza" && fastest) {
      m3 = `${fastest.nombre} crece ${pct1(fastest.g)} con apenas ${fastest.pctRebate}% de carga comercial, mientras la cartera promedio opera entre 3% y 5%. El motor de eficiencia está fuera del top de concentración.`;
    } else if (scenarioId === "tension") {
      const tier1Growth = top3.map(c => ((c.actual - c.anterior) / c.anterior) * 100);
      const flatNames = top3.filter((c, i) => Math.abs(tier1Growth[i]) < 3).map(c => c.nombre).join(" y ");
      m3 = worst
        ? `${worst.nombre} cae ${pct1(worst.g)}${flatNames ? ` mientras ${flatNames} se mantienen prácticamente planos` : ""}, lo que indica que el deterioro empezó por la periferia y aún no contagia el núcleo Tier 1.`
        : `El crecimiento del período anterior se desinfló sin que cambiara el portafolio comercial.`;
    } else if (scenarioId === "crisis") {
      m3 = worst && fastest
        ? `${worst.nombre} cae ${pct1(worst.g)} mientras ${fastest.nombre} crece ${pct1(fastest.g)}, lo que muestra ruptura del modelo comercial: el deterioro es estructural en los canales tradicionales y el e-commerce absorbe parcialmente la caída.`
        : `El portafolio entra en contracción profunda con concentración del riesgo en cuentas Tier 1.`;
    } else if (fastest) {
      m3 = `${fastest.nombre} crece ${pct1(fastest.g)} con carga comercial ${fastest.pctRebate}%, lo que explica que la eficiencia de la cartera dependa de un canal con condiciones distintas al promedio.`;
    }

    const m4 = `¿Qué quieres entender primero?`;
    const confianza = `*Confianza alta · cifras runtime sobre escenario ${scenarioId}.*`;
    const opener = [m1, m2, m3, m4, confianza].filter(Boolean).join("\n\n");

    const suggestionsByScenario = {
      bonanza: [
        "¿Por qué Mercado Libre crece tanto?",
        "¿Qué pasa si pierdo a Falabella?",
        "¿Dónde están los clientes que caen?",
      ],
      tension: [
        "¿Qué clientes están en caída?",
        "¿La carga comercial está subiendo sin retorno?",
        "¿Dónde podemos recuperar volumen?",
      ],
      crisis: [
        "¿Qué clientes están perdiendo más volumen?",
        "¿Mercado Libre puede compensar?",
        "¿Dónde corto y dónde sostengo?",
      ],
    };
    const suggestions = suggestionsByScenario[scenarioId] || suggestionsByScenario.bonanza;

    // BRIEF N-bis · Tipo A puro · suggestionsByScenario filtradas (LEGACY · no-runtime · por consistencia)
    return { opener, suggestions: filterTextualSuggestions(suggestions) };
  }

  // ────────────────────────────────────────────────────────────────────────
  // BRANCH MARGENES
  //   Cifra principal · pct, pctAnt, totalUSD, gapPuntos, benchmark CANÓNICAS
  //   via getMargenKPI(scenarioId). Ventas canónicas via getVentasKPI para
  //   coherencia bitwise (escala miles → fmtM). Runtime se usa SOLO para
  //   enriquecimiento: outlier topRebate y outlier virtuoso (Mercado Libre).
  // ────────────────────────────────────────────────────────────────────────
  if (moduloId === "margenes") {
    const k = getMargenKPI(scenarioId);
    const vk = getVentasKPI("Anual", null, scenarioId);
    const margenPct = k.pct;
    const margenAnt = k.pctAnt;
    const contribTotal = k.totalUSD;       // escala miles
    const gap = k.gapPuntos;                // YoY (pct - pctAnt) · NO vs benchmark (ver L17790)
    const benchmark = k.benchmark || 30.1;
    const deltaPp = margenPct - margenAnt; // delta YoY puntos
    const ventaActual = vk.totalActual;    // escala miles (KPI canónico)

    // FIX #D-MARGEN-GAP-BENCHMARK-MIENTE · el gap a benchmark = margen − benchmark (no gapPuntos · YoY).
    const _marginGapFixOn = (typeof ADI_MARGIN_BENCHMARK_GAP_FIX_ENABLED !== "undefined" && ADI_MARGIN_BENCHMARK_GAP_FIX_ENABLED);
    const _gapBench = _marginGapFixOn ? (margenPct - benchmark) : gap;

    // ── Gap contribution vs benchmark · ventas canónicas × gap puntos
    //    Esto coincide con el monto que el dashboard expone como brecha vs benchmark.
    const gapContrib = ventaActual * (Math.abs(_gapBench) / 100); // escala miles

    // ── Contribución erosionada YoY · ventas canónicas × delta puntos
    //    Solo aplica cuando deltaPp < 0 (margen cayó respecto al período anterior).
    const erosionContrib = ventaActual * (Math.abs(deltaPp) / 100); // escala miles

    // ── Runtime · outlier de carga comercial (cliente concentrador)
    const marg = clientesMargen;
    const ml = marg.find(c => c.nombre === "Mercado Libre");
    const topRebate = [...marg].sort((a, b) => b.rebates - a.rebates)[0];

    let m1, m2, m3;

    if (scenarioId === "bonanza") {
      // Bonanza · gap vs benchmark (positivo o negativo según escenario)
      m1 = `El margen general está en ${margenPct.toFixed(1)}%, ${Math.abs(_gapBench).toFixed(1)} puntos ${_gapBench >= 0 ? "sobre" : "bajo"} el benchmark de industria (${benchmark.toFixed(1)}%), equivalente a ${fmtM(gapContrib)} de contribución ${_gapBench >= 0 ? "capturada sobre el estándar" : "no capturada"}.`;
      m2 = `${topRebate.nombre} concentra ${fmtM(topRebate.rebates)} en carga comercial con margen ${topRebate.margen.toFixed(1)}%, mientras ${ml.nombre} opera con margen ${ml.margen.toFixed(1)}% y carga ${ml.pctRebate}% — la diferencia es estructural, no coyuntural.`;
      m3 = `La carga comercial sobre cuentas Tier 1 explica gran parte de la diferencia versus benchmark, ya que el resto del portafolio opera dentro de rango.`;
    } else if (scenarioId === "tension") {
      m1 = `El margen cayó de ${margenAnt.toFixed(1)}% a ${margenPct.toFixed(1)}% en un año (${deltaPp >= 0 ? "+" : ""}${deltaPp.toFixed(1)}pp), equivalente aproximadamente a ${fmtM(erosionContrib)} de contribución erosionada.`;
      m2 = `${topRebate.nombre} concentra ${fmtM(topRebate.rebates)} en carga comercial con margen ${topRebate.margen.toFixed(1)}%, lo que muestra que la erosión se origina en las cuentas que más pesan.`;
      m3 = `La carga comercial subió sin retorno en volumen, lo que significa que el incentivo dejó de comprar ventas y empezó a destruir contribución.`;
    } else if (scenarioId === "crisis") {
      m1 = `El margen colapsó de ${margenAnt.toFixed(1)}% a ${margenPct.toFixed(1)}% (${deltaPp >= 0 ? "+" : ""}${deltaPp.toFixed(1)}pp), equivalente aproximadamente a ${fmtM(erosionContrib)} de contribución destruida.`;
      m2 = `${topRebate.nombre} concentra ${fmtM(topRebate.rebates)} en carga comercial sobre margen ${topRebate.margen.toFixed(1)}%, lo que indica que algunas cuentas Tier 1 están operando cerca o bajo costo real.`;
      m3 = `La empresa está perdiendo contribución por sostener volumen, ya que la carga comercial supera el retorno marginal de varios clientes.`;
    } else {
      m1 = `El margen general está en ${margenPct.toFixed(1)}%, con gap de ${Math.abs(_gapBench).toFixed(1)}pp ${_gapBench >= 0 ? "sobre" : "bajo"} benchmark.`;
      m2 = `${topRebate.nombre} concentra ${fmtM(topRebate.rebates)} en carga comercial.`;
      m3 = `La presión sobre margen explica la mayor parte de la brecha versus benchmark.`;
    }

    const m4 = `¿Por dónde profundizamos?`;
    const confianza = `*Confianza alta · cifras runtime sobre escenario ${scenarioId}.*`;
    const opener = [m1, m2, m3, m4, confianza].join("\n\n");

    const suggestionsByScenario = {
      bonanza: [
        "¿Cuánto margen perdemos por cliente?",
        "¿Falabella está pagando lo que vale?",
        "¿Qué pasa si bajo la carga comercial de Lider?",
      ],
      tension: [
        "¿Dónde se está yendo el margen?",
        "¿Qué cliente concentra la pérdida?",
        "¿Cuánto recupero si renegocio la carga comercial?",
      ],
      crisis: [
        "¿Qué clientes están en pérdida real?",
        "¿Cuánto cuesta sostener a Ripley?",
        "¿Qué pasa si subo precios a los Tier 2?",
      ],
    };
    const suggestions = suggestionsByScenario[scenarioId] || suggestionsByScenario.bonanza;

    // BRIEF N-bis · Tipo A puro · suggestionsByScenario filtradas (LEGACY · no-runtime · por consistencia)
    return { opener, suggestions: filterTextualSuggestions(suggestions) };
  }

  // ────────────────────────────────────────────────────────────────────────
  // BRANCH INVENTARIO
  // ────────────────────────────────────────────────────────────────────────
  if (moduloId === "inventario") {
    const k = getInvKPI(scenarioId);
    const totalInvUSD = k.totalUSD;       // canónico scenario-aware
    const inmovUSD = k.inmovilizadoUSD;   // canónico scenario-aware
    const inmovPct = k.inmovilizadoPct;   // canónico scenario-aware
    const doh = k.doh;

    // Top categoría runtime sobre SKUs con estado !== "Activo"
    // (autorización BRIEF #2 · Opción C)
    const skuScn = applyScenarioToSkuInventario(scenarioId);
    const inmovSkus = skuScn.filter(s => s.estado !== "Activo");

    let topCatName = null;
    let topCatPct = 0;
    let topCatUSD = 0;
    if (inmovSkus.length > 0) {
      const byCat = {};
      inmovSkus.forEach(s => { byCat[s.sfamilia] = (byCat[s.sfamilia] || 0) + s.stockUSD; });
      const sumInmovUSD = inmovSkus.reduce((s, x) => s + x.stockUSD, 0);
      const sortedCat = Object.entries(byCat).sort((a, b) => b[1] - a[1]);
      topCatName = sortedCat[0][0];
      topCatUSD = sortedCat[0][1];
      topCatPct = (topCatUSD / sumInmovUSD) * 100;
    }

    // Header · cifra principal canónica scenario-aware
    const m1 = `El ${inmovPct.toFixed(1)}% del inventario opera fuera de rango óptimo, con ${fmtK(inmovUSD)} comprometidos sobre un total de ${fmtK(totalInvUSD)} en stock. La cobertura promedio se ubica en ${doh} días.`;

    // Cuerpo · top categoría runtime (R3 + R5)
    let m2 = "";
    if (topCatName) {
      m2 = `${topCatName} concentra el ${topCatPct.toFixed(1)}% del capital inmovilizado, lo que explica que el problema esté estructuralmente en una sola línea de producto.`;
    }

    // Lectura causal · diferenciada por scenario (R8)
    let m3 = "";
    if (scenarioId === "bonanza") {
      m3 = `El stock detenido es manejable en magnitud pero está concentrado en SKUs específicos, ya que la rotación promedio del portafolio rotacional opera sobre 8x.`;
    } else if (scenarioId === "tension") {
      m3 = `La velocidad del deterioro pesa más que el monto absoluto, ya que SKUs que estaban activos hace meses cruzaron a estado lento sin reacción comercial.`;
    } else if (scenarioId === "crisis") {
      m3 = `El capital comprometido se duplicó versus el escenario base, lo que provoca presión sobre flujo de caja y obliga a priorizar liquidación versus sostenimiento.`;
    }

    const m4 = `¿Por dónde quieres empezar a desarmar el problema?`;
    const confianza = `*Confianza alta · cifras runtime sobre escenario ${scenarioId}.*`;
    const opener = [m1, m2, m3, m4, confianza].filter(Boolean).join("\n\n");

    const suggestionsByScenario = {
      bonanza: [
        "¿Qué SKUs están atrapando más capital?",
        "¿Por qué Materiales de Construcción se desbordó?",
        "¿Cuánto puedo recuperar si actúo ahora?",
      ],
      tension: [
        "¿Qué productos están deteniéndose?",
        "¿Por qué Línea Blanca dejó de rotar?",
        "¿Cuánto pierdo si los liquido?",
      ],
      crisis: [
        "¿Qué SKUs liquido primero?",
        "¿Cuánto puedo recuperar en 90 días?",
        "¿Qué productos están en quiebre próximo?",
      ],
    };
    const suggestions = suggestionsByScenario[scenarioId] || suggestionsByScenario.bonanza;

    // BRIEF N-bis · Tipo A puro · suggestionsByScenario filtradas (LEGACY · no-runtime · por consistencia)
    return { opener, suggestions: filterTextualSuggestions(suggestions) };
  }

  // Fallback defensivo · módulo no reconocido
  return {
    opener: "Cuéntame qué módulo quieres explorar: ventas, márgenes o inventario.",
    // BRIEF N-bis · Tipo A puro · filtradas
    suggestions: filterTextualSuggestions(["Las ventas", "El margen", "El inventario"]),
  };
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #7 (post-46-bis) · QUERY INTERPRETER LIMPIO · PIEZAS 1-3
// ════════════════════════════════════════════════════════════════════════════
//
// Capa paramétrica de retrieval · paralela al flujo legacy · NUNCA secuestra
// preguntas ejecutivas. Activación EXCLUSIVA cuando:
//   1. Suggestion interceptor NO aplica (no es from suggestion)
//   2. executiveLanguageDetector retorna isExecutive === false
//   3. queryInterpreter retorna isRetrieval === true
//
// Orden cognitivo LOCKED (regla nuclear):
//   Retrieval responde datos.
//   Ferrari interpreta problemas.
//   Premise valida afirmaciones.
//
// Decisiones founder integradas FASE 2:
//   D1 · Excepción top N + por + metric NO bloquea como ejecutivo
//   D2 · retrieval_filtered diferido a #7-bis (V1 solo simple/multi/ranked)
//   D3 · METRICS singular Y plural ambos
//   D4 · Paramétricos preservados PRIORIDAD A · Ferrari sigue capturando
//   D5 · Premise corre siempre · PREPEND solo si claim afirmativo
// ════════════════════════════════════════════════════════════════════════════

// ── PIEZA 2 · executiveLanguageDetector ─────────────────────────────────────
// Detecta si el input tiene lenguaje ejecutivo (problema/foco/causa/riesgo/
// presión/erosión/comprimido/atrapado/dependencia/amenaza). Si retorna
// isExecutive=true · QI NUNCA captura · cae a Ferrari path scoreIntents.
//
// Excepción D1: "top N + dimension + por + metric" NO bloquea como ejecutivo
// aunque domain_concentration esté activado (F6 noun+top emite canonical pero
// query es retrieval ranked puro · no riesgo).
const EXECUTIVE_KEYWORDS_RAW = [
  "problema", "foco", "causa", "por que", "porque", "que pasa", "riesgo",
  "presion", "erosion", "comprimido", "comprimida", "atrapado", "atrapada",
  "dependencia", "amenaza", "donde esta", "me cuesta", "comen", "comiendo",
  "esta cayendo", "pierdo", "perdemos", "pagando", "renegociar",
  "bajo carga", "sobre el margen", "crece tanto", "erosionado", "erosionada",
  "presionado", "presionada", "destruyen", "diluyen", "asfixia",
];
const EXECUTIVE_CONCEPTS_RAW = [
  "loss_explicit", "mechanism_entity_erosion", "mechanism_entity_dependency",
  "mechanism_entity_quality", "domain_concentration", "profitability_negative",
];

function executiveLanguageDetector(text, concepts) {
  if (!text || typeof text !== "string") {
    return { isExecutive: false, marker: null };
  }
  // Normalizar (lowercase + remove accents)
  const norm = text
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

  // Excepción D1 · top N + por + dimension + metric: NO bloquear como executive
  // (es retrieval ranked puro · F6 "concentration" debe ceder a QI)
  const hasTopN = /\btop\s+\d+\b/.test(norm) || /\bprimeros?\s+\d+\b/.test(norm);
  const hasPorConector = /\bpor\b/.test(norm);
  const METRIC_TOKENS_QUICK = [
    "ventas", "venta", "margen", "margenes", "contribucion", "contribuciones",
    "rotacion", "cobertura", "doh", "carga", "stock", "rentabilidad",
    "participacion", "aporte",
  ];
  const DIMENSION_TOKENS_QUICK = [
    "cliente", "clientes", "cuenta", "cuentas", "sku", "skus",
    "producto", "productos", "familia", "familias", "marca", "marcas",
    "sucursal", "sucursales", "bodega", "bodegas", "canal", "canales",
    "tier",
  ];
  const hasMetric = METRIC_TOKENS_QUICK.some(m => new RegExp("\\b" + m + "\\b").test(norm));
  const hasDimension = DIMENSION_TOKENS_QUICK.some(d => new RegExp("\\b" + d + "\\b").test(norm));
  const isTopNRanked = hasTopN && hasPorConector && hasMetric && hasDimension;

  // Keywords ejecutivos
  for (const kw of EXECUTIVE_KEYWORDS_RAW) {
    if (norm.includes(kw)) {
      // Verificar excepción top N antes de bloquear
      if (isTopNRanked) {
        // top N override: ignorar keyword executive (caso D1)
        // Salvo keywords MUY fuertes que claramente son ejecutivos
        const HARD_KEYWORDS = ["problema", "foco", "causa", "riesgo", "amenaza", "me cuesta"];
        if (!HARD_KEYWORDS.includes(kw)) continue;
      }
      return { isExecutive: true, marker: "keyword:" + kw };
    }
  }

  // Concepts ejecutivos (desde semantic pipeline)
  const conceptsList = Array.isArray(concepts) ? concepts : [];
  for (const c of EXECUTIVE_CONCEPTS_RAW) {
    if (conceptsList.includes(c)) {
      // Excepción D1: domain_concentration con estructura top N + por + metric
      if (c === "domain_concentration" && isTopNRanked) {
        continue;
      }
      return { isExecutive: true, marker: "concept:" + c };
    }
  }

  return { isExecutive: false, marker: null };
}

// ── PIEZA 1 · queryInterpreter ──────────────────────────────────────────────
// Función pura · toma (text, scenario, semanticContext) y retorna shape de
// retrieval paramétrico:
//   { isRetrieval, queryType, metrics, dimensions, format, limit }
//
// queryType V1 (Decisión 2 · retrieval_filtered diferido a #7-bis):
//   "simple"  · 1 metric + 1 dimension
//   "multi"   · 2+ metrics + 1 dimension
//   "ranked"  · 1 metric + 1 dimension + top N
//
// METRICS singular Y plural (Decisión 3).
const QI_METRIC_VOCAB = {
  ventas:        ["ventas", "venta"],
  margen:        ["margen", "margenes", "márgenes"],
  contribucion:  ["contribucion", "contribuciones", "contribución"],
  rotacion:      ["rotacion", "rotación"],
  cobertura:     ["cobertura", "doh"],
  carga:         ["carga", "carga comercial"],
  stock:         ["stock"],
  rentabilidad:  ["rentabilidad"],
  participacion: ["participacion", "participación"],
  aporte:        ["aporte"],
};
const QI_DIMENSION_VOCAB = {
  cliente:   ["cliente", "clientes", "cuenta", "cuentas"],
  sku:       ["sku", "skus"],
  producto:  ["producto", "productos"],
  familia:   ["familia", "familias", "categoria", "categorias", "categoría", "categorías"],
  marca:     ["marca", "marcas"],
  sucursal:  ["sucursal", "sucursales", "bodega", "bodegas"],
  canal:     ["canal", "canales"],
  tier:      ["tier"],
};
const QI_FORMAT_KEYWORDS = {
  tabla:   ["en tabla", "tabular", "como tabla"],
  ranking: ["rankeado", "ranking", "ordenado"],
  lista:   ["en lista", "como lista"],
};
const QI_IMPERATIVE_PREFIX = [
  "dame", "muestrame", "muéstrame", "listame", "lístame",
  "lista de", "lista", "ranking de", "dame ranking de",
];

function queryInterpreter(text, scenario, semanticContext) {
  const empty = {
    isRetrieval: false,
    queryType: null,
    metrics: [],
    dimensions: [],
    format: null,
    limit: null,
  };
  if (!text || typeof text !== "string") return empty;

  // Normalizar (lowercase + remove accents)
  const norm = text
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[¿?¡!]/g, "")
    .trim();

  // 1. Detectar metrics (canonical key · puede haber múltiples)
  const detectedMetrics = [];
  for (const [canonical, vocab] of Object.entries(QI_METRIC_VOCAB)) {
    for (const term of vocab) {
      if (new RegExp("\\b" + term.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "\\b").test(norm)) {
        if (!detectedMetrics.includes(canonical)) detectedMetrics.push(canonical);
        break;
      }
    }
  }

  // 2. Detectar dimensions (canonical key)
  const detectedDimensions = [];
  for (const [canonical, vocab] of Object.entries(QI_DIMENSION_VOCAB)) {
    for (const term of vocab) {
      if (new RegExp("\\b" + term.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "\\b").test(norm)) {
        if (!detectedDimensions.includes(canonical)) detectedDimensions.push(canonical);
        break;
      }
    }
  }

  // 3. Detectar conector "por" (requerido para retrieval)
  const hasPor = /\bpor\b/.test(norm);

  // 4. Sin metrics o sin dimensions o sin "por" · NO es retrieval V1
  if (detectedMetrics.length === 0 || detectedDimensions.length === 0 || !hasPor) {
    return empty;
  }

  // 5. Detectar top N (ranked)
  let topN = null;
  const topMatch = norm.match(/\btop\s+(\d+)\b/) || norm.match(/\bprimeros?\s+(\d+)\b/);
  if (topMatch) {
    topN = parseInt(topMatch[1], 10);
    if (Number.isNaN(topN) || topN < 1 || topN > 50) topN = null;
  }

  // 6. Detectar format keyword
  let detectedFormat = null;
  for (const [fmtKey, kws] of Object.entries(QI_FORMAT_KEYWORDS)) {
    for (const kw of kws) {
      if (norm.includes(kw)) { detectedFormat = fmtKey; break; }
    }
    if (detectedFormat) break;
  }

  // 7. Detectar imperativo (informativo · no requerido)
  const hasImperative = QI_IMPERATIVE_PREFIX.some(p =>
    norm === p || norm.startsWith(p + " ")
  );

  // 8. Determinar queryType
  let queryType;
  if (topN !== null) {
    queryType = "ranked";
  } else if (detectedMetrics.length >= 2) {
    queryType = "multi";
  } else {
    queryType = "simple";
  }

  // 9. Default format
  let finalFormat = detectedFormat;
  if (!finalFormat) {
    if (queryType === "ranked") finalFormat = "ranking";
    else if (queryType === "multi") finalFormat = "tabla";
    else finalFormat = "tabla";
  }

  return {
    isRetrieval: true,
    queryType,
    metrics: detectedMetrics,
    dimensions: detectedDimensions,
    format: finalFormat,
    limit: topN,
  };
}

// ── PIEZA 3 · composeRetrieval ──────────────────────────────────────────────
// Composer ligero · genera output paramétrico estructurado.
// Estructura canónica preliminar: Header + Cuerpo tabular (NBSP padding) +
// Foco breve + Confianza. SIN recomendación full. SIN sentrixAction V1.
//
// Lee datasets canónicos:
//   · clientesMargen (via applyScenarioToClientesMargen) · cliente dim
//   · skusMargen · sku/producto dim
//   · sfamiliasMargen · familia/categoria dim
//   · clientesVentas / sfamiliasVentas para metric "ventas" cuando aplica
//
// Si una metric/dimension no se puede resolver con datasets disponibles,
// retorna null · QI fallback a path legacy.

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #9 (post-46-bis) · RETRIEVAL INTELLIGENCE LAYER · PIEZAS 1-3
// ════════════════════════════════════════════════════════════════════════════
//
// Capa de razonamiento mínimo sobre QueryInterpreter retrieval.
// Agrega Lectura ejecutiva (1-2 frases) + Próximo ángulo dentro del Foco.
//
// REGLA NUCLEAR · IDENTIDAD COGNITIVA RETRIEVAL:
//   RIL describe patrones · NUNCA explica causas.
//   No inventa. No interpreta más allá de lo objetivo.
//   Fallback silencioso si datos no soportan lectura no-trivial.
//
// Decisiones founder integradas FASE 2:
//   D1 · Signature variables runtime directas (no qiOutput parsing)
//   D2 · Calidad cruzada · cruce confirmado AMBOS sentidos (estricto)
//   D3 · Riesgo umbral · top3_share ∈ (0.40, 0.95)
//   D4 · Brecha umbral · gap_pct ≥ 15% (wording natural)
//   D5 · Brecha scope · solo queryType === "ranked"
//   D6 · Próximo ángulo · mapeo rentabilidad→margen, aporte→contribucion,
//        participacion→ventas
//   D7 · Datos no-monetary · CONCENTRACIÓN/RIESGO flexibles · CALIDAD
//        CRUZADA y BRECHA strict
//
// GUARDRAILS LOCKED:
//   1. NO inventar causas
//   2. NO convertir retrieval en Ferrari (≤ 2 frases Lectura)
//   3. NO tocar Ferrari composers / handleUserSubmit
//   4. Próximo ángulo SIEMPRE dentro de Foco · NUNCA en suggestions
//   5. try-catch defensivo · passthrough si falla
// ════════════════════════════════════════════════════════════════════════════

// ── PIEZA 3.1 · rilIsMonetaryOrPct ──────────────────────────────────────────
// Identifica si una metric es monetary o porcentual (para D7 · BRECHA/CALIDAD
// requieren tipo conocido; CONCENTRACIÓN acepta cualquier sumable).
function rilIsMonetaryOrPct(metricKey) {
  // Monetary
  if (metricKey === "ventas" || metricKey === "venta") return "monetary";
  if (metricKey === "contribucion" || metricKey === "contribuciones") return "monetary";
  if (metricKey === "aporte") return "monetary";
  // Porcentual
  if (metricKey === "margen" || metricKey === "margenes") return "pct";
  if (metricKey === "rentabilidad") return "pct";
  if (metricKey === "carga") return "pct";
  if (metricKey === "participacion") return "pct";
  // Sumable numérico (unidades stock)
  if (metricKey === "stock") return "count";
  return null;
}

// ── PIEZA 3.2 · rilComputeConcentracion ─────────────────────────────────────
// Compute concentración stats sobre sortedRows (ya ordenado desc).
// Retorna métricas: top3Share, leaderShare, plus nombres.
function rilComputeConcentracion(sortedRows, sortField) {
  if (!Array.isArray(sortedRows) || sortedRows.length === 0) return null;
  let total = 0;
  for (const r of sortedRows) total += (r[sortField] || 0);
  if (total <= 0) return null;
  const top1Val = sortedRows[0][sortField] || 0;
  const top2Val = sortedRows.length > 1 ? (sortedRows[1][sortField] || 0) : 0;
  const top3Val = sortedRows.length > 2 ? (sortedRows[2][sortField] || 0) : 0;
  const top3Sum = top1Val + top2Val + top3Val;
  return {
    total: total,
    top1Val: top1Val,
    top2Val: top2Val,
    top3Val: top3Val,
    top1Name: sortedRows[0].nombre || "—",
    top2Name: sortedRows.length > 1 ? (sortedRows[1].nombre || "—") : null,
    top3Name: sortedRows.length > 2 ? (sortedRows[2].nombre || "—") : null,
    leaderShare: top1Val / total,
    top3Share: top3Sum / total,
    // Para CONCENTRACIÓN: porcentaje del siguiente (top2) sobre total
    nextShare: top2Val / total,
  };
}

// ── PIEZA 3.3 · rilComputeBrecha ────────────────────────────────────────────
// Compute brecha top1 vs top2 · solo si datos suficientes y monetary/pct.
function rilComputeBrecha(sortedRows, sortField) {
  if (!Array.isArray(sortedRows) || sortedRows.length < 2) return null;
  const top1Val = sortedRows[0][sortField] || 0;
  const top2Val = sortedRows[1][sortField] || 0;
  if (top2Val <= 0) return null;
  const gap = top1Val - top2Val;
  const gapPct = gap / top2Val;
  return {
    top1Val: top1Val,
    top2Val: top2Val,
    top1Name: sortedRows[0].nombre || "—",
    top2Name: sortedRows[1].nombre || "—",
    gap: gap,
    gapPct: gapPct, // ratio (0.17 = 17%)
  };
}

// ── PIEZA 3.4 · rilDetectCalidadCruzada ─────────────────────────────────────
// Detecta disonancia multi-metric: top1 de metric[0] tiene metric[1] bajo avg
// PORTAFOLIO Y best metric[1] tiene metric[0] bajo avg PORTAFOLIO.
// Cruce confirmado en AMBOS sentidos (D2 estricto). Si solo uno → null.
//
// Solo aplica para metric[1] de tipo "pct" o "monetary" (D7 strict para
// CALIDAD CRUZADA · comparable contra avg portfolio).
function rilDetectCalidadCruzada(sortedRows, metricMap, metrics) {
  if (!Array.isArray(metrics) || metrics.length < 2) return null;
  if (!Array.isArray(sortedRows) || sortedRows.length < 4) return null;

  const m0Key = metrics[0];
  const m1Key = metrics[1];
  const m0Field = metricMap[m0Key]?.field;
  const m1Field = metricMap[m1Key]?.field;
  if (!m0Field || !m1Field) return null;

  const m1Type = rilIsMonetaryOrPct(m1Key);
  const m0Type = rilIsMonetaryOrPct(m0Key);
  if (!m1Type || !m0Type) return null;
  // D7 strict: ambos comparables
  if (m1Type === "count" || m0Type === "count") return null;

  // Calcular promedios del portfolio (todos los rows)
  let sumM0 = 0, sumM1 = 0, count = 0;
  for (const r of sortedRows) {
    if (typeof r[m0Field] === "number" && typeof r[m1Field] === "number") {
      sumM0 += r[m0Field];
      sumM1 += r[m1Field];
      count++;
    }
  }
  if (count === 0) return null;
  const avgM0 = sumM0 / count;
  const avgM1 = sumM1 / count;
  if (avgM0 <= 0 || avgM1 <= 0) return null;

  // Top1 por metric[0] = sortedRows[0]
  const top1 = sortedRows[0];
  const top1M0 = top1[m0Field];
  const top1M1 = top1[m1Field];
  if (typeof top1M0 !== "number" || typeof top1M1 !== "number") return null;

  // Best row por metric[1] (orden descendente m1Field)
  let bestM1Row = null;
  let bestM1Val = -Infinity;
  for (const r of sortedRows) {
    const v = r[m1Field];
    if (typeof v === "number" && v > bestM1Val) {
      bestM1Val = v;
      bestM1Row = r;
    }
  }
  if (!bestM1Row || bestM1Row === top1) return null;
  const bestM1M0 = bestM1Row[m0Field];
  if (typeof bestM1M0 !== "number") return null;

  // Cruce AMBOS sentidos · D2 estricto:
  //   · top1 metric[0] tiene metric[1] BAJO avg portfolio
  //   · best metric[1] tiene metric[0] BAJO avg portfolio
  const top1HasLowM1 = top1M1 < avgM1;
  const bestHasLowM0 = bestM1M0 < avgM0;
  if (!top1HasLowM1 || !bestHasLowM0) return null;

  // Adicionalmente: para evitar disonancias triviales, exigir margen
  // significativo (≥ 10% de gap relativo en cualquier dirección).
  const m1GapPct = Math.abs(top1M1 - avgM1) / avgM1;
  const m0GapPct = Math.abs(bestM1M0 - avgM0) / avgM0;
  if (m1GapPct < 0.10 && m0GapPct < 0.10) return null;

  return {
    top1Name: top1.nombre || "—",
    top1M0Val: top1M0,
    top1M1Val: top1M1,
    bestM1Name: bestM1Row.nombre || "—",
    bestM1Val: bestM1Val,
    bestM1M0Val: bestM1M0,
    avgM0: avgM0,
    avgM1: avgM1,
    m0Type: m0Type,
    m1Type: m1Type,
  };
}

// ── PIEZA 3.5 · rilPickNextAngle ────────────────────────────────────────────
// Determinístico · retorna frase de próximo ángulo según queryType + primary
// metric (con mapeo D6) + dim.
function rilPickNextAngle(queryType, primaryMetric, dim) {
  // D6 · mapeo de metrics derivadas a base
  const metricMap = {
    rentabilidad: "margen",
    aporte: "contribucion",
    participacion: "ventas",
  };
  const m = metricMap[primaryMetric] || primaryMetric;
  const dimLow = (dim === "cliente" || dim === "sku" || dim === "familia" || dim === "marca")
                 ? dim : "item";

  if (queryType === "multi") {
    return "evaluar carga comercial por " + dimLow + " para identificar palancas de margen";
  }
  if (queryType === "ranked") {
    if (m === "ventas") return "validar margen del líder";
    if (m === "margen") return "validar volumen del líder vs lastres";
    if (m === "contribucion") return "validar rotación y disponibilidad operativa del líder";
    return "profundizar en el líder o validar lastres del portafolio";
  }
  // simple
  if (m === "ventas")       return "cruzar con margen y carga comercial para validar si esa concentración es sana";
  if (m === "margen")       return "cruzar con ventas para identificar palancas de margen";
  if (m === "contribucion") return "validar rotación y disponibilidad operativa del líder";
  if (m === "carga")        return "comparar contra benchmark interno (3.5%)";
  if (m === "stock")        return "cruzar con rotación por " + dimLow;
  return "profundizar en el líder o validar lastres del portafolio";
}

// ── PIEZA 1 · retrievalIntelligenceLayer ────────────────────────────────────
// Dispatcher principal · aplica prioridad LOCKED 5 dimensiones.
// Variables runtime directas (D1) · no parsing del opener.
//
// Retorna:
//   {
//     readingLine: string | null,   // Lectura 1-2 frases (null = fallback)
//     nextAngleLine: string,        // Próximo ángulo · siempre presente
//     enrichedFoco: string,         // Foco original + próximo ángulo
//   }
//
// Si datos no soportan lectura no-trivial · readingLine=null (fallback
// silencioso · respeta D3 del BRIEF #8).
function retrievalIntelligenceLayer(qi, scenario, sortedRows, metricMap, sortField, originalFoco, dim) {
  // Sanity checks
  if (!qi || !Array.isArray(sortedRows) || sortedRows.length === 0) {
    return { readingLine: null, nextAngleLine: "", enrichedFoco: originalFoco || "" };
  }

  const primaryMetric = qi.metrics?.[0];
  const queryType = qi.queryType;
  if (!primaryMetric || !queryType) {
    return { readingLine: null, nextAngleLine: "", enrichedFoco: originalFoco || "" };
  }

  // Próximo ángulo siempre se computa (Prioridad 5)
  const nextAngle = rilPickNextAngle(queryType, primaryMetric, dim);
  // Enriquecer Foco: " · Próximo ángulo: <angle>."
  let enrichedFoco = originalFoco || "";
  if (enrichedFoco && nextAngle) {
    // Remover punto final si lo tiene · agregar próximo ángulo
    const trimmedFoco = enrichedFoco.replace(/\.\s*$/, "");
    enrichedFoco = trimmedFoco + ". Próximo ángulo: " + nextAngle + ".";
  }

  // Fallback inmediato si sortedRows < 4 · disciplina edge cases
  if (sortedRows.length < 4) {
    return { readingLine: null, nextAngleLine: nextAngle, enrichedFoco };
  }

  let readingLine = null;

  try {
    // ── PRIORIDAD 1 · CALIDAD CRUZADA (solo multi-metric) ───────────────
    if (qi.metrics.length >= 2) {
      const cal = rilDetectCalidadCruzada(sortedRows, metricMap, qi.metrics);
      if (cal) {
        const m0Label = metricMap[qi.metrics[0]]?.label || qi.metrics[0];
        const m1Label = metricMap[qi.metrics[1]]?.label || qi.metrics[1];
        const fmtM0 = metricMap[qi.metrics[0]]?.formatter || ((v) => String(v));
        const fmtM1 = metricMap[qi.metrics[1]]?.formatter || ((v) => String(v));
        const avgM1Formatted = cal.m1Type === "pct"
          ? cal.avgM1.toFixed(1) + "%"
          : fmtM1(cal.avgM1);
        readingLine = "Lectura · " + cal.top1Name + " lidera " + m0Label
                    + " (" + fmtM0(cal.top1M0Val) + ") pero opera con "
                    + m1Label + " " + fmtM1(cal.top1M1Val)
                    + ", bajo el portafolio promedio (" + avgM1Formatted + "). "
                    + cal.bestM1Name + " cruza la lectura: "
                    + m1Label + " " + fmtM1(cal.bestM1Val)
                    + " con apenas " + fmtM0(cal.bestM1M0Val) + " en " + m0Label + ".";
        return { readingLine, nextAngleLine: nextAngle, enrichedFoco };
      }
      // Calidad no detectada · fallback a CONCENTRACIÓN/RIESGO de metric[0]
    }

    // ── PRIORIDAD 2/3 · RIESGO / CONCENTRACIÓN (single-metric o fallback) ─
    const conc = rilComputeConcentracion(sortedRows, sortField);
    if (!conc) {
      return { readingLine: null, nextAngleLine: nextAngle, enrichedFoco };
    }

    // PRIORIDAD 4 (en ranked) · BRECHA · puede combinarse con concentración
    // D5 · solo aplica ranked · D4 umbral 15%
    let brechaLine = null;
    if (queryType === "ranked") {
      const metricType = rilIsMonetaryOrPct(primaryMetric);
      // D7 · BRECHA solo monetary o pct
      if (metricType === "monetary" || metricType === "pct") {
        const brecha = rilComputeBrecha(sortedRows, sortField);
        if (brecha && brecha.gapPct >= 0.15) {
          const fmt = metricMap[primaryMetric]?.formatter || ((v) => String(v));
          const gapPctRounded = Math.round(brecha.gapPct * 100);
          brechaLine = "Lectura · " + brecha.top1Name + " lidera con "
                     + fmt(brecha.top1Val) + ", " + gapPctRounded + "% sobre "
                     + brecha.top2Name + " (" + fmt(brecha.top2Val) + ").";
        }
      }
    }

    if (brechaLine) {
      readingLine = brechaLine;
      return { readingLine, nextAngleLine: nextAngle, enrichedFoco };
    }

    // PRIORIDAD 2 · RIESGO (top3 ∈ (0.40, 0.95))
    // Solo aplica en queryType "simple" · en ranked, top3 es mecánicamente
    // alto por construcción del filtro (top N usuario) · "dependencia
    // operacional sobre top3" sería engañoso en top5/top10.
    if (queryType === "simple" && qi.metrics.length === 1
        && conc.top3Share > 0.40 && conc.top3Share < 0.95) {
      const pct = Math.round(conc.top3Share * 100);
      // Nombres con coma + "y"
      const t1 = conc.top1Name || "";
      const t2 = conc.top2Name || "";
      const t3 = conc.top3Name || "";
      readingLine = "Lectura · Top 3 concentra " + pct + "% del total · dependencia operacional sobre "
                  + t1 + ", " + t2 + " y " + t3 + ".";
      return { readingLine, nextAngleLine: nextAngle, enrichedFoco };
    }

    // PRIORIDAD 3 · CONCENTRACIÓN (default · leader > 15%)
    if (conc.leaderShare > 0.15 && sortedRows.length >= 4) {
      const leaderPct = Math.round(conc.leaderShare * 100);
      const nextPct = Math.round(conc.nextShare * 100);
      readingLine = "Lectura · " + conc.top1Name + " concentra " + leaderPct
                  + "% del total · resto fragmentado bajo " + nextPct + "% individual.";
      return { readingLine, nextAngleLine: nextAngle, enrichedFoco };
    }

    // Fallback silencioso · datos no soportan lectura no-trivial (D3 del #8)
    return { readingLine: null, nextAngleLine: nextAngle, enrichedFoco };
  } catch (e) {
    // try-catch defensivo · fallback completo
    return { readingLine: null, nextAngleLine: nextAngle, enrichedFoco };
  }
}

// ════════════════════════════════════════════════════════════════════════════
// CORTE 1 · COMPOSERS DE FAMILIA · deterministas, scenario-aware (R1/R2).
// Toda cifra sale de applyScenarioToSfamilias{Ventas,Margen}(scenarioId) → idéntica
// al dashboard del escenario activo. NO se replica el motor cognitivo de cliente.
// Solo se invocan desde paths gateados por FEATURE_FAMILY_AS_ENTITY.
//   · SKU→familia: relación DIRECTA (skusMargen.sfamilia · membership).
//   · cliente→familia: relación DOMINANTE/PROXY · lenguaje ejecutivo, nunca absoluto.
//     PROHIBIDO emitir "todos los clientes que compran" (criterio 5 · test negativo).
// Formato de moneda idéntico al dashboard (ModuloVentas: actual.toLocaleString()+"K").
// ════════════════════════════════════════════════════════════════════════════
function _familyFmtMoney(v) {
  // Espeja el render del dashboard: "$" + valor.toLocaleString() + "K".
  return "$" + (v).toLocaleString() + "K";
}
function _familyFmtPct(v) {
  return (v >= 0 ? "+" : "") + v.toFixed(1) + "%";
}
function _familySkusText(familyName, skus) {
  if (!skus || skus.length === 0) {
    return `No tengo SKUs asociados a ${familyName} en el catálogo.`;
  }
  const lista = skus.length === 1
    ? skus[0]
    : skus.slice(0, -1).join(", ") + " y " + skus[skus.length - 1];
  // Relación directa SKU→familia.
  return `Los SKUs que forman ${familyName} son ${lista}.`;
}
function _familyClientsText(familyName, clientes) {
  if (!clientes || clientes.length === 0) {
    return `En este escenario ningún cliente tiene a ${familyName} como familia dominante.`;
  }
  // Dominante/proxy · "principalmente" = top; "(también …)" = resto. Nunca absoluto.
  const principales = clientes.slice(0, 2);
  const resto = clientes.slice(2);
  const princStr = principales.length === 1 ? principales[0] : principales.join(" y ");
  let txt = `${familyName} está concentrada principalmente en ${princStr} — los clientes donde aparece como familia dominante en este dataset`;
  if (resto.length > 0) txt += ` (también ${resto.join(", ")})`;
  txt += ".";
  return txt;
}
function _familyMetricsText(familyName, fam, m, share, yoy) {
  let t = `${familyName} vende ${_familyFmtMoney(fam.actual)} (${_familyFmtPct(yoy)} vs año anterior · ${share.toFixed(1)}% de la cartera · ${(fam.unidades || 0).toLocaleString()} unidades · rebate ${(fam.pctRebate || 0).toFixed(1)}%).`;
  if (m) {
    t += ` Contribución ${_familyFmtMoney(m.contribucion)}, margen ${m.margen.toFixed(1)}%.`;
  } else {
    t += ` El margen por familia llega en una próxima iteración.`;
  }
  return t;
}

// composeFamilyDive(familyName, scenarioId, { subFocus })
//   familyName=null  → familia top por ventas (caso 1 · "cuál es la mejor familia").
//   subFocus=null    → dive completo (apertura).
//   subFocus="skus" | "clientes" | "metrics" → sub-respuesta de arrastre (criterio 7).
function composeFamilyDive(familyName, scenarioId, opts = {}) {
  const subFocus = (opts && opts.subFocus) || null;

  // R1 · fuente canónica scenario-aware (idéntica al dashboard del escenario).
  const ventasF = applyScenarioToSfamiliasVentas(scenarioId);
  const margenF = applyScenarioToSfamiliasMargen(scenarioId);

  // Resolver familia: nombre específico, o top por ventas si null.
  // ventasF viene ordenado desc por actual → [0] es la familia top.
  let fam = familyName ? ventasF.find(f => f.sfamilia === familyName) : null;
  let resolved = familyName;
  if (!fam) {
    fam = ventasF[0] || null;
    resolved = fam ? fam.sfamilia : null;
  }
  if (!fam) {
    return {
      opener: "No tengo familias en el detalle de este escenario.",
      suggestions: filterTextualSuggestions([]),
      familyResolved: null,
      derivedModule: "ventas",
    };
  }

  const m = margenF.find(x => x.sfamilia === resolved) || null;

  // Métricas scenario-aware.
  const totalVenta = ventasF.reduce((s, f) => s + (f.actual || 0), 0);
  const share = totalVenta ? (fam.actual / totalVenta) * 100 : 0;
  const yoy = fam.anterior ? ((fam.actual - fam.anterior) / fam.anterior) * 100 : 0;

  // Clientes dominantes (proxy) · orden por venta scenario-aware.
  const clientesDom = applyScenarioToClientesVentas(scenarioId)
    .filter(c => c.sfamilia === resolved)
    .sort((a, b) => b.actual - a.actual)
    .map(c => c.nombre);

  // SKUs (relación directa · membership desde skusMargen.sfamilia).
  const skusDir = skusMargen.filter(s => s.sfamilia === resolved).map(s => s.nombre);

  // ── Sub-respuestas de arrastre ──
  if (subFocus === "skus") {
    return {
      opener: _familySkusText(resolved, skusDir),
      suggestions: filterTextualSuggestions([
        `Qué clientes compran ${resolved}`,
        `Cuánto vende ${resolved}`,
      ]),
      familyResolved: resolved,
      derivedModule: "ventas",
    };
  }
  if (subFocus === "clientes") {
    return {
      opener: _familyClientsText(resolved, clientesDom),
      suggestions: filterTextualSuggestions([
        `Qué SKUs forman ${resolved}`,
        `Cuánto vende ${resolved}`,
      ]),
      familyResolved: resolved,
      derivedModule: "ventas",
    };
  }
  if (subFocus === "metrics") {
    return {
      opener: _familyMetricsText(resolved, fam, m, share, yoy),
      suggestions: filterTextualSuggestions([
        `Qué SKUs forman ${resolved}`,
        `Qué clientes compran ${resolved}`,
      ]),
      familyResolved: resolved,
      derivedModule: "ventas",
    };
  }

  // ── Dive completo (apertura) ──
  const lines = [];
  let l1 = `${resolved} vende ${_familyFmtMoney(fam.actual)} en este escenario (${_familyFmtPct(yoy)} vs año anterior · ${share.toFixed(1)}% de la cartera).`;
  if (m) l1 += ` Contribución ${_familyFmtMoney(m.contribucion)}, margen ${m.margen.toFixed(1)}%.`;
  lines.push(l1);
  lines.push(_familyClientsText(resolved, clientesDom));   // dominante (proxy)
  lines.push(_familySkusText(resolved, skusDir));          // directo

  return {
    opener: lines.join("\n\n"),
    suggestions: filterTextualSuggestions([
      `Qué SKUs forman ${resolved}`,
      `Qué clientes compran ${resolved}`,
      `Cuánto margen tiene ${resolved}`,
    ]),
    familyResolved: resolved,
    derivedModule: "ventas",
  };
}

function composeRetrieval(qi, scenario) {
  // Sanity check
  if (!qi || !qi.isRetrieval || !Array.isArray(qi.metrics) || !Array.isArray(qi.dimensions)) {
    return null;
  }
  if (qi.metrics.length === 0 || qi.dimensions.length === 0) return null;

  // V1 single dimension (multi-dimension diferido)
  const dim = qi.dimensions[0];

  // Resolver dataset según dimension
  let rows = null;
  let dimLabel = "";
  let nameField = "nombre";
  try {
    if (dim === "cliente") {
      rows = applyScenarioToClientesMargen(scenario);
      dimLabel = "Cliente";
    } else if (dim === "sku" || dim === "producto") {
      rows = skusMargen;
      dimLabel = "SKU";
    } else if (dim === "familia") {
      // CORTE 1 · R2 · fuente canónica scenario-aware (idéntica al dashboard).
      // Con flag OFF se preserva el estático (comportamiento del piso). Con flag ON
      // ningún path conversacional emite la cifra estática (mundo-marca).
      rows = FEATURE_FAMILY_AS_ENTITY ? applyScenarioToSfamiliasMargen(scenario) : sfamiliasMargen;
      dimLabel = "Familia";
    } else if (dim === "marca") {
      // Marca · agrupación dinámica desde clientesMargen
      const grouped = {};
      const baseRows = applyScenarioToClientesMargen(scenario);
      for (const r of baseRows) {
        const m = r.marca || "Otros";
        if (!grouped[m]) {
          grouped[m] = { nombre: m, venta: 0, contribucion: 0, margen: 0, count: 0, pctRebate: 0 };
        }
        grouped[m].venta        += r.venta;
        grouped[m].contribucion += r.contribucion;
        grouped[m].margen       += r.margen;
        grouped[m].pctRebate    += r.pctRebate;
        grouped[m].count        += 1;
      }
      rows = Object.values(grouped).map(g => ({
        ...g,
        margen:    +(g.margen / g.count).toFixed(1),
        pctRebate: +(g.pctRebate / g.count).toFixed(1),
      }));
      dimLabel = "Marca";
    } else {
      // Dimensions no soportadas V1 (sucursal/canal/tier): fail to legacy
      return null;
    }
  } catch (e) {
    return null;
  }

  if (!Array.isArray(rows) || rows.length === 0) return null;

  // Resolver metrics (fields del row)
  const metricMap = {
    ventas:        { field: "venta",         label: "Ventas",        formatter: (v) => "$" + Math.round(v / 100) / 10 + "M" },
    margen:        { field: "margen",        label: "Margen",        formatter: (v) => v.toFixed(1) + "%" },
    contribucion:  { field: "contribucion",  label: "Contribución",  formatter: (v) => "$" + Math.round(v / 100) / 10 + "M" },
    carga:         { field: "pctRebate",     label: "Carga Comercial", formatter: (v) => v.toFixed(1) + "%" },
    aporte:        { field: "contribucion",  label: "Aporte",        formatter: (v) => "$" + Math.round(v / 100) / 10 + "M" },
    rentabilidad:  { field: "margen",        label: "Rentabilidad",  formatter: (v) => v.toFixed(1) + "%" },
    stock:         { field: "unidades",      label: "Unidades",      formatter: (v) => String(v) },
    participacion: { field: "venta",         label: "Participación", formatter: (v, total) => total ? ((v / total) * 100).toFixed(1) + "%" : "—" },
    cobertura:     null,
    rotacion:      null,
  };

  // Validar que todas las metrics solicitadas se pueden resolver con este dataset
  for (const m of qi.metrics) {
    const map = metricMap[m];
    if (!map) return null;
    if (!(map.field in rows[0])) return null;
  }

  // Sort + limit (ranked usa primera metric)
  let sortedRows = [...rows];
  const sortField = metricMap[qi.metrics[0]].field;
  sortedRows.sort((a, b) => (b[sortField] || 0) - (a[sortField] || 0));
  if (qi.limit !== null && qi.limit > 0) {
    sortedRows = sortedRows.slice(0, qi.limit);
  }

  // Total para participación (si aplica)
  const totalVenta = rows.reduce((s, r) => s + (r.venta || 0), 0);

  // Build cuerpo tabular con NBSP padding
  const NBSP = "\u00A0";
  function padRight(s, width) {
    s = String(s);
    if (s.length >= width) return s.substring(0, width);
    return s + NBSP.repeat(width - s.length);
  }
  function padLeft(s, width) {
    s = String(s);
    if (s.length >= width) return s.substring(s.length - width);
    return NBSP.repeat(width - s.length) + s;
  }

  // Header dinámico
  const metricLabels = qi.metrics.map(m => metricMap[m].label);
  let scenarioLabel = "Bonanza";
  if (scenario === "tension") scenarioLabel = "Tensión";
  else if (scenario === "crisis") scenarioLabel = "Crisis";

  let header;
  if (qi.queryType === "ranked") {
    header = `Top ${qi.limit} ${dimLabel === "Cliente" ? "clientes" : dimLabel === "SKU" ? "SKUs" : dimLabel === "Familia" ? "familias" : "marcas"} por ${metricLabels[0]} · escenario ${scenarioLabel}.`;
  } else if (qi.queryType === "multi") {
    header = `${metricLabels.join(" y ")} por ${dimLabel} · escenario ${scenarioLabel}.`;
  } else {
    header = `${metricLabels[0]} por ${dimLabel} · escenario ${scenarioLabel}.`;
  }

  // Build tabla
  // Columna 0: nombre (max 22 char)
  // Columna 1..N: metrics formatted
  const NAME_W = 22;
  const METRIC_W = 12;
  let table = "";
  // Header row
  table += padRight(dimLabel, NAME_W);
  for (const lbl of metricLabels) table += padLeft(lbl, METRIC_W);
  table += "\n";
  // Separator
  table += "─".repeat(NAME_W + METRIC_W * metricLabels.length) + "\n";
  // Data rows
  for (const r of sortedRows) {
    const name = r[nameField] || r.nombre || "—";
    table += padRight(name, NAME_W);
    for (const m of qi.metrics) {
      const map = metricMap[m];
      const val = r[map.field];
      if (typeof val !== "number") {
        table += padLeft("—", METRIC_W);
      } else {
        table += padLeft(map.formatter(val, totalVenta), METRIC_W);
      }
    }
    table += "\n";
  }

  // Foco · breve insight ejecutivo del top1
  const top1 = sortedRows[0];
  const top1Name = top1?.[nameField] || top1?.nombre || "—";
  const top1Val = top1 ? top1[sortField] : null;
  const top1Formatted = top1Val !== null && top1Val !== undefined
    ? metricMap[qi.metrics[0]].formatter(top1Val, totalVenta)
    : "—";

  let foco;
  if (qi.queryType === "ranked") {
    foco = `Foco · ${top1Name} encabeza el ranking con ${top1Formatted} en ${metricLabels[0]}.`;
  } else {
    foco = `Foco · ${top1Name} concentra el mayor ${metricLabels[0]} (${top1Formatted}).`;
  }

  // ════════════════════════════════════════════════════════════════════════
  // BRIEF #9 · PIEZA 2 · RIL INTEGRATION
  //
  // Llamar al Retrieval Intelligence Layer con variables runtime directas.
  // try-catch defensivo · si RIL falla · passthrough opener actual sin Lectura.
  // Variables ril_* prefijadas · scoped al try-catch.
  // RIL NO toca foco original directamente · retorna enrichedFoco para
  // reemplazo controlado.
  // ════════════════════════════════════════════════════════════════════════
  let ril_readingLine = null;
  let ril_enrichedFoco = foco;
  try {
    const ril_result = retrievalIntelligenceLayer(
      qi, scenario, sortedRows, metricMap, sortField, foco, dim
    );
    if (ril_result && typeof ril_result === "object") {
      if (typeof ril_result.readingLine === "string" && ril_result.readingLine.length > 0) {
        ril_readingLine = ril_result.readingLine;
      }
      if (typeof ril_result.enrichedFoco === "string" && ril_result.enrichedFoco.length > 0) {
        ril_enrichedFoco = ril_result.enrichedFoco;
      }
    }
  } catch (ril_err) {
    // eslint-disable-next-line no-console
    console.warn("BRIEF #9 RIL error:", ril_err);
    // FAIL-SAFE: opener actual sin Lectura · foco original intacto
    ril_readingLine = null;
    ril_enrichedFoco = foco;
  }

  // Confianza · referencia escenario + dataset
  const confianza = `Cifras runtime del escenario ${scenarioLabel}. ${sortedRows.length} ${dimLabel.toLowerCase()}(s) en la respuesta.`;

  // Build opener · Lectura insertada entre tabla y Foco si presente
  let opener;
  if (ril_readingLine) {
    opener = `${header}\n\n${table}\n${ril_readingLine}\n\n${ril_enrichedFoco}\n\n${confianza}`;
  } else {
    opener = `${header}\n\n${table}\n${ril_enrichedFoco}\n\n${confianza}`;
  }

  // Suggestions contextuales · 3 invitaciones a profundizar
  const suggestions = [];
  if (qi.queryType !== "ranked") {
    suggestions.push(`Top 5 ${dimLabel.toLowerCase()}s por ${metricLabels[0]}`);
  }
  if (qi.metrics.length === 1 && qi.metrics[0] !== "margen") {
    suggestions.push(`${metricLabels[0]} y margen por ${dimLabel.toLowerCase()}`);
  } else if (qi.metrics.length === 1 && qi.metrics[0] === "margen") {
    suggestions.push(`Ventas y margen por ${dimLabel.toLowerCase()}`);
  }
  if (suggestions.length < 3) suggestions.push(`¿Cómo está el ${dimLabel === "Cliente" ? "negocio por cliente" : dimLabel === "SKU" ? "portafolio de productos" : "mix por familia"}?`);
  while (suggestions.length < 3) suggestions.push("¿Qué más querés explorar?");

  return {
    opener,
    // BRIEF N-bis · Tipo A puro · suggestions filtradas
    suggestions: filterTextualSuggestions(suggestions.slice(0, 3)),
    sentrixAction: null,
    derivedIntentType: "query_interpreter",
    // FIX FOUNDATION-REASONER · campos aditivos · backward compat estricta
    // Permite QI Guard poblar lastClientList/lastSkuList sin recomputar.
    // sortedRows ya está ordenado+sliced por composeRetrieval · single source
    // of truth. nameField default "nombre" para cliente/familia/marca · para
    // sku/producto la key real es "sku" pero el filtro tolera ambos (fallback
    // r.nombre captura familia/marca · primer hit gana).
    entities: sortedRows
      .map(r => r[nameField] || r.nombre || r.sku)
      .filter(n => typeof n === "string" && n.length > 0),
    entityDim: dim,
    // RETRIEVALFIX→CONTRATO (ARCO B) · exponer las CIFRAS del ranking — las MISMAS
    // de la tabla (sortField + formatter primario del metricMap) — alineadas 1:1
    // con `entities` (mismo orden de sortedRows · misma resolución de nombre).
    // CERO recompute · CERO formato nuevo · si un row no trae número → se omite
    // (honesto · el cruce nombre↔cifra servirá ese nombre sin cifra, no inventa).
    materialMetrics: sortedRows.map(r => {
      const _name = r[nameField] || r.nombre || r.sku;
      if (typeof _name !== "string" || !_name.length) return null;
      const _raw = r[sortField];
      if (typeof _raw !== "number") return null;
      return { entity: _name, metric: metricLabels[0] || "Valor", value: metricMap[qi.metrics[0]].formatter(_raw, totalVenta) };
    }).filter(Boolean),
  };
}

// ════════════════════════════════════════════════════════════════════════════
// BRIEF #8 (post-46-bis) · RESPONSE CONTRACT ENGINE · PIEZAS 1-4
// ════════════════════════════════════════════════════════════════════════════
//
// Capa de post-procesamiento que recibe rawPayload de cualquier composer
// (Ferrari · ModuleOverview · QI · Disambig · Generic) y aplica estructura
// canónica + identidad narrativa Ferrari uniforme.
//
// REGLA NUCLEAR · IDENTIDAD NARRATIVA UNIFICADA:
//   Todos los outputs deben tener (cuando aplique):
//     Header (cifra ancla) · Cuerpo (evidencia) · Lectura (causal) ·
//     Foco (operativo) · Confianza
//
// Decisiones founder integradas FASE 2:
//   D1 · Construir SOBRE buildResponseContract v1 (no paralelo)
//   D2 · Detección tier por intent.type / derivedIntentType
//   D3 · Lectura QI computada · fallback si datos no soportan
//   D4 · Mantener "Buena pregunta" en Generic · solo cifras ancla scenario
//   D5 · 3 composers Ferrari sin contrato v1 → deuda V2 #B8-1 (passthrough)
//   D6 · Voz sobria · sin marketing · controller senior
//
// GUARDRAILS LOCKED:
//   1. RCE ordena · no alarga
//   2. NO cambia datos ni cálculos
//   3. NO toca composers Ferrari · passthrough estricto
//   4. NO toca QueryInterpreter ni composeRetrieval (EXCEPCIÓN AUTORIZADA ·
//      FOUNDATION-REASONER · composeRetrieval expone campos aditivos
//      entities/entityDim para que callsite QI Guard pueda poblar
//      lastClientList/lastSkuList. NO modifica lógica de sort/slice ·
//      NO altera opener/suggestions/sentrixAction/derivedIntentType.)
//   5. Fail-safe passthrough obligatorio
//   6. try-catch wrapper · rce_* prefijadas
// ════════════════════════════════════════════════════════════════════════════

// ── PIEZA 4 · CONFIDENCE_TEMPLATES + helpers ────────────────────────────────
// Voz sobria · cifras runtime · sin inflar. Si V_VISUAL detecta inflado,
// refinar en sub-deuda del BRIEF.
const RCE_CONFIDENCE_TEMPLATES = {
  bonanza: "Confianza alta · cifras runtime del escenario Bonanza.",
  tension: "Confianza alta · cifras runtime del escenario Tensión.",
  crisis:  "Confianza alta · cifras runtime del escenario Crisis.",
};

// Cifras ancla por scenario (cold-start context · disambig upgrade).
// Solo se usan en upgrades · NO en passthrough de composers.
const RCE_SCENARIO_ANCHOR = {
  bonanza: { ventasTotal: "$100M", crecimiento: "+7.6%", margen: "25.6%" },
  tension: { ventasTotal: "$92.9M", crecimiento: "0%", margen: "22.4%" },
  crisis:  { ventasTotal: "$87.4M", crecimiento: "-12.6%", margen: "18.9%" },
};

// Detección de tier desde intent.type / derivedIntentType (Decisión 2).
// Mapping explícito · estable · no requiere markers en composers.
//
// intent.type values reales del artifact (detectIntent línea 4356):
//   "generic" cuando no matchea ningún composer específico ("Hola", "?")
//   "module" cuando es módulo overview ("¿Cómo está ventas?")
//   "client", "sku_deep_dive", "simulation", "cognitive_action",
//   "client_followup", composers Ferrari específicos, etc.
function detectRceTier(derivedIntentType, intentType, lastComposerResponse) {
  const t = derivedIntentType || intentType || "";
  // Tier explícitos por derivedIntentType (QI lo setea a "query_interpreter",
  // disambig path lo setea a "disambiguation")
  if (t === "query_interpreter") return "qi";
  if (t === "disambiguation") return "disambig";
  if (t === "module") return "module_overview";
  // Generic: intent.type === "generic" (fallback final detectIntent)
  // O caso sin tipo y sin lastComposerResponse (defensivo)
  if (t === "generic") return "generic";
  if (!t && !lastComposerResponse) return "generic";
  // Default conservador · cualquier intent.type conocido (Ferrari) → ferrari
  return "ferrari";
}

// ── PIEZA 2.1 · upgradeQiOutput ─────────────────────────────────────────────
// Recibe opener QI (Header + tabla + Foco + Confianza) y agrega Lectura
// computada entre Cuerpo y Foco. Si datos no soportan lectura no-trivial,
// fallback a passthrough (no inventa).
//
// Heurística computación:
//   · simple/multi/ranked con dim cliente o sku · concentración top 3
//   · single metric · gap entre top1 y top3
//   · si tabla tiene <3 filas · fallback (no concentración informativa)
function upgradeQiOutput(rawPayload, qiMeta) {
  if (!rawPayload || typeof rawPayload.opener !== "string") return rawPayload;

  // Parsear estructura del opener QI: detectar "Foco · " como ancla
  const opener = rawPayload.opener;
  const focoIdx = opener.indexOf("\nFoco · ");
  if (focoIdx < 0) return rawPayload; // estructura inesperada · passthrough

  // Extraer datos para Lectura desde qiMeta si disponibles
  // qiMeta.sortedRows o qiMeta.queryType pueden no estar · fallback robusto
  let lecturaText = null;
  try {
    const rows = (qiMeta && Array.isArray(qiMeta.sortedRows)) ? qiMeta.sortedRows : null;
    const metric0 = qiMeta?.metrics?.[0];
    const dim = qiMeta?.dimensions?.[0];
    if (rows && rows.length >= 3 && metric0) {
      const metricField = {
        ventas: "venta", venta: "venta",
        margen: "margen", margenes: "margen",
        contribucion: "contribucion", contribuciones: "contribucion",
        carga: "pctRebate", stock: "unidades",
        rentabilidad: "margen", aporte: "contribucion",
      }[metric0];
      if (metricField && metricField in rows[0]) {
        const isMonetary = ["venta", "contribucion"].includes(metricField);
        const total = rows.reduce((s, r) => s + (r[metricField] || 0), 0);
        const top3Sum = (rows[0][metricField] || 0) + (rows[1][metricField] || 0) + (rows[2][metricField] || 0);
        if (total > 0 && isMonetary) {
          const pctTop3 = Math.round((top3Sum / total) * 100);
          if (pctTop3 >= 40 && pctTop3 <= 99) {
            const dimLabel = dim === "cliente" ? "cuentas" : dim === "sku" ? "SKUs" : dim === "familia" ? "familias" : "items";
            lecturaText = `Lectura · Los 3 primeros ${dimLabel} concentran ${pctTop3}% del total. El resto del portafolio aporta participación fragmentada.`;
          }
        } else if (!isMonetary) {
          // Para %: gap entre top1 y top-de-bottom-3 (último top N o último de rows)
          const top1Val = rows[0][metricField] || 0;
          const lastIdx = Math.min(rows.length - 1, qiMeta?.limit ? qiMeta.limit - 1 : rows.length - 1);
          const bottomVal = rows[lastIdx][metricField] || 0;
          const gap = top1Val - bottomVal;
          if (Math.abs(gap) >= 2) {
            const dimLabel = dim === "cliente" ? "cuenta" : dim === "sku" ? "SKU" : dim === "familia" ? "familia" : "item";
            const direction = gap > 0 ? "sobre" : "bajo";
            lecturaText = `Lectura · La ${dimLabel} líder está ${Math.abs(gap).toFixed(1)}pp ${direction} la última del ranking · spread amplio sugiere heterogeneidad operativa.`;
          }
        }
      }
    }
  } catch (e) {
    lecturaText = null; // fallback silencioso
  }

  if (!lecturaText) return rawPayload; // no inventa · passthrough

  // Insertar Lectura entre Cuerpo (tabla) y Foco
  const beforeFoco = opener.substring(0, focoIdx);
  const fromFoco = opener.substring(focoIdx);
  const newOpener = beforeFoco + "\n\n" + lecturaText + fromFoco;

  return { ...rawPayload, opener: newOpener };
}

// ── PIEZA 2.2 · upgradeDisambigOutput ───────────────────────────────────────
// Agrega cifras ancla del cliente (si disambig.entity es cliente conocido)
// + Confianza. Voz sobria.
function upgradeDisambigOutput(rawPayload, scenario, intentMeta) {
  if (!rawPayload || typeof rawPayload.opener !== "string") return rawPayload;

  // Intentar identificar entidad cliente en concepts_full del intent
  let clientName = null;
  try {
    const concepts = intentMeta?._semantic_meta?.concepts_full || [];
    for (const c of concepts) {
      if (c?.type === "client_entity" && c?.value) {
        clientName = c.value;
        break;
      }
    }
  } catch (e) { clientName = null; }

  // Si no hay cliente identificado, solo agregar Confianza
  if (!clientName) {
    const confianza = RCE_CONFIDENCE_TEMPLATES[scenario] || RCE_CONFIDENCE_TEMPLATES.bonanza;
    // Solo agregar si no está ya presente (avoid duplication)
    if (rawPayload.opener.includes("Confianza")) return rawPayload;
    return {
      ...rawPayload,
      opener: rawPayload.opener + "\n\n" + confianza,
    };
  }

  // Lookup cifras del cliente (clientesMargen + scenario transform)
  let cifrasText = null;
  try {
    const rows = applyScenarioToClientesMargen(scenario);
    const row = rows.find(r => r.nombre === clientName);
    if (row) {
      const ventaM = (row.venta / 1000).toFixed(1);
      const margenPct = row.margen.toFixed(1);
      const contribM = (row.contribucion / 1000).toFixed(1);
      const cargaPct = row.pctRebate.toFixed(1);
      cifrasText = `Cifras de ${clientName} en ${scenario === "tension" ? "Tensión" : scenario === "crisis" ? "Crisis" : "Bonanza"}: Ventas $${ventaM}M · margen ${margenPct}% · contribución $${contribM}M · carga ${cargaPct}%.`;
    }
  } catch (e) { cifrasText = null; }

  const confianza = RCE_CONFIDENCE_TEMPLATES[scenario] || RCE_CONFIDENCE_TEMPLATES.bonanza;
  const parts = [rawPayload.opener];
  if (cifrasText) parts.push(cifrasText);
  if (!rawPayload.opener.includes("Confianza")) parts.push(confianza);

  return {
    ...rawPayload,
    opener: parts.join("\n\n"),
  };
}

// ── PIEZA 2.3 · upgradeGenericOutput ────────────────────────────────────────
// GENERIC_RESPONSES ya tiene cifras ancla del scenario (definidas constantes
// línea 416+). Decisión 4: mantener "Buena pregunta" · no reescribir.
// Solo agregar Foco operativo si no presente.
function upgradeGenericOutput(rawPayload, scenario) {
  if (!rawPayload || typeof rawPayload.opener !== "string") return rawPayload;

  // Si ya tiene "Foco" en el opener, passthrough
  if (rawPayload.opener.includes("Foco · ")) return rawPayload;

  // Foco operativo simple · acotar pregunta a módulo
  const focoText = "Foco · acotá la pregunta a un módulo (ventas, margen o inventario) para diagnóstico operacional.";

  // Insertar antes del "Para responderte" (si presente) o al final
  const paraIdx = rawPayload.opener.indexOf("\n\nPara responderte");
  if (paraIdx > 0) {
    const before = rawPayload.opener.substring(0, paraIdx);
    const after = rawPayload.opener.substring(paraIdx);
    return {
      ...rawPayload,
      opener: before + "\n\n" + focoText + after,
    };
  }
  // Fallback: append
  return {
    ...rawPayload,
    opener: rawPayload.opener + "\n\n" + focoText,
  };
}

// ── PIEZA 1 · applyResponseContractEngine ───────────────────────────────────
// Dispatcher principal · recibe rawPayload + meta · detecta tier · aplica
// estrategia · retorna finalPayload. Fail-safe passthrough en error.
//
// rawInput shape:
//   {
//     opener: string,
//     suggestions: array,
//     sentrixAction: object | null,
//     scenario: string ("bonanza" | "tension" | "crisis"),
//     derivedIntentType: string | null,
//     intentType: string | null,
//     lastComposerResponse: object | null,
//     intentMeta: object | null,         // intent completo (para concepts_full)
//     qiMeta: object | null,             // queryInterpreter result si aplica
//   }
//
// Retorna:
//   {
//     opener: string (posiblemente enriquecido),
//     suggestions: array (passthrough V1),
//     sentrixAction: object | null (passthrough),
//     strategy: string (qi_upgrade | disambig_upgrade | generic_upgrade |
//                       ferrari_passthrough | module_overview_passthrough |
//                       unknown_passthrough),
//     rceApplied: boolean,
//   }
function applyResponseContractEngine(rawInput) {
  // Sanity checks · fail-safe passthrough
  if (!rawInput || typeof rawInput !== "object") {
    return { opener: "", suggestions: [], sentrixAction: null, strategy: "invalid_input", rceApplied: false };
  }
  const rawPayload = {
    opener: typeof rawInput.opener === "string" ? rawInput.opener : "",
    suggestions: Array.isArray(rawInput.suggestions) ? rawInput.suggestions : [],
    sentrixAction: rawInput.sentrixAction || null,
  };

  // Si opener vacío · passthrough sin tocar
  if (rawPayload.opener.length === 0) {
    return { ...rawPayload, strategy: "empty_passthrough", rceApplied: false };
  }

  // Detectar tier (Decisión 2)
  const tier = detectRceTier(
    rawInput.derivedIntentType,
    rawInput.intentType,
    rawInput.lastComposerResponse
  );

  const scenario = rawInput.scenario || "bonanza";

  // Dispatcher por tier
  try {
    if (tier === "ferrari") {
      // GUARDRAIL 3: passthrough estricto · cero modificación
      return { ...rawPayload, strategy: "ferrari_passthrough", rceApplied: true };
    }
    if (tier === "module_overview") {
      // Passthrough · composeModuleOverview ya tiene estructura propia
      return { ...rawPayload, strategy: "module_overview_passthrough", rceApplied: true };
    }
    if (tier === "qi") {
      const upgraded = upgradeQiOutput(rawPayload, rawInput.qiMeta);
      return { ...upgraded, strategy: "qi_upgrade", rceApplied: true };
    }
    if (tier === "disambig") {
      const upgraded = upgradeDisambigOutput(rawPayload, scenario, rawInput.intentMeta);
      return { ...upgraded, strategy: "disambig_upgrade", rceApplied: true };
    }
    if (tier === "generic") {
      const upgraded = upgradeGenericOutput(rawPayload, scenario);
      return { ...upgraded, strategy: "generic_upgrade", rceApplied: true };
    }
    // Tier desconocido · passthrough conservador
    return { ...rawPayload, strategy: "unknown_passthrough", rceApplied: false };
  } catch (rceErr) {
    // GUARDRAIL 5: fail-safe passthrough obligatorio
    // eslint-disable-next-line no-console
    console.warn("BRIEF #8 RCE dispatch error:", rceErr);
    return { ...rawPayload, strategy: "error_passthrough", rceApplied: false };
  }
}

