// PANEL ADI
// ════════════════════════════════════════════════════════════════════════════
const BLOCK_COLORS = [C.blue, C.cyan, C.indigo, C.amber, C.red, C.green];

// ═══════════════════════════════════════════════════════
// BRIEF FIX · Markdown Lite Renderer
//
// Lightweight markdown parser for **bold** and *italic*.
// Does NOT process headers, lists, links, code, etc.
// Just the two tokens that getClientDeepDive emits.
//
// Returns an array of React fragments + JSX elements.
// Safe to use inside any component.
// ═══════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// HIGHLIGHTING FINANCIERO · Nivel 3 · Bloomberg-inspired adaptado a narrativa
// Detecta cifras financieras y de gestión, las trata como "data tokens" con
// background sutil para que destaquen sin romper el flujo de lectura.
// Mejor que Bloomberg porque no satura · mejor que ChatGPT porque diferencia
// el dato del contexto narrativo. Refuerza Conversational-First BI.
// NO toca composer · solo enriquece visualmente el render.
// ════════════════════════════════════════════════════════════════════════════

// Estilo base compartido por todas las cifras numéricas
// El chip background es el "data token" Bloomberg-inspired: sutil, sin saturar
const NUM_BASE = {
  fontFamily:"'JetBrains Mono', ui-monospace, monospace",
  fontFeatureSettings:"'tnum'",
  fontWeight:600,
  fontSize:"1.05em",
  letterSpacing:"0.2px",
  padding:"1px 5px",
  borderRadius:3,
  background:"rgba(255,255,255,0.04)",
  border:"1px solid rgba(255,255,255,0.04)",
  whiteSpace:"nowrap",
  verticalAlign:"baseline"
};

const FINANCIAL_HIGHLIGHT = {
  // Cifras monetarias y porcentajes absolutos → blanco bold mono con chip sutil
  money: { ...NUM_BASE, color:"#FFFFFF" },
  pct:   { ...NUM_BASE, color:"#FFFFFF" },
  // Días, meses, semanas, multiplicadores · cifras de gestión BI
  unit:  { ...NUM_BASE, color:"#FFFFFF" },
  // Multiplicadores X · típico KPI ejecutivo
  mult:  { ...NUM_BASE, color:"#FFFFFF" },
  // Ratios A:B · típico de análisis comparativo
  ratio: { ...NUM_BASE, color:"#FFFFFF" },
  // Variaciones en puntos porcentuales → amber (métrica de gestión)
  pp:    { ...NUM_BASE, color:"#fde047", background:"rgba(253,224,71,0.06)", border:"1px solid rgba(253,224,71,0.1)" },
  // Deltas con dirección explícita → semáforo
  up:    { ...NUM_BASE, color:"#10b981", background:"rgba(16,185,129,0.06)", border:"1px solid rgba(16,185,129,0.1)" },
  down:  { ...NUM_BASE, color:"#f43f5e", background:"rgba(244,63,94,0.06)", border:"1px solid rgba(244,63,94,0.1)" },
  // Nombres de clientes → cyan suave link-like · SIN chip (es entidad, no dato)
  entity:{ color:"#7fdef0", fontWeight:500 },
};

const KNOWN_ENTITIES = [
  "Mercado Libre", "Falabella", "Lider", "Líder", "Jumbo", "Sodimac",
  "Tottus", "Paris", "Ripley", "Easy", "La Polar", "Hites", "ABC", "Unimarc"
];

// BRIEF A · Capa de proyección hero · función pura determinística
// Proyecta el opener del composer V2 a la estructura del hero ejecutivo.
// Sin LLM · sin inferencia · sin variabilidad · fallback automático si falla.
//
// Composer V2 produce opener con 5 bloques separados por \n\n: B2 (tesis),
// B3 (evidencia), B4 (lectura), B5 (acción), B6 (confianza).
//
// Hero compacto consume solo B2 + B3 (Principio 7 Executive Reading · 5
// segundos visibles). Chat completo consume el opener entero (5 bloques)
// vía chatOpener cuando el usuario clickea "Sí, conversemos".
//
// Variante conservadora · closer y actions preservados de ADI_THESIS.
// Si el opener tiene < 2 bloques, fallback completo a ADI_THESIS (modo seguro).
function projectComposerOpenerToHero(composerOutput, fallbackThesis) {
  // BRIEF N-bis · helper local para preservar fallbackThesis shape filtrando
  // chatSuggestions Tipo A · ADI_THESIS hardcoded contiene strings.
  const filteredFallback = fallbackThesis
    ? { ...fallbackThesis, chatSuggestions: filterTextualSuggestions(fallbackThesis.chatSuggestions) }
    : fallbackThesis;
  if (!composerOutput || !composerOutput.opener) return filteredFallback;
  const blocks = composerOutput.opener.split(/\n\n+/).filter(Boolean);
  if (blocks.length < 2) return filteredFallback;
  return {
    eyebrow:         fallbackThesis.eyebrow,
    paragraphs:      [blocks[0], blocks[1]],
    closer:          fallbackThesis.closer,
    actions:         fallbackThesis.actions,
    chatOpener:      composerOutput.opener,
    // BRIEF N-bis · composerOutput.suggestions ya viene filtrado del composer
    // pero aplicamos el helper como defense-in-depth (idempotente).
    chatSuggestions: filterTextualSuggestions(composerOutput.suggestions),
    sentrixOpener:   fallbackThesis.sentrixOpener,
  };
}

// Patrón unificado · longest-match-first
// Orden importa: deltas con signo > pp > money > unit > mult > ratio > pct > entity
function tokenizeFinancialText(text) {
  if (!text) return [];
  const entityAlt = KNOWN_ENTITIES.map(e => e.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")).join("|");
  // Regex maestra · longest-match-first
  // 1: delta-up    (+X% o +X.X%)
  // 2: delta-down  (-X% o -X.X%)
  // 3: pp          (X.X pp / X pp / +X pp / -X pp / X.X puntos)
  // 4: money       ($XXX K/M/B con punto/coma decimal opcional)
  // 5: unit        (X días / X.X meses / X semanas / X.X años)
  // 6: mult        (X.Xx · multiplicador)
  // 7: ratio       (X:Y · proporción)
  // 8: pct         (XX.X% sin signo explícito)
  // 9: entity      (nombre cliente conocido)
  const re = new RegExp(
    "(\\+\\d+(?:[.,]\\d+)?%)" +                                          // 1 up
    "|(\\-\\d+(?:[.,]\\d+)?%)" +                                         // 2 down
    "|([+\\-]?\\d+(?:[.,]\\d+)?\\s?(?:pp|puntos)\\b)" +                  // 3 pp
    "|(\\$\\s?\\d+(?:[.,]\\d+)?\\s?[KMB]?(?:\\b|(?=\\W)))" +             // 4 money
    "|(\\d+(?:[.,]\\d+)?\\s?(?:días|dias|meses|semanas|años|anos|horas)\\b)" + // 5 unit
    "|(\\d+(?:[.,]\\d+)?x\\b)" +                                         // 6 mult
    "|(\\d+:\\d+)" +                                                     // 7 ratio
    "|(\\d+(?:[.,]\\d+)?%)" +                                            // 8 pct
    "|(" + entityAlt + ")",                                              // 9 entity
    "gi"
  );
  const tokens = [];
  let lastIdx = 0;
  let m;
  while ((m = re.exec(text)) !== null) {
    if (m.index > lastIdx) {
      tokens.push({ type:"plain", text: text.slice(lastIdx, m.index) });
    }
    if (m[1])      tokens.push({ type:"up",     text: m[1] });
    else if (m[2]) tokens.push({ type:"down",   text: m[2] });
    else if (m[3]) tokens.push({ type:"pp",     text: m[3] });
    else if (m[4]) tokens.push({ type:"money",  text: m[4] });
    else if (m[5]) tokens.push({ type:"unit",   text: m[5] });
    else if (m[6]) tokens.push({ type:"mult",   text: m[6] });
    else if (m[7]) tokens.push({ type:"ratio",  text: m[7] });
    else if (m[8]) tokens.push({ type:"pct",    text: m[8] });
    else if (m[9]) tokens.push({ type:"entity", text: m[9] });
    lastIdx = m.index + m[0].length;
  }
  if (lastIdx < text.length) tokens.push({ type:"plain", text: text.slice(lastIdx) });
  return tokens;
}

// Estilos "plain" sin chip: usados en contexto tabular para no romper alineación
const FINANCIAL_PLAIN = {
  money: { color:"#FFFFFF", fontWeight:600, fontFamily:"'JetBrains Mono', ui-monospace, monospace", fontSize:"0.94em", fontFeatureSettings:"'tnum'", letterSpacing:"0.2px" },
  pct:   { color:"#FFFFFF", fontWeight:600, fontFamily:"'JetBrains Mono', ui-monospace, monospace", fontSize:"0.94em", fontFeatureSettings:"'tnum'" },
  unit:  { color:"#FFFFFF", fontWeight:600, fontFamily:"'JetBrains Mono', ui-monospace, monospace", fontSize:"0.94em", fontFeatureSettings:"'tnum'" },
  mult:  { color:"#FFFFFF", fontWeight:600, fontFamily:"'JetBrains Mono', ui-monospace, monospace", fontSize:"0.94em", fontFeatureSettings:"'tnum'" },
  ratio: { color:"#FFFFFF", fontWeight:600, fontFamily:"'JetBrains Mono', ui-monospace, monospace", fontSize:"0.94em", fontFeatureSettings:"'tnum'" },
  pp:    { color:"#fde047", fontWeight:600, fontFamily:"'JetBrains Mono', ui-monospace, monospace", fontSize:"0.94em", fontFeatureSettings:"'tnum'" },
  up:    { color:"#10b981", fontWeight:600, fontFamily:"'JetBrains Mono', ui-monospace, monospace", fontSize:"0.94em", fontFeatureSettings:"'tnum'" },
  down:  { color:"#f43f5e", fontWeight:600, fontFamily:"'JetBrains Mono', ui-monospace, monospace", fontSize:"0.94em", fontFeatureSettings:"'tnum'" },
  entity:{ color:"#7fdef0", fontWeight:500 },
};

// Detecta si el texto está en contexto tabular: alguna línea con 2+ espacios consecutivos
// (alineación columnar tipo "Falabella     $19.4M"). En ese caso suprimimos el chip
// para no romper la visualidad de tabla.
function isTabularText(text) {
  if (!text) return false;
  // Buscar línea con 2+ espacios consecutivos entre caracteres no-espacio
  return /\S\s{2,}\S/.test(text);
}

function renderWithFinancialHighlight(text, keyPrefix="fh", forcePlain=false) {
  const tokens = tokenizeFinancialText(text);
  if (tokens.length <= 1) return text; // Sin matches · devuelve string crudo
  const styleSet = forcePlain ? FINANCIAL_PLAIN : FINANCIAL_HIGHLIGHT;
  return tokens.map((t, i) => {
    if (t.type === "plain") return t.text;
    const style = styleSet[t.type];
    return <span key={`${keyPrefix}-${i}`} style={style}>{t.text}</span>;
  });
}

function renderMarkdownLite(text) {
  if (!text) return null;

  // Detección de contexto tabular: si el texto tiene alineación columnar
  // (2+ espacios consecutivos entre caracteres), suprimimos chips en cifras
  // para no romper la visualidad de tabla. En prosa narrativa: chips normales.
  const forcePlain = isTabularText(text);

  // Tokenize the string into segments of plain text + bold + italic.
  // Strategy: greedy from longest to shortest. **bold** must be matched
  // before *italic* to avoid conflicts. Plain segments además pasan por
  // el highlighter financiero para resaltar cifras y entidades.

  const segments = [];
  let remaining = text;
  let key = 0;

  while (remaining.length > 0) {
    // Try **bold** first
    const boldMatch = remaining.match(/^\*\*([^*]+)\*\*/);
    if (boldMatch) {
      segments.push(<strong key={`md-${key++}`}>{renderWithFinancialHighlight(boldMatch[1], `md-${key}b`, forcePlain)}</strong>);
      remaining = remaining.slice(boldMatch[0].length);
      continue;
    }

    // Then try *italic*
    const italicMatch = remaining.match(/^\*([^*]+)\*/);
    if (italicMatch) {
      segments.push(<em key={`md-${key++}`}>{renderWithFinancialHighlight(italicMatch[1], `md-${key}i`, forcePlain)}</em>);
      remaining = remaining.slice(italicMatch[0].length);
      continue;
    }

    // Otherwise consume plain text until the next * marker
    const nextMarker = remaining.indexOf("*");
    if (nextMarker === -1) {
      // No more markers; consume the rest as plain text con highlighting
      segments.push(<span key={`md-${key++}`}>{renderWithFinancialHighlight(remaining, `md-${key}p`, forcePlain)}</span>);
      break;
    }

    // Consume text up to the next *
    if (nextMarker > 0) {
      segments.push(<span key={`md-${key++}`}>{renderWithFinancialHighlight(remaining.slice(0, nextMarker), `md-${key}p`, forcePlain)}</span>);
      remaining = remaining.slice(nextMarker);
    } else {
      // Marker at position 0 but didn't match bold/italic (orphan *)
      // Treat the single * as literal text and move on
      segments.push(<span key={`md-${key++}`}>{remaining.charAt(0)}</span>);
      remaining = remaining.slice(1);
    }
  }

  return segments;
}

function AdiBlocks({ text, loading }) {
  const blocks = text.split(/\n\n+/).filter(Boolean);
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:22 }}>
      {blocks.map((block,i)=>{
        // ── Hook ejecutivo
        if (block.startsWith("__HOOK__")) {
          const lines    = block.replace("__HOOK__","").trim().split("\n").filter(Boolean);
          const question = lines[lines.length-1];
          const body     = lines.slice(0,-1).join("\n");
          return (
            <div key={i} style={{ background:"linear-gradient(135deg,rgba(0,176,212,0.07),rgba(14,127,168,0.05))", border:`1px solid rgba(0,176,212,0.2)`, borderRadius:10, padding:"13px 15px", position:"relative", overflow:"hidden" }}>
              <div style={{ position:"absolute", left:0, top:0, bottom:0, width:3, background:"linear-gradient(180deg,#00b0d4,#0e7fa8)", borderRadius:"10px 0 0 10px" }}/>
              <p style={{ fontSize:13.5, color:C.textSub, lineHeight:1.6, paddingLeft:4, whiteSpace:"pre-line", marginBottom:10 }}>{body}</p>
              <p style={{ fontSize:13.5, fontWeight:700, color:C.cyan, lineHeight:1.5, paddingLeft:4, borderTop:`1px solid rgba(0,176,212,0.15)`, paddingTop:9 }}>{question}</p>
              {loading && <span style={{ display:"inline-block", width:5, height:11, background:C.cyan, borderRadius:2, animation:"blink 0.8s infinite", marginLeft:3 }}/>}
            </div>
          );
        }

        // ── Cita de Confianza — tratamiento metadata (divisor + dot verde)
        const trimmed = block.trim();
        const isConfianzaBlock = /^\*[^*]+\*$/.test(trimmed) && /confianza/i.test(trimmed);
        if (isConfianzaBlock) {
          const inner = trimmed.replace(/^\*/, "").replace(/\*$/, "");
          return (
            <div key={i} style={{
              display:"flex", alignItems:"flex-start", gap:8,
              paddingTop:11, marginTop:2,
              borderTop:"1px solid rgba(255,255,255,0.05)",
              fontSize:12, color:C.textMuted, fontStyle:"italic",
              lineHeight:1.6, letterSpacing:"0.01em"
            }}>
              <span style={{
                display:"inline-block", width:5, height:5, borderRadius:"50%",
                background:C.green, marginTop:6, flexShrink:0,
                boxShadow:"0 0 6px rgba(16,185,129,0.5)"
              }}/>
              <span>{inner}</span>
            </div>
          );
        }

        // ── Primer párrafo del análisis — apertura con más peso visual
        const isFirst = i === 0 || (i === 1 && blocks[0].startsWith("__HOOK__"));
        if (isFirst && !block.startsWith("__HOOK__")) {
          return (
            <p key={i} style={{ fontSize:13.5, fontWeight:600, color:C.text, lineHeight:1.6, letterSpacing:"-0.005em", whiteSpace:"pre-line" }}>{renderMarkdownLite(block)}</p>
          );
        }

        // ── Último párrafo — cierre ejecutivo, mismo estilo que los demás
        const isLast = i === blocks.length - 1 && !loading;
        if (isLast && !block.startsWith("__HOOK__")) {
          return (
            <p key={i} style={{ fontSize:13, color:C.textSub, lineHeight:1.6, whiteSpace:"pre-line" }}>{renderMarkdownLite(block)}</p>
          );
        }

        // ── Párrafos intermedios — texto estándar
        return <p key={i} style={{ fontSize:13, color:C.textSub, lineHeight:1.6, whiteSpace:"pre-line" }}>{renderMarkdownLite(block)}</p>;
      })}
      {loading && <span style={{ display:"inline-block", width:6, height:12, background:C.blue, borderRadius:2, animation:"blink 0.8s infinite" }}/>}
    </div>
  );
}

