        // BRIEF #26-bis · pasamos conversationContext para que el fallback
        // pueda resolver entidad desde memoria antes de pedir aclaración.
        const response = generateSimulation(intent.text, scenario, modulo, conversationContextRef.current);
        responseOpener      = response.opener;
        responseSuggestions = response.suggestions;
