      // ════════════════════════════════════════════════════════════════════
      try {
        const etlg_tier = detectRceTier(derivedIntentType, intent?.type, lastComposerResponse);
        // Solo tiers ferrari + module_overview (D5 LOCKED)
        if (etlg_tier === "ferrari" || etlg_tier === "module_overview") {
          const etlg_intentMeta = {
            intent_id: intent?._semantic_meta?.intent_id || null,
            intent_type: intent?.type || null,
            archetype: intent?.crossDomain?.archetype || null,
            concepts: intent?._semantic_meta?.concepts || [],
            modulo: intent?.modulo || null,
            client_name: intent?.clientName || null,
            tier: etlg_tier,
          };
          const etlg_rawPayload = {
            opener: responseOpener,
            suggestions: responseSuggestions,
            sentrixAction: responseSentrixAction,
          };
          const etlg_result = executiveThesisLineGenerator(etlg_rawPayload, etlg_intentMeta, scenario);
          if (etlg_result
              && etlg_result.shouldApply === true
              && typeof etlg_result.thesisLine === "string"
              && etlg_result.thesisLine.length > 0) {
            // ETLG SUMA · prepend thesis al opener · NO modifica cuerpo
            responseOpener = etlg_result.thesisLine + "\n\n" + responseOpener;
          }
          // shouldApply=false → passthrough silencioso · responseOpener intacto
        }
      } catch (etlg_err) {
        // eslint-disable-next-line no-console
        console.warn("BRIEF #10 ETLG error:", etlg_err);
        // FAIL-SAFE: responseOpener intacto · path actual ejecuta
      }

      // ════════════════════════════════════════════════════════════════════
      // BRIEF #8 (post-46-bis) · PIEZA 3 · RESPONSE CONTRACT ENGINE
      //
      // Punto de integración: DESPUÉS de la cadena if/else if intent.type
      // (composer ganador asignó responseOpener) · ANTES de Premise APPLY
      // (PREPEND/APPEND del BRIEF #38).
      //
      // Orden funcional preservado: Composer → RCE upgrade → Premise APPLY →
      // SGE override → setters React.
      //
      // try-catch defensivo · variables rce_* prefijadas · scoped al guard.
