// ── _extractTopClientNames · helper privado · shape detection defensiva ──
// Mitigación bug [object Object] · cross_signals tienen 2 shapes distintos para top3:
//   · customer_dependency.top3_names      · array de STRINGS plano
//   · margin_pressure.top3_instances      · array de OBJECTS con clientName
// Detecta shape · extrae nombres uniformes · filtra null/undefined.
// Lección #L-CROSS-SIGNALS-TOP3-SHAPES-DISTINTOS-OBJECTS-VS-STRINGS-MAPEO-EXPLICITO.
function _extractTopClientNames(arr) {
  if (!Array.isArray(arr) || arr.length === 0) return [];
  return arr.map(item => {
    if (typeof item === "string") return item;                                    // top3_names (strings)
    if (item && typeof item.clientName === "string") return item.clientName;      // top3_instances (objects)
    if (item && typeof item.name === "string") return item.name;
    return null;
  }).filter(s => s !== null);
}

// ── _renderCausalPlaceholders · helper privado · sustituye placeholders ──
// D-R.C-2 firmado · fallback "(cifra no disponible)" cuando valor null/undefined.
// D-R.C-3 firmado · separador " · " en narrative_assembled.
// Cifras runtime extraídas desde ctx + scan + cross_signals.
function _renderCausalPlaceholders(template, ctx, scan) {
  if (!template || typeof template !== "string") return "";
  const cs = ctx.cross_signals || {};
  const v = ctx.ventas || {};
  const inv = ctx.inventario || {};
  const mar = ctx.margenes || {};
  // Extracción defensiva (fallback string si campo ausente)
  const FB = "(cifra no disponible)";
  const carga_pct = mar.cargaComercialPromedio !== undefined ? String(mar.cargaComercialPromedio) : FB;
  const recup_K_value = scan && scan.commercial_erosion && scan.commercial_erosion.aggregate
    ? scan.commercial_erosion.aggregate.recuperable_total_K
    : (cs.margin_pressure ? cs.margin_pressure.valor_recuperable_K : undefined);
  const recup_str = typeof recup_K_value === "number" ? _fmtMoneyK(recup_K_value) : FB;
  // Top 3 clientes · margin_pressure usa objects
  const mp_top3 = cs.margin_pressure && cs.margin_pressure.top3_instances
    ? _extractTopClientNames(cs.margin_pressure.top3_instances).slice(0, 3)
    : [];
  const top3_clientes = mp_top3.length > 0 ? mp_top3.join(", ") : FB;
  // Top 3 customer_dependency · usa strings
  const cd_top3 = cs.customer_dependency && cs.customer_dependency.top3_names
    ? _extractTopClientNames(cs.customer_dependency.top3_names).slice(0, 3)
    : [];
  const top3_clientes_cd = cd_top3.length > 0 ? cd_top3.join(", ") : FB;
  const cap_pct = inv.capitalPctAtrapado !== undefined ? String(inv.capitalPctAtrapado) : FB;
  const cap_str = inv.capitalAtrapado !== undefined ? _fmtMoneyK(_capEscalaK(inv.capitalAtrapado)) : FB;
  const qog_perdida_M = cs.quality_of_growth && cs.quality_of_growth.contribucion_perdida_M !== undefined
    ? String(cs.quality_of_growth.contribucion_perdida_M)
    : FB;
  const cd_pct = cs.customer_dependency && cs.customer_dependency.top3_participacion_pct !== undefined
    ? String(cs.customer_dependency.top3_participacion_pct)
    : FB;
  const cd_contrib_M = cs.customer_dependency && cs.customer_dependency.top3_contribucion_M !== undefined
    ? String(cs.customer_dependency.top3_contribucion_M)
    : FB;
  const mp_instances = cs.margin_pressure && cs.margin_pressure.instances_count !== undefined
    ? String(cs.margin_pressure.instances_count)
    : FB;
  return template
    .replace("{carga_pct}", carga_pct)
    .replace("{recup_str}", recup_str)
    .replace("{top3_clientes}", top3_clientes)
    .replace("{top3_clientes_cd}", top3_clientes_cd)
    .replace("{cap_pct}", cap_pct)
    .replace("{cap_str}", cap_str)
    .replace("{qog_perdida_M}", qog_perdida_M)
    .replace("{cd_pct}", cd_pct)
    .replace("{cd_contrib_M}", cd_contrib_M)
    .replace("{mp_instances}", mp_instances);
}

// ── composeCausalChain · función pública R.C · MAIN ENTRY ────────────────
// Compone cadena causal de 3 pasos para un driver canonical.
//
// Input:
//   driver_key · string · key canonical de DRIVER_CANONICAL_KEYS (R.A)
//   ctx        · object · aggregator output (con cross_signals)
//                NOTA: ctx puede incluir ctx.scan opcional · si no · busca runtime.
//
// Output (D-R.C-1/2/3 firmadas):
//   {
//     driver: string,
//     cadena: { causa, consecuencia, riesgo },
//     narrative_assembled: "causa · consecuencia · riesgo",  // separador " · "
//     placeholders_filled: { ... },
//     narrative_structure: string,  // metadatos voz diferenciada
//     caveat: null | "Algunos campos no disponibles · cadena con fallback",
//   }
//
// Honest fallback:
//   Si flag OFF / driver_key inválido / driver no en CAUSAL_CHAINS → null.
//   D-R.C-4 firmado · 1 driver por invocación · caller decide cuántos invocar.
function composeCausalChain(driver_key, ctx) {
  // Flag rollback
  if (!VOICE_CAUSAL_GRAPH_ENABLED) return null;
  // Validación shape
  if (!driver_key || typeof driver_key !== "string") return null;
  // Lookup defensivo · driver no catalogado retorna null (honest)
  const def = CAUSAL_CHAINS[driver_key];
  if (!def) return null;
  // ctx validación
  if (!ctx || typeof ctx !== "object") return null;
  // Obtener scan si está disponible (algunos drivers requieren scan.commercial_erosion)
  const scan = ctx.scan || (ctx.scenarioId ? scanMechanisms(ctx.scenarioId) : null);
  // Render cada paso con placeholders runtime
  const causa = _renderCausalPlaceholders(def.causa, ctx, scan);
  const consecuencia = _renderCausalPlaceholders(def.consecuencia, ctx, scan);
  const riesgo = _renderCausalPlaceholders(def.riesgo, ctx, scan); // riesgo es texto fijo · pero pasamos para defensivo
  // Detectar si hubo fallback aplicado
  const FB_MARKER = "(cifra no disponible)";
  const hasFallback = causa.includes(FB_MARKER) || consecuencia.includes(FB_MARKER) || riesgo.includes(FB_MARKER);
  // D-R.C-3 · separador " · "
  const narrative_assembled = causa + " · " + consecuencia + " · " + riesgo;
  return {
    driver: driver_key,
    cadena: { causa, consecuencia, riesgo },
    narrative_assembled,
    placeholders_filled: { causa, consecuencia, riesgo },
    narrative_structure: def.narrative_structure,
    caveat: hasFallback ? "Algunos campos no disponibles · cadena con fallback" : null,
  };
}

