// BRIEF R · R.D · CONFIDENCE ENGINE
//
// Declarador sistemático de nivel de confianza cross-componente.
// Regla 3 del manifiesto: ADI explicita honestidad epistémica.
//
// Decisiones aplicadas (founder firmado):
//   · D-R.D-1 · threshold "alta" = signals >= 3 AND completeness >= 0.85
//   · D-R.D-2 · 1 reason representativa seleccionada determinísticamente
//   · D-R.D-3 · "baja" solo edge cases sintéticos · MVP siempre "alta"
//   · D-R.D-4 · caveat null en "alta" si completeness >= 0.95
//   · D-R.D-5 · drivers_involved argumento opcional
//
// Ajustes V4 aplicados:
//   · Reason "alta" #3 reescrita a voz consultora (NO tecnicismo cross_signals)
//   · Reason "baja" #2 con renderer runtime + fallback genérico
//
// Lecciones aplicadas:
//   · #L-NAMING-CONVENTION-DEL-BRIEF-DEBE-MATCHEAR-NOMBRES-RUNTIME-REALES (V2 audit)
//   · #L-CATALOGOS-COMPARTIDOS-CROSS-PIEZA-VIVEN-EN-NAMESPACE-INDEPENDIENTE-NO-EN-PIEZA-PROPIETARIA
// ════════════════════════════════════════════════════════════════════════════

// Flag rollback granular R.D.
const VOICE_CONFIDENCE_ENGINE_ENABLED = true;

// CONFIDENCE_REASONS · 3 niveles · 3 razones cada uno · voz consultora sénior.
//
// V4 ajustes firmados:
//   · alta[2] · reescrito · NO tecnicismo "cross_signals" · lenguaje negocio
//   · baja[1] · placeholder {dataset_X} renderer runtime · fallback "datos"
const CONFIDENCE_REASONS = {
  alta: [
    "Señales convergentes desde múltiples dimensiones · ventas, márgenes e inventario apuntan en la misma dirección",
    "Cifras claras y consistentes con histórico observado",
    "El diagnóstico se sostiene en señales que convergen entre ventas, márgenes e inventario · NO es interpretación aislada",
  ],
  media: [
    "Interpretación requiere información adicional de convenios comerciales",
    "Histórico parcial · ventana de observación corta",
    "Señal presente pero contraste limitado entre dimensiones",
  ],
  baja: [
    "Señal aislada · NO convergente con otras dimensiones",
    "Datos incompletos en {dataset_X}",
    "Variabilidad alta · interpretación ambigua",
  ],
};

// ── _countConvergentSignals · helper privado · cuenta cross_signals existe=true ──
// Conteo determinístico de señales activas en el aggregator.
// Las 4 cross_signals canónicas (qog · cust_dep · mp · cap_leak) producen
// existe=true cross-3-escenarios runtime · signals_count=4 cross-escenario MVP.
function _countConvergentSignals(ctx) {
  if (!ctx || !ctx.cross_signals) return 0;
  const cs = ctx.cross_signals;
  let count = 0;
  for (const k of Object.keys(cs)) {
    if (cs[k] && cs[k].existe === true) count++;
  }
  return count;
}

// ── _computeDataCompleteness · helper privado · cobertura datasets crudos ──
//
// CRÍTICO: usa nombres runtime reales · NO los prescritos por BRIEF.
// Lección #L-NAMING-CONVENTION-DEL-BRIEF-DEBE-MATCHEAR-NOMBRES-RUNTIME-REALES.
//
// Campos reales runtime (V2 audit pre-flight):
//   clientesVentas[]  · nombre, actual, anterior, presupuesto
//   clientesMargen[]  · nombre, venta, contribucion, pctRebate, benchmark, margen
//   skuInventario[]   · sku, stockUSD, doh, estado, alerta, sfamilia
//
// NO usar: cliente, ventas, capital_USD, DOH, familia (BRIEF prescription · no runtime)
//
// Output: [0,1] ratio · 1.0 = todos los campos críticos populated en todos los items.
function _computeDataCompleteness(scenarioId) {
  if (typeof scenarioId !== "string") return 0;
  let cv, cm, skus;
  try {
    cv = applyScenarioToClientesVentas(scenarioId);
    cm = applyScenarioToClientesMargen(scenarioId);
    skus = applyScenarioToSkuInventario(scenarioId);
  } catch (e) {
    return 0;
  }
  if (!Array.isArray(cv) || !Array.isArray(cm) || !Array.isArray(skus)) return 0;
  if (cv.length === 0 || cm.length === 0 || skus.length === 0) return 0;
  // Campos críticos · nombres RUNTIME REALES
  const cvCritical = ["nombre", "actual", "anterior", "presupuesto"];
  const cmCritical = ["nombre", "margen", "contribucion", "pctRebate", "benchmark", "venta"];
  const skuCritical = ["sku", "stockUSD", "doh", "estado", "alerta"];
  const fieldRatio = (items, fields) => {
    return fields.reduce((acc, f) => {
      const populated = items.filter(it => it[f] !== undefined && it[f] !== null).length;
      return acc + (populated / items.length);
    }, 0) / fields.length;
  };
  const cvScore = fieldRatio(cv, cvCritical);
  const cmScore = fieldRatio(cm, cmCritical);
  const skuScore = fieldRatio(skus, skuCritical);
  return (cvScore + cmScore + skuScore) / 3;
}

// ── _determineConfidenceLevel · helper privado · thresholds D-R.D-1 ──
// signals >= 3 AND completeness >= 0.85 → "alta"
// signals >= 2 AND completeness >= 0.7  → "media"
// resto                                  → "baja"
function _determineConfidenceLevel(signals_count, completeness) {
  if (signals_count >= 3 && completeness >= 0.85) return "alta";
  if (signals_count >= 2 && completeness >= 0.7)  return "media";
  return "baja";
}

// ── _selectConfidenceReason · helper privado · selección determinística D-R.D-2 ──
// 1 reason representativa elegida runtime por signals_count o drivers_involved.length.
// El selector usa módulo sobre signals_count para discriminar suavemente entre escenarios
// sin saturar la narrativa (NO concatena múltiples reasons · NO randomness).
//
// Si level = "baja" + reason contiene placeholder {dataset_X} · renderer runtime
// detecta cuál dataset tiene menor completeness y rellena (fallback "datos" si todos OK).
function _selectConfidenceReason(level, signals_count, completeness, drivers_involved, scenarioId) {
  const reasons = CONFIDENCE_REASONS[level];
  if (!reasons || reasons.length === 0) return "";
  // Selector determinístico · usa drivers_involved.length si disponible · sino signals_count
  const selectorBase = (drivers_involved && Array.isArray(drivers_involved) && drivers_involved.length > 0)
    ? drivers_involved.length
    : signals_count;
  const idx = ((selectorBase % reasons.length) + reasons.length) % reasons.length;
  let reason = reasons[idx];
  // Renderer placeholder {dataset_X} (solo aplica a "baja" reason #2)
  if (reason.includes("{dataset_X}")) {
    const datasetFallback = _identifyIncompleteDataset(scenarioId) || "datos";
    reason = reason.replace("{dataset_X}", datasetFallback);
  }
  return reason;
}

// ── _identifyIncompleteDataset · helper privado · detecta dataset menos populated ──
// Para "baja" reason #2 renderer · identifica cuál dataset tiene menor completeness.
// Fallback "datos" si todos OK.
function _identifyIncompleteDataset(scenarioId) {
  if (typeof scenarioId !== "string") return "datos";
  let cv, cm, skus;
  try {
    cv = applyScenarioToClientesVentas(scenarioId);
    cm = applyScenarioToClientesMargen(scenarioId);
    skus = applyScenarioToSkuInventario(scenarioId);
  } catch (e) {
    return "datos";
  }
  const scoreOf = (items, fields) => {
    if (!Array.isArray(items) || items.length === 0) return 0;
    return fields.reduce((acc, f) => {
      const populated = items.filter(it => it[f] !== undefined && it[f] !== null).length;
      return acc + (populated / items.length);
    }, 0) / fields.length;
  };
  const cvScore = scoreOf(cv, ["nombre", "actual", "anterior", "presupuesto"]);
  const cmScore = scoreOf(cm, ["nombre", "margen", "contribucion", "pctRebate", "benchmark", "venta"]);
  const skuScore = scoreOf(skus, ["sku", "stockUSD", "doh", "estado", "alerta"]);
  // Identificar el más bajo
  if (cvScore <= cmScore && cvScore <= skuScore) return "ventas";
  if (cmScore <= cvScore && cmScore <= skuScore) return "márgenes";
  if (skuScore <= cvScore && skuScore <= cmScore) return "inventario";
  return "datos";
}

// ── assessConfidence · función pública R.D · MAIN ENTRY ──────────────────
// Evalúa nivel de confianza del análisis cross-componente.
//
// Input:
//   scenarioId        · string · "bonanza" | "tension" | "crisis"
//   drivers_involved? · array opcional · drivers del análisis activo (D-R.D-5)
//   ctx?              · object opcional · aggregator computed (evita recomputar)
//
// Output (shape D-R.D-1 a D-R.D-5):
//   {
//     level:                "alta" | "media" | "baja",
//     reasoning:            string · 1 reason representativa runtime,
//     signals_convergentes: number,
//     data_completeness:    number [0,1],
//     caveat:               string | null (null si completeness >= 0.95),
//   }
//
// Honest fallback: scenarioId inválido o flag OFF → null.
function assessConfidence(scenarioId, drivers_involved, ctx) {
  // Flag rollback
  if (!VOICE_CONFIDENCE_ENGINE_ENABLED) return null;
  // Validación
  if (typeof scenarioId !== "string") return null;
  // Compute ctx si no provisto
  const evalCtx = ctx || crossDomainAggregator(scenarioId);
  if (!evalCtx) return null;
  // Métricas
  const signals_count = _countConvergentSignals(evalCtx);
  const data_completeness = _computeDataCompleteness(scenarioId);
  const level = _determineConfidenceLevel(signals_count, data_completeness);
  const reasoning = _selectConfidenceReason(level, signals_count, data_completeness, drivers_involved, scenarioId);
  // D-R.D-4 · caveat solo si completeness < 0.95
  const caveat = data_completeness < 0.95 ? "Algunos campos parcialmente disponibles" : null;
  return {
    level,
    reasoning,
    signals_convergentes: signals_count,
    data_completeness,
    caveat,
  };
}

