// BRIEF R · R.H · QUESTION GENERATOR
//
// Generador de preguntas estratégicas que ADI sugiere proactivamente al
// cierre del reporte ejecutivo (R.I sección "Pregunta sugerida").
//
// 🚨 R.H NO duplica suggestions M.B.3:
//   · R.H · preguntas ESTRATÉGICAS cross-pattern · catálogo cerrado · 18 preguntas
//   · M.B.3 · suggestions navegación específica del cliente · runtime inline post deep dive
//   · GREETING_RESPONSE · 3 caminos onboarding usuario nuevo · LOCKED
// Cero overlap funcional · operan en momentos distintos.
//
// Decisiones aplicadas (founder firmado):
//   · D-R.H-1 · 3 preguntas por driver · 18 total (6 drivers × 3)
//   · D-R.H-2 · Selector módulo hash sobre scenarioId (varía cross-escenario sin saturar)
//   · D-R.H-3 · n opcional · default 3 · cap 6
//   · D-R.H-4 · Honest fallback empty + caveat literal
//
// Lecciones aplicadas:
//   · #L-QUESTION-GENERATOR-DISTINTO-DE-SUGGESTIONS-NAVEGACION (R.H nueva)
//   · #L-SELECTOR-DETERMINISTICO-HASH-EVITA-RANDOMNESS-Y-DISCRIMINA-CROSS-ESCENARIO (heredada R.D · validada R.H)
//   · #L-CAPA-FUNDACIONAL-CONSUMERS-INVOCAN-FUNCIONES-LOCKED-NO-DUPLICAN
// ════════════════════════════════════════════════════════════════════════════

// Flag rollback granular R.H.
const VOICE_QUESTION_GENERATOR_ENABLED = true;

// EXECUTIVE_QUESTIONS · 18 preguntas estratégicas (6 drivers × 3).
//
// Voz: "controller sénior abriendo conversación" · NO "checklist auditor".
// Todas inician con "¿" · todas abren conversación (NO cierran con sí/no obvio).
// Cada pregunta específica al driver con palanca clara.
//
// Ejemplo runtime cross-escenario:
//   · Bonanza pattern=tier1_lock · drivers primary [customer_dep, qog, mp] · drivers secondary [commercial_erosion]
//   · Crisis pattern=operational_strangulation · drivers primary [trapped, commercial, liquidity]
//
// Cero overlap con suggestions M.B.3 (¿Qué SKUs aportan más en Falabella?) · NIVEL estratégico.
const EXECUTIVE_QUESTIONS = {
  commercial_erosion: [
    "¿Qué cuentas pueden absorber renegociación de carga sin perder volumen crítico?",
    "¿Cuál es el piso de margen estructural por cuenta Tier 1?",
    "¿La política comercial actual tiene comparable interno reciente?",
  ],
  trapped_capital: [
    "¿Qué familias toleran congelación temporal de pedidos sin afectar servicio?",
    "¿La planificación de compras revisa rotación o solo cobertura mínima?",
    "¿Hay SKUs candidatos a liquidación priorizada antes que escale?",
  ],
  customer_dependency_risk: [
    "¿Qué plan de mitigación tenemos ante caída 20% en Tier 1?",
    "¿Las cuentas medianas pueden absorber volumen liberado de Tier 1?",
    "¿Hay revisión estratégica trimestral con cuentas Tier 1 hoy?",
  ],
  quality_of_growth_deterioration: [
    "¿Por qué la calidad de crecimiento está deteriorándose?",
    "¿El mix de cuentas que sostiene crecimiento es sustentable a 12 meses?",
    "¿Tenemos visibilidad de contribución por unidad incremental vendida?",
  ],
  liquidity_compression: [
    "¿Cuál es la capacidad de absorber stress combinado stock + márgenes?",
    "¿Tenemos cash flow forecast a 13 semanas con escenarios pesimistas?",
    "¿Qué decisiones tácticas estamos posponiendo por presión simultánea?",
  ],
  margin_pressure: [
    "¿Las renegociaciones recientes tienen comparable interno auditado?",
    "¿Existe piso mínimo de margen comunicado a fuerza comercial?",
    "¿El benchmark interno se mantiene como referencia activa en negociación?",
  ],
};

// ── _hashScenarioId · helper privado · módulo determinístico ──
// D-R.H-2 firmado · hash determinístico sobre scenarioId string.
// Garantiza varianza cross-escenario sin randomness · misma input → mismo output.
// Pre-flight V2.1 confirmó discriminación: Bonanza∩Tensión=1 · Bonanza∩Crisis=0 · Tensión∩Crisis=0.
function _hashScenarioId(scenarioId) {
  if (typeof scenarioId !== "string") return 0;
  let h = 0;
  for (let i = 0; i < scenarioId.length; i++) {
    h = (h * 31 + scenarioId.charCodeAt(i)) | 0;
  }
  return Math.abs(h);
}

// ── _selectQuestionForDriver · helper privado · selección determinística ──
// Para un driver dado, selecciona 1 pregunta del pool aplicando hash + offset.
// Si la pregunta ya fue seleccionada (alreadyPicked) · prueba siguiente índice.
// Si NINGUNA del pool es nueva · retorna null (skip silencioso).
// Defensiva: si driver no catalogado en EXECUTIVE_QUESTIONS → retorna null.
function _selectQuestionForDriver(driver, hash, offset, alreadyPicked) {
  const pool = EXECUTIVE_QUESTIONS[driver];
  if (!Array.isArray(pool) || pool.length === 0) return null;
  const setPicked = new Set(alreadyPicked || []);
  for (let i = 0; i < pool.length; i++) {
    const idx = (hash + offset + i) % pool.length;
    const q = pool[idx];
    if (!setPicked.has(q)) return q;
  }
  return null;
}

// ── generateQuestions · función pública R.H · MAIN ENTRY ─────────────────
// Genera n preguntas estratégicas runtime para el escenario dado.
//
// Pipeline:
//   1. detectBusinessPattern(scenarioId) → primary + secondary patterns
//   2. drivers_primary + drivers_secondary (dedupe)
//   3. Selector hash determinístico · 2 preguntas drivers primary · 1 secondary
//   4. Si faltan para llegar a n · seguir extrayendo del pool primary
//
// Input:
//   scenarioId · string · "bonanza" | "tension" | "crisis"
//   ctx?       · object · aggregator computed
//   options?   · object · { n: number · default 3 · cap 6 }
//
// Output (D-R.H-1 a D-R.H-4):
//   {
//     questions: [string, string, ...] · n preguntas,
//     pattern_context: { primary_id, primary_name } | null,
//     fallback_caveat: string | null,
//     meta: { drivers_primary, drivers_secondary, hash, total_evaluated }
//   }
//
// Honest fallback (D-R.H-4):
//   · Flag OFF / scenarioId inválido / pattern primary null → empty + caveat literal
function generateQuestions(scenarioId, ctx, options) {
  // Flag rollback
  if (!VOICE_QUESTION_GENERATOR_ENABLED) {
    return {
      questions: [],
      pattern_context: null,
      fallback_caveat: "Motor de generación de preguntas estratégicas desactivado en esta configuración.",
      meta: { drivers_primary: [], drivers_secondary: [], hash: 0, total_evaluated: 0 },
    };
  }
  // Validación scenarioId
  if (typeof scenarioId !== "string") {
    return {
      questions: [],
      pattern_context: null,
      fallback_caveat: "No tengo preguntas estratégicas porque el escenario no está bien identificado.",
      meta: { drivers_primary: [], drivers_secondary: [], hash: 0, total_evaluated: 0 },
    };
  }
  // n opcional · default 3 · cap 6 (D-R.H-3)
  let n = 3;
  if (options && typeof options.n === "number" && options.n > 0) {
    n = Math.min(6, options.n);
  }
  // Compute ctx defensivamente
  const evalCtx = ctx || crossDomainAggregator(scenarioId);
  if (!evalCtx || !evalCtx.cross_signals) {
    return {
      questions: [],
      pattern_context: null,
      fallback_caveat: "No tengo preguntas estratégicas porque no se detectó un patrón claro.",
      meta: { drivers_primary: [], drivers_secondary: [], hash: 0, total_evaluated: 0 },
    };
  }
  // Detectar pattern (R.F)
  const patternResult = detectBusinessPattern(scenarioId, evalCtx);
  if (!patternResult || !patternResult.primary_pattern) {
    return {
      questions: [],
      pattern_context: null,
      fallback_caveat: "No tengo preguntas estratégicas porque no se detectó un patrón claro.",
      meta: { drivers_primary: [], drivers_secondary: [], hash: 0, total_evaluated: 0 },
    };
  }
  const primary = patternResult.primary_pattern;
  const drivers_primary = primary.drivers_involved || [];
  // Drivers secondary · dedupe (heredado lógica R.G _buildDriversPool)
  const drivers_secondary = [];
  for (const sp of (patternResult.secondary_patterns || [])) {
    for (const d of (sp.drivers_involved || [])) {
      if (!drivers_primary.includes(d) && !drivers_secondary.includes(d)) {
        drivers_secondary.push(d);
      }
    }
  }
  // Hash determinístico cross-escenario (D-R.H-2)
  const hash = _hashScenarioId(scenarioId);
  // Selector: 2 primary + 1 secondary · fill con primary si faltan
  const questions = [];
  // 2 preguntas drivers primary
  let primaryPicked = 0;
  for (let i = 0; i < drivers_primary.length && primaryPicked < 2 && questions.length < n; i++) {
    const drv = drivers_primary[i];
    const q = _selectQuestionForDriver(drv, hash, i, questions);
    if (q) {
      questions.push(q);
      primaryPicked++;
    }
  }
  // 1 pregunta secondary (si existe driver secondary)
  if (drivers_secondary.length > 0 && questions.length < n) {
    const drv = drivers_secondary[0];
    const q = _selectQuestionForDriver(drv, hash, 1, questions);
    if (q) questions.push(q);
  }
  // Fill restantes desde primary pool · skip duplicados
  let fillAttempts = 0;
  while (questions.length < n && fillAttempts < 30) {
    fillAttempts++;
    const drv = drivers_primary[fillAttempts % drivers_primary.length];
    if (!drv) break;
    const q = _selectQuestionForDriver(drv, hash, fillAttempts, questions);
    if (q) questions.push(q);
  }
  return {
    questions: questions.slice(0, n),
    pattern_context: {
      primary_id: primary.id,
      primary_name: primary.name,
    },
    fallback_caveat: null,
    meta: {
      drivers_primary,
      drivers_secondary,
      hash,
      total_evaluated: questions.length,
    },
  };
}

