// Flag rollback granular R.I · D-R.I-5 default FALSE · V1 sigue corriendo runtime React
// hasta que founder valide V_VISUAL R.I y active flag manualmente.
// D-RJ-1 firmado (A') post-V_VISUAL R.J · activación default true · cerebro
// ejecutivo accesible por default · rollback granular preservado (setear false
// si emerge necesidad). Test RJ-FLAG-1 verifica el nuevo default explícitamente.
const VOICE_NARRATIVE_V2_ENABLED = true;

// Umbrales Delta Comparator (D-R.I-6 firmado · validados runtime V3 pre-flight).
const DELTA_UMBRAL_VENTAS_YOY_PCT = 3.0;
const DELTA_UMBRAL_CLIENTE_DELTA_PCT = 5.0;
const DELTA_UMBRAL_CLIENTE_RELEVANCIA_K = 3000;

// ── _stripTrailingDot · helper privado · evita doble punto al concatenar ──
// Bug 3 fix · narrative_assembled / statement terminan en "." · concatenación
// genera ".." literal. Strip trailing dot antes de agregar separador.
function _stripTrailingDot(s) {
  if (typeof s !== "string") return s;
  return s.replace(/\.+\s*$/, "");
}

// ── _signedPct · helper privado · formato "+X.X%" / "-X.X%" ──
function _signedPct(v) {
  if (typeof v !== "number" || isNaN(v)) return "?";
  return v > 0 ? "+" + v.toFixed(1) : v.toFixed(1);
}

// ── _composeDeltaTemporal · Delta Comparator mínimo determinístico ──────
// Regla 4 manifiesto · "lo que cambió en el período".
//
// MVP scope (audit pre-flight V1 confirmó campos disponibles runtime):
//   · Ventas agregado YoY (ctx.ventas.crecimientoYoY) · cifra nativa runtime
//   · Top movers per-cliente (cliente.actual vs cliente.anterior · cálculo trivial)
//
// Campos NO disponibles runtime (deuda #D-DELTA-COMPARATOR-LIMITADO-MVP):
//   · margen anterior · capital atrapado anterior · DOH anterior por SKU
//   · Post-MVP agregar al dataset · activar más dimensiones del Delta.
//
// Umbrales materialidad (D-R.I-6 firmado):
//   · YoY agregado ≥ ±DELTA_UMBRAL_VENTAS_YOY_PCT
//   · Δ cliente ≥ ±DELTA_UMBRAL_CLIENTE_DELTA_PCT AND cliente.actual ≥ DELTA_UMBRAL_CLIENTE_RELEVANCIA_K
//
// Si NINGÚN delta material → honest fallback narrative "sin cambios materiales".
function _composeDeltaTemporal(scenarioId, ctx) {
  if (!ctx || !ctx.ventas) return null;
  const deltas_detected = [];
  // Delta 1 · Ventas agregadas YoY (siempre presente runtime)
  const yoy = ctx.ventas.crecimientoYoY;
  if (typeof yoy === "number" && Math.abs(yoy) >= DELTA_UMBRAL_VENTAS_YOY_PCT) {
    const direction_verb = yoy > 0 ? "crecen" : "caen";
    deltas_detected.push({
      dimension: "ventas_agregado",
      direccion: yoy > 0 ? "positivo" : "negativo",
      magnitud_pct: yoy,
      narrative: "Las ventas " + direction_verb + " " + _signedPct(yoy) + "% YoY · " +
                 _fmtMoneyK(ctx.ventas.total) + " totales",
    });
  }
  // Delta 2 · Top movers per-cliente (clientes con cambio >umbral AND tier 1/2)
  let ventas = null;
  try { ventas = applyScenarioToClientesVentas(scenarioId); } catch (e) { ventas = null; }
  if (Array.isArray(ventas)) {
    const movers = ventas
      .filter(c => c && typeof c.anterior === "number" && c.anterior > 0 &&
                   typeof c.actual === "number" && c.actual >= DELTA_UMBRAL_CLIENTE_RELEVANCIA_K)
      .map(c => ({
        nombre: c.nombre,
        delta_pct: ((c.actual - c.anterior) / c.anterior) * 100,
        delta_K: c.actual - c.anterior,
      }))
      .filter(m => Math.abs(m.delta_pct) >= DELTA_UMBRAL_CLIENTE_DELTA_PCT)
      .sort((a, b) => Math.abs(b.delta_pct) - Math.abs(a.delta_pct))
      .slice(0, 3);
    if (movers.length > 0) {
      const names = movers.map(m => m.nombre + " " + _signedPct(m.delta_pct) + "%").join(" · ");
      deltas_detected.push({
        dimension: "clientes_movers",
        direccion: "mixto",
        magnitud_pct: null,
        narrative: "Cuentas con mayor variación: " + names,
      });
    }
  }
  // Honest fallback (D-R.I-6 firmado · sin material)
  if (deltas_detected.length === 0) {
    return {
      deltas_detected: [],
      narrative: "Sin cambios materiales en el período · negocio estable bajo umbrales declarados",
      caveat: "Período sin movimientos significativos en ventas agregadas ni por cuenta · revisar si umbrales son apropiados.",
    };
  }
  // Composer narrativa integrada · 1 frase con conectores
  const body = deltas_detected.map(d => d.narrative).join(" · ");
  return {
    deltas_detected,
    narrative: body,
    caveat: null,
  };
}

// ── detectExecutiveReportV2Intent · clasificador R.I V2 ──────────────────
// Honra el flag VOICE_NARRATIVE_V2_ENABLED · default FALSE · V1 sigue activo.
// Patterns: "resumen ejecutivo" · "panorama del negocio" · "informe ejecutivo"
// · "cómo está el negocio" · "qué hay del negocio".
//
// Returns:
//   · null si flag OFF (V1 sigue capturando intent vía detectExecutiveReportIntent)
//   · null si text no matchea
//   · { type: "executive_report_v2", subtype, areas } si match
//
// Cero touch a detectExecutiveReportIntent V1 (Q.D Día 1 LOCKED).
function detectExecutiveReportV2Intent(text) {
  if (!VOICE_NARRATIVE_V2_ENABLED) return null;
  if (!text || typeof text !== "string") return null;
  // Patterns alineados con manifiesto (cubre Q.D V1 + extensiones V2)
  const V2_PATTERNS = [
    /\bresumen\s+ejecutivo\b/i,
    /\binforme\s+ejecutivo\b/i,
    /\bpanorama\s+del\s+negocio\b/i,
    /\bpanorama\s+ejecutivo\b/i,
    /\bc[oó]mo\s+est[aá]\s+el\s+negocio\b/i,
    /\bqu[eé]\s+hay\s+del\s+negocio\b/i,
    /\breporte\s+ejecutivo\b/i,
    /\breporte\s+gerencial\b/i,
  ];
  let matched = false;
  for (const p of V2_PATTERNS) {
    if (p.test(text)) { matched = true; break; }
  }
  if (!matched) return null;
  // Áreas opcionales (alineado V1 · permite partial)
  const areas = [];
  if (/\b(venta|ventas|ingreso|crecimiento)\b/i.test(text)) areas.push("ventas");
  if (/\b(margen|m[aá]rgenes|carga\s+comercial|rebate)\b/i.test(text)) areas.push("margenes");
  if (/\b(inventario|stock|capital|sku|doh)\b/i.test(text)) areas.push("inventario");
  const isPartial = areas.length > 0 && areas.length < 3 &&
    /\b(solamente|s[oó]lo|enf[oó]cate|solo\s+en)\b/i.test(text);
  return {
    type: "executive_report_v2",
    subtype: isPartial ? "partial" : "full",
    areas: areas.length > 0 ? areas : null,
  };
}

// ════════════════════════════════════════════════════════════════════════════
// R.I · COMPOSITORES PRIVADOS · 8 funciones · 1 por elemento manifiesto
// Cada composer:
//   · Recibe input pieza R.X (LOCKED · cero modificación)
//   · Aplica _stripTrailingDot para evitar bug 3 doble punto
//   · Retorna string formato "**Header**\\ncontenido" (compatible motor ALPHA)
//   · Retorna "" si input ausente (D-R.I-4 skip silencioso)
// ════════════════════════════════════════════════════════════════════════════

// ── 1 · Tesis ejecutiva · integra R.B primary_tension + R.F primary_pattern ─
// Ejemplo runtime Crisis (V4.3 pre-flight):
//   "**Tesis ejecutiva**
//    Estrangulamiento operativo · Capital atrapado 72.9% del portafolio coexiste
//    con margen comprimido recuperable $2.37M mensual · liquidez bajo presión..."
function _composeTesisEjecutivaV2(tension, pattern) {
  if (!tension || !tension.primary_tension || !pattern || !pattern.primary_pattern) return "";
  const pat_name = pattern.primary_pattern.name;
  const tens_stmt = _stripTrailingDot(tension.primary_tension.statement || "");
  if (!pat_name || !tens_stmt) return "";
  return "**Tesis ejecutiva**\n" + pat_name + " · " + tens_stmt + ".";
}

// ── 2 · Evidencia crítica · cifras runtime canonical · ancla narrativa ─────
// D-R.I-2 firmado · reusa cifras canonical (NO redundancia · ANCLA).
function _composeEvidenciaCriticaV2(ctx) {
  if (!ctx) return "";
  const cs = ctx.cross_signals || {};
  const inv = ctx.inventario || {};
  const evid = [];
  if (cs.margin_pressure && typeof cs.margin_pressure.valor_recuperable_K === "number") {
    evid.push("Recuperable mensual " + _fmtMoneyK(cs.margin_pressure.valor_recuperable_K) +
              " en " + (cs.margin_pressure.instances_count || 0) + " cuentas con carga sobre benchmark");
  }
  if (typeof inv.capitalAtrapado === "number" && typeof inv.capitalPctAtrapado === "number") {
    evid.push("Capital atrapado " + _fmtMoneyK(_capEscalaK(inv.capitalAtrapado)) +
              " (" + inv.capitalPctAtrapado + "% del portafolio)");
  }
  if (cs.customer_dependency && typeof cs.customer_dependency.top3_participacion_pct === "number") {
    evid.push("concentración Tier 1: " + cs.customer_dependency.top3_participacion_pct +
              "% del volumen en 3 cuentas");
  }
  if (evid.length === 0) return "";
  return "**Evidencia crítica**\n" + evid.join(" · ") + ".";
}

// ── 3 · Lo que cambió · Delta Comparator narrative (regla 4 manifiesto) ────
function _composeLoQueCambioV2(deltaResult) {
  if (!deltaResult || !deltaResult.narrative) return "";
  return "**Lo que cambió**\n" + _stripTrailingDot(deltaResult.narrative) + ".";
}

// ── 4 · Mecánica económica · R.C composeCausalChain × 2 drivers ────────────
// Bug 1 mitigado · usa .narrative_assembled (no .statement/.narrative).
function _composeMecanicaEconomicaV2(pattern, ctx) {
  if (!pattern || !pattern.primary_pattern || !ctx) return "";
  const drivers_top = (pattern.primary_pattern.drivers_involved || []).slice(0, 2);
  if (drivers_top.length === 0) return "";
  const chains = drivers_top
    .map(d => composeCausalChain(d, ctx))
    .filter(c => c && c.narrative_assembled);
  if (chains.length === 0) return "";
  const texts = chains.map(c => _stripTrailingDot(c.narrative_assembled));
  return "**Mecánica económica**\n" + texts.join(". ") + ".";
}

// ── 5 · Impacto económico · Q.B valorizationEngine forward ─────────────────
// Bug 2 mitigado · usa .yearly.base_target_3_5_K (no .annual.anual_100).
function _composeImpactoEconomicoV2(valorization) {
  if (!valorization || !valorization.available) return "";
  const monthly_K = (valorization.monthly && valorization.monthly.base_target_3_5_K) || 0;
  const yearly_K = (valorization.yearly && valorization.yearly.base_target_3_5_K) || 0;
  if (monthly_K === 0 && yearly_K === 0) return "";
  return "**Impacto económico**\nValorización forward · target benchmark 3.5% libera " +
         _fmtMoneyK(monthly_K) + " mensual · proyección anual " + _fmtMoneyK(yearly_K) + ".";
}

// ── 6 · Prioridad ejecutiva · R.G top-3 acciones priorizadas ───────────────
function _composePrioridadEjecutivaV2(prioritized) {
  if (!prioritized || !Array.isArray(prioritized.prioritized_recommendations) ||
      prioritized.prioritized_recommendations.length === 0) return "";
  const top = prioritized.prioritized_recommendations.slice(0, 3);
  const lines = top.map((r, i) => (i + 1) + ". " + _stripTrailingDot(r.action_text));
  return "**Prioridad ejecutiva**\n" + lines.join("\n");
}

// ── 7 · Confianza · R.D footer cursiva ──────────────────────────────────────
// RI18 · formato distintivo "*Confianza X · Y.*" (cursiva markdown).
function _composeConfianzaFooterV2(confidence) {
  if (!confidence || !confidence.level || !confidence.reasoning) return "";
  return "*Confianza " + confidence.level + " · " + _stripTrailingDot(confidence.reasoning) + ".*";
}

// ── 8 · Pregunta sugerida · R.H 1 pregunta estratégica cierre ──────────────
// RI19 · pregunta inicia con "¿" (validado upstream R.H · catálogo 18/18).
function _composePreguntaSugeridaV2(questions) {
  if (!questions || !Array.isArray(questions.questions) || questions.questions.length === 0) return "";
  return "**Pregunta sugerida**\n" + questions.questions[0];
}

// ── composeExecutiveReportV2 · función pública R.I · MAIN ENTRY ───────────
// Orquestador pipeline · invoca cada pieza LOCKED · compone 8 elementos manifiesto.
//
// Pipeline:
//   ctx ← crossDomainAggregator(scenarioId)
//   tension ← detectEconomicTension(scenarioId, ctx)               (R.B)
//   pattern ← detectBusinessPattern(scenarioId, ctx)               (R.F)
//   delta ← _composeDeltaTemporal(scenarioId, ctx)                 (NUEVO regla 4)
//   valorization ← valorizationEngine(scenarioId)                  (Q.B)
//   prioritized ← prioritizeRecommendations(scenarioId, ctx)       (R.G · encapsula R.F+R.E+R.D)
//   confidence ← assessConfidence(scenarioId, drivers, ctx)        (R.D)
//   questions ← generateQuestions(scenarioId, ctx, { n: 1 })       (R.H)
//
// Output:
//   {
//     available: boolean,
//     scenarioId,
//     elements: [string × 8 · skip silencioso si pieza null],
//     elements_rendered_count: number,
//     elements_skipped_count: number,
//     meta: { tension_id, pattern_id, confidence_level, delta_count, ... }
//   }
//
// Honest fallback:
//   · Flag OFF / scenarioId inválido / ctx ausente → null
//   · Per-elemento · skip silencioso (D-R.I-4 firmado)
function composeExecutiveReportV2(scenarioId, ctx, options) {
  if (!VOICE_NARRATIVE_V2_ENABLED) return null;
  if (typeof scenarioId !== "string") return null;
  options = options || {};
  // Compute ctx defensivamente
  const evalCtx = ctx || crossDomainAggregator(scenarioId);
  if (!evalCtx || !evalCtx.cross_signals) return null;
  // Pipeline invocación piezas LOCKED
  let tension = null, pattern = null, delta = null, valorization = null;
  let prioritized = null, confidence = null, questions = null;
  try { tension      = detectEconomicTension(scenarioId, evalCtx); } catch (e) { tension = null; }
  try { pattern      = detectBusinessPattern(scenarioId, evalCtx); } catch (e) { pattern = null; }
  try { delta        = _composeDeltaTemporal(scenarioId, evalCtx); } catch (e) { delta = null; }
  try { valorization = valorizationEngine(scenarioId); } catch (e) { valorization = null; }
  try { prioritized  = prioritizeRecommendations(scenarioId, evalCtx); } catch (e) { prioritized = null; }
  const drivers_for_conf = (pattern && pattern.primary_pattern) ? pattern.primary_pattern.drivers_involved : [];
  try { confidence   = assessConfidence(scenarioId, drivers_for_conf, evalCtx); } catch (e) { confidence = null; }
  try { questions    = generateQuestions(scenarioId, evalCtx, { n: 1 }); } catch (e) { questions = null; }
  // Componer 8 elementos · D-R.I-7 orden: 1 → 2 → 3(Lo que cambió) → 4 → 5 → 6 → 7 → 8
  const elements_raw = [
    _composeTesisEjecutivaV2(tension, pattern),       // #1
    _composeEvidenciaCriticaV2(evalCtx),               // #2
    _composeLoQueCambioV2(delta),                      // #3 (entre #2 y #4 · D-R.I-7)
    _composeMecanicaEconomicaV2(pattern, evalCtx),     // #4
    _composeImpactoEconomicoV2(valorization),          // #5
    _composePrioridadEjecutivaV2(prioritized),         // #6
    _composeConfianzaFooterV2(confidence),             // #7 footer cursiva
    _composePreguntaSugeridaV2(questions),             // #8
  ];
  // D-R.I-4 · skip silencioso · solo elementos no-vacíos
  const elements = elements_raw.filter(s => typeof s === "string" && s.length > 0);
  const elements_skipped_count = elements_raw.length - elements.length;
  return {
    available: elements.length > 0,
    scenarioId,
    elements,
    elements_rendered_count: elements.length,
    elements_skipped_count,
    meta: {
      scenarioId,
      tension_id: tension && tension.primary_tension ? tension.primary_tension.id : null,
      pattern_id: pattern && pattern.primary_pattern ? pattern.primary_pattern.id : null,
      confidence_level: confidence ? confidence.level : null,
      delta_count: delta ? delta.deltas_detected.length : 0,
      valorization_available: valorization ? valorization.available : false,
      prioritized_count: prioritized ? prioritized.prioritized_recommendations.length : 0,
      questions_count: questions ? questions.questions.length : 0,
    },
  };
}

// ── composeExecutiveReportV2Narrative · text user-facing pipeline B ───────
// Convierte shape estructurado en text narrativo · compatible pipeline B dispatch.
// Separator "\n\n" entre elementos (D-R.I-3 firmado · convención motor ALPHA).
function composeExecutiveReportV2Narrative(reportV2) {
  if (!reportV2 || !reportV2.available) return null;
  const opener = (reportV2.elements || []).join("\n\n");
  return {
    opener,
    suggestions: [],                              // alineado con Q.D V1 · MVP sin suggestions
    sentrixAction: null,
    reasoningPattern: "executive_report_v2",
    narrative_signals: {
      kind: "executive_report_v2",
      scenario: reportV2.scenarioId,
      n_elements: reportV2.elements_rendered_count,
      n_skipped: reportV2.elements_skipped_count,
      tension_id: reportV2.meta ? reportV2.meta.tension_id : null,
      pattern_id: reportV2.meta ? reportV2.meta.pattern_id : null,
      delta_count: reportV2.meta ? reportV2.meta.delta_count : 0,
    },
  };
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF R · R.I · NARRATIVE ENGINE V2 + DELTA COMPARATOR
// (R.J Suite final + V_VISUAL 18 queries siguiente)
// ════════════════════════════════════════════════════════════════════════════


// ════════════════════════════════════════════════════════════════════════════
// BRIEF S · S.A · ENTITY REGISTRY ENGINE  (⭐⭐⭐ SHARED CORE · CROSS-BRIEF)
//
// Estructura canónica de entidades del negocio · cross-BRIEF · extensible.
// NO solo para BRIEF S · sino para U/W/T/V futuros que consumirán esta API.
//
// 🚨 SHARED CORE · NO feature comercial · infraestructura.
//    Aliases NO existen en datasets · derivación automática determinística MVP
//    (D-S.A-1 firmado · exact match · no fuzzy · evita false positives).
//
// Manifiesto fundacional S · esta pieza respalda:
//   · "recuerda el negocio" → identidad canónica cross-sesión
//   · base para S.B Memory Store · S.D Snapshots · S.E Comparator
//
// Decisiones aplicadas (founder firmado):
//   · D-S-2-REFACTOR · wrapper persistencia híbrido (window.storage · localStorage · in-memory)
//   · D-S.A-1 · A · aliases derivación automática (exact match · no fuzzy)
//   · D-S.A-2 · A · product_family auto-derivada de sfamilia runtime
//   · D-S.A-3 · A · initialization eager IIFE
//   · D-S.A-4 · A · índices precomputed
//   · D-S.A-5 · C · hybrid persistence (reinit estructura + persist metadata)
//   · D-S.A-6 · A · kind prefix en id resuelve conflicto canonical_name cross-kind
//
// Lecciones aplicadas:
//   · #L-ENTITY-REGISTRY-ES-SHARED-CORE-INFRAESTRUCTURA-NO-FEATURE-COMERCIAL
//   · #L-EXACT-MATCH-EN-ALIASES-PREVIENE-FALSE-POSITIVES-NO-FUZZY-MATCH
//   · #L-KIND-PREFIX-EN-ID-RESUELVE-CONFLICTO-CANONICAL-NAME-CROSS-KIND
//   · #L-WINDOW-STORAGE-ASYNC-LOCAL-STORAGE-SYNC-WRAPPER-HOMOGENIZA-ASYNC
//   · #L-CONSULTA-IN-MEMORY-SYNC-INIT-PERSIST-ASYNC-DISEÑO-CORRECTO-CROSS-MODE-STORAGE
//   · #L-PERSISTENCIA-HYBRID-ESTRUCTURA-DERIVADA-METADATA-ACUMULATIVA-CORRECTO-CROSS-BRIEF
//
// Deudas registradas:
//   · #D-ALIASES-MANUALES-OVERRIDE-POST-MVP-SI-FOUNDER-PIDE-EXPLICITO
//   · #D-COMPETITOR-KIND-NO-MVP-EXTENSION-POST-MVP-SI-DATASET-AGREGA-DATOS
// ════════════════════════════════════════════════════════════════════════════

// Flag rollback granular S.A.
const VOICE_ENTITY_REGISTRY_ENABLED = true;

// KIND_REGISTRY · 5 kinds MVP · extensible BRIEFs futuros (U/W/T/V).
//   · client          · 13 entidades · desde clientesVentas runtime
//   · sku             · 13 entidades · desde skuInventario runtime
//   · brand           · 5 entidades · marcas únicas (4 clientes + Makita SKU-only)
//   · product_family  · 4 entidades · sfamilia únicas (D-S.A-2 firmado · auto-derivada)
//   · channel         · 2 entidades · Retail + E-commerce
// Total: 37 entidades inicializables runtime (cross-3 escenarios IDÉNTICAS).
// NO MVP · "competitor" (#D-COMPETITOR-KIND-NO-MVP) · extensión post-MVP.
const KIND_REGISTRY = [
  "client",
  "sku",
  "brand",
  "product_family",
  "channel",
];

// ── _storage · wrapper persistencia con feature detection (D-S-2-REFACTOR) ──
// API uniforme async cross-mode:
//   · window_storage (artifact Claude.ai · proprietary async key-value)
//   · local_storage  (build local Vite/CRA · sync wrapped en async)
//   · in_memory      (fallback degradado · session-only · no persistente)
// Tracking storageMode expuesto vía getStorageMode() para transparencia founder.
const _storage = (function _detectStorage() {
  // Caso A · Artifact Claude.ai · window.storage proprietary API
  if (typeof window !== "undefined" && window.storage && typeof window.storage.get === "function") {
    return {
      mode: "window_storage",
      is_persistent: true,
      get: async function (key) {
        try { const r = await window.storage.get(key); return r ? r.value : null; }
        catch (e) { return null; }
      },
      set: async function (key, value) {
        try { await window.storage.set(key, value); return true; }
        catch (e) { return false; }
      },
      list: async function (prefix) {
        try { const r = await window.storage.list(prefix); return r ? r.keys : []; }
        catch (e) { return []; }
      },
      del: async function (key) {
        try { await window.storage.delete(key); return true; }
        catch (e) { return false; }
      },
    };
  }
  // Caso B · build local · localStorage estándar (sync · wrap en async)
  if (typeof localStorage !== "undefined") {
    return {
      mode: "local_storage",
      is_persistent: true,
      get: async function (key) {
        try { return localStorage.getItem(key); }
        catch (e) { return null; }
      },
      set: async function (key, value) {
        try {
          const v = typeof value === "string" ? value : JSON.stringify(value);
          localStorage.setItem(key, v); return true;
        } catch (e) { return false; }
      },
      list: async function (prefix) {
        try { return Object.keys(localStorage).filter(k => k.startsWith(prefix || "")); }
        catch (e) { return []; }
      },
      del: async function (key) {
        try { localStorage.removeItem(key); return true; }
        catch (e) { return false; }
      },
    };
  }
  // Caso C · fallback in-memory degradado · session-only
  const _mem = {};
  return {
    mode: "in_memory",
    is_persistent: false,
    get: async function (key) { return _mem[key] != null ? _mem[key] : null; },
    set: async function (key, value) { _mem[key] = value; return true; },
    list: async function (prefix) { return Object.keys(_mem).filter(k => k.startsWith(prefix || "")); },
    del: async function (key) { delete _mem[key]; return true; },
  };
})();

// ── _normalizeAlias · helper privado · normalización determinística ─────────
// Lowercase + trim + sin-acentos. Base para exact match en index by_alias.
// EXACT MATCH only (D-S.A-1 firmado) · NO fuzzy · evita false positives.
function _normalizeAlias(text) {
  if (text == null) return "";
  return String(text)
    .toLowerCase()
    .trim()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

// ── _generateAliases · helper privado · derivación automática ───────────────
// Genera aliases determinísticos desde canonical_name. NO usa fuzzy · NO LLM.
// Ejemplo runtime:
//   _generateAliases("Falabella") → ["Falabella","falabella","falabella"]
//   _generateAliases("Mercado Libre") → ["Mercado Libre","mercado libre","mercado libre","mercado","libre"]
//   _generateAliases("LG-DRYER8KG") → ["LG-DRYER8KG","lg-dryer8kg","lg-dryer8kg"]
// Deduplicación via Set. Trim sufijos legales (S.A./Ltda) defensive.
function _generateAliases(canonical_name) {
  if (typeof canonical_name !== "string" || canonical_name.length === 0) return [];
  const out = new Set();
  out.add(canonical_name);
  out.add(canonical_name.toLowerCase());
  const norm = _normalizeAlias(canonical_name);
  out.add(norm);
  // Trim sufijos legales (defensive · datasets actuales NO los tienen)
  const trimmed = norm.replace(/\s+(s\.a\.|ltda|sa|sociedad)$/i, "").trim();
  if (trimmed.length > 0 && trimmed !== norm) out.add(trimmed);
  // Multi-word: agregar palabras individuales si len > 1 word (ej "Mercado Libre" → ["mercado", "libre"])
  const words = norm.split(/\s+/);
  if (words.length > 1) {
    for (const w of words) {
      if (w.length >= 4) out.add(w);
    }
  }
  return Array.from(out);
}

// ── _buildEntityId · helper privado · kind prefix + canonical normalized ───
// D-S.A-6 firmado · kind prefix en id resuelve conflicto canonical_name cross-kind.
// Ejemplo runtime:
//   _buildEntityId("client", "Falabella") → "client_falabella"
//   _buildEntityId("sku", "LG-DRYER8KG") → "sku_lg_dryer8kg"
//   _buildEntityId("brand", "Samsung") → "brand_samsung"
function _buildEntityId(kind, canonical_name) {
  if (typeof kind !== "string" || typeof canonical_name !== "string") return null;
  const norm = _normalizeAlias(canonical_name)
    .replace(/[^\w-]+/g, "_")
    .replace(/^_+|_+$/g, "");
  return kind + "_" + norm;
}

// ── EntityRegistry · estructura canónica · IIFE eager init (D-S.A-3 firmado) ─
// Inicialización al parse · 37 entidades runtime (cross-3 escenarios IDÉNTICAS).
// Hybrid persistence (D-S.A-5 firmado) · reinit estructura desde datasets cada
// sesión · merge metadata persistida (industry · tier · custom fields).
// Índices precomputed (D-S.A-4 firmado) · O(1) lookups runtime.
const EntityRegistry = (function _initEntityRegistry() {
  if (!VOICE_ENTITY_REGISTRY_ENABLED) {
    return { entities: {}, index: { by_canonical_name: {}, by_alias: {}, by_kind: {} }, meta: { storage_mode: _storage.mode, is_persistent: _storage.is_persistent } };
  }
  // Defensive · datasets pueden no estar definidos en harness · graceful empty
  const _clientes = (typeof clientesVentas !== "undefined" && Array.isArray(clientesVentas)) ? clientesVentas : [];
  const _skus = (typeof skuInventario !== "undefined" && Array.isArray(skuInventario)) ? skuInventario : [];
  const entities = {};
  const idx_canonical = {};
  const idx_alias = {};
  const idx_kind = { client: [], sku: [], brand: [], product_family: [], channel: [] };
  const _now = "2026-05-26T00:00:00Z"; // determinístico (NO Date.now · evita fuga determinismo)
  // Helper · registrar entidad
  function _addEntity(kind, canonical_name, metadata) {
    if (!canonical_name || !kind) return;
    const id = _buildEntityId(kind, canonical_name);
    if (!id || entities[id]) return; // idempotente
    const aliases = _generateAliases(canonical_name);
    entities[id] = {
      id,
      kind,
      canonical_name,
      aliases,
      created_at: _now,
      last_seen: _now,
      metadata: metadata || {},
    };
    idx_canonical[canonical_name] = id;
    for (const a of aliases) {
      const norm = _normalizeAlias(a);
      if (norm.length > 0 && !idx_alias[norm]) idx_alias[norm] = id;
    }
    if (idx_kind[kind]) idx_kind[kind].push(id);
  }
  // ── Inicialización runtime · 5 kinds ──
  // 1 · client (13 entidades · desde clientesVentas)
  const _seen_clients = new Set();
  for (const c of _clientes) {
    if (!c || !c.nombre || _seen_clients.has(c.nombre)) continue;
    _seen_clients.add(c.nombre);
    _addEntity("client", c.nombre, {
      tier: null,
      industry: null,
      canal: c.canal || null,
      sfamilia: c.sfamilia || null,
      marca: c.marca || null,
    });
  }
  // 2 · sku (13 entidades · desde skuInventario)
  const _seen_skus = new Set();
  for (const s of _skus) {
    if (!s || !s.sku || _seen_skus.has(s.sku)) continue;
    _seen_skus.add(s.sku);
    _addEntity("sku", s.sku, {
      marca: s.marca || null,
      sfamilia: s.sfamilia || null,
      bodega: s.bodega || null,
    });
  }
  // 3 · brand (5 entidades · marcas únicas client + sku)
  const _seen_brands = new Set();
  for (const c of _clientes) { if (c && c.marca) _seen_brands.add(c.marca); }
  for (const s of _skus)     { if (s && s.marca) _seen_brands.add(s.marca); }
  for (const brand of _seen_brands) _addEntity("brand", brand, {});
  // 4 · product_family (4 entidades · sfamilia únicas)
  const _seen_sfam = new Set();
  for (const c of _clientes) { if (c && c.sfamilia) _seen_sfam.add(c.sfamilia); }
  for (const s of _skus)     { if (s && s.sfamilia) _seen_sfam.add(s.sfamilia); }
  for (const sfam of _seen_sfam) _addEntity("product_family", sfam, {});
  // 5 · channel (2 entidades · Retail + E-commerce)
  const _seen_ch = new Set();
  for (const c of _clientes) { if (c && c.canal) _seen_ch.add(c.canal); }
  for (const ch of _seen_ch) _addEntity("channel", ch, {});
  return {
    schema_version: "S.A.v1",
    initialized_at: _now,
    entities,
    index: {
      by_canonical_name: idx_canonical,
      by_alias: idx_alias,
      by_kind: idx_kind,
    },
    meta: {
      storage_mode: _storage.mode,
      is_persistent: _storage.is_persistent,
      total_entities: Object.keys(entities).length,
    },
  };
})();

// ── resolveEntity · función pública · resolución sync por alias ──────────────
// Exact match en index by_alias (lowercase + trim + sin-acentos).
// D-S.A-1 firmado · NO fuzzy · evita false positives ("LG" no matchea "Lider").
// Retorna entity object o null (honest fallback si no catalogada).
//
// Ejemplos runtime:
//   resolveEntity("Falabella") → { id: "client_falabella", kind: "client", ... }
//   resolveEntity("falabella retail") → null (alias no catalogado · #D-ALIASES-MANUALES-OVERRIDE-POST-MVP)
//   resolveEntity("FALA") → null (alias no catalogado · solo {canonical, lowercase, normalized})
//   resolveEntity("Mercado Libre") → entity (multi-word incluido en aliases)
//   resolveEntity("inexistente") → null honest
function resolveEntity(text) {
  if (!VOICE_ENTITY_REGISTRY_ENABLED) return null;
  if (typeof text !== "string") return null;
  const norm = _normalizeAlias(text);
  if (norm.length === 0) return null;
  const id = EntityRegistry.index.by_alias[norm];
  if (!id) return null;
  return EntityRegistry.entities[id] || null;
}

// ── registerEntity · función pública · idempotente · kind prefix en id ──────
// Si entity con mismo kind+canonical_name existe → retorna existente.
// Si NO existe → registra y retorna nueva. D-S.A-6 firmado.
function registerEntity(spec) {
  if (!VOICE_ENTITY_REGISTRY_ENABLED) return null;
  if (!spec || typeof spec !== "object") return null;
  const { kind, canonical_name, metadata } = spec;
  if (typeof kind !== "string" || typeof canonical_name !== "string") return null;
  if (!KIND_REGISTRY.includes(kind)) return null;
  const id = _buildEntityId(kind, canonical_name);
  if (!id) return null;
  // Idempotente · si existe retorna sin modificar
  if (EntityRegistry.entities[id]) return EntityRegistry.entities[id];
  const aliases = _generateAliases(canonical_name);
  const _now = "2026-05-26T00:00:00Z";
  const entity = {
    id,
    kind,
    canonical_name,
    aliases,
    created_at: _now,
    last_seen: _now,
    metadata: metadata || {},
  };
  EntityRegistry.entities[id] = entity;
  EntityRegistry.index.by_canonical_name[canonical_name] = id;
  for (const a of aliases) {
    const norm = _normalizeAlias(a);
    if (norm.length > 0 && !EntityRegistry.index.by_alias[norm]) {
      EntityRegistry.index.by_alias[norm] = id;
    }
  }
  if (EntityRegistry.index.by_kind[kind]) {
    EntityRegistry.index.by_kind[kind].push(id);
  }
  EntityRegistry.meta.total_entities = Object.keys(EntityRegistry.entities).length;
  return entity;
}

// ── getEntityById · función pública · lookup directo by id ──────────────────
function getEntityById(id) {
  if (!VOICE_ENTITY_REGISTRY_ENABLED) return null;
  if (typeof id !== "string") return null;
  return EntityRegistry.entities[id] || null;
}

// ── getEntitiesByKind · función pública · agrupados por kind ────────────────
function getEntitiesByKind(kind) {
  if (!VOICE_ENTITY_REGISTRY_ENABLED) return [];
  if (typeof kind !== "string") return [];
  const ids = EntityRegistry.index.by_kind[kind] || [];
  return ids.map(id => EntityRegistry.entities[id]).filter(Boolean);
}

// ── updateEntityMetadata · función pública · merge patch + timestamp ────────
// Preserva otras fields · solo merge en metadata. Actualiza last_seen.
// Hybrid persistence (D-S.A-5) · metadata acumulada cross-sesión vía _storage
// (persist async fuera del API sync de esta función).
function updateEntityMetadata(id, patch) {
  if (!VOICE_ENTITY_REGISTRY_ENABLED) return null;
  if (typeof id !== "string" || !patch || typeof patch !== "object") return null;
  const entity = EntityRegistry.entities[id];
  if (!entity) return null;
  entity.metadata = Object.assign({}, entity.metadata, patch);
  entity.last_seen = "2026-05-26T00:00:00Z"; // determinístico
  return entity;
}

// ── listEntities · función pública · filter opcional ────────────────────────
// Sin filter: retorna todas las entidades.
// Con filter { kind, alias_match }: aplica.
function listEntities(filter) {
  if (!VOICE_ENTITY_REGISTRY_ENABLED) return [];
  const all = Object.values(EntityRegistry.entities);
  if (!filter || typeof filter !== "object") return all;
  let out = all;
  if (filter.kind && typeof filter.kind === "string") {
    out = out.filter(e => e.kind === filter.kind);
  }
  if (filter.alias_match && typeof filter.alias_match === "string") {
    const norm = _normalizeAlias(filter.alias_match);
    out = out.filter(e => e.aliases.some(a => _normalizeAlias(a).includes(norm)));
  }
  return out;
}

// ── getStorageMode · función pública · transparencia founder ────────────────
// Retorna modo actual del wrapper _storage:
//   "window_storage" (artifact Claude.ai)
//   "local_storage"  (build local Vite/CRA)
//   "in_memory"      (fallback degradado · session-only)
function getStorageMode() {
  return _storage.mode;
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF S · S.A · ENTITY REGISTRY ENGINE
// (S.B Memory Store Engine siguiente · pre-flight aparte)
// ════════════════════════════════════════════════════════════════════════════


// ════════════════════════════════════════════════════════════════════════════
// BRIEF S · S.B · MEMORY STORE ENGINE  (PURE STORE · API pública async-aware)
//
// Estructura persistente cross-sesión que guarda conversaciones + insights.
// PURE STORE · S.B NO captura runtime React automáticamente · S.G (Auto Delta
// Integrator) invocará logEvent desde su flujo. Cero touch a runReasoningEngine
// + detectIntent + composeExecutiveReportV2 + PanelADI (BRIEF R LOCKED).
//
// Manifiesto fundacional S · esta pieza respalda:
//   · "qué pasó" → conversaciones persistidas cross-sesión
//   · "qué dijimos" → events queryables por S.F Recall Narrative
//
// Decisiones aplicadas (founder firmado · 6 decisiones):
//   · D-S.B-1 · A · todo persistido (events + summary · S.F necesita events)
//   · D-S.B-2 · A · memoria infinita MVP + deuda auto-cleanup post-MVP
//   · D-S.B-3 · A · log everything · S.F filtra al componer (store vs consumer)
//   · D-S.B-4 · D · hybrid end-of-session (page-load nueva + timeout 30min)
//   · D-S.B-5 · C · MVP solo v1 · deuda framework migration post-MVP
//   · D-S.B-6 · C · hybrid entities_referenced (default auto · override manual)
//
// Mitigación pre-implementación · R-S.B-4 seq counter persistence:
//   seq counter PERSISTIDO cross-page-load via MemoryStore.meta.seq_counters
//   (mapa "scenarioId_YYYYMMDD" → integer). Evita collision si founder carga
//   runtime React 2 veces el mismo día con mismo escenario.
//
// Lecciones aplicadas:
//   · #L-S-F-RECALL-NARRATIVE-REQUIERE-EVENTS-PERSISTIDOS-NO-SOLO-SUMMARIES
//   · #L-MEMORIA-ES-STORE-NARRATIVA-ES-CONSUMER-SEPARACION-ARQUITECTONICA-LIMPIA
//   · #L-CONVENIENCE-DEFAULT-FLEXIBILITY-OVERRIDE-PATRON-ARQUITECTONICO-CORRECTO
//   · #L-EJECUTOR-FILTRO-3-CAPTURA-SEQ-COUNTER-PERSISTENCE-PRE-IMPLEMENTACION-EVITA-COLLISION
//   · #L-FILTRO-3-EJECUTOR-CAPTURA-BUGS-FUTUROS-QUE-ARQUITECTO-NO-VE-EN-DOCUMENTO
//
// Deudas registradas:
//   · #D-AUTO-CLEANUP-OLD-SESSIONS-POST-MVP-SI-EMERGE-PRESION-STORAGE
//   · #D-SCHEMA-MIGRATION-FRAMEWORK-POST-MVP-SI-S-EVOLUCIONA-V2-PLUS
// ════════════════════════════════════════════════════════════════════════════

// Flag rollback granular S.B.
const VOICE_MEMORY_STORE_ENABLED = true;

// Schema version actual. D-S.B-5 firmado · MVP solo v1 · sin migration framework.
const _MEMORY_STORE_SCHEMA_VERSION = "S.B.v1";

// Session timeout · 30 min sin events → endSession implícito al próximo startSession.
// D-S.B-4 firmado · hybrid (page-load nueva + timeout 30min).
const _SESSION_TIMEOUT_MS = 30 * 60 * 1000;

// Storage key · namespace S.B en wrapper _storage (cross-mode: window_storage / localStorage / in_memory).
const _MEMORY_STORE_KEY = "adi_memory_store_s_b_v1";

// ── _isoNow · timestamp ISO determinístico ───────────────────────────────────
// MVP: timestamp fijo determinístico para evitar fuga de Date.now() cruda.
// Runtime React: founder puede sobrescribir con Date real si necesita (post-MVP).
// Determinismo permite bitwise tests cross-init.
function _isoNow() {
  return "2026-05-26T00:00:00Z";
}

// ── _generateSessionId · hash determinístico ────────────────────────────────
// Shape: ses_<scenarioId>_<YYYYMMDD>_<base36_hash>
// Hash determinístico de (scenarioId + isoDate + seq) · no random · D-S.B-4 mitigación
// seq counter persistido cross-page-load (R-S.B-4) vía MemoryStore.meta.seq_counters.
//
// Ejemplos runtime:
//   _generateSessionId("bonanza", "2026-05-26T10:00:00Z", 1)
//     → "ses_bonanza_20260526_xzlv5o"
//   _generateSessionId("bonanza", "2026-05-26T10:00:00Z", 1) (mismo input)
//     → "ses_bonanza_20260526_xzlv5o" (idéntico)
//   _generateSessionId("bonanza", "2026-05-26T10:00:00Z", 2)
//     → "ses_bonanza_20260526_xzlv5n" (distinto seq)
function _generateSessionId(scenarioId, isoDate, seq) {
  if (typeof scenarioId !== "string" || typeof isoDate !== "string") return null;
  const seqNum = (typeof seq === "number" && isFinite(seq)) ? seq : 1;
  const input = scenarioId + ":" + isoDate + ":" + seqNum;
  let h = 0;
  for (let i = 0; i < input.length; i++) h = (h * 31 + input.charCodeAt(i)) | 0;
  const dateKey = isoDate.slice(0, 10).replace(/-/g, "");
  return "ses_" + scenarioId + "_" + dateKey + "_" + Math.abs(h).toString(36);
}

// ── _extractEntitiesFromText · 1/2/3-gram + resolveEntity (S.A) ─────────────
// Consume S.A API pública sync. Cero acoplamiento beyond resolveEntity.
// Devuelve array de entity_ids (sin duplicados · sin nulls).
//
// Ejemplos runtime (con S.A LOCKED · 37 entidades):
//   _extractEntitiesFromText("perfil de Falabella") → ["client_falabella"]
//   _extractEntitiesFromText("Falabella y Lider") → ["client_falabella","client_lider"]
//   _extractEntitiesFromText("Mercado Libre crece") → ["client_mercado_libre"]
//   _extractEntitiesFromText("Samsung y LG") → ["brand_samsung","brand_lg"]
//   _extractEntitiesFromText("hola") → []
//   _extractEntitiesFromText("la capital de Francia") → [] honest empty
function _extractEntitiesFromText(text) {
  if (typeof text !== "string" || text.length === 0) return [];
  if (typeof resolveEntity !== "function") return []; // defensive · S.A debe estar cargado
  const found = new Set();
  const norm = _normalizeAlias(text);
  const tokens = norm.split(/[\s,.;:!?()]+/).filter(t => t.length > 0);
  // 1-grams
  for (const tok of tokens) {
    const e = resolveEntity(tok);
    if (e) found.add(e.id);
  }
  // 2-grams + 3-grams (para "Mercado Libre" · "La Polar")
  for (let i = 0; i < tokens.length - 1; i++) {
    const bigram = tokens[i] + " " + tokens[i + 1];
    const e2 = resolveEntity(bigram);
    if (e2) found.add(e2.id);
    if (i < tokens.length - 2) {
      const trigram = bigram + " " + tokens[i + 2];
      const e3 = resolveEntity(trigram);
      if (e3) found.add(e3.id);
    }
  }
  return Array.from(found);
}

// ── _updateIndices · helper privado · indices precomputed runtime ───────────
// Mantiene index.by_entity · by_pattern · by_date · by_scenario actualizados.
function _updateIndices(store, session) {
  if (!session || !session.session_id) return;
  const sid = session.session_id;
  // by_date
  if (session.started_at) {
    const dateKey = session.started_at.slice(0, 10);
    if (!store.index.by_date[dateKey]) store.index.by_date[dateKey] = [];
    if (!store.index.by_date[dateKey].includes(sid)) store.index.by_date[dateKey].push(sid);
  }
  // by_scenario
  if (session.scenarioId) {
    if (!store.index.by_scenario[session.scenarioId]) store.index.by_scenario[session.scenarioId] = [];
    if (!store.index.by_scenario[session.scenarioId].includes(sid)) store.index.by_scenario[session.scenarioId].push(sid);
  }
  // by_entity + by_pattern desde events
  if (Array.isArray(session.events)) {
    for (const ev of session.events) {
      if (Array.isArray(ev.entities_referenced)) {
        for (const eid of ev.entities_referenced) {
          if (!store.index.by_entity[eid]) store.index.by_entity[eid] = [];
          if (!store.index.by_entity[eid].includes(sid)) store.index.by_entity[eid].push(sid);
        }
      }
      if (ev.pattern_id) {
        if (!store.index.by_pattern[ev.pattern_id]) store.index.by_pattern[ev.pattern_id] = [];
        if (!store.index.by_pattern[ev.pattern_id].includes(sid)) store.index.by_pattern[ev.pattern_id].push(sid);
      }
    }
  }
}

// ── MemoryStore · estructura persistente · IIFE eager init ──────────────────
// Init in-memory · load async desde _storage (post-init · best-effort).
// _persistMemoryStore() async vía _storage wrapper · fire-and-forget con console.warn defensivo.
const MemoryStore = (function _initMemoryStore() {
  if (!VOICE_MEMORY_STORE_ENABLED) {
    return {
      schema_version: _MEMORY_STORE_SCHEMA_VERSION,
      initialized_at: _isoNow(),
      sessions: {},
      index: { by_entity: {}, by_pattern: {}, by_date: {}, by_scenario: {} },
      meta: {
        storage_mode: (typeof _storage !== "undefined") ? _storage.mode : "in_memory",
        is_persistent: false,
        total_sessions: 0,
        active_session_id: null,
        seq_counters: {},
      },
    };
  }
  return {
    schema_version: _MEMORY_STORE_SCHEMA_VERSION,
    initialized_at: _isoNow(),
    sessions: {},
    index: { by_entity: {}, by_pattern: {}, by_date: {}, by_scenario: {} },
    meta: {
      storage_mode: (typeof _storage !== "undefined") ? _storage.mode : "in_memory",
      is_persistent: (typeof _storage !== "undefined") ? _storage.is_persistent : false,
      total_sessions: 0,
      active_session_id: null,
      // seq_counters mitigación R-S.B-4 · persistencia cross-page-load
      // Shape: { "bonanza_20260526": 3, "crisis_20260526": 1, ... }
      seq_counters: {},
    },
  };
})();

// ── _persistMemoryStore · async + console.warn defensivo ────────────────────
// Mejora aplicada (founder firmó): console.warn si persist falla · founder
// puede ver runtime React DevTools si memoria NO se persiste.
async function _persistMemoryStore() {
  if (!VOICE_MEMORY_STORE_ENABLED) return false;
  if (typeof _storage === "undefined") return false;
  try {
    const payload = (typeof JSON !== "undefined") ? JSON.stringify(MemoryStore) : MemoryStore;
    await _storage.set(_MEMORY_STORE_KEY, payload);
    return true;
  } catch (e) {
    if (typeof console !== "undefined" && console.warn) {
      console.warn("[S.B] Memory persistence failed · session NOT persisted:", e);
    }
    return false;
  }
}

// ── _loadMemoryStore · async init desde _storage al cargar runtime React ────
// Hybrid persistence (D-S.B-1 firmado): all events + sessions persistidos.
// Si store cargado tiene schema_version compatible → merge a in-memory MemoryStore.
// Si incompatible → log warning + use empty (D-S.B-5 firmado · MVP solo v1).
async function _loadMemoryStore() {
  if (!VOICE_MEMORY_STORE_ENABLED) return false;
  if (typeof _storage === "undefined") return false;
  try {
    const raw = await _storage.get(_MEMORY_STORE_KEY);
    if (!raw) return false;
    const loaded = (typeof raw === "string") ? JSON.parse(raw) : raw;
    if (!loaded || typeof loaded !== "object") return false;
    if (loaded.schema_version !== _MEMORY_STORE_SCHEMA_VERSION) {
      if (typeof console !== "undefined" && console.warn) {
        console.warn("[S.B] Memory schema mismatch · expected " + _MEMORY_STORE_SCHEMA_VERSION + " · got " + loaded.schema_version + " · #D-SCHEMA-MIGRATION-FRAMEWORK-POST-MVP");
      }
      return false;
    }
    // Merge loaded → in-memory MemoryStore (preserve current init meta)
    MemoryStore.sessions = loaded.sessions || {};
    MemoryStore.index = loaded.index || { by_entity: {}, by_pattern: {}, by_date: {}, by_scenario: {} };
    MemoryStore.meta.total_sessions = Object.keys(MemoryStore.sessions).length;
    MemoryStore.meta.seq_counters = (loaded.meta && loaded.meta.seq_counters) || {};
    MemoryStore.meta.active_session_id = (loaded.meta && loaded.meta.active_session_id) || null;
    return true;
  } catch (e) {
    if (typeof console !== "undefined" && console.warn) {
      console.warn("[S.B] Memory load failed:", e);
    }
    return false;
  }
}

// ── startSession · arranca sesión nueva · idempotente ────────────────────────
// D-S.B-4 firmado · hybrid end-of-session: si hay sesión activa, ciérrala
// implícitamente antes de arrancar nueva (page-reload SPA o timeout).
function startSession(scenarioId) {
  if (!VOICE_MEMORY_STORE_ENABLED) return null;
  if (typeof scenarioId !== "string" || scenarioId.length === 0) return null;
  // Cerrar sesión activa previa (defensive · si crash sin endSession)
  if (MemoryStore.meta.active_session_id) {
    const prevSession = MemoryStore.sessions[MemoryStore.meta.active_session_id];
    if (prevSession && !prevSession.ended_at) {
      prevSession.ended_at = _isoNow();
      // summary default · sin override
      prevSession.summary = _computeSummaryFromEvents(prevSession);
    }
  }
  // seq counter persistido cross-page-load (R-S.B-4 mitigación)
  const now = _isoNow();
  const dateKey = now.slice(0, 10).replace(/-/g, "");
  const seqKey = scenarioId + "_" + dateKey;
  const seq = (MemoryStore.meta.seq_counters[seqKey] || 0) + 1;
  MemoryStore.meta.seq_counters[seqKey] = seq;
  const session_id = _generateSessionId(scenarioId, now, seq);
  if (!session_id) return null;
  // Idempotente · si session_id ya existe retorna existente (collision defensive)
  if (MemoryStore.sessions[session_id]) {
    MemoryStore.meta.active_session_id = session_id;
    return session_id;
  }
  const session = {
    session_id,
    scenarioId,
    started_at: now,
    ended_at: null,
    events: [],
    summary: {
      primary_concerns: [],
      primary_drivers: [],
      primary_patterns: [],
      primary_tensions: [],
      entities_focused: [],
      event_count: 0,
      duration_ms: 0,
    },
  };
  MemoryStore.sessions[session_id] = session;
  MemoryStore.meta.active_session_id = session_id;
  MemoryStore.meta.total_sessions = Object.keys(MemoryStore.sessions).length;
  _updateIndices(MemoryStore, session);
  // Persist async fire-and-forget
  if (typeof _persistMemoryStore === "function") { _persistMemoryStore(); }
  return session_id;
}

// ── logEvent · append event a sesión · auto-extracción entities (D-S.B-6 C) ──
// D-S.B-3 firmado · log everything (incluido GREETING/OOD) · S.F filtra al componer.
// D-S.B-6 firmado · hybrid: default auto-extract via _extractEntitiesFromText
// si caller NO provee entities_referenced; override manual si caller lo provee.
function logEvent(session_id, event) {
  if (!VOICE_MEMORY_STORE_ENABLED) return false;
  if (typeof session_id !== "string" || !event || typeof event !== "object") return false;
  const session = MemoryStore.sessions[session_id];
  if (!session) return false;
  if (session.ended_at) return false; // no log a sesión cerrada
  // Enriquecer event con timestamp si no provisto
  const enriched = {
    ts: event.ts || _isoNow(),
    kind: event.kind || "unknown",
  };
  // Copiar fields opcionales
  if (typeof event.text === "string") enriched.text = event.text;
  if (typeof event.composer === "string") enriched.composer = event.composer;
  if (typeof event.intent_type === "string") enriched.intent_type = event.intent_type;
  if (typeof event.pattern_id === "string") enriched.pattern_id = event.pattern_id;
  if (typeof event.tension_id === "string") enriched.tension_id = event.tension_id;
  if (typeof event.confidence === "string") enriched.confidence = event.confidence;
  // entities_referenced hybrid (D-S.B-6 firmado)
  if (Array.isArray(event.entities_referenced)) {
    // Override manual · caller proveyó (ej S.G con report.entities_referenced precomputed)
    enriched.entities_referenced = event.entities_referenced.slice();
  } else if (typeof event.text === "string") {
    // Default auto · _extractEntitiesFromText runtime
    enriched.entities_referenced = _extractEntitiesFromText(event.text);
  } else {
    enriched.entities_referenced = [];
  }
  session.events.push(enriched);
  // Actualizar indices con event nuevo
  _updateIndices(MemoryStore, session);
  // Persist async fire-and-forget
  if (typeof _persistMemoryStore === "function") { _persistMemoryStore(); }
  return true;
}

// ── _computeSummaryFromEvents · helper privado ───────────────────────────────
// Computa summary desde events · agregaciones: patterns, tensions, entities top-N.
function _computeSummaryFromEvents(session) {
  if (!session || !Array.isArray(session.events)) {
    return { primary_concerns: [], primary_drivers: [], primary_patterns: [], primary_tensions: [], entities_focused: [], event_count: 0, duration_ms: 0 };
  }
  const patterns = new Set();
  const tensions = new Set();
  const entityFreq = {};
  for (const ev of session.events) {
    if (ev.pattern_id) patterns.add(ev.pattern_id);
    if (ev.tension_id) tensions.add(ev.tension_id);
    if (Array.isArray(ev.entities_referenced)) {
      for (const eid of ev.entities_referenced) {
        entityFreq[eid] = (entityFreq[eid] || 0) + 1;
      }
    }
  }
  // Top-3 entities por frecuencia
  const sortedEntities = Object.keys(entityFreq).sort((a, b) => entityFreq[b] - entityFreq[a]);
  const top3Entities = sortedEntities.slice(0, 3);
  return {
    primary_concerns: [],
    primary_drivers: [],
    primary_patterns: Array.from(patterns),
    primary_tensions: Array.from(tensions),
    entities_focused: top3Entities,
    event_count: session.events.length,
    duration_ms: 0, // determinístico · _isoNow fijo
  };
}

// ── endSession · cierra sesión + computa summary ─────────────────────────────
// Acepta summary_override opcional para merge sobre summary computed.
function endSession(session_id, summary_override) {
  if (!VOICE_MEMORY_STORE_ENABLED) return null;
  if (typeof session_id !== "string") return null;
  const session = MemoryStore.sessions[session_id];
  if (!session) return null;
  if (session.ended_at) return session; // idempotente · ya cerrada
  session.ended_at = _isoNow();
  const computed = _computeSummaryFromEvents(session);
  if (summary_override && typeof summary_override === "object") {
    session.summary = Object.assign({}, computed, summary_override);
  } else {
    session.summary = computed;
  }
  if (MemoryStore.meta.active_session_id === session_id) {
    MemoryStore.meta.active_session_id = null;
  }
  if (typeof _persistMemoryStore === "function") { _persistMemoryStore(); }
  return session;
}

// ── getSession · lookup directo sync ────────────────────────────────────────
function getSession(session_id) {
  if (!VOICE_MEMORY_STORE_ENABLED) return null;
  if (typeof session_id !== "string") return null;
  return MemoryStore.sessions[session_id] || null;
}

// ── searchSessions · filter sync vía indices precomputed ────────────────────
// Filter opcional: { entity_id, pattern_id, date, scenarioId, since, until }
// Sin filter → retorna todas las sesiones.
function searchSessions(filter) {
  if (!VOICE_MEMORY_STORE_ENABLED) return [];
  const allSessions = Object.values(MemoryStore.sessions);
  if (!filter || typeof filter !== "object") return allSessions;
  let candidate_ids = null;
  // entity_id · usa index O(1)
  if (filter.entity_id && typeof filter.entity_id === "string") {
    candidate_ids = MemoryStore.index.by_entity[filter.entity_id] || [];
  }
  // pattern_id · usa index · intersection si ya hay candidate_ids
  if (filter.pattern_id && typeof filter.pattern_id === "string") {
    const byPattern = MemoryStore.index.by_pattern[filter.pattern_id] || [];
    candidate_ids = (candidate_ids === null) ? byPattern : candidate_ids.filter(id => byPattern.includes(id));
  }
  // date · index O(1)
  if (filter.date && typeof filter.date === "string") {
    const byDate = MemoryStore.index.by_date[filter.date] || [];
    candidate_ids = (candidate_ids === null) ? byDate : candidate_ids.filter(id => byDate.includes(id));
  }
  // scenarioId · index O(1)
  if (filter.scenarioId && typeof filter.scenarioId === "string") {
    const byScenario = MemoryStore.index.by_scenario[filter.scenarioId] || [];
    candidate_ids = (candidate_ids === null) ? byScenario : candidate_ids.filter(id => byScenario.includes(id));
  }
  let out = (candidate_ids === null) ? allSessions : candidate_ids.map(id => MemoryStore.sessions[id]).filter(Boolean);
  // since / until · linear scan post-index
  if (filter.since && typeof filter.since === "string") {
    out = out.filter(s => s.started_at >= filter.since);
  }
  if (filter.until && typeof filter.until === "string") {
    out = out.filter(s => s.started_at <= filter.until);
  }
  return out;
}

// ── getMemoryStoreStats · transparencia founder ─────────────────────────────
function getMemoryStoreStats() {
  return {
    schema_version: MemoryStore.schema_version,
    total_sessions: MemoryStore.meta.total_sessions,
    active_session_id: MemoryStore.meta.active_session_id,
    storage_mode: MemoryStore.meta.storage_mode,
    is_persistent: MemoryStore.meta.is_persistent,
    indexed_entities_count: Object.keys(MemoryStore.index.by_entity).length,
    indexed_patterns_count: Object.keys(MemoryStore.index.by_pattern).length,
  };
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF S · S.B · MEMORY STORE ENGINE
// (S.C Session Continuity Layer siguiente · pre-flight aparte)
// ════════════════════════════════════════════════════════════════════════════


// ════════════════════════════════════════════════════════════════════════════
// BRIEF S · S.C · SESSION CONTINUITY LAYER  (PURE DETECTOR · lookup determinístico)
//
// Detecta cuando founder REFERENCIA conversación previa y resuelve contexto
// runtime React contra Memory Store. Análogo a S.B PURE STORE · S.C es PURE
// DETECTOR. Consumers (S.F Recall Narrative · próxima pieza) invocan según
// necesidad. Cero touch a runReasoningEngine + detectIntent + composeExecutiveReportV2
// + PanelADI + S.A + S.B (todos LOCKED).
//
// Manifiesto fundacional S · esta pieza respalda:
//   · "qué dijimos" → detección referencias conversacionales explícitas
//   · "cada conversación es continuación de la anterior" → enlace S.B histórico
//
// Decisiones aplicadas (founder firmado · 5 decisiones):
//   · D-S.C-1 · A · orden de prioridad catálogo · primer match wins · determinístico
//   · D-S.C-2 · B · objeto con fallback_caveat poblado · honest fallback obligatorio
//   · D-S.C-3 · A · sesión más reciente · sesión activa excluida · evita loop infinito
//   · D-S.C-4 · A · timezone MVP determinístico · deuda post-MVP
//   · D-S.C-5 · A · primer entity match · simpleza MVP · multi-entity post-MVP
//
// Lecciones aplicadas:
//   · #L-ORDEN-CATALOGO-PRIORIDAD-PRIMER-MATCH-WINS-DETERMINISTICO-PREFERIBLE-A-SPECIFICITY-HEURISTICA
//   · #L-FALLBACK-CAVEAT-POBLADO-EN-OBJETO-PERMITE-CONSUMER-COMPONER-NARRATIVA-HONESTA
//   · #L-SESION-MAS-RECIENTE-EXCLUYENDO-ACTIVA-EVITA-RECALL-SELF-LOOP-INFINITO
//   · #L-S-C-PURE-DETECTOR-ANALOGO-A-S-B-PURE-STORE-PATRON-ARQUITECTONICO-EMERGENTE
//   · #L-PATRON-EMERGENTE-S-CAPAS-DATOS-PURAS-DETECTORES-COMPARATORS-CONSUMERS-UTILITIES
//
// Deudas registradas:
//   · #D-TIMEZONE-AWARE-ELAPSED-DAYS-POST-MVP-SI-EMERGE-PROBLEMA-OFF-BY-1
//   · #D-MULTI-ENTITY-CONTINUITY-POST-MVP-SI-FOUNDER-PIDE-EXPLICITO
// ════════════════════════════════════════════════════════════════════════════

// Flag rollback granular S.C.
const VOICE_SESSION_CONTINUITY_ENABLED = true;

// CONTINUITY_PATTERNS · 5 patterns ORDENADOS POR PRIORIDAD (D-S.C-1 firmado).
// Orden = prioridad · primer match wins · determinístico cross-runtime.
// Extensible BRIEFs futuros (W/T agregan patterns post-MVP si emerge necesidad).
//
//   1 · temporal_relative   · "hace X días/semanas/meses" · cuantitativo más específico
//   2 · entity_continuation · "sobre Falabella seguimos" · entity + verbo continuación
//   3 · temporal_anchor     · "el otro día" · referencia sin cantidad explícita
//   4 · topical_reference   · "como te dije" · referencia conversacional
//   5 · plan_followup       · "qué pasó con" · más genérico
const CONTINUITY_PATTERNS = [
  {
    id: "temporal_relative",
    kind: "temporal",
    regex: /hace\s+(\d+|un|una|dos|tres|cuatro|cinco|seis|siete|ocho|nueve|diez)\s+(d[ií]as?|semanas?|meses?|mes)\b/i,
    has_elapsed_days: true,
  },
  {
    id: "entity_continuation",
    kind: "entity",
    regex: /(sobre|de|para|con)\s+\S+.*\b(seguimos|continuamos|qu[eé]\s+pas[oó]|c[oó]mo\s+(va|qued[oó])|actualizaci[oó]n|donde\s+quedamos)/i,
    has_elapsed_days: false,
  },
  {
    id: "temporal_anchor",
    kind: "temporal",
    regex: /(el\s+otro\s+d[ií]a|[uú]ltima\s+vez|el\s+mes\s+pasado|la\s+semana\s+pasada|[uú]ltimo\s+an[aá]lisis)/i,
    has_elapsed_days: false,
  },
  {
    id: "topical_reference",
    kind: "topical",
    regex: /(como\s+te\s+(dije|menci[oó]n[eé]|coment[eé])|cuando\s+(hablamos|conversamos)\s+(de|sobre)|lo\s+que\s+(dijiste|mencionaste|conversamos))/i,
    has_elapsed_days: false,
  },
  {
    id: "plan_followup",
    kind: "plan",
    regex: /(qu[eé]\s+pas[oó]\s+con|actualizaci[oó]n\s+de|c[oó]mo\s+(qued[oó]|va)|seguimos\s+con)/i,
    has_elapsed_days: false,
  },
];

// CONTINUITY_TEMPLATES · narrativas pre-redactadas por kind.
// PURE STRING TEMPLATES · NO LLM · NO generación open-ended.
// Plurales/concordancia gramatical determinística.
const CONTINUITY_TEMPLATES = {
  // Templates con sesión previa resuelta
  entity_with_session:    "La última vez que hablamos de {entity_name} (hace {elapsed_days} días) {previous_topic_phrase}.",
  temporal_with_session:  "Como te mencioné hace {elapsed_days} días{entity_phrase}, {previous_topic_phrase}.",
  topical_with_session:   "Cuando conversamos {topic_phrase}{entity_phrase}, {previous_topic_phrase}.",
  plan_with_session:      "Sobre {entity_or_topic_phrase}{previous_summary_phrase}, te puedo dar un update.",
  // Templates honest fallback · sin sesión previa
  entity_no_session:      "No tengo registro de conversaciones previas sobre {entity_name} · esta es la primera vez que la discutimos.",
  temporal_no_session:    "No tengo registro de una conversación previa hace {elapsed_days} días{entity_phrase}.",
  topical_no_session:     "No tengo registro de una conversación previa{topic_phrase}{entity_phrase}.",
  plan_no_session:        "No tengo registro de un plan previo{entity_phrase}.",
};

// ── _extractElapsedDays · conversión cantidad temporal → días ───────────────
// D-S.C-4 firmado · MVP determinístico · deuda timezone post-MVP.
// Soporta: "hace 30 días" · "hace una semana" · "hace dos meses" · "hace 5 semanas"
// Ejemplos runtime:
//   _extractElapsedDays("hace 30 días", ...) → 30
//   _extractElapsedDays("hace una semana", ...) → 7
//   _extractElapsedDays("hace dos meses", ...) → 60
function _extractElapsedDays(regex_match) {
  if (!regex_match || regex_match.length < 3) return null;
  const qty_raw = regex_match[1];
  const unit = regex_match[2].toLowerCase();
  const wordToNum = { un: 1, una: 1, dos: 2, tres: 3, cuatro: 4, cinco: 5, seis: 6, siete: 7, ocho: 8, nueve: 9, diez: 10 };
  const qty = /^\d+$/.test(qty_raw) ? parseInt(qty_raw, 10) : (wordToNum[qty_raw.toLowerCase()] || null);
  if (qty == null) return null;
  if (unit.startsWith("seman")) return qty * 7;
  if (unit.startsWith("mes")) return qty * 30;
  return qty; // días
}

// ── _selectMostRecentSession · sort desc + exclude active ───────────────────
// D-S.C-3 firmado · sesión más reciente · activa excluida · evita loop infinito.
function _selectMostRecentSession(sessions) {
  if (!Array.isArray(sessions) || sessions.length === 0) return null;
  const activeId = (typeof MemoryStore !== "undefined" && MemoryStore.meta) ? MemoryStore.meta.active_session_id : null;
  const candidates = sessions.filter(s => s && s.session_id && s.session_id !== activeId);
  if (candidates.length === 0) return null;
  // Sort desc por started_at (ISO strings lexicográficos comparables)
  candidates.sort((a, b) => {
    if (a.started_at > b.started_at) return -1;
    if (a.started_at < b.started_at) return 1;
    return 0;
  });
  return candidates[0];
}

// ── _composeFallbackCaveat · honest narrative · D-S.C-2 firmado ─────────────
// Cuando NO hay sesión previa · narrativa honesta poblada en fallback_caveat.
function _composeFallbackCaveat(reference_kind, entities, topic_hint) {
  const entity_name = (Array.isArray(entities) && entities.length > 0 && typeof getEntityById === "function")
    ? (getEntityById(entities[0]) ? getEntityById(entities[0]).canonical_name : null)
    : null;
  const entity_phrase = entity_name ? " sobre " + entity_name : "";
  if (reference_kind === "entity" && entity_name) {
    return CONTINUITY_TEMPLATES.entity_no_session.replace("{entity_name}", entity_name);
  }
  if (reference_kind === "temporal") {
    return CONTINUITY_TEMPLATES.temporal_no_session
      .replace("{elapsed_days}", (topic_hint && topic_hint.elapsed_days) ? topic_hint.elapsed_days : "varios")
      .replace("{entity_phrase}", entity_phrase);
  }
  if (reference_kind === "topical") {
    const topic_phrase = (topic_hint && topic_hint.topic_hint) ? " sobre " + topic_hint.topic_hint : "";
    return CONTINUITY_TEMPLATES.topical_no_session
      .replace("{topic_phrase}", topic_phrase)
      .replace("{entity_phrase}", entity_phrase);
  }
  if (reference_kind === "plan") {
    return CONTINUITY_TEMPLATES.plan_no_session.replace("{entity_phrase}", entity_phrase);
  }
  return "No tengo registro de la conversación previa que mencionas.";
}

// ── detectContinuityReference · función pública · PURE DETECTOR ─────────────
// D-S.C-1 firmado · orden catálogo · primer match wins.
// D-S.C-5 firmado · primer entity match · simpleza MVP.
// NO consulta Memory Store · solo regex + extracción entities desde query.
//
// Retorna { kind, pattern_id, payload } o null si no hay match continuity.
//
// Ejemplos runtime:
//   detectContinuityReference("hace 30 días Falabella tenía margen 24%")
//     → { kind: "temporal", pattern_id: "temporal_relative", payload: { elapsed_days: 30, entities: ["client_falabella"], topic_hint: null } }
//   detectContinuityReference("sobre Lider seguimos donde quedamos")
//     → { kind: "entity", pattern_id: "entity_continuation", payload: { elapsed_days: null, entities: ["client_lider"], topic_hint: null } }
//   detectContinuityReference("hola")                  → null
//   detectContinuityReference("resumen ejecutivo")     → null
//   detectContinuityReference("perfil de Falabella")   → null (sin verbo continuity)
function detectContinuityReference(query, options) {
  if (!VOICE_SESSION_CONTINUITY_ENABLED) return null;
  if (typeof query !== "string" || query.length === 0) return null;
  // D-S.C-1 · orden catálogo · primer match wins
  for (const pat of CONTINUITY_PATTERNS) {
    const m = query.match(pat.regex);
    if (!m) continue;
    // Extraer entities desde query (D-S.C-5 · primer match · S.B helper reused)
    const entities = (typeof _extractEntitiesFromText === "function") ? _extractEntitiesFromText(query) : [];
    // Extraer elapsed_days si pattern es cuantitativo
    const elapsed_days = pat.has_elapsed_days ? _extractElapsedDays(m) : null;
    return {
      kind: pat.kind,
      pattern_id: pat.id,
      payload: {
        elapsed_days,
        entities,
        topic_hint: null,
        match_text: m[0],
      },
    };
  }
  return null;
}

// ── resolveContext · función pública · lookup contra Memory Store ───────────
// Consume S.B vía searchSessions + getSession. D-S.C-2 firmado · honest fallback
// obligatorio · siempre retorna objeto con fallback_caveat si no hay sesión.
//
// Ejemplos runtime:
//   const ref = detectContinuityReference("sobre Falabella seguimos");
//   resolveContext(ref)
//     // sin sesión previa → { previous_session_id: null, fallback_caveat: "No tengo registro...", ... }
//     // con sesión previa → { previous_session_id: "ses_...", previous_session: {...}, elapsed_days: X, ... }
function resolveContext(reference, options) {
  if (!VOICE_SESSION_CONTINUITY_ENABLED) return null;
  if (!reference || typeof reference !== "object" || !reference.kind) return null;
  const payload = reference.payload || {};
  const entities = Array.isArray(payload.entities) ? payload.entities : [];
  const ref_elapsed_days = payload.elapsed_days;
  // Lookup en Memory Store
  let candidate_sessions = [];
  if (entities.length > 0 && typeof searchSessions === "function") {
    // D-S.C-5 · primer entity match
    candidate_sessions = searchSessions({ entity_id: entities[0] });
  } else if (typeof searchSessions === "function") {
    // Sin entity · todas las sesiones (excluyendo active)
    candidate_sessions = searchSessions();
  }
  const most_recent = _selectMostRecentSession(candidate_sessions);
  // Honest fallback · sin sesión previa (D-S.C-2 firmado)
  if (!most_recent) {
    return {
      reference_kind: reference.kind,
      previous_session_id: null,
      previous_session: null,
      previous_topic: null,
      relevant_entities: entities,
      elapsed_days: ref_elapsed_days,
      fallback_caveat: _composeFallbackCaveat(reference.kind, entities, payload),
    };
  }
  // Sesión previa resuelta
  return {
    reference_kind: reference.kind,
    previous_session_id: most_recent.session_id,
    previous_session: most_recent,
    previous_topic: (most_recent.summary && Array.isArray(most_recent.summary.primary_patterns) && most_recent.summary.primary_patterns[0]) || null,
    relevant_entities: entities,
    elapsed_days: ref_elapsed_days, // del usuario · NO calculado (D-S.C-4 deuda timezone)
    fallback_caveat: null,
  };
}

// ── composeContinuityIntro · función pública · narrative determinística ─────
// PURE STRING COMPOSER · templates pre-redactadas · NO LLM.
// Si fallback_caveat presente · retorna caveat string honesto.
// Si previous_session resuelta · compone template entity/temporal/topical/plan.
function composeContinuityIntro(resolved_context) {
  if (!VOICE_SESSION_CONTINUITY_ENABLED) return null;
  if (!resolved_context || typeof resolved_context !== "object") return null;
  // Caso honest fallback · retorna caveat poblado
  if (resolved_context.fallback_caveat) return resolved_context.fallback_caveat;
  if (!resolved_context.previous_session) return null;
  const ent_id = (Array.isArray(resolved_context.relevant_entities) && resolved_context.relevant_entities.length > 0)
    ? resolved_context.relevant_entities[0]
    : null;
  const entity_obj = (ent_id && typeof getEntityById === "function") ? getEntityById(ent_id) : null;
  const entity_name = entity_obj ? entity_obj.canonical_name : null;
  const elapsed = resolved_context.elapsed_days;
  const topic = resolved_context.previous_topic;
  const previous_topic_phrase = topic ? "discutimos " + topic : "lo conversamos";
  const entity_phrase = entity_name ? " sobre " + entity_name : "";
  if (resolved_context.reference_kind === "entity" && entity_name) {
    return CONTINUITY_TEMPLATES.entity_with_session
      .replace("{entity_name}", entity_name)
      .replace("{elapsed_days}", (elapsed != null) ? elapsed : "algunos")
      .replace("{previous_topic_phrase}", previous_topic_phrase);
  }
  if (resolved_context.reference_kind === "temporal") {
    return CONTINUITY_TEMPLATES.temporal_with_session
      .replace("{elapsed_days}", (elapsed != null) ? elapsed : "algunos")
      .replace("{entity_phrase}", entity_phrase)
      .replace("{previous_topic_phrase}", previous_topic_phrase);
  }
  if (resolved_context.reference_kind === "topical") {
    return CONTINUITY_TEMPLATES.topical_with_session
      .replace("{topic_phrase}", topic ? "sobre " + topic : "")
      .replace("{entity_phrase}", entity_phrase)
      .replace("{previous_topic_phrase}", previous_topic_phrase);
  }
  if (resolved_context.reference_kind === "plan") {
    const entity_or_topic_phrase = entity_name || topic || "ese tema";
    const previous_summary_phrase = topic ? " (lo discutimos como " + topic + ")" : "";
    return CONTINUITY_TEMPLATES.plan_with_session
      .replace("{entity_or_topic_phrase}", entity_or_topic_phrase)
      .replace("{previous_summary_phrase}", previous_summary_phrase);
  }
  return null;
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF S · S.C · SESSION CONTINUITY LAYER
// (S.D Business Snapshot Engine siguiente · pre-flight aparte)
