    capital_atrapado_K: (typeof i.capitalAtrapado === "number") ? ((typeof ADI_DELTA_PRELUDE_CAPITAL_ESCALA_ENABLED !== "undefined" && ADI_DELTA_PRELUDE_CAPITAL_ESCALA_ENABLED) ? i.capitalAtrapado / 1000 : i.capitalAtrapado) : null,
    capital_pct_atrapado: (typeof i.capitalPctAtrapado === "number") ? i.capitalPctAtrapado : null,
    skus_criticos_count: (typeof i.skusCriticosCount === "number") ? i.skusCriticosCount : null,
