// PREVIOUS_ACTION_PHRASES · 12 entries mapping pattern_id → frase (D-S.F-5).
// Fallback genérico "conversamos" si pattern_id no catalogado · honest inline.
// Audit constitución voz ADI · verbos neutros · sin adjetivación dramática.
const PREVIOUS_ACTION_PHRASES = {
  tier1_lock:                "discutimos el bloqueo Tier 1",
  silent_compression:        "vimos la presión silenciosa de carga comercial",
  operational_strangulation: "abordamos el estrangulamiento operativo",
  growth_quality_decay:      "discutimos la calidad del crecimiento",
  benchmark_gap_widening:    "abordamos la brecha vs benchmark",
  capital_concentration:     "discutimos la concentración de capital",
  margin_erosion:            "vimos la erosión de margen",
  dependency_with_decay:     "discutimos la dependencia con deterioro",
  silent_growth_killer:      "abordamos el freno silencioso al crecimiento",
  capital_lockup:            "vimos el bloqueo de capital",
  benchmark_lag:             "discutimos el rezago vs benchmark",
  cuenta_expuesta:           "discutimos la exposición de cuenta",
  // Fallback en _composePreviousActionPhrase: "conversamos"
};

// ── _formatAmount · formato consistente cifras dinero ───────────────────────
// > 1000K → "$X.XM" (1 decimal · M = millón)
// ≤ 1000K → "$XK" (sin decimales · K = mil)
// 0 → "$0K" honest
function _formatAmount(value_K) {
  if (typeof value_K !== "number" || !isFinite(value_K)) return "$0";
  const abs = Math.abs(value_K);
  if (abs >= 1000) {
    return "$" + (value_K / 1000).toFixed(1).replace(/\.0$/, "") + "M";
  }
  return "$" + Math.round(value_K) + "K";
}

// ── _selectRecallTemplate · matriz 2x2 selector ─────────────────────────────
function _selectRecallTemplate(has_session, has_delta, fallback_caveat, snapshot_caveat) {
  if (snapshot_caveat) return "snapshot_caveat";
  if (fallback_caveat) return "honest_no_history";
  if (has_session && has_delta) return "recall_full";
  if (has_session && !has_delta) return "recall_qualitative";
  if (!has_session && has_delta) return "delta_only";
  return "honest_no_history"; // fallback defensive
}

// ── _composePreviousActionPhrase · pattern_id → frase ───────────────────────
// D-S.F-5 firmado · fallback inline "conversamos" si pattern_id no catalogado.
function _composePreviousActionPhrase(pattern_id) {
  if (typeof pattern_id !== "string" || pattern_id.length === 0) return "conversamos";
  return PREVIOUS_ACTION_PHRASES[pattern_id] || "conversamos";
}

// ── _composeDirectionPhrase · single delta → frase business ─────────────────
// D-S.F-4 firmado · DIRECTION_PHRASES catálogo lookup · 36 entries.
// Constitución voz ADI · vocabulario auditado pre-implementación.
function _composeDirectionPhrase(delta_obj, entity_canonical_name) {
  if (!delta_obj || typeof delta_obj !== "object") return null;
  const dim = delta_obj.dimension;
  const dir = delta_obj.direction;
  const dimCfg = DIRECTION_PHRASES[dim];
  if (!dimCfg) {
    // Fallback genérico · honest inline (D-S.F-5 spirit)
    const abs = Math.abs(delta_obj.delta);
    return "el indicador " + dim + " cambió en " + abs;
  }
  const tmpl = dimCfg[dir] || dimCfg.neutral || dimCfg.negative; // defensive
  if (!tmpl) return null;
  const abs = Number(Math.abs(delta_obj.delta).toFixed(2));
  // Display absoluto · drop .00 trailing
  const abs_display = (abs % 1 === 0) ? String(abs) : String(abs).replace(/\.0+$/, "");
  const amount = _formatAmount(abs);
  // {entity} substitution
  const entity_str = (delta_obj.entity_id === "portfolio")
    ? "el portfolio"
    : (entity_canonical_name || delta_obj.entity_id);
  return tmpl
    .replace("{entity}", entity_str)
    .replace("{abs}", abs_display)
    .replace("{amount}", amount);
}

// ── _composeTopDeltaPhrase · concat múltiples deltas (D-S.F-3) ──────────────
// D-S.F-3 firmado · concat "y" hasta 2 · ", además" para 3 · cap 3.
function _composeTopDeltaPhrase(top_deltas, entity_filter, get_entity_name_fn) {
  if (!Array.isArray(top_deltas) || top_deltas.length === 0) return "no hubo cambios significativos";
  // Filtrar por entity opcional
  let filtered = top_deltas;
  if (typeof entity_filter === "string") {
    filtered = top_deltas.filter(d => d.entity_id === entity_filter);
    if (filtered.length === 0) filtered = top_deltas; // si filter vacía, usar todo
  }
  // Cap 3 · solo deltas relevantes (high + medium)
  const relevant = filtered.filter(d => d.relevance === "high" || d.relevance === "medium").slice(0, 3);
  if (relevant.length === 0) {
    // fallback · usar low si no hay relevantes pero hay algo
    if (filtered.length === 0) return "no hubo cambios significativos";
    const first = filtered[0];
    const name = (typeof get_entity_name_fn === "function") ? get_entity_name_fn(first.entity_id) : null;
    const phrase = _composeDirectionPhrase(first, name);
    return phrase || "el cambio fue menor";
  }
  const phrases = relevant.map(d => {
    const name = (typeof get_entity_name_fn === "function") ? get_entity_name_fn(d.entity_id) : null;
    return _composeDirectionPhrase(d, name);
  }).filter(Boolean);
  if (phrases.length === 0) return "no hubo cambios significativos";
  if (phrases.length === 1) return phrases[0];
  if (phrases.length === 2) return phrases[0] + " y " + phrases[1];
  // 3 phrases: "A, B, además C"
  return phrases[0] + ", " + phrases[1] + ", además " + phrases[2];
}

// ── _fillRecallTemplate · template substitution ─────────────────────────────
function _fillRecallTemplate(template_str, payload) {
  if (typeof template_str !== "string") return "";
  let out = template_str;
  for (const k of Object.keys(payload || {})) {
    const v = payload[k];
    if (v == null) continue;
    out = out.split("{" + k + "}").join(String(v));
  }
  return out;
}

// ── composeRecallNarrative · función pública principal ──────────────────────
// Orquesta narrativa runtime · consume continuity_context (S.C) + opcional
// temporal_comparison (S.E) · retorna recall_narrative completo con references.
//
// Output shape:
// {
//   narrative_text: "Hace 30 días discutimos tier1_lock sobre Falabella. ...",
//   references: {
//     sessions: ["ses_xxx"] | [],
//     snapshots: ["snap_xxx", "snap_yyy"] | [],
//     entities: ["client_falabella"],
//   },
//   template_used: "recall_full" | "recall_qualitative" | "delta_only" | "honest_no_history" | "snapshot_caveat",
//   caveat: null | string,
// }
function composeRecallNarrative(continuity_context, temporal_comparison, options) {
  if (!VOICE_RECALL_NARRATIVE_ENABLED) return null;
  // Inputs · todos opcionales pero al menos uno debe estar presente
  const has_ctx = continuity_context && typeof continuity_context === "object";
  const has_cmp = temporal_comparison && typeof temporal_comparison === "object";
  if (!has_ctx && !has_cmp) return null;
  const ctx = has_ctx ? continuity_context : null;
  const cmp = has_cmp ? temporal_comparison : null;
  // Detectar caveats
  const fallback_caveat = (ctx && ctx.fallback_caveat) || null;
  const snapshot_caveat = (cmp && cmp.caveat) || null;
  // Determinar disponibilidad data
  const has_session = !!(ctx && ctx.previous_session_id && ctx.previous_session);
  const has_relevant_deltas = !!(cmp && Array.isArray(cmp.deltas) && cmp.deltas.length > 0 && cmp.summary && cmp.summary.high_relevance_count + cmp.summary.medium_relevance_count > 0);
  const template_id = _selectRecallTemplate(has_session, has_relevant_deltas, fallback_caveat, snapshot_caveat);
  const template_str = RECALL_TEMPLATES[template_id];
  if (!template_str) return null;
  // Resolve entity canonical (D-S.F-2 · estructura neutra · sin artículos)
  let entity_id = null;
  let entity_canonical = null;
  if (ctx && Array.isArray(ctx.relevant_entities) && ctx.relevant_entities.length > 0) {
    entity_id = ctx.relevant_entities[0];
  }
  if (entity_id && typeof getEntityById === "function") {
    const e = getEntityById(entity_id);
    if (e) entity_canonical = e.canonical_name;
  }
  // Entity name lookup helper para top_delta_phrase
  const get_entity_name = function(eid) {
    if (eid === "portfolio") return null; // template usa "el portfolio" internamente
    if (typeof getEntityById === "function") {
      const ent = getEntityById(eid);
      return ent ? ent.canonical_name : null;
    }
    return null;
  };
  // Compose payload per template
  let narrative_text = "";
  if (template_id === "honest_no_history") {
    narrative_text = fallback_caveat;
  } else if (template_id === "snapshot_caveat") {
    narrative_text = snapshot_caveat;
  } else if (template_id === "recall_full") {
    // Top deltas filtered by entity if available (D-S.F-3)
    const top = (typeof getTopDeltas === "function") ? getTopDeltas(cmp, 3) : (cmp.deltas || []).slice(0, 3);
    const top_phrase = _composeTopDeltaPhrase(top, entity_id, get_entity_name);
    const elapsed = (ctx && ctx.elapsed_days != null) ? ctx.elapsed_days : (cmp.summary && cmp.summary.elapsed_days);
    const pattern_id = (ctx && ctx.previous_topic) || null;
    narrative_text = _fillRecallTemplate(template_str, {
      elapsed_days: elapsed != null ? elapsed : "algunos",
      previous_action_phrase: _composePreviousActionPhrase(pattern_id),
      entity: entity_canonical || "esta cuenta",
      top_delta_phrase: top_phrase,
    });
  } else if (template_id === "recall_qualitative") {
    const elapsed = (ctx && ctx.elapsed_days != null) ? ctx.elapsed_days : null;
    const pattern_id = (ctx && ctx.previous_topic) || null;
    narrative_text = _fillRecallTemplate(template_str, {
      elapsed_days: elapsed != null ? elapsed : "algunos",
      previous_action_phrase: _composePreviousActionPhrase(pattern_id),
      entity: entity_canonical || "esta cuenta",
    });
  } else if (template_id === "delta_only") {
    const top = (typeof getTopDeltas === "function") ? getTopDeltas(cmp, 3) : (cmp.deltas || []).slice(0, 3);
    const top_phrase = _composeTopDeltaPhrase(top, null, get_entity_name);
    const elapsed = (cmp.summary && cmp.summary.elapsed_days != null) ? cmp.summary.elapsed_days : "algunos";
    narrative_text = _fillRecallTemplate(template_str, {
      elapsed_days: elapsed,
      top_delta_phrase: top_phrase,
    });
  }
  // References
  const references = {
    sessions: (has_session) ? [ctx.previous_session_id] : [],
    snapshots: [],
    entities: (entity_id) ? [entity_id] : [],
  };
  if (cmp && cmp.deltas && cmp.deltas.length > 0) {
    // No tenemos los snapshot_ids directamente · pero podemos derivar entidades adicionales
    const all_entities = new Set(references.entities);
    for (const d of cmp.deltas.slice(0, 10)) {
      if (d.entity_id && d.entity_id !== "portfolio") all_entities.add(d.entity_id);
    }
    references.entities = Array.from(all_entities);
  }
  return {
    narrative_text,
    references,
    template_used: template_id,
    caveat: fallback_caveat || snapshot_caveat || null,
  };
}

// ── getRecallNarrativeStats · transparencia founder ─────────────────────────
function getRecallNarrativeStats() {
  return {
    templates_count: Object.keys(RECALL_TEMPLATES).length,
    direction_phrases_count: Object.keys(DIRECTION_PHRASES).length,
    action_phrases_count: Object.keys(PREVIOUS_ACTION_PHRASES).length,
    templates_supported: Object.keys(RECALL_TEMPLATES),
    dimensions_with_direction_phrases: Object.keys(DIRECTION_PHRASES),
    patterns_with_action_phrases: Object.keys(PREVIOUS_ACTION_PHRASES),
  };
}

