// Flag rollback granular S.H.
const VOICE_PERSISTENCE_BRIDGE_ENABLED = true;

// Schema version del wrapper consolidado · D-S.H-3 firmado.
const _PERSISTENCE_BRIDGE_SCHEMA_VERSION = "S.H.v1";

// ── _serializeStoresShape · helper privado · construye export object ────────
// D-S.H-5 firmado · solo BRIEF S state · NO BRIEF R aggregator runtime.
function _serializeStoresShape(options) {
  const opts = options || {};
  const includeReg = opts.include_entity_registry !== false;
  const includeMem = opts.include_memory_store !== false;
  const includeSnap = opts.include_business_snapshots !== false;
  const now = (typeof _isoNow === "function") ? _isoNow() : "2026-05-26T00:00:00Z";
  const out = {
    schema_version: _PERSISTENCE_BRIDGE_SCHEMA_VERSION,
    exported_at: now,
    storage_mode: (typeof _storage !== "undefined") ? _storage.mode : "in_memory",
    brief: "S",
  };
  if (includeReg && typeof EntityRegistry !== "undefined") {
    out.entity_registry = EntityRegistry;
  }
  if (includeMem && typeof MemoryStore !== "undefined") {
    out.memory_store = MemoryStore;
  }
  if (includeSnap && typeof BusinessSnapshots !== "undefined") {
    out.business_snapshots = BusinessSnapshots;
  }
  out.meta = {
    total_entities: (out.entity_registry && out.entity_registry.meta) ? out.entity_registry.meta.total_entities : 0,
    total_sessions: (out.memory_store && out.memory_store.meta) ? out.memory_store.meta.total_sessions : 0,
    total_snapshots: (out.business_snapshots && out.business_snapshots.meta) ? out.business_snapshots.meta.total_snapshots : 0,
  };
  return out;
}

// ── _validateImportPayloadShape · helper privado · pre-flight checks ────────
// D-S.H-3 firmado · reject completo si shape inválido · NO partial import.
// Retorna { valid, errors[], schema_version, stats }
function _validateImportPayloadShape(payload) {
  const result = {
    valid: false,
    errors: [],
    schema_version: null,
    stats: { entities: 0, sessions: 0, snapshots: 0 },
  };
  if (!payload || typeof payload !== "object") {
    result.errors.push("Payload no es un objeto JSON válido.");
    return result;
  }
  // Root schema_version
  if (payload.schema_version !== _PERSISTENCE_BRIDGE_SCHEMA_VERSION) {
    result.errors.push("Schema version mismatch · expected " + _PERSISTENCE_BRIDGE_SCHEMA_VERSION + " · got " + (payload.schema_version || "undefined"));
    result.schema_version = payload.schema_version || null;
    return result;
  }
  result.schema_version = payload.schema_version;
  // Validar entity_registry si presente
  if (payload.entity_registry) {
    if (payload.entity_registry.schema_version !== "S.A.v1") {
      result.errors.push("entity_registry.schema_version mismatch · expected S.A.v1 · got " + payload.entity_registry.schema_version);
    } else if (!payload.entity_registry.entities || typeof payload.entity_registry.entities !== "object") {
      result.errors.push("entity_registry.entities ausente o inválido.");
    } else {
      result.stats.entities = Object.keys(payload.entity_registry.entities).length;
    }
  }
  // Validar memory_store si presente
  if (payload.memory_store) {
    if (payload.memory_store.schema_version !== "S.B.v1") {
      result.errors.push("memory_store.schema_version mismatch · expected S.B.v1 · got " + payload.memory_store.schema_version);
    } else if (!payload.memory_store.sessions || typeof payload.memory_store.sessions !== "object") {
      result.errors.push("memory_store.sessions ausente o inválido.");
    } else {
      result.stats.sessions = Object.keys(payload.memory_store.sessions).length;
    }
  }
  // Validar business_snapshots si presente
  if (payload.business_snapshots) {
    if (payload.business_snapshots.schema_version !== "S.D.v1") {
      result.errors.push("business_snapshots.schema_version mismatch · expected S.D.v1 · got " + payload.business_snapshots.schema_version);
    } else if (!payload.business_snapshots.snapshots || typeof payload.business_snapshots.snapshots !== "object") {
      result.errors.push("business_snapshots.snapshots ausente o inválido.");
    } else {
      result.stats.snapshots = Object.keys(payload.business_snapshots.snapshots).length;
    }
  }
  // Al menos un store debe estar presente para ser útil
  if (!payload.entity_registry && !payload.memory_store && !payload.business_snapshots) {
    result.errors.push("Payload no contiene ningún store válido (entity_registry, memory_store, business_snapshots).");
  }
  result.valid = result.errors.length === 0;
  return result;
}

// ── exportMemoryToJSON · función pública · serializar a objeto ──────────────
function exportMemoryToJSON(options) {
  if (!VOICE_PERSISTENCE_BRIDGE_ENABLED) return null;
  return _serializeStoresShape(options);
}

// ── exportMemoryToJSONString · función pública · string browser-ready ───────
function exportMemoryToJSONString(options) {
  if (!VOICE_PERSISTENCE_BRIDGE_ENABLED) return null;
  const obj = _serializeStoresShape(options);
  if (!obj) return null;
  try {
    return JSON.stringify(obj);
  } catch (e) {
    if (typeof console !== "undefined" && console.warn) {
      console.warn("[S.H] exportMemoryToJSONString failed:", e);
    }
    return null;
  }
}

// ── validateMemoryJSONPayload · función pública · pre-import check ──────────
// Founder valida ANTES de importar · seguro · NO modifica state.
function validateMemoryJSONPayload(payload) {
  if (!VOICE_PERSISTENCE_BRIDGE_ENABLED) {
    return { valid: false, errors: ["Persistence bridge disabled."], schema_version: null, stats: {} };
  }
  // Si string · intentar parse
  let parsed = payload;
  if (typeof payload === "string") {
    try {
      parsed = JSON.parse(payload);
    } catch (e) {
      return { valid: false, errors: ["JSON parse error: " + (e && e.message)], schema_version: null, stats: {} };
    }
  }
  return _validateImportPayloadShape(parsed);
}

// ── importMemoryFromJSON · función pública · merge conservador ──────────────
// D-S.H-2 firmado · conservador estricto · skip entities/sessions/snapshots con id existente.
// D-S.H-3 firmado · reject completo si validation falla.
// options.dry_run · si true · solo preview · NO modifica state.
function importMemoryFromJSON(payload, options) {
  const opts = options || {};
  const dry_run = opts.dry_run === true;
  // Parse si string
  let parsed = payload;
  if (typeof payload === "string") {
    try {
      parsed = JSON.parse(payload);
    } catch (e) {
      return {
        success: false,
        schema_version: null,
        imported_count: { entities: 0, sessions: 0, snapshots: 0 },
        conflict_count: { entities: 0, sessions: 0, snapshots: 0 },
        errors: ["JSON parse error: " + (e && e.message)],
        caveat: "Payload no es JSON válido.",
      };
    }
  }
  // Validation (D-S.H-3 firmado · reject completo)
  const validation = _validateImportPayloadShape(parsed);
  if (!validation.valid) {
    return {
      success: false,
      schema_version: validation.schema_version,
      imported_count: { entities: 0, sessions: 0, snapshots: 0 },
      conflict_count: { entities: 0, sessions: 0, snapshots: 0 },
      errors: validation.errors,
      caveat: "Validation failed · ningún store modificado.",
    };
  }
  // Pre-compute counts (D-S.H-2 conservative)
  const result = {
    success: true,
    schema_version: validation.schema_version,
    imported_count: { entities: 0, sessions: 0, snapshots: 0 },
    conflict_count: { entities: 0, sessions: 0, snapshots: 0 },
    errors: [],
    caveat: dry_run ? "DRY RUN · state NO modificado · preview de import." : null,
  };
  // ── Entity Registry merge conservador ──────────────────────────────────
  if (parsed.entity_registry && typeof EntityRegistry !== "undefined") {
    const incoming = parsed.entity_registry.entities || {};
    for (const eid of Object.keys(incoming)) {
      if (EntityRegistry.entities[eid]) {
        result.conflict_count.entities++;
      } else {
        if (!dry_run) {
          EntityRegistry.entities[eid] = incoming[eid];
        }
        result.imported_count.entities++;
      }
    }
    if (!dry_run) {
      // Recompute indices via re-traverse (skip merge directo · evita inconsistencias)
      EntityRegistry.meta.total_entities = Object.keys(EntityRegistry.entities).length;
      // Indices by_canonical_name + by_kind preservados (build-once cross-fetches)
    }
  }
  // ── Memory Store merge conservador ─────────────────────────────────────
  if (parsed.memory_store && typeof MemoryStore !== "undefined") {
    const incoming = parsed.memory_store.sessions || {};
    for (const sid of Object.keys(incoming)) {
      if (MemoryStore.sessions[sid]) {
        result.conflict_count.sessions++;
      } else {
        if (!dry_run) {
          MemoryStore.sessions[sid] = incoming[sid];
          // Update indices via _updateIndices si disponible
          if (typeof _updateIndices === "function") {
            _updateIndices(MemoryStore, incoming[sid]);
          }
        }
        result.imported_count.sessions++;
      }
    }
    if (!dry_run) {
      MemoryStore.meta.total_sessions = Object.keys(MemoryStore.sessions).length;
    }
  }
  // ── Business Snapshots merge conservador ───────────────────────────────
  if (parsed.business_snapshots && typeof BusinessSnapshots !== "undefined") {
    const incoming = parsed.business_snapshots.snapshots || {};
    for (const snapId of Object.keys(incoming)) {
      if (BusinessSnapshots.snapshots[snapId]) {
        result.conflict_count.snapshots++;
      } else {
        if (!dry_run) {
          BusinessSnapshots.snapshots[snapId] = incoming[snapId];
          // Update indices
          const snap = incoming[snapId];
          const dateKey = snap.taken_at ? snap.taken_at.slice(0, 10) : null;
          if (dateKey) {
            if (!BusinessSnapshots.index.by_date[dateKey]) BusinessSnapshots.index.by_date[dateKey] = [];
            if (!BusinessSnapshots.index.by_date[dateKey].includes(snapId)) BusinessSnapshots.index.by_date[dateKey].push(snapId);
          }
          if (snap.scenarioId) {
            if (!BusinessSnapshots.index.by_scenario[snap.scenarioId]) BusinessSnapshots.index.by_scenario[snap.scenarioId] = [];
            if (!BusinessSnapshots.index.by_scenario[snap.scenarioId].includes(snapId)) BusinessSnapshots.index.by_scenario[snap.scenarioId].push(snapId);
          }
        }
        result.imported_count.snapshots++;
      }
    }
    if (!dry_run) {
      BusinessSnapshots.meta.total_snapshots = Object.keys(BusinessSnapshots.snapshots).length;
    }
  }
  // Persist async fire-and-forget (si no dry_run)
  if (!dry_run) {
    if (typeof _persistMemoryStore === "function") { _persistMemoryStore(); }
    if (typeof _persistBusinessSnapshots === "function") { _persistBusinessSnapshots(); }
  }
  return result;
}

// ── _triggerJSONDownload · helper opcional · descarga programática browser ──
// Founder ejecuta runtime React: _triggerJSONDownload("adi_memory_20260527.json", exportMemoryToJSONString())
// Crea blob URL + click sintético · cero touch UI visible.
// En Node/runtime sin browser APIs · retorna false silencioso.
function _triggerJSONDownload(filename, json_string) {
  if (typeof filename !== "string" || typeof json_string !== "string") return false;
  if (typeof window === "undefined" || typeof document === "undefined") return false;
  if (typeof Blob === "undefined" || typeof URL === "undefined") return false;
  try {
    const blob = new Blob([json_string], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = filename;
    a.style.display = "none";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    // Liberar URL después de un breve delay para garantizar trigger del download
    setTimeout(function() { URL.revokeObjectURL(url); }, 1000);
    return true;
  } catch (e) {
    if (typeof console !== "undefined" && console.warn) {
      console.warn("[S.H] _triggerJSONDownload failed:", e);
    }
    return false;
  }
}

// ── getPersistenceBridgeStats · transparencia founder ───────────────────────
function getPersistenceBridgeStats() {
  let size_bytes = 0;
  try {
    const obj = _serializeStoresShape({});
    size_bytes = (typeof JSON !== "undefined") ? JSON.stringify(obj).length : 0;
  } catch (e) {
    size_bytes = -1;
  }
  return {
    schema_version: _PERSISTENCE_BRIDGE_SCHEMA_VERSION,
    current_state_size_bytes: size_bytes,
    current_state_size_kb: (size_bytes > 0) ? Number((size_bytes / 1024).toFixed(1)) : 0,
    stores_included: ["entity_registry", "memory_store", "business_snapshots"],
    download_helper_available: (typeof window !== "undefined" && typeof Blob !== "undefined"),
  };
}

