// Flag rollback granular harness.
const VOICE_DEMO_DELTA_HARNESS_ENABLED = true;

// D-SPLUS-ACT-2 · C · seed híbrido · flag separado controla seed demo en init runtime.
// true → demo (seed automático al montar · prelude visible desde primera vez)
// false → producción real (snapshots se acumulan naturalmente · sin seed sintético)
const VOICE_SEED_DEMO_ON_INIT = true;

// DEMO_DELTA_PROFILE · perfiles curados por escenario (D-HARNESS-2 firmado).
// Cada delta es SUMADO al snapshot actual para construir el "pasado":
//   pasado = hoy + delta · entonces hoy - pasado = -delta → direction observable.
// Ej: hoy margen 22 · delta +2 → hace 30d era 24 → hoy cayó 2pp (negative) ✅
// Cifras realistas negocio Innova Ferre · narrativa coherente con tesis escenario.
const DEMO_DELTA_PROFILE = {
  bonanza: {
    entities: {
      client_falabella: { margen_pct: 2, carga_comercial_pct: -0.3, contribucion_K: 229 },
    },
    portfolio: { capital_atrapado_K: -5800 },
  },
  tension: {
    entities: {
      client_falabella: { margen_pct: 3, carga_comercial_pct: -0.5 },
    },
    portfolio: { margen_promedio_pct: 2, concentracion_tier1_pct: -2 },
  },
  crisis: {
    entities: {
      client_falabella: { margen_pct: 5 },
    },
    portfolio: { capital_pct_atrapado: -8, capital_atrapado_K: -12000 },
  },
};
// FIX #D-DELTA-PRELUDE-CAPITAL-ESCALA-BIS · los deltas demo de capital_atrapado_K estaban en USD (-5800,
// -12000) igual que el snapshot. Al escalar el snapshot+threshold a K real, estos deltas demo bajan
// coordinadamente a K real (÷1000) para que el "past" sintético quede en la misma escala. Override
// post-declaración para no tocar los literales (OFF byte-idéntico). Solo el capital · las otras dims intactas.
if (typeof ADI_DELTA_PRELUDE_CAPITAL_ESCALA_ENABLED !== "undefined" && ADI_DELTA_PRELUDE_CAPITAL_ESCALA_ENABLED) {
  if (DEMO_DELTA_PROFILE.bonanza && DEMO_DELTA_PROFILE.bonanza.portfolio && typeof DEMO_DELTA_PROFILE.bonanza.portfolio.capital_atrapado_K === "number") {
    DEMO_DELTA_PROFILE.bonanza.portfolio.capital_atrapado_K = DEMO_DELTA_PROFILE.bonanza.portfolio.capital_atrapado_K / 1000;
  }
  if (DEMO_DELTA_PROFILE.crisis && DEMO_DELTA_PROFILE.crisis.portfolio && typeof DEMO_DELTA_PROFILE.crisis.portfolio.capital_atrapado_K === "number") {
    DEMO_DELTA_PROFILE.crisis.portfolio.capital_atrapado_K = DEMO_DELTA_PROFILE.crisis.portfolio.capital_atrapado_K / 1000;
  }
}

// ── _applyDemoDeltaToSnapshot · helper privado · construye pasado sintético ──
// Clona snapshot actual · SUMA deltas profile · backdatea · marca _demo_seed.
function _applyDemoDeltaToSnapshot(current_snap, profile, backdated_iso) {
  const clone = JSON.parse(JSON.stringify(current_snap));
  clone._demo_seed = true;
  clone.taken_at = backdated_iso;
  // Regenerar snapshot_id basado en fecha backdateada
  const dateKey = backdated_iso.slice(0, 10).replace(/-/g, "");
  clone.snapshot_id = "snap_" + current_snap.scenarioId + "_" + dateKey + "_demoseed";
  // Aplicar deltas entities
  if (profile && profile.entities) {
    for (const eid of Object.keys(profile.entities)) {
      if (!clone.entities[eid]) continue;
      const dims = profile.entities[eid];
      for (const dim of Object.keys(dims)) {
        if (typeof clone.entities[eid][dim] === "number") {
          clone.entities[eid][dim] = Number((clone.entities[eid][dim] + dims[dim]).toFixed(2));
        }
      }
    }
  }
  // Aplicar deltas portfolio
  if (profile && profile.portfolio) {
    for (const dim of Object.keys(profile.portfolio)) {
      if (typeof clone.portfolio[dim] === "number") {
        clone.portfolio[dim] = Number((clone.portfolio[dim] + profile.portfolio[dim]).toFixed(2));
      }
    }
  }
  return clone;
}

// ── seedDemoDeltaHistory · función pública · inyecta pasado sintético ───────
// options: { days_ago?, force? }
// Retorna { success, scenarioId, snapshot_id, days_ago, dimensions_modified, caveat }
function seedDemoDeltaHistory(scenarioId, options) {
  if (!VOICE_DEMO_DELTA_HARNESS_ENABLED) {
    return { success: false, caveat: "Demo delta harness disabled." };
  }
  if (typeof scenarioId !== "string" || scenarioId.length === 0) {
    return { success: false, caveat: "scenarioId requerido." };
  }
  const profile = DEMO_DELTA_PROFILE[scenarioId];
  if (!profile) {
    return { success: false, caveat: "No hay perfil demo para escenario: " + scenarioId };
  }
  if (typeof takeBusinessSnapshot !== "function" || typeof BusinessSnapshots === "undefined") {
    return { success: false, caveat: "S.D Business Snapshot no disponible." };
  }
  const opts = options || {};
  const days_ago = (typeof opts.days_ago === "number" && opts.days_ago > 0) ? opts.days_ago : 30;
  const force = opts.force === true;
  // Snapshot actual (current · real aggregator)
  const current = takeBusinessSnapshot(scenarioId);
  if (!current) return { success: false, caveat: "No se pudo tomar snapshot actual." };
  // Calcular fecha backdateada
  const now = (typeof _isoNow === "function") ? _isoNow() : "2026-05-28T00:00:00Z";
  const nowMs = Date.parse(now.slice(0, 10) + "T00:00:00Z");
  const backMs = nowMs - (days_ago * 24 * 60 * 60 * 1000);
  const backdated_iso = new Date(backMs).toISOString().slice(0, 10) + "T00:00:00Z";
  // Construir snapshot pasado sintético
  const seed_snap = _applyDemoDeltaToSnapshot(current, profile, backdated_iso);
  // Idempotencia · skip si ya existe (salvo force)
  if (!force && BusinessSnapshots.snapshots[seed_snap.snapshot_id]) {
    return {
      success: true,
      scenarioId,
      snapshot_id: seed_snap.snapshot_id,
      days_ago,
      already_existed: true,
      caveat: "Snapshot demo ya existía · usar force:true para regenerar.",
    };
  }
  // Inyectar al store + indices
  BusinessSnapshots.snapshots[seed_snap.snapshot_id] = seed_snap;
  const dateKey = backdated_iso.slice(0, 10);
  if (!BusinessSnapshots.index.by_date[dateKey]) BusinessSnapshots.index.by_date[dateKey] = [];
  if (!BusinessSnapshots.index.by_date[dateKey].includes(seed_snap.snapshot_id)) {
    BusinessSnapshots.index.by_date[dateKey].push(seed_snap.snapshot_id);
  }
  if (!BusinessSnapshots.index.by_scenario[scenarioId]) BusinessSnapshots.index.by_scenario[scenarioId] = [];
  if (!BusinessSnapshots.index.by_scenario[scenarioId].includes(seed_snap.snapshot_id)) {
    BusinessSnapshots.index.by_scenario[scenarioId].push(seed_snap.snapshot_id);
  }
  BusinessSnapshots.meta.total_snapshots = Object.keys(BusinessSnapshots.snapshots).length;
  // Contar dimensiones modificadas
  let dims_modified = 0;
  if (profile.entities) for (const e of Object.keys(profile.entities)) dims_modified += Object.keys(profile.entities[e]).length;
  if (profile.portfolio) dims_modified += Object.keys(profile.portfolio).length;
  // Persist async
  if (typeof _persistBusinessSnapshots === "function") { _persistBusinessSnapshots(); }
  return {
    success: true,
    scenarioId,
    snapshot_id: seed_snap.snapshot_id,
    days_ago,
    backdated_to: backdated_iso,
    dimensions_modified: dims_modified,
    caveat: null,
  };
}

// ── clearDemoDeltaHistory · función pública · reversibilidad limpia ─────────
// Elimina snapshots con _demo_seed:true · opcional filtrar por scenarioId.
// Retorna { success, removed_count, removed_ids }
function clearDemoDeltaHistory(scenarioId) {
  if (!VOICE_DEMO_DELTA_HARNESS_ENABLED) {
    return { success: false, removed_count: 0, removed_ids: [] };
  }
  if (typeof BusinessSnapshots === "undefined") {
    return { success: false, removed_count: 0, removed_ids: [] };
  }
  const removed_ids = [];
  for (const sid of Object.keys(BusinessSnapshots.snapshots)) {
    const snap = BusinessSnapshots.snapshots[sid];
    if (!snap || snap._demo_seed !== true) continue;
    if (typeof scenarioId === "string" && snap.scenarioId !== scenarioId) continue;
    removed_ids.push(sid);
  }
  // Eliminar del store + indices
  for (const sid of removed_ids) {
    const snap = BusinessSnapshots.snapshots[sid];
    const dateKey = snap.taken_at ? snap.taken_at.slice(0, 10) : null;
    delete BusinessSnapshots.snapshots[sid];
    // Limpiar indices
    if (dateKey && BusinessSnapshots.index.by_date[dateKey]) {
      BusinessSnapshots.index.by_date[dateKey] = BusinessSnapshots.index.by_date[dateKey].filter(x => x !== sid);
      if (BusinessSnapshots.index.by_date[dateKey].length === 0) delete BusinessSnapshots.index.by_date[dateKey];
    }
    if (snap.scenarioId && BusinessSnapshots.index.by_scenario[snap.scenarioId]) {
      BusinessSnapshots.index.by_scenario[snap.scenarioId] = BusinessSnapshots.index.by_scenario[snap.scenarioId].filter(x => x !== sid);
    }
    // Limpiar latest_per_scenario si apuntaba al removido
    if (snap.scenarioId && BusinessSnapshots.meta.latest_per_scenario[snap.scenarioId] === sid) {
      const remaining = BusinessSnapshots.index.by_scenario[snap.scenarioId] || [];
      BusinessSnapshots.meta.latest_per_scenario[snap.scenarioId] = remaining.length > 0 ? remaining[remaining.length - 1] : null;
    }
  }
  BusinessSnapshots.meta.total_snapshots = Object.keys(BusinessSnapshots.snapshots).length;
  if (removed_ids.length > 0 && typeof _persistBusinessSnapshots === "function") { _persistBusinessSnapshots(); }
  return {
    success: true,
    removed_count: removed_ids.length,
    removed_ids,
  };
}

// ── getDemoDeltaHarnessStats · transparencia founder ────────────────────────
function getDemoDeltaHarnessStats() {
  let seed_count = 0;
  if (typeof BusinessSnapshots !== "undefined") {
    for (const sid of Object.keys(BusinessSnapshots.snapshots)) {
      if (BusinessSnapshots.snapshots[sid] && BusinessSnapshots.snapshots[sid]._demo_seed === true) seed_count++;
    }
  }
  return {
    enabled: VOICE_DEMO_DELTA_HARNESS_ENABLED,
    profiles_available: Object.keys(DEMO_DELTA_PROFILE),
    active_seed_snapshots: seed_count,
    note: "Demo scaffolding · NO capacidad de producto · simula evolución temporal para validar prelude S.G.",
  };
}

