// ════════════════════════════════════════════════════════════════════════════
// BRIEF U · U.A · INDUSTRY CATALOG + INFERENCE ENGINE  (Calibración por Industria)
//
// MANIFIESTO U: "ADI no analiza en el vacío · entiende el sector. Un DOH de 90 días
// es normal en construcción y crítico en retail. ADI calibra su criterio según la
// industria de cada cuenta · porque el mismo número significa cosas distintas según
// dónde se mide."
//
// U.A cubre "entiende el sector": catálogo de industrias + motor de inferencia
// determinístico que asigna sector a cada entidad.
//
// SCOPE FIRMADO:
//   · D-U.A-1 · C · 4 sectores: retail + construccion + consumo_masivo + generico
//                   (catálogo EXTENSIBLE · industrial agregable a futuro sin re-tocar)
//   · D-U.A-2 · B · señal: canonical_name curado PRIMERO → sfamilia fallback → genérico
//   · D-U.A-3 · B · profile 4 dims (doh + margin + rotation + carga)
//                   ⚠️ valores DERIVADOS del dataset real donde hay ≥2 muestras,
//                   marcados como ASUNCIÓN ajustable donde no. NO inventados.
//   · D-U.A-4 · A · solo sfamilia + canonical_name (marca/canal transversales · excluidos)
//
// DISCIPLINA: cero LLM · cero randomness · primer match wins · fallback genérico
// siempre disponible (D-U-3 · nunca null). Cero touch BRIEF R + S + S+ LOCKED.
//
// FUENTE DE VALORES PROFILE (auditoría dataset bonanza · condición D-U.A-3):
//   · DOH/rotación: derivados de SKUs agrupados por sfamilia→sector
//   · margen: derivado de SKUs por sector (consistente con DOH)
//   · carga: derivado de clientes por sector
//   · generico: derivado de portfolio.doh_promedio (62) + asunción donde no hay señal
// ════════════════════════════════════════════════════════════════════════════

// Flag rollback granular U.A.
const VOICE_INDUSTRY_CATALOG_ENABLED = true;

// INDUSTRY_CATALOG · 4 sectores (D-U.A-1 C · extensible).
// profile · 4 dimensiones (D-U.A-3 B) · valores con fuente documentada:
//   [DERIVADO] = promedio real del dataset bonanza (≥2 muestras)
//   [ASUNCIÓN] = valor de referencia inicial · ajustable cuando haya datos sectoriales reales
const INDUSTRY_CATALOG = {
  retail: {
    id: "retail",
    label: "Retail",
    // Tiendas departamentales / electro · Falabella, Ripley, Paris, etc.
    profile: {
      typical_doh: 53,            // [DERIVADO] avg DOH SKUs Electrodomésticos+Línea Blanca (n=6)
      typical_margin_pct: 20,     // [DERIVADO] avg margen SKUs retail (n=6 · 20.3 redondeado)
      typical_rotation: 6.0,      // [DERIVADO] avg rotación SKUs retail (n=6)
      typical_carga_pct: 3.7,     // [DERIVADO] avg carga comercial clientes retail (n=7)
    },
  },
  construccion: {
    id: "construccion",
    label: "Construcción",
    // Materiales de construcción · Sodimac, Easy · ciclos largos, obra en curso.
    profile: {
      typical_doh: 90,            // [DERIVADO] avg DOH SKUs Materiales de Construcción (n=4) · EL MANIFIESTO
      typical_margin_pct: 21,     // [DERIVADO] avg margen SKUs construcción (n=4)
      typical_rotation: 3.9,      // [DERIVADO] avg rotación SKUs construcción (n=4)
      typical_carga_pct: 5.5,     // [DERIVADO] avg carga comercial clientes construcción (n=2 · Sodimac+Easy)
    },
  },
  consumo_masivo: {
    id: "consumo_masivo",
    label: "Consumo Masivo",
    // Supermercados · Jumbo, Tottus, Unimarc, Lider · rotación alta, DOH bajo.
    profile: {
      typical_doh: 43,            // [DERIVADO] avg DOH SKUs Cuidado Personal (n=3)
      typical_margin_pct: 26,     // [DERIVADO] avg margen SKUs consumo masivo (n=3)
      typical_rotation: 7.9,      // [DERIVADO] avg rotación SKUs consumo masivo (n=3)
      typical_carga_pct: 3.5,     // [DERIVADO] avg carga comercial clientes consumo masivo (n=4)
    },
  },
  generico: {
    id: "generico",
    label: "Genérico",
    // Fallback D-U-3 · promedio cross-sector · usado cuando no se conoce el sector.
    profile: {
      typical_doh: 62,            // [DERIVADO] portfolio.doh_promedio del aggregator
      typical_margin_pct: 22,     // [ASUNCIÓN] referencia inicial · ajustable (avg aprox cross-sector)
      typical_rotation: 6.0,      // [ASUNCIÓN] referencia inicial · ajustable
      typical_carga_pct: 4.0,     // [ASUNCIÓN] referencia inicial · ajustable
    },
  },
};

// INDUSTRY_INFERENCE_RULES · reglas determinísticas · orden = prioridad (primer match wins).
// D-U.A-2 B: canonical_name curado PRIMERO (certeza) → sfamilia fallback (robusto).
// D-U.A-4 A: solo señales canonical_name + sfamilia (marca/canal excluidos · transversales).
const INDUSTRY_INFERENCE_RULES = [
  // ── Bloque 1 · canonical_name curado (certeza · clientes conocidos Innova Ferre) ──
  { signal: "canonical_name", match: "Sodimac",       industry: "construccion" },
  { signal: "canonical_name", match: "Easy",          industry: "construccion" },
  { signal: "canonical_name", match: "Jumbo",         industry: "consumo_masivo" },
  { signal: "canonical_name", match: "Tottus",        industry: "consumo_masivo" },
  { signal: "canonical_name", match: "Unimarc",       industry: "consumo_masivo" },
  { signal: "canonical_name", match: "Lider",         industry: "consumo_masivo" },
  { signal: "canonical_name", match: "Falabella",     industry: "retail" },
  { signal: "canonical_name", match: "Ripley",        industry: "retail" },
  { signal: "canonical_name", match: "Paris",         industry: "retail" },
  { signal: "canonical_name", match: "La Polar",      industry: "retail" },
  { signal: "canonical_name", match: "Hites",         industry: "retail" },
  { signal: "canonical_name", match: "ABC",           industry: "retail" },
  { signal: "canonical_name", match: "Mercado Libre", industry: "retail" },
  // ── Bloque 2 · sfamilia fallback (robusto · clientes nuevos no curados) ──
  { signal: "sfamilia", match: "Materiales de Construcción", industry: "construccion" },
  { signal: "sfamilia", match: "Cuidado Personal",           industry: "consumo_masivo" },
  { signal: "sfamilia", match: "Electrodomésticos",          industry: "retail" },
  { signal: "sfamilia", match: "Línea Blanca",               industry: "retail" },
];

// ── inferIndustry · determinístico · primer match wins · genérico fallback (D-U-3) ──
function inferIndustry(entity) {
  if (!VOICE_INDUSTRY_CATALOG_ENABLED) return "generico";
  if (!entity || typeof entity !== "object") return "generico";
  const md = entity.metadata || entity; // acepta entity completa o objeto plano con señales
  for (const rule of INDUSTRY_INFERENCE_RULES) {
    let value = null;
    if (rule.signal === "canonical_name") {
      value = entity.canonical_name || md.canonical_name || null;
    } else if (rule.signal === "sfamilia") {
      value = md.sfamilia || null;
    }
    if (value && value === rule.match && INDUSTRY_CATALOG[rule.industry]) {
      return rule.industry;
    }
  }
  return "generico"; // D-U-3 · nunca null
}

// ── getIndustryProfile · perfil del sector (4 dims) ──
function getIndustryProfile(industry_id) {
  if (!VOICE_INDUSTRY_CATALOG_ENABLED) return null;
  const sector = INDUSTRY_CATALOG[industry_id] || INDUSTRY_CATALOG["generico"];
  return sector ? Object.assign({}, sector.profile) : null;
}

// ── listIndustries · catálogo de sectores ──
function listIndustries() {
  if (!VOICE_INDUSTRY_CATALOG_ENABLED) return [];
  return Object.keys(INDUSTRY_CATALOG).map(k => ({
    id: INDUSTRY_CATALOG[k].id,
    label: INDUSTRY_CATALOG[k].label,
  }));
}

// ── getIndustryCatalogStats · transparencia ──
function getIndustryCatalogStats() {
  return {
    enabled: VOICE_INDUSTRY_CATALOG_ENABLED,
    sectors_count: Object.keys(INDUSTRY_CATALOG).length,
    sectors: Object.keys(INDUSTRY_CATALOG),
    rules_count: INDUSTRY_INFERENCE_RULES.length,
    rules_by_signal: INDUSTRY_INFERENCE_RULES.reduce((acc, r) => {
      acc[r.signal] = (acc[r.signal] || 0) + 1; return acc;
    }, {}),
    profile_dimensions: ["typical_doh", "typical_margin_pct", "typical_rotation", "typical_carga_pct"],
  };
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF U · U.A · INDUSTRY CATALOG + INFERENCE ENGINE
