// ════════════════════════════════════════════════════════════════════════════
// BRIEF U · U.B · INDUSTRY ASSIGNMENT LAYER  (Calibración por Industria)
//
// Aplica inferIndustry (U.A) a las entidades del registry + override manual.
//
// SCOPE FIRMADO:
//   · D-U.B-1 · C · lazy getEntityIndustry (infiere si null) + assign explícito
//   · D-U.B-2 · A · solo kind=client (SKUs/brands/familias transversales)
//   · D-U.B-3 · A · overrideIndustry valida contra catálogo · rechaza inválidos
//   · D-U.B-4 · A · re-asignar respeta override manual (flag industry_override)
//
// HALLAZGO PERSISTENCIA (filtro #3):
//   updateEntityMetadata (S.A) es runtime-only · el registry se reinicializa desde
//   datasets cada parse (industry:null). Los cambios NO sobreviven reload. Por eso
//   getEntityIndustry usa LAZY inference: si metadata.industry es null, infiere
//   on-demand vía inferIndustry. Esto hace la persistencia IRRELEVANTE para industria
//   (re-inferible determinística). Solo overrides manuales se perderían en reload.
//   Deuda registrada: #D-REGISTRY-METADATA-PERSISTENCE-POST-MVP (baja prioridad).
//
// DISCIPLINA: cero LLM · cero randomness · usa solo APIs públicas S.A
// (updateEntityMetadata, getEntitiesByKind, getEntityById) · cero touch estructura.
// ════════════════════════════════════════════════════════════════════════════

// Flag rollback granular U.B.
const VOICE_INDUSTRY_ASSIGNMENT_ENABLED = true;

// ── assignIndustriesToRegistry · asigna sector a clients vía inferIndustry ──
// D-U.B-2 A: solo kind=client. D-U.B-4 A: salta los que tienen industry_override.
// Retorna { assigned_count, by_industry, skipped_overrides }
function assignIndustriesToRegistry() {
  if (!VOICE_INDUSTRY_ASSIGNMENT_ENABLED) {
    return { assigned_count: 0, by_industry: {}, skipped_overrides: 0 };
  }
  if (typeof getEntitiesByKind !== "function" || typeof updateEntityMetadata !== "function" || typeof inferIndustry !== "function") {
    return { assigned_count: 0, by_industry: {}, skipped_overrides: 0 };
  }
  const clients = getEntitiesByKind("client");
  let assigned_count = 0;
  let skipped_overrides = 0;
  const by_industry = {};
  for (const c of clients) {
    if (!c || !c.id) continue;
    // D-U.B-4 · respetar override manual previo · NO sobrescribir
    if (c.metadata && c.metadata.industry_override === true) {
      skipped_overrides++;
      const ind = c.metadata.industry || "generico";
      by_industry[ind] = (by_industry[ind] || 0) + 1;
      continue;
    }
    const industry = inferIndustry(c);
    updateEntityMetadata(c.id, { industry });
    assigned_count++;
    by_industry[industry] = (by_industry[industry] || 0) + 1;
  }
  return { assigned_count, by_industry, skipped_overrides };
}

// ── getEntityIndustry · lookup con LAZY inference (D-U.B-1 C) ────────────────
// 1. lookup metadata.industry · 2. si null → inferIndustry lazy · 3. nunca null (D-U-3).
function getEntityIndustry(entity_id) {
  if (!VOICE_INDUSTRY_ASSIGNMENT_ENABLED) return "generico";
  if (typeof getEntityById !== "function") return "generico";
  const entity = getEntityById(entity_id);
  if (!entity) return "generico";
  // 1 · metadata.industry ya asignada
  if (entity.metadata && typeof entity.metadata.industry === "string" && entity.metadata.industry.length > 0) {
    return entity.metadata.industry;
  }
  // 2 · lazy inference (D-U.B-1 C · funciona aunque no se haya corrido assign)
  if (typeof inferIndustry === "function") {
    return inferIndustry(entity);
  }
  // 3 · fallback genérico (D-U-3)
  return "generico";
}

// ── overrideIndustry · asignación manual · valida catálogo (D-U.B-3 A) ──────
// Setea metadata.industry + industry_override:true (D-U.B-4). Rechaza inválidos.
function overrideIndustry(entity_id, industry_id) {
  if (!VOICE_INDUSTRY_ASSIGNMENT_ENABLED) return null;
  if (typeof industry_id !== "string") return null;
  // D-U.B-3 · validar contra catálogo · rechaza sectores inexistentes
  if (typeof INDUSTRY_CATALOG === "undefined" || !INDUSTRY_CATALOG[industry_id]) return null;
  if (typeof updateEntityMetadata !== "function") return null;
  return updateEntityMetadata(entity_id, { industry: industry_id, industry_override: true });
}

// ── getAssignmentStats · transparencia ──────────────────────────────────────
function getAssignmentStats() {
  if (!VOICE_INDUSTRY_ASSIGNMENT_ENABLED) return { enabled: false };
  const clients = (typeof getEntitiesByKind === "function") ? getEntitiesByKind("client") : [];
  let assigned = 0, overrides = 0, unassigned = 0;
  const by_industry = {};
  for (const c of clients) {
    const md = c.metadata || {};
    if (md.industry_override === true) overrides++;
    if (typeof md.industry === "string" && md.industry.length > 0) {
      assigned++;
      by_industry[md.industry] = (by_industry[md.industry] || 0) + 1;
    } else {
      unassigned++;
    }
  }
  return {
    enabled: VOICE_INDUSTRY_ASSIGNMENT_ENABLED,
    total_clients: clients.length,
    assigned,
    unassigned,
    overrides,
    by_industry,
    note: "Industria runtime-only · getEntityIndustry infiere lazy si no asignada (re-inferible determinística).",
  };
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF U · U.B · INDUSTRY ASSIGNMENT LAYER
// ════════════════════════════════════════════════════════════════════════════


// ════════════════════════════════════════════════════════════════════════════
// BRIEF U · U.C · SECTORAL THRESHOLDS ENGINE  ⭐ CASO FUNDACIONAL
//
// MANIFIESTO: "Un DOH de 90 días es normal en construcción y crítico en retail."
// U.C cubre "normal construcción · crítico retail": thresholds calibrados por sector.
//
// SCOPE FIRMADO:
//   · D-U.C-1 · A · 4 dimensiones (DOH + margen + carga + rotación)
//   · D-U.C-2 · A · niveles semánticos por dirección:
//                   DOH/carga (más es PEOR): normal / elevated / critical
//                   margen/rotación (más es MEJOR): healthy / pressured / critical
//   · D-U.C-3 · C · valores explícitos · JSDoc documenta derivación de typical U.A
//   · D-U.C-4 · A · classifyBySector(value, dimension, industry_id) · motor PURO
//   · D-U.C-5 · A · fallback genérico (sector desconocido) · null (dimensión inexistente)
//
// TRAZABILIDAD (condición D-U.C-3 · cadena de honestidad U.A→U.C):
//   Cada threshold deriva del typical_* de INDUSTRY_CATALOG (U.A · derivado del dataset).
//   DOH/carga: normal = typical · elevated = typical×1.3 · critical = elevated×1.2
//   margen/rotación: healthy = typical · pressured = typical×0.8 · critical = pressured×0.8
//   El caso fundacional sale de datos reales: DOH 90 construcción (typical 90) = normal,
//   DOH 90 retail (typical 53 · critical 83) = critical. NO inventado.
//
// DISCIPLINA: cero LLM · cero randomness · catálogo fijo extensible · motor puro.
// ════════════════════════════════════════════════════════════════════════════

// Flag rollback granular U.C.
const VOICE_SECTORAL_THRESHOLDS_ENABLED = true;

// SECTORAL_THRESHOLDS · thresholds calibrados por sector (D-U.C-1/2/3).
// Cada bloque documenta el typical_* U.A fuente + la fórmula de derivación.
const SECTORAL_THRESHOLDS = {
  // ── DOH · días de inventario · MÁS ES PEOR · normal/elevated/critical ──
  // Derivación: normal = typical_doh U.A · elevated = ×1.3 · critical = elevated×1.2
  DOH: {
    retail:        { normal: 53,  elevated: 69,  critical: 83 },
    // typical_doh U.A retail = 53 [DERIVADO n=6 SKU] · elevated 53×1.3=69 · critical 69×1.2=83
    construccion:  { normal: 90,  elevated: 117, critical: 140 },
    // typical_doh U.A construcción = 90 [DERIVADO n=4 SKU Materiales] · elevated 117 · critical 140 · ⭐ DOH 90 ≤ normal → "normal"
    consumo_masivo:{ normal: 43,  elevated: 56,  critical: 67 },
    // typical_doh U.A consumo_masivo = 43 [DERIVADO n=3 SKU] · elevated 56 · critical 67
    generico:      { normal: 62,  elevated: 81,  critical: 97 },
    // typical_doh U.A genérico = 62 [DERIVADO portfolio.doh_promedio] · elevated 81 · critical 97
  },
  // ── carga_comercial_pct · MÁS ES PEOR · normal/elevated/critical ──
  carga_comercial_pct: {
    retail:        { normal: 3.7, elevated: 4.8, critical: 5.8 },
    // typical_carga U.A retail = 3.7 [DERIVADO n=7 clientes] · elevated 4.8 · critical 5.8
    construccion:  { normal: 5.5, elevated: 7.2, critical: 8.6 },
    // typical_carga U.A construcción = 5.5 [DERIVADO n=2 clientes] · elevated 7.2 · critical 8.6
    consumo_masivo:{ normal: 3.5, elevated: 4.6, critical: 5.5 },
    // typical_carga U.A consumo_masivo = 3.5 [DERIVADO n=4 clientes] · elevated 4.6 · critical 5.5
    generico:      { normal: 4.0, elevated: 5.2, critical: 6.2 },
    // typical_carga U.A genérico = 4.0 [ASUNCIÓN U.A] · elevated 5.2 · critical 6.2
  },
  // ── margen_pct · MÁS ES MEJOR · healthy/pressured/critical (dirección inversa) ──
  // Derivación: healthy = typical_margin · pressured = ×0.8 · critical = pressured×0.8
  margen_pct: {
    retail:        { healthy: 20, pressured: 16,   critical: 12.8 },
    // typical_margin U.A retail = 20 [DERIVADO n=6 SKU] · pressured 16 · critical 12.8
    construccion:  { healthy: 21, pressured: 16.8, critical: 13.4 },
    // typical_margin U.A construcción = 21 [DERIVADO n=4 SKU] · pressured 16.8 · critical 13.4
    consumo_masivo:{ healthy: 26, pressured: 20.8, critical: 16.6 },
    // typical_margin U.A consumo_masivo = 26 [DERIVADO n=3 SKU] · pressured 20.8 · critical 16.6
    generico:      { healthy: 22, pressured: 17.6, critical: 14.1 },
    // typical_margin U.A genérico = 22 [ASUNCIÓN U.A] · pressured 17.6 · critical 14.1
  },
  // ── rotacion · MÁS ES MEJOR · healthy/pressured/critical (dirección inversa) ──
  rotacion: {
    retail:        { healthy: 6.0, pressured: 4.8, critical: 3.8 },
    // typical_rotation U.A retail = 6.0 [DERIVADO n=6 SKU] · pressured 4.8 · critical 3.8
    construccion:  { healthy: 3.9, pressured: 3.1, critical: 2.5 },
    // typical_rotation U.A construcción = 3.9 [DERIVADO n=4 SKU] · pressured 3.1 · critical 2.5
    consumo_masivo:{ healthy: 7.9, pressured: 6.3, critical: 5.0 },
    // typical_rotation U.A consumo_masivo = 7.9 [DERIVADO n=3 SKU] · pressured 6.3 · critical 5.0
    generico:      { healthy: 6.0, pressured: 4.8, critical: 3.8 },
    // typical_rotation U.A genérico = 6.0 [ASUNCIÓN U.A] · pressured 4.8 · critical 3.8
  },
};

// Dirección por dimensión: "higher_worse" (DOH/carga) o "higher_better" (margen/rotación).
// Gobierna la semántica de classifyBySector.
const _THRESHOLD_DIRECTION = {
  DOH: "higher_worse",
  carga_comercial_pct: "higher_worse",
  margen_pct: "higher_better",
  rotacion: "higher_better",
};

// ── resolveThreshold · obtiene threshold(s) por dimensión × sector ──────────
// D-U.C-5: sector desconocido → generico. Dimensión inexistente → null.
// level opcional: retorna el número de ese nivel · sin level: retorna el objeto completo.
function resolveThreshold(dimension, industry_id, level) {
  if (!VOICE_SECTORAL_THRESHOLDS_ENABLED) return null;
  const dim = SECTORAL_THRESHOLDS[dimension];
  if (!dim) return null; // dimensión inexistente · honest
  const sector = dim[industry_id] || dim["generico"]; // fallback genérico (D-U.C-5)
  if (!sector) return null;
  if (typeof level === "string") {
    return typeof sector[level] === "number" ? sector[level] : null;
  }
  return Object.assign({}, sector);
}

// ── classifyBySector · motor PURO · clasifica valor por sector (D-U.C-4) ────
// DOH/carga (higher_worse): value ≤ normal → "normal" · ≤ elevated → "elevated" · else "critical"
// margen/rotación (higher_better): value ≥ healthy → "healthy" · ≥ pressured → "pressured" · else "critical"
function classifyBySector(value, dimension, industry_id) {
  if (!VOICE_SECTORAL_THRESHOLDS_ENABLED) return null;
  if (typeof value !== "number") return null;
  const t = resolveThreshold(dimension, industry_id);
  if (!t) return null; // dimensión inexistente · null
  const direction = _THRESHOLD_DIRECTION[dimension];
  if (direction === "higher_worse") {
    if (value <= t.normal) return "normal";
    if (value <= t.elevated) return "elevated";
    return "critical";
  } else { // higher_better
    if (value >= t.healthy) return "healthy";
    if (value >= t.pressured) return "pressured";
    return "critical";
  }
}

// ── getThresholdsStats · transparencia ──────────────────────────────────────
function getThresholdsStats() {
  return {
    enabled: VOICE_SECTORAL_THRESHOLDS_ENABLED,
    dimensions: Object.keys(SECTORAL_THRESHOLDS),
    dimensions_count: Object.keys(SECTORAL_THRESHOLDS).length,
    sectors_per_dimension: Object.keys(SECTORAL_THRESHOLDS.DOH).length,
    direction_map: Object.assign({}, _THRESHOLD_DIRECTION),
    note: "Thresholds derivados de typical_* U.A (dataset real). DOH/carga higher_worse · margen/rotación higher_better.",
  };
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF U · U.C · SECTORAL THRESHOLDS ENGINE ⭐ CASO FUNDACIONAL
// ════════════════════════════════════════════════════════════════════════════


// ════════════════════════════════════════════════════════════════════════════
// BRIEF U · U.D · SECTORAL BENCHMARK ENGINE  (Calibración por Industria)
//
// MANIFIESTO: "el mismo número significa cosas distintas según dónde se mide."
// U.D cubre la comparación contra referencia sectorial: "este valor está X% sobre/bajo
// el benchmark de su sector". Complementa U.C (clasificación) con comparación cuantitativa.
//
// SCOPE FIRMADO:
//   · D-U.D-1 · C · benchmarks explícitos = typical_* U.A · JSDoc trazabilidad
//   · D-U.D-2 · B · computeBenchmarkGap incluye interpretation de negocio
//                   (caso "at" gap=0 → "en_benchmark" · no mejor/peor)
//   · D-U.D-3 · A · independiente · NO lee ni toca el benchmark genérico R (30.1% / 3.5%)
//   · D-U.D-4 · A · 4 dims · fallback genérico (sector) · null (dimensión inexistente)
//   · ESTRUCTURA · dimensión→sector (igual U.C) · getBenchmark(dim, sector) mismo
//                  orden de args que resolveThreshold(dim, sector) · consistencia API
//
// TRAZABILIDAD (cadena honestidad U.A→U.D):
//   Cada benchmark = typical_* de INDUSTRY_CATALOG (U.A · derivado del dataset real).
//   El benchmark sectorial ES el valor típico/esperado del sector. NO inventado.
//
// DESACOPLAMIENTO: U.D reutiliza _THRESHOLD_DIRECTION de U.C (solo LECTURA · cero touch).
// U.D NO lee benchmark_pct/target_carga del cerebro R (capas separadas).
//
// DISCIPLINA: cero LLM · cero randomness · catálogo fijo · motor puro.
// ════════════════════════════════════════════════════════════════════════════

// Flag rollback granular U.D.
const VOICE_SECTORAL_BENCHMARK_ENABLED = true;

// SECTORAL_BENCHMARKS · estructura dimensión→sector (igual U.C · consistencia API).
// Cada benchmark = typical_* de U.A (derivado del dataset · documentado).
const SECTORAL_BENCHMARKS = {
  // doh · = typical_doh U.A
  doh: {
    retail: 53,         // typical_doh U.A retail [DERIVADO n=6 SKU]
    construccion: 90,   // typical_doh U.A construcción [DERIVADO n=4 SKU Materiales]
    consumo_masivo: 43, // typical_doh U.A consumo_masivo [DERIVADO n=3 SKU]
    generico: 62,       // typical_doh U.A genérico [DERIVADO portfolio.doh_promedio]
  },
  // margen_pct · = typical_margin_pct U.A
  margen_pct: {
    retail: 20,         // typical_margin U.A retail [DERIVADO n=6 SKU]
    construccion: 21,   // typical_margin U.A construcción [DERIVADO n=4 SKU]
    consumo_masivo: 26, // typical_margin U.A consumo_masivo [DERIVADO n=3 SKU]
    generico: 22,       // typical_margin U.A genérico [ASUNCIÓN U.A]
  },
  // rotacion · = typical_rotation U.A
  rotacion: {
    retail: 6.0,        // typical_rotation U.A retail [DERIVADO n=6 SKU]
    construccion: 3.9,  // typical_rotation U.A construcción [DERIVADO n=4 SKU]
    consumo_masivo: 7.9,// typical_rotation U.A consumo_masivo [DERIVADO n=3 SKU]
    generico: 6.0,      // typical_rotation U.A genérico [ASUNCIÓN U.A]
  },
  // carga_comercial_pct · = typical_carga_pct U.A
  carga_comercial_pct: {
    retail: 3.7,        // typical_carga U.A retail [DERIVADO n=7 clientes]
    construccion: 5.5,  // typical_carga U.A construcción [DERIVADO n=2 clientes]
    consumo_masivo: 3.5,// typical_carga U.A consumo_masivo [DERIVADO n=4 clientes]
    generico: 4.0,      // typical_carga U.A genérico [ASUNCIÓN U.A]
  },
};

// ── getBenchmark · referencia sectorial por dimensión × sector ──────────────
// D-U.D-4: sector desconocido → generico. Dimensión inexistente → null.
function getBenchmark(dimension, industry_id) {
  if (!VOICE_SECTORAL_BENCHMARK_ENABLED) return null;
  const dim = SECTORAL_BENCHMARKS[dimension];
  if (!dim) return null; // dimensión inexistente · honest
  const bm = (typeof dim[industry_id] === "number") ? dim[industry_id] : dim["generico"];
  return (typeof bm === "number") ? bm : null;
}

// ── computeBenchmarkGap · gap vs benchmark sectorial + interpretación negocio ─
// Retorna { gap, gap_pct, direction, interpretation } | null
//   direction: "above" | "below" | "at" (signo crudo del gap)
//   interpretation: según _THRESHOLD_DIRECTION (U.C · solo lee):
//     higher_worse (DOH/carga):  above → peor · below → mejor
//     higher_better (margen/rot): above → mejor · below → peor
//     gap=0 → "en_benchmark" (D-U.D-2 · caso "at")
function computeBenchmarkGap(value, dimension, industry_id) {
  if (!VOICE_SECTORAL_BENCHMARK_ENABLED) return null;
  if (typeof value !== "number") return null;
  const bm = getBenchmark(dimension, industry_id);
  if (bm === null) return null; // dimensión inexistente
  const gap = Math.round((value - bm) * 10) / 10;
  const gap_pct = (bm !== 0) ? Math.round((gap / bm) * 1000) / 10 : null;
  // direction · signo crudo
  let direction;
  if (gap > 0) direction = "above";
  else if (gap < 0) direction = "below";
  else direction = "at";
  // interpretation · semántica de negocio según dirección de la dimensión
  let interpretation;
  if (direction === "at") {
    interpretation = "en_benchmark"; // D-U.D-2 · caso "at"
  } else {
    // _THRESHOLD_DIRECTION (U.C) usa clave "DOH" mayúscula · SECTORAL_BENCHMARKS (U.D)
    // usa "doh" minúscula (API que pide el BRIEF). Mapeo case-insensitive para leer
    // la dirección de U.C sin tocarlo (cero touch U.C LOCKED).
    const dir = _resolveBenchmarkDirection(dimension);
    if (dir === "higher_worse") {
      interpretation = (direction === "above") ? "peor_que_benchmark" : "mejor_que_benchmark";
    } else if (dir === "higher_better") {
      interpretation = (direction === "above") ? "mejor_que_benchmark" : "peor_que_benchmark";
    } else {
      interpretation = "fuera_de_benchmark"; // dimensión sin dirección catalogada (defensive)
    }
  }
  return { gap, gap_pct, direction, interpretation };
}

// ── _resolveBenchmarkDirection · helper · mapea dimensión U.D → dirección U.C ─
// U.D usa claves minúsculas (doh) · U.C _THRESHOLD_DIRECTION usa DOH mayúscula.
// Lookup case-insensitive · lee U.C sin modificarlo (cero touch U.C LOCKED).
function _resolveBenchmarkDirection(dimension) {
  if (typeof _THRESHOLD_DIRECTION === "undefined" || typeof dimension !== "string") return null;
  // match directo
  if (_THRESHOLD_DIRECTION[dimension]) return _THRESHOLD_DIRECTION[dimension];
  // match case-insensitive (doh → DOH)
  const lower = dimension.toLowerCase();
  for (const k of Object.keys(_THRESHOLD_DIRECTION)) {
    if (k.toLowerCase() === lower) return _THRESHOLD_DIRECTION[k];
  }
  return null;
}

// ── getBenchmarkStats · transparencia ───────────────────────────────────────
function getBenchmarkStats() {
  return {
    enabled: VOICE_SECTORAL_BENCHMARK_ENABLED,
    dimensions: Object.keys(SECTORAL_BENCHMARKS),
    dimensions_count: Object.keys(SECTORAL_BENCHMARKS).length,
    sectors_per_dimension: Object.keys(SECTORAL_BENCHMARKS.doh).length,
    note: "Benchmarks = typical_* U.A (dataset real). Independiente del benchmark genérico R. Interpretación vía _THRESHOLD_DIRECTION U.C.",
  };
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF U · U.D · SECTORAL BENCHMARK ENGINE
// ════════════════════════════════════════════════════════════════════════════


// ════════════════════════════════════════════════════════════════════════════
// BRIEF U · U.E · CALIBRATION RESOLVER  ⭐ INTEGRACIÓN · RESOLVER PURO
//
// MANIFIESTO U: "ADI calibra su criterio según la industria de cada cuenta."
// U.E es donde todo converge: entity → industria (U.B) → clasificación (U.C) →
// benchmark gap (U.D) → contexto sectorial narrado (constitución voz ADI).
//
// Patrón ESPEJO de S.G→S+:
//   S.A-S.F (piezas puras) · S.G (wrapper/resolver) · S+ (activación user-facing)
//   U.A-U.D (piezas puras) · U.E (resolver) · U+ futuro (activación user-facing al cerebro)
//
// SCOPE FIRMADO:
//   · D-U.E-1 · A · resolver puro · NO toca dispatcher/cerebro · activación U+ separado
//   · D-U.E-2 · A · flag default OFF (mandato BRIEF · paridad S.G)
//   · D-U.E-3 · A · API dimensión minúscula uniforme · _DIMENSION_KEY_MAP interno
//                   encapsula asimetría DOH (U.C mayúscula) / doh (U.D minúscula)
//   · D-U.E-4 · C · acepta entity (objeto) o entity_id (string)
//   · D-U.E-5 · A · sectoral_context plantilla fija · WORDING ESPAÑOL NATURAL
//                   ⚠️ NO anglicismos · etiquetas traducidas al user-facing:
//                     normal → "normal" · elevated → "algo elevado"
//                     critical → "crítico" · healthy → "saludable"
//                     pressured → "bajo presión"
//   · D-U.E-6 · A · 4 dimensiones (doh + margen + carga + rotación)
//
// AUDIT VOZ ADI · sectoral_context NO contiene:
//   · Anglicismos (elevated/pressured/healthy/critical en inglés)
//   · Vocabulario alarmista (deterioró/alarmante/preocupante/dramático)
//
// DISCIPLINA: cero LLM · cero randomness · resolver puro · cero touch R+S+S++U.A-U.D.
// ════════════════════════════════════════════════════════════════════════════

// Flag rollback granular U.E · default OFF (D-U.E-2 A · activación post-V_VISUAL).
const VOICE_CALIBRATION_RESOLVER_ENABLED = false;

// _DIMENSION_KEY_MAP · encapsula asimetría DOH/doh cross-motor (D-U.E-3 A).
// API U.E es minúscula uniforme · internamente traduce a la clave de cada motor.
const _DIMENSION_KEY_MAP = {
  doh:                 { thresholds: "DOH",                 benchmarks: "doh" },
  margen_pct:          { thresholds: "margen_pct",          benchmarks: "margen_pct" },
  rotacion:            { thresholds: "rotacion",            benchmarks: "rotacion" },
  carga_comercial_pct: { thresholds: "carga_comercial_pct", benchmarks: "carga_comercial_pct" },
};

// ── _DIMENSION_GENDER · género gramatical de cada dimensión (D-U+.A) ────────
// Soporta concordancia adjetival en español natural. D-U+.A-2: default "masc"
// para dimensión no catalogada (fallback español genérico).
const _DIMENSION_GENDER = {
  doh:                 "masc",  // "el DOH" (siglas masc por convención)
  margen_pct:          "masc",  // "el margen"
  rotacion:            "fem",   // "la rotación"
  carga_comercial_pct: "fem",   // "la carga comercial"
};

// ── Etiquetas español natural (D-U.E-5 · wording corregido founder) ──────────
const _CLASSIFICATION_LABEL_ES = {
  normal:     { masc: "normal",       fem: "normal" },          // invariante
  elevated:   { masc: "algo elevado", fem: "algo elevada" },    // D-U+.A concordancia
  critical:   { masc: "crítico",      fem: "crítica" },         // D-U+.A concordancia
  healthy:    { masc: "saludable",    fem: "saludable" },       // invariante
  pressured:  { masc: "bajo presión", fem: "bajo presión" },    // locución prep+sust · invariante
};

// Nombres de dimensión para display (user-facing).
const _DIMENSION_LABEL_ES = {
  doh:                 "DOH",
  margen_pct:          "margen",
  rotacion:            "rotación",
  carga_comercial_pct: "carga comercial",
};

// Unidad por dimensión (para wording natural).
const _DIMENSION_UNIT_ES = {
  doh:                 "días",
  margen_pct:          "%",
  rotacion:            "",
  carga_comercial_pct: "%",
};

// Nombres de sector para display.
const _INDUSTRY_LABEL_ES = {
  retail:         "retail",
  construccion:   "construcción",
  consumo_masivo: "consumo masivo",
  generico:       "genérico",
};

// ── _composeSectoralContext · narrativa español natural (D-U.E-5) ───────────
// Plantilla fija según clasificación + dirección de gap. Cero anglicismos · cero
// vocabulario alarmista. Honest factual neutro.
function _composeSectoralContext(calibration) {
  if (!calibration || typeof calibration !== "object") return "";
  const { dimension, value, industry, classification, benchmark, gap } = calibration;
  const dimLabel = _DIMENSION_LABEL_ES[dimension] || dimension;
  const unit = (_DIMENSION_UNIT_ES[dimension] != null) ? _DIMENSION_UNIT_ES[dimension] : "";
  const indLabel = _INDUSTRY_LABEL_ES[industry] || industry;
  // D-U+.A · concordancia adjetival · clasificación según género de la dimensión.
  // D-U+.A-2 · default "masc" si dimensión no catalogada en _DIMENSION_GENDER.
  const gender = _DIMENSION_GENDER[dimension] || "masc";
  const classEntry = _CLASSIFICATION_LABEL_ES[classification];
  const classLabel = (classEntry && typeof classEntry === "object")
    ? (classEntry[gender] || classEntry.masc || classification)
    : (classEntry || classification);
  // Verbo · "es" para sustantivo (normal/crítico/saludable) · "está" para estado (algo elevado/bajo presión).
  const useEstar = (classification === "elevated" || classification === "pressured");
  const verb = useEstar ? "está" : "es";
  // Valor + unidad: "90 días", "20%", "6"
  const valueStr = (unit === "%") ? (value + "%") : (unit ? (value + " " + unit) : String(value));
  // Benchmark + unidad
  const bmStr = (unit === "%") ? (benchmark + "%") : (unit === "días") ? (benchmark + " días") : String(benchmark);
  // Construcción según gap interpretation
  let tail;
  if (!gap || gap.interpretation === "en_benchmark") {
    tail = "en línea con el benchmark del sector (" + bmStr + ").";
  } else {
    const pct = Math.abs(gap.gap_pct);
    if (gap.interpretation === "peor_que_benchmark") {
      // higher_worse arriba · higher_better abajo
      const side = (gap.direction === "above") ? "sobre" : "bajo";
      tail = pct + "% " + side + " el benchmark del sector (" + bmStr + ").";
    } else if (gap.interpretation === "mejor_que_benchmark") {
      const side = (gap.direction === "above") ? "sobre" : "bajo";
      tail = pct + "% " + side + " el benchmark del sector (" + bmStr + ").";
    } else {
      tail = "fuera del benchmark del sector (" + bmStr + ").";
    }
  }
  return dimLabel + " " + valueStr + " " + verb + " " + classLabel + " para " + indLabel + ", " + tail;
}

// ── resolveCalibration · resolver puro · orquesta U.B+U.C+U.D ───────────────
// D-U.E-4 C: acepta entity (objeto) o entity_id (string).
// D-U.E-2 A: flag default OFF · `force_enabled` o flag true habilita.
// Retorna calibration completa o null si flag OFF/inputs inválidos.
function resolveCalibration(dimension, entity_or_id, value, options) {
  // 1 · Flag gate (D-U.E-2)
  const force_enabled = !!(options && options.force_enabled === true);
  if (!VOICE_CALIBRATION_RESOLVER_ENABLED && !force_enabled) return null;
  // 2 · Validar inputs
  if (typeof dimension !== "string" || !_DIMENSION_KEY_MAP[dimension]) return null;
  if (typeof value !== "number") return null;
  // 3 · Resolver entity (D-U.E-4 C · acepta string u objeto)
  let entity = null;
  if (typeof entity_or_id === "string") {
    if (typeof getEntityById === "function") entity = getEntityById(entity_or_id);
  } else if (entity_or_id && typeof entity_or_id === "object") {
    entity = entity_or_id;
  }
  if (!entity || !entity.id) return null;
  // 4 · Resolver industria (U.B · lazy)
  const industry = (typeof getEntityIndustry === "function") ? getEntityIndustry(entity.id) : "generico";
  // 5 · Mapear dimension → claves cross-motor (D-U.E-3)
  const keyMap = _DIMENSION_KEY_MAP[dimension];
  // 6 · U.C · threshold + classification
  const threshold = (typeof resolveThreshold === "function") ? resolveThreshold(keyMap.thresholds, industry) : null;
  const classification = (typeof classifyBySector === "function") ? classifyBySector(value, keyMap.thresholds, industry) : null;
  // 7 · U.D · benchmark + gap
  const benchmark = (typeof getBenchmark === "function") ? getBenchmark(keyMap.benchmarks, industry) : null;
  const gap = (typeof computeBenchmarkGap === "function") ? computeBenchmarkGap(value, keyMap.benchmarks, industry) : null;
  // 8 · Componer calibration
  const calibration = {
    dimension,
    value,
    entity_id: entity.id,
    industry,
    benchmark,
    threshold,
    classification,
    gap,
    sectoral_context: "", // se rellena abajo
  };
  // 9 · sectoral_context (D-U.E-5 · español natural)
  calibration.sectoral_context = _composeSectoralContext(calibration);
  return calibration;
}

// ── getCalibrationStats · transparencia ─────────────────────────────────────
function getCalibrationStats() {
  return {
    enabled: VOICE_CALIBRATION_RESOLVER_ENABLED,
    dimensions_exposed: Object.keys(_DIMENSION_KEY_MAP),
    classification_labels: Object.assign({}, _CLASSIFICATION_LABEL_ES),
    industry_labels: Object.assign({}, _INDUSTRY_LABEL_ES),
    pattern: "resolver puro · orquesta U.B (industry) + U.C (classify) + U.D (gap) · español neutro",
    note: "Flag default OFF · activación user-facing al cerebro es momento BRIEF U+ separado (paridad S.G→S+).",
  };
}

