// ════════════════════════════════════════════════════════════════════════════
// BRIEF U+ · U+.B · ACTIVACIÓN CEREBRO USER-FACING ⭐ TOUCH CONSCIENTE
//
// MANIFIESTO U+ user-facing: ADI deja de tener la calibración como motor invisible
// y la entrega como insight visible (Variante 4 · "Nota sectorial · ... refuerza/matiza
// la lectura del cliente"). Espejo arquitectónico de S.G→S+:
//
//   S.G (resolver) → S+ (activación dispatcher · prependDeltaToNarrative)
//   U.E (resolver) → U+.B (activación dispatcher · appendCalibrationToNarrative)
//
// SCOPE FIRMADO U+.B:
//   · D-U+.B-1 · Variante 4 · Tip "Nota sectorial" + cierre adaptativo refuerza/matiza
//   · D-U+.B-2 · A · wrapper appendCalibrationToNarrative (espejo prependDeltaToNarrative)
//   · D-U+.B-3 · B'+C+max1 · intent v2 AND ≥1 entity pressured/elevated/critical AND max 1 entity
//                Selección: Opción B "más mencionada en R.I V2" · fallback "más severa"
//   · D-U+.B-4 · A · cooldown _calibrationShownThisLoad page-load
//   · D-U+.B-5 · A · VOICE_CALIBRATION_INTEGRATOR_ENABLED = false default + rollback variant
//   · D-U+.B-6 · A · touch consciente línea 31094 PanelADI (paridad S+)
//
// 4 CAPAS DEFENSIVAS · flag OFF, intent ≠ v2, cooldown ya mostrado, sin entity relevante
//   → return narrative original bitwise.
//
// VOZ ADI · NO alarmista · sectoral_context de U.E ya pasa audit (cero anglicismos/alarmista).
// ════════════════════════════════════════════════════════════════════════════

// Flag rollback granular U+.B · ACTIVADO user-facing · activación consciente firmada founder.
const VOICE_CALIBRATION_INTEGRATOR_ENABLED = true;

// Cooldown page-load · paralelo _deltaPreludeShownThisLoad (S+).
let _calibrationShownThisLoad = false;

// ── Dimensiones candidatas por entity · prioridad de calibración ────────────
// Orden: la más severa primero. Dimensiones que el cerebro discute más en R.I V2:
//   carga_comercial_pct (presión de cuenta) · margen_pct (calidad) · doh (capital) · rotacion
const _U_PLUS_CALIBRATION_DIMS = ["carga_comercial_pct", "margen_pct", "doh", "rotacion"];

// Severidad de clasificación · ordenamiento para selección "más severa" (fallback).
const _U_PLUS_SEVERITY_RANK = { critical: 3, elevated: 2, pressured: 2, normal: 1, healthy: 1 };

// Clasificaciones que disparan el gate de relevancia B' (no-healthy/no-normal).
const _U_PLUS_RELEVANT_CLASSIFICATIONS = ["critical", "elevated", "pressured"];

// ── _resetCalibrationCooldown · testing/runtime reset ───────────────────────
function _resetCalibrationCooldown() {
  _calibrationShownThisLoad = false;
}

// ── _countEntityMentionsInNarrative · selección Opción B "más mencionada" ──
// Recibe el opener narrativo (string) y la lista de entity registry (clientes).
// Retorna { entity_id → mention_count } solo para los que aparecen ≥1 vez.
function _countEntityMentionsInNarrative(narrativeText, clients) {
  const counts = {};
  if (typeof narrativeText !== "string" || !Array.isArray(clients)) return counts;
  for (const c of clients) {
    if (!c || !c.canonical_name) continue;
    // Match por canonical_name (case-insensitive · word-boundary aproximado)
    const re = new RegExp("\\b" + c.canonical_name.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "\\b", "gi");
    const matches = narrativeText.match(re);
    if (matches && matches.length > 0) counts[c.id] = matches.length;
  }
  return counts;
}

// ── _selectCalibrationCandidate · elige entity para mostrar (Opción B + fallback) ──
// 1) De las menciones, encontrar las que tienen ≥1 dimensión con clasificación relevante
// 2) Si hay varias → la MÁS MENCIONADA (Opción B firmada D-U+.B-3)
// 3) Fallback (ninguna mencionada relevante) → la MÁS SEVERA del registry
// Retorna { entity_id, calibration } o null si ninguna aplica.
function _selectCalibrationCandidate(narrativeText, scenarioId) {
  if (typeof getEntitiesByKind !== "function") return null;
  if (typeof takeBusinessSnapshot !== "function") return null;
  if (typeof resolveCalibration !== "function") return null;
  const clients = getEntitiesByKind("client");
  const snap = takeBusinessSnapshot(scenarioId);
  if (!snap || !snap.entities) return null;
  const mentions = _countEntityMentionsInNarrative(narrativeText, clients);

  // Construir candidatos: para cada entity, computar calibraciones en las dims candidatas
  // y elegir la más severa de esa entity. Solo conservamos entities con ≥1 dim relevante.
  const candidates = [];
  for (const c of clients) {
    const e = snap.entities[c.id];
    if (!e) continue;
    let bestForEntity = null;
    for (const dim of _U_PLUS_CALIBRATION_DIMS) {
      const value = e[dim];
      if (typeof value !== "number") continue;
      const cal = resolveCalibration(dim, c.id, value, { force_enabled: true });
      if (!cal) continue;
      if (_U_PLUS_RELEVANT_CLASSIFICATIONS.indexOf(cal.classification) < 0) continue;
      const sev = _U_PLUS_SEVERITY_RANK[cal.classification] || 0;
      if (!bestForEntity || sev > bestForEntity._sev) {
        bestForEntity = Object.assign({}, cal, { _sev: sev });
      }
    }
    if (bestForEntity) {
      candidates.push({
        entity_id: c.id,
        entity_name: c.canonical_name,
        mentions: mentions[c.id] || 0,
        severity: bestForEntity._sev,
        calibration: bestForEntity,
      });
    }
  }
  if (candidates.length === 0) return null;

  // Opción B firmada · más mencionada · desempate por severidad
  candidates.sort((a, b) => {
    if (b.mentions !== a.mentions) return b.mentions - a.mentions; // más mencionada primero
    return b.severity - a.severity; // desempate más severa
  });
  const top = candidates[0];

  // Si la top NO está mencionada en narrative · fallback "más severa"
  if (top.mentions === 0) {
    candidates.sort((a, b) => b.severity - a.severity);
    return candidates[0];
  }
  return top;
}

// ── _composeCalibrationTip · Variante 4 "Nota sectorial" + cierre adaptativo ──
// D-U+.B-1: "Nota sectorial · [Entity] opera con [dim] [valor], [clasif concordada]
//            para [sector] (X% [sobre/bajo] el benchmark del sector [valor]).
//            Esto [refuerza/matiza] la lectura del cliente."
// Fallback firmado: si mapping a "tensión principal" complejiza → "Esto matiza la lectura del cliente."
//
// IMPORTANTE: NO usar sectoral_context directo · contiene verbo "está/es" que choca con
// "opera con" del wording firmado. Reconstruimos con los campos crudos del calibration
// usando las mismas etiquetas español natural (concordancia heredada U+.A).
function _composeCalibrationTip(candidate) {
  if (!candidate || !candidate.calibration) return "";
  const cal = candidate.calibration;
  if (!cal.dimension || cal.value == null || !cal.classification || !cal.industry) return "";
  // Etiquetas (mismos maps de U.E · concordancia U+.A)
  const dimLabel = (typeof _DIMENSION_LABEL_ES !== "undefined") ? (_DIMENSION_LABEL_ES[cal.dimension] || cal.dimension) : cal.dimension;
  const unit = (typeof _DIMENSION_UNIT_ES !== "undefined" && _DIMENSION_UNIT_ES[cal.dimension] != null) ? _DIMENSION_UNIT_ES[cal.dimension] : "";
  const indLabel = (typeof _INDUSTRY_LABEL_ES !== "undefined") ? (_INDUSTRY_LABEL_ES[cal.industry] || cal.industry) : cal.industry;
  const gender = (typeof _DIMENSION_GENDER !== "undefined") ? (_DIMENSION_GENDER[cal.dimension] || "masc") : "masc";
  const classEntry = (typeof _CLASSIFICATION_LABEL_ES !== "undefined") ? _CLASSIFICATION_LABEL_ES[cal.classification] : null;
  const classLabel = (classEntry && typeof classEntry === "object")
    ? (classEntry[gender] || classEntry.masc || cal.classification)
    : (classEntry || cal.classification);
  // Valor + unidad formateado
  const valueStr = (unit === "%") ? (cal.value + "%") : (unit ? (cal.value + " " + unit) : String(cal.value));
  // Benchmark string
  const bmStr = (unit === "%") ? (cal.benchmark + "%") : (unit === "días") ? (cal.benchmark + " días") : String(cal.benchmark);
  // Gap tail
  let gapTail = "";
  if (cal.gap && cal.gap.interpretation !== "en_benchmark") {
    const pct = Math.abs(cal.gap.gap_pct);
    const side = (cal.gap.direction === "above") ? "sobre" : "bajo";
    gapTail = " (" + pct + "% " + side + " el benchmark del sector " + bmStr + ")";
  } else {
    gapTail = " (en línea con el benchmark del sector " + bmStr + ")";
  }
  // Cierre adaptativo · fallback simple firmado D-U+.B-1
  const closure = "Esto matiza la lectura del cliente.";
  // Wording firmado Variante 4: "[Entity] opera con [dim] [valor], [clasif] para [sector] (gap)."
  return "Nota sectorial · " + candidate.entity_name + " opera con " + dimLabel + " " + valueStr + ", " + classLabel + " para " + indLabel + gapTail + ". " + closure;
}

// ── appendCalibrationToNarrative · WRAPPER espejo prependDeltaToNarrative ────
// 4 CAPAS DEFENSIVAS · cualquier gate fail → return narrative original bitwise.
// SOLO toca narrativeV2.opener insertando "Nota sectorial" entre Confianza y Pregunta sugerida.
function appendCalibrationToNarrative(narrativeV2, scenarioId, options) {
  // CAPA 1 · narrativa válida
  if (!narrativeV2 || typeof narrativeV2 !== "object" || typeof narrativeV2.opener !== "string") {
    return narrativeV2;
  }
  // CAPA 2 · flag OFF
  const force_enabled = !!(options && options.force_enabled === true);
  if (!VOICE_CALIBRATION_INTEGRATOR_ENABLED && !force_enabled) return narrativeV2;
  // CAPA 3 · intent debe ser executive_report_v2 (D-U+.B-3 C)
  const intentType = options && options.intent_type;
  if (intentType !== "executive_report_v2") return narrativeV2;
  // CAPA 4 · cooldown page-load (D-U+.B-4)
  if (_calibrationShownThisLoad && !force_enabled) return narrativeV2;
  // CAPA 5 · seleccionar candidate (D-U+.B-3 + Opción B)
  const candidate = _selectCalibrationCandidate(narrativeV2.opener, scenarioId);
  if (!candidate) return narrativeV2; // sin entity relevante
  // CAPA 6 · componer tip
  const tip = _composeCalibrationTip(candidate);
  if (!tip) return narrativeV2;
  // Insertar entre "Confianza alta..." y "Pregunta sugerida" · cero touch composers internos.
  // Patrón de inserción: localizar "**Pregunta sugerida**" en el opener y prepend el tip.
  const opener = narrativeV2.opener;
  const pregIdx = opener.indexOf("**Pregunta sugerida**");
  let nuevoOpener;
  if (pregIdx > 0) {
    nuevoOpener = opener.slice(0, pregIdx) + "*" + tip + "*\n\n" + opener.slice(pregIdx);
  } else {
    // fallback · append al final si no hay "Pregunta sugerida"
    nuevoOpener = opener + "\n\n*" + tip + "*";
  }
  _calibrationShownThisLoad = true; // marcar cooldown solo cuando efectivamente insertamos
  // Retornar narrativa enriquecida (objeto nuevo · NO muta el original)
  return Object.assign({}, narrativeV2, { opener: nuevoOpener });
}

