// ════════════════════════════════════════════════════════════════════════════
// BRIEF AN · AN.A · CROSS_DIMENSION_CATALOG  ⭐ NAVEGACIÓN ANALÍTICA · CATÁLOGO
//
// MANIFIESTO BRIEF AN · ADI deja de responder dimensión por dimensión y empieza
// a CRUZAR dimensiones sobre las entities recordadas del turno anterior.
// Ejemplo runtime objetivo (post AN+ activación):
//   T1: "qué clientes con bajo margen" → ADI: M.B.1 + Lider/Jumbo/Paris
//   T2: "y cómo está su carga"         → ADI (M.AN.1): cruce margen × carga
//                                        sobre ring conversacional
//
// AN.A · PRIMERA PIEZA · CATÁLOGO solamente. Construye el catálogo extensible
// + 4 getters de transparencia. NO toca nada del dispatcher, composers, ni
// resolver conversacional pre-existente (que YA existe completo · BRIEFs G/#14/#24/#27).
//
// SCOPE FIRMADO AN.A:
//   · D-AN-1 · B · 3 cruces core MVP (margen×carga · margen×rotación · DOH×margen)
//   · D-AN-2 · A · clave alfabética estricta `<dim_a>_<dim_b>` orden alfabético
//                  → permite extensión N×M cero touch al resto del catálogo
//                  → la clave es INTERNA · alfabética; el label es USER-FACING (orden semántico)
//   · D-AN-3 · A · cada cruce tiene "lens" semántico (presion_comercial · capital_atrapado · etc)
//   · D-AN-11 · A · VOICE_AN_ENABLED = false default · activación user-facing en AN+
//
// CONVENCIÓN CLAVE ALFABÉTICA (D-AN-2):
//   Las 4 dims ordenadas alfabéticamente:
//     carga_comercial_pct < doh < margen_pct < rotacion
//   Por lo tanto la clave del catálogo es:
//     · margen × carga    → "carga_comercial_pct_margen_pct"
//     · margen × rotación → "margen_pct_rotacion"
//     · DOH × margen      → "doh_margen_pct"
//   El label español sigue orden semántico de lectura: "margen × carga" · NO "carga × margen".
//   Esta divergencia clave-interna ↔ label-user-facing es DELIBERADA · evita ambigüedad
//   de extensión (la clave es determinística) sin sacrificar legibilidad ejecutiva.
//
// CERO TOUCH: catálogos R · U.A-U.F · S.A-S.I · S+ · U+.A · U+.B · _DIMENSION_KEY_MAP ·
//             composers existentes · resolver conversacional · dispatcher. Aditivo puro.
//
// DISCIPLINA: cero LLM · cero randomness · catálogo fijo declarativo · motor puro.
// ════════════════════════════════════════════════════════════════════════════

// Flag rollback granular AN · default OFF (D-AN-11 · activación user-facing en AN+ separado).
const VOICE_AN_ENABLED = false;

// CROSS_DIMENSION_CATALOG · 3 cruces core MVP · clave alfabética estricta (D-AN-1/2).
//
// Extensión N×M futura: para agregar p.ej. carga × rotación → nueva entry con
// clave alfabética "carga_comercial_pct_rotacion" + composer dedicado.
// Las entries existentes quedan intactas (cero touch al extender).
const CROSS_DIMENSION_CATALOG = {
  // Cruce 1 · margen × carga · presión comercial
  // Clave alfabética: carga_comercial_pct < margen_pct
  carga_comercial_pct_margen_pct: {
    dim_a: "carga_comercial_pct",
    dim_b: "margen_pct",
    lens: "presion_comercial",
    composer: "_composeAn1MargenCarga",
    label_es: "margen × carga",
  },
  // Cruce 2 · DOH × margen · capital atrapado
  // Clave alfabética: doh < margen_pct
  doh_margen_pct: {
    dim_a: "doh",
    dim_b: "margen_pct",
    lens: "capital_atrapado",
    composer: "_composeAn3DohMargen",
    label_es: "DOH × margen",
  },
  // Cruce 3 · margen × rotación · eficiencia operativa
  // Clave alfabética: margen_pct < rotacion
  margen_pct_rotacion: {
    dim_a: "margen_pct",
    dim_b: "rotacion",
    lens: "eficiencia_operativa",
    composer: "_composeAn2MargenRotacion",
    label_es: "margen × rotación",
  },
};

// ── _validateCrossKey · helper interno · verifica orden alfabético estricto ──
// D-AN-2: claves del catálogo deben ser "<dim_a>_<dim_b>" con dim_a < dim_b alfabético.
// Útil para tests + extensibilidad futura (assert al agregar entry).
function _validateCrossKey(key, dim_a, dim_b) {
  if (typeof key !== "string" || typeof dim_a !== "string" || typeof dim_b !== "string") return false;
  if (dim_a >= dim_b) return false; // orden alfabético estricto
  const expected = dim_a + "_" + dim_b;
  return key === expected;
}

// ── getCrossDimension · accessor principal por clave ───────────────────────
// D-AN-11: si flag OFF y sin force_enabled → null (paridad U.E resolveCalibration)
function getCrossDimension(crossKey, options) {
  const force_enabled = !!(options && options.force_enabled === true);
  if (!VOICE_AN_ENABLED && !force_enabled) return null;
  if (typeof crossKey !== "string") return null;
  const entry = CROSS_DIMENSION_CATALOG[crossKey];
  return entry || null;
}

// ── listCrossDimensions · lista keys disponibles ────────────────────────────
function listCrossDimensions(options) {
  const force_enabled = !!(options && options.force_enabled === true);
  if (!VOICE_AN_ENABLED && !force_enabled) return [];
  return Object.keys(CROSS_DIMENSION_CATALOG);
}

// ── getCrossesByLens · filtro por lens semántico (D-AN-3) ──────────────────
// Permite que el detector AN encuentre cruces por su lens (presion_comercial · etc)
// sin recorrer todo el catálogo.
function getCrossesByLens(lens, options) {
  const force_enabled = !!(options && options.force_enabled === true);
  if (!VOICE_AN_ENABLED && !force_enabled) return [];
  if (typeof lens !== "string") return [];
  const result = [];
  for (const key of Object.keys(CROSS_DIMENSION_CATALOG)) {
    if (CROSS_DIMENSION_CATALOG[key].lens === lens) result.push(key);
  }
  return result;
}

// ── getAnStats · transparencia + auditoría ──────────────────────────────────
function getAnStats() {
  const lenses = {};
  for (const key of Object.keys(CROSS_DIMENSION_CATALOG)) {
    const l = CROSS_DIMENSION_CATALOG[key].lens;
    lenses[l] = (lenses[l] || 0) + 1;
  }
  return {
    catalog_size: Object.keys(CROSS_DIMENSION_CATALOG).length,
    lenses: lenses,
    lenses_unique: Object.keys(lenses),
    flag_enabled: VOICE_AN_ENABLED,
    pieces_status: { AN_A: "complete", AN_B: "pending", AN_C: "pending", AN_D: "pending", AN_E: "pending", AN_PLUS: "pending" },
    note: "AN.A es catálogo puro · resolver conversacional pre-existente (BRIEFs G/#14/#24/#27) consumido cero touch en AN.B/C.",
  };
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF AN · AN.A · CROSS_DIMENSION_CATALOG
// ════════════════════════════════════════════════════════════════════════════


// ════════════════════════════════════════════════════════════════════════════
// BRIEF AN · AN.B · INTENT DETECTOR · WRAPPER post-detectIntent ⭐
//
// AN.B detecta queries cross-dimensión que detectIntent legacy NO captura:
//   "y la carga"           (conector + dim sin entity)
//   "y como esta su carga" (conector + pronoun + dim sin entity)
//   "esos como estan de carga" (pronoun plural + dim · ya resolved deíctico)
//
// Casos que AN.B NO toca (respeta legacy):
//   "el primero"          → legacy retorna {type:"client", clientName:...} · AN no override
//   "fuga de capital"     → legacy retorna cross_domain_query · AN no override
//   "Falabella margen"    → entity explícita · legacy maneja
//
// SCOPE FIRMADO AN.B:
//   · D-AN.B-1 · B · wrapper post-detectIntent · cero touch 188 líneas legacy
//   · D-AN.B-2 · A · 3 sub-patrones OR simples (connector + pronoun + dim_referenced)
//   · D-AN.B-3 · A · _AN_DIM_LEXICON mínimo SIN acentos (normalización confirmada)
//   · D-AN.B-4 · A-PRIME · cascada 4 niveles · honest fail si no resuelve dim previa
//                Valores REALES runtime verificados auditoría:
//                investigationMetric ∈ {capital_inmovilizado, contribucion, doh, rotacion}
//                investigationDomain ∈ {inventario, margenes}
//                (Comentario init cerebro R diverge runtime · deuda registrada)
//   · D-AN.B-5 · A · sin cooldown extra · lifecycle del ring suficiente
//   · D-AN.B-6 · A · override solo "generic"/"out_of_domain"/"empty"
//   · D-AN.B-7 · A · 1 flag VOICE_AN_ENABLED · AN+ tendrá flag separado
//
// CERO TOUCH: detectIntent (188 líneas LOCKED) · detectDeicticReference (BRIEF G) ·
//             CONCEPT_ONTOLOGY · cerebro R · S · S+ · U · U+ · dispatcher.
// AN.B es ADITIVO PURO · consume infraestructura · no construye.
//
// DEUDA REGISTRADA: #D-CEREBRO-R-COMENTARIO-DESALINEADO-INVESTIGATION-METRIC-VALORES-REALES
// ════════════════════════════════════════════════════════════════════════════

// ── Patrones léxicos (D-AN.B-2) · OR de 3 sub-patrones ──────────────────────
// Texto se normaliza al entrar (lowercase + NFD + strip diacritics · mismo
// patrón que detectIntent línea 4396) · lexicon SIN acentos es suficiente.
const _AN_CONNECTORS = /^(y|ahora|tambien|ademas)\s+/i;
const _AN_PRONOUNS   = /\b(ellos|esos|esas|estos|estas|aquellos|aquellas|su|sus|ese|esa|este|esta|le|les)\b/i;

// ── _AN_DIM_LEXICON · dim_key → patrones léxicos sin acentos (D-AN.B-3) ────
// Plurales/sinónimos ortográficos cubiertos · acentos quitados por normalización.
const _AN_DIM_LEXICON = {
  margen_pct:          ["margen", "margenes", "rentabilidad"],
  carga_comercial_pct: ["carga", "carga comercial", "rebate", "rebates"],
  rotacion:            ["rotacion", "rota"],
  doh:                 ["doh", "dias de inventario", "cobertura", "stock days"],
};

// ── _AN_METRIC_TO_DIM · cascada nivel 1 (D-AN.B-4 A-PRIME) ─────────────────
// Valores REALES runtime verificados auditoría · NO los del comentario init.
const _AN_METRIC_TO_DIM = {
  capital_inmovilizado: "doh",        // capital atrapado se mide en días stock
  contribucion:         "margen_pct", // contribución mide rentabilidad
  doh:                  "doh",
  rotacion:             "rotacion",
};

// ── _AN_DOMAIN_TO_DIM · cascada nivel 2 (D-AN.B-4 A-PRIME) ─────────────────
// Valores REALES runtime: solo inventario · margenes. "ventas" no se escribe.
const _AN_DOMAIN_TO_DIM = {
  inventario: "doh",
  margenes:   "margen_pct",
};

// ── _AN_INTENT_TO_DIM · cascada nivel 3 (D-AN.B-4) ─────────────────────────
// Solo intents donde la dim previa es OBVIAMENTE inferible.
// SIN entries hardcoded ambiguas (cross_domain_query, client, module_overview
// caen a nivel 4 honest null).
const _AN_INTENT_TO_DIM = {
  sku_deep_dive: "doh",
  rotation_dive: "rotacion",
};

// ── Lista de intents que AN puede sobreescribir (D-AN.B-6) ─────────────────
// Únicos casos donde AN puede tomar control · todo lo demás respeta legacy.
const _AN_LEGACY_INTENT_OVERRIDABLE = [
  "generic", "out_of_domain", "empty",
  "ad_hoc_reasoning",   // 🆕 AN+.FIX D-AN+.FIX-2 · robustez Fix A (BRIEF I path)
  "cross_domain_query", // 🆕 AN+.FIX D-AN+.FIX-2 · CAUSA RAÍZ "y la carga" runtime React
                        //     (concept_rebate matchea "carga" → detectIntent retorna cross_domain_query)
                        //     Seguridad: is_cross_intent en AN.B requiere ring+continuity+dim+catálogo
                        //     "qué clientes comen el margen" SIN ring → AN.B null → legacy gana (preservado)
];

// ── _detectDimReferenced · busca dim del catálogo en query (lookup léxico) ─
// Retorna dim_key del _DIMENSION_KEY_MAP · null si query no menciona dim.
// Asume text YA normalizado (lowercase + sin acentos).
function _detectDimReferenced(normalizedText) {
  if (typeof normalizedText !== "string" || !normalizedText) return null;
  // Probar cada dim · buscar word-boundary o frase
  for (const dimKey of Object.keys(_AN_DIM_LEXICON)) {
    const patterns = _AN_DIM_LEXICON[dimKey];
    for (const pat of patterns) {
      // word-boundary para palabras simples · substring para frases con espacios
      if (pat.indexOf(" ") >= 0) {
        if (normalizedText.indexOf(pat) >= 0) return dimKey;
      } else {
        const re = new RegExp("\\b" + pat.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "\\b", "i");
        if (re.test(normalizedText)) return dimKey;
      }
    }
  }
  return null;
}

// ── _inferPreviousDim · cascada de 4 niveles (D-AN.B-4 A-PRIME) ────────────
// Cascada de precedencia más preciso → menos preciso · level 4 = honest fail.
//   1. investigationMetric (BRIEF #27)
//   2. investigationDomain (BRIEF #27)
//   3. legacyIntent.type (intent específico)
//   4. NULL · honest fail (NO cruce equivocado)
function _inferPreviousDim(conversationContext, legacyIntentType) {
  // Nivel 1 · investigationMetric (más preciso)
  if (conversationContext && conversationContext.investigationMetric) {
    const m = _AN_METRIC_TO_DIM[conversationContext.investigationMetric];
    if (m) return m;
  }
  // Nivel 2 · investigationDomain (dominio general)
  if (conversationContext && conversationContext.investigationDomain) {
    const d = _AN_DOMAIN_TO_DIM[conversationContext.investigationDomain];
    if (d) return d;
  }
  // Nivel 3 · lastIntent específico
  if (typeof legacyIntentType === "string" && _AN_INTENT_TO_DIM[legacyIntentType]) {
    return _AN_INTENT_TO_DIM[legacyIntentType];
  }
  // Nivel 4 · honest fail · NO cruce equivocado
  return null;
}

// ── detectAnCrossIntent · función principal · wrapper post-detectIntent ────
// 3 reglas combinadas (D-AN.B-5):
//   R1 · indicador continuidad (connector OR pronoun OR dim referenced sin entity)
//   R2 · ring conversacional poblado (lastClientList no-vacío)
//   R3 · legacyIntent NO en _AN_LEGACY_INTENT_OVERRIDABLE → return null (respeta)
//
// Retorna cross_intent o null. NO modifica el legacy intent · solo agrega señal.
function detectAnCrossIntent(text, conversationContext, legacyIntent, options) {
  // CAPA 1 · flag gate (D-AN.B-7)
  const force_enabled = !!(options && options.force_enabled === true);
  if (!VOICE_AN_ENABLED && !force_enabled) return null;
  // CAPA 2 · inputs válidos
  if (typeof text !== "string" || !text) return null;
  if (!conversationContext || typeof conversationContext !== "object") return null;
  // CAPA 3 · legacy intent debe ser overridable (D-AN.B-6)
  // Si legacy resolvió "client", "client_followup", "cross_domain_query", etc.,
  // AN.B respeta · NO override.
  const legacyType = (legacyIntent && legacyIntent.type) ? legacyIntent.type : "generic";
  if (_AN_LEGACY_INTENT_OVERRIDABLE.indexOf(legacyType) < 0) return null;
  // CAPA 4 · ring conversacional poblado (R2)
  const lastClientList = conversationContext.lastClientList;
  const ringPopulated = Array.isArray(lastClientList) && lastClientList.length > 0;
  if (!ringPopulated) return null;
  // Normalizar texto (paridad detectIntent línea 4396)
  const normalized = text.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();
  // CAPA 5 · indicador continuidad (R1 · 3 sub-patrones OR)
  const hasConnector = _AN_CONNECTORS.test(normalized);
  const hasPronoun = _AN_PRONOUNS.test(normalized);
  const dimReferenced = _detectDimReferenced(normalized);
  const hasContinuity = hasConnector || hasPronoun || (dimReferenced != null);
  if (!hasContinuity) return null;
  // CAPA 6 · inferir dim previa (cascada 4 niveles · honest fail nivel 4)
  const dimPrevious = _inferPreviousDim(conversationContext, legacyType);
  if (dimPrevious === null) return null; // honest fail (D-AN.B-4 nivel 4)
  // CAPA 7 · si query menciona dim explícita, usarla; si no, INHERIT dimPrevious
  // En el caso "esos cómo están" sin dim específica · usamos dimPrevious para ambos.
  // En "y la carga" · dimReferenced=carga, dimPrevious=margen → cruce 2D real.
  const dimA = dimReferenced;
  const dimB = dimPrevious;
  // Si no hay dimReferenced (ej. "esos cómo están") · no hay cruce 2D real → null
  // (en MVP exigimos al menos una dim mencionada explícita · futuro: dim default por lens)
  if (dimA === null) return null;
  // Si dim_a === dim_b · no es cruce real · honest skip
  if (dimA === dimB) return null;
  // CAPA 8 · construir cross_key alfabético (D-AN-2 · misma convención AN.A)
  const sorted = (dimA < dimB) ? [dimA, dimB] : [dimB, dimA];
  const crossKey = sorted[0] + "_" + sorted[1];
  // CAPA 9 · validar contra catálogo AN.A · si no existe, honest null
  const catalogEntry = (typeof getCrossDimension === "function")
    ? getCrossDimension(crossKey, { force_enabled: true })
    : null;
  if (!catalogEntry) return null;
  // Construir intent AN
  return {
    type: "cross_dimension_query",
    is_cross_intent: true,
    cross_key: crossKey,
    entities: lastClientList.slice(), // copia · cero mutation del ring
    dim_referenced: dimReferenced,
    dim_previous: dimPrevious,
    lens: catalogEntry.lens,
    source: hasConnector
      ? "connector"
      : (hasPronoun ? "pronoun" : "explicit_dim"),
  };
}

