// ════════════════════════════════════════════════════════════════════════════
// BRIEF AN · AN.C · COMPOSERS NARRATIVOS CROSS-DIMENSIÓN ⭐ USER-FACING
//
// AN.C es la pieza VISIBLE de BRIEF AN. Genera el string narrativo que el
// usuario lee cuando hace una query cross-dimensional sobre el ring que dejó
// el turno anterior. Recibe entities + scenarioId + crossKey y entrega la
// narrativa final (AN-2 firmado · "cuentas que viste" estilo R.I V2).
//
// SCOPE FIRMADO AN.C:
//   · D-AN-7   · B · AN-2 ajustado "cuentas que viste" (firmado founder)
//   · D-AN.C-1 · B · max 5 entities (rings reales M.B.X/E.X)
//   · D-AN.C-2 · A · skip silencioso entity sin dim (honest fail por entity)
//   · D-AN.C-3 · A · frase honesta dispersión (0 entities patrón)
//   · D-AN.C-4 · A · foco 1 entity ("presión focal · no estructural")
//   · D-AN.C-5 · A · respeta VOICE_AN_ENABLED (paridad AN.A/B)
//   · D-AN.C-6 · A · string narrativo retorno (paridad appendCalibrationToNarrative)
//   · D-AN-8   · C · template centralizado + 3 thin composers (DRY+aislamiento)
//
// 🆕 #R-UNIVERSAL-INMERSION-EJECUTIVA · INVARIANTE ANTI-FUGA LENGUAJE COGNITIVO
//   "El usuario nunca debe percibir la estructura cognitiva interna de ADI;
//    debe percibir únicamente el negocio que está analizando."
//   Wording AN.C respeta esta regla rectora · sin "entidades" / "turno anterior" /
//   "ring" / "intent" / "calibration" / "deictic" / "scenario" / "snapshot" /
//   "registry" / "narrativeV2" / "opener" en NINGÚN output.
//
// CERO TOUCH: cerebro R · S · S+ · U · U+ · AN.A · AN.B · dispatcher · resolver.
// AN.C es ADITIVO PURO · consume calibración U.E + catálogo AN.A.
// ════════════════════════════════════════════════════════════════════════════

// ── REGLA UNIVERSAL ECL · lista de términos prohibidos user-facing ─────────
// Auditada en Q.E-AN-C · CHECK obligatorio en TODA suite user-facing futura
// (AN.D · AN.E · AN+ · W · T · V · ECL).
// Términos en lowercase · sin acentos (paridad normalización detectIntent).
const _FORBIDDEN_INTERNAL_TERMS = [
  "entidad", "entidades",
  "turno anterior", "ultimo turno", "turno previo",
  "ring",
  "intent",
  "calibracion", "calibration",
  "deictic", "deictico",
  "cross-dimension", "cross_dimension",
  "session", "scenario", "snapshot", "registry",
  "narrativev2", "opener",
];

// ── _AN_LENS_INTERPRETATION · cierre interpretativo por lens ───────────────
// 3 lens (1 por cruce MVP · D-AN-3 1 cruce por lens):
//   presion_comercial    · "presión comercial atada al margen en cuentas con menor sector-fit"
//   capital_atrapado     · "capital atrapado en cuentas con menor rotación"
//   eficiencia_operativa · "eficiencia operativa baja · capital atrapado en cuentas con margen estrecho"
const _AN_LENS_INTERPRETATION = {
  presion_comercial:    "presión comercial sobre el margen en cuentas peor calzadas con su sector",
  capital_atrapado:     "capital detenido en cuentas que rotan lento",
  eficiencia_operativa: "baja eficiencia operativa: capital detenido en cuentas de margen estrecho",
};

// ── _AN_PATTERN_LABEL · cómo describir el patrón en cada cruce ─────────────
// Usado en header "X muestran el patrón consistente <pattern_label>".
const _AN_PATTERN_LABEL = {
  carga_comercial_pct_margen_pct: "margen bajo con carga comercial alta",
  doh_margen_pct:                  "inventario elevado con margen bajo",
  margen_pct_rotacion:             "margen bajo y rotación lenta",
};

// ── _AN_PATTERN_PREDICATE · qué clasificaciones definen "patrón" por dim ──
// Para cada cruce: condición que define "esta entity cumple el patrón".
// presion_comercial   · margen pressured/critical + carga elevated/critical
// capital_atrapado    · doh elevated/critical + margen pressured/critical
// eficiencia_operativa · margen pressured/critical + rotacion pressured/critical
const _AN_PRESSURE_CLASSES = ["pressured", "critical", "elevated"];
function _entityFulfillsPattern(crossKey, calA, calB) {
  if (!calA || !calB) return false;
  // Patrón = ambas dims muestran clasificación adversa (no normal/healthy)
  const adverseA = _AN_PRESSURE_CLASSES.indexOf(calA.classification) >= 0;
  const adverseB = _AN_PRESSURE_CLASSES.indexOf(calB.classification) >= 0;
  return adverseA && adverseB;
}

// ── _composeAnEntityLine · línea por cuenta (AN-2 ajustado) ────────────────
// Formato: "· <name> · <dim_a> X% <verbo> <clase> (Y% sobre/bajo el benchmark del sector) · <dim_b> ..."
function _composeAnEntityLine(entityName, calA, calB) {
  if (!entityName || !calA || !calB) return null;
  function partFor(cal) {
    const dimLabel = (typeof _DIMENSION_LABEL_ES !== "undefined") ? (_DIMENSION_LABEL_ES[cal.dimension] || cal.dimension) : cal.dimension;
    const unit = (typeof _DIMENSION_UNIT_ES !== "undefined" && _DIMENSION_UNIT_ES[cal.dimension] != null) ? _DIMENSION_UNIT_ES[cal.dimension] : "";
    const gender = (typeof _DIMENSION_GENDER !== "undefined") ? (_DIMENSION_GENDER[cal.dimension] || "masc") : "masc";
    const classEntry = (typeof _CLASSIFICATION_LABEL_ES !== "undefined") ? _CLASSIFICATION_LABEL_ES[cal.classification] : null;
    const classLabel = (classEntry && typeof classEntry === "object")
      ? (classEntry[gender] || classEntry.masc || cal.classification)
      : (classEntry || cal.classification);
    // Verbo: "está" para pressured/elevated/critical · "es" para normal/healthy
    const verb = (_AN_PRESSURE_CLASSES.indexOf(cal.classification) >= 0) ? "está" : "es";
    const valueStr = (unit === "%") ? (cal.value + "%") : (unit ? (cal.value + " " + unit) : String(cal.value));
    let gapTail;
    if (cal.gap && cal.gap.interpretation !== "en_benchmark") {
      const pct = Math.abs(cal.gap.gap_pct);
      const side = (cal.gap.direction === "above") ? "sobre" : "bajo";
      gapTail = "(" + pct + "% " + side + " el benchmark del sector)";
    } else {
      gapTail = "(en línea con el benchmark del sector)";
    }
    return dimLabel + " " + valueStr + " " + verb + " " + classLabel + " " + gapTail;
  }
  return "· " + entityName + " · " + partFor(calA) + " · " + partFor(calB);
}

// ── 🆕 _AN_ENTITY_NOUN · sustantivos user-facing por entityType ─────────────
// REGLA UNIVERSAL ECL #R-UNIVERSAL-INMERSION-EJECUTIVA: el usuario nunca
// percibe estructura cognitiva interna. Cuando un composer itera sobre un
// ring de entities, el sustantivo + género user-facing debe coincidir con
// el tipo REAL del entity ("cuentas" FEM para clients · "productos" MASC
// para SKUs · NO "entidades").
//
// REUTILIZACIÓN FUTURA (decisión estratégica · 7+ BRIEFs):
//   · AN.D suite integración · auditar composers usan este map
//   · AN.E cierre stats wording
//   · AN+ activación user-facing dispatcher
//   · W (organizational learning) · "ADI aprendió que los productos X..."
//   · T (proactive initiative) · "Los productos Z requieren atención..."
//   · V (founder personalization) · override custom admitido
//   · ECL (executive conversation) · capa rectora · iteración sobre cualquier ring
//
// DEUDA REGISTRADA: #D-FUTURO-AN-ENTITY-NOUN-EXTENDER-A-MAS-ENTITYTYPES-
//                   CANAL-SUCURSAL-MARCA-CUANDO-RUNTIME-LO-DEMANDE
const _AN_ENTITY_NOUN = {
  client: {
    singular:        "cuenta",
    plural:          "cuentas",
    gender:          "fem",
    article_plural:  "las",
    article_singular: "la",
  },
  sku: {
    singular:        "producto",
    plural:          "productos",
    gender:          "masc",
    article_plural:  "los",
    article_singular: "el",
  },
  // Fallback honest cuando entityType desconocido (paridad cascada AN.B nivel 4)
  default: {
    singular:        "elemento",
    plural:          "elementos",
    gender:          "masc",
    article_plural:  "los",
    article_singular: "el",
  },
};

// ── _detectRingEntityType · detecta entityType del primer entity del ring ──
// Usa BRIEF S registry (getEntityById) que ya tiene campo `kind` ∈ {client, sku}.
// Si ring mixto · usa primer entity (caso edge documentado · raro en práctica).
// Honest fail · ring vacío o kind desconocido → "default".
function _detectRingEntityType(entities) {
  if (!Array.isArray(entities) || entities.length === 0) return "default";
  const first = entities[0];
  // entity puede venir como objeto {id, canonical_name} o como id string
  const eid = (typeof first === "object" && first !== null) ? first.id : first;
  if (typeof eid !== "string") return "default";
  if (typeof getEntityById !== "function") {
    // Fallback heurístico por prefijo si registry no disponible
    if (eid.startsWith("client_")) return "client";
    if (eid.startsWith("sku_"))    return "sku";
    return "default";
  }
  const reg = getEntityById(eid);
  if (!reg || typeof reg.kind !== "string") {
    // Fallback heurístico por prefijo si registry no resuelve
    if (eid.startsWith("client_")) return "client";
    if (eid.startsWith("sku_"))    return "sku";
    return "default";
  }
  // Validar kind contra _AN_ENTITY_NOUN keys conocidos
  if (_AN_ENTITY_NOUN[reg.kind]) return reg.kind;
  return "default";
}

// ── _composeAnCrossTemplate · TEMPLATE CENTRALIZADO (D-AN-8 Opción C) ──────
// Recibe crossKey del catálogo + entities del ring + scenarioId.
// Retorna string narrativo con header bold + tesis + listado · AN-2 firmado.
// Honest fails:
//   · Catálogo no resuelve crossKey → ""
//   · 0 entities con ambas dims disponibles → ""  (skip composer completo)
//   · 0 entities cumplen patrón → frase honesta dispersión (D-AN.C-3)
//   · 1 entity cumple patrón → foco "presión focal" (D-AN.C-4)
//   · ≥2 entities cumplen patrón → "K muestran patrón consistente" (AN-2 base)
function _composeAnCrossTemplate(crossKey, entities, scenarioId, options) {
  // CAPA 1 · flag (D-AN.C-5)
  const force_enabled = !!(options && options.force_enabled === true);
  if (!VOICE_AN_ENABLED && !force_enabled) return "";
  // CAPA 2 · inputs válidos
  if (typeof crossKey !== "string" || !Array.isArray(entities)) return "";
  if (entities.length === 0) return "";
  // CAPA 3 · catálogo resuelve crossKey
  const entry = (typeof getCrossDimension === "function")
    ? getCrossDimension(crossKey, { force_enabled: true })
    : null;
  if (!entry) return "";
  // CAPA 4 · max 5 entities (D-AN.C-1)
  const capped = entities.slice(0, 5);
  // CAPA 5 · acceso datos · takeBusinessSnapshot
  if (typeof takeBusinessSnapshot !== "function" || typeof resolveCalibration !== "function") return "";
  const snap = takeBusinessSnapshot(scenarioId);
  if (!snap || !snap.entities) return "";
  // CAPA 6 · construir calibraciones por entity (skip silencioso si dim faltante · D-AN.C-2)
  const cards = [];
  for (const ent of capped) {
    // ent puede venir como objeto {id, canonical_name} o como id string
    const eid = (typeof ent === "object" && ent !== null) ? ent.id : ent;
    const ename = (typeof ent === "object" && ent !== null && ent.canonical_name) ? ent.canonical_name : eid;
    const data = snap.entities[eid];
    if (!data) continue; // skip silencioso · entity no en snapshot
    const valA = data[entry.dim_a];
    const valB = data[entry.dim_b];
    if (typeof valA !== "number" || typeof valB !== "number") continue; // skip silencioso · dim faltante
    const calA = resolveCalibration(entry.dim_a, eid, valA, { force_enabled: true });
    const calB = resolveCalibration(entry.dim_b, eid, valB, { force_enabled: true });
    if (!calA || !calB) continue;
    cards.push({ name: ename, calA: calA, calB: calB });
  }
  if (cards.length === 0) return ""; // honest fail · sin datos suficientes
  // CAPA 7 · detectar patrón cross-entity
  const fulfilling = cards.filter(c => _entityFulfillsPattern(crossKey, c.calA, c.calB));
  // CAPA 7-BIS · 🆕 detectar entityType del ring · sustantivo user-facing apropiado
  // (REGLA UNIVERSAL ECL · "cuentas" FEM para clients · "productos" MASC para SKUs)
  const entityType = _detectRingEntityType(entities);
  const noun = _AN_ENTITY_NOUN[entityType] || _AN_ENTITY_NOUN.default;
  // CAPA 8 · construir header tesis (D-AN-7=B firmado · entityType-aware)
  const lensInterp = _AN_LENS_INTERPRETATION[entry.lens] || "patrón cruzado";
  const patternLabel = _AN_PATTERN_LABEL[crossKey] || "patrón consistente";
  let header;
  if (fulfilling.length === 0) {
    // D-AN.C-3 · frase honesta dispersión
    header = "De " + noun.article_plural + " " + cards.length + " " + noun.plural + " que viste, ninguno muestra el patrón consistente "
      + patternLabel + " · " + lensInterp.replace(/^./, c => c.toLowerCase()) + " no se concentra en este grupo.";
    // Concordancia "ninguno" MASC · si fem usar "ninguna"
    if (noun.gender === "fem") {
      header = header.replace("ninguno muestra", "ninguna muestra");
    }
  } else if (fulfilling.length === 1) {
    // D-AN.C-4 · foco 1 entity · "presión focal · no estructural"
    // Concordancia · "1 muestra" sin género ambiguo · OK ambos
    header = "De " + noun.article_plural + " " + cards.length + " " + noun.plural + " que viste, 1 muestra el patrón consistente "
      + patternLabel + ": " + fulfilling[0].name + " · presión focal, no estructural.";
  } else {
    // AN-2 base · K muestran patrón consistente
    const namesStr = fulfilling.length === 2
      ? fulfilling[0].name + " y " + fulfilling[1].name
      : fulfilling.slice(0, -1).map(c => c.name).join(", ") + " y " + fulfilling[fulfilling.length - 1].name;
    header = "De " + noun.article_plural + " " + cards.length + " " + noun.plural + " que viste, " + fulfilling.length
      + " muestran el patrón consistente " + patternLabel + ": " + namesStr
      + " · sugiere " + lensInterp + ".";
  }
  // CAPA 9 · construir listado por entity
  const lines = cards.map(c => _composeAnEntityLine(c.name, c.calA, c.calB)).filter(l => l != null);
  // CAPA 10 · ensamblar narrativa final (AN-2 firmado · header + listado)
  return "**Cruza " + entry.label_es + "**\n" + header + "\n\n" + lines.join("\n");
}

// ── _composeAn1MargenCarga · thin composer · cruce margen × carga ──────────
function _composeAn1MargenCarga(entities, scenarioId, options) {
  return _composeAnCrossTemplate("carga_comercial_pct_margen_pct", entities, scenarioId, options);
}

// ── _composeAn2MargenRotacion · thin composer · cruce margen × rotación ───
function _composeAn2MargenRotacion(entities, scenarioId, options) {
  return _composeAnCrossTemplate("margen_pct_rotacion", entities, scenarioId, options);
}

// ── _composeAn3DohMargen · thin composer · cruce DOH × margen ──────────────
function _composeAn3DohMargen(entities, scenarioId, options) {
  return _composeAnCrossTemplate("doh_margen_pct", entities, scenarioId, options);
}

