// BRIEF W · ORGANIZATIONAL MEMORY · W.1 · MODELO DE DATOS + STORAGE 🧠
// ════════════════════════════════════════════════════════════════════════════
//
// Memoria organizacional auditada · 4 categorías:
//   · Decision · decisiones declaradas explícitas
//   · Pattern · consultas recurrentes observables
//   · Focus · focos de atención declarados
//   · Milestone · hitos de negocio confirmados
//
// Principios firmados (BRIEF_W_DESIGN_v1_1.md):
//   · Memoria con propósito ejecutivo · cero almacenamiento por almacenar
//   · Explícito sobre implícito · cero inferencia oculta
//   · Memoria auditada · cero especulación (Principio 7 v1.1)
//   · Ground truth · no fuente de verdad
//   · W es pasivo · T/V/ECL consumen · no al revés
//
// W.1 alcance:
//   · Shapes data + namespace OrganizationalMemory (IIFE)
//   · CRUD reutiliza wrapper _storage (D-S-2-REFACTOR · S.B · cero duplicación)
//   · Sin detectores (W.2) · sin pattern detection (W.3)
//   · Sin recall API (W.4) · sin UI (W.5) · sin hooks composers (W.6)
//
// Decisiones firmadas:
//   D-W1-NAMESPACE = A (OrganizationalMemory)
//   D-W-ALCANCE-MEMORIA = C (decisiones + patrones)
//   D-W-PERSISTENCIA = C (localStorage · backend deuda futura)
//   D-W-PRIVACY-CONTROL = C (automático + transparente + borrable)
// ════════════════════════════════════════════════════════════════════════════

const W_ENABLED = true;
const W_SCHEMA_VERSION = 1;

const OrganizationalMemory = (function _initOrganizationalMemory() {
  // Cache local · evita lecturas redundantes a _storage
  const _cache = {
    meta: null,
    decisions: null,
    patterns: null,
    focuses: null,
    milestones: null,
    dismisses: null,
    preferences: null,
  };

  // ──────────────────────────────────────────────────────────────────────────
  // Helpers privados · ID generation
  // ──────────────────────────────────────────────────────────────────────────

  function _generateId(prefix) {
    const ts = Date.now();
    const rnd = Math.floor(Math.random() * 1000000).toString(36);
    return `${prefix}_${ts}_${rnd}`;
  }

  function _nowISO() {
    return new Date().toISOString();
  }

  // ──────────────────────────────────────────────────────────────────────────
  // Helpers privados · acceso _storage reutilizando wrapper S.B
  // ──────────────────────────────────────────────────────────────────────────

  async function _readCategory(category) {
    if (_cache[category] !== null) return _cache[category];
    if (!W_ENABLED) {
      _cache[category] = (category === "meta") ? null : [];
      return _cache[category];
    }
    const raw = await _storage.get(`w_memory:${category}`);
    if (!raw) {
      _cache[category] = (category === "meta") ? null : [];
      return _cache[category];
    }
    try {
      const parsed = (typeof raw === "string") ? JSON.parse(raw) : raw;
      _cache[category] = parsed;
      return parsed;
    } catch (e) {
      _cache[category] = (category === "meta") ? null : [];
      return _cache[category];
    }
  }

  async function _writeCategory(category, value) {
    if (!W_ENABLED) return false;
    _cache[category] = value;
    const serialized = JSON.stringify(value);
    return await _storage.set(`w_memory:${category}`, serialized);
  }

  async function _ensureMeta() {
    let meta = await _readCategory("meta");
    if (!meta) {
      meta = {
        schemaVersion: W_SCHEMA_VERSION,
        enabled: true,
        createdAt: _nowISO(),
      };
      await _writeCategory("meta", meta);
    }
    return meta;
  }

  // ──────────────────────────────────────────────────────────────────────────
  // API pública · DECISIONS
  // ──────────────────────────────────────────────────────────────────────────

  async function addDecision(decisionData) {
    if (!W_ENABLED) return null;
    await _ensureMeta();
    const decision = {
      id: _generateId("w_d"),
      type: "decision",
      category: decisionData.category || "otro",
      entity: decisionData.entity || null,
      declaredAt: decisionData.declaredAt || _nowISO(),
      scenarioActivo: decisionData.scenarioActivo || null,
      context: decisionData.context || {},
      status: decisionData.status || "active",
      schemaVersion: W_SCHEMA_VERSION,
    };
    const list = await _readCategory("decisions");
    list.push(decision);
    await _writeCategory("decisions", list);
    return decision;
  }

  async function listDecisions() {
    return await _readCategory("decisions");
  }

  async function getDecisionById(id) {
    const list = await _readCategory("decisions");
    return list.find(d => d.id === id) || null;
  }

  async function deleteDecision(id) {
    const list = await _readCategory("decisions");
    const filtered = list.filter(d => d.id !== id);
    if (filtered.length === list.length) return false;
    await _writeCategory("decisions", filtered);
    return true;
  }

  async function updateDecisionStatus(id, newStatus) {
    const list = await _readCategory("decisions");
    const idx = list.findIndex(d => d.id === id);
    if (idx === -1) return false;
    list[idx].status = newStatus;
    await _writeCategory("decisions", list);
    return true;
  }

  // ──────────────────────────────────────────────────────────────────────────
  // API pública · PATTERNS (consulta recurrente · upsert behavior)
  // ──────────────────────────────────────────────────────────────────────────

  async function upsertPattern(patternData) {
    if (!W_ENABLED) return null;
    await _ensureMeta();
    const list = await _readCategory("patterns");
    const targetKey = patternData.target.entity
      ? patternData.target.entity.entityRefId
      : patternData.target.concept;
    const expectedId = `w_p_${targetKey}`;
    const idx = list.findIndex(p => p.id === expectedId);
    const now = _nowISO();
    if (idx === -1) {
      const newPattern = {
        id: expectedId,
        type: "consultation_pattern",
        target: patternData.target,
        frequency: {
          count: 1,
          firstSeenAt: now,
          lastSeenAt: now,
          windowDays: patternData.frequency?.windowDays || 14,
        },
        contexts: patternData.contexts ? [...patternData.contexts] : [],
        status: "active",
        schemaVersion: W_SCHEMA_VERSION,
      };
      list.push(newPattern);
      await _writeCategory("patterns", list);
      return newPattern;
    }
    list[idx].frequency.count += 1;
    list[idx].frequency.lastSeenAt = now;
    if (patternData.contexts) {
      list[idx].contexts.push(...patternData.contexts);
    }
    await _writeCategory("patterns", list);
    return list[idx];
  }

  async function listPatterns() {
    return await _readCategory("patterns");
  }

  async function deletePattern(id) {
    const list = await _readCategory("patterns");
    const filtered = list.filter(p => p.id !== id);
    if (filtered.length === list.length) return false;
    await _writeCategory("patterns", filtered);
    return true;
  }

  async function updatePatternStatus(id, newStatus) {
    const list = await _readCategory("patterns");
    const idx = list.findIndex(p => p.id === id);
    if (idx === -1) return false;
    list[idx].status = newStatus;
    await _writeCategory("patterns", list);
    return true;
  }

  // ──────────────────────────────────────────────────────────────────────────
  // API pública · FOCUSES (atención declarada)
  // ──────────────────────────────────────────────────────────────────────────

  async function addFocus(focusData) {
    if (!W_ENABLED) return null;
    await _ensureMeta();
    const focus = {
      id: _generateId("w_f"),
      type: "attention_focus",
      target: focusData.target || null,
      declaredAt: focusData.declaredAt || _nowISO(),
      followUpHorizon: focusData.followUpHorizon || "ongoing",
      reason: focusData.reason || "",
      status: "active",
      schemaVersion: W_SCHEMA_VERSION,
    };
    const list = await _readCategory("focuses");
    list.push(focus);
    await _writeCategory("focuses", list);
    return focus;
  }

  async function listFocuses() {
    return await _readCategory("focuses");
  }

  async function deleteFocus(id) {
    const list = await _readCategory("focuses");
    const filtered = list.filter(f => f.id !== id);
    if (filtered.length === list.length) return false;
    await _writeCategory("focuses", filtered);
    return true;
  }

  async function updateFocusStatus(id, newStatus) {
    const list = await _readCategory("focuses");
    const idx = list.findIndex(f => f.id === id);
    if (idx === -1) return false;
    list[idx].status = newStatus;
    await _writeCategory("focuses", list);
    return true;
  }

  // ──────────────────────────────────────────────────────────────────────────
  // API pública · MILESTONES (hitos de negocio)
  // ──────────────────────────────────────────────────────────────────────────

  async function addMilestone(milestoneData) {
    if (!W_ENABLED) return null;
    await _ensureMeta();
    const milestone = {
      id: _generateId("w_m"),
      type: "business_milestone",
      description: milestoneData.description || "",
      declaredAt: milestoneData.declaredAt || _nowISO(),
      scope: milestoneData.scope || "global",
      affectedEntities: milestoneData.affectedEntities || [],
      schemaVersion: W_SCHEMA_VERSION,
    };
    const list = await _readCategory("milestones");
    list.push(milestone);
    await _writeCategory("milestones", list);
    return milestone;
  }

  async function listMilestones() {
    return await _readCategory("milestones");
  }

  async function deleteMilestone(id) {
    const list = await _readCategory("milestones");
    const filtered = list.filter(m => m.id !== id);
    if (filtered.length === list.length) return false;
    await _writeCategory("milestones", filtered);
    return true;
  }

  // ──────────────────────────────────────────────────────────────────────────
  // API pública · DISMISSES (T.4 patch · proactive rejections)

  function _dismissKey(proactiveType, entityRefId, triggerType) {
    const ent = entityRefId || "global";
    return `${proactiveType}::${ent}::${triggerType}`;
  }

  async function addDismiss(input) {
    if (!input || typeof input !== "object") return null;
    const proactiveType = String(input.proactiveType || "");
    const entityRefId = input.entityRefId || null;
    const triggerType = String(input.triggerType || "");
    if (!proactiveType || !triggerType) return null;
    const key = _dismissKey(proactiveType, entityRefId, triggerType);
    const list = await _readCategory("dismisses");
    const existing = list.find(d => d.key === key);
    if (existing) return existing;
    const now = new Date().toISOString();
    const item = {
      id: `w_d_${now.replace(/[^0-9]/g, "").substring(0, 14)}_${list.length}`,
      key,
      proactiveType,
      entityRefId,
      triggerType,
      proactiveVariant: input.proactiveVariant || null,
      dismissedAt: now,
    };
    list.push(item);
    await _writeCategory("dismisses", list);
    return item;
  }

  async function listDismisses() {
    return await _readCategory("dismisses");
  }

  async function wasDismissed(proactiveType, entityRefId, triggerType) {
    if (!proactiveType || !triggerType) return false;
    const key = _dismissKey(proactiveType, entityRefId, triggerType);
    const list = await _readCategory("dismisses");
    return list.some(d => d.key === key);
  }

  async function deleteDismiss(id) {
    const list = await _readCategory("dismisses");
    const filtered = list.filter(d => d.id !== id);
    if (filtered.length === list.length) return false;
    await _writeCategory("dismisses", filtered);
    return true;
  }

  async function clearDismisses() {
    await _writeCategory("dismisses", []);
    return true;
  }

  // ──────────────────────────────────────────────────────────────────────────
  // API pública · PREFERENCES (V.1 patch · executive preferences ONLY)
  //
  // V.1 implementa 6ta categoría de memoria · paridad arquitectónica con
  // T.4a (dismisses). 3 shapes tipados EXCLUSIVAMENTE para preferencias
  // ejecutivas de análisis. Cualquier shape no tipado → rechazo silencioso.
  //
  // SHAPES AUTORIZADOS (Principio #0-bis ALCANCE PREFERENCIAS):
  //   · priority · target entidad/módulo · level +1/-1
  //   · depth    · level high/medium/low · scope global/módulo
  //   · focus    · target métrica/entidad · status active
  //
  // V NO almacena gustos personales · emociones · datos no-ejecutivos.

  function _validatePreferenceShape(input) {
    if (!input || typeof input !== "object") return null;
    const type = input.type;
    if (!["priority", "depth", "focus"].includes(type)) return null;

    if (type === "priority") {
      if (!input.target || typeof input.target !== "object") return null;
      if (!["entity", "module"].includes(input.target.kind)) return null;
      if (typeof input.target.name !== "string" || !input.target.name) return null;
      if (![1, -1].includes(input.level)) return null;
      return {
        type: "priority",
        target: {
          kind: input.target.kind,
          name: input.target.name,
          refId: input.target.refId || null,
        },
        level: input.level,
      };
    }

    if (type === "depth") {
      if (!["high", "medium", "low"].includes(input.level)) return null;
      let scope = "global";
      if (input.scope && typeof input.scope === "object" && input.scope.module) {
        if (!["ventas", "margenes", "inventario"].includes(input.scope.module)) return null;
        scope = { module: input.scope.module };
      } else if (input.scope === "global" || !input.scope) {
        scope = "global";
      } else {
        return null;
      }
      return { type: "depth", level: input.level, scope };
    }

    if (type === "focus") {
      if (!input.target || typeof input.target !== "object") return null;
      if (!["metric", "entity"].includes(input.target.kind)) return null;
      if (typeof input.target.name !== "string" || !input.target.name) return null;
      return {
        type: "focus",
        target: {
          kind: input.target.kind,
          name: input.target.name,
          refId: input.target.refId || null,
        },
      };
    }

    return null;
  }

  function _preferenceKey(validated) {
    if (validated.type === "depth") {
      const scopeKey = typeof validated.scope === "object" ? validated.scope.module : "global";
      return `depth::${scopeKey}`;
    }
    return `${validated.type}::${validated.target.kind}::${validated.target.name}`;
  }

  async function setPreference(input) {
    const validated = _validatePreferenceShape(input);
    if (!validated) return null;
    const key = _preferenceKey(validated);
    const list = await _readCategory("preferences");
    const now = new Date().toISOString();
    const existingIdx = list.findIndex(p => p.status === "active" && _preferenceKey(p) === key);

    if (existingIdx >= 0) {
      list[existingIdx] = {
        ...list[existingIdx],
        ...validated,
        declaredAt: now,
        status: "active",
      };
      await _writeCategory("preferences", list);
      return list[existingIdx];
    }

    const item = {
      id: `w_p_${now.replace(/[^0-9]/g, "").substring(0, 14)}_${list.length}`,
      ...validated,
      declaredAt: now,
      status: "active",
    };
    list.push(item);
    await _writeCategory("preferences", list);
    return item;
  }

  async function getPreference(type, targetName) {
    if (!["priority", "depth", "focus"].includes(type)) return null;
    const list = await _readCategory("preferences");
    if (type === "depth") {
      return list.find(p => p.status === "active" && p.type === "depth" && (
        (targetName === "global" && p.scope === "global") ||
        (typeof p.scope === "object" && p.scope.module === targetName)
      )) || null;
    }
    return list.find(p => p.status === "active" && p.type === type && p.target?.name === targetName) || null;
  }

  async function listPreferences(filter) {
    const list = await _readCategory("preferences");
    let result = list.filter(p => p.status === "active");
    if (filter && typeof filter === "object") {
      if (filter.type && ["priority", "depth", "focus"].includes(filter.type)) {
        result = result.filter(p => p.type === filter.type);
      }
    }
    return result;
  }

  async function deletePreference(id) {
    const list = await _readCategory("preferences");
    const item = list.find(p => p.id === id);
    if (!item) return false;
    item.status = "removed";
    await _writeCategory("preferences", list);
    return true;
  }

  async function clearPreferences() {
    await _writeCategory("preferences", []);
    return true;
  }

  async function getPreferenceStats() {
    const list = await _readCategory("preferences");
    const active = list.filter(p => p.status === "active");
    const byType = { priority: 0, depth: 0, focus: 0 };
    for (const p of active) {
      byType[p.type] = (byType[p.type] || 0) + 1;
    }
    return {
      total_active: active.length,
      by_type: byType,
      total_records: list.length,
      shapes_authorized: ["priority", "depth", "focus"],
    };
  }

  // ──────────────────────────────────────────────────────────────────────────
  // API pública · META + UTILIDADES
  // ──────────────────────────────────────────────────────────────────────────

  async function getMeta() {
    return await _ensureMeta();
  }

  async function getStorageInfo() {
    return {
      mode: _storage.mode,
      is_persistent: _storage.is_persistent,
      w_enabled: W_ENABLED,
      schemaVersion: W_SCHEMA_VERSION,
    };
  }

  async function clearAll() {
    // Privacy control D-W-PRIVACY-CONTROL = C · founder puede borrar TODO
    if (!W_ENABLED) return false;
    await _storage.del("w_memory:meta");
    await _storage.del("w_memory:decisions");
    await _storage.del("w_memory:patterns");
    await _storage.del("w_memory:focuses");
    await _storage.del("w_memory:milestones");
    await _storage.del("w_memory:dismisses");
    await _storage.del("w_memory:preferences");
    _cache.meta = null;
    _cache.decisions = null;
    _cache.patterns = null;
    _cache.focuses = null;
    _cache.milestones = null;
    _cache.dismisses = null;
    _cache.preferences = null;
    return true;
  }

  return {
    // Decisions
    addDecision, listDecisions, getDecisionById,
    deleteDecision, updateDecisionStatus,
    // Patterns
    upsertPattern, listPatterns, deletePattern, updatePatternStatus,
    // Focuses
    addFocus, listFocuses, deleteFocus, updateFocusStatus,
    // Milestones
    addMilestone, listMilestones, deleteMilestone,
    // Dismisses (T.4 patch · proactive rejections)
    addDismiss, listDismisses, wasDismissed, deleteDismiss, clearDismisses,
    // Preferences (V.1 patch · executive preferences ONLY · 6ta categoría)
    setPreference, getPreference, listPreferences,
    deletePreference, clearPreferences, getPreferenceStats,
    // Meta + util
    getMeta, getStorageInfo, clearAll,
  };
})();

// ──────────────────────────────────────────────────────────────────────────
// VOICE_BRIEF_W_PARTIAL · flag ceremonial W.1 (paridad S.I + U.F + AN.E)
// ──────────────────────────────────────────────────────────────────────────
