// VOICE_BRIEF_W_COMPLETE = true se setea cuando W.6 (integración composers) cierre.
// Consumers futuros (T/V/ECL) pueden check: if (VOICE_BRIEF_W_PARTIAL) { ... }
const VOICE_BRIEF_W_PARTIAL = true;
const VOICE_BRIEF_W_COMPLETE = true;

async function getBriefWStats() {
  const meta = await OrganizationalMemory.getMeta();
  const decisions = await OrganizationalMemory.listDecisions();
  const patterns = await OrganizationalMemory.listPatterns();
  const focuses = await OrganizationalMemory.listFocuses();
  const milestones = await OrganizationalMemory.listMilestones();
  const storage = await OrganizationalMemory.getStorageInfo();
  return {
    brief: "W",
    status: VOICE_BRIEF_W_PARTIAL ? "partial_w1" : "in_progress",
    pieces_status: {
      W_1_data_storage: "complete",
      W_2_detection: "complete",
      W_3_pattern_detection: "complete",
      W_4_recall_api: "complete",
      W_5_ui_memoria: "complete",
      W_6_integration: "complete",
    },
    schema_version: meta?.schemaVersion || null,
    storage_mode: storage.mode,
    is_persistent: storage.is_persistent,
    w_enabled: W_ENABLED,
    counts: {
      decisions: decisions.length,
      patterns: patterns.length,
      focuses: focuses.length,
      milestones: milestones.length,
      total: decisions.length + patterns.length + focuses.length + milestones.length,
    },
    parity_pattern: "S.A-S.I (memory store) ↔ U.A-U.F (calibration) ↔ AN.A-AN.E (navigation) ↔ W.1-W.6 (organizational memory)",
    invariants_preserved: [
      "EntityRegistry bitwise (S.A LOCKED)",
      "MemoryStore bitwise (S.B LOCKED)",
      "_storage wrapper bitwise (D-S-2-REFACTOR)",
      "48+ composers v1.x-calibrated bitwise",
    ],
  };
}

