// ════════════════════════════════════════════════════════════════════════════
// BRIEF V · V.2 · OrgPreferenceDetector ⚙️
// PURE DETECTOR · whitelist 6 patterns deícticos · Principio #2 BRIEF V
// ════════════════════════════════════════════════════════════════════════════
//
// Detecta comandos conversacionales del founder que declaran preferencias
// ejecutivas de análisis. WHITELIST ESTRICTA · cualquier comando fuera de los
// 6 patterns → return null silencioso.
//
// V.2 NO escribe nada · NO consulta memoria · NO modifica estado.
// V.2 solo parsea texto y retorna intent estructurado para V.6 wrapper.
//
// Paralelo arquitectónico: W.2 (OrgMemoryDetector) y T.1 (OrgProactiveDetector).
//
// PRINCIPIOS APLICADOS (BRIEF_V_DESIGN_v1.md):
//   #0      · solo análisis ejecutivo · cero gustos/emociones/personal
//   #0-bis  · whitelist 3 dimensiones (priority/depth/focus)
//   #1      · solo declaración explícita · cero inferencia
//   #2      · 6 patterns deícticos cerrados
// ════════════════════════════════════════════════════════════════════════════

// Patterns deícticos · array de objetos { regex, type, level?, status?, needsTarget }
// Orden importa · primer match gana (determinístico)
const V2_PREFERENCE_PATTERNS = [
  // PRIORITY POSITIVA
  { regex: /me\s+importa\s+m[áa]s\s+(.+)/i, type: "priority", level: 1, needsTarget: true, label: "me_importa_mas" },
  { regex: /priori[zc][aá]\s+(.+)/i, type: "priority", level: 1, needsTarget: true, label: "prioriza" },
  // PRIORITY NEGATIVA
  { regex: /no\s+me\s+muestres\s+m[áa]s\s+(.+)/i, type: "priority", level: -1, needsTarget: true, label: "no_muestres_mas" },
  { regex: /me\s+importa\s+menos\s+(.+)/i, type: "priority", level: -1, needsTarget: true, label: "me_importa_menos" },
  // FOCUS ACTIVO
  { regex: /^foco\s+en\s+(.+)/i, type: "focus", status: "active", needsTarget: true, label: "foco_en" },
  { regex: /focali[zc][aá]\s+(?:en\s+)?(.+)/i, type: "focus", status: "active", needsTarget: true, label: "focaliza_en" },
  // FOCUS INACTIVO
  { regex: /olvida\s+(?:el\s+)?foco\s+(?:en\s+|sobre\s+)?(.+)/i, type: "focus", status: "inactive", needsTarget: true, label: "olvida_foco" },
  { regex: /quita\s+(?:el\s+)?foco\s+(?:de\s+|sobre\s+)?(.+)/i, type: "focus", status: "inactive", needsTarget: true, label: "quita_foco" },
  // DEPTH HIGH
  { regex: /m[áa]s\s+(?:detalle|profundidad|profundo)/i, type: "depth", level: "high", needsTarget: false, label: "mas_detalle" },
  { regex: /quiero\s+m[áa]s\s+detalle/i, type: "depth", level: "high", needsTarget: false, label: "quiero_mas_detalle" },
  // DEPTH LOW
  { regex: /menos\s+(?:detalle|profundidad)/i, type: "depth", level: "low", needsTarget: false, label: "menos_detalle" },
  { regex: /m[áa]s\s+(?:breve|conciso|corto)/i, type: "depth", level: "low", needsTarget: false, label: "mas_breve" },
];

// Vocabulario para extraer target (paralelo a vocabulario T.3)
const V2_VALID_MODULES = ["ventas", "margenes", "márgenes", "inventario"];
const V2_VALID_METRICS = ["margen", "márgenes", "carga", "doh", "contribución", "contribucion", "concentración", "concentracion", "rotación", "rotacion", "ventas"];

const OrgPreferenceDetector = (function _initOrgPreferenceDetector() {

  // ──────────────────────────────────────────────────────────────────────
  // Helper · normaliza texto · paridad W.2/T.1
  // ──────────────────────────────────────────────────────────────────────

  function _normalizeText(text) {
    if (typeof text !== "string") return "";
    return text.trim();
  }

  // ──────────────────────────────────────────────────────────────────────
  // Helper · extrae target del raw match
  // Prioridad: entity (EntityRegistry) → module → metric
  // ──────────────────────────────────────────────────────────────────────

  function _extractTarget(targetText) {
    const txt = typeof targetText === "string" ? targetText.trim() : "";
    if (!txt) return null;

    // Strip puntos finales · "Falabella." → "Falabella"
    const clean = txt.replace(/[.!?]+$/, "").trim();
    const lower = clean.toLowerCase();

    // 1. Buscar entidad via EntityRegistry (si existe)
    if (typeof _extractEntitiesFromText === "function") {
      try {
        const entities = _extractEntitiesFromText(clean);
        if (entities && entities.length > 0) {
          const ent = entities[0];
          return {
            kind: "entity",
            name: ent.canonical_name || ent.name || clean,
            refId: ent.entityRefId || ent.refId || null,
          };
        }
      } catch (e) { /* fall-through */ }
    }

    // 2. Buscar módulo
    for (const m of V2_VALID_MODULES) {
      if (lower.includes(m)) {
        const moduleName = m === "márgenes" ? "margenes" : m;
        return { kind: "module", name: moduleName, refId: null };
      }
    }

    // 3. Buscar métrica
    for (const metric of V2_VALID_METRICS) {
      if (lower.includes(metric)) {
        const metricName = metric
          .replace("márgenes", "margen")
          .replace("contribución", "contribucion")
          .replace("concentración", "concentracion")
          .replace("rotación", "rotacion");
        return { kind: "metric", name: metricName, refId: null };
      }
    }

    return null;
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · detectPreferenceCommand
  // ──────────────────────────────────────────────────────────────────────
  //
  // Argumentos:
  //   text: string · texto crudo del founder
  //
  // Returns:
  //   { detected: false }                              · si no matchea whitelist
  //   {
  //     detected: true,
  //     type: "priority" | "depth" | "focus",
  //     target?: { kind, name, refId },                · si needsTarget=true
  //     level?: 1 | -1 | "high" | "low",
  //     status?: "active" | "inactive",                · solo para focus
  //     scope?: "global" | { module },                 · solo para depth
  //     raw_match: string,                             · texto match original
  //     pattern_label: string                          · debug · ID de pattern
  //   }

  function detectPreferenceCommand(text) {
    const norm = _normalizeText(text);
    if (!norm) return { detected: false };

    for (const pattern of V2_PREFERENCE_PATTERNS) {
      const match = norm.match(pattern.regex);
      if (!match) continue;

      const result = {
        detected: true,
        type: pattern.type,
        raw_match: match[0],
        pattern_label: pattern.label,
      };

      if (pattern.type === "depth") {
        result.level = pattern.level;
        result.scope = "global";  // V.2 solo soporta global por ahora · módulo en V futuro
        return result;
      }

      if (pattern.type === "focus") {
        result.status = pattern.status;
        if (pattern.needsTarget) {
          const target = _extractTarget(match[1]);
          if (!target) return { detected: false };  // pattern matcheó pero no extrajo target → ignorar
          result.target = target;
        }
        return result;
      }

      if (pattern.type === "priority") {
        result.level = pattern.level;
        if (pattern.needsTarget) {
          const target = _extractTarget(match[1]);
          if (!target) return { detected: false };
          if (target.kind === "metric") return { detected: false };  // priority NO soporta métricas (solo entity/module)
          result.target = target;
        }
        return result;
      }
    }

    return { detected: false };
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · getDetectorStats (introspección)
  // ──────────────────────────────────────────────────────────────────────

  function getDetectorStats() {
    return {
      patterns_count: V2_PREFERENCE_PATTERNS.length,
      patterns_by_type: V2_PREFERENCE_PATTERNS.reduce((acc, p) => {
        acc[p.type] = (acc[p.type] || 0) + 1;
        return acc;
      }, {}),
      labels: V2_PREFERENCE_PATTERNS.map(p => p.label),
      valid_modules: V2_VALID_MODULES,
      valid_metrics: V2_VALID_METRICS,
    };
  }

  return {
    detectPreferenceCommand,
    getDetectorStats,
  };
})();

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF V · V.2 · OrgPreferenceDetector ⚙️
// (próxima pieza: V.3 · OrgPreferenceApplier · hooks read-only)
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF V · V.3 · OrgPreferenceApplier ⚙️📖
// PURE APPLIER · read-only · hooks consultados por consumers
// ════════════════════════════════════════════════════════════════════════════
//
// Expone 3 hooks principales que cualquier consumer puede consultar para
// determinar las preferencias activas del founder · sin escribir estado.
//
// Consumers actuales:
//   · T.5 OrgProactiveSelector (V.4 patch · priority + focus boost en scoring)
//
// Consumers futuros (post-V):
//   · Composers v1.x · depth para verbosity ajustable (BRIEF ECL)
//   · Otros agentes ADI (cross-module · dispatcher)
//
// Defaults balanced (Principio #5 BRIEF V):
//   · priority sin pref → 0 (neutro)
//   · depth sin pref → "medium" (comportamiento actual)
//   · focus sin pref → [] (vacío)
//
// GARANTÍA: sin preferencias declaradas = ADI bitwise idéntico actual.
// ════════════════════════════════════════════════════════════════════════════

const OrgPreferenceApplier = (function _initOrgPreferenceApplier() {

  // ──────────────────────────────────────────────────────────────────────
  // Helper · obtener todas las preferences active de un tipo
  // ──────────────────────────────────────────────────────────────────────

  async function _getActiveByType(type) {
    if (typeof OrganizationalMemory === "undefined") return [];
    if (typeof OrganizationalMemory.listPreferences !== "function") return [];
    try {
      return await OrganizationalMemory.listPreferences({ type });
    } catch (e) {
      return [];
    }
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · getActivePriority
  // ──────────────────────────────────────────────────────────────────────
  //
  // Argumentos:
  //   target: string · puede ser entityRefId (ej: "client_falabella") o
  //           name (ej: "Falabella" · "ventas")
  //
  // Returns: +1 | 0 | -1
  //   · +1 = founder lo declaró como prioritario
  //   · -1 = founder pidió mostrar menos
  //   ·  0 = sin preferencia (default balanced)

  async function getActivePriority(target) {
    if (typeof target !== "string" || !target) return 0;
    const list = await _getActiveByType("priority");
    if (list.length === 0) return 0;

    // Tier 1 · match exacto por refId
    let match = list.find(p => p.target?.refId === target);
    // Tier 2 · match por name (entity o module)
    if (!match) {
      const lower = target.toLowerCase();
      match = list.find(p => p.target?.name && p.target.name.toLowerCase() === lower);
    }
    if (!match) return 0;
    return match.level;
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · getActiveDepth
  // ──────────────────────────────────────────────────────────────────────
  //
  // Argumentos:
  //   moduleName: string opcional · ej: "ventas" · "margenes" · "inventario"
  //
  // Returns: "high" | "medium" | "low"
  //   · default "medium" (ADI actual)
  //
  // Override resolution:
  //   · Si moduleName + existe pref scope={module: X} con X===moduleName → usa
  //   · Else · usa scope global
  //   · Else · "medium"

  async function getActiveDepth(moduleName) {
    const list = await _getActiveByType("depth");
    if (list.length === 0) return "medium";

    // Tier 1 · override por módulo
    if (moduleName && typeof moduleName === "string") {
      const moduleMatch = list.find(p =>
        typeof p.scope === "object" && p.scope.module === moduleName
      );
      if (moduleMatch) return moduleMatch.level;
    }

    // Tier 2 · scope global
    const globalMatch = list.find(p => p.scope === "global");
    if (globalMatch) return globalMatch.level;

    return "medium";
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · getActiveFocus
  // ──────────────────────────────────────────────────────────────────────
  //
  // Returns: array de FocusPreference (cada uno con target.kind/name/refId)
  //   · default [] (sin focos declarados)

  async function getActiveFocus() {
    const list = await _getActiveByType("focus");
    return list;
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · hasAnyPreference (fast path para consumers)
  // ──────────────────────────────────────────────────────────────────────
  //
  // Returns: boolean
  //   · true si existe al menos 1 preferencia active de cualquier tipo
  //   · útil para skip lookups si el founder no ha personalizado nada

  async function hasAnyPreference() {
    if (typeof OrganizationalMemory === "undefined") return false;
    if (typeof OrganizationalMemory.listPreferences !== "function") return false;
    try {
      const all = await OrganizationalMemory.listPreferences();
      return all.length > 0;
    } catch (e) {
      return false;
    }
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · isEntityInFocus (helper conveniente)
  // ──────────────────────────────────────────────────────────────────────
  //
  // Argumentos:
  //   entityRefIdOrName: string
  //
  // Returns: boolean

  async function isEntityInFocus(entityRefIdOrName) {
    if (typeof entityRefIdOrName !== "string" || !entityRefIdOrName) return false;
    const focuses = await getActiveFocus();
    if (focuses.length === 0) return false;
    const lower = entityRefIdOrName.toLowerCase();
    return focuses.some(f =>
      (f.target?.refId === entityRefIdOrName) ||
      (f.target?.name && f.target.name.toLowerCase() === lower)
    );
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · getApplierStats (introspección)
  // ──────────────────────────────────────────────────────────────────────

  async function getApplierStats() {
    if (typeof OrganizationalMemory === "undefined") {
      return {
        total_active: 0,
        priorities_count: 0,
        depth_set: false,
        focuses_count: 0,
        memory_available: false,
      };
    }
    try {
      const all = await OrganizationalMemory.listPreferences();
      const byType = { priority: 0, depth: 0, focus: 0 };
      for (const p of all) {
        byType[p.type] = (byType[p.type] || 0) + 1;
      }
      return {
        total_active: all.length,
        priorities_count: byType.priority,
        depth_set: byType.depth > 0,
        focuses_count: byType.focus,
        memory_available: true,
      };
    } catch (e) {
      return {
        total_active: 0,
        priorities_count: 0,
        depth_set: false,
        focuses_count: 0,
        memory_available: false,
      };
    }
  }

  return {
    getActivePriority,
    getActiveDepth,
    getActiveFocus,
    hasAnyPreference,
    isEntityInFocus,
    getApplierStats,
  };
})();

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF V · V.3 · OrgPreferenceApplier ⚙️📖
// (próxima pieza: V.4 · Patches mínimos T.5 · priority + focus scoring)
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF W · ORGANIZATIONAL MEMORY · W.2 · DETECTION LAYER 🧠
// ════════════════════════════════════════════════════════════════════════════
//
// PURE DETECTOR · cero cableado runtime hasta W.6
// Consumer de OrganizationalMemory (W.1) · CRUD para promoción
// Consumer de _extractEntitiesFromText (S.B helper) · gate E
// Consumer de EntityRegistry (S.A) · resolución de canonical
//
// Regla AAA·E·F · gate arquitectónico vinculante (founder firmó):
//   Promoción a memoria requiere SIMULTÁNEAMENTE:
//   (A) Acción Declarativa · verbo en triggers categoría
//   (E) Entidad Empresarial Válida · _extractEntitiesFromText >=1
//   (F) Filtro Especulativo Limpio · cero marcadores
//
// Gate E.bis · I1 + I3 (founder firmó D-W2-AMBIGUEDAD = C):
//   (E.bis.I1) Si mismo token resuelve a >1 entityRefId · ambiguo · cero promoción
//   (E.bis.I3) Si >1 entidad detectada en decision/focus · ambiguo · cero promoción
//             Excepción: milestones sistémicos (regulacion/equipo) permiten múltiples
//
// Decisiones firmadas:
//   D-W2-RUNTIME = 3        (PURE DETECTOR · diferir cableado a W.6)
//   D-W2-DETECCION = C      (híbrido)
//   D-W2-EVIDENCIA = AAA·E·F (regla vinculante)
//   D-W2-AMBIGUEDAD = C     (I1 + I3 con excepción milestones sistémicos)
// ════════════════════════════════════════════════════════════════════════════

// ── Marcadores especulativos · gate F · STRICT (founder firmó) ──────────────
const W2_SPECULATIVE_MARKERS = [
  "quizás", "quizas",
  "tal vez", "talvez",
  "podría", "podria", "podrían", "podrian",
  "puede ser",
  "sospecho", "sospecho que",
  "parece", "parece que",
  "capaz",
  "es posible", "posiblemente",
  "supongo", "supongo que",
  "creo que",
  "me da la sensación", "me da la sensacion",
  "suena a",
  "da la impresión", "da la impresion",
  "no estoy seguro", "no estoy segura",
];

// ── Triggers · gate A · acción declarativa por categoría ────────────────────

const W2_DECISION_TRIGGERS = {
  renegociar:  ["decidí renegociar", "voy a renegociar", "ya renegoci",
                "renegocié", "renegoci"],
  liquidar:    ["decidí liquidar", "voy a liquidar", "ya liquid",
                "liquidé", "vamos a liquidar"],
  escalar:     ["decidí escalar", "voy a escalar", "ya escal",
                "escalé", "vamos a escalar"],
  stop_loss:   ["decidí cortar", "voy a cortar", "ya cort",
                "cortamos", "stop loss"],
  monitorear:  ["decidí monitorear", "vamos a monitorear", "voy a monitorear"],
  aprobar:     ["aprobé", "aprobamos", "decidí aprobar", "ya aprob"],
  otro:        ["decidí", "ya decidí", "ya decidimos", "tomé la decisión",
                "tomamos la decisión"],
};

const W2_FOCUS_TRIGGERS = {
  ongoing:     ["voy a seguir", "vamos a seguir", "tengo que seguir",
                "necesito seguir", "seguir de cerca"],
  weekly:      ["seguimiento semanal", "revisar cada semana",
                "ver cada semana"],
  monthly:     ["seguimiento mensual", "revisar cada mes",
                "monitorear mensual"],
  quarterly:   ["seguimiento trimestral", "revisar trimestral"],
  generic:     ["vigilar", "monitorear", "atención a",
                "poner atención", "estar pendiente de"],
};

const W2_MILESTONE_TRIGGERS = {
  competidor:  ["entró un competidor", "nuevo competidor",
                "apareció un competidor"],
  regulacion:  ["cambió la regulación", "nueva regulación",
                "modificación regulatoria"],
  equipo:      ["perdimos al equipo", "se fue el equipo",
                "renunció el equipo"],
  confirmado:  ["confirmé que", "confirmamos que", "se confirmó que",
                "verificamos que", "validamos que"],
  cambio:      ["cambió", "se modificó", "ya cambió"],
};

// Milestones SISTÉMICOS · permiten múltiples entidades (gate E.bis excepción)
const W2_SYSTEMIC_MILESTONE_CATEGORIES = new Set(["regulacion", "equipo"]);

// ── OrgMemoryDetector · namespace W.2 · IIFE PURE DETECTOR ──────────────────

const OrgMemoryDetector = (function _initOrgMemoryDetector() {

  function _normalizeText(text) {
    if (typeof text !== "string") return "";
    return text.toLowerCase().trim();
  }

  // ──────────────────────────────────────────────────────────────────────
  // Gate F · Filtro Especulativo (estricto)
  // ──────────────────────────────────────────────────────────────────────
  function isSpeculative(text) {
    const norm = _normalizeText(text);
    if (norm.length === 0) return false;
    for (const marker of W2_SPECULATIVE_MARKERS) {
      if (norm.includes(marker)) return true;
    }
    return false;
  }

  // ──────────────────────────────────────────────────────────────────────
  // Gate E · Entidad Válida + Gate E.bis · Ambigüedad
  // ──────────────────────────────────────────────────────────────────────
  function _extractValidEntities(text) {
    if (typeof _extractEntitiesFromText !== "function") return [];
    const entityIds = _extractEntitiesFromText(text);
    if (!Array.isArray(entityIds) || entityIds.length === 0) return [];
    const entities = [];
    for (const id of entityIds) {
      if (typeof EntityRegistry !== "undefined" && EntityRegistry.entities[id]) {
        const e = EntityRegistry.entities[id];
        entities.push({
          kind: e.kind,
          name: e.canonical_name,
          entityRefId: id,
        });
      }
    }
    return entities;
  }

  function _extractValidEntitiesStrict(text, allowMultiple) {
    const entities = _extractValidEntities(text);
    if (entities.length === 0) {
      return { entities: [], ambiguous: false, reason: "no_entity" };
    }
    if (entities.length > 1 && !allowMultiple) {
      // Gate E.bis · I3 · múltiples entidades en decision/focus → ambiguo
      return { entities, ambiguous: true, reason: "multiple_entities" };
    }
    return { entities, ambiguous: false, reason: "ok" };
  }

  // ──────────────────────────────────────────────────────────────────────
  // Gate A · Trigger Match
  // ──────────────────────────────────────────────────────────────────────
  function _matchTrigger(text, triggerMap) {
    const norm = _normalizeText(text);
    for (const category of Object.keys(triggerMap)) {
      for (const phrase of triggerMap[category]) {
        if (norm.includes(phrase)) {
          return { matched: true, category, phrase };
        }
      }
    }
    return { matched: false, category: null, phrase: null };
  }

  // ──────────────────────────────────────────────────────────────────────
  // Detector 1 · DECISIONES (strict · 1 entidad única)
  // ──────────────────────────────────────────────────────────────────────
  function detectDecisionTrigger(text) {
    if (isSpeculative(text)) {
      return { detected: false, reason: "speculative" };
    }
    const trigger = _matchTrigger(text, W2_DECISION_TRIGGERS);
    if (!trigger.matched) {
      return { detected: false, reason: "no_trigger_decision" };
    }
    const entResult = _extractValidEntitiesStrict(text, false);
    if (entResult.entities.length === 0) {
      return { detected: false, reason: "no_valid_entity" };
    }
    if (entResult.ambiguous) {
      return { detected: false, reason: "ambiguous_entity" };
    }
    return {
      detected: true,
      type: "decision",
      category: trigger.category,
      triggerPhrase: trigger.phrase,
      entity: entResult.entities[0],
      narrativaSummary: text.substring(0, 200),
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // Detector 2 · FOCOS DECLARADOS (strict · 1 entidad única)
  // ──────────────────────────────────────────────────────────────────────
  function detectFocusTrigger(text) {
    if (isSpeculative(text)) {
      return { detected: false, reason: "speculative" };
    }
    const trigger = _matchTrigger(text, W2_FOCUS_TRIGGERS);
    if (!trigger.matched) {
      return { detected: false, reason: "no_trigger_focus" };
    }
    const entResult = _extractValidEntitiesStrict(text, false);
    if (entResult.entities.length === 0) {
      return { detected: false, reason: "no_valid_entity" };
    }
    if (entResult.ambiguous) {
      return { detected: false, reason: "ambiguous_entity" };
    }
    const horizon = (trigger.category === "generic") ? "ongoing" : trigger.category;
    return {
      detected: true,
      type: "focus",
      target: {
        kind: "entity",
        entity: entResult.entities[0],
        topic: null,
      },
      followUpHorizon: horizon,
      reason: text.substring(0, 200),
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // Detector 3 · MILESTONES (sistémicos permiten múltiples · excepción E.bis)
  // ──────────────────────────────────────────────────────────────────────
  function detectMilestoneTrigger(text) {
    if (isSpeculative(text)) {
      return { detected: false, reason: "speculative" };
    }
    const trigger = _matchTrigger(text, W2_MILESTONE_TRIGGERS);
    if (!trigger.matched) {
      return { detected: false, reason: "no_trigger_milestone" };
    }
    const isSystemic = W2_SYSTEMIC_MILESTONE_CATEGORIES.has(trigger.category);
    // Sistémicos permiten múltiples entidades · no-sistémicos requieren única
    const entResult = _extractValidEntitiesStrict(text, isSystemic);
    if (!isSystemic && entResult.entities.length === 0) {
      return { detected: false, reason: "no_valid_entity_for_specific_milestone" };
    }
    if (!isSystemic && entResult.ambiguous) {
      return { detected: false, reason: "ambiguous_entity" };
    }
    return {
      detected: true,
      type: "milestone",
      category: trigger.category,
      triggerPhrase: trigger.phrase,
      description: text.substring(0, 300),
      scope: isSystemic ? "global" : "entity_specific",
      affectedEntities: entResult.entities.map(e => e.entityRefId),
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // Orchestrator
  // ──────────────────────────────────────────────────────────────────────
  function detectAllTriggers(text, context) {
    const ctx = context || {};
    const candidates = [];
    const dec = detectDecisionTrigger(text);
    if (dec.detected) candidates.push(dec);
    const foc = detectFocusTrigger(text);
    if (foc.detected) candidates.push(foc);
    const mil = detectMilestoneTrigger(text);
    if (mil.detected) candidates.push(mil);
    return {
      text,
      context: ctx,
      candidates,
      blockedBySpeculative: isSpeculative(text),
      detectedCount: candidates.length,
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // Promoter · enforcement AAA·E·F + E.bis
  // ──────────────────────────────────────────────────────────────────────
  async function promoteIfValid(text, context) {
    if (!W_ENABLED) {
      return { promoted: [], reason: "w_disabled" };
    }
    const ctx = context || {};
    const analysis = detectAllTriggers(text, ctx);
    if (analysis.blockedBySpeculative) {
      return { promoted: [], reason: "speculative", analysis };
    }
    if (analysis.candidates.length === 0) {
      return { promoted: [], reason: "no_triggers", analysis };
    }
    const promotedIds = [];
    for (const candidate of analysis.candidates) {
      if (candidate.type === "decision") {
        const dec = await OrganizationalMemory.addDecision({
          category: candidate.category,
          entity: candidate.entity,
          scenarioActivo: ctx.scenarioActivo || null,
          context: {
            moduloAlMomento: ctx.moduloAlMomento || null,
            cifraReferenciada: ctx.cifraReferenciada || null,
            narrativaSummary: candidate.narrativaSummary,
          },
        });
        if (dec) promotedIds.push({ id: dec.id, type: "decision" });
      } else if (candidate.type === "focus") {
        const foc = await OrganizationalMemory.addFocus({
          target: candidate.target,
          followUpHorizon: candidate.followUpHorizon,
          reason: candidate.reason,
        });
        if (foc) promotedIds.push({ id: foc.id, type: "focus" });
      } else if (candidate.type === "milestone") {
        const mil = await OrganizationalMemory.addMilestone({
          description: candidate.description,
          scope: candidate.scope,
          affectedEntities: candidate.affectedEntities,
        });
        if (mil) promotedIds.push({ id: mil.id, type: "milestone" });
      }
    }
    return {
      promoted: promotedIds,
      reason: "success",
      promotedCount: promotedIds.length,
      analysis,
    };
  }

  return {
    detectDecisionTrigger,
    detectFocusTrigger,
    detectMilestoneTrigger,
    detectAllTriggers,
    promoteIfValid,
    isSpeculative,
  };
})();

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF W · W.2 · DETECTION LAYER 🧠
// (próxima pieza: W.3 · Pattern Detection · contadores frecuencia)
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF W · ORGANIZATIONAL MEMORY · W.3 · PATTERN DETECTION 🧠
// ════════════════════════════════════════════════════════════════════════════
//
// PURE DETECTOR · cero cableado runtime hasta W.6
// Consumer de OrganizationalMemory (W.1) · CRUD upsertPattern + listPatterns +
//                                          updatePatternStatus (W.3a patch)
// Consumer de OrgMemoryDetector (W.2) · isSpeculative para filtro F
//
// Patrón observable · NO declarativo:
//   W.2 detecta TRIGGERS DECLARATIVOS (founder declara explícito)
//   W.3 detecta PATRONES OBSERVABLES (founder consulta repetido)
//
// Decisiones firmadas:
//   D-W3-VENTANA = B          · 14 días default
//   D-W3-UMBRAL = B           · 3 consultas mínimo para promoción
//   D-W3-DECAY = B            · "decayed" tras 60 días sin actividad
//   D-W3-INVOCACION = P       · trackConsultation invocado desde W.6
//   D-W3-DECAY-MECHANICS = X  · updatePatternStatus en W.1 (W.3a patch)
// ════════════════════════════════════════════════════════════════════════════

const W3_DEFAULT_WINDOW_DAYS = 14;
const W3_PROMOTION_THRESHOLD = 3;
const W3_DECAY_THRESHOLD_DAYS = 60;

const OrgMemoryPatterns = (function _initOrgMemoryPatterns() {

  // Cache local de counters · key: targetKey (entityRefId|concept)
  // value: { count, firstSeenAt, lastSeenAt, contexts[], promoted }
  const _counters = {};

  // ──────────────────────────────────────────────────────────────────────────
  // Helpers privados
  // ──────────────────────────────────────────────────────────────────────────

  function _nowISO() {
    return new Date().toISOString();
  }

  function _daysSince(isoTimestamp) {
    if (!isoTimestamp) return Infinity;
    const then = new Date(isoTimestamp).getTime();
    const now = Date.now();
    if (isNaN(then)) return Infinity;
    return (now - then) / (1000 * 60 * 60 * 24);
  }

  function _resolveEntityFromRefId(entityRefId) {
    if (typeof EntityRegistry === "undefined") return null;
    if (!EntityRegistry.entities[entityRefId]) return null;
    const e = EntityRegistry.entities[entityRefId];
    return {
      kind: e.kind,
      name: e.canonical_name,
      entityRefId,
    };
  }

  function _getTargetKey(targetSpec) {
    if (!targetSpec) return null;
    if (targetSpec.kind === "entity" && targetSpec.entityRefId) {
      return targetSpec.entityRefId;
    }
    if (targetSpec.kind === "concept" && targetSpec.concept) {
      return targetSpec.concept;
    }
    return null;
  }

  // ──────────────────────────────────────────────────────────────────────────
  // API pública · trackConsultation
  // ──────────────────────────────────────────────────────────────────────────
  //
  // Registra una consulta sobre una entidad o concepto.
  // Si counter cruza el umbral W3_PROMOTION_THRESHOLD · promueve automáticamente
  // a pattern persistido vía OrganizationalMemory.upsertPattern.
  //
  // Aplica filtro F (isSpeculative) sobre context.queryText si presente.
  // NO requiere gate A (no es declarativo · es observable).
  // Gate E aplica implícitamente: targetSpec debe contener entityRefId/concept válidos.
  //
  // Argumentos:
  //   targetSpec: { kind: "entity"|"concept", entityRefId?: string, concept?: string }
  //   context: { module?, scenario?, queryText? }
  //
  // Returns:
  //   { tracked: boolean, count: number, promoted: boolean, patternId?: string,
  //     reason?: "speculative"|"invalid_target"|"w_disabled" }

  async function trackConsultation(targetSpec, context) {
    if (!W_ENABLED) {
      return { tracked: false, count: 0, promoted: false, reason: "w_disabled" };
    }
    const ctx = context || {};
    // Filtro F · si query original es especulativa · cero tracking
    if (ctx.queryText && OrgMemoryDetector.isSpeculative(ctx.queryText)) {
      return { tracked: false, count: 0, promoted: false, reason: "speculative" };
    }
    const targetKey = _getTargetKey(targetSpec);
    if (!targetKey) {
      return { tracked: false, count: 0, promoted: false, reason: "invalid_target" };
    }
    const now = _nowISO();
    // Inicializa o incrementa counter local
    if (!_counters[targetKey]) {
      _counters[targetKey] = {
        count: 0,
        firstSeenAt: now,
        lastSeenAt: now,
        contexts: [],
        promoted: false,
      };
    }
    _counters[targetKey].count += 1;
    _counters[targetKey].lastSeenAt = now;
    if (ctx.module || ctx.scenario) {
      _counters[targetKey].contexts.push({
        module: ctx.module || null,
        scenario: ctx.scenario || null,
      });
    }
    const counter = _counters[targetKey];
    // Verifica umbral de promoción
    if (counter.count >= W3_PROMOTION_THRESHOLD && !counter.promoted) {
      // Construye target persistible
      const persistTarget = (targetSpec.kind === "entity")
        ? {
            kind: "entity",
            entity: _resolveEntityFromRefId(targetSpec.entityRefId),
            concept: null,
          }
        : {
            kind: "concept",
            entity: null,
            concept: targetSpec.concept,
          };
      // Promueve vía W.1 upsertPattern
      const pattern = await OrganizationalMemory.upsertPattern({
        target: persistTarget,
        contexts: counter.contexts,
        frequency: { windowDays: W3_DEFAULT_WINDOW_DAYS },
      });
      counter.promoted = true;
      return {
        tracked: true,
        count: counter.count,
        promoted: true,
        patternId: pattern ? pattern.id : null,
      };
    }
    // Si ya estaba promovido · sigue upserting para incrementar count en storage
    if (counter.promoted) {
      const persistTarget = (targetSpec.kind === "entity")
        ? {
            kind: "entity",
            entity: _resolveEntityFromRefId(targetSpec.entityRefId),
            concept: null,
          }
        : {
            kind: "concept",
            entity: null,
            concept: targetSpec.concept,
          };
      await OrganizationalMemory.upsertPattern({
        target: persistTarget,
        contexts: ctx.module || ctx.scenario
          ? [{ module: ctx.module || null, scenario: ctx.scenario || null }]
          : [],
        frequency: { windowDays: W3_DEFAULT_WINDOW_DAYS },
      });
      return {
        tracked: true,
        count: counter.count,
        promoted: true,
        patternId: `w_p_${targetKey}`,
      };
    }
    // Tracking activo pero aún no cruza umbral
    return {
      tracked: true,
      count: counter.count,
      promoted: false,
    };
  }

  // ──────────────────────────────────────────────────────────────────────────
  // API pública · decayInactivePatterns
  // ──────────────────────────────────────────────────────────────────────────
  //
  // Recorre patterns persistidos en OrganizationalMemory y marca como "decayed"
  // todos los que llevan más de thresholdDays sin actualización.
  //
  // Returns:
  //   { decayed: number, patternsAffected: string[] }

  async function decayInactivePatterns(thresholdDays) {
    if (!W_ENABLED) {
      return { decayed: 0, patternsAffected: [] };
    }
    const threshold = (typeof thresholdDays === "number" && thresholdDays > 0)
      ? thresholdDays
      : W3_DECAY_THRESHOLD_DAYS;
    const patterns = await OrganizationalMemory.listPatterns();
    const decayed = [];
    for (const p of patterns) {
      if (p.status !== "active") continue;
      const lastSeen = p.frequency && p.frequency.lastSeenAt;
      if (_daysSince(lastSeen) > threshold) {
        await OrganizationalMemory.updatePatternStatus(p.id, "decayed");
        decayed.push(p.id);
      }
    }
    return { decayed: decayed.length, patternsAffected: decayed };
  }

  // ──────────────────────────────────────────────────────────────────────────
  // API pública · getActivePatterns
  // ──────────────────────────────────────────────────────────────────────────

  async function getActivePatterns() {
    if (!W_ENABLED) return [];
    const patterns = await OrganizationalMemory.listPatterns();
    return patterns.filter(p => p.status === "active");
  }

  // ──────────────────────────────────────────────────────────────────────────
  // API pública · getPatternStats (diagnóstico)
  // ──────────────────────────────────────────────────────────────────────────

  async function getPatternStats() {
    if (!W_ENABLED) {
      return {
        w_enabled: false,
        local_counters: 0,
        persisted: { active: 0, decayed: 0, archived: 0, total: 0 },
      };
    }
    const patterns = await OrganizationalMemory.listPatterns();
    const counts = { active: 0, decayed: 0, archived: 0, total: patterns.length };
    for (const p of patterns) {
      if (counts[p.status] !== undefined) counts[p.status] += 1;
    }
    return {
      w_enabled: true,
      window_days: W3_DEFAULT_WINDOW_DAYS,
      promotion_threshold: W3_PROMOTION_THRESHOLD,
      decay_threshold_days: W3_DECAY_THRESHOLD_DAYS,
      local_counters: Object.keys(_counters).length,
      persisted: counts,
    };
  }

  // ──────────────────────────────────────────────────────────────────────────
  // API pública · resetLocalCounters (testing / clearAll integration)
  // ──────────────────────────────────────────────────────────────────────────

  function resetLocalCounters() {
    for (const k of Object.keys(_counters)) {
      delete _counters[k];
    }
    return true;
  }

  return {
    trackConsultation,
    decayInactivePatterns,
    getActivePatterns,
    getPatternStats,
    resetLocalCounters,
  };
})();

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF W · W.3 · PATTERN DETECTION 🧠
// (próxima pieza: W.4 · Recall API · consumer-facing queries)
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF W · ORGANIZATIONAL MEMORY · W.4 · RECALL API 🧠
// ════════════════════════════════════════════════════════════════════════════
//
// PURE READ-ONLY API · ground truth queries para BRIEFs futuros (T/V/ECL)
//
// Consumers previstos:
//   · T (Proactive Initiative): recallByEntity cuando detecta cambio
//   · V (Founder Personalization): recallByCategory para inferir preferencias
//   · ECL (Executive Conversation): recallSince para narrativa continuidad
//
// Consumer de OrganizationalMemory (W.1) · lecturas via list* methods
// Cero modificación a storage · cero invalidación · cero cache propio
//   (W.1 _cache interno ya optimiza relecturas)
//
// Decisiones firmadas:
//   D-W4-ALCANCE = B          · 6 queries básicas
//   D-W4-SHAPE-RETURN = B     · objeto estructurado por categoría
//   D-W4-CACHE = A            · cero cache propio
// ════════════════════════════════════════════════════════════════════════════

const OrgMemoryRecall = (function _initOrgMemoryRecall() {

  // ──────────────────────────────────────────────────────────────────────
  // Helpers privados · timestamps
  // ──────────────────────────────────────────────────────────────────────

  function _toTimestamp(value) {
    if (value === null || value === undefined) return null;
    if (value instanceof Date) return value.getTime();
    if (typeof value === "number") return value;
    if (typeof value === "string") {
      const t = new Date(value).getTime();
      return isNaN(t) ? null : t;
    }
    return null;
  }

  function _isInDateRange(itemDate, fromTs, toTs) {
    const t = _toTimestamp(itemDate);
    if (t === null) return false;
    if (fromTs !== null && t < fromTs) return false;
    if (toTs !== null && t > toTs) return false;
    return true;
  }

  function _emptyResult() {
    return { decisions: [], patterns: [], focuses: [], milestones: [] };
  }

  // ──────────────────────────────────────────────────────────────────────
  // Helper · lee las 4 categorías en paralelo (lecturas cacheadas en W.1)
  // ──────────────────────────────────────────────────────────────────────

  async function _readAllCategories() {
    if (!W_ENABLED) return _emptyResult();
    const [decisions, patterns, focuses, milestones] = await Promise.all([
      OrganizationalMemory.listDecisions(),
      OrganizationalMemory.listPatterns(),
      OrganizationalMemory.listFocuses(),
      OrganizationalMemory.listMilestones(),
    ]);
    return { decisions, patterns, focuses, milestones };
  }

  // ──────────────────────────────────────────────────────────────────────
  // Query 1 · recallByEntity
  // ──────────────────────────────────────────────────────────────────────
  //
  // Retorna todas las memorias asociadas a una entidad específica.
  // Cross-categoría: decisions + focuses + patterns + milestones.
  //
  // Argumentos:
  //   entityRefId: string · canonical ID de EntityRegistry (S.A)
  //
  // Returns: { decisions[], patterns[], focuses[], milestones[] }

  async function recallByEntity(entityRefId) {
    if (!entityRefId || typeof entityRefId !== "string") return _emptyResult();
    if (!W_ENABLED) return _emptyResult();
    const all = await _readAllCategories();
    return {
      decisions: all.decisions.filter(d => 
        d.entity && d.entity.entityRefId === entityRefId
      ),
      patterns: all.patterns.filter(p => 
        p.target && p.target.entity && p.target.entity.entityRefId === entityRefId
      ),
      focuses: all.focuses.filter(f => 
        f.target && f.target.entity && f.target.entity.entityRefId === entityRefId
      ),
      milestones: all.milestones.filter(m => 
        Array.isArray(m.affectedEntities) && m.affectedEntities.includes(entityRefId)
      ),
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // Query 2 · recallByCategory
  // ──────────────────────────────────────────────────────────────────────
  //
  // Retorna SOLO la categoría solicitada · otras 3 vacías.
  // Útil para consumers que solo necesitan una categoría (V/T patterns/focuses).
  //
  // Argumentos:
  //   category: "decisions"|"patterns"|"focuses"|"milestones"
  //
  // Returns: { decisions[], patterns[], focuses[], milestones[] }
  //          (3 vacías · 1 poblada)

  async function recallByCategory(category) {
    const valid = ["decisions", "patterns", "focuses", "milestones"];
    if (!valid.includes(category)) return _emptyResult();
    if (!W_ENABLED) return _emptyResult();
    const result = _emptyResult();
    if (category === "decisions") {
      result.decisions = await OrganizationalMemory.listDecisions();
    } else if (category === "patterns") {
      result.patterns = await OrganizationalMemory.listPatterns();
    } else if (category === "focuses") {
      result.focuses = await OrganizationalMemory.listFocuses();
    } else if (category === "milestones") {
      result.milestones = await OrganizationalMemory.listMilestones();
    }
    return result;
  }

  // ──────────────────────────────────────────────────────────────────────
  // Query 3 · recallByDateRange
  // ──────────────────────────────────────────────────────────────────────
  //
  // Retorna memorias declaradas/registradas en ventana temporal.
  // Decisions/focuses/milestones usan declaredAt.
  // Patterns usan frequency.lastSeenAt.
  //
  // Argumentos:
  //   from: ISO timestamp | Date | null (sin límite inferior)
  //   to:   ISO timestamp | Date | null (sin límite superior)

  async function recallByDateRange(from, to) {
    if (!W_ENABLED) return _emptyResult();
    const fromTs = _toTimestamp(from);
    const toTs = _toTimestamp(to);
    const all = await _readAllCategories();
    return {
      decisions: all.decisions.filter(d => _isInDateRange(d.declaredAt, fromTs, toTs)),
      patterns: all.patterns.filter(p => 
        p.frequency && _isInDateRange(p.frequency.lastSeenAt, fromTs, toTs)
      ),
      focuses: all.focuses.filter(f => _isInDateRange(f.declaredAt, fromTs, toTs)),
      milestones: all.milestones.filter(m => _isInDateRange(m.declaredAt, fromTs, toTs)),
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // Query 4 · recallByStatus
  // ──────────────────────────────────────────────────────────────────────
  //
  // Filtra por status: "active" | "completed" | "archived" | "obsoleta" 
  //                  | "decayed" | "fulfilled"
  //
  // Patrones de status válidos por categoría:
  //   decisions: active · completed · archived · obsoleta
  //   patterns:  active · decayed · archived
  //   focuses:   active · fulfilled · archived · obsoleta
  //   milestones: (no tienen status · siempre incluidos · cero filtrado)

  async function recallByStatus(status) {
    if (!W_ENABLED) return _emptyResult();
    if (typeof status !== "string" || status.length === 0) return _emptyResult();
    const all = await _readAllCategories();
    return {
      decisions: all.decisions.filter(d => d.status === status),
      patterns: all.patterns.filter(p => p.status === status),
      focuses: all.focuses.filter(f => f.status === status),
      milestones: [],  // milestones no tienen status
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // Query 5 · recallActiveItems
  // ──────────────────────────────────────────────────────────────────────
  //
  // Conveniencia: todo lo "vivo" del sistema.
  // decisions/focuses/patterns con status="active" + todos los milestones.

  async function recallActiveItems() {
    if (!W_ENABLED) return _emptyResult();
    const all = await _readAllCategories();
    return {
      decisions: all.decisions.filter(d => d.status === "active"),
      patterns: all.patterns.filter(p => p.status === "active"),
      focuses: all.focuses.filter(f => f.status === "active"),
      milestones: all.milestones,  // milestones siempre incluidos
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // Query 6 · recallSince
  // ──────────────────────────────────────────────────────────────────────
  //
  // Memorias declaradas/observadas en los últimos N días.
  // Helper sobre recallByDateRange con from=now-Ndays · to=null.

  async function recallSince(daysAgo) {
    if (!W_ENABLED) return _emptyResult();
    if (typeof daysAgo !== "number" || daysAgo <= 0) return _emptyResult();
    const from = new Date(Date.now() - daysAgo * 24 * 60 * 60 * 1000);
    return await recallByDateRange(from, null);
  }

  return {
    recallByEntity,
    recallByCategory,
    recallByDateRange,
    recallByStatus,
    recallActiveItems,
    recallSince,
  };
})();

