// FIN BRIEF W · W.4 · RECALL API 🧠
// (próxima pieza: W.5 · UI Memoria · panel transparencia + borrar)
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF T · PROACTIVE INITIATIVE · T.1 · DELTA DETECTION + UMBRALES 🎯
// ════════════════════════════════════════════════════════════════════════════
//
// PURE DETECTOR · cero cableado runtime hasta T.6
// Sin consumers · sin generación de mensajes en T.1 · solo detection layer
//
// Misión: detectar deltas materiales entre scenarios y cruces de zona
//         operativa · base determinística para proactivos posteriores
//
// Referencia diseño: BRIEF_T_DESIGN_v1_1.md (firmado)
// Decisiones firmadas autónomas: snapshot via scenarios · 6 métricas core
// ════════════════════════════════════════════════════════════════════════════

const T_ENABLED = true;

// ── Umbrales REGULARES (con memoria W) · firmados doc v1.1 ──────────────────
// Claves conceptuales unificadas (sin sufijo unit · T.1-bis fix)
// Unidades implícitas: margen/carga/concentracion en pp · doh en días ·
//                      contribucion en % · rotacion en x
const T_DELTA_THRESHOLDS_REGULAR = {
  margen: 0.5,
  carga: 0.3,
  doh: 15,
  contribucion: 5,
  concentracion: 2,
  rotacion: 2,
};

// ── Umbrales EXCEPCIONALES (override sin memoria) · firmados doc v1.1 ───────
const T_DELTA_THRESHOLDS_EXCEPTIONAL = {
  margen: 2.0,              // 4x regular
  carga: 1.0,               // 3.3x regular
  doh: 45,                  // 3x regular
  contribucion: 15,         // 3x regular
  concentracion: 5,         // 2.5x regular
  rotacion: 6,              // 3x regular
};

// ── Materialidad absoluta · requisito adicional para excepcional ────────────
const T_EXCEPTIONAL_ABSOLUTE_USD = 500000;

// ── Zonas operativas por métrica · firmadas doc v1.1 ────────────────────────
// Determinan cruces semánticamente materiales (no fluctuaciones internas).
const T_OPERATIONAL_ZONES = {
  margen: {
    healthy:   { min: 22, max: Infinity },
    pressured: { min: 18, max: 22 },
    critical:  { min: -Infinity, max: 18 },
  },
  carga: {
    healthy:   { min: -Infinity, max: 3.5 },
    pressured: { min: 3.5, max: 5 },
    critical:  { min: 5, max: Infinity },
  },
  doh: {
    healthy:   { min: -Infinity, max: 60 },
    pressured: { min: 60, max: 120 },
    critical:  { min: 120, max: Infinity },
  },
  concentracion: {
    healthy:   { min: -Infinity, max: 35 },
    pressured: { min: 35, max: 50 },
    critical:  { min: 50, max: Infinity },
  },
};

const T_ZONE_ORDER = ["healthy", "pressured", "critical"];

const OrgProactiveDetector = (function _initOrgProactiveDetector() {

  // ──────────────────────────────────────────────────────────────────────
  // Helper · resolver zona de una métrica para un valor dado
  // ──────────────────────────────────────────────────────────────────────

  function _resolveZone(metric, value) {
    const zones = T_OPERATIONAL_ZONES[metric];
    if (!zones || typeof value !== "number" || isNaN(value)) return null;
    for (const zoneName of T_ZONE_ORDER) {
      const range = zones[zoneName];
      if (!range) continue;
      if (value >= range.min && value < range.max) return zoneName;
      if (value === range.max && zoneName === "critical") return zoneName;
    }
    return null;
  }

  // ──────────────────────────────────────────────────────────────────────
  // Helper · distancia entre zonas (cruce semántico material)
  // ──────────────────────────────────────────────────────────────────────

  function _zoneDistance(zoneA, zoneB) {
    if (!zoneA || !zoneB) return 0;
    const idxA = T_ZONE_ORDER.indexOf(zoneA);
    const idxB = T_ZONE_ORDER.indexOf(zoneB);
    if (idxA === -1 || idxB === -1) return 0;
    return Math.abs(idxA - idxB);
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · detectMaterialDelta
  // ──────────────────────────────────────────────────────────────────────
  //
  // Detecta si el delta entre prevValue y currValue de una métrica cruza 
  // el umbral material (regular o excepcional).
  //
  // metricKey: clave de T_DELTA_THRESHOLDS_* (margen · carga · etc)
  // prevValue, currValue: valores numéricos
  //
  // Returns: {
  //   detected: boolean,
  //   delta: number (currValue - prevValue),
  //   absDelta: number,
  //   threshold: "regular" | "exceptional" | "below",
  //   regularThreshold: number,
  //   exceptionalThreshold: number,
  // }

  function detectMaterialDelta(metricKey, prevValue, currValue) {
    if (!T_ENABLED) return { detected: false, threshold: "disabled" };
    if (typeof prevValue !== "number" || typeof currValue !== "number") {
      return { detected: false, threshold: "invalid_input" };
    }
    if (isNaN(prevValue) || isNaN(currValue)) {
      return { detected: false, threshold: "invalid_input" };
    }
    const regular = T_DELTA_THRESHOLDS_REGULAR[metricKey];
    const exceptional = T_DELTA_THRESHOLDS_EXCEPTIONAL[metricKey];
    if (typeof regular !== "number" || typeof exceptional !== "number") {
      return { detected: false, threshold: "unknown_metric" };
    }
    const delta = currValue - prevValue;
    const absDelta = Math.abs(delta);
    let threshold = "below";
    if (absDelta >= exceptional) threshold = "exceptional";
    else if (absDelta >= regular) threshold = "regular";
    return {
      detected: threshold !== "below",
      delta,
      absDelta,
      threshold,
      regularThreshold: regular,
      exceptionalThreshold: exceptional,
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · detectZoneCrossing
  // ──────────────────────────────────────────────────────────────────────
  //
  // Detecta si el valor cruzó zona operativa (healthy/pressured/critical).
  // Solo cruces semánticamente materiales (fluctuaciones internas a la
  // misma zona NO se reportan).
  //
  // metricKey: clave de T_OPERATIONAL_ZONES
  // prevValue, currValue: valores numéricos
  //
  // Returns: {
  //   crossed: boolean,
  //   prevZone: string | null,
  //   currZone: string | null,
  //   distance: number (1 = adjacent · 2 = saltea intermedia),
  //   direction: "deterioro" | "recuperacion" | "lateral" | "none",
  // }

  function detectZoneCrossing(metricKey, prevValue, currValue) {
    if (!T_ENABLED) return { crossed: false };
    const prevZone = _resolveZone(metricKey, prevValue);
    const currZone = _resolveZone(metricKey, currValue);
    if (!prevZone || !currZone) {
      return { crossed: false, prevZone, currZone, distance: 0, direction: "none" };
    }
    if (prevZone === currZone) {
      return { crossed: false, prevZone, currZone, distance: 0, direction: "lateral" };
    }
    const distance = _zoneDistance(prevZone, currZone);
    const prevIdx = T_ZONE_ORDER.indexOf(prevZone);
    const currIdx = T_ZONE_ORDER.indexOf(currZone);
    // healthy(0) → pressured(1) → critical(2)
    const direction = currIdx > prevIdx ? "deterioro" : "recuperacion";
    return { crossed: true, prevZone, currZone, distance, direction };
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · evaluateMaterialEvent
  // ──────────────────────────────────────────────────────────────────────
  //
  // Combina detectMaterialDelta + detectZoneCrossing en una evaluación 
  // unificada para una entidad y métrica.
  //
  // params: {
  //   metricKey, prevValue, currValue,
  //   contribucionAfectada (USD): para validar materialidad absoluta excepcional,
  //   entityType: "client" | "sku" | "marca" (informativo)
  // }
  //
  // Returns: {
  //   material: boolean (cumple umbral regular),
  //   exceptional: boolean (cumple umbral excepcional + materialidad absoluta o cruce 2+ zonas),
  //   delta_info, zone_info,
  //   reason: "below_threshold" | "regular_material" | "exceptional_severe"
  // }

  function evaluateMaterialEvent(params) {
    if (!T_ENABLED) return { material: false, exceptional: false, reason: "disabled" };
    const { metricKey, prevValue, currValue, contribucionAfectada } = params || {};
    const delta = detectMaterialDelta(metricKey, prevValue, currValue);
    const zone = detectZoneCrossing(metricKey, prevValue, currValue);
    if (!delta.detected) {
      return { material: false, exceptional: false, delta_info: delta, zone_info: zone, reason: "below_threshold" };
    }
    // Evaluación excepcional: delta excepcional + (materialidad absoluta O cruce 2 zonas)
    const meetsExceptionalDelta = delta.threshold === "exceptional";
    const meetsAbsoluteMateriality = (
      typeof contribucionAfectada === "number" &&
      Math.abs(contribucionAfectada) >= T_EXCEPTIONAL_ABSOLUTE_USD
    );
    const meetsZoneJump = zone.crossed && zone.distance >= 2;
    const exceptional = meetsExceptionalDelta && (meetsAbsoluteMateriality || meetsZoneJump);
    return {
      material: true,
      exceptional,
      delta_info: delta,
      zone_info: zone,
      reason: exceptional ? "exceptional_severe" : "regular_material",
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · getThresholds (introspección)
  // ──────────────────────────────────────────────────────────────────────

  function getThresholds() {
    return {
      regular: { ...T_DELTA_THRESHOLDS_REGULAR },
      exceptional: { ...T_DELTA_THRESHOLDS_EXCEPTIONAL },
      absolute_usd: T_EXCEPTIONAL_ABSOLUTE_USD,
      zones: T_OPERATIONAL_ZONES,
    };
  }

  return {
    detectMaterialDelta,
    detectZoneCrossing,
    evaluateMaterialEvent,
    getThresholds,
  };
})();

