// ════════════════════════════════════════════════════════════════════════════
// BRIEF ECL-CONT · RESOLVER DE CONTINUACIÓN · CONT.0 · flag + detector (inerte)
// ────────────────────────────────────────────────────────────────────────────
// Continuidad conversacional: si el motor NO reconoció nada nuevo (sin entidad/
// módulo/métrica nueva) PERO hay foco activo vigente → continuar la investigación
// en vez de caer al fallback. PRINCIPIO RECTOR: nuevo intent → nuevo foco · nada
// nuevo + foco activo → continuidad · la continuidad NO secuestra la conversación.
// CONT.0 es INERTE: detector puro · 0 consumers. El resolver lo consume en CONT.1.
// ════════════════════════════════════════════════════════════════════════════
const ECL_CONT_ENABLED = true;
const ARCO_ENABLED = true;  // Arco Ejecutivo · arco siempre presente · rollback a false = render gateado legacy
const ARCO_EJECUTIVO_COMPLETE = true;  // Arco Ejecutivo SKU · cierre formal · paridad VOICE_BRIEF_*_COMPLETE
const ECL_CONT_COMPLETE = false;  // CONT.2 (descenso jerárquico) lo sube a true

// ECL-CONT.2 Fase 1 · detector de query de descenso (corre DENTRO de la continuidad).
// NO es un intent · solo distingue "bajar de nivel" de "deepen del mismo nivel".
// CERO dependencia de investigationDomain/metric (evita la enfermedad de CONT.1).
function eclContIsDescentQuery(text) {
  if (!text) return false;
  const t = text.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  const DESCENT_PHRASES = [
    "detras", "se concentra", "concentra",
    "categoria", "categorias", "familia",
    "producto", "productos", "sku", "skus",
    "marca", "marcas",
    "desglos", "composicion", "compone",
    "donde esta", "donde se", "que hay detras", "que explica",
  ];
  return DESCENT_PHRASES.some(p => t.includes(p));
}

// ── detectEllipticalSkuDrill ─────────────────────────────────────────────
// FIX #D-DRILL-ELIPTICO-SKU · resuelve la elipsis "¿qué SKU?"/"¿qué productos?" como drill sobre el
// cliente/familia navegado. SOLO dispara si: (1) el flag está ON, (2) el texto ES una forma elíptica
// CORTA de pedir SKUs (match estricto · no substring de una frase larga), (3) hay contexto de
// navegación FRESCO (lastClientMentioned del turno actual). Devuelve un intent que el dispatch rutea a
// composeClientToSku (el MISMO destino que "dame los SKU de esa familia"). Sin contexto fresco → null
// (cae al comportamiento de hoy · el drill elíptico CONTINÚA una navegación, no la empieza · firma D).
// LÉXICO/RUTEO PURO: cero cálculo nuevo · reusa composeClientToSku.
function detectEllipticalSkuDrill(text, context) {
  if (typeof ADI_DRILL_ELIPTICO_SKU_ENABLED === "undefined" || !ADI_DRILL_ELIPTICO_SKU_ENABLED) return null;
  if (!text || !context) return null;

  const norm = text
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[¿?¡!.,;:]/g, "")
    .trim();

  // Forma elíptica CORTA de pedir SKUs · match EXACTO del texto completo (no substring · evita capturar
  // frases largas que ya rutean a otro lado · ej. "qué skus le pesan a Falabella" tiene su propio detector).
  const ELLIPTICAL_SKU_PHRASES = [
    "que sku", "que skus", "cuales sku", "cuales skus",
    "que producto", "que productos", "cuales productos",
    "y los sku", "y los skus", "y que skus", "y que sku",
    "y los productos", "y que productos",
  ];
  if (!ELLIPTICAL_SKU_PHRASES.includes(norm)) return null;

  // Contexto de navegación FRESCO: un cliente mencionado en el turno actual (recién navegado).
  // Sin esto → null (en frío no inventa drill · firma cláusula · test D).
  const cc = context;
  const _freshClient = !!cc.lastClientMentioned
    && cc.lastClientMentionedTurn === cc.turnCount;
  if (!_freshClient) return null;

  return {
    type: "client_to_sku_drill",
    clientName: cc.lastClientMentioned,
  };
}

// Detector estructural puro · "nada nuevo + foco activo vigente".
// NO decide ángulo · solo si aplica continuidad. Determinístico · fail-safe.
function eclContIsPureContinuation(signals) {
  if (typeof ECL_CONT_ENABLED === "undefined" || !ECL_CONT_ENABLED) return false;
  const s = signals || {};
  // 1. Intent nuevo SIEMPRE gana · si se derivó algo nuevo, NO es continuación.
  if (s.derivedClient || s.derivedSku || s.derivedModule || s.derivedMetric) return false;
  // NOTA #L-CONT-NOMATCH-ES-LA-COMPUERTA: NO chequear derivedIntentType. El detector solo
  // se invoca en la compuerta del fallback (no-match estructural) · ahí derivedIntentType puede
  // ser un disfraz ("module"/"global_honest_fallback"). "Intent nuevo gana" lo garantiza la
  // ESTRUCTURA del pipeline (los intents reales despachan antes de la compuerta).
  // 2. Foco activo vigente (hypothesis · o lastClient + domain).
  const cc = s.conversationContext || {};
  // CONT.1-FIX · hasFocus acepta cualquier señal de foco · el anti-stale (lastClient
  // viejo tras rankings) se resuelve en el MODE routing, no acá (ver _clientCentric).
  const hasFocus = !!cc.investigationHypothesis
    || !!cc.investigationDomain
    || !!cc.lastClientMentioned
    // FIX #D-ACTIVERESULT-SE-PIERDE · un análisis activo con entidades ES foco (check estricto ·
    // objeto vacío NO cuenta · el fallback legítimo sigue cayendo). Aditivo · solo se evalúa si
    // los términos anteriores no dieron foco (OR) y si NO hubo derived* nuevo (parte 1 del gate).
    || (typeof ADI_ACTIVE_RESULT_CONTINUITY_ENABLED !== "undefined" && ADI_ACTIVE_RESULT_CONTINUITY_ENABLED
         && !!(cc.activeResult && Array.isArray(cc.activeResult.entities) && cc.activeResult.entities.length > 0));
  return hasFocus;
}

