// Registro central · namespaced por dominio (Principio 8). Cada traducción es una
// función pura (ctx ya calculado) → string ejecutivo. Direccional por signo.
// Comercial + Inventario poblados · resto reservado (módulo nuevo = namespace nuevo).
const EXEC_TRANSLATIONS = {
  comercial: {
    benchmark: (c) =>
      `se encuentra ${Math.abs(c.gap)} puntos ${c.gap < 0 ? "por debajo" : "por encima"} del promedio de la cartera`,
    contribucion: (c) =>
      `aporta ${c.pct} del negocio analizado · su peso es ${c.pct >= c.pctVentas ? "mayor" : "menor"} que su participación en ventas (${c.pctVentas})`,
    concentracion: (c) =>
      `una parte importante del negocio depende de ${c.entity} · ${c.pct} del total se concentra en una sola cuenta`,
    carga_comercial: (c) =>
      `${c.pct} de las ventas está asociado a acuerdos comerciales · ${c.pct >= c.pctPromedio ? "por encima" : "por debajo"} del promedio de la cartera (${c.pctPromedio})`,
  },
  inventario: {
    cobertura: (c) =>
      `hay inventario para aproximadamente ${c.meses} meses de venta al ritmo actual · ${c.meses >= c.mesesNormal ? "por encima" : "por debajo"} de lo que normalmente requiere la operación`,
    rotacion: (c) =>
      `rota ${c.n}x al año · ${c.n < c.nCartera ? "por debajo" : "por encima"} del ritmo del resto de la cartera`,
    capital_inmovilizado: (c) =>
      `hay aproximadamente ${c.monto} comprometido en inventario que aún no se transforma en venta · ${Math.abs(c.pct)} ${c.pct >= 0 ? "por encima" : "por debajo"} de lo considerado normal`,
  },
  financiero:  {},  // reservado · futuro módulo
  personas:    {},  // reservado
  compras:     {},  // reservado
  operaciones: {},  // reservado
};
// ════════════════════════════════════════════════════════════════════════════
// EXEC_GLOSSARY · sustitución léxica 1:1 de vocabulario técnico (VOZ2.3-glossary)
// ────────────────────────────────────────────────────────────────────────────
// Mecanismo SEPARADO de EXEC_TRANSLATIONS (regla de oro D-VOZ2-GLOSSARY-SPLIT):
//   · GLOSSARY = término → reemplazo · SOLO narrativa · NUNCA conceptos · NUNCA tablas densas.
//   · NO recibe ctx ni cifras · estructuralmente incapaz de interpretar.
//   · La traducción conceptual (significado + cifras) pertenece a EXEC_TRANSLATIONS.
// INERTE en VOZ2.3-glossary-scaffold: 0 consumers. Lo consume la micro-calibración de jerga.
// ════════════════════════════════════════════════════════════════════════════
const EXEC_GLOSSARY = {
  "best practice": "mejor práctica",
  "pp": "puntos porcentuales",        // solo prosa · tablas intactas
  "lead time": "tiempo de reposición",
  "fill rate": "nivel de cumplimiento de pedidos",
  "stock-out": "quiebre de stock",
  "DOH": "días de cobertura",          // léxico · vive en tablas SKU → efecto real mínimo por scope
};

// ════════════════════════════════════════════════════════════════════════════
// applyGlossary · aplica EXEC_GLOSSARY · SOLO superficie narrativa (D-VOZ2-GLOSSARY-SURFACE)
// ────────────────────────────────────────────────────────────────────────────
// FAIL-SAFE: sustituye únicamente si surface === "narrative".
// Cualquier otra surface (table/cell/chip/card/export/metric_label/drilldown) o
// surface ausente → passthrough total (devuelve text intacto · ante la duda NO sustituye).
// word-boundary \b · case-insensitive con preservación de mayúscula inicial.
// Multi-palabra primero (best practice, tier 1, lead time, fill rate, stock-out)
// para que un término compuesto no sea pisado por uno simple.
// Gateado por VOZ2_ENABLED · INERTE hasta que un composer lo invoque.
// ════════════════════════════════════════════════════════════════════════════
function applyGlossary(text, options = {}) {
  if (typeof VOZ2_ENABLED === "undefined" || !VOZ2_ENABLED) return text;
  if (!text || typeof text !== "string") return text;
  if (!options || options.surface !== "narrative") return text;  // fail-safe

  const terms = Object.keys(EXEC_GLOSSARY).sort((a, b) => b.length - a.length); // multi-palabra primero
  let out = text;
  for (const term of terms) {
    const repl = EXEC_GLOSSARY[term];
    const esc = term.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const re = new RegExp("\\b" + esc + "\\b", "gi");
    out = out.replace(re, (match) => {
      // preservar mayúscula inicial del match original
      if (match[0] === match[0].toUpperCase() && match[0] !== match[0].toLowerCase()) {
        return repl.charAt(0).toUpperCase() + repl.slice(1);
      }
      return repl;
    });
  }
  return out;
}

