// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF T · T.1 · DELTA DETECTION + UMBRALES 🎯
// (próxima pieza: T.2 · Memory Recall Bridge)
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF T · PROACTIVE INITIATIVE · T.2 · MEMORY RECALL BRIDGE 🌉
// ════════════════════════════════════════════════════════════════════════════
//
// PURE READ-ONLY · primer puente W ↔ T
// Cero cableado runtime hasta T.6
//
// Consumer de:
//   · OrgMemoryRecall.recallByEntity (W.4) · busca memoria sobre entidad afectada
//   · OrgMemoryRecall.recallActiveItems (W.4) · busca milestones sistémicos recientes
//   · OrgProactiveDetector.evaluateMaterialEvent (T.1) · ya invocado por caller
//
// Misión: dado un evento material detectado por T.1 sobre una entidad ·
//         retornar el anchor de memoria que justifica el proactivo · 
//         o null si no hay anchor (caller decide si excepción material aplica).
//
// Decisiones firmadas autónomas:
//   D-T2-ANCHOR-PRIORITY = decision > focus > pattern > milestone
//   D-T2-EXCEPTIONAL-OVERRIDE-FORMAL = ON (anchor sintético si excepcional sin memoria)
//   D-T2-RECENT-WINDOW = 30 días para milestones sistémicos
// ════════════════════════════════════════════════════════════════════════════

const T2_MILESTONE_SYSTEMIC_WINDOW_DAYS = 30;

const OrgProactiveAnchor = (function _initOrgProactiveAnchor() {

  // ──────────────────────────────────────────────────────────────────────
  // Helper · días desde timestamp ISO
  // ──────────────────────────────────────────────────────────────────────

  function _daysSince(isoTimestamp) {
    if (!isoTimestamp) return Infinity;
    const then = new Date(isoTimestamp).getTime();
    if (isNaN(then)) return Infinity;
    return (Date.now() - then) / (1000 * 60 * 60 * 24);
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · findAnchorForEvent
  // ──────────────────────────────────────────────────────────────────────
  //
  // Dado un evento material sobre una entidad · busca el mejor anchor de 
  // memoria en W para justificar un proactivo.
  //
  // Argumentos:
  //   params: {
  //     entityRefId: string · canonical ID de EntityRegistry,
  //     materialEventResult: resultado de OrgProactiveDetector.evaluateMaterialEvent
  //   }
  //
  // Returns: {
  //   hasAnchor: boolean,
  //   anchor: {
  //     type: "decision" | "focus" | "pattern" | "milestone_systemic" | "exceptional_no_memory",
  //     priority: number (1=highest, 5=lowest),
  //     record: object (el item completo de W) | null,
  //     reasoning: string (cómo se eligió)
  //   } | null,
  //   reason: "memory_anchor" | "exceptional_override" | "no_anchor"
  // }

  async function findAnchorForEvent(params) {
    if (!T_ENABLED) return { hasAnchor: false, anchor: null, reason: "t_disabled" };
    const { entityRefId, materialEventResult } = params || {};
    if (!entityRefId || typeof entityRefId !== "string") {
      return { hasAnchor: false, anchor: null, reason: "invalid_entity" };
    }
    if (!materialEventResult || !materialEventResult.material) {
      return { hasAnchor: false, anchor: null, reason: "event_not_material" };
    }

    // ── 1. Búsqueda principal: memoria específica sobre la entidad ──
    let recall = null;
    try {
      recall = await OrgMemoryRecall.recallByEntity(entityRefId);
    } catch (e) {
      recall = { decisions: [], patterns: [], focuses: [], milestones: [] };
    }

    // Prioridad 1 · DECISION activa (más fuerte · founder firmó explícito)
    const activeDecision = (recall.decisions || []).find(d => d.status === "active");
    if (activeDecision) {
      return {
        hasAnchor: true,
        anchor: {
          type: "decision",
          priority: 1,
          record: activeDecision,
          reasoning: "decision activa sobre entidad · anchor más fuerte",
        },
        reason: "memory_anchor",
      };
    }

    // Prioridad 2 · FOCUS activo
    const activeFocus = (recall.focuses || []).find(f => f.status === "active");
    if (activeFocus) {
      return {
        hasAnchor: true,
        anchor: {
          type: "focus",
          priority: 2,
          record: activeFocus,
          reasoning: "foco activo sobre entidad · anchor declarativo",
        },
        reason: "memory_anchor",
      };
    }

    // Prioridad 3 · PATTERN activo (observacional)
    const activePattern = (recall.patterns || []).find(p => p.status === "active");
    if (activePattern) {
      return {
        hasAnchor: true,
        anchor: {
          type: "pattern",
          priority: 3,
          record: activePattern,
          reasoning: "pattern observable activo · anchor por frecuencia consulta",
        },
        reason: "memory_anchor",
      };
    }

    // Prioridad 4 · MILESTONE específico sobre entidad
    const recentEntityMilestone = (recall.milestones || []).find(m => 
      _daysSince(m.declaredAt) <= T2_MILESTONE_SYSTEMIC_WINDOW_DAYS
    );
    if (recentEntityMilestone) {
      return {
        hasAnchor: true,
        anchor: {
          type: "milestone",
          priority: 4,
          record: recentEntityMilestone,
          reasoning: "milestone reciente sobre entidad · anchor contextual",
        },
        reason: "memory_anchor",
      };
    }

    // ── 2. Búsqueda alternativa: milestone sistémico reciente ──
    // (excepción 1 del doc design · scope global · sin entidad específica)
    let globalActives = null;
    try {
      globalActives = await OrgMemoryRecall.recallActiveItems();
    } catch (e) {
      globalActives = { milestones: [] };
    }
    const systemicMilestone = (globalActives.milestones || []).find(m =>
      m.scope === "global" &&
      _daysSince(m.declaredAt) <= T2_MILESTONE_SYSTEMIC_WINDOW_DAYS
    );
    if (systemicMilestone) {
      return {
        hasAnchor: true,
        anchor: {
          type: "milestone_systemic",
          priority: 5,
          record: systemicMilestone,
          reasoning: "milestone sistémico reciente scope global · excepción 1 transversal",
        },
        reason: "memory_anchor",
      };
    }

    // ── 3. Override excepcional: evento muy material sin memoria ──
    // (excepción 2 del doc design · founder firmó explícito v1.1)
    if (materialEventResult.exceptional) {
      return {
        hasAnchor: true,
        anchor: {
          type: "exceptional_no_memory",
          priority: 6,
          record: null,
          reasoning: "evento excepcionalmente material sin memoria previa · override v1.1",
        },
        reason: "exceptional_override",
      };
    }

    // ── 4. Sin anchor · proactivo NO procede ──
    return {
      hasAnchor: false,
      anchor: null,
      reason: "no_anchor",
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · findAnchorByPriority (helper · solo lookup directo)
  // ──────────────────────────────────────────────────────────────────────
  //
  // Versión más simple · solo busca anchor sin evaluar excepción.
  // Útil para consumers que ya saben que el evento es material.

  async function findAnchorByPriority(entityRefId) {
    if (!T_ENABLED || !entityRefId) return null;
    const stubMaterialEvent = { material: true, exceptional: false };
    const result = await findAnchorForEvent({
      entityRefId,
      materialEventResult: stubMaterialEvent,
    });
    return result.hasAnchor ? result.anchor : null;
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · getAnchorStats (introspección)
  // ──────────────────────────────────────────────────────────────────────

  function getAnchorStats() {
    return {
      systemic_window_days: T2_MILESTONE_SYSTEMIC_WINDOW_DAYS,
      priority_order: ["decision", "focus", "pattern", "milestone", "milestone_systemic", "exceptional_no_memory"],
      priority_values: { decision: 1, focus: 2, pattern: 3, milestone: 4, milestone_systemic: 5, exceptional_no_memory: 6 },
    };
  }

  return {
    findAnchorForEvent,
    findAnchorByPriority,
    getAnchorStats,
  };
})();

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF T · T.2 · MEMORY RECALL BRIDGE 🌉
// (próxima pieza: T.3 · Proactive Composer · voz canónica v1.2 + Principio 8)
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF T · PROACTIVE INITIATIVE · T.3 · PROACTIVE COMPOSER 🎙️
// ════════════════════════════════════════════════════════════════════════════
//
// PURE COMPOSER · cero cableado runtime hasta T.6
// Primer composer del BRIEF T · genera mensajes con voz canónica v1.2
//
// Consumer de:
//   · OrgProactiveDetector (T.1) · evaluateMaterialEvent ya invocado
//   · OrgProactiveAnchor (T.2) · findAnchorForEvent ya invocado
//   · EntityRegistry (S.A) · resolución de nombres canónicos
//
// 3 variantes obligatorias:
//   1. REGULAR · proactivo con anchor de memoria (priority 1-4)
//   2. EXCEPTIONAL · proactivo override sin memoria (priority 6)
//   3. TRANSVERSAL · proactivo sistémico (priority 5 · milestone global)
//
// Decisiones firmadas:
//   D-T3-PROACTIVE-FORMAT  = B  · párrafo compacto 3-5 oraciones
//   D-T3-EXCEPTIONAL-VOICE = C  · transparencia EMBEBIDA en flujo natural
//   D-T3-CLOSER            = C  · 2-3 suggestions clickeables
//
// Cumple Principio 8 v1.1 (VOZ_ADI_CANONICA): interpretación default · 
// NO recomendación imperativa por default.
// ════════════════════════════════════════════════════════════════════════════

// ── Plantillas vinculantes EXCEPCIONAL (lineas obligatorias doc T v1.1) ─────
const T3_EXCEPTIONAL_OBLIGATORY_PHRASES = [
  "no tenía registro previo",
  "se eleva por su materialidad",
];

// ── Mapeo categoría decisión → verbo conjugado natural ──────────────────────
const T3_DECISION_VERB_MAP = {
  renegociar: "renegociar",
  liquidar: "liquidar",
  escalar: "escalar",
  stop_loss: "cortar",
  monitorear: "monitorear",
  aprobar: "aprobar",
  otro: "actuar sobre",
};

// ── Mapeo zone crossing → frase descriptiva (Principio 4 · cuantitativo) ────
const T3_ZONE_CROSSING_PHRASES = {
  "healthy->pressured":  "pasando de healthy a pressured",
  "pressured->critical": "pasando de pressured a critical",
  "healthy->critical":   "pasando directamente de healthy a critical",
  "critical->pressured": "recuperándose de critical a pressured",
  "pressured->healthy":  "recuperándose de pressured a healthy",
  "critical->healthy":   "recuperación completa de critical a healthy",
};

// ── Mapeo metric → vocabulario natural (paridad composers v1.x) ─────────────
const T3_METRIC_VOCABULARY = {
  margen:        { noun: "margen",           unit: "pp", verb: "cayó",     verbUp: "subió"    },
  carga:         { noun: "carga comercial",  unit: "pp", verb: "subió",    verbUp: "subió"    },
  doh:           { noun: "DOH",              unit: "días", verb: "subió",  verbUp: "subió"    },
  contribucion:  { noun: "contribución",     unit: "%",  verb: "cayó",     verbUp: "subió"    },
  concentracion: { noun: "concentración",    unit: "pp", verb: "subió",    verbUp: "subió"    },
  rotacion:      { noun: "rotación",         unit: "x",  verb: "bajó",     verbUp: "subió"    },
};

const OrgProactiveComposer = (function _initOrgProactiveComposer() {

  // ──────────────────────────────────────────────────────────────────────
  // Helpers privados de formato (sin imperativos · cuantitativo · sobrio)
  // ──────────────────────────────────────────────────────────────────────

  function _resolveEntityName(entityRefId) {
    if (typeof EntityRegistry === "undefined" || !EntityRegistry.entities[entityRefId]) {
      return entityRefId || "entidad";
    }
    return EntityRegistry.entities[entityRefId].canonical_name;
  }

  function _formatDelta(metricKey, prev, curr) {
    const voc = T3_METRIC_VOCABULARY[metricKey];
    if (!voc) return `${prev} → ${curr}`;
    const absDelta = Math.abs(curr - prev).toFixed(1);
    const direction = curr < prev ? voc.verb : voc.verbUp;
    return `${voc.noun} ${direction} ${absDelta}${voc.unit}`;
  }

  function _formatPrevCurr(metricKey, prev, curr) {
    const voc = T3_METRIC_VOCABULARY[metricKey];
    if (!voc) return `de ${prev} a ${curr}`;
    return `de ${prev}${voc.unit === "x" ? "x" : voc.unit} a ${curr}${voc.unit === "x" ? "x" : voc.unit}`;
  }

  function _formatZoneCrossing(zoneInfo) {
    if (!zoneInfo || !zoneInfo.crossed) return "";
    const key = `${zoneInfo.prevZone}->${zoneInfo.currZone}`;
    return T3_ZONE_CROSSING_PHRASES[key] || `pasando de ${zoneInfo.prevZone} a ${zoneInfo.currZone}`;
  }

  function _daysSinceDeclaration(isoTimestamp) {
    if (!isoTimestamp) return null;
    const then = new Date(isoTimestamp).getTime();
    if (isNaN(then)) return null;
    return Math.floor((Date.now() - then) / (1000 * 60 * 60 * 24));
  }

  // T.3-bis · normaliza expresión temporal a frase natural
  function _formatDaysPhrase(days) {
    if (days === null || days === undefined) return "recientemente";
    if (days === 0) return "hoy";
    if (days === 1) return "ayer";
    return `hace ${days} días`;
  }

  // ──────────────────────────────────────────────────────────────────────
  // VARIANTE 1 · REGULAR (con anchor de memoria · priority 1-4)
  // ──────────────────────────────────────────────────────────────────────

  function _composeRegular(params) {
    const { entityName, metricKey, prevValue, currValue, zoneInfo, anchor } = params;
    const deltaText = _formatDelta(metricKey, prevValue, currValue);
    const prevCurrText = _formatPrevCurr(metricKey, prevValue, currValue);
    const zoneText = _formatZoneCrossing(zoneInfo);

    let memoryText = "";
    const days = anchor.record ? _daysSinceDeclaration(anchor.record.declaredAt || anchor.record.frequency?.lastSeenAt) : null;
    const daysPhrase = _formatDaysPhrase(days);

    if (anchor.type === "decision") {
      const cat = anchor.record.category;
      const verb = T3_DECISION_VERB_MAP[cat] || "actuar sobre";
      memoryText = `${daysPhrase} decidiste ${verb} ${entityName}`;
    } else if (anchor.type === "focus") {
      memoryText = `${daysPhrase} declaraste foco activo sobre ${entityName}`;
    } else if (anchor.type === "pattern") {
      const count = anchor.record.frequency?.count || "varias";
      memoryText = `${entityName} aparece ${count} veces en tus consultas recientes`;
    } else if (anchor.type === "milestone") {
      const desc = anchor.record.description || "evento registrado";
      memoryText = `${daysPhrase} se registró: ${desc.substring(0, 100)}`;
    }

    const mechanismText = `El cambio se concentra en la métrica ${T3_METRIC_VOCABULARY[metricKey]?.noun || metricKey}`;

    const sentence1 = `${entityName} tuvo una variación de ${deltaText} esta semana${zoneText ? `, ${zoneText}` : ""}.`;
    const sentence2 = `${memoryText.charAt(0).toUpperCase()}${memoryText.slice(1)}.`;
    const sentence3 = `${mechanismText} (${prevCurrText}).`;

    return `${sentence1} ${sentence2} ${sentence3}`;
  }

  // ──────────────────────────────────────────────────────────────────────
  // VARIANTE 2 · EXCEPTIONAL (override sin memoria · priority 6 · v1.1)
  // ──────────────────────────────────────────────────────────────────────
  // Plantilla embebida (D-T3-EXCEPTIONAL-VOICE = C firmado):
  // "[Entidad] tuvo [cambio]. Aunque no tenía registro previo sobre [Entidad] 
  //  en tu memoria, este evento se eleva por su materialidad: [justificación]. 
  //  [Mecanismo]."

  function _composeExceptional(params) {
    const { entityName, metricKey, prevValue, currValue, zoneInfo, materialEventResult } = params;
    const deltaText = _formatDelta(metricKey, prevValue, currValue);
    const prevCurrText = _formatPrevCurr(metricKey, prevValue, currValue);
    const zoneText = _formatZoneCrossing(zoneInfo);

    // Justificación cuantitativa del override
    let justification = "el cambio supera umbrales excepcionales de materialidad";
    const justificationParts = [];
    if (zoneInfo && zoneInfo.crossed && zoneInfo.distance >= 2) {
      justificationParts.push("cruza dos zonas operativas");
    }
    if (params.contribucionAfectada && Math.abs(params.contribucionAfectada) >= 500000) {
      const contribK = Math.abs(params.contribucionAfectada) / 1000;
      justificationParts.push(`la contribución afectada supera los $${Math.round(contribK)}K`);
    }
    if (justificationParts.length > 0) {
      justification = justificationParts.join(" y ");
    }

    const mechanismText = `La variación se concentra en la métrica ${T3_METRIC_VOCABULARY[metricKey]?.noun || metricKey} (${prevCurrText})`;

    const sentence1 = `${entityName} tuvo una variación de ${deltaText} esta semana${zoneText ? `, ${zoneText}` : ""}.`;
    // OBLIGATORIA línea v1.1 embebida (D-T3-EXCEPTIONAL-VOICE = C):
    const sentence2 = `Aunque no tenía registro previo sobre ${entityName} en tu memoria, este evento se eleva por su materialidad: ${justification}.`;
    const sentence3 = `${mechanismText}.`;

    return `${sentence1} ${sentence2} ${sentence3}`;
  }

  // ──────────────────────────────────────────────────────────────────────
  // VARIANTE 3 · TRANSVERSAL SISTÉMICO (priority 5 · milestone global)
  // ──────────────────────────────────────────────────────────────────────

  function _composeTransversal(params) {
    const { entityName, metricKey, prevValue, currValue, zoneInfo, anchor } = params;
    const deltaText = _formatDelta(metricKey, prevValue, currValue);
    const prevCurrText = _formatPrevCurr(metricKey, prevValue, currValue);
    const zoneText = _formatZoneCrossing(zoneInfo);

    const milestoneDesc = anchor.record?.description || "cambio sistémico reciente";
    const days = anchor.record ? _daysSinceDeclaration(anchor.record.declaredAt) : null;
    const daysPhrase = _formatDaysPhrase(days);
    const daysPhraseCap = `${daysPhrase.charAt(0).toUpperCase()}${daysPhrase.slice(1)}`;

    const mechanismText = `La variación de ${T3_METRIC_VOCABULARY[metricKey]?.noun || metricKey} (${prevCurrText}) puede vincularse con este cambio de contexto`;

    const sentence1 = `${entityName} tuvo una variación de ${deltaText} esta semana${zoneText ? `, ${zoneText}` : ""}.`;
    const sentence2 = `${daysPhraseCap} se registró un cambio sistémico: ${milestoneDesc.substring(0, 120)}.`;
    const sentence3 = `${mechanismText}.`;

    return `${sentence1} ${sentence2} ${sentence3}`;
  }

  // ──────────────────────────────────────────────────────────────────────
  // Generador de suggestions (D-T3-CLOSER = C · 2-3 botones clickeables)
  // ──────────────────────────────────────────────────────────────────────

  function _buildSuggestions(params) {
    const { entityName, metricKey, anchor } = params;
    const suggestions = [];
    // Sug 1 · ver detalle entidad afectada (siempre)
    suggestions.push(`Ver detalle ${entityName}`);
    // Sug 2 · vinculada a métrica afectada
    const noun = T3_METRIC_VOCABULARY[metricKey]?.noun || metricKey;
    suggestions.push(`Mecanismo del cambio en ${noun}`);
    // Sug 3 · vinculada al anchor (si aplica)
    if (anchor && anchor.type === "decision") {
      const cat = anchor.record?.category || "decisión";
      suggestions.push(`Estado de la ${cat} sobre ${entityName}`);
    } else if (anchor && anchor.type === "focus") {
      suggestions.push(`Foco declarado sobre ${entityName}`);
    } else if (anchor && anchor.type === "pattern") {
      suggestions.push(`Patrón de consultas sobre ${entityName}`);
    } else if (anchor && anchor.type === "milestone_systemic") {
      suggestions.push("Detalle del cambio sistémico");
    } else if (anchor && anchor.type === "exceptional_no_memory") {
      suggestions.push(`Comparar ${entityName} vs cartera`);
    }
    return suggestions.slice(0, 3);
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · composeProactive
  // ──────────────────────────────────────────────────────────────────────
  //
  // Argumentos:
  //   params: {
  //     entityRefId: string,
  //     metricKey: string,
  //     prevValue: number,
  //     currValue: number,
  //     materialEventResult: resultado T.1 evaluateMaterialEvent,
  //     anchorResult: resultado T.2 findAnchorForEvent,
  //     contribucionAfectada?: number (USD · solo para exceptional)
  //   }
  //
  // Returns: {
  //   composed: boolean,
  //   variant: "regular" | "exceptional" | "transversal" | null,
  //   text: string,
  //   suggestions: string[],
  //   anchorType: string | null,
  //   reason: "ok" | "no_anchor" | "invalid_input"
  // }

  function composeProactive(params) {
    if (!T_ENABLED) return { composed: false, variant: null, text: "", suggestions: [], anchorType: null, reason: "t_disabled" };
    if (!params || !params.entityRefId || !params.metricKey) {
      return { composed: false, variant: null, text: "", suggestions: [], anchorType: null, reason: "invalid_input" };
    }
    if (!params.anchorResult || !params.anchorResult.hasAnchor) {
      return { composed: false, variant: null, text: "", suggestions: [], anchorType: null, reason: "no_anchor" };
    }

    const entityName = _resolveEntityName(params.entityRefId);
    const anchor = params.anchorResult.anchor;
    const materialEventResult = params.materialEventResult || {};
    const zoneInfo = materialEventResult.zone_info || null;

    const composerParams = {
      entityName,
      metricKey: params.metricKey,
      prevValue: params.prevValue,
      currValue: params.currValue,
      zoneInfo,
      anchor,
      materialEventResult,
      contribucionAfectada: params.contribucionAfectada,
    };

    let variant = "regular";
    let text = "";

    if (anchor.type === "exceptional_no_memory") {
      variant = "exceptional";
      text = _composeExceptional(composerParams);
    } else if (anchor.type === "milestone_systemic") {
      variant = "transversal";
      text = _composeTransversal(composerParams);
    } else {
      variant = "regular";
      text = _composeRegular(composerParams);
    }

    const suggestions = _buildSuggestions(composerParams);

    return {
      composed: true,
      variant,
      text,
      suggestions,
      anchorType: anchor.type,
      reason: "ok",
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · getComposerStats (introspección)
  // ──────────────────────────────────────────────────────────────────────

  function getComposerStats() {
    return {
      variants_supported: ["regular", "exceptional", "transversal"],
      decision_verbs_count: Object.keys(T3_DECISION_VERB_MAP).length,
      metric_vocabulary_count: Object.keys(T3_METRIC_VOCABULARY).length,
      zone_crossings_count: Object.keys(T3_ZONE_CROSSING_PHRASES).length,
      exceptional_obligatory_phrases: T3_EXCEPTIONAL_OBLIGATORY_PHRASES,
    };
  }

  return {
    composeProactive,
    getComposerStats,
  };
})();

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF T · T.3 · PROACTIVE COMPOSER 🎙️
// (próxima pieza: T.4 · Dismiss Layer + W patch · 5ta categoría memoria)
