// ════════════════════════════════════════════════════════════════════════════
// BRIEF T · PROACTIVE INITIATIVE · T.4 · DISMISS LAYER 🚫
// ════════════════════════════════════════════════════════════════════════════
//
// PURE LAYER · cero cableado runtime hasta T.6
//
// Consumer de OrganizationalMemory.wasDismissed (T.4a patch)
// Filtra candidatos proactivos que el founder ya rechazó previamente.
//
// Decisiones firmadas autónomas:
//   D-T4-DISMISS-KEY = triple-key (proactiveType, entityRefId, triggerType)
//   D-T4-NAMESPACE-T = OrgProactiveDismiss
// ════════════════════════════════════════════════════════════════════════════

const OrgProactiveDismiss = (function _initOrgProactiveDismiss() {

  // ──────────────────────────────────────────────────────────────────────
  // API pública · isDismissed
  // ──────────────────────────────────────────────────────────────────────
  //
  // Wrapper más expresivo sobre OrganizationalMemory.wasDismissed.
  //
  // Argumentos:
  //   candidate: {
  //     proactiveType: "regular_material" | "exceptional_severe" | "systemic",
  //     entityRefId: string | null,
  //     triggerType: string (metric: "margen" | "carga" | ...)
  //   }
  //
  // Returns: boolean

  async function isDismissed(candidate) {
    if (!T_ENABLED || !candidate) return false;
    if (typeof OrganizationalMemory === "undefined") return false;
    if (typeof OrganizationalMemory.wasDismissed !== "function") return false;
    return await OrganizationalMemory.wasDismissed(
      candidate.proactiveType,
      candidate.entityRefId,
      candidate.triggerType
    );
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · filterDismissed
  // ──────────────────────────────────────────────────────────────────────
  //
  // Filtra una lista de candidatos · retorna solo los NO dismisseados.
  //
  // Argumentos:
  //   candidates: array de { proactiveType, entityRefId, triggerType, ... }
  //
  // Returns: array filtrado

  async function filterDismissed(candidates) {
    if (!T_ENABLED || !Array.isArray(candidates)) return [];
    const filtered = [];
    for (const c of candidates) {
      const skip = await isDismissed(c);
      if (!skip) filtered.push(c);
    }
    return filtered;
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · registerDismiss
  // ──────────────────────────────────────────────────────────────────────
  //
  // Helper para registrar un dismiss · wrapper sobre addDismiss con
  // validación defensiva.

  async function registerDismiss(candidate) {
    if (!T_ENABLED || !candidate) return null;
    if (typeof OrganizationalMemory === "undefined") return null;
    if (typeof OrganizationalMemory.addDismiss !== "function") return null;
    return await OrganizationalMemory.addDismiss({
      proactiveType: candidate.proactiveType,
      entityRefId: candidate.entityRefId,
      triggerType: candidate.triggerType,
      proactiveVariant: candidate.proactiveVariant || null,
    });
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · getDismissStats (introspección)
  // ──────────────────────────────────────────────────────────────────────

  async function getDismissStats() {
    if (!T_ENABLED || typeof OrganizationalMemory === "undefined") {
      return { total: 0, by_type: {} };
    }
    const list = await OrganizationalMemory.listDismisses();
    const byType = {};
    for (const d of list) {
      byType[d.proactiveType] = (byType[d.proactiveType] || 0) + 1;
    }
    return { total: list.length, by_type: byType };
  }

  return {
    isDismissed,
    filterDismissed,
    registerDismiss,
    getDismissStats,
  };
})();

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF T · T.4 · DISMISS LAYER 🚫
// (próxima pieza: T.5 · Quota + Selection Engine)
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF T · PROACTIVE INITIATIVE · T.5 · QUOTA + SELECTION ENGINE 🎯
// ════════════════════════════════════════════════════════════════════════════
//
// PURE SELECTOR + ORCHESTRATOR · cero cableado runtime hasta T.6
//
// Consumer de:
//   · OrgProactiveDetector (T.1) · evaluateMaterialEvent
//   · OrgProactiveAnchor (T.2) · findAnchorForEvent
//   · OrgProactiveComposer (T.3 post-T.3-bis) · composeProactive
//   · OrgProactiveDismiss (T.4) · filterDismissed
//
// Misión:
//   1. Aplicar cuotas de sesión (D-T5-QUOTA-LIMITS · doc v1.1)
//   2. Seleccionar el mejor candidato según prioridad (D-T5-SELECTION-PRIORITY)
//   3. Orquestar pipeline T.1→T.2→T.3→T.4 atómicamente
//
// Decisiones firmadas autónomas:
//   D-T5-CUOTAS = state in-memory · reset por sesión
//   D-T5-QUOTA-LIMITS = 1 por módulo (3: ventas/margenes/inventario) +
//                       1 transversal = 4 máximo
//   D-T5-PRIORITY = materialidad > anchor type > recencia > alfabético
// ════════════════════════════════════════════════════════════════════════════

const T5_VALID_MODULES = ["ventas", "margenes", "inventario"];
const T5_QUOTA_PER_MODULE = 1;
const T5_QUOTA_TRANSVERSAL = 1;

// V.4 · BRIEF V scoring boosts · consumed by _scoreCandidate when preferences exist
// Magnitudes balanced contra materiality (50-100) · NO domina señal cuantitativa
const V4_PRIORITY_BOOST = 10;  // ±10 por priority level (+1 o -1)
const V4_FOCUS_BOOST = 5;       // +5 si entity en focus active

// Prioridad de anchor type (menor número = mayor prioridad)
const T5_ANCHOR_PRIORITY = {
  "decision": 1,
  "focus": 2,
  "pattern": 3,
  "milestone": 4,
  "milestone_systemic": 5,
  "exceptional_no_memory": 6,
};

const OrgProactiveSelector = (function _initOrgProactiveSelector() {

  // ──────────────────────────────────────────────────────────────────────
  // State in-memory · session quotas
  // ──────────────────────────────────────────────────────────────────────

  let _sessionQuotas = {
    modulesUsed: new Set(),       // módulos con proactivo ya emitido
    transversalUsed: false,        // proactivo transversal ya emitido
    sessionStartedAt: Date.now(),
  };

  // ──────────────────────────────────────────────────────────────────────
  // Helper · timestamp de un candidato (para tie-breaking por recencia)
  // ──────────────────────────────────────────────────────────────────────

  function _getCandidateTimestamp(candidate) {
    const anchor = candidate.anchorResult?.anchor;
    if (!anchor || !anchor.record) return 0;
    const iso = anchor.record.declaredAt
             || anchor.record.frequency?.lastSeenAt
             || null;
    if (!iso) return 0;
    const t = new Date(iso).getTime();
    return isNaN(t) ? 0 : t;
  }

  // ──────────────────────────────────────────────────────────────────────
  // Helper · score de candidato (mayor score = mejor candidato)
  // ──────────────────────────────────────────────────────────────────────
  //
  // Score combina: materialidad (excepcional=100 · regular=50)
  //              - anchor priority (decision=1 a exceptional=6)
  //              + recencia normalizada
  //
  // Result: número · más alto = más prioritario

  // V.4 · _scoreCandidate AHORA async · consulta preferences si hasAnyPreference()
  // Fast path · cuando no hay preferences · cero overhead · score idéntico actual
  async function _scoreCandidate(candidate) {
    if (!candidate || !candidate.materialEventResult) return -Infinity;
    const ev = candidate.materialEventResult;
    if (!ev.material) return -Infinity;

    // Componente 1 · materialidad (excepcional pesa más que regular)
    const materialityScore = ev.exceptional ? 100 : 50;

    // Componente 2 · anchor priority (invertido · menor priority = mejor)
    const anchorType = candidate.anchorResult?.anchor?.type;
    const anchorPriorityValue = T5_ANCHOR_PRIORITY[anchorType] || 99;
    const anchorScore = 20 - anchorPriorityValue;  // decision=19 · exceptional=14

    // Componente 3 · recencia (normalizada: hoy=10, hace 30d=0)
    const ts = _getCandidateTimestamp(candidate);
    let recencyScore = 0;
    if (ts > 0) {
      const daysAgo = (Date.now() - ts) / (1000 * 60 * 60 * 24);
      recencyScore = Math.max(0, 10 - daysAgo / 3);  // hoy=10 · 30d=0
    }

    let baseScore = materialityScore + anchorScore + recencyScore;

    // V.4 · Componente 4 (opcional) · preferences boost · FAST PATH
    if (typeof OrgPreferenceApplier !== "undefined" && typeof OrgPreferenceApplier.hasAnyPreference === "function") {
      try {
        const hasPrefs = await OrgPreferenceApplier.hasAnyPreference();
        if (!hasPrefs) return baseScore;  // fast path · cero overhead

        // Priority boost · busca por entityRefId · luego por módulo
        let priorityLevel = 0;
        if (candidate.entityRefId) {
          priorityLevel = await OrgPreferenceApplier.getActivePriority(candidate.entityRefId);
        }
        if (priorityLevel === 0 && candidate.module) {
          priorityLevel = await OrgPreferenceApplier.getActivePriority(candidate.module);
        }
        const priorityBoost = priorityLevel * V4_PRIORITY_BOOST;  // +10 · 0 · -10

        // Focus boost · si entity está en focus active
        let focusBoost = 0;
        if (candidate.entityRefId) {
          const inFocus = await OrgPreferenceApplier.isEntityInFocus(candidate.entityRefId);
          if (inFocus) focusBoost = V4_FOCUS_BOOST;
        }

        return baseScore + priorityBoost + focusBoost;
      } catch (e) {
        return baseScore;  // defensivo · si applier falla · score base
      }
    }

    return baseScore;
  }

  // ──────────────────────────────────────────────────────────────────────
  // Helper · comparar candidatos (sort comparator)
  // ──────────────────────────────────────────────────────────────────────

  function _compareCandidates(a, b) {
    const scoreA = _scoreCandidate(a);
    const scoreB = _scoreCandidate(b);
    if (scoreB !== scoreA) return scoreB - scoreA;
    // Tie-breaking final · alfabético por entityRefId (determinístico)
    const idA = a.entityRefId || "";
    const idB = b.entityRefId || "";
    return idA.localeCompare(idB);
  }

  // ──────────────────────────────────────────────────────────────────────
  // Helper · ¿candidato es transversal?
  // ──────────────────────────────────────────────────────────────────────

  function _isTransversal(candidate) {
    return candidate.anchorResult?.anchor?.type === "milestone_systemic";
  }

  // ──────────────────────────────────────────────────────────────────────
  // Helper · ¿cuota disponible para candidato?
  // ──────────────────────────────────────────────────────────────────────

  function _hasQuota(candidate) {
    if (_isTransversal(candidate)) {
      return !_sessionQuotas.transversalUsed;
    }
    const module = candidate.module || null;
    if (!module || !T5_VALID_MODULES.includes(module)) return false;
    return !_sessionQuotas.modulesUsed.has(module);
  }

  // ──────────────────────────────────────────────────────────────────────
  // Helper · consumir cuota
  // ──────────────────────────────────────────────────────────────────────

  function _consumeQuota(candidate) {
    if (_isTransversal(candidate)) {
      _sessionQuotas.transversalUsed = true;
      return;
    }
    if (candidate.module) {
      _sessionQuotas.modulesUsed.add(candidate.module);
    }
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · selectBestProactive
  // ──────────────────────────────────────────────────────────────────────
  //
  // Argumentos:
  //   candidates: array de candidatos pre-evaluados con shape:
  //     {
  //       entityRefId, module, metricKey, prevValue, currValue,
  //       materialEventResult (T.1 result),
  //       anchorResult (T.2 result),
  //       composedResult (T.3 result · opcional · puede componerse aquí)
  //     }
  //   options: { consumeQuota: boolean } · default true
  //
  // Returns:
  //   {
  //     selected: candidate | null,
  //     score: number,
  //     reason: "selected" | "no_candidates" | "all_dismissed" | "no_quota",
  //     remainingQuota: { modulesAvailable, transversalAvailable }
  //   }

  async function selectBestProactive(candidates, options) {
    if (!T_ENABLED) return { selected: null, reason: "t_disabled" };
    const opts = options || { consumeQuota: true };
    if (!Array.isArray(candidates) || candidates.length === 0) {
      return { selected: null, reason: "no_candidates" };
    }

    // Paso 1 · filtrar dismisseados
    const dismissCandidates = candidates.map(c => ({
      proactiveType: c.materialEventResult?.exceptional ? "exceptional_severe" : "regular_material",
      entityRefId: c.entityRefId,
      triggerType: c.metricKey,
    }));
    const stillValid = [];
    for (let i = 0; i < candidates.length; i++) {
      const isDis = await OrgProactiveDismiss.isDismissed(dismissCandidates[i]);
      if (!isDis) stillValid.push(candidates[i]);
    }
    if (stillValid.length === 0) {
      return { selected: null, reason: "all_dismissed" };
    }

    // Paso 2 · filtrar por cuota disponible
    const withQuota = stillValid.filter(c => _hasQuota(c));
    if (withQuota.length === 0) {
      return { selected: null, reason: "no_quota" };
    }

    // Paso 3 · pre-computar scores async (V.4 · _scoreCandidate ahora async)
    // Luego sort sincrónico con scores ya computados
    const scoredCandidates = [];
    for (const c of withQuota) {
      const score = await _scoreCandidate(c);
      scoredCandidates.push({ candidate: c, score });
    }
    scoredCandidates.sort((a, b) => {
      if (b.score !== a.score) return b.score - a.score;
      // Tie-break alfabético por entityRefId (paridad _compareCandidates original)
      const idA = a.candidate.entityRefId || "";
      const idB = b.candidate.entityRefId || "";
      return idA.localeCompare(idB);
    });
    const best = scoredCandidates[0]?.candidate;
    if (!best) return { selected: null, reason: "no_quota" };

    // Paso 4 · consumir cuota (si opts lo permite)
    if (opts.consumeQuota !== false) {
      _consumeQuota(best);
    }

    return {
      selected: best,
      score: scoredCandidates[0].score,
      reason: "selected",
      remainingQuota: getRemainingQuota(),
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · evaluateFullPipeline (orquestador end-to-end)
  // ──────────────────────────────────────────────────────────────────────
  //
  // Orquesta T.1→T.2→T.3→T.4→T.5 atómicamente para una lista de eventos crudos.
  //
  // Argumentos:
  //   rawEvents: array de {
  //     entityRefId, module, metricKey, prevValue, currValue, contribucionAfectada?
  //   }
  //
  // Returns: { selected: { candidate, composedText, suggestions } | null, reason }

  async function evaluateFullPipeline(rawEvents) {
    if (!T_ENABLED) return { selected: null, reason: "t_disabled" };
    if (!Array.isArray(rawEvents) || rawEvents.length === 0) {
      return { selected: null, reason: "no_events" };
    }

    // Paso A · T.1 evaluate + T.2 anchor para cada raw event
    const candidates = [];
    for (const ev of rawEvents) {
      const materialEventResult = OrgProactiveDetector.evaluateMaterialEvent({
        metricKey: ev.metricKey,
        prevValue: ev.prevValue,
        currValue: ev.currValue,
        contribucionAfectada: ev.contribucionAfectada,
      });
      if (!materialEventResult.material) continue;
      const anchorResult = await OrgProactiveAnchor.findAnchorForEvent({
        entityRefId: ev.entityRefId,
        materialEventResult,
      });
      if (!anchorResult.hasAnchor) continue;
      candidates.push({
        entityRefId: ev.entityRefId,
        module: ev.module || null,
        metricKey: ev.metricKey,
        prevValue: ev.prevValue,
        currValue: ev.currValue,
        contribucionAfectada: ev.contribucionAfectada,
        materialEventResult,
        anchorResult,
      });
    }

    // Paso B · T.5 select
    const selectionResult = await selectBestProactive(candidates);
    if (!selectionResult.selected) {
      return { selected: null, reason: selectionResult.reason };
    }

    // Paso C · T.3 compose sobre el seleccionado
    const c = selectionResult.selected;
    const composed = OrgProactiveComposer.composeProactive({
      entityRefId: c.entityRefId,
      metricKey: c.metricKey,
      prevValue: c.prevValue,
      currValue: c.currValue,
      materialEventResult: c.materialEventResult,
      anchorResult: c.anchorResult,
      contribucionAfectada: c.contribucionAfectada,
    });

    if (!composed.composed) {
      return { selected: null, reason: "compose_failed" };
    }

    return {
      selected: {
        candidate: c,
        composedText: composed.text,
        suggestions: composed.suggestions,
        variant: composed.variant,
        anchorType: composed.anchorType,
      },
      reason: "ok",
      score: selectionResult.score,
      remainingQuota: getRemainingQuota(),
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · resetSessionQuotas
  // ──────────────────────────────────────────────────────────────────────

  function resetSessionQuotas() {
    _sessionQuotas = {
      modulesUsed: new Set(),
      transversalUsed: false,
      sessionStartedAt: Date.now(),
    };
    return true;
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · getRemainingQuota
  // ──────────────────────────────────────────────────────────────────────

  function getRemainingQuota() {
    const modulesAvailable = T5_VALID_MODULES.filter(m => !_sessionQuotas.modulesUsed.has(m));
    return {
      modulesAvailable,
      modulesAvailableCount: modulesAvailable.length,
      transversalAvailable: !_sessionQuotas.transversalUsed,
      sessionStartedAt: _sessionQuotas.sessionStartedAt,
    };
  }

  // ──────────────────────────────────────────────────────────────────────
  // API pública · getSelectorStats (introspección)
  // ──────────────────────────────────────────────────────────────────────

  function getSelectorStats() {
    return {
      valid_modules: T5_VALID_MODULES,
      quota_per_module: T5_QUOTA_PER_MODULE,
      quota_transversal: T5_QUOTA_TRANSVERSAL,
      anchor_priority: T5_ANCHOR_PRIORITY,
      current_session: getRemainingQuota(),
    };
  }

  return {
    selectBestProactive,
    evaluateFullPipeline,
    resetSessionQuotas,
    getRemainingQuota,
    getSelectorStats,
  };
})();

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF T · T.5 · QUOTA + SELECTION ENGINE 🎯
// (próxima pieza: T.6 · UI Integration + Runtime Wiring · último BRIEF T)
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// BRIEF AN · AN+ · ACTIVACIÓN USER-FACING DISPATCHER ⭐ 4to MOMENTO HISTÓRICO
//
// AN+ es la activación user-facing del BRIEF AN motor completo. Paridad
// arquitectónica con S+ (prependDeltaToNarrative · BRIEF S→S+) y U+.B
// (appendCalibrationToNarrative · BRIEF U→U+).
//
// SCOPE FIRMADO AN+:
//   · D-AN+.1 · A · sección AN+ propia (paridad S+ post-S.I)
//   · D-AN+.2 · C · respeta D-AN.B-5 sin cooldown extra (AN.B ya gestiona)
//   · D-AN+.3 · A · responseSuggestions [] vacío honest · cero invención
//   · D-AN+.4 · A · cross_dimension_event consumible en lastComposerResponse
//   · D-AN+.5 · A (CORREGIDO por filtro #3 arquitecto) · wrapper SOLO en unified
//                Razón: prependDeltaToNarrative + appendCalibrationToNarrative
//                       ambos tienen 1 sólo call site (línea 31114-31118 unified) ·
//                       NO existen en path legacy (deprecado por flag
//                       VOICE_UNIFIED_ROUTING_ENABLED=true línea 5517) ·
//                       "Paridad disciplinaria" = wrapper SOLO unified · NO ambos.
//
// 🆕 INVARIANTE #R-AN-PLUS-HABILITADOR-EVIDENCE-SYNC-LAYER-API-PREPARADA-NO-CABLEADA
//    "AN no es el destino final. AN es la capa que permitirá una futura
//     sincronización profunda entre ADI y Sentrix."
//    _dispatchAnComposer emite cross_dimension_event como ESTRUCTURA (no solo
//    string proyectado). Futura Evidence Sync Layer puede suscribirse opt-in.
//    CERO hardcode a Sentrix · CERO acoplamiento UI · solo estructura emitible.
//
// 2 TOUCHES CONSCIENTES autorizados (paridad funcional S+/U+.B):
//   1. Wrapper post-detectIntent (unified · línea 30794)
//   2. Case nuevo dispatcher cross_dimension_query (línea ~31134)
//
// LECCIÓN REGISTRADA (2da caza filtro #3 reverso arquitecto):
//   #L-FILTRO-3-ARQUITECTONICO-SEGUNDA-CAZA-EJECUTOR-AFIRMACION-PARIDAD
//   El ejecutor afirmó "2 wrappers paridad disciplinaria" sin verificar ·
//   arquitecto grep S+/U+.B en 30s · ambos wrappean 1 sólo call site unified.
//   Romper paridad por error fáctico habría sido asimetría silenciosa.
// ════════════════════════════════════════════════════════════════════════════

// ── VOICE_AN_INTEGRATOR_ENABLED · flag rollback ────────────────────────────
// Paridad VOICE_CALIBRATION_INTEGRATOR_ENABLED (U+.B) y dispatcher S+.
// OFF default · activación post-V_VISUAL · igual que S+ y U+.B.
// Si flag === false: case dispatcher NO emite narrativa cross-dim · fallback honest.
const VOICE_AN_INTEGRATOR_ENABLED = false;

// ── _dispatchAnComposer · helper REAL (diferido desde D-AN.D-2=A) ─────────
// PIPELINE: catálogo → composer thin → cross_dimension_event estructura
//
// Recibe: crossKey (del intent AN.B), entities (ring resuelto), scenarioId.
// Retorna: cross_dimension_event objeto con 8 campos consumibles · o null si
//          cualquier capa defensiva falla (honest fail · paridad AN.B 9 capas).
//
// 🆕 ESTRUCTURA EMITIBLE (visión Evidence Sync Layer preservada · D-AN+.4):
//   {
//     cross_key:     string       · clave alfabética catálogo
//     dim_a:         string       · dimensión A (orden alfabético)
//     dim_b:         string       · dimensión B (orden alfabético)
//     lens:          string       · presion_comercial · capital_atrapado · eficiencia_operativa
//     entities:      array        · [{id, canonical_name, kind}] ring procesado
//     entity_type:   string       · client | sku | default
//     narrative:     string       · output user-facing (cumple REGLA UNIVERSAL ECL)
//     scenario_id:   string       · "bonanza" | "tension" | "crisis"
//     timestamp:     string ISO   · momento de emisión
//     source:        string       · "an_plus_dispatcher"
//   }
// Futura Evidence Sync Layer puede suscribirse OPT-IN al evento y abrir Sentrix
// usando entities[] · cambiar vista usando entity_type · etc.
// CERO hardcode Sentrix · CERO acoplamiento UI · solo estructura.
function _dispatchAnComposer(crossKey, entities, scenarioId, options) {
  // CAPA 1 · flag gate (D-AN+ paridad rollback)
  const force_enabled = !!(options && options.force_enabled === true);
  if (!VOICE_AN_INTEGRATOR_ENABLED && !force_enabled) return null;
  // CAPA 2 · inputs válidos
  if (typeof crossKey !== "string" || !Array.isArray(entities) || entities.length === 0) return null;
  if (typeof scenarioId !== "string") return null;
  // CAPA 3 · catálogo resuelve crossKey + composer
  if (typeof getCrossDimension !== "function") return null;
  const entry = getCrossDimension(crossKey, { force_enabled: true });
  if (!entry || !entry.composer) return null;
  // Composers map · 3 cruces MVP (extensible · post-MVP solo agrega entry catálogo + composer)
  const composers = {
    _composeAn1MargenCarga:    typeof _composeAn1MargenCarga    === "function" ? _composeAn1MargenCarga    : null,
    _composeAn2MargenRotacion: typeof _composeAn2MargenRotacion === "function" ? _composeAn2MargenRotacion : null,
    _composeAn3DohMargen:      typeof _composeAn3DohMargen      === "function" ? _composeAn3DohMargen      : null,
  };
  const composerFn = composers[entry.composer];
  if (typeof composerFn !== "function") return null;
  // CAPA 4 · invocar composer + entityType detectable
  const narrative = composerFn(entities, scenarioId, { force_enabled: true });
  if (typeof narrative !== "string" || narrative.length === 0) return null;
  const entityType = (typeof _detectRingEntityType === "function")
    ? _detectRingEntityType(entities)
    : "default";
  // Emitir cross_dimension_event estructura completa
  // Entities con kind enriquecido si registry disponible (paridad BRIEF S)
  const enrichedEntities = entities.map(function(e) {
    const eid = (typeof e === "object" && e !== null) ? e.id : e;
    const ename = (typeof e === "object" && e !== null && e.canonical_name) ? e.canonical_name : eid;
    let kind = null;
    if (typeof getEntityById === "function") {
      const reg = getEntityById(eid);
      if (reg && reg.kind) kind = reg.kind;
    }
    return { id: eid, canonical_name: ename, kind: kind };
  });
  return {
    cross_key:    crossKey,
    dim_a:        entry.dim_a,
    dim_b:        entry.dim_b,
    lens:         entry.lens,
    entities:     enrichedEntities,
    entity_type:  entityType,
    narrative:    narrative,
    scenario_id:  scenarioId,
    timestamp:    new Date().toISOString(),
    source:       "an_plus_dispatcher",
  };
}

// ════════════════════════════════════════════════════════════════════════════
// FIN BRIEF AN · AN+ · ACTIVACIÓN USER-FACING DISPATCHER ⭐
// (próximos touches conscientes en PanelADI: wrapper detectIntent + case dispatcher)
// ════════════════════════════════════════════════════════════════════════════


// ════════════════════════════════════════════════════════════════════════════
// APP PRINCIPAL
// ════════════════════════════════════════════════════════════════════════════
export default function ADISentric() {
  // ── BRIEF #20: empty state landing.
  // El componente inicia SIN módulo activo · muestra logo grande + 3 cards.
  // Click en una card → setModulo("ventas"|"margenes"|"inventario") → carga Hero contextual.
  const [modulo,     setModulo]     = useState(null);
  const [filtro,     setFiltro]     = useState("Anual");
  const [filtros,    setFiltros]    = useState({ marcas:[], sfamilias:[], canales:[], sucursales:[], clientes:[], skus:[] });
  // FIX #D-AUTOLINK-FILTRO-AUTOMATICO · origen del filtro vigente: "auto" (autolink/panorama) |
  // "explicit" (click manual) | null (sin filtro). Paralelo a filtros · lo escribe handleSentrixAction
  // desde payload._origin · lo lee la limpieza (handleNewChat/reset-escenario) para borrar SOLO el auto.
  const [filtrosOrigin, setFiltrosOrigin] = useState(null);
  // FIX #D-AUTOLINK-FILTRO-AUTOMATICO · ref espejo del origen · se setea SÍNCRONO en handleSentrixAction
  // (sin lag de render) · la limpieza lo lee. El state filtrosOrigin es para render; el ref para la lógica.
  const filtrosOriginRef = useRef(null);
  const [adiProfile, setAdiProfile] = useState("retail");
  const [userRole,   setUserRole]   = useState("gerente_comercial");
  const [userName,   setUserName]   = useState("JuanCa"); // nombre del usuario activo

  // ── Layout plegable: ADI centro + Sentrix derecho
  // Default: ADI ocupa el ancho disponible, Sentrix cerrado
  const [sentrixOpen, setSentrixOpen] = useState(false);
  const containerRef                  = useRef(null);

  // ── Magic Moment (BRIEF #3): tracking de módulos que ya corrieron su animación
  // de tesis ejecutiva en esta sesión. Cada módulo se anima una sola vez.
  const [animatedModules, setAnimatedModules] = useState(() => new Set());
  const markModuleAnimated = useCallback((mod) => {
    setAnimatedModules(prev => prev.has(mod) ? prev : new Set([...prev, mod]));
  }, []);

  // ── Escenarios (BRIEF #4): narrativa global del demo (Bonanza/Tensión/Crisis).
  // Cambiar de escenario re-dispara el Magic Moment porque es información nueva.
  // Resetear animatedModules en el mismo tick que cambia scenario evita un
  // flicker de un solo render donde shouldAnimate aún sería false.
  const [scenario, setScenario] = useState("bonanza");
  const handleScenarioChange = useCallback((next) => {
    if (next === scenario) return;
    setAnimatedModules(new Set());
    // FIX #D-AUTOLINK-FILTRO-AUTOMATICO · al cambiar de escenario, limpiar el filtro SOLO si fue
    // automático · el explícito se preserva. off → no limpia (como hoy).
    if (typeof ADI_AUTOLINK_FILTER_ORIGIN_ENABLED !== "undefined" && ADI_AUTOLINK_FILTER_ORIGIN_ENABLED && filtrosOriginRef.current === "auto") {
      setFiltros({ marcas:[], sfamilias:[], canales:[], sucursales:[], clientes:[], skus:[] });
      filtrosOriginRef.current = null;
      setFiltrosOrigin(null);
    }
    setScenario(next);
  }, [scenario]);

  // FIX #D-AUTOLINK-FILTRO-AUTOMATICO · el padre limpia el filtro AUTO cuando PanelADI lo señala
  // (Nueva sesión). Solo si el filtro vigente es auto · el explícito se preserva (invariante). off → no-op.
  const handleAutoFilterReset = useCallback(() => {
    if (typeof ADI_AUTOLINK_FILTER_ORIGIN_ENABLED !== "undefined" && ADI_AUTOLINK_FILTER_ORIGIN_ENABLED && filtrosOriginRef.current === "auto") {
      setFiltros({ marcas:[], sfamilias:[], canales:[], sucursales:[], clientes:[], skus:[] });
      filtrosOriginRef.current = null;
      setFiltrosOrigin(null);
    }
  }, []);

  // FIX #D-BOTON-LIMPIAR-FILTROS · "⌫ Limpiar filtros" · limpia los 6 campos de un golpe (auto Y
  // explícito · limpieza total a pedido del usuario), SIN tocar el chat/análisis/opener. Convive con
  // el fix de origen (limpia también el rastro de origen). NO toca handleNewChat (el reset del chat).
  const handleLimpiarFiltros = useCallback(() => {
    setFiltros({ marcas:[], sfamilias:[], canales:[], sucursales:[], clientes:[], skus:[] });
    if (typeof ADI_AUTOLINK_FILTER_ORIGIN_ENABLED !== "undefined" && ADI_AUTOLINK_FILTER_ORIGIN_ENABLED) {
      filtrosOriginRef.current = null;
      setFiltrosOrigin(null);
    }
  }, []);

  // ── Botón "✨ Explícame …" desde Sentrix (BRIEF #9): puente datos → chat.
  // Al pulsar, cerramos Sentrix para enfocar atención en ADI, sincronizamos
  // el módulo si el botón viene de un módulo distinto al activo, y emitimos
  // un evento (explainTriggered) que el PanelADI escucha vía useEffect.
  // El timestamp fuerza un nuevo trigger aunque se pulse dos veces seguidas.
  const [explainTriggered, setExplainTriggered] = useState(null);
  const handleExplain = useCallback((moduloRequest) => {
    const targetModulo = moduloRequest || modulo;
    setSentrixOpen(false);
    if (targetModulo !== modulo) setModulo(targetModulo);
    setExplainTriggered({
      scenario: scenario,
      modulo:   targetModulo,
      timestamp: Date.now(),
    });
  }, [modulo, scenario]);

  // BRIEF #16 · Banner del mecanismo activo en Sentrix.
  // Cuando ADI pasa contexto a Sentrix vía botón contextual, este estado
  // guarda el nombre del mecanismo activo para mostrarlo como banner en la
  // cabecera del módulo. null = sin banner (apertura libre de Sentrix).
  const [sentrixMechanismBanner, setSentrixMechanismBanner] = useState(null);

  // BRIEF #23-quater · flag para distinguir cambio de módulo guiado por
  // Sentrix (NO resetea chat) vs cambio manual del usuario clickeando los
  // tabs (SÍ resetea chat). Se setea en handleSentrixAction antes de cambiar
  // el módulo, y PanelADI lo consume en su useEffect de reset. El consumidor
  // limpia el flag tras leerlo, así que persiste solo un render.
  const [sentrixDrivenModuleSwitch, setSentrixDrivenModuleSwitch] = useState(false);
  const [sentrixEvidencia, setSentrixEvidencia] = useState(null); // C3.2 · evidencia de la tesis (nivel 2) recibida vía onSentrixAction · display-only · null = sin nivel 2

  // BRIEF #16 · Puente ADI → Sentrix · contextual con filtros + banner.
  // Aplica filtro de clientes a Sentrix (preserva otros filtros), cambia
  // módulo si es necesario, setea el banner del mecanismo activo, y abre
  // Sentrix si estaba cerrado.
  const handleSentrixAction = useCallback((payload) => {
    if (!payload) return;
    // FIX #D-AUTOLINK-FILTRO-AUTOMATICO · persistir el origen del filtro vigente (auto vs explicit)
    // desde payload._origin · default "explicit" (los clicks no marcan o marcan explicit · solo el
    // auto-link/panorama marcan "auto"). La limpieza lee esto para borrar SOLO el auto.
    if (typeof ADI_AUTOLINK_FILTER_ORIGIN_ENABLED !== "undefined" && ADI_AUTOLINK_FILTER_ORIGIN_ENABLED) {
      const _origin = payload._origin === "auto" ? "auto" : "explicit";
      filtrosOriginRef.current = _origin;   // síncrono · la limpieza lo lee sin lag
      setFiltrosOrigin(_origin);            // para render (el resto del componente)
    }
    // C3.2 · evidencia de la tesis (nivel 2) · display-only · el payload es la única fuente (reemplazar):
    // si trae evidencia (overview de inventario) la muestra; si no (finding/click) la limpia.
    setSentrixEvidencia(VOICE_C32_EVIDENCE_ENABLED ? (payload.evidencia || null) : null);
    // BRIEF #23 · aplicar todas las entidades específicas que ADI
    // mencionó (no solo clientes). Cuando un campo NO viene en el
    // payload, se limpia con ||[] para evitar que filtros de
    // respuestas anteriores contaminen la nueva. Comportamiento
    // determinístico: el payload es la única fuente de verdad.
    setFiltros(prev => ({
      ...prev,
      clientes:    payload.clientes    || [],
      skus:        payload.skus        || [],
      marcas:      payload.marcas      || [],
      sfamilias:   payload.sfamilias   || [],
      sucursales:  payload.sucursales  || [],
      canales:     payload.canales     || [],
    }));
    if (payload.modulo && payload.modulo !== modulo) {
      // BRIEF #23-quater · marcar que el cambio viene de ADI · el useEffect
      // de reset en PanelADI lo lee y preserva la conversación. Sin este
      // flag, setModulo dispararía el reset y el chat volvería al hero.
      setSentrixDrivenModuleSwitch(true);
      setModulo(payload.modulo);
    }
    setSentrixMechanismBanner(payload.mechanismBanner || null);
    if (!sentrixOpen) {
      setSentrixOpen(true);
    }
  }, [modulo, sentrixOpen]);

  const MESES = ["Ene","Feb","Mar","Abr","May","Jun","Jul","Ago","Sep","Oct","Nov","Dic","Anual"];
  const MOD   = { ventas:{ label:"Ventas", color:C.blue }, margenes:{ label:"Márgenes", color:C.blue }, inventario:{ label:"Inventario", color:C.blue } };

  const handleContextChange = (key, val) => key==="adiProfile" ? setAdiProfile(val) : setUserRole(val);

  return (
    <div style={{ height:"100vh", background:C.bg, fontFamily:"'DM Sans','Segoe UI',sans-serif", color:C.text, display:"flex", flexDirection:"column", overflow:"hidden" }}>

      <header style={{ position:"relative", display:"flex", alignItems:"center", justifyContent:"space-between", padding:"0 24px", height:56, borderBottom:`1px solid ${C.border}`, background:"linear-gradient(180deg, rgba(0,176,212,0.025) 0%, transparent 80%)", flexShrink:0 }}>
        {/* aurora line · respirando 6s · indica sistema vivo */}
        <div style={{ position:"absolute", left:0, right:0, bottom:-1, height:1, background:"linear-gradient(90deg, transparent 5%, rgba(0,176,212,0.5) 50%, transparent 95%)", pointerEvents:"none", animation:"auroraBreathe 6s ease-in-out infinite" }}/>

        <div style={{ display:"flex", alignItems:"center", gap:18, flexShrink:0 }}>
          <button onClick={()=>{ if(modulo) { setModulo(null); setSentrixOpen(false); } }}
            disabled={!modulo}
            title={modulo ? "Volver al inicio" : ""}
            style={{
              display:"flex", alignItems:"center", gap:10,
              background:"transparent", border:"none",
              padding:0,
              cursor: modulo ? "pointer" : "default",
              opacity: modulo ? 1 : 0.35,
              transition:"opacity 0.25s cubic-bezier(.4,0,.2,1)",
              fontFamily:"inherit"
            }}
            onMouseEnter={e=>{ if(modulo){ e.currentTarget.style.opacity = 0.85; } }}
            onMouseLeave={e=>{ if(modulo){ e.currentTarget.style.opacity = 1; } }}>
            <div style={{
              width:32, height:32,
              borderRadius:8,
              display:"flex", alignItems:"center", justifyContent:"center",
              flexShrink:0,
              background:"linear-gradient(135deg, rgba(0,176,212,0.08), rgba(14,127,168,0.04))",
              border:"1px solid rgba(0,176,212,0.18)",
              boxShadow:"inset 0 1px 0 rgba(255,255,255,0.06), 0 0 0 1px rgba(0,176,212,0.06), 0 4px 12px -3px rgba(0,176,212,0.2)"
            }}>
              <svg width="20" height="20" viewBox="0 0 200 200" fill="none" stroke="#00b0d4" strokeWidth="2.8" strokeLinecap="round" strokeLinejoin="round">
                <polygon points="100,15 173.6,57.5 173.6,142.5 100,185 26.4,142.5 26.4,57.5" strokeWidth="3.2"/>
                <circle cx="100" cy="100" r="55" strokeWidth="1.7" opacity="0.65"/>
                <ellipse cx="100" cy="100" rx="55" ry="22" strokeWidth="1.5" opacity="0.5"/>
                <ellipse cx="100" cy="100" rx="22" ry="55" strokeWidth="1.5" opacity="0.5"/>
                <circle cx="100" cy="100" r="6" fill="#00b0d4" stroke="none"/>
              </svg>
            </div>
            <div style={{ display:"flex", alignItems:"baseline", gap:7 }}>
              <span style={{ fontWeight:700, fontSize:14, letterSpacing:"-0.3px", color:C.text }}>ADI</span>
              <span style={{ fontWeight:500, fontSize:10.5, color:C.textMuted, fontFamily:"'JetBrains Mono', ui-monospace, monospace", letterSpacing:"1.2px", textTransform:"uppercase" }}>Sentrix</span>
            </div>
          </button>
          {modulo && (
            <>
              <div style={{ width:1, height:20, background:"linear-gradient(180deg, transparent, "+C.border+" 30%, "+C.border+" 70%, transparent)" }}/>
              <nav style={{ display:"flex", gap:1 }}>
                {Object.entries(MOD).map(([k,v])=>{
                  const isActive = modulo===k;
                  return (
                    <button key={k} onClick={()=>setModulo(k)} style={{
                      position:"relative",
                      padding:"6px 14px", borderRadius:6, fontSize:12.5, fontWeight:600,
                      letterSpacing:"-0.005em",
                      border:"none",
                      background: isActive ? "rgba(0,176,212,0.07)" : "transparent",
                      color: isActive ? v.color : C.textMuted,
                      cursor:"pointer", transition:"all 0.18s cubic-bezier(.4,0,.2,1)"
                    }}
                    onMouseEnter={e=>{ if(!isActive){ e.currentTarget.style.color = C.textSub; e.currentTarget.style.background = "rgba(255,255,255,0.025)"; } }}
                    onMouseLeave={e=>{ if(!isActive){ e.currentTarget.style.color = C.textMuted; e.currentTarget.style.background = "transparent"; } }}>
                      {v.label}
                      {isActive && (
                        <span style={{ position:"absolute", left:14, right:14, bottom:-3, height:2, background:v.color, borderRadius:1, boxShadow:`0 0 8px ${v.color}88` }}/>
                      )}
                    </button>
                  );
                })}
              </nav>
            </>
          )}
        </div>

        <div style={{ display:"flex", alignItems:"center", gap:14, flexShrink:0 }}>
          {modulo && (
            <>
              <ContextSelector adiProfile={adiProfile} userRole={userRole} onChange={handleContextChange}/>
              <div style={{ width:1, height:20, background:"linear-gradient(180deg, transparent, "+C.border+" 30%, "+C.border+" 70%, transparent)" }}/>
              <ScenarioSelector scenario={scenario} onChange={handleScenarioChange}/>
            </>
          )}
          <div style={{ display:"flex", alignItems:"center", gap:7, paddingLeft:modulo?14:0, borderLeft:modulo?`1px solid ${C.border}`:"none", flexShrink:0, whiteSpace:"nowrap" }}>
            <span style={{ position:"relative", width:6, height:6, borderRadius:"50%", background:C.green, flexShrink:0 }}>
              <span style={{ position:"absolute", inset:-3, borderRadius:"50%", border:"1px solid rgba(16,185,129,0.5)", animation:"livePulse 1.8s ease-out infinite" }}/>
            </span>
            <span style={{ fontSize:9.5, color:C.textMuted, fontFamily:"'JetBrains Mono', ui-monospace, monospace", letterSpacing:"1px" }}>LIVE</span>
            <span style={{ fontSize:10.5, color:C.text, fontWeight:500, fontFamily:"'JetBrains Mono', ui-monospace, monospace", letterSpacing:"0.3px" }}>{getCurrentDateString()}</span>
          </div>
        </div>
      </header>

      {/* ── Fila 2: Filtros + Meses · solo cuando hay módulo activo (BRIEF #20) */}
      {modulo && (
        <div style={{ padding:"9px 24px", borderBottom:`1px solid ${C.border}`, background:"linear-gradient(180deg, #0a0a0a, #080808)", flexShrink:0, display:"flex", alignItems:"center", justifyContent:"space-between", gap:16 }}>
          <div style={{ flex:1, minWidth:0 }}>
            <FiltrosGlobales filtros={filtros} onChange={setFiltros}/>
          </div>
          <div style={{ display:"flex", alignItems:"center", gap:2, padding:3, background:"rgba(255,255,255,0.02)", border:`1px solid ${C.border}`, borderRadius:8, flexShrink:0 }}>
            {MESES.map(m=>{
              const isActive = filtro===m;
              return (
                <button key={m} onClick={()=>setFiltro(m)} style={{
                  padding:"4px 9px", borderRadius:5, fontSize:10.5, fontWeight:500,
                  border:"none",
                  background: isActive ? "rgba(0,176,212,0.1)" : "transparent",
                  color: isActive ? C.blue : C.textMuted,
                  cursor:"pointer", transition:"all 0.15s",
                  fontFamily:"'JetBrains Mono', ui-monospace, monospace",
                  letterSpacing:"0.5px",
                  boxShadow: isActive ? "inset 0 0 0 1px rgba(0,176,212,0.25)" : "none"
                }}
                onMouseEnter={e=>{ if(!isActive){ e.currentTarget.style.color = C.textSub; e.currentTarget.style.background = "rgba(255,255,255,0.03)"; } }}
                onMouseLeave={e=>{ if(!isActive){ e.currentTarget.style.color = C.textMuted; e.currentTarget.style.background = "transparent"; } }}>{m}</button>
              );
            })}
          </div>
        </div>
      )}

      <div ref={containerRef} style={{ display:"flex", flex:1, overflow:"hidden", position:"relative" }}>

        {/* ════════════════════════════════════════════════
            ADI · CENTRO — protagonista, siempre visible
        ════════════════════════════════════════════════ */}
        <main style={{
          flex:1, minWidth:0,
          transition:"flex 300ms ease",
          display:"flex", flexDirection:"column",
          position:"relative",
          background:"linear-gradient(180deg, #090909 0%, #070707 100%)",
          boxShadow:"inset 0 0 60px rgba(0,0,0,0.4)",
          overflow:"hidden"
        }}>
          {/* ── ATMÓSFERA · Grid de puntos ultra-sutil (Vercel-style) */}
          <div style={{
            position:"absolute", inset:0, zIndex:0, pointerEvents:"none",
            backgroundImage:"radial-gradient(circle, rgba(255,255,255,0.025) 1px, transparent 1px)",
            backgroundSize:"32px 32px",
            backgroundPosition:"-1px -1px",
            maskImage:"radial-gradient(ellipse 80% 60% at 50% 40%, black 30%, transparent 100%)",
            WebkitMaskImage:"radial-gradient(ellipse 80% 60% at 50% 40%, black 30%, transparent 100%)"
          }}/>
          {/* ── ATMÓSFERA · Aurora cyan respirando (lento, 18s) */}
          <div style={{
            position:"absolute", inset:0, zIndex:0, pointerEvents:"none",
            background:"radial-gradient(ellipse 55% 45% at 50% 30%, rgba(0,176,212,0.05) 0%, rgba(0,176,212,0.02) 35%, transparent 70%)",
            animation:"adiAurora 18s ease-in-out infinite",
            transformOrigin:"50% 30%"
          }}/>
          {/* Wrapper del contenido con z-index para que viva sobre la atmósfera */}
          <div style={{ position:"relative", zIndex:1, display:"flex", flexDirection:"column", flex:1, minHeight:0 }}>
          {modulo ? (
            <>
            {/* Botón toggle de Sentrix */}
            <div style={{ position:"absolute", top:14, right:14, zIndex:10 }}>
            <button onClick={()=>{
              // BRIEF #16 · apertura libre limpia el banner del mecanismo
              const willOpen = !sentrixOpen;
              setSentrixOpen(willOpen);
              if (willOpen) setSentrixMechanismBanner(null);
            }}
              style={{
                display:"flex", alignItems:"center", gap:7,
                padding:"7px 14px", borderRadius:7,
                fontSize:11.5, fontWeight:600,
                letterSpacing:"-0.005em",
                border:`1px solid ${sentrixOpen?"rgba(0,176,212,0.35)":C.border}`,
                background: sentrixOpen
                  ? "linear-gradient(180deg, rgba(0,176,212,0.12), rgba(0,176,212,0.04))"
                  : "linear-gradient(180deg, #131313, #0e0e0e)",
                color:sentrixOpen?C.blue:C.textSub,
                cursor:"pointer", transition:"all 0.2s cubic-bezier(.4,0,.2,1)",
                boxShadow: sentrixOpen
                  ? "0 4px 14px -4px rgba(0,176,212,0.3), inset 0 1px 0 rgba(255,255,255,0.04)"
                  : "0 4px 12px -4px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.03)"
              }}
              onMouseEnter={e=>{
                if (!sentrixOpen) {
                  e.currentTarget.style.borderColor = "rgba(0,176,212,0.3)";
                  e.currentTarget.style.color = C.text;
                  e.currentTarget.style.transform = "translateY(-1px)";
                }
              }}
              onMouseLeave={e=>{
                if (!sentrixOpen) {
                  e.currentTarget.style.borderColor = C.border;
                  e.currentTarget.style.color = C.textSub;
                  e.currentTarget.style.transform = "translateY(0)";
                }
              }}>
              {sentrixOpen ? (
                <>
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round"><polyline points="15 18 9 12 15 6"/></svg>
                  <span>Ocultar datos</span>
                </>
              ) : (
                <>
                  <span>Ver datos</span>
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 18 15 12 9 6"/></svg>
                </>
              )}
            </button>
          </div>

          <PanelADI
            modulo={modulo} filtro={filtro}
            marca={filtros.marcas[0]||"Anual"}
            adiProfile={adiProfile} userRole={userRole}
            userName={userName}
            width="100%"
            scenario={scenario}
            shouldAnimate={!animatedModules.has(modulo)}
            onAnimationComplete={markModuleAnimated}
            onShowData={() => { setSentrixOpen(true); setSentrixMechanismBanner(null); }}
            explainTriggered={explainTriggered}
            onSentrixAction={handleSentrixAction}
            onAutoFilterReset={handleAutoFilterReset}
            onLimpiarFiltros={handleLimpiarFiltros}
            sentrixDrivenModuleSwitch={sentrixDrivenModuleSwitch}
            onConsumeSentrixDrivenFlag={() => setSentrixDrivenModuleSwitch(false)}
          />
            </>
          ) : (
            /* ═══════════════════════════════════════════════════════
               EMPTY STATE LANDING · BRIEF #20
               Cuando modulo=null · logo ADI grande respirando + 3 cards
               de módulo para que el usuario elija dónde empezar.
               Click en card → setModulo(k) → carga Hero contextual normal.
               ═══════════════════════════════════════════════════════ */
            <div style={{
              flex:1,
              display:"flex", flexDirection:"column",
              alignItems:"center", justifyContent:"center",
              padding:"40px 32px",
              gap:24,
              overflowY:"auto",
              animation:"emptyFadeIn 400ms cubic-bezier(.4,0,.2,1)"
            }}>
              {/* ── LOGO 120×120 · transform-origin estable */}
              <div style={{
                position:"relative", width:120, height:120,
                display:"flex", alignItems:"center", justifyContent:"center",
                transformOrigin:"center center",
                animation:"adiBreath 3.2s ease-in-out infinite",
                filter:"drop-shadow(0 0 20px rgba(0,176,212,0.4)) drop-shadow(0 0 40px rgba(0,176,212,0.15))",
                flexShrink:0
              }}>
                <span style={{
                  position:"absolute", inset:-18, borderRadius:"50%",
                  border:"1px solid rgba(0,176,212,0.35)",
                  animation:"adiOrbRing 2.8s ease-out infinite",
                  pointerEvents:"none", transformOrigin:"center center"
                }}/>
                <span style={{
                  position:"absolute", inset:-18, borderRadius:"50%",
                  border:"1px solid rgba(0,176,212,0.22)",
                  animation:"adiOrbRing 2.8s ease-out infinite",
                  animationDelay:"0.9s",
                  pointerEvents:"none", transformOrigin:"center center"
                }}/>
                <span style={{
                  position:"absolute", inset:-18, borderRadius:"50%",
                  border:"1px solid rgba(0,176,212,0.15)",
                  animation:"adiOrbRing 2.8s ease-out infinite",
                  animationDelay:"1.8s",
                  pointerEvents:"none", transformOrigin:"center center"
                }}/>
                <svg viewBox="0 0 200 200" width="100%" height="100%" fill="none" stroke="#00b0d4" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" style={{ position:"relative", zIndex:1 }}>
                  <polygon points="100,15 173.6,57.5 173.6,142.5 100,185 26.4,142.5 26.4,57.5" strokeWidth="2"/>
                  <circle cx="100" cy="100" r="55" strokeWidth="1.2" opacity="0.7"/>
                  <ellipse cx="100" cy="100" rx="55" ry="22" strokeWidth="1" opacity="0.55"/>
                  <ellipse cx="100" cy="100" rx="22" ry="55" strokeWidth="1" opacity="0.55"/>
                  <ellipse cx="100" cy="100" rx="55" ry="40" strokeWidth="0.9" opacity="0.4" transform="rotate(35 100 100)"/>
                  <ellipse cx="100" cy="100" rx="55" ry="40" strokeWidth="0.9" opacity="0.4" transform="rotate(-35 100 100)"/>
                  <path d="M 72 138 L 92 65 Q 95 58 100 58 Q 105 58 108 65 L 128 138" strokeWidth="2.2"/>
                  <path d="M 82 110 Q 100 105 118 110" strokeWidth="1.8"/>
                  <path d="M 70 142 Q 68 135 74 132" strokeWidth="1.5" opacity="0.8"/>
                  <path d="M 130 142 Q 132 135 126 132" strokeWidth="1.5" opacity="0.8"/>
                  <path d="M 128 78 Q 120 65 105 65 Q 88 65 85 78 Q 82 90 95 95 L 115 102 Q 128 108 125 122 Q 122 135 105 135 Q 88 135 80 122" strokeWidth="2.2"/>
                  <path d="M 128 78 Q 132 72 128 68" strokeWidth="1.5" opacity="0.8"/>
                  <path d="M 80 122 Q 76 128 80 132" strokeWidth="1.5" opacity="0.8"/>
                  <circle cx="100" cy="100" r="3" strokeWidth="1.2"/>
                </svg>
              </div>

              {/* ── Manifiesto · sin "Soy ADI" porque el logo grande ya es ADI */}
              <div style={{ textAlign:"center", display:"flex", flexDirection:"column", gap:8 }}>
                <h1 style={{
                  fontFamily:"'DM Sans', 'system-ui', sans-serif",
                  fontSize:26, fontWeight:500, color:C.text,
                  letterSpacing:"-0.03em", margin:0,
                  lineHeight:1.25
                }}>
                  Tus datos ya hablan.
                </h1>
                <p style={{
                  fontFamily:"'DM Sans', 'system-ui', sans-serif",
                  fontSize:15, fontWeight:400, color:C.textSub,
                  letterSpacing:"-0.005em", margin:0,
                  lineHeight:1.5
                }}>
                  Ahora entendamos lo que significan.
                </p>
              </div>

              {/* ── Divider */}
              <div style={{
                width:60, height:1,
                background:"linear-gradient(90deg, transparent, rgba(255,255,255,0.12), transparent)"
              }}/>

              {/* ── Label */}
              <p style={{
                fontFamily:"'JetBrains Mono', ui-monospace, monospace",
                fontSize:9.5, color:C.textMuted,
                textTransform:"uppercase", letterSpacing:"1.6px",
                margin:0
              }}>
                ¿Por dónde querés empezar?
              </p>

              {/* ── 3 cards de módulo · con stagger animation */}
              <div style={{
                display:"flex", gap:14, flexWrap:"wrap",
                justifyContent:"center", maxWidth:780, width:"100%"
              }}>
                {[
                  { k:"ventas",      label:"Ventas",      desc:"Concentración, evolución y Pareto de clientes" },
                  { k:"margenes",    label:"Márgenes",    desc:"Carga comercial, gap vs benchmark, palancas"   },
                  { k:"inventario",  label:"Inventario",  desc:"Capital inmovilizado, desalineación, rotación" },
                ].map((m, idx) => {
                  const mod = MOD[m.k];
                  // Stagger: card 0 → 200ms · card 1 → 280ms · card 2 → 360ms
                  const staggerDelay = 200 + (idx * 80);
                  return (
                    <button key={m.k} onClick={()=>setModulo(m.k)}
                      style={{
                        flex:"1 1 230px", maxWidth:260, minHeight:140,
                        padding:"20px 18px",
                        background:"rgba(255,255,255,0.02)",
                        border:"1px solid rgba(255,255,255,0.06)",
                        borderRadius:10,
                        cursor:"pointer",
                        display:"flex", flexDirection:"column", alignItems:"flex-start",
                        gap:10, textAlign:"left",
                        transition:"border-color 0.22s cubic-bezier(.4,0,.2,1), background 0.22s cubic-bezier(.4,0,.2,1), transform 0.22s cubic-bezier(.4,0,.2,1), box-shadow 0.22s cubic-bezier(.4,0,.2,1)",
                        fontFamily:"'DM Sans', 'system-ui', sans-serif",
                        boxShadow:"inset 0 1px 0 rgba(255,255,255,0.025)",
                        opacity:0,
                        animation:`emptyFadeIn 460ms cubic-bezier(.4,0,.2,1) ${staggerDelay}ms forwards`
                      }}
                      onMouseEnter={e=>{
                        e.currentTarget.style.borderColor = `${mod.color}55`;
                        e.currentTarget.style.background = `rgba(0,176,212,0.04)`;
                        e.currentTarget.style.transform = "translateY(-2px)";
                        e.currentTarget.style.boxShadow = `inset 0 1px 0 rgba(255,255,255,0.05), 0 8px 24px -8px ${mod.color}44`;
                      }}
                      onMouseLeave={e=>{
                        e.currentTarget.style.borderColor = "rgba(255,255,255,0.06)";
                        e.currentTarget.style.background = "rgba(255,255,255,0.02)";
                        e.currentTarget.style.transform = "translateY(0)";
                        e.currentTarget.style.boxShadow = "inset 0 1px 0 rgba(255,255,255,0.025)";
                      }}>
                      <div style={{
                        display:"flex", alignItems:"center", gap:8,
                        fontSize:9.5, color:mod.color,
                        fontFamily:"'JetBrains Mono', ui-monospace, monospace",
                        textTransform:"uppercase", letterSpacing:"1.6px",
                        fontWeight:600
                      }}>
                        <span style={{
                          width:5, height:5, borderRadius:"50%",
                          background:mod.color,
                          boxShadow:`0 0 6px ${mod.color}`
                        }}/>
                        Módulo
                      </div>
                      <h3 style={{
                        fontSize:18, fontWeight:600, color:C.text,
                        margin:0, letterSpacing:"-0.025em"
                      }}>
                        {m.label}
                      </h3>
                      <p style={{
                        fontSize:11.5, color:C.textMuted,
                        margin:0, lineHeight:1.5, letterSpacing:"-0.005em"
                      }}>
                        {m.desc}
                      </p>
                      <div style={{
                        marginTop:"auto", display:"flex", alignItems:"center", gap:5,
                        fontSize:10.5, color:mod.color, fontWeight:500,
                        letterSpacing:"-0.005em"
                      }}>
                        <span>Explorar</span>
                        <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                          <line x1="5" y1="12" x2="19" y2="12"/>
                          <polyline points="12 5 19 12 12 19"/>
                        </svg>
                      </div>
                    </button>
                  );
                })}
              </div>
            </div>
          )}
          </div>
        </main>

        {/* ════════════════════════════════════════════════
            SENTRIX · DERECHO — bandeja de datos, plegable
        ════════════════════════════════════════════════ */}
        {sentrixOpen && (
          <aside style={{
            position:"relative",
            width:"40%", minWidth:480,
            borderLeft:`1px solid ${C.border}`,
            background:"linear-gradient(180deg, #080808 0%, #060606 100%)",
            transition:"width 300ms ease",
            display:"flex", flexDirection:"column",
            flexShrink:0, overflow:"hidden"
          }}>
            {/* Acento glow vertical en borde izquierdo */}
            <div style={{
              position:"absolute", left:0, top:0, bottom:0, width:1,
              background:"linear-gradient(180deg, transparent 0%, rgba(0,176,212,0.25) 25%, rgba(0,176,212,0.25) 75%, transparent 100%)",
              pointerEvents:"none"
            }}/>
            {/* Header Sentrix con módulo activo + cerrar */}
            <div style={{
              padding:"12px 18px",
              borderBottom:`1px solid ${C.border}`,
              display:"flex", alignItems:"center", justifyContent:"space-between",
              flexShrink:0
            }}>
              <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                <span style={{ fontSize:10, fontWeight:600, color:C.textMuted, letterSpacing:"1.8px", fontFamily:"'JetBrains Mono', ui-monospace, monospace", textTransform:"uppercase" }}>
                  SENTRIX
                </span>
                <svg width="8" height="8" viewBox="0 0 8 8" fill="none" style={{ flexShrink:0, opacity:0.35 }}>
                  <path d="M2.5 1.5L5.5 4L2.5 6.5" stroke={C.textMuted} strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
                <span style={{ fontSize:10.5, color:MOD[modulo]?.color || C.textSub, fontWeight:600, fontFamily:"'JetBrains Mono', ui-monospace, monospace", letterSpacing:"0.3px" }}>
                  {MOD[modulo]?.label || "—"}
                </span>
                <svg width="8" height="8" viewBox="0 0 8 8" fill="none" style={{ flexShrink:0, opacity:0.35 }}>
                  <path d="M2.5 1.5L5.5 4L2.5 6.5" stroke={C.textMuted} strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
                <span style={{ fontSize:10.5, color:C.textSub, fontFamily:"'JetBrains Mono', ui-monospace, monospace", letterSpacing:"0.3px" }}>{filtro}</span>
                {filtros.marcas.length>0 && (
                  <>
                    <svg width="8" height="8" viewBox="0 0 8 8" fill="none" style={{ flexShrink:0, opacity:0.35 }}>
                      <path d="M2.5 1.5L5.5 4L2.5 6.5" stroke={C.textMuted} strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"/>
                    </svg>
                    <span style={{ fontSize:10.5, color:C.amber, fontFamily:"'JetBrains Mono', ui-monospace, monospace", letterSpacing:"0.3px" }}>{filtros.marcas.join(", ")}</span>
                  </>
                )}
              </div>
              <button onClick={()=>setSentrixOpen(false)}
                style={{ background:"transparent", border:"none",
                         color:C.textMuted, cursor:"pointer",
                         width:26, height:26, borderRadius:"50%",
                         display:"flex", alignItems:"center", justifyContent:"center",
                         transition:"all 0.18s cubic-bezier(.4,0,.2,1)"
                }}
                onMouseEnter={e=>{ e.currentTarget.style.background="rgba(255,255,255,0.05)"; e.currentTarget.style.color=C.text; }}
                onMouseLeave={e=>{ e.currentTarget.style.background="transparent"; e.currentTarget.style.color=C.textMuted; }}
                title="Cerrar bandeja de datos">
                <svg width="11" height="11" viewBox="0 0 11 11" fill="none">
                  <path d="M2 2L9 9M9 2L2 9" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/>
                </svg>
              </button>
            </div>

            {/* Contenido del módulo activo */}
            <div style={{ padding:"16px 18px", flex:1, overflowY:"auto", minHeight:0 }}>
              {/* BRIEF #16 · Banner del mecanismo cognitivo activo.
                  Solo aparece cuando el usuario llegó a Sentrix vía botón
                  contextual de ADI. Tiene ✕ para cerrar (no afecta los
                  filtros, solo es metadata visual). */}
              {sentrixMechanismBanner && (
                <div style={{
                  marginBottom: 14,
                  padding: "8px 14px",
                  background: "rgba(0, 194, 232, 0.05)",
                  borderLeft: `3px solid ${C.blue}`,
                  borderRadius: "0 4px 4px 0",
                  display: "flex",
                  alignItems: "center",
                  gap: 10,
                }}>
                  <span style={{
                    fontSize: 10.5,
                    fontWeight: 700,
                    color: C.blue,
                    letterSpacing: "0.4px",
                    textTransform: "uppercase",
                  }}>
                    Mecanismo activo
                  </span>
                  <span style={{
                    fontSize: 12,
                    color: C.text,
                    fontWeight: 600,
                  }}>
                    {sentrixMechanismBanner}
                  </span>
                  <button
                    onClick={() => setSentrixMechanismBanner(null)}
                    style={{
                      marginLeft: "auto",
                      background: "transparent",
                      border: "none",
                      color: C.textSub,
                      fontSize: 12,
                      cursor: "pointer",
                      padding: "2px 6px",
                    }}
                    title="Quitar contexto del mecanismo"
                  >
                    ✕
                  </button>
                </div>
              )}
              {modulo==="ventas"     && <ModuloVentas filtro={filtro} filtros={filtros} scenario={scenario} onExplain={() => handleExplain("ventas")}/>}
              {modulo==="margenes"   && <ModuloMargenes filtro={filtro} filtros={filtros} scenario={scenario} onExplain={() => handleExplain("margenes")}/>}
              {modulo==="inventario" && <ModuloInventario filtro={filtro} filtros={filtros} scenario={scenario} onExplain={() => handleExplain("inventario")} evidencia={VOICE_C32_EVIDENCE_ENABLED ? sentrixEvidencia : null}/>}
            </div>
          </aside>
        )}

      </div>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:ital,opsz,wght@0,9..40,400;0,9..40,500;0,9..40,600;0,9..40,700;0,9..40,800;0,9..40,900&display=swap');
        * { box-sizing:border-box; margin:0; padding:0; }
        ::-webkit-scrollbar { width:6px; height:6px; }
        ::-webkit-scrollbar-track { background:transparent; }
        ::-webkit-scrollbar-thumb { background:rgba(0,176,212,0.15); border-radius:4px; transition:background 0.2s; }
        ::-webkit-scrollbar-thumb:hover { background:rgba(0,176,212,0.3); }
        ::-webkit-scrollbar-corner { background:transparent; }
        @keyframes blink { 0%,100%{opacity:1} 50%{opacity:0} }
        @keyframes pulse { 0%,100%{opacity:0.4} 50%{opacity:0.9} }
        @keyframes auroraBreathe { 0%,100%{opacity:0.6} 50%{opacity:1} }
        @keyframes scanline { 0%{left:-60%} 100%{left:120%} }
        @keyframes chartScan { 0%{left:-40%} 100%{left:120%} }
        @keyframes livePulse {
          0%  { box-shadow: 0 0 0 0 rgba(0,176,212,0.5); transform:scale(1); }
          60% { box-shadow: 0 0 0 8px rgba(0,176,212,0); transform:scale(1.15); }
          100%{ box-shadow: 0 0 0 0 rgba(0,176,212,0);  transform:scale(1); }
        }
        @keyframes adiBreath {
          0%, 100% { transform: scale(1);    box-shadow: 0 0 20px rgba(0,176,212,0.25); }
          50%      { transform: scale(1.04); box-shadow: 0 0 28px rgba(0,176,212,0.45); }
        }
        @keyframes adiAurora {
          0%, 100% { transform: scale(1)   translate(0, 0);     opacity: 0.7; }
          25%      { transform: scale(1.06) translate(-3%, 2%);  opacity: 0.85; }
          50%      { transform: scale(1.1)  translate(2%, -2%);  opacity: 1; }
          75%      { transform: scale(1.04) translate(3%, 3%);   opacity: 0.8; }
        }
        @keyframes adiOrbRing {
          0%   { transform: scale(0.85); opacity: 0.9; }
          70%  { opacity: 0.1; }
          100% { transform: scale(1.6);  opacity: 0; }
        }
        @keyframes emptyFadeIn {
          from { opacity: 0; transform: translateY(8px); }
          to   { opacity: 1; transform: translateY(0); }
        }
        @keyframes adiSpark {
          0%, 100% {
            transform: scale(1);
            box-shadow: 0 0 0 1px rgba(0,176,212,0.4), 0 0 16px rgba(0,176,212,0.55), 0 0 32px rgba(0,176,212,0.2);
          }
          50% {
            transform: scale(1.1);
            box-shadow: 0 0 0 1px rgba(0,176,212,0.7), 0 0 28px rgba(0,176,212,0.85), 0 0 56px rgba(0,176,212,0.4);
          }
        }
        button:focus { outline:none; }
        input::placeholder { color:#9a9a9a; }
        /* Scrollbar custom · dark mode premium */
        ::-webkit-scrollbar { width:8px; height:8px; }
        ::-webkit-scrollbar-track { background:transparent; }
        ::-webkit-scrollbar-thumb { background:rgba(255,255,255,0.06); border-radius:4px; transition:background 0.2s; }
        ::-webkit-scrollbar-thumb:hover { background:rgba(255,255,255,0.12); }
        ::-webkit-scrollbar-corner { background:transparent; }
        /* Firefox */
        * { scrollbar-width:thin; scrollbar-color:rgba(255,255,255,0.06) transparent; }
      `}</style>
    </div>
  );
}
